bool _intDoubleMapEquals(Map<int, double> left, Map<int, double> right) {
  if (identical(left, right)) {
    return true;
  }
  if (left.length != right.length) {
    return false;
  }
  for (final entry in left.entries) {
    if (right[entry.key] != entry.value) {
      return false;
    }
  }
  return true;
}

bool _stringMapEquals(Map<String, String> left, Map<String, String> right) {
  if (identical(left, right)) {
    return true;
  }
  if (left.length != right.length) {
    return false;
  }
  for (final entry in left.entries) {
    if (right[entry.key] != entry.value) {
      return false;
    }
  }
  return true;
}

bool _stringListEquals(List<String> left, List<String> right) {
  if (identical(left, right)) {
    return true;
  }
  if (left.length != right.length) {
    return false;
  }
  for (var index = 0; index < left.length; index += 1) {
    if (left[index] != right[index]) {
      return false;
    }
  }
  return true;
}

bool _stringSetEquals(Set<String> left, Set<String> right) {
  if (identical(left, right)) {
    return true;
  }
  if (left.length != right.length) {
    return false;
  }
  return left.containsAll(right);
}

bool _fortuneSheetGuideListEquals(
  List<FortuneSheetGuide> left,
  List<FortuneSheetGuide> right,
) {
  if (identical(left, right)) {
    return true;
  }
  if (left.length != right.length) {
    return false;
  }
  for (var index = 0; index < left.length; index += 1) {
    if (left[index] != right[index]) {
      return false;
    }
  }
  return true;
}

class FortuneSheetGuide {
  const FortuneSheetGuide({
    required this.index,
    required this.axis,
    required this.positionMm,
  });

  final int index;
  final String axis;
  final double positionMm;

  FortuneSheetGuide copyWith({int? index, String? axis, double? positionMm}) {
    return FortuneSheetGuide(
      index: index ?? this.index,
      axis: axis ?? this.axis,
      positionMm: positionMm ?? this.positionMm,
    );
  }

  @override
  bool operator ==(Object other) {
    return other is FortuneSheetGuide &&
        other.index == index &&
        other.axis == axis &&
        other.positionMm == positionMm;
  }

  @override
  int get hashCode => Object.hash(index, axis, positionMm);
}

