String fortuneContextMenuAxisSizeUnitLabel(
  FortuneSheet sheet,
  FortuneSheetLocale locale,
) {
  final key = fortuneSheetGridClientPhysicalSize(sheet) == null
      ? 'context-menu-pixel-unit'
      : 'context-menu-millimeter-unit';
  return locale.contextMenuLabels[key] ?? key;
}

