List<FortuneRawShapeOverlay> fortuneRawShapeOverlays(FortuneSheet sheet) {
  final overlays = <FortuneRawShapeOverlay>[];

  void collect(
    Object? raw, {
    required bool allowAnyType,
    required String? placeholderLabel,
    required String sourceName,
  }) {
    final items = <Object?>[];
    if (raw is Map) {
      if (_fortuneRawShapeHasGeometry(raw)) {
        items.add(raw);
      } else {
        items.addAll(raw.values);
      }
    } else if (raw is List) {
      items.addAll(raw);
    }
    for (var index = 0; index < items.length; index += 1) {
      final item = items[index];
      final overlay = _fortuneRawShapeOverlay(
        item,
        allowAnyType: allowAnyType,
        placeholderLabel: placeholderLabel,
        hitKey: '$sourceName:$index',
      );
      if (overlay != null) {
        overlays.add(overlay);
      }
    }
  }

  collect(
    sheet.extraFields['shapes'],
    allowAnyType: false,
    placeholderLabel: null,
    sourceName: 'shapes',
  );
  for (final key in const ['chart', 'charts']) {
    collect(
      sheet.extraFields[key],
      allowAnyType: true,
      placeholderLabel: 'Chart',
      sourceName: key,
    );
  }
  for (final key in const [
    'customOverlay',
    'customoverlay',
    'customOverlays',
    'customoverlays',
    'overlays',
  ]) {
    collect(
      sheet.extraFields[key],
      allowAnyType: true,
      placeholderLabel: 'Overlay',
      sourceName: key,
    );
  }

  final ordered = <({int index, FortuneRawShapeOverlay overlay})>[];
  for (var index = 0; index < overlays.length; index += 1) {
    ordered.add((index: index, overlay: overlays[index]));
  }
  ordered.sort((a, b) {
    final zIndexComparison = a.overlay.zIndex.compareTo(b.overlay.zIndex);
    if (zIndexComparison != 0) {
      return zIndexComparison;
    }
    return a.index.compareTo(b.index);
  });
  return [for (final item in ordered) item.overlay];
}

Rect fortuneRawShapeOverlayScreenRect(
  FortuneRawShapeOverlay overlay,
  FortuneSettings settings,
  Offset scrollOffset,
  double zoomRatio,
) {
  final effectiveZoomRatio = zoomRatio <= 0 ? 1.0 : zoomRatio;
  return Rect.fromLTWH(
    settings.rowHeaderWidth +
        overlay.rect.left * effectiveZoomRatio -
        scrollOffset.dx,
    settings.columnHeaderHeight +
        overlay.rect.top * effectiveZoomRatio -
        scrollOffset.dy,
    overlay.rect.width * effectiveZoomRatio,
    overlay.rect.height * effectiveZoomRatio,
  );
}

bool _fortuneRawShapeHasGeometry(Map raw) {
  final hasRectGeometry =
      (raw.containsKey('left') || raw.containsKey('x')) &&
      (raw.containsKey('top') || raw.containsKey('y')) &&
      (raw.containsKey('width') || raw.containsKey('w')) &&
      (raw.containsKey('height') || raw.containsKey('h'));
  final hasLineGeometry =
      (raw.containsKey('x1') ||
          raw.containsKey('startX') ||
          raw.containsKey('startx')) &&
      (raw.containsKey('y1') ||
          raw.containsKey('startY') ||
          raw.containsKey('starty')) &&
      (raw.containsKey('x2') ||
          raw.containsKey('endX') ||
          raw.containsKey('endx')) &&
      (raw.containsKey('y2') ||
          raw.containsKey('endY') ||
          raw.containsKey('endy'));
  return hasRectGeometry || hasLineGeometry;
}

FortuneRawShapeOverlay? _fortuneRawShapeOverlay(
  Object? raw, {
  required bool allowAnyType,
  required String? placeholderLabel,
  required String hitKey,
}) {
  if (raw is! Map) {
    return null;
  }
  final type =
      '${raw['type'] ?? raw['shape'] ?? raw['chartType'] ?? raw['name'] ?? 'rect'}'
          .toLowerCase();
  if (!allowAnyType &&
      type.isNotEmpty &&
      type != 'rect' &&
      type != 'rectangle' &&
      type != 'box' &&
      type != 'ellipse' &&
      type != 'oval' &&
      type != 'circle' &&
      type != 'line') {
    return null;
  }
  final kind = _fortuneRawShapeKind(type, allowAnyType: allowAnyType);
  var left = _fortuneRawShapeDouble(raw['left'] ?? raw['x']);
  var top = _fortuneRawShapeDouble(raw['top'] ?? raw['y']);
  var width = _fortuneRawShapeDouble(raw['width'] ?? raw['w']);
  var height = _fortuneRawShapeDouble(raw['height'] ?? raw['h']);
  Offset? lineStart;
  Offset? lineEnd;
  if (kind == 'line') {
    final x1 = _fortuneRawShapeDouble(
      raw['x1'] ?? raw['startX'] ?? raw['startx'],
    );
    final y1 = _fortuneRawShapeDouble(
      raw['y1'] ?? raw['startY'] ?? raw['starty'],
    );
    final x2 = _fortuneRawShapeDouble(raw['x2'] ?? raw['endX'] ?? raw['endx']);
    final y2 = _fortuneRawShapeDouble(raw['y2'] ?? raw['endY'] ?? raw['endy']);
    if (x1 != null && y1 != null && x2 != null && y2 != null) {
      left = math.min(x1, x2);
      top = math.min(y1, y2);
      width = (x2 - x1).abs();
      height = (y2 - y1).abs();
      lineStart = Offset(x1 - left, y1 - top);
      lineEnd = Offset(x2 - left, y2 - top);
    }
  }
  if (left == null || top == null || width == null || height == null) {
    return null;
  }
  if (kind == 'line') {
    if (width <= 0 && height <= 0) {
      return null;
    }
    lineStart ??= Offset.zero;
    lineEnd ??= Offset(width, height);
  } else if (width <= 0 || height <= 0) {
    return null;
  }
  final isPlaceholder = placeholderLabel != null;
  final chartOption = placeholderLabel == 'Chart'
      ? _fortuneRawChartOption(raw)
      : null;
  final chartMetadataOption = placeholderLabel == 'Chart'
      ? _fortuneRawChartOptionMetadata(raw, chartOption)
      : null;
  final fillColor =
      _fortuneRawShapeColor(
        raw['fillColor'] ??
            raw['fillcolor'] ??
            raw['fill'] ??
            raw['background'] ??
            raw['backgroundColor'] ??
            raw['backgroundcolor'] ??
            raw['color'] ??
            chartOption?['backgroundColor'] ??
            chartOption?['backgroundcolor'] ??
            chartOption?['background'],
      ) ??
      (isPlaceholder ? const Color(0xfff8fbff) : null);
  final strokeColor =
      _fortuneRawShapeColor(
        raw['strokeColor'] ??
            raw['strokecolor'] ??
            raw['stroke'] ??
            raw['borderColor'] ??
            raw['bordercolor'] ??
            raw['border'] ??
            chartOption?['borderColor'] ??
            chartOption?['bordercolor'] ??
            chartOption?['border'],
      ) ??
      (isPlaceholder ? const Color(0xff8ab4f8) : null);
  final strokeWidth =
      _fortuneRawShapeDouble(
        raw['strokeWidth'] ??
            raw['strokewidth'] ??
            raw['lineWidth'] ??
            raw['linewidth'] ??
            raw['borderWidth'] ??
            raw['borderwidth'] ??
            chartOption?['borderWidth'] ??
            chartOption?['borderwidth'],
      ) ??
      (isPlaceholder ? 1.5 : 1);
  final zIndex =
      _fortuneRawShapeDouble(
        raw['zIndex'] ?? raw['zindex'] ?? raw['z'],
      )?.toInt() ??
      0;
  final effectiveLabel = placeholderLabel == 'Chart'
      ? _fortuneRawChartTitle(raw) ?? placeholderLabel
      : placeholderLabel;
  return FortuneRawShapeOverlay(
    hitKey: hitKey,
    rect: Rect.fromLTWH(left, top, width, height),
    kind: kind,
    fillColor: fillColor,
    strokeColor: strokeColor,
    strokeWidth: math.max(0, strokeWidth),
    zIndex: zIndex,
    placeholderLabel: effectiveLabel,
    lineStart: lineStart,
    lineEnd: lineEnd,
    chartSeries: placeholderLabel == 'Chart'
        ? _fortuneRawChartSeries(raw)
        : const [],
    chartDatasets: placeholderLabel == 'Chart'
        ? _fortuneRawChartDatasets(raw)
        : const [],
    chartGraphics: placeholderLabel == 'Chart'
        ? _fortuneRawChartGraphics(raw)
        : const [],
    chartLegends: placeholderLabel == 'Chart'
        ? _fortuneRawChartRootComponentListPreferRoot(raw, 'legend')
        : const [],
    chartTooltips: placeholderLabel == 'Chart'
        ? _fortuneRawChartRootComponentListPreferRoot(raw, 'tooltip')
        : const [],
    chartTitles: placeholderLabel == 'Chart'
        ? _fortuneRawChartTitleComponentList(raw)
        : const [],
    chartToolboxes: placeholderLabel == 'Chart'
        ? _fortuneRawChartRootComponentListPreferRoot(raw, 'toolbox')
        : const [],
    chartGrids: placeholderLabel == 'Chart'
        ? _fortuneRawChartRootComponentList(raw, 'grid')
        : const [],
    chartDataZooms: placeholderLabel == 'Chart'
        ? _fortuneRawChartRootComponentListPreferRoot(raw, 'dataZoom')
        : const [],
    chartVisualMaps: placeholderLabel == 'Chart'
        ? _fortuneRawChartRootComponentListPreferRoot(raw, 'visualMap')
        : const [],
    chartCalendars: placeholderLabel == 'Chart'
        ? _fortuneRawChartRootComponentList(raw, 'calendar')
        : const [],
