        ? _fortuneRawChartStateAnimationEasing(raw)
        : null,
    chartAnimation: placeholderLabel == 'Chart'
        ? fortuneRawBool(chartMetadataOption?['animation'])
        : null,
    chartAnimationThreshold:
        placeholderLabel == 'Chart' && chartMetadataOption != null
        ? _fortuneRawChartSeriesNonNegativeDouble(
