Map? _fortuneRawChartOption(Map raw) {
  final option = raw['option'] ?? raw['options'];
  final xAxis = raw['xAxis'] ?? raw['xaxis'];
  final yAxis = raw['yAxis'] ?? raw['yaxis'];
  if (option is Map) {
    if (xAxis == null && yAxis == null) {
      return option;
    }
    final merged = Map<Object?, Object?>.from(option);
    if (xAxis != null &&
        !merged.containsKey('xAxis') &&
        !merged.containsKey('xaxis')) {
      merged['xAxis'] = xAxis;
    }
    if (yAxis != null &&
        !merged.containsKey('yAxis') &&
        !merged.containsKey('yaxis')) {
      merged['yAxis'] = yAxis;
    }
    return merged;
  }
  if (xAxis == null && yAxis == null) {
    return null;
  }
  final axes = <Object?, Object?>{};
  if (xAxis != null) {
    axes['xAxis'] = xAxis;
  }
  if (yAxis != null) {
    axes['yAxis'] = yAxis;
  }
  return axes;
}

Map _fortuneRawChartOptionMetadata(Map raw, Map? option) {
  if (option == null) {
    return raw;
  }
  return Map<Object?, Object?>.from(raw)..addAll(option);
}

