Object? _fortuneRawChartSeriesDatasetValues(
  List<FortuneRawChartDataset> datasets,
  Map series,
  int seriesIndex,
) {
  if (datasets.isEmpty) {
    return null;
  }
  final datasetIndex =
      _fortuneRawChartSeriesNonNegativeInt(series, 'datasetIndex') ?? 0;
  if (datasetIndex < 0 || datasetIndex >= datasets.length) {
    return null;
  }
  final dataset = datasets[datasetIndex];
  final source = dataset.source;
  if (source is! List || source.isEmpty) {
    return null;
  }
  final rows = [
    for (final row in source)
      if (row is List) row,
  ];
  if (rows.isEmpty) {
    return null;
  }
  final layout =
      _fortuneRawChartNonEmptyString(
        series['seriesLayoutBy'] ?? series['serieslayoutby'],
      ) ??
      dataset.seriesLayoutBy ??
      'column';
  final hasHeader = _fortuneRawChartDatasetHasHeader(
    dataset.sourceHeader,
    rows,
    layout,
  );
  if (layout.toLowerCase() == 'row') {
    final rowIndex = (hasHeader ? 1 : 0) + seriesIndex;
    if (rowIndex < 0 || rowIndex >= rows.length) {
      return null;
    }
    final row = rows[rowIndex];
    final startColumn = hasHeader && row.isNotEmpty ? 1 : 0;
    return [
      for (
        var columnIndex = startColumn;
        columnIndex < row.length;
        columnIndex += 1
      )
        row[columnIndex],
    ];
  }
  final columnIndex = (hasHeader ? 1 : 0) + seriesIndex;
  if (rows.any((row) => columnIndex >= row.length)) {
    return null;
  }
  final startRow = hasHeader ? 1 : 0;
  return [
    for (var rowIndex = startRow; rowIndex < rows.length; rowIndex += 1)
      rows[rowIndex][columnIndex],
  ];
}

bool _fortuneRawChartDatasetHasHeader(
  Object? sourceHeader,
  List<List> rows,
  String layout,
) {
  final parsedBool = _fortuneRawChartBool(sourceHeader);
  if (parsedBool != null) {
    return parsedBool;
  }
  if (sourceHeader is num) {
    return sourceHeader > 0;
  }
  if (sourceHeader is String) {
    final parsedNumber = num.tryParse(sourceHeader.trim());
    if (parsedNumber != null) {
      return parsedNumber > 0;
    }
  }
  if (layout.toLowerCase() == 'row') {
    final firstColumn = [
      for (final row in rows)
        if (row.isNotEmpty) row.first,
    ];
    return firstColumn.any(_fortuneRawChartDatasetHeaderValue);
  }
  final firstRow = rows.first;
  return firstRow.any(_fortuneRawChartDatasetHeaderValue);
}

bool _fortuneRawChartDatasetHeaderValue(Object? value) {
  if (value == null) {
    return false;
  }
  if (value is num) {
    return false;
  }
  if (value is String) {
    return double.tryParse(value.trim()) == null;
  }
  return true;
}

