class _FortuneRawChartDataZoomPercentRange {
  const _FortuneRawChartDataZoomPercentRange(this.start, this.end);

  final double? start;
  final double? end;
}

_FortuneRawChartDataZoomPercentRange _fortuneRawChartDataZoomPercentRange(
  Map raw,
) {
  final dataZoom = _fortuneRawChartDataZoom(raw);
  final rawStart = _fortuneRawShapeDouble(dataZoom?['start']);
  final rawEnd = _fortuneRawShapeDouble(dataZoom?['end']);
  var start = rawStart == null || !rawStart.isFinite
      ? _fortuneRawChartDataZoomValuePercent(
          raw,
          dataZoom?['startValue'] ?? dataZoom?['startvalue'],
        )
      : rawStart.clamp(0, 100).toDouble();
  var end = rawEnd == null || !rawEnd.isFinite
      ? _fortuneRawChartDataZoomValuePercent(
          raw,
          dataZoom?['endValue'] ?? dataZoom?['endvalue'],
          end: true,
        )
      : rawEnd.clamp(0, 100).toDouble();
  var minSpan = _fortuneRawChartDataZoomNonNegativeDouble(raw, 'minSpan');
  var maxSpan = _fortuneRawChartDataZoomNonNegativeDouble(raw, 'maxSpan');
  final categoryCount = _fortuneRawChartDataZoomCategoryCount(raw);
  if (categoryCount > 0) {
    minSpan ??= _fortuneRawChartDataZoomValueSpanPercent(
      raw,
      'minValueSpan',
      categoryCount,
    );
    maxSpan ??= _fortuneRawChartDataZoomValueSpanPercent(
      raw,
      'maxValueSpan',
      categoryCount,
    );
  }
  if (start == null || end == null || (minSpan == null && maxSpan == null)) {
    return _FortuneRawChartDataZoomPercentRange(start, end);
  }
  if (end < start) {
    final nextStart = end;
    end = start;
    start = nextStart;
  }
  var span = end - start;
  if (maxSpan != null && span > maxSpan) {
    end = (start + maxSpan).clamp(0, 100).toDouble();
    span = end - start;
  }
  if (minSpan != null && span < minSpan) {
    end = (start + minSpan).clamp(0, 100).toDouble();
    if (end - start < minSpan) {
      start = (end - minSpan).clamp(0, 100).toDouble();
    }
  }
  return _FortuneRawChartDataZoomPercentRange(start, end);
}

double? _fortuneRawChartDataZoomValueSpanPercent(
  Map raw,
  String key,
  int categoryCount,
) {
  final valueSpan = _fortuneRawChartDataZoomNonNegativeDouble(raw, key);
  if (valueSpan == null || valueSpan <= 0) {
    return null;
  }
  return (valueSpan * 100 / categoryCount).clamp(0, 100).toDouble();
}

double? _fortuneRawChartDataZoomValuePercent(
  Map raw,
  Object? value, {
  bool end = false,
}) {
  final categoryCount = _fortuneRawChartDataZoomCategoryCount(raw);
  if (categoryCount <= 0) {
    return null;
  }
  final index = _fortuneRawChartDataZoomValueIndex(raw, value, categoryCount);
  if (index == null) {
    return null;
  }
  final edgeIndex = end ? index + 1 : index;
  return (edgeIndex * 100 / categoryCount).clamp(0, 100).toDouble();
}

int _fortuneRawChartDataZoomCategoryCount(Map raw) {
  final option = _fortuneRawChartOption(raw);
  final axisLabels = _fortuneRawChartXAxisLabels(raw);
  var count = axisLabels.length;
  final rawSeries =
      raw['series'] ??
      (option is Map ? option['series'] : null) ??
      (raw['options'] is Map ? (raw['options'] as Map)['series'] : null);
  if (rawSeries is List) {
    for (final item in rawSeries) {
      if (item is! Map) {
        continue;
      }
      final data = item['data'] ?? item['values'];
      if (data is List) {
        count = math.max(count, data.length);
      }
    }
  }
  return count;
}

int? _fortuneRawChartDataZoomValueIndex(
  Map raw,
  Object? value,
  int categoryCount,
) {
  if (categoryCount <= 0) {
    return null;
  }
  final numeric = _fortuneRawShapeDouble(value);
  if (numeric != null && numeric.isFinite) {
    return numeric.round().clamp(0, categoryCount - 1).toInt();
  }
  final labels = _fortuneRawChartXAxisCategoryLabels(raw);
  if (labels.isEmpty || value == null) {
    return null;
  }
  final label = '$value';
  final index = labels.indexOf(label);
  return index < 0 ? null : index.clamp(0, categoryCount - 1).toInt();
}

