bool _fortuneRawChartToolboxVisible(Map raw) {
  final toolbox = _fortuneRawChartToolbox(raw);
  if (toolbox == null || _fortuneRawChartBool(toolbox['show']) == false) {
    return false;
  }
  return _fortuneRawChartToolboxFeatureCount(raw) > 0;
}

int _fortuneRawChartToolboxFeatureCount(Map raw) {
  final toolbox = _fortuneRawChartToolbox(raw);
  if (toolbox == null) {
    return 0;
  }
  final feature = toolbox['feature'];
  if (feature is Map) {
    var count = 0;
    for (final value in feature.values) {
      if (_fortuneRawChartBool(value) == false) {
        continue;
      }
      if (value is Map && _fortuneRawChartBool(value['show']) == false) {
        continue;
      }
      count += 1;
    }
    return math.min(count, 6);
  }
  return _fortuneRawChartBool(toolbox['show']) == true ? 1 : 0;
}

bool? _fortuneRawChartToolboxShowTitle(Map raw) {
  final toolbox = _fortuneRawChartToolbox(raw);
  return fortuneRawBool(toolbox?['showTitle'] ?? toolbox?['showtitle']);
}

List<String> _fortuneRawChartToolboxFeatureKeys(Map raw) {
  final toolbox = _fortuneRawChartToolbox(raw);
  final feature = toolbox?['feature'];
  if (feature is! Map) {
    return const [];
  }
  final keys = <String>[];
  for (final entry in feature.entries) {
    final key = '${entry.key}'.trim();
    final value = entry.value;
    if (key.isEmpty || _fortuneRawChartBool(value) == false) {
      continue;
    }
    if (value is Map && _fortuneRawChartBool(value['show']) == false) {
      continue;
    }
    keys.add(key);
    if (keys.length >= 6) {
      break;
    }
  }
  return keys;
}

Map<String, String> _fortuneRawChartToolboxFeatureTitles(Map raw) {
  final toolbox = _fortuneRawChartToolbox(raw);
  final feature = toolbox?['feature'];
  if (feature is! Map) {
    return const {};
  }
  final titles = <String, String>{};
  for (final entry in feature.entries) {
    final key = '${entry.key}'.trim();
    final value = entry.value;
    if (key.isEmpty || _fortuneRawChartBool(value) == false) {
      continue;
    }
    if (value is! Map || _fortuneRawChartBool(value['show']) == false) {
      continue;
    }
    final title = value['title'];
    if (title is String) {
      final normalized = title.trim();
      if (normalized.isNotEmpty) {
        titles[key] = normalized;
      }
    }
  }
  return titles;
}

