String? _fortuneRawChartTitle(Map raw) {
  String? titleFrom(Object? value) {
    if (value is String && value.trim().isNotEmpty) {
      return value.trim();
    }
    if (value is Map) {
      if (_fortuneRawChartTitleHidden(value)) {
        return '';
      }
      final text = value['text'] ?? value['title'];
      if (text is String && text.trim().isNotEmpty) {
        return text.trim();
      }
    }
    return null;
  }

  return titleFrom(raw['title']) ??
      titleFrom(raw['chartTitle']) ??
      titleFrom(raw['charttitle']) ??
      (raw['option'] is Map
          ? titleFrom((raw['option'] as Map)['title'])
          : null) ??
      (raw['options'] is Map
          ? titleFrom((raw['options'] as Map)['title'])
          : null);
}

Map? _fortuneRawChartTitleMap(Map raw) {
  Map? mapFrom(Object? value) {
    if (value is Map) {
      return _fortuneRawChartTitleHidden(value) ? null : value;
    }
    if (value is List) {
      for (final item in value) {
        if (item is Map && !_fortuneRawChartTitleHidden(item)) {
          return item;
        }
      }
    }
    return null;
  }

  return mapFrom(raw['title']) ??
      mapFrom(raw['chartTitle']) ??
      mapFrom(raw['charttitle']) ??
      (raw['option'] is Map
          ? mapFrom((raw['option'] as Map)['title'])
          : null) ??
      (raw['options'] is Map
          ? mapFrom((raw['options'] as Map)['title'])
          : null);
}

