double? _fortuneRawChartTitlePositionOffset(
  Map raw,
  String key,
  String alternateKey,
) {
  final value = _fortuneRawChartTitlePositionValue(raw, key, alternateKey);
  if (value is String && value.trim().endsWith('%')) {
    return null;
  }
  final offset = _fortuneRawShapeDouble(value);
  if (offset == null || !offset.isFinite) {
    return null;
  }
  return offset;
}

double? _fortuneRawChartTitlePositionPercent(
  Map raw,
  String key,
  String alternateKey,
) {
  final value = _fortuneRawChartTitlePositionValue(raw, key, alternateKey);
  if (value is! String) {
    return null;
  }
  final text = value.trim();
  if (!text.endsWith('%')) {
    return null;
  }
  final percent = double.tryParse(text.substring(0, text.length - 1).trim());
  if (percent == null || !percent.isFinite) {
    return null;
  }
  return percent / 100;
}

Object? _fortuneRawChartTitlePositionValue(
  Map raw,
