  final right = _fortuneRawChartGridInsetValue(
    grid['right'],
    percentBase: plotWidthBase,
  );
  final bottom = _fortuneRawChartGridInsetValue(
    grid['bottom'],
    percentBase: plotHeightBase,
  );
  if (left == null && top == null && right == null && bottom == null) {
