  final symbol = axisLine['symbol'];
  bool isArrow(Object? value) =>
      '${value ?? ''}'.trim().toLowerCase() == 'arrow';
  if (symbol is List) {
    final start = symbol.isNotEmpty && isArrow(symbol.first);
    final end = symbol.length > 1 ? isArrow(symbol[1]) : start;
    return (start, end);
  }
  final arrow = isArrow(symbol);
  return (arrow, arrow);
}

