FontWeight? _fortuneRawChartAxisLabelFontWeight(Map? axis) {
  final axisLabel = axis?['axisLabel'] ?? axis?['axislabel'];
  if (axisLabel is! Map) {
    return null;
  }
  final weight = axisLabel['fontWeight'] ?? axisLabel['fontweight'];
  if (weight == null) {
    return null;
  }
  if (weight is num) {
    return _fortuneRawChartNumericFontWeight(weight.round());
  }
  final value = '$weight'.trim().toLowerCase();
  if (value.isEmpty || value == 'normal') {
    return FontWeight.w400;
  }
  if (value == 'bold' || value == 'bolder') {
    return FontWeight.w700;
  }
  if (value == 'lighter') {
    return FontWeight.w300;
  }
  final numeric = int.tryParse(value);
  if (numeric != null) {
    return _fortuneRawChartNumericFontWeight(numeric);
  }
  return null;
}

FontWeight _fortuneRawChartNumericFontWeight(int weight) {
  if (weight <= 100) {
    return FontWeight.w100;
  }
  if (weight <= 200) {
    return FontWeight.w200;
  }
  if (weight <= 300) {
    return FontWeight.w300;
  }
  if (weight <= 400) {
    return FontWeight.w400;
  }
  if (weight <= 500) {
    return FontWeight.w500;
  }
  if (weight <= 600) {
    return FontWeight.w600;
  }
  if (weight <= 700) {
    return FontWeight.w700;
  }
  if (weight <= 800) {
    return FontWeight.w800;
  }
  return FontWeight.w900;
}

