Map<String, FortuneRawChartRichTextStyle> _fortuneRawChartTextStyleRichStyles(
  Map style,
) {
  final rich = style['rich'];
  if (rich is! Map) {
    return const {};
  }
  final styles = <String, FortuneRawChartRichTextStyle>{};
  for (final entry in rich.entries) {
    final key = entry.key.toString().trim();
    final rawStyle = entry.value;
    if (key.isEmpty || rawStyle is! Map) {
      continue;
    }
    final fontSize = _fortuneRawShapeDouble(
      rawStyle['fontSize'] ?? rawStyle['fontsize'],
    );
    final style = FortuneRawChartRichTextStyle(
      color: _fortuneRawShapeColor(
        rawStyle['color'] ??
            rawStyle['textColor'] ??
            rawStyle['textcolor'] ??
            rawStyle['fontColor'] ??
            rawStyle['fontcolor'],
      ),
      fontSize: fontSize != null && fontSize.isFinite && fontSize > 0
          ? fontSize
          : null,
      fontWeight: _fortuneRawChartTextStyleFontWeight(rawStyle),
      fontStyle: _fortuneRawChartTextStyleFontStyle(rawStyle),
      fontFamily: _fortuneRawChartTextStyleFontFamily(rawStyle),
      backgroundColor: _fortuneRawShapeColor(
        rawStyle['backgroundColor'] ?? rawStyle['backgroundcolor'],
      ),
    );
    styles[key] = style;
  }
  return styles;
}

