FontWeight? _fortuneRawChartTextStyleFontWeight(Map style) {
  final weight = style['fontWeight'] ?? style['fontweight'];
  if (weight == null) {
    return null;
  }
  if (weight is num) {
    return _fortuneRawChartNumericFontWeight(weight.round());
  }
  final value = '$weight'.trim().toLowerCase();
  if (value.isEmpty || value == 'normal') {
    return FontWeight.w400;
  }
  if (value == 'bold' || value == 'bolder') {
    return FontWeight.w700;
  }
  if (value == 'lighter') {
    return FontWeight.w300;
  }
  final numeric = int.tryParse(value);
  return numeric == null ? null : _fortuneRawChartNumericFontWeight(numeric);
}

FontStyle? _fortuneRawChartTextStyleFontStyle(Map style) {
  final rawStyle = style['fontStyle'] ?? style['fontstyle'];
  if (rawStyle == null) {
    return null;
  }
  final value = '$rawStyle'.trim().toLowerCase();
  if (value == 'italic' || value == 'oblique') {
    return FontStyle.italic;
