EdgeInsets? _fortuneRawChartAxisLabelPadding(Map? axis) {
  final axisLabel = axis?['axisLabel'] ?? axis?['axislabel'];
  if (axisLabel is! Map) {
    return null;
  }
  final rawPadding = axisLabel['padding'];
  if (rawPadding == null) {
    return null;
  }
  if (rawPadding is List) {
    final values = rawPadding
        .map(_fortuneRawShapeDouble)
        .whereType<double>()
        .where((value) => value.isFinite && value >= 0)
        .toList();
    if (values.isEmpty) {
      return null;
    }
    if (values.length == 1) {
      return EdgeInsets.all(values[0]);
    }
    if (values.length == 2) {
      return EdgeInsets.symmetric(vertical: values[0], horizontal: values[1]);
    }
    if (values.length == 3) {
      return EdgeInsets.fromLTRB(values[1], values[0], values[1], values[2]);
    }
    return EdgeInsets.fromLTRB(values[3], values[0], values[1], values[2]);
  }
  if (rawPadding is Map) {
    final top = _fortuneRawShapeDouble(rawPadding['top']) ?? 0;
    final right = _fortuneRawShapeDouble(rawPadding['right']) ?? 0;
    final bottom = _fortuneRawShapeDouble(rawPadding['bottom']) ?? 0;
    final left = _fortuneRawShapeDouble(rawPadding['left']) ?? 0;
    if ([
      top,
      right,
      bottom,
      left,
    ].any((value) => !value.isFinite || value < 0)) {
      return null;
    }
    if (top == 0 && right == 0 && bottom == 0 && left == 0) {
      return null;
    }
    return EdgeInsets.fromLTRB(left, top, right, bottom);
  }
  final value = _fortuneRawShapeDouble(rawPadding);
  if (value == null || !value.isFinite || value < 0) {
    return null;
  }
  return EdgeInsets.all(value);
}

