  if (layout is! Map) {
    return const [];
  }
  final rawPoints = layout['labelLinePoints'] ?? layout['labellinepoints'];
  if (rawPoints is! List) {
    return const [];
  }
  final points = <Offset>[];
  for (final rawPoint in rawPoints) {
    double? x;
    double? y;
    if (rawPoint is List && rawPoint.length >= 2) {
      x = _fortuneRawShapeDouble(rawPoint[0]);
      y = _fortuneRawShapeDouble(rawPoint[1]);
    } else if (rawPoint is Map) {
      x = _fortuneRawShapeDouble(rawPoint['x']);
      y = _fortuneRawShapeDouble(rawPoint['y']);
    }
    if (x == null || y == null || !x.isFinite || !y.isFinite) {
      continue;
    }
    points.add(Offset(x, y));
  }
  return points.length >= 2 ? List.unmodifiable(points) : const [];
}

