}

double? _fortuneRawChartBorderRadiusValue(Object? rawRadius) {
  final rawValue = rawRadius is List && rawRadius.isNotEmpty
      ? rawRadius.first
      : rawRadius;
  final radius = _fortuneRawShapeDouble(rawValue);
  if (radius == null || !radius.isFinite || radius <= 0) {
    return null;
  }
  return radius;
}

EdgeInsets? _fortuneRawChartLabelPadding(Object? rawPadding) {
  double? paddingValue(Object? value) {
    final padding = _fortuneRawShapeDouble(value);
    if (padding == null || !padding.isFinite || padding < 0) {
      return null;
    }
    return padding;
  }

  if (rawPadding is List) {
    final values = [for (final item in rawPadding) paddingValue(item)];
    if (values.isEmpty || values.any((value) => value == null)) {
      return null;
    }
    if (values.length == 1) {
      return EdgeInsets.all(values[0]!);
    }
    if (values.length == 2) {
      return EdgeInsets.symmetric(vertical: values[0]!, horizontal: values[1]!);
    }
    if (values.length == 3) {
      return EdgeInsets.fromLTRB(
        values[1]!,
        values[0]!,
        values[1]!,
        values[2]!,
      );
    }
    return EdgeInsets.fromLTRB(values[3]!, values[0]!, values[1]!, values[2]!);
  }
  final padding = paddingValue(rawPadding);
  return padding == null ? null : EdgeInsets.all(padding);
}

double? _fortuneRawChartFiniteDouble(Object? rawValue) {
  final value = _fortuneRawShapeDouble(rawValue);
  if (value == null || !value.isFinite) {
    return null;
  }
  return value;
}

String? _fortuneRawChartLabelAlign(Object? rawValue) {
  final value = rawValue?.toString().trim().toLowerCase();
  if (value == 'left' || value == 'center' || value == 'right') {
    return value;
  }
  return null;
}

String? _fortuneRawChartLabelVerticalAlign(Object? rawValue) {
  final value = rawValue?.toString().trim().toLowerCase();
  if (value == 'top' || value == 'middle' || value == 'bottom') {
    return value;
  }
  return null;
}

String? _fortuneRawChartLabelAlignTo(Object? rawValue) {
  final value = rawValue?.toString().trim().toLowerCase();
  if (value == 'none' || value == 'labelline' || value == 'edge') {
    return value == 'labelline' ? 'labelLine' : value;
  }
  return null;
}

(double?, bool) _fortuneRawChartLabelDistanceValue(Object? rawValue) {
  if (rawValue is String) {
    final text = rawValue.trim();
    if (text.endsWith('%')) {
      final percent = double.tryParse(text.substring(0, text.length - 1));
      if (percent == null || !percent.isFinite || percent < 0) {
        return (null, false);
      }
      return (percent / 100, true);
    }
  }
  final value = _fortuneRawShapeDouble(rawValue);
  if (value == null || !value.isFinite || value < 0) {
    return (null, false);
  }
  return (value, false);
}

String? _fortuneRawChartLabelOverflow(Object? rawValue) {
  if (rawValue is! String) {
    return null;
  }
  final value = rawValue.trim();
  if (value == 'truncate' || value == 'break' || value == 'breakAll') {
    return value;
  }
  return value.toLowerCase() == 'breakall' ? 'breakAll' : null;
}

String? _fortuneRawChartLabelEllipsis(Object? rawValue) {
  if (rawValue == null) {
    return null;
  }
  final value = rawValue.toString();
  return value.isEmpty ? null : value;
}

String _fortuneRawShapeKind(String type, {required bool allowAnyType}) {
  switch (type) {
    case 'ellipse':
    case 'oval':
    case 'circle':
      return 'ellipse';
    case 'line':
      return 'line';
    case 'rect':
    case 'rectangle':
    case 'box':
      return 'rect';
  }
  return allowAnyType ? 'rect' : type;
}

void fortuneDrawRawShapeOverlay(
  Canvas canvas,
  Rect rect,
  FortuneRawShapeOverlay overlay,
  Rect clip, {
  Map<String, ui.Image> decodedImages = const <String, ui.Image>{},
  Offset? hoverPosition,
  Offset? clickPosition,
  String? hoverOverlayKey,
  String? clickOverlayKey,
}) {
  if (!rect.overlaps(clip)) {
    return;
  }
  if (overlay.kind == 'line') {
    final scaleX = overlay.rect.width == 0
        ? 1.0
        : rect.width / overlay.rect.width;
    final scaleY = overlay.rect.height == 0
        ? 1.0
        : rect.height / overlay.rect.height;
    final lineStart = overlay.lineStart ?? Offset.zero;
    final lineEnd =
        overlay.lineEnd ?? Offset(overlay.rect.width, overlay.rect.height);
    final start =
        rect.topLeft + Offset(lineStart.dx * scaleX, lineStart.dy * scaleY);
    final end = rect.topLeft + Offset(lineEnd.dx * scaleX, lineEnd.dy * scaleY);
    canvas.drawLine(
      start,
      end,
      Paint()
        ..color = overlay.strokeColor ?? const Color(0xff5f6368)
        ..strokeWidth = math.max(1, overlay.strokeWidth)
        ..strokeCap = StrokeCap.round,
    );
    return;
  }
  if (overlay.fillColor != null) {
    final paint = Paint()..color = overlay.fillColor!;
    if (overlay.kind == 'ellipse') {
      canvas.drawOval(rect, paint);
    } else {
      canvas.drawRect(rect, paint);
    }
  }
  if (overlay.placeholderLabel != null) {
    _fortuneDrawRawOverlayPlaceholder(
      canvas,
      rect,
      overlay.placeholderLabel!,
      overlay.chartSeries,
      overlay.chartGraphics,
      overlay.chartLegendLabels,
      overlay.chartXAxisLabels,
      overlay.chartYAxisLabels,
      gridInsets: overlay.chartGridInsets,
      chartTooltipHoverPosition:
          (hoverOverlayKey == null || hoverOverlayKey == overlay.hitKey) &&
              rect.contains(hoverPosition ?? const Offset(-1, -1))
          ? hoverPosition
          : null,
      chartTooltipClickPosition:
          (clickOverlayKey == null || clickOverlayKey == overlay.hitKey) &&
              rect.contains(clickPosition ?? const Offset(-1, -1))
          ? clickPosition
          : null,
      gridBackgroundColor: overlay.chartGridBackgroundColor,
      gridBorderColor: overlay.chartGridBorderColor,
      gridBorderWidth: overlay.chartGridBorderWidth,
      gridBorderType: overlay.chartGridBorderType,
      gridContainLabel: overlay.chartGridContainLabel,
      gridShadowColor: overlay.chartGridShadowColor,
      gridShadowBlur: overlay.chartGridShadowBlur,
      gridShadowOffsetX: overlay.chartGridShadowOffsetX,
      gridShadowOffsetY: overlay.chartGridShadowOffsetY,
