    );
  }
  if (overlay.strokeColor != null && overlay.strokeWidth > 0) {
    final strokePaint = Paint()
      ..color = overlay.strokeColor!
      ..style = PaintingStyle.stroke
      ..strokeWidth = overlay.strokeWidth;
    final strokeRect = rect.deflate(overlay.strokeWidth / 2);
    if (overlay.kind == 'ellipse') {
      canvas.drawOval(strokeRect, strokePaint);
    } else {
      canvas.drawRect(strokeRect, strokePaint);
    }
  }
}

