  String? yAxisNameLocation,
  double? xAxisNameGap,
  double? yAxisNameGap,
  double? xAxisNameRotationDegrees,
  double? yAxisNameRotationDegrees,
}) {
  final chartRect = rect.deflate(10);
  if (chartRect.width <= 12 || chartRect.height <= 12) {
    return;
  }
  final axisPaint = Paint()
    ..color = const Color(0xff5f6368)
    ..strokeWidth = 1.2
    ..style = PaintingStyle.stroke;
  final linePaint = Paint()
    ..color = const Color(0xff0188fb)
    ..strokeWidth = 1.6
    ..style = PaintingStyle.stroke;
  final hasLegend =
      chartSeries.any((series) => series.name != null) ||
      legendLabels.isNotEmpty;
  final visibleChartSeries = _fortuneRawChartVisibleSeries(
    chartSeries,
    legendSelected,
  );
  final dataZoomWindow = dataZoomVisible
      ? _fortuneRawChartDataZoomIndexWindow(
          visibleChartSeries,
          dataZoomStartPercent,
          dataZoomEndPercent,
          dataZoomFilterMode,
          vertical: dataZoomVertical,
        )
      : null;
  final hasXAxisLabels = xAxisLabelVisible && xAxisLabels.isNotEmpty;
  final hasYAxisLabels = yAxisLabelVisible && yAxisLabels.isNotEmpty;
  final xLabelFontSize = xAxisLabelFontSize ?? 8;
  final yLabelFontSize = yAxisLabelFontSize ?? 8;
  final xLabelTextHeight = xAxisLabelLineHeight ?? xLabelFontSize;
  final yLabelTextHeight = yAxisLabelLineHeight ?? yLabelFontSize;
  final legendFontSize = legendTextFontSize ?? 9;
  final defaultLegendItemSize = math.max(7.0, legendFontSize - 2);
  final legendSwatchWidth = legendItemWidth ?? defaultLegendItemSize;
  final legendSwatchHeight = legendItemHeight ?? defaultLegendItemSize;
  final legendGap = legendItemGap ?? 6;
  final effectiveLegendPadding = legendPadding ?? EdgeInsets.zero;
  final legendPositioned =
      legendLeftOffset != null ||
      legendTopOffset != null ||
      legendRightOffset != null ||
      legendBottomOffset != null ||
      legendLeftPercent != null ||
      legendTopPercent != null ||
      legendRightPercent != null ||
      legendBottomPercent != null ||
      legendLeft != null ||
      legendTop != null;
  final xLabelRotation = xAxisLabelRotationDegrees ?? 0;
  final yLabelRotation = yAxisLabelRotationDegrees ?? 0;
  final xLabelMargin = xAxisLabelMargin ?? 3;
  final xLabelSpace = xAxisLabelInside
      ? 8.0
      : (xLabelRotation == 0
            ? xLabelTextHeight + xLabelMargin + 5
            : math.max(
                xLabelTextHeight + xLabelMargin + 5,
                xLabelTextHeight * 2.4,
              ));
  final yLabelSpace = yAxisLabelInside
      ? 2.0
      : (yLabelRotation == 0
            ? math.max(24.0, yLabelTextHeight * 3)
            : math.max(24.0, yLabelTextHeight * 3.4));
  final xNameFontSize = xAxisNameFontSize ?? 8;
  final yNameFontSize = yAxisNameFontSize ?? 8;
  final xNameRotation = xAxisNameRotationDegrees ?? 0;
  final yNameRotation = yAxisNameRotationDegrees ?? 0;
  final hasXAxisName = xAxisName != null;
  final hasYAxisName = yAxisName != null;
  final legendCount = math.max(chartSeries.length, legendLabels.length);
  final legendRowHeight = math.max(legendFontSize, legendSwatchHeight);
  final legendSpace = hasLegend && !legendPositioned
      ? legendVertical
            ? math.max(
                16.0,
                legendCount * legendRowHeight +
                    math.max(0, legendCount - 1) * legendGap +
                    effectiveLegendPadding.vertical +
                    7,
              )
            : math.max(
                16.0,
                legendRowHeight + effectiveLegendPadding.vertical + 7,
              )
      : 0.0;
  final dataZoomSpace = dataZoomVisible && !dataZoomVertical ? 14.0 : 0.0;
  var axisBottom =
      chartRect.bottom -
      legendSpace -
