      yAxisNameTextShadowColor: yAxisNameTextShadowColor,
      xAxisNameTextShadowBlur: xAxisNameTextShadowBlur,
      yAxisNameTextShadowBlur: yAxisNameTextShadowBlur,
      xAxisNameTextShadowOffsetX: xAxisNameTextShadowOffsetX,
      yAxisNameTextShadowOffsetX: yAxisNameTextShadowOffsetX,
      xAxisNameTextShadowOffsetY: xAxisNameTextShadowOffsetY,
      yAxisNameTextShadowOffsetY: yAxisNameTextShadowOffsetY,
      xAxisNameOpacity: xAxisNameOpacity,
      yAxisNameOpacity: yAxisNameOpacity,
      xAxisNameRichStyles: xAxisNameRichStyles,
      yAxisNameRichStyles: yAxisNameRichStyles,
      xAxisNameBackgroundColor: xAxisNameBackgroundColor,
      yAxisNameBackgroundColor: yAxisNameBackgroundColor,
      xAxisNameBorderColor: xAxisNameBorderColor,
      yAxisNameBorderColor: yAxisNameBorderColor,
      xAxisNameBorderWidth: xAxisNameBorderWidth,
      yAxisNameBorderWidth: yAxisNameBorderWidth,
      xAxisNameBorderType: xAxisNameBorderType,
      yAxisNameBorderType: yAxisNameBorderType,
      xAxisNamePadding: xAxisNamePadding,
      yAxisNamePadding: yAxisNamePadding,
      xAxisNameBorderRadius: xAxisNameBorderRadius,
      yAxisNameBorderRadius: yAxisNameBorderRadius,
      xAxisNameWidth: xAxisNameWidth,
      yAxisNameWidth: yAxisNameWidth,
      xAxisNameHeight: xAxisNameHeight,
      yAxisNameHeight: yAxisNameHeight,
      xAxisNameLineHeight: xAxisNameLineHeight,
      yAxisNameLineHeight: yAxisNameLineHeight,
      xAxisNameAlign: xAxisNameAlign,
      yAxisNameAlign: yAxisNameAlign,
      xAxisNameVerticalAlign: xAxisNameVerticalAlign,
      yAxisNameVerticalAlign: yAxisNameVerticalAlign,
      xAxisNameOverflow: xAxisNameOverflow,
      yAxisNameOverflow: yAxisNameOverflow,
      xAxisNameEllipsis: xAxisNameEllipsis,
      yAxisNameEllipsis: yAxisNameEllipsis,
      xAxisNameLocation: xAxisNameLocation,
      yAxisNameLocation: yAxisNameLocation,
      xAxisNameGap: xAxisNameGap,
      yAxisNameGap: yAxisNameGap,
      xAxisNameRotationDegrees: xNameRotation,
      yAxisNameRotationDegrees: yNameRotation,
    );
  }
  if (hasLegend) {
    _fortuneDrawRawChartLegend(
      canvas,
      chartRect,
      axisBottom + (hasXAxisLabels ? 12 : 0),
      chartSeries,
      legendLabels,
      legendTextColor ?? const Color(0xff5f6368),
      legendFontSize,
      legendTextFontWeight ?? FontWeight.w400,
      legendTextFontStyle ?? FontStyle.normal,
      legendTextFontFamily,
      legendTextLineHeight,
      legendTextOpacity,
      legendTextBackgroundColor,
      legendTextBoxBorderColor,
      legendTextBoxBorderWidth,
      legendTextBoxBorderType,
      legendTextBoxBorderRadius,
      legendTextBorderColor,
      legendTextBorderWidth,
      legendTextPadding,
      legendTextWidth,
      legendTextHeight,
      legendTextOverflow,
      legendTextEllipsis,
      legendTextAlign,
      legendTextVerticalAlign,
      legendTextRichStyles,
      legendTextShadowColor,
      legendTextShadowBlur,
      legendTextShadowOffsetX,
      legendTextShadowOffsetY,
      legendFormatter,
      legendSwatchWidth,
      legendSwatchHeight,
      legendGap,
      icon: legendIcon,
      selected: legendSelected,
      inactiveColor: legendInactiveColor,
      shadowColor: legendShadowColor,
      shadowBlur: legendShadowBlur,
      shadowOffsetX: legendShadowOffsetX,
      shadowOffsetY: legendShadowOffsetY,
      backgroundColor: legendBackgroundColor,
      borderColor: legendBorderColor,
      borderWidth: legendBorderWidth,
      borderType: legendBorderType,
      borderRadius: legendBorderRadius,
      padding: effectiveLegendPadding,
      vertical: legendVertical,
      horizontalPosition: legendLeft,
      verticalPosition: legendTop,
      leftOffset: legendLeftOffset,
      topOffset: legendTopOffset,
      rightOffset: legendRightOffset,
      bottomOffset: legendBottomOffset,
      leftPercent: legendLeftPercent,
      topPercent: legendTopPercent,
      rightPercent: legendRightPercent,
      bottomPercent: legendBottomPercent,
    );
  }
  if (dataZoomVisible) {
    _fortuneDrawRawChartDataZoom(
      canvas,
      chartRect,
      legendSpace,
      dataZoomStartPercent,
      dataZoomEndPercent,
      vertical: dataZoomVertical,
      backgroundColor: dataZoomBackgroundColor,
      fillerColor: dataZoomFillerColor,
      handleColor: dataZoomHandleColor,
      borderColor: dataZoomBorderColor,
      borderWidth: dataZoomBorderWidth,
      borderType: dataZoomBorderType,
      size: dataZoomSize,
      handleSize: dataZoomHandleSize,
      handleBorderColor: dataZoomHandleBorderColor,
      handleBorderWidth: dataZoomHandleBorderWidth,
      handleBorderType: dataZoomHandleBorderType,
      handleShadowColor: dataZoomHandleShadowColor,
      handleShadowBlur: dataZoomHandleShadowBlur,
      handleShadowOffsetX: dataZoomHandleShadowOffsetX,
      handleShadowOffsetY: dataZoomHandleShadowOffsetY,
      handleOpacity: dataZoomHandleOpacity,
      showDetail: dataZoomShowDetail,
      showDataShadow: dataZoomShowDataShadow,
      chartSeries: chartSeries,
    );
  }
  if (visualMapVisible) {
    _fortuneDrawRawChartVisualMap(
      canvas,
      chartRect,
      visualMapColors,
      vertical: visualMapVertical,
      inverse: visualMapInverse,
      calculable: visualMapCalculable,
      minLabel: visualMapMinLabel,
      maxLabel: visualMapMaxLabel,
      textColor: visualMapTextColor,
      textBackgroundColor: visualMapTextBackgroundColor,
      textBoxBorderColor: visualMapTextBoxBorderColor,
      textBoxBorderWidth: visualMapTextBoxBorderWidth,
      textBoxBorderType: visualMapTextBoxBorderType,
      textBoxBorderRadius: visualMapTextBoxBorderRadius,
      textBorderColor: visualMapTextBorderColor,
      textBorderWidth: visualMapTextBorderWidth,
      textPadding: visualMapTextPadding,
      textWidth: visualMapTextWidth,
      textHeight: visualMapTextHeight,
      textOverflow: visualMapTextOverflow,
      textEllipsis: visualMapTextEllipsis,
      textAlign: visualMapTextAlign,
      textVerticalAlign: visualMapTextVerticalAlign,
      textRichStyles: visualMapTextRichStyles,
      textFontSize: visualMapTextFontSize,
      textFontWeight: visualMapTextFontWeight,
      textFontStyle: visualMapTextFontStyle,
      textFontFamily: visualMapTextFontFamily,
      textLineHeight: visualMapTextLineHeight,
      textOpacity: visualMapTextOpacity,
      textShadowColor: visualMapTextShadowColor,
      textShadowBlur: visualMapTextShadowBlur,
      textShadowOffsetX: visualMapTextShadowOffsetX,
      textShadowOffsetY: visualMapTextShadowOffsetY,
      itemWidth: visualMapItemWidth,
      itemHeight: visualMapItemHeight,
      backgroundColor: visualMapBackgroundColor,
      borderColor: visualMapBorderColor,
      borderWidth: visualMapBorderWidth,
      borderType: visualMapBorderType,
      padding: visualMapPadding,
      textGap: visualMapTextGap,
      shadowColor: visualMapShadowColor,
      shadowBlur: visualMapShadowBlur,
      shadowOffsetX: visualMapShadowOffsetX,
      shadowOffsetY: visualMapShadowOffsetY,
      horizontalPosition: visualMapLeft,
      verticalPosition: visualMapTop,
      leftOffset: visualMapLeftOffset,
      topOffset: visualMapTopOffset,
      rightOffset: visualMapRightOffset,
      bottomOffset: visualMapBottomOffset,
      leftPercent: visualMapLeftPercent,
      topPercent: visualMapTopPercent,
      rightPercent: visualMapRightPercent,
      bottomPercent: visualMapBottomPercent,
    );
  }
  if (toolboxVisible) {
    _fortuneDrawRawChartToolbox(
      canvas,
      chartRect,
      featureCount: toolboxFeatureCount,
      vertical: toolboxVertical,
      iconColor: toolboxIconColor,
      iconBorderWidth: toolboxIconBorderWidth,
      iconBorderType: toolboxIconBorderType,
      iconOpacity: toolboxIconOpacity,
      iconShadowColor: toolboxIconShadowColor,
      iconShadowBlur: toolboxIconShadowBlur,
      iconShadowOffsetX: toolboxIconShadowOffsetX,
      iconShadowOffsetY: toolboxIconShadowOffsetY,
      iconSize: toolboxIconSize,
      itemGap: toolboxItemGap,
      leftOffset: toolboxLeftOffset,
      topOffset: toolboxTopOffset,
      rightOffset: toolboxRightOffset,
      bottomOffset: toolboxBottomOffset,
      horizontalPosition: toolboxHorizontalPosition,
      verticalPosition: toolboxVerticalPosition,
      leftPercent: toolboxLeftPercent,
      topPercent: toolboxTopPercent,
      rightPercent: toolboxRightPercent,
      bottomPercent: toolboxBottomPercent,
    );
  }
  if (chartGraphics.isNotEmpty) {
    _fortuneDrawRawChartGraphics(
      canvas,
      chartRect,
      chartGraphics,
      decodedImages,
    );
  }
  final shouldPaintTooltip =
      chartTooltipVisible &&
      (chartTooltipAlwaysShowContent == true ||
          chartTooltipInteractionPosition != null);
  if (shouldPaintTooltip) {
    _fortuneDrawRawChartTooltip(
      canvas,
      chartRect,
      plotRect,
      chartSeries,
      xAxisLabels,
      hoverPosition: chartTooltipAlwaysShowContent == true
          ? null
          : chartTooltipInteractionPosition,
      xAxisInverse: xAxisInverse,
      yAxisInverse: yAxisInverse,
      xAxisBoundaryGap: xAxisBoundaryGap,
      trigger: chartTooltipTrigger,
      order: chartTooltipOrder,
      formatter: chartTooltipFormatter,
      position: chartTooltipPosition,
      confine: chartTooltipConfine,
      backgroundColor: chartTooltipBackgroundColor,
      borderColor: chartTooltipBorderColor,
      borderWidth: chartTooltipBorderWidth,
      borderType: chartTooltipBorderType,
      borderRadius: chartTooltipBorderRadius,
      padding: chartTooltipPadding,
      shadowColor: chartTooltipShadowColor,
      shadowBlur: chartTooltipShadowBlur,
      shadowOffsetX: chartTooltipShadowOffsetX,
      shadowOffsetY: chartTooltipShadowOffsetY,
      textColor: chartTooltipTextColor,
      textFontSize: chartTooltipTextFontSize,
      textFontWeight: chartTooltipTextFontWeight,
      textFontStyle: chartTooltipTextFontStyle,
      textFontFamily: chartTooltipTextFontFamily,
      textLineHeight: chartTooltipTextLineHeight,
      textWidth: chartTooltipTextWidth,
      textHeight: chartTooltipTextHeight,
      textAlign: chartTooltipTextAlign,
      textVerticalAlign: chartTooltipTextVerticalAlign,
      textOverflow: chartTooltipTextOverflow,
      textEllipsis: chartTooltipTextEllipsis,
      textBorderColor: chartTooltipTextBorderColor,
      textBorderWidth: chartTooltipTextBorderWidth,
      textShadowColor: chartTooltipTextShadowColor,
      textShadowBlur: chartTooltipTextShadowBlur,
      textShadowOffsetX: chartTooltipTextShadowOffsetX,
      textShadowOffsetY: chartTooltipTextShadowOffsetY,
      textOpacity: chartTooltipTextOpacity,
    );
  }
  final effectiveTitleTextColor =
      _fortuneRawChartColorWithOpacity(
        titleTextColor ?? const Color(0xff5f6368),
        titleTextOpacity,
      ) ??
      titleTextColor ??
      const Color(0xff5f6368);
  final effectiveTitleTextBackgroundColor = _fortuneRawChartColorWithOpacity(
    titleTextBackgroundColor,
    titleTextOpacity,
  );
  final effectiveTitleTextBorderColor = _fortuneRawChartColorWithOpacity(
    titleTextBorderColor,
    titleTextOpacity,
  );
  final effectiveTitleTextShadowColor = _fortuneRawChartColorWithOpacity(
    titleTextShadowColor,
    titleTextOpacity,
  );
  final effectiveTitleSubtextColor =
      _fortuneRawChartColorWithOpacity(
        titleSubtextColor ?? const Color(0xff80868b),
        titleSubtextOpacity,
      ) ??
      titleSubtextColor ??
      const Color(0xff80868b);
  final effectiveTitleSubtextBackgroundColor = _fortuneRawChartColorWithOpacity(
    titleSubtextBackgroundColor,
    titleSubtextOpacity,
  );
  final effectiveTitleSubtextBorderColor = _fortuneRawChartColorWithOpacity(
    titleSubtextBorderColor,
    titleSubtextOpacity,
  );
  final effectiveTitleSubtextShadowColor = _fortuneRawChartColorWithOpacity(
    titleSubtextShadowColor,
    titleSubtextOpacity,
  );
  final textPainter = TextPainter(
    text: TextSpan(
      text: label,
      style: TextStyle(
        color: effectiveTitleTextColor,
        fontSize: titleTextFontSize ?? 11,
        fontWeight: titleTextFontWeight ?? FontWeight.w400,
        fontStyle: titleTextFontStyle ?? FontStyle.normal,
        fontFamily: titleTextFontFamily,
        backgroundColor: effectiveTitleTextBackgroundColor,
        height: _fortuneRawChartLabelHeightRatio(
          titleTextFontSize ?? 11,
          titleTextLineHeight,
        ),
        shadows: _fortuneRawChartLabelShadows(
          effectiveTitleTextShadowColor,
          titleTextShadowBlur,
          titleTextShadowOffsetX,
          titleTextShadowOffsetY,
        ),
      ),
    ),
    maxLines: 1,
    textDirection: TextDirection.ltr,
  )..layout(maxWidth: math.max(0, rect.width - 12));
  final titleStrokePainter = _fortuneRawChartLabelStrokePainter(
    text: label,
    fontSize: titleTextFontSize ?? 11,
    fontWeight: titleTextFontWeight ?? FontWeight.w400,
    fontStyle: titleTextFontStyle ?? FontStyle.normal,
    fontFamily: titleTextFontFamily,
    lineHeight: titleTextLineHeight ?? titleTextFontSize ?? 11,
    textBorderColor: effectiveTitleTextBorderColor,
    textBorderWidth: titleTextBorderWidth,
    overflow: null,
    ellipsis: null,
    maxWidth: math.max(0, rect.width - 12),
  );
  final subtextPainter = titleSubtext == null
      ? null
      : (TextPainter(
          text: TextSpan(
            text: titleSubtext,
            style: TextStyle(
              color: effectiveTitleSubtextColor,
              fontSize: titleSubtextFontSize ?? 9,
              fontWeight: titleSubtextFontWeight ?? FontWeight.w400,
              fontStyle: titleSubtextFontStyle ?? FontStyle.normal,
              fontFamily: titleSubtextFontFamily,
              backgroundColor: effectiveTitleSubtextBackgroundColor,
              height: _fortuneRawChartLabelHeightRatio(
                titleSubtextFontSize ?? 9,
                titleSubtextLineHeight,
              ),
              shadows: _fortuneRawChartLabelShadows(
                effectiveTitleSubtextShadowColor,
                titleSubtextShadowBlur,
                titleSubtextShadowOffsetX,
                titleSubtextShadowOffsetY,
              ),
            ),
          ),
          maxLines: 1,
          textDirection: TextDirection.ltr,
        )..layout(maxWidth: math.max(0, rect.width - 12)));
  final subtextStrokePainter = titleSubtext == null
      ? null
      : _fortuneRawChartLabelStrokePainter(
          text: titleSubtext,
          fontSize: titleSubtextFontSize ?? 9,
          fontWeight: titleSubtextFontWeight ?? FontWeight.w400,
          fontStyle: titleSubtextFontStyle ?? FontStyle.normal,
          fontFamily: titleSubtextFontFamily,
          lineHeight: titleSubtextLineHeight ?? titleSubtextFontSize ?? 9,
          textBorderColor: effectiveTitleSubtextBorderColor,
          textBorderWidth: titleSubtextBorderWidth,
          overflow: null,
          ellipsis: null,
          maxWidth: math.max(0, rect.width - 12),
        );
  final effectiveTitlePadding = titlePadding ?? EdgeInsets.zero;
  final effectiveTitleItemGap = titleItemGap ?? 3;
  final groupWidth = math.max(textPainter.width, subtextPainter?.width ?? 0);
  final groupHeight =
      textPainter.height +
      (subtextPainter == null
          ? 0
          : subtextPainter.height + effectiveTitleItemGap);
  final groupLeft = switch (titleLeft) {
    'left' => rect.left + 6,
    'right' => rect.right - groupWidth - 6,
    _ => rect.left + (rect.width - groupWidth) / 2,
  };
  final positionedGroupLeft = titleLeftPercent == null
      ? titleLeftOffset == null
            ? titleRightPercent == null
                  ? titleRightOffset == null
                        ? groupLeft
                        : rect.right - groupWidth - titleRightOffset
                  : rect.right - groupWidth - rect.width * titleRightPercent
            : rect.left + titleLeftOffset
      : rect.left + rect.width * titleLeftPercent;
  final groupTop = switch (titleTop) {
    'middle' => rect.top + (rect.height - groupHeight) / 2,
    'bottom' => rect.bottom - groupHeight - 6,
    _ => rect.top + 6,
  };
  final positionedGroupTop = titleTopPercent == null
      ? titleTopOffset == null
            ? titleBottomPercent == null
                  ? titleBottomOffset == null
                        ? groupTop
                        : rect.bottom - groupHeight - titleBottomOffset
                  : rect.bottom - groupHeight - rect.height * titleBottomPercent
            : rect.top + titleTopOffset
      : rect.top + rect.height * titleTopPercent;
  final hasExplicitHorizontalPosition =
      titleLeft != null ||
      titleLeftOffset != null ||
      titleLeftPercent != null ||
      titleRightOffset != null ||
      titleRightPercent != null;
  final hasExplicitVerticalPosition =
      titleTop != null ||
      titleTopOffset != null ||
      titleTopPercent != null ||
      titleBottomOffset != null ||
      titleBottomPercent != null;
  final titleOffset = titleLeft == null
      ? Offset(
          !hasExplicitHorizontalPosition
              ? rect.left + (rect.width - textPainter.width) / 2
              : positionedGroupLeft,
          !hasExplicitVerticalPosition ? rect.top + 6 : positionedGroupTop,
        )
      : Offset(
          positionedGroupLeft,
          !hasExplicitVerticalPosition ? rect.top + 6 : positionedGroupTop,
        );
  final titleTextBox = Rect.fromLTWH(
    titleOffset.dx,
    titleOffset.dy,
    textPainter.width,
    textPainter.height,
  );
  final subtextOffset = subtextPainter == null
      ? null
      : !hasExplicitHorizontalPosition
      ? Offset(
          rect.left + (rect.width - subtextPainter.width) / 2,
          titleOffset.dy + textPainter.height + effectiveTitleItemGap,
        )
      : Offset(
          positionedGroupLeft,
          titleOffset.dy + textPainter.height + effectiveTitleItemGap,
        );
  final contentBox = subtextPainter == null || subtextOffset == null
      ? titleTextBox
      : titleTextBox.expandToInclude(
          Rect.fromLTWH(
            subtextOffset.dx,
            subtextOffset.dy,
            subtextPainter.width,
            subtextPainter.height,
          ),
        );
  final titleBox = Rect.fromLTWH(
    contentBox.left - effectiveTitlePadding.left,
    contentBox.top - effectiveTitlePadding.top,
    contentBox.width + effectiveTitlePadding.horizontal,
    contentBox.height + effectiveTitlePadding.vertical,
  );
  final titleRadius = Radius.circular(titleBorderRadius ?? 0);
  final titleRRect = RRect.fromRectAndRadius(titleBox, titleRadius);
  if (titleShadowColor != null) {
    final paint = Paint()
      ..color = titleShadowColor
      ..maskFilter =
          (titleShadowBlur != null &&
              titleShadowBlur.isFinite &&
              titleShadowBlur > 0)
          ? MaskFilter.blur(BlurStyle.normal, titleShadowBlur)
          : null;
    final shadowOffset = Offset(
      titleShadowOffsetX ?? 0,
      titleShadowOffsetY ?? 0,
    );
    if (titleBorderRadius != null && titleBorderRadius > 0) {
      canvas.drawRRect(titleRRect.shift(shadowOffset), paint);
    } else {
      canvas.drawRect(titleBox.shift(shadowOffset), paint);
    }
  }
  if (titleBackgroundColor != null) {
    final paint = Paint()..color = titleBackgroundColor;
    if (titleBorderRadius != null && titleBorderRadius > 0) {
      canvas.drawRRect(titleRRect, paint);
    } else {
      canvas.drawRect(titleBox, paint);
    }
  }
  if (titleBorderColor != null) {
    final width = titleBorderWidth ?? 1;
    final paint = Paint()
      ..color = titleBorderColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = width;
    if (titleBorderRadius != null && titleBorderRadius > 0) {
      final strokeRRect = RRect.fromRectAndRadius(
        titleBox.deflate(width / 2),
        titleRadius,
      );
      if (titleBorderType == 'dashed' || titleBorderType == 'dotted') {
        _fortuneDrawRawChartDashedRRect(
          canvas,
          strokeRRect,
          paint,
          titleBorderType!,
        );
      } else {
        canvas.drawRRect(strokeRRect, paint);
      }
    } else if (titleBorderType == 'dashed' || titleBorderType == 'dotted') {
      _fortuneDrawRawChartDashedRect(
        canvas,
        titleBox.deflate(width / 2),
        paint,
        titleBorderType!,
      );
    } else {
      canvas.drawRect(titleBox.deflate(width / 2), paint);
    }
  }
  if (effectiveTitleTextBackgroundColor != null) {
    canvas.drawRect(
      titleTextBox.inflate(2),
      Paint()..color = effectiveTitleTextBackgroundColor,
    );
  }
  titleStrokePainter?.paint(canvas, titleOffset);
  textPainter.paint(canvas, titleOffset);
  if (subtextPainter != null && subtextOffset != null) {
    if (effectiveTitleSubtextBackgroundColor != null) {
      canvas.drawRect(
        Rect.fromLTWH(
          subtextOffset.dx,
          subtextOffset.dy,
          subtextPainter.width,
          subtextPainter.height,
        ).inflate(2),
        Paint()..color = effectiveTitleSubtextBackgroundColor,
      );
    }
    subtextStrokePainter?.paint(canvas, subtextOffset);
    subtextPainter.paint(canvas, subtextOffset);
  }
}

bool _fortuneRawChartTooltipAllowsHover(String? triggerOn) {
  if (triggerOn == null) {
    return true;
  }
  return triggerOn
      .split('|')
      .map((part) => part.trim().toLowerCase())
      .contains('mousemove');
}

bool _fortuneRawChartTooltipAllowsClick(String? triggerOn) {
  if (triggerOn == null) {
    return true;
  }
  return triggerOn
      .split('|')
      .map((part) => part.trim().toLowerCase())
      .contains('click');
}

void _fortuneDrawRawChartGraphics(
  Canvas canvas,
  Rect chartRect,
  List<FortuneRawChartGraphicElement> graphics,
  Map<String, ui.Image> decodedImages,
) {
  for (final graphic in _fortuneRawChartGraphicsPaintOrder(graphics)) {
    _fortuneDrawRawChartGraphicElement(
      canvas,
      chartRect,
      graphic,
      Offset.zero,
      decodedImages,
      const Size(1, 1),
    );
  }
}

List<FortuneRawChartGraphicElement> _fortuneRawChartGraphicsPaintOrder(
  List<FortuneRawChartGraphicElement> graphics,
) {
  final indexed = <MapEntry<int, FortuneRawChartGraphicElement>>[
    for (var index = 0; index < graphics.length; index += 1)
      MapEntry(index, graphics[index]),
  ];
  indexed.sort((left, right) {
    final leftGraphic = left.value;
    final rightGraphic = right.value;
    final zLevelCompare = (leftGraphic.zLevel ?? 0).compareTo(
      rightGraphic.zLevel ?? 0,
    );
    if (zLevelCompare != 0) {
      return zLevelCompare;
    }
    final zCompare = (leftGraphic.z ?? 0).compareTo(rightGraphic.z ?? 0);
    if (zCompare != 0) {
      return zCompare;
    }
    final z2Compare = (leftGraphic.z2 ?? 0).compareTo(rightGraphic.z2 ?? 0);
    if (z2Compare != 0) {
      return z2Compare;
    }
    return left.key.compareTo(right.key);
  });
  return [for (final entry in indexed) entry.value];
}

void _fortuneDrawRawChartGraphicElement(
  Canvas canvas,
  Rect chartRect,
  FortuneRawChartGraphicElement graphic,
  Offset parentOffset,
  Map<String, ui.Image> decodedImages,
  Size parentStrokeScale,
) {
  if (graphic.ignore == true || graphic.invisible == true) {
    return;
  }
  final width =
      graphic.width ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'width') ??
      _fortuneRawChartGraphicShapeWidth(graphic) ??
      0;
  final height =
      graphic.height ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'height') ??
      _fortuneRawChartGraphicShapeHeight(graphic) ??
      0;
  final position = _fortuneRawChartGraphicPosition(
    chartRect,
    graphic,
    Size(width, height),
    parentOffset,
  );
  final transformOrigin = _fortuneRawChartGraphicTransformOrigin(
    graphic.origin,
    position,
    Size(width, height),
  );
  final scale = _fortuneRawChartGraphicScale(
    graphic.scale,
    graphic.scaleX,
    graphic.scaleY,
  );
  final strokeScale = _fortuneRawChartGraphicAccumulatedStrokeScale(
    parentStrokeScale,
    scale,
  );
  canvas.save();
  if ((graphic.rotation != null && graphic.rotation != 0) || scale != null) {
    canvas.translate(transformOrigin.dx, transformOrigin.dy);
    if (graphic.rotation != null && graphic.rotation != 0) {
      canvas.rotate(graphic.rotation!);
    }
    if (scale != null) {
      canvas.scale(scale.width, scale.height);
    }
    canvas.translate(-transformOrigin.dx, -transformOrigin.dy);
  }
  final clipPath = _fortuneRawChartGraphicClipPath(
    chartRect,
    graphic.clipPath,
    position,
  );
  if (clipPath != null) {
    canvas.clipPath(clipPath);
  }
  switch (graphic.type) {
    case 'rect':
      final rectOffset = Offset(
        _fortuneRawChartGraphicNumber(graphic.shape, 'x') ?? 0,
        _fortuneRawChartGraphicNumber(graphic.shape, 'y') ?? 0,
      );
      _fortuneDrawRawChartGraphicRect(
        canvas,
        Rect.fromLTWH(
          position.dx + rectOffset.dx,
          position.dy + rectOffset.dy,
          width,
          height,
        ),
        graphic,
        strokeScale,
      );
    case 'text':
      _fortuneDrawRawChartGraphicText(canvas, position, graphic);
    case 'image':
      _fortuneDrawRawChartGraphicImage(
        canvas,
        position,
        graphic,
        decodedImages,
      );
    case 'circle':
      _fortuneDrawRawChartGraphicCircle(canvas, position, graphic, strokeScale);
    case 'ellipse':
      _fortuneDrawRawChartGraphicEllipse(
        canvas,
        position,
        graphic,
        strokeScale,
      );
    case 'line':
      _fortuneDrawRawChartGraphicLine(canvas, position, graphic, strokeScale);
    case 'bezierCurve':
    case 'beziercurve':
      _fortuneDrawRawChartGraphicBezierCurve(
        canvas,
        position,
        graphic,
        strokeScale,
      );
    case 'arc':
      _fortuneDrawRawChartGraphicArc(canvas, position, graphic, strokeScale);
    case 'sector':
      _fortuneDrawRawChartGraphicSector(canvas, position, graphic, strokeScale);
    case 'ring':
      _fortuneDrawRawChartGraphicRing(canvas, position, graphic, strokeScale);
    case 'polyline':
      _fortuneDrawRawChartGraphicPolyline(
        canvas,
        position,
        graphic,
        strokeScale,
      );
    case 'polygon':
      _fortuneDrawRawChartGraphicPolygon(
        canvas,
        position,
        graphic,
        strokeScale,
      );
    case 'path':
      _fortuneDrawRawChartGraphicPath(canvas, position, graphic, strokeScale);
    case 'compoundPath':
    case 'compoundpath':
      _fortuneDrawRawChartGraphicCompoundPath(
        canvas,
        position,
        graphic,
        strokeScale,
      );
  }
  _fortuneDrawRawChartGraphicTextContent(canvas, position, graphic);
  for (final child in _fortuneRawChartGraphicsPaintOrder(graphic.children)) {
    _fortuneDrawRawChartGraphicElement(
      canvas,
      chartRect,
      child,
      position,
      decodedImages,
      strokeScale,
    );
  }
  canvas.restore();
}

Size _fortuneRawChartGraphicAccumulatedStrokeScale(
  Size parentScale,
  Size? localScale,
) {
  if (localScale == null) {
    return parentScale;
  }
  return Size(
    parentScale.width * localScale.width,
    parentScale.height * localScale.height,
  );
}

Path? _fortuneRawChartGraphicClipPath(
  Rect chartRect,
  FortuneRawChartGraphicElement? graphic,
  Offset parentOffset,
) {
  if (graphic == null || graphic.ignore == true || graphic.invisible == true) {
    return null;
  }
  final width =
      graphic.width ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'width') ??
      _fortuneRawChartGraphicShapeWidth(graphic) ??
      0;
  final height =
      graphic.height ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'height') ??
      _fortuneRawChartGraphicShapeHeight(graphic) ??
      0;
  final position = _fortuneRawChartGraphicPosition(
    chartRect,
    graphic,
    Size(width, height),
    parentOffset,
  );
  switch (graphic.type) {
    case 'rect':
      final rectOffset = Offset(
        _fortuneRawChartGraphicNumber(graphic.shape, 'x') ?? 0,
        _fortuneRawChartGraphicNumber(graphic.shape, 'y') ?? 0,
      );
      final rect = Rect.fromLTWH(
        position.dx + rectOffset.dx,
        position.dy + rectOffset.dy,
        width,
        height,
      );
      if (rect.width <= 0 || rect.height <= 0) {
        return null;
      }
      final radius = _fortuneRawChartGraphicBorderRadius(graphic);
      final path = Path();
      if (radius > 0) {
        path.addRRect(RRect.fromRectAndRadius(rect, Radius.circular(radius)));
      } else {
        path.addRect(rect);
      }
      return path;
    case 'circle':
      final radius = _fortuneRawChartGraphicNumber(graphic.shape, 'r');
      if (radius == null || radius <= 0) {
        return null;
      }
      return _fortuneRawChartGraphicCirclePath(
        Offset(
          position.dx +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cx') ?? radius),
          position.dy +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cy') ?? radius),
        ),
        radius,
      );
    case 'ellipse':
      final rx = _fortuneRawChartGraphicNumber(graphic.shape, 'rx');
      final ry = _fortuneRawChartGraphicNumber(graphic.shape, 'ry');
      if (rx == null || ry == null || rx <= 0 || ry <= 0) {
        return null;
      }
      return _fortuneRawChartGraphicEllipsePath(
        Offset(
          position.dx +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cx') ?? rx),
          position.dy +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cy') ?? ry),
        ),
        rx,
        ry,
      );
    case 'sector':
      final radius = _fortuneRawChartGraphicNumber(graphic.shape, 'r');
      final startAngle = _fortuneRawChartGraphicNumber(
        graphic.shape,
        'startAngle',
      );
      final endAngle = _fortuneRawChartGraphicNumber(graphic.shape, 'endAngle');
      if (radius == null ||
          radius <= 0 ||
          startAngle == null ||
          endAngle == null) {
        return null;
      }
      final innerRadius = math.max(
        0,
        _fortuneRawChartGraphicNumber(graphic.shape, 'r0') ??
            _fortuneRawChartGraphicNumber(graphic.shape, 'rO') ??
            0,
      );
      return _fortuneRawChartGraphicSectorPath(
        Offset(
          position.dx +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cx') ?? 0),
          position.dy +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cy') ?? 0),
        ),
        radius,
        innerRadius.clamp(0, radius).toDouble(),
        startAngle,
        endAngle - startAngle,
      );
    case 'ring':
      final radius = _fortuneRawChartGraphicNumber(graphic.shape, 'r');
      if (radius == null || radius <= 0) {
        return null;
      }
      final innerRadius = math.max(
        0,
        _fortuneRawChartGraphicNumber(graphic.shape, 'r0') ??
            _fortuneRawChartGraphicNumber(graphic.shape, 'rO') ??
            0,
      );
      return _fortuneRawChartGraphicSectorPath(
        Offset(
          position.dx +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cx') ?? 0),
          position.dy +
              (_fortuneRawChartGraphicNumber(graphic.shape, 'cy') ?? 0),
        ),
        radius,
        innerRadius.clamp(0, radius).toDouble(),
        -math.pi,
        math.pi * 2,
      );
    case 'polygon':
      final points = _fortuneRawChartGraphicPoints(graphic.shape, position);
      if (points.length < 3) {
        return null;
      }
      return _fortuneRawChartGraphicPolylinePath(points)..close();
    case 'path':
      final pathData =
          _fortuneRawChartGraphicString(graphic.shape, 'pathData') ??
          _fortuneRawChartGraphicString(graphic.shape, 'pathdata') ??
          _fortuneRawChartGraphicString(graphic.shape, 'd');
      if (pathData == null) {
        return null;
      }
      return _fortuneRawChartGraphicSvgPath(pathData, position);
    case 'compoundPath':
    case 'compoundpath':
      final rawPaths = _fortuneRawChartGraphicMapValue(graphic.shape, 'paths');
      if (rawPaths is! List) {
        return null;
      }
      final path = Path();
      var hasPath = false;
      for (final rawPath in rawPaths) {
        final pathData = _fortuneRawChartGraphicCompoundPathData(rawPath);
        if (pathData == null) {
          continue;
        }
        final childPath = _fortuneRawChartGraphicSvgPath(pathData, position);
        if (childPath == null) {
          continue;
        }
        path.addPath(childPath, Offset.zero);
        hasPath = true;
      }
      return hasPath ? path : null;
  }
  return null;
}

Offset _fortuneRawChartGraphicPosition(
  Rect chartRect,
  FortuneRawChartGraphicElement graphic,
  Size size,
  Offset parentOffset,
) {
  final hasParent = parentOffset != Offset.zero;
  final origin = hasParent ? parentOffset : chartRect.topLeft;
  final position = _fortuneRawChartGraphicPositionOffset(graphic.position);
  final x = graphic.x ?? position?.dx;
  final y = graphic.y ?? position?.dy;
  final dx = x != null
      ? origin.dx + x
      : _fortuneRawChartGraphicAxisPosition(
          graphic.left,
          graphic.right,
          chartRect.left,
          chartRect.width,
          size.width,
          fallback: origin.dx,
        );
  final dy = y != null
      ? origin.dy + y
      : _fortuneRawChartGraphicAxisPosition(
          graphic.top,
          graphic.bottom,
          chartRect.top,
          chartRect.height,
          size.height,
          fallback: origin.dy,
        );
  return Offset(dx, dy);
}

Offset? _fortuneRawChartGraphicPositionOffset(Object? raw) {
  if (raw is! List || raw.length < 2) {
    return null;
  }
  final x = _fortuneRawShapeDouble(raw[0]);
  final y = _fortuneRawShapeDouble(raw[1]);
  if (x == null || y == null) {
    return null;
  }
  return Offset(x, y);
}

double _fortuneRawChartGraphicAxisPosition(
  Object? leading,
  Object? trailing,
  double start,
  double extent,
  double size, {
  required double fallback,
}) {
  if (_fortuneRawChartGraphicIsCenterOffset(leading)) {
    return start + ((extent - size) / 2);
  }
  final leadingOffset = _fortuneRawChartGraphicOffset(leading, extent);
  if (leadingOffset != null) {
    return start + leadingOffset;
  }
  final trailingOffset = _fortuneRawChartGraphicOffset(trailing, extent);
  if (trailingOffset != null) {
    return start + extent - trailingOffset - size;
  }
  return fallback;
}

bool _fortuneRawChartGraphicIsCenterOffset(Object? raw) {
  if (raw is! String) {
    return false;
  }
  final value = raw.trim().toLowerCase();
  return value == 'center' || value == 'middle';
}

double? _fortuneRawChartGraphicOffset(Object? raw, double extent) {
  if (raw is String) {
    final value = raw.trim().toLowerCase();
    if (value == 'center' || value == 'middle') {
      return extent / 2;
    }
    if (value.endsWith('%')) {
      final percent = double.tryParse(value.substring(0, value.length - 1));
      if (percent != null && percent.isFinite) {
        return extent * percent / 100;
      }
    }
  }
  return _fortuneRawShapeDouble(raw);
}

double? _fortuneRawChartGraphicShapeWidth(
  FortuneRawChartGraphicElement graphic,
) {
  final radius = _fortuneRawChartGraphicNumber(graphic.shape, 'r');
  if (radius != null && radius > 0) {
    return radius * 2;
  }
  final rx = _fortuneRawChartGraphicNumber(graphic.shape, 'rx');
  if (rx != null && rx > 0) {
    return rx * 2;
  }
  return null;
}

double? _fortuneRawChartGraphicShapeHeight(
  FortuneRawChartGraphicElement graphic,
) {
  final radius = _fortuneRawChartGraphicNumber(graphic.shape, 'r');
  if (radius != null && radius > 0) {
    return radius * 2;
  }
  final ry = _fortuneRawChartGraphicNumber(graphic.shape, 'ry');
  if (ry != null && ry > 0) {
    return ry * 2;
  }
  return null;
}

Offset _fortuneRawChartGraphicTransformOrigin(
  Object? raw,
  Offset position,
  Size size,
) {
  if (raw is List && raw.length >= 2) {
    return Offset(
      position.dx +
          (_fortuneRawChartGraphicOriginOffset(raw[0], size.width) ?? 0),
      position.dy +
          (_fortuneRawChartGraphicOriginOffset(raw[1], size.height) ?? 0),
    );
  }
  return position;
}

double? _fortuneRawChartGraphicOriginOffset(Object? raw, double extent) {
  return _fortuneRawChartGraphicOffset(raw, extent);
}

Size? _fortuneRawChartGraphicScale(
  Object? raw,
  double? scaleX,
  double? scaleY,
) {
  if (raw is List && raw.isNotEmpty) {
    final rawScaleX = _fortuneRawShapeDouble(raw.first);
    final rawScaleY = raw.length > 1
        ? _fortuneRawShapeDouble(raw[1])
        : rawScaleX;
    if (rawScaleX == null || rawScaleY == null) {
      return null;
    }
    return Size(rawScaleX, rawScaleY);
  }
  final scale = _fortuneRawShapeDouble(raw);
  if (scale != null) {
    return Size(scale, scale);
  }
  if (scaleX == null && scaleY == null) {
    return null;
  }
  return Size(scaleX ?? 1, scaleY ?? 1);
}

void _fortuneDrawRawChartGraphicRect(
  Canvas canvas,
  Rect rect,
  FortuneRawChartGraphicElement graphic,
  Size strokeScale,
) {
  if (rect.width <= 0 || rect.height <= 0) {
    return;
  }
  final radius = _fortuneRawChartGraphicBorderRadius(graphic);
  final rrect = radius > 0
      ? RRect.fromRectAndRadius(rect, Radius.circular(radius))
      : null;
  final fillColor = _fortuneRawShapeColor(
    _fortuneRawChartGraphicMapValue(graphic.style, 'fill') ??
        _fortuneRawChartGraphicMapValue(graphic.style, 'color'),
  );
  final shadowPaint = _fortuneRawChartGraphicShadowPaint(graphic);
  final strokeFirst = _fortuneRawChartGraphicStrokeFirst(graphic);
  if (shadowPaint != null) {
    final shadowOffset = _fortuneRawChartGraphicShadowOffset(graphic);
    if (rrect == null) {
      canvas.drawRect(rect.shift(shadowOffset), shadowPaint);
    } else {
      canvas.drawRRect(rrect.shift(shadowOffset), shadowPaint);
    }
  }
  if (fillColor != null && !strokeFirst) {
    final fillPaint = Paint()
      ..color = _fortuneRawChartGraphicFillColor(graphic, fillColor)
      ..blendMode = _fortuneRawChartGraphicBlendMode(graphic);
    if (rrect == null) {
      canvas.drawRect(rect, fillPaint);
    } else {
      canvas.drawRRect(rrect, fillPaint);
    }
  }
  final strokeColor = _fortuneRawShapeColor(
    _fortuneRawChartGraphicMapValue(graphic.style, 'stroke'),
  );
  final strokeWidth = _fortuneRawChartGraphicStrokeWidth(graphic, strokeScale);
  if (strokeColor != null && strokeWidth > 0) {
    final strokePaint = Paint()
      ..color = _fortuneRawChartGraphicStrokeColor(graphic, strokeColor)
      ..style = PaintingStyle.stroke
      ..strokeWidth = strokeWidth
      ..blendMode = _fortuneRawChartGraphicBlendMode(graphic);
    final lineCap = _fortuneRawChartGraphicLineCap(graphic.style);
    if (lineCap != null) {
      strokePaint.strokeCap = _fortuneRawChartStrokeCap(lineCap);
    }
    final lineJoin = _fortuneRawChartGraphicLineJoin(graphic.style);
    if (lineJoin != null) {
      strokePaint.strokeJoin = _fortuneRawChartStrokeJoin(lineJoin);
    }
    final miterLimit = _fortuneRawChartGraphicLineMiterLimit(graphic.style);
    if (miterLimit != null) {
      strokePaint.strokeMiterLimit = miterLimit;
    }
    final strokePath = Path();
    final strokeRect = strokeFirst ? rect : rect.deflate(strokeWidth / 2);
    if (rrect == null || strokeFirst) {
      strokePath.addRect(strokeRect);
    } else {
      strokePath.addRRect(rrect.deflate(strokeWidth / 2));
    }
    if (strokeFirst) {
      _fortuneDrawRawChartGraphicStrokePath(
        canvas,
        strokePath,
        strokePaint,
        graphic,
      );
    }
    if (fillColor != null && strokeFirst) {
      final fillPaint = Paint()
        ..color = _fortuneRawChartGraphicFillColor(graphic, fillColor)
        ..blendMode = _fortuneRawChartGraphicBlendMode(graphic);
      if (rrect == null) {
        canvas.drawRect(rect, fillPaint);
      } else {
        canvas.drawRRect(rrect, fillPaint);
      }
    }
    if (!strokeFirst) {
      _fortuneDrawRawChartGraphicStrokePath(
        canvas,
        strokePath,
        strokePaint,
        graphic,
      );
    }
  }
}

void _fortuneDrawRawChartGraphicText(
  Canvas canvas,
  Offset position,
  FortuneRawChartGraphicElement graphic,
) {
  final text = _fortuneRawChartGraphicString(graphic.style, 'text');
  if (text == null) {
    return;
  }
  final color = _fortuneRawChartGraphicFillColor(
    graphic,
    _fortuneRawShapeColor(
          _fortuneRawChartGraphicMapValue(graphic.style, 'fill') ??
              _fortuneRawChartGraphicMapValue(graphic.style, 'textFill') ??
              _fortuneRawChartGraphicMapValue(graphic.style, 'textfill') ??
              _fortuneRawChartGraphicMapValue(graphic.style, 'color'),
        ) ??
        const Color(0xff5f6368),
  );
  final textShadows = _fortuneRawChartGraphicTextShadows(graphic);
  final fontSize = _fortuneRawChartGraphicFontSize(graphic.style) ?? 12;
  final fontWeight = _fortuneRawChartGraphicFontWeight(graphic.style);
  final fontStyle = _fortuneRawChartGraphicFontStyle(graphic.style);
  final fontFamily = _fortuneRawChartGraphicFontFamily(graphic.style);
  final lineHeight = _fortuneRawChartGraphicLineHeight(graphic.style);
  final layoutWidth =
      _fortuneRawChartGraphicNumber(graphic.style, 'width') ?? graphic.width;
  final layoutHeight =
      _fortuneRawChartGraphicNumber(graphic.style, 'height') ?? graphic.height;
  final horizontalAlign = _fortuneRawChartGraphicTextAlign(graphic.style);
  final verticalAlign = _fortuneRawChartGraphicTextVerticalAlign(graphic.style);
  final padding =
      _fortuneRawChartGraphicTextPadding(graphic.style) ?? EdgeInsets.zero;
  final overflow = _fortuneRawChartGraphicTextOverflow(graphic.style);
  final ellipsis = _fortuneRawChartGraphicTextEllipsis(graphic.style);
  final maxLines = overflow == 'truncate' && layoutWidth != null ? 1 : null;
  final painterEllipsis = maxLines == null ? null : ellipsis ?? '...';
  final textPainter =
      TextPainter(
        text: TextSpan(
          text: text,
          style: TextStyle(
            color: color,
            fontSize: fontSize,
            fontWeight: fontWeight,
            fontStyle: fontStyle,
            fontFamily: fontFamily,
            height: _fortuneRawChartLabelHeightRatio(fontSize, lineHeight),
            shadows: textShadows,
          ),
        ),
        textAlign: _fortuneRawChartGraphicFlutterTextAlign(horizontalAlign),
        maxLines: maxLines,
        ellipsis: painterEllipsis,
        textDirection: TextDirection.ltr,
      )..layout(
        minWidth: layoutWidth ?? 0,
        maxWidth: layoutWidth ?? double.infinity,
      );
  var paintOffset = position;
  if (layoutWidth == null) {
    if (horizontalAlign == 'center') {
      paintOffset = paintOffset.translate(-textPainter.width / 2, 0);
    } else if (horizontalAlign == 'right') {
      paintOffset = paintOffset.translate(-textPainter.width, 0);
    }
  }
  final verticalExtent = layoutHeight ?? textPainter.height;
  if (verticalAlign == 'middle') {
    paintOffset = paintOffset.translate(0, -verticalExtent / 2);
  } else if (verticalAlign == 'bottom') {
    paintOffset = paintOffset.translate(0, -verticalExtent);
  }
  final boxRect = Rect.fromLTWH(
    paintOffset.dx - padding.left,
    paintOffset.dy - padding.top,
    (layoutWidth ?? textPainter.width) + padding.horizontal,
    verticalExtent + padding.vertical,
  );
  _fortuneDrawRawChartGraphicTextBox(canvas, boxRect, graphic);
  final textBorderPaint = _fortuneRawChartGraphicTextBorderPaint(graphic);
  if (textBorderPaint != null) {
    final borderPainter =
        TextPainter(
          text: TextSpan(
            text: text,
            style: TextStyle(
              foreground: textBorderPaint,
              fontSize: fontSize,
              fontWeight: fontWeight,
              fontStyle: fontStyle,
              fontFamily: fontFamily,
              height: _fortuneRawChartLabelHeightRatio(fontSize, lineHeight),
              shadows: textShadows,
            ),
          ),
          textAlign: _fortuneRawChartGraphicFlutterTextAlign(horizontalAlign),
          maxLines: maxLines,
          ellipsis: painterEllipsis,
          textDirection: TextDirection.ltr,
        )..layout(
          minWidth: layoutWidth ?? 0,
          maxWidth: layoutWidth ?? double.infinity,
        );
    borderPainter.paint(canvas, paintOffset);
  }
  textPainter.paint(canvas, paintOffset);
}

void _fortuneDrawRawChartGraphicImage(
  Canvas canvas,
  Offset position,
  FortuneRawChartGraphicElement graphic,
  Map<String, ui.Image> decodedImages,
) {
  final source =
      _fortuneRawChartGraphicString(graphic.style, 'image') ??
      _fortuneRawChartGraphicString(graphic.style, 'src') ??
      _fortuneRawChartGraphicString(graphic.shape, 'image') ??
      _fortuneRawChartGraphicString(graphic.shape, 'src');
  if (source == null) {
    return;
  }
  final decoded = decodedImages[source];
  if (decoded == null) {
    return;
  }
  final x =
      _fortuneRawChartGraphicNumber(graphic.style, 'x') ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'x') ??
      0;
  final y =
      _fortuneRawChartGraphicNumber(graphic.style, 'y') ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'y') ??
      0;
  final width =
      _fortuneRawChartGraphicNumber(graphic.style, 'width') ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'width') ??
      graphic.width ??
      decoded.width.toDouble();
  final height =
      _fortuneRawChartGraphicNumber(graphic.style, 'height') ??
      _fortuneRawChartGraphicNumber(graphic.shape, 'height') ??
      graphic.height ??
      decoded.height.toDouble();
  if (width <= 0 || height <= 0) {
    return;
  }
  final rect = Rect.fromLTWH(position.dx + x, position.dy + y, width, height);
  final shadowPaint = _fortuneRawChartGraphicShadowPaint(graphic);
  if (shadowPaint != null) {
    canvas.drawRect(
      rect.shift(_fortuneRawChartGraphicShadowOffset(graphic)),
      shadowPaint,
    );
  }
  final opacity = _fortuneRawChartGraphicOpacity(graphic);
  final paint = Paint()
    ..filterQuality = FilterQuality.medium
    ..blendMode = _fortuneRawChartGraphicBlendMode(graphic)
    ..color = opacity == null
        ? const Color(0xffffffff)
        : Color.fromRGBO(255, 255, 255, opacity);
  canvas.drawImageRect(
    decoded,
    Rect.fromLTWH(0, 0, decoded.width.toDouble(), decoded.height.toDouble()),
    rect,
    paint,
  );
}

void _fortuneDrawRawChartGraphicTextContent(
  Canvas canvas,
  Offset parentPosition,
  FortuneRawChartGraphicElement parent,
) {
  final textGraphic = _fortuneRawChartGraphicTextContentElement(parent);
  if (textGraphic == null || textGraphic.type != 'text') {
    return;
  }
  final textPosition = _fortuneRawChartGraphicTextContentPosition(
    parentPosition,
    parent,
    textGraphic,
  );
  if (textPosition == null) {
    return;
  }
  _fortuneDrawRawChartGraphicText(canvas, textPosition, textGraphic);
}

FortuneRawChartGraphicElement? _fortuneRawChartGraphicTextContentElement(
  FortuneRawChartGraphicElement parent,
) {
  final raw = parent.textContent;
  if (raw is! Map) {
    return null;
  }
  final normalized = Map<Object?, Object?>.from(raw);
  normalized['type'] ??= 'text';
  return _fortuneRawChartGraphicElement(normalized);
}

Offset? _fortuneRawChartGraphicTextContentPosition(
  Offset parentPosition,
  FortuneRawChartGraphicElement parent,
  FortuneRawChartGraphicElement textGraphic,
) {
  final rawPosition = _fortuneRawChartGraphicMapValue(
    parent.textConfig,
    'position',
  )?.toString().trim().toLowerCase();
  final position = rawPosition == null || rawPosition.isEmpty
      ? 'inside'
      : rawPosition;
  final parentOffset = Offset(
    _fortuneRawChartGraphicNumber(parent.shape, 'x') ?? 0,
    _fortuneRawChartGraphicNumber(parent.shape, 'y') ?? 0,
  );
  final width =
      parent.width ??
      _fortuneRawChartGraphicNumber(parent.shape, 'width') ??
      _fortuneRawChartGraphicShapeWidth(parent);
  final height =
      parent.height ??
      _fortuneRawChartGraphicNumber(parent.shape, 'height') ??
      _fortuneRawChartGraphicShapeHeight(parent);
  if (width == null || height == null || width <= 0 || height <= 0) {
    return null;
  }
  final parentRect = Rect.fromLTWH(
    parentPosition.dx + parentOffset.dx,
    parentPosition.dy + parentOffset.dy,
    width,
    height,
  );
  final distance =
      _fortuneRawChartGraphicNumber(parent.textConfig, 'distance') ?? 5;
  final anchor = switch (position) {
    'top' => Offset(parentRect.center.dx, parentRect.top - distance),
    'bottom' => Offset(parentRect.center.dx, parentRect.bottom + distance),
    'left' => Offset(parentRect.left - distance, parentRect.center.dy),
    'right' => Offset(parentRect.right + distance, parentRect.center.dy),
    'topleft' => Offset(parentRect.left - distance, parentRect.top - distance),
    'topright' => Offset(
      parentRect.right + distance,
      parentRect.top - distance,
    ),
    'bottomleft' => Offset(
      parentRect.left - distance,
      parentRect.bottom + distance,
    ),
    'bottomright' => Offset(
      parentRect.right + distance,
      parentRect.bottom + distance,
    ),
    'insidetop' => Offset(parentRect.center.dx, parentRect.top + distance),
    'insidebottom' => Offset(
      parentRect.center.dx,
      parentRect.bottom - distance,
    ),
    'insideleft' => Offset(parentRect.left + distance, parentRect.center.dy),
    'insideright' => Offset(parentRect.right - distance, parentRect.center.dy),
    'insidetopleft' => Offset(
      parentRect.left + distance,
      parentRect.top + distance,
    ),
    'insidetopright' => Offset(
      parentRect.right - distance,
      parentRect.top + distance,
    ),
    'insidebottomleft' => Offset(
      parentRect.left + distance,
      parentRect.bottom - distance,
    ),
    'insidebottomright' => Offset(
      parentRect.right - distance,
      parentRect.bottom - distance,
    ),
    _ when position.startsWith('inside') => parentRect.center,
    _ => null,
  };
  return anchor?.translate(textGraphic.x ?? 0, textGraphic.y ?? 0);
}

void _fortuneDrawRawChartGraphicTextBox(
  Canvas canvas,
  Rect rect,
