  final tokenPattern = RegExp(
    r'[MmLlHhVvCcSsQqTtAaZz]|[-+]?(?:\d+\.\d+|\d+|\.\d+)(?:[eE][-+]?\d+)?',
  );
  final tokens = tokenPattern
      .allMatches(pathData)
      .map((match) => match.group(0)!)
      .toList();
  if (tokens.isEmpty) {
    return null;
  }
  final path = Path();
  var index = 0;
  var command = '';
  var current = position;
  var subpathStart = position;
  Offset? lastCubicControl;
  Offset? lastQuadraticControl;
  var drew = false;

  bool isCommand(String token) => RegExp(r'^[A-Za-z]$').hasMatch(token);

  double? readNumber() {
    if (index >= tokens.length || isCommand(tokens[index])) {
      return null;
    }
    return double.tryParse(tokens[index++]);
  }

  while (index < tokens.length) {
    if (isCommand(tokens[index])) {
      command = tokens[index++];
    }
    if (command.isEmpty) {
      return null;
    }
    switch (command) {
      case 'M':
      case 'm':
        final x = readNumber();
        final y = readNumber();
        if (x == null || y == null) {
          return drew ? path : null;
        }
        current = command == 'm'
            ? current + Offset(x, y)
            : position + Offset(x, y);
        path.moveTo(current.dx, current.dy);
        subpathStart = current;
        lastCubicControl = null;
        lastQuadraticControl = null;
        drew = true;
        command = command == 'm' ? 'l' : 'L';
      case 'L':
      case 'l':
        final x = readNumber();
        final y = readNumber();
        if (x == null || y == null) {
          return drew ? path : null;
        }
        current = command == 'l'
            ? current + Offset(x, y)
            : position + Offset(x, y);
        path.lineTo(current.dx, current.dy);
        lastCubicControl = null;
        lastQuadraticControl = null;
        drew = true;
      case 'H':
      case 'h':
        final x = readNumber();
        if (x == null) {
          return drew ? path : null;
        }
        current = Offset(
          command == 'h' ? current.dx + x : position.dx + x,
          current.dy,
        );
        path.lineTo(current.dx, current.dy);
        lastCubicControl = null;
        lastQuadraticControl = null;
        drew = true;
      case 'V':
      case 'v':
        final y = readNumber();
        if (y == null) {
          return drew ? path : null;
        }
        current = Offset(
          current.dx,
          command == 'v' ? current.dy + y : position.dy + y,
        );
        path.lineTo(current.dx, current.dy);
        lastCubicControl = null;
        lastQuadraticControl = null;
        drew = true;
      case 'C':
      case 'c':
        final x1 = readNumber();
        final y1 = readNumber();
        final x2 = readNumber();
        final y2 = readNumber();
        final x = readNumber();
        final y = readNumber();
        if (x1 == null ||
            y1 == null ||
            x2 == null ||
            y2 == null ||
            x == null ||
            y == null) {
          return drew ? path : null;
        }
        final control1 = command == 'c'
            ? current + Offset(x1, y1)
            : position + Offset(x1, y1);
        final control2 = command == 'c'
            ? current + Offset(x2, y2)
            : position + Offset(x2, y2);
        current = command == 'c'
            ? current + Offset(x, y)
            : position + Offset(x, y);
        path.cubicTo(
          control1.dx,
          control1.dy,
          control2.dx,
          control2.dy,
          current.dx,
          current.dy,
        );
        lastCubicControl = control2;
        lastQuadraticControl = null;
        drew = true;
      case 'S':
      case 's':
        final x2 = readNumber();
        final y2 = readNumber();
        final x = readNumber();
        final y = readNumber();
        if (x2 == null || y2 == null || x == null || y == null) {
          return drew ? path : null;
        }
        final control1 = lastCubicControl == null
            ? current
            : Offset(
                (current.dx * 2) - lastCubicControl.dx,
                (current.dy * 2) - lastCubicControl.dy,
              );
        final control2 = command == 's'
            ? current + Offset(x2, y2)
            : position + Offset(x2, y2);
        current = command == 's'
            ? current + Offset(x, y)
            : position + Offset(x, y);
        path.cubicTo(
          control1.dx,
          control1.dy,
          control2.dx,
          control2.dy,
          current.dx,
          current.dy,
        );
        lastCubicControl = control2;
        lastQuadraticControl = null;
        drew = true;
      case 'Q':
      case 'q':
        final x1 = readNumber();
        final y1 = readNumber();
        final x = readNumber();
        final y = readNumber();
        if (x1 == null || y1 == null || x == null || y == null) {
          return drew ? path : null;
        }
        final control = command == 'q'
            ? current + Offset(x1, y1)
            : position + Offset(x1, y1);
        current = command == 'q'
            ? current + Offset(x, y)
            : position + Offset(x, y);
        path.quadraticBezierTo(control.dx, control.dy, current.dx, current.dy);
        lastCubicControl = null;
        lastQuadraticControl = control;
        drew = true;
      case 'T':
      case 't':
        final x = readNumber();
        final y = readNumber();
        if (x == null || y == null) {
          return drew ? path : null;
        }
        final control = lastQuadraticControl == null
            ? current
            : Offset(
                (current.dx * 2) - lastQuadraticControl.dx,
                (current.dy * 2) - lastQuadraticControl.dy,
              );
        current = command == 't'
            ? current + Offset(x, y)
            : position + Offset(x, y);
        path.quadraticBezierTo(control.dx, control.dy, current.dx, current.dy);
        lastCubicControl = null;
        lastQuadraticControl = control;
        drew = true;
      case 'A':
      case 'a':
        final rx = readNumber();
        final ry = readNumber();
        final axisRotation = readNumber();
        final largeArcFlag = readNumber();
        final sweepFlag = readNumber();
        final x = readNumber();
        final y = readNumber();
        if (rx == null ||
            ry == null ||
            axisRotation == null ||
            largeArcFlag == null ||
            sweepFlag == null ||
            x == null ||
            y == null) {
          return drew ? path : null;
        }
        final end = command == 'a'
            ? current + Offset(x, y)
            : position + Offset(x, y);
        _fortuneRawChartGraphicAppendSvgArc(
          path,
          current,
          end,
          rx.abs(),
          ry.abs(),
          axisRotation,
          largeArcFlag != 0,
          sweepFlag != 0,
        );
        current = end;
        lastCubicControl = null;
        lastQuadraticControl = null;
        drew = true;
      case 'Z':
      case 'z':
        path.close();
        current = subpathStart;
        lastCubicControl = null;
        lastQuadraticControl = null;
        drew = true;
        command = '';
      default:
        return drew ? path : null;
    }
  }
  return drew ? path : null;
}

void _fortuneRawChartGraphicAppendSvgArc(
  Path path,
  Offset start,
  Offset end,
  double rx,
  double ry,
  double axisRotation,
  bool largeArc,
  bool sweep,
) {
  if (rx <= 0 || ry <= 0 || start == end) {
    path.lineTo(end.dx, end.dy);
    return;
  }
  final radians = axisRotation * math.pi / 180;
  final cosPhi = math.cos(radians);
  final sinPhi = math.sin(radians);
  final dx2 = (start.dx - end.dx) / 2;
  final dy2 = (start.dy - end.dy) / 2;
  final x1Prime = (cosPhi * dx2) + (sinPhi * dy2);
  final y1Prime = (-sinPhi * dx2) + (cosPhi * dy2);
  var adjustedRx = rx;
  var adjustedRy = ry;
  final radiusScale =
      (x1Prime * x1Prime) / (adjustedRx * adjustedRx) +
      (y1Prime * y1Prime) / (adjustedRy * adjustedRy);
  if (radiusScale > 1) {
    final scale = math.sqrt(radiusScale);
    adjustedRx *= scale;
    adjustedRy *= scale;
  }
  final rx2 = adjustedRx * adjustedRx;
  final ry2 = adjustedRy * adjustedRy;
  final x1Prime2 = x1Prime * x1Prime;
  final y1Prime2 = y1Prime * y1Prime;
  final centerDenominator = (rx2 * y1Prime2) + (ry2 * x1Prime2);
  if (centerDenominator == 0) {
    path.lineTo(end.dx, end.dy);
    return;
  }
  final centerNumerator = math.max(
    0.0,
    ((rx2 * ry2) - (rx2 * y1Prime2) - (ry2 * x1Prime2)) / centerDenominator,
  );
  final centerSign = largeArc == sweep ? -1.0 : 1.0;
  final centerFactor = centerSign * math.sqrt(centerNumerator);
  final cxPrime = centerFactor * adjustedRx * y1Prime / adjustedRy;
  final cyPrime = -centerFactor * adjustedRy * x1Prime / adjustedRx;
  final center = Offset(
    (cosPhi * cxPrime) - (sinPhi * cyPrime) + ((start.dx + end.dx) / 2),
    (sinPhi * cxPrime) + (cosPhi * cyPrime) + ((start.dy + end.dy) / 2),
  );
  final startVector = Offset(
    (x1Prime - cxPrime) / adjustedRx,
    (y1Prime - cyPrime) / adjustedRy,
  );
  final endVector = Offset(
    (-x1Prime - cxPrime) / adjustedRx,
    (-y1Prime - cyPrime) / adjustedRy,
  );
  final startAngle = _fortuneRawChartGraphicVectorAngle(
    const Offset(1, 0),
    startVector,
  );
  var sweepAngle = _fortuneRawChartGraphicVectorAngle(startVector, endVector);
  if (!sweep && sweepAngle > 0) {
    sweepAngle -= math.pi * 2;
  } else if (sweep && sweepAngle < 0) {
    sweepAngle += math.pi * 2;
  }
  final segmentCount = math.max(1, (sweepAngle.abs() / (math.pi / 2)).ceil());
  final segmentSweep = sweepAngle / segmentCount;
  for (var index = 0; index < segmentCount; index += 1) {
    final theta1 = startAngle + (index * segmentSweep);
    final theta2 = theta1 + segmentSweep;
    _fortuneRawChartGraphicAppendSvgArcSegment(
      path,
      center,
      adjustedRx,
      adjustedRy,
      cosPhi,
      sinPhi,
      theta1,
      theta2,
    );
  }
}

double _fortuneRawChartGraphicVectorAngle(Offset from, Offset to) {
  final denominator = math.sqrt(
    ((from.dx * from.dx) + (from.dy * from.dy)) *
        ((to.dx * to.dx) + (to.dy * to.dy)),
  );
  if (denominator == 0) {
    return 0;
  }
  final dot = ((from.dx * to.dx) + (from.dy * to.dy)) / denominator;
  final clampedDot = dot.clamp(-1.0, 1.0);
  final sign = ((from.dx * to.dy) - (from.dy * to.dx)) < 0 ? -1.0 : 1.0;
  return sign * math.acos(clampedDot);
}

void _fortuneRawChartGraphicAppendSvgArcSegment(
  Path path,
  Offset center,
  double rx,
  double ry,
  double cosPhi,
  double sinPhi,
  double theta1,
  double theta2,
) {
  final alpha = (4 / 3) * math.tan((theta2 - theta1) / 4);
  final point1 = Offset(math.cos(theta1), math.sin(theta1));
  final point2 = Offset(math.cos(theta2), math.sin(theta2));
  final control1 = Offset(
    point1.dx - (alpha * point1.dy),
    point1.dy + (alpha * point1.dx),
  );
  final control2 = Offset(
    point2.dx + (alpha * point2.dy),
    point2.dy - (alpha * point2.dx),
  );
  final transformedControl1 = _fortuneRawChartGraphicSvgArcPoint(
    control1,
    center,
    rx,
    ry,
    cosPhi,
    sinPhi,
  );
  final transformedControl2 = _fortuneRawChartGraphicSvgArcPoint(
    control2,
    center,
    rx,
    ry,
    cosPhi,
    sinPhi,
  );
  final transformedPoint2 = _fortuneRawChartGraphicSvgArcPoint(
    point2,
    center,
    rx,
    ry,
    cosPhi,
    sinPhi,
  );
  path.cubicTo(
    transformedControl1.dx,
    transformedControl1.dy,
    transformedControl2.dx,
    transformedControl2.dy,
    transformedPoint2.dx,
    transformedPoint2.dy,
  );
}

Offset _fortuneRawChartGraphicSvgArcPoint(
  Offset point,
  Offset center,
  double rx,
  double ry,
  double cosPhi,
  double sinPhi,
) {
  return Offset(
    center.dx + (rx * ((cosPhi * point.dx) - (sinPhi * point.dy))),
    center.dy + (ry * ((sinPhi * point.dx) + (cosPhi * point.dy))),
  );
}

