FontWeight? _fortuneRawChartGraphicFontWeightFromFont(Object? style) {
  final prefix = _fortuneRawChartGraphicFontPrefix(style);
  if (prefix == null) {
    return null;
  }
  final tokens = prefix.split(RegExp(r'\s+'));
  for (final token in tokens) {
    final value = token.trim().toLowerCase();
    if (value == 'bold' || value == 'bolder') {
      return FontWeight.w700;
    }
    if (value == 'lighter') {
      return FontWeight.w300;
    }
    final numeric = int.tryParse(value);
    if (numeric != null) {
      return _fortuneRawChartNumericFontWeight(numeric);
    }
  }
  return null;
}

