  return null;
}

String? _fortuneRawChartGraphicFontFamilyFromFont(Object? style) {
  final font = _fortuneRawChartGraphicString(style, 'font');
  final match = _fortuneRawChartGraphicFontSizeMatch(style);
  if (font == null || match == null) {
    return null;
  }
  var family = font.substring(match.end).trim();
  if (family.isEmpty) {
    return null;
  }
  if ((family.startsWith('"') && family.endsWith('"')) ||
      (family.startsWith("'") && family.endsWith("'"))) {
    family = family.substring(1, family.length - 1).trim();
  }
  return family.isEmpty ? null : family;
}

