}

String? _fortuneRawChartGraphicLineCap(Object? style) {
  return _fortuneRawChartLineCap(
    _fortuneRawChartGraphicMapValue(style, 'lineCap') ??
        _fortuneRawChartGraphicMapValue(style, 'linecap') ??
        _fortuneRawChartGraphicMapValue(style, 'cap'),
  );
}

String? _fortuneRawChartGraphicLineJoin(Object? style) {
  final rawJoin =
      _fortuneRawChartGraphicMapValue(style, 'lineJoin') ??
      _fortuneRawChartGraphicMapValue(style, 'linejoin') ??
      _fortuneRawChartGraphicMapValue(style, 'join');
  if (rawJoin == null) {
    return null;
  }
  final join = '$rawJoin'.trim().toLowerCase();
  if (join == 'bevel' || join == 'round' || join == 'miter') {
    return join;
  }
  return null;
}

double? _fortuneRawChartGraphicLineMiterLimit(Object? style) {
  final limit =
      _fortuneRawChartGraphicNumber(style, 'miterLimit') ??
      _fortuneRawChartGraphicNumber(style, 'miterlimit');
  if (limit == null || !limit.isFinite || limit <= 0) {
    return null;
  }
  return limit;
}

bool _fortuneRawChartGraphicStrokeFirst(FortuneRawChartGraphicElement graphic) {
  return fortuneRawBool(
        _fortuneRawChartGraphicMapValue(graphic.style, 'strokeFirst') ??
            _fortuneRawChartGraphicMapValue(graphic.style, 'strokefirst'),
      ) ??
      false;
}

bool _fortuneRawChartGraphicStrokeNoScale(
  FortuneRawChartGraphicElement graphic,
) {
  return fortuneRawBool(
        _fortuneRawChartGraphicMapValue(graphic.style, 'strokeNoScale') ??
            _fortuneRawChartGraphicMapValue(graphic.style, 'strokenoscale'),
      ) ??
      false;
}

double _fortuneRawChartGraphicBorderRadius(
  FortuneRawChartGraphicElement graphic,
) {
  final rawRadius = _fortuneRawChartGraphicMapValue(graphic.shape, 'r');
  final radius = rawRadius is List && rawRadius.isNotEmpty
      ? _fortuneRawShapeDouble(rawRadius.first)
      : _fortuneRawShapeDouble(rawRadius);
  if (radius == null || !radius.isFinite || radius <= 0) {
    return 0;
  }
  return radius;
}

Color _fortuneRawChartGraphicColor(
  FortuneRawChartGraphicElement graphic,
  Color color,
) {
  return _fortuneRawChartGraphicColorWithOpacity(graphic, color, null);
}

Color _fortuneRawChartGraphicFillColor(
  FortuneRawChartGraphicElement graphic,
  Color color,
) {
  return _fortuneRawChartGraphicColorWithOpacity(
    graphic,
    color,
    _fortuneRawChartGraphicFillOpacity(graphic),
  );
}

Color _fortuneRawChartGraphicStrokeColor(
  FortuneRawChartGraphicElement graphic,
  Color color,
) {
  return _fortuneRawChartGraphicColorWithOpacity(
    graphic,
    color,
    _fortuneRawChartGraphicStrokeOpacity(graphic),
  );
}

Color _fortuneRawChartGraphicColorWithOpacity(
  FortuneRawChartGraphicElement graphic,
  Color color,
  double? channelOpacity,
) {
  final opacity = _fortuneRawChartGraphicCombinedOpacity(
    _fortuneRawChartGraphicOpacity(graphic),
    channelOpacity,
  );
  return _fortuneRawChartColorWithOpacity(color, opacity) ?? color;
}

double? _fortuneRawChartGraphicCombinedOpacity(
  double? opacity,
  double? channelOpacity,
) {
  if (opacity == null) {
    return channelOpacity;
  }
  if (channelOpacity == null) {
    return opacity;
  }
  return (opacity * channelOpacity).clamp(0, 1).toDouble();
}

double? _fortuneRawChartGraphicOpacity(FortuneRawChartGraphicElement graphic) {
  return _fortuneRawChartGraphicOpacityValue(graphic.style, 'opacity');
}

double? _fortuneRawChartGraphicFillOpacity(
  FortuneRawChartGraphicElement graphic,
) {
  return _fortuneRawChartGraphicOpacityValue(graphic.style, 'fillOpacity') ??
      _fortuneRawChartGraphicOpacityValue(graphic.style, 'fillopacity');
}

double? _fortuneRawChartGraphicStrokeOpacity(
  FortuneRawChartGraphicElement graphic,
) {
  return _fortuneRawChartGraphicOpacityValue(graphic.style, 'strokeOpacity') ??
      _fortuneRawChartGraphicOpacityValue(graphic.style, 'strokeopacity');
}

double? _fortuneRawChartGraphicOpacityValue(Object? style, String key) {
  final opacity = _fortuneRawChartGraphicNumber(style, key);
  if (opacity == null || !opacity.isFinite) {
    return null;
  }
  return opacity.clamp(0, 1).toDouble();
}

Paint? _fortuneRawChartGraphicShadowPaint(
  FortuneRawChartGraphicElement graphic,
) {
  final shadowColor = _fortuneRawShapeColor(
    _fortuneRawChartGraphicMapValue(graphic.style, 'shadowColor') ??
        _fortuneRawChartGraphicMapValue(graphic.style, 'shadowcolor'),
  );
  final shadowBlur =
      _fortuneRawChartGraphicNumber(graphic.style, 'shadowBlur') ??
      _fortuneRawChartGraphicNumber(graphic.style, 'shadowblur') ??
      0;
  if (shadowColor == null || shadowBlur <= 0) {
    return null;
  }
  return Paint()
    ..color = _fortuneRawChartGraphicColor(graphic, shadowColor)
    ..blendMode = _fortuneRawChartGraphicBlendMode(graphic)
    ..maskFilter = MaskFilter.blur(BlurStyle.normal, shadowBlur);
}

BlendMode _fortuneRawChartGraphicBlendMode(
  FortuneRawChartGraphicElement graphic,
) {
  final raw =
      _fortuneRawChartGraphicMapValue(graphic.style, 'blendMode') ??
      _fortuneRawChartGraphicMapValue(graphic.style, 'blendmode') ??
      _fortuneRawChartGraphicMapValue(graphic.style, 'blend');
  return _fortuneRawChartBlendMode(raw?.toString());
}

Offset _fortuneRawChartGraphicShadowOffset(
  FortuneRawChartGraphicElement graphic,
) {
  return Offset(
    _fortuneRawChartGraphicNumber(graphic.style, 'shadowOffsetX') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'shadowoffsetx') ??
        0,
    _fortuneRawChartGraphicNumber(graphic.style, 'shadowOffsetY') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'shadowoffsety') ??
        0,
  );
}

List<Shadow>? _fortuneRawChartGraphicTextShadows(
  FortuneRawChartGraphicElement graphic,
) {
  final shadowColor = _fortuneRawShapeColor(
    _fortuneRawChartGraphicMapValue(graphic.style, 'textShadowColor') ??
        _fortuneRawChartGraphicMapValue(graphic.style, 'textshadowcolor') ??
        _fortuneRawChartGraphicMapValue(graphic.style, 'shadowColor') ??
        _fortuneRawChartGraphicMapValue(graphic.style, 'shadowcolor'),
  );
  final shadowBlur =
      _fortuneRawChartGraphicNumber(graphic.style, 'textShadowBlur') ??
      _fortuneRawChartGraphicNumber(graphic.style, 'textshadowblur') ??
      _fortuneRawChartGraphicNumber(graphic.style, 'shadowBlur') ??
      _fortuneRawChartGraphicNumber(graphic.style, 'shadowblur') ??
      0;
  if (shadowColor == null || shadowBlur <= 0) {
    return null;
  }
  return [
    Shadow(
      color: _fortuneRawChartGraphicColor(graphic, shadowColor),
      blurRadius: shadowBlur,
      offset: _fortuneRawChartGraphicTextShadowOffset(graphic),
    ),
  ];
}

Offset _fortuneRawChartGraphicTextShadowOffset(
  FortuneRawChartGraphicElement graphic,
) {
  return Offset(
    _fortuneRawChartGraphicNumber(graphic.style, 'textShadowOffsetX') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'textshadowoffsetx') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'shadowOffsetX') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'shadowoffsetx') ??
        0,
    _fortuneRawChartGraphicNumber(graphic.style, 'textShadowOffsetY') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'textshadowoffsety') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'shadowOffsetY') ??
        _fortuneRawChartGraphicNumber(graphic.style, 'shadowoffsety') ??
        0,
  );
}

Object? _fortuneRawChartGraphicMapValue(Object? raw, String key) {
  if (raw is! Map) {
    return null;
  }
  return raw[key] ?? raw[key.toLowerCase()];
}

String? _fortuneRawChartGraphicString(Object? raw, String key) {
  return _fortuneRawChartNonEmptyString(
    _fortuneRawChartGraphicMapValue(raw, key),
  );
}

double? _fortuneRawChartGraphicNumber(Object? raw, String key) {
  return _fortuneRawShapeDouble(_fortuneRawChartGraphicMapValue(raw, key));
}

void _fortuneDrawRawChartAxisNames(
  Canvas canvas,
  Rect chartRect,
  double axisLeft,
  double axisBottom, {
  required double plotAxisLeft,
  required double plotAxisBottom,
  required String? xAxisName,
  required String? yAxisName,
  required Color xAxisNameColor,
  required Color yAxisNameColor,
  required double xAxisNameFontSize,
  required double yAxisNameFontSize,
  required FontWeight xAxisNameFontWeight,
  required FontWeight yAxisNameFontWeight,
  required FontStyle xAxisNameFontStyle,
  required FontStyle yAxisNameFontStyle,
  required String? xAxisNameFontFamily,
  required String? yAxisNameFontFamily,
  required Color? xAxisNameTextBorderColor,
  required Color? yAxisNameTextBorderColor,
  required double? xAxisNameTextBorderWidth,
  required double? yAxisNameTextBorderWidth,
  required Color? xAxisNameTextShadowColor,
  required Color? yAxisNameTextShadowColor,
  required double? xAxisNameTextShadowBlur,
  required double? yAxisNameTextShadowBlur,
  required double? xAxisNameTextShadowOffsetX,
  required double? yAxisNameTextShadowOffsetX,
  required double? xAxisNameTextShadowOffsetY,
  required double? yAxisNameTextShadowOffsetY,
  required double? xAxisNameOpacity,
  required double? yAxisNameOpacity,
  required Map<String, FortuneRawChartRichTextStyle> xAxisNameRichStyles,
  required Map<String, FortuneRawChartRichTextStyle> yAxisNameRichStyles,
  required Color? xAxisNameBackgroundColor,
  required Color? yAxisNameBackgroundColor,
  required Color? xAxisNameBorderColor,
  required Color? yAxisNameBorderColor,
  required double? xAxisNameBorderWidth,
  required double? yAxisNameBorderWidth,
  required String? xAxisNameBorderType,
  required String? yAxisNameBorderType,
  required EdgeInsets? xAxisNamePadding,
  required EdgeInsets? yAxisNamePadding,
  required double? xAxisNameBorderRadius,
  required double? yAxisNameBorderRadius,
  required double? xAxisNameWidth,
  required double? yAxisNameWidth,
  required double? xAxisNameHeight,
  required double? yAxisNameHeight,
  required double? xAxisNameLineHeight,
  required double? yAxisNameLineHeight,
  required String? xAxisNameAlign,
  required String? yAxisNameAlign,
  required String? xAxisNameVerticalAlign,
  required String? yAxisNameVerticalAlign,
  required String? xAxisNameOverflow,
  required String? yAxisNameOverflow,
  required String? xAxisNameEllipsis,
  required String? yAxisNameEllipsis,
  required String? xAxisNameLocation,
  required String? yAxisNameLocation,
  required double? xAxisNameGap,
  required double? yAxisNameGap,
  required double xAxisNameRotationDegrees,
  required double yAxisNameRotationDegrees,
}) {
  if (xAxisName != null) {
    final nameColor =
        _fortuneRawChartColorWithOpacity(xAxisNameColor, xAxisNameOpacity) ??
        xAxisNameColor;
    final nameBackgroundColor = _fortuneRawChartColorWithOpacity(
      xAxisNameBackgroundColor,
      xAxisNameOpacity,
    );
    final nameBorderColor = _fortuneRawChartColorWithOpacity(
      xAxisNameBorderColor,
      xAxisNameOpacity,
    );
    final nameTextBorderColor = _fortuneRawChartColorWithOpacity(
      xAxisNameTextBorderColor,
      xAxisNameOpacity,
    );
    final nameTextShadowColor = _fortuneRawChartColorWithOpacity(
      xAxisNameTextShadowColor,
      xAxisNameOpacity,
    );
    final maxWidth = _fortuneRawChartLabelMaxWidth(
      math.max(0, chartRect.width / 2),
      xAxisNameWidth,
      xAxisNameOverflow,
    );
    final painter = _fortuneRawChartLabelFillPainter(
      text: xAxisName,
      color: nameColor,
      fontSize: xAxisNameFontSize,
      fontWeight: xAxisNameFontWeight,
      fontStyle: xAxisNameFontStyle,
      fontFamily: xAxisNameFontFamily,
      backgroundColor: null,
      lineHeight: xAxisNameLineHeight,
      textShadowColor: nameTextShadowColor,
      textShadowBlur: xAxisNameTextShadowBlur,
      textShadowOffsetX: xAxisNameTextShadowOffsetX,
      textShadowOffsetY: xAxisNameTextShadowOffsetY,
      overflow: xAxisNameOverflow,
      ellipsis: xAxisNameEllipsis,
      richStyles: xAxisNameRichStyles,
      maxWidth: maxWidth,
    );
    final strokePainter = _fortuneRawChartLabelStrokePainter(
      text: xAxisName,
      fontSize: xAxisNameFontSize,
      fontWeight: xAxisNameFontWeight,
      fontStyle: xAxisNameFontStyle,
      fontFamily: xAxisNameFontFamily,
      lineHeight: xAxisNameLineHeight,
      textBorderColor: nameTextBorderColor,
      textBorderWidth: xAxisNameTextBorderWidth,
      overflow: xAxisNameOverflow,
      ellipsis: xAxisNameEllipsis,
      maxWidth: maxWidth,
    );
    final boxWidth = math.max(painter.width, xAxisNameWidth ?? 0);
    final xOffset = switch (xAxisNameLocation ?? 'end') {
      'start' => plotAxisLeft,
      'middle' =>
        plotAxisLeft +
            math.max(0.0, (chartRect.right - plotAxisLeft - boxWidth) / 2),
      _ => chartRect.right - boxWidth,
    };
    final yOffset = axisBottom + (xAxisNameGap ?? xAxisNameFontSize + 5);
    _fortunePaintRawChartLabel(
      canvas,
      painter,
      strokePainter,
      Offset(xOffset, yOffset),
      nameBackgroundColor,
      nameBorderColor,
      xAxisNameBorderWidth,
      xAxisNamePadding,
      xAxisNameBorderRadius,
      xAxisNameWidth,
      xAxisNameHeight,
      xAxisNameAlign,
      xAxisNameVerticalAlign,
      xAxisNameRotationDegrees,
      xAxisNameBorderType,
    );
  }
  if (yAxisName != null) {
    final nameColor =
        _fortuneRawChartColorWithOpacity(yAxisNameColor, yAxisNameOpacity) ??
        yAxisNameColor;
    final nameBackgroundColor = _fortuneRawChartColorWithOpacity(
      yAxisNameBackgroundColor,
      yAxisNameOpacity,
    );
    final nameBorderColor = _fortuneRawChartColorWithOpacity(
      yAxisNameBorderColor,
      yAxisNameOpacity,
    );
    final nameTextBorderColor = _fortuneRawChartColorWithOpacity(
      yAxisNameTextBorderColor,
      yAxisNameOpacity,
    );
    final nameTextShadowColor = _fortuneRawChartColorWithOpacity(
      yAxisNameTextShadowColor,
      yAxisNameOpacity,
    );
    final maxWidth = _fortuneRawChartLabelMaxWidth(
      math.max(0, axisLeft - chartRect.left - 1),
      yAxisNameWidth,
      yAxisNameOverflow,
    );
    final painter = _fortuneRawChartLabelFillPainter(
      text: yAxisName,
      color: nameColor,
      fontSize: yAxisNameFontSize,
      fontWeight: yAxisNameFontWeight,
      fontStyle: yAxisNameFontStyle,
      fontFamily: yAxisNameFontFamily,
      backgroundColor: null,
      lineHeight: yAxisNameLineHeight,
      textShadowColor: nameTextShadowColor,
      textShadowBlur: yAxisNameTextShadowBlur,
      textShadowOffsetX: yAxisNameTextShadowOffsetX,
      textShadowOffsetY: yAxisNameTextShadowOffsetY,
      overflow: yAxisNameOverflow,
      ellipsis: yAxisNameEllipsis,
      richStyles: yAxisNameRichStyles,
      maxWidth: maxWidth,
    );
    final strokePainter = _fortuneRawChartLabelStrokePainter(
      text: yAxisName,
      fontSize: yAxisNameFontSize,
      fontWeight: yAxisNameFontWeight,
      fontStyle: yAxisNameFontStyle,
      fontFamily: yAxisNameFontFamily,
      lineHeight: yAxisNameLineHeight,
      textBorderColor: nameTextBorderColor,
      textBorderWidth: yAxisNameTextBorderWidth,
      overflow: yAxisNameOverflow,
      ellipsis: yAxisNameEllipsis,
      maxWidth: maxWidth,
    );
    final boxWidth = math.max(painter.width, yAxisNameWidth ?? 0);
    final boxHeight = math.max(painter.height, yAxisNameHeight ?? 0);
    final yOffset = switch (yAxisNameLocation ?? 'end') {
      'start' => plotAxisBottom - boxHeight,
      'middle' =>
        chartRect.top +
            math.max(0.0, (plotAxisBottom - chartRect.top - boxHeight) / 2),
      _ => chartRect.top + 1,
    };
    final xOffset = yAxisNameGap == null
        ? chartRect.left + 1
        : axisLeft - yAxisNameGap - boxWidth;
    _fortunePaintRawChartLabel(
      canvas,
      painter,
      strokePainter,
      Offset(xOffset, yOffset),
      nameBackgroundColor,
      nameBorderColor,
      yAxisNameBorderWidth,
      yAxisNamePadding,
      yAxisNameBorderRadius,
      yAxisNameWidth,
      yAxisNameHeight,
      yAxisNameAlign,
      yAxisNameVerticalAlign,
      yAxisNameRotationDegrees,
      yAxisNameBorderType,
    );
  }
}

void _fortuneDrawRawChartDataZoom(
  Canvas canvas,
  Rect chartRect,
  double legendSpace,
  double? startPercent,
  double? endPercent, {
  bool vertical = false,
  Color? backgroundColor,
  Color? fillerColor,
  Color? handleColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  double? size,
  double? handleSize,
  Color? handleBorderColor,
  double? handleBorderWidth,
  String? handleBorderType,
  Color? handleShadowColor,
  double? handleShadowBlur,
  double? handleShadowOffsetX,
  double? handleShadowOffsetY,
  double? handleOpacity,
  bool? showDetail,
  Object? showDataShadow,
  List<FortuneRawChartSeries> chartSeries = const [],
}) {
  final double trackSize = size == null || !size.isFinite
      ? 5.0
      : size.clamp(1.0, 40.0).toDouble();
  final double resolvedHandleSize = handleSize == null || !handleSize.isFinite
      ? math.max(10, trackSize + 5).toDouble()
      : handleSize.clamp(1.0, 60.0).toDouble();
  final double handleThickness = math.max(3, trackSize / 2).toDouble();
  final trackLength = math.max(
    0.0,
    vertical ? chartRect.height * 0.68 : chartRect.width * 0.72,
  );
  if (trackLength <= 0) {
    return;
  }
  final trackRect = vertical
      ? Rect.fromLTWH(
          chartRect.right - 8,
          chartRect.top + (chartRect.height - trackLength) / 2,
          trackSize,
          trackLength,
        )
      : Rect.fromLTWH(
          chartRect.left + (chartRect.width - trackLength) / 2,
          chartRect.bottom - legendSpace - 11,
          trackLength,
          trackSize,
        );
  final start = (startPercent ?? 0).clamp(0, 100).toDouble();
  final end = math.max(start, (endPercent ?? 100).clamp(0, 100).toDouble());
  final fillRect = vertical
      ? Rect.fromLTRB(
          trackRect.left,
          trackRect.top + trackRect.height * start / 100,
          trackRect.right,
          trackRect.top + trackRect.height * end / 100,
        )
      : Rect.fromLTRB(
          trackRect.left + trackRect.width * start / 100,
          trackRect.top,
          trackRect.left + trackRect.width * end / 100,
          trackRect.bottom,
        );
  final radius = Radius.circular(
    math.min(trackRect.width, trackRect.height) / 2,
  );
  canvas.drawRRect(
    RRect.fromRectAndRadius(trackRect, radius),
    Paint()..color = backgroundColor ?? const Color(0xffe8eaed),
  );
  _fortuneDrawRawChartDataZoomShadow(
    canvas,
    trackRect,
    chartSeries,
    showDataShadow,
    vertical: vertical,
  );
  final resolvedBorderWidth = borderWidth ?? 0;
  if (borderColor != null && resolvedBorderWidth > 0) {
    final borderPaint = Paint()
      ..color = borderColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = resolvedBorderWidth;
    if (borderType == 'dashed' || borderType == 'dotted') {
      _fortuneDrawRawChartDashedRRect(
        canvas,
        RRect.fromRectAndRadius(
          trackRect.deflate(resolvedBorderWidth / 2),
          radius,
        ),
        borderPaint,
        borderType!,
      );
    } else {
      canvas.drawRRect(RRect.fromRectAndRadius(trackRect, radius), borderPaint);
    }
  }
  if (fillRect.width > 0) {
    canvas.drawRRect(
      RRect.fromRectAndRadius(fillRect, radius),
      Paint()..color = fillerColor ?? const Color(0xffa8c7fa),
    );
  }
  final resolvedHandleColor = _fortuneRawChartColorWithOpacity(
    handleColor ?? const Color(0xff5f6368),
    handleOpacity,
  )!;
  final resolvedHandleBorderColor = _fortuneRawChartColorWithOpacity(
    handleBorderColor,
    handleOpacity,
  );
  final resolvedHandleShadowColor = _fortuneRawChartColorWithOpacity(
    handleShadowColor,
    handleOpacity,
  );
  final handlePaint = Paint()..color = resolvedHandleColor;
  final resolvedHandleBorderWidth = handleBorderWidth ?? 0;
  final handleShadowPaint = resolvedHandleShadowColor == null
      ? null
      : (Paint()
          ..color = resolvedHandleShadowColor
          ..maskFilter =
              (handleShadowBlur != null &&
                  handleShadowBlur.isFinite &&
                  handleShadowBlur > 0)
              ? MaskFilter.blur(BlurStyle.normal, handleShadowBlur)
              : null);
  final handleShadowOffset = Offset(
    handleShadowOffsetX ?? 0,
    handleShadowOffsetY ?? 0,
  );
  final handleCenters = vertical
      ? [
          Offset(trackRect.center.dx, fillRect.top),
          Offset(trackRect.center.dx, fillRect.bottom),
        ]
      : [
          Offset(fillRect.left, trackRect.center.dy),
          Offset(fillRect.right, trackRect.center.dy),
        ];
  for (final center in handleCenters) {
    final handleRect = Rect.fromCenter(
      center: center,
      width: vertical ? resolvedHandleSize : handleThickness,
      height: vertical ? handleThickness : resolvedHandleSize,
    );
    if (handleShadowPaint != null) {
      canvas.drawRRect(
        RRect.fromRectAndRadius(
          handleRect.shift(handleShadowOffset),
          const Radius.circular(1.5),
        ),
        handleShadowPaint,
      );
    }
    canvas.drawRRect(
      RRect.fromRectAndRadius(handleRect, const Radius.circular(1.5)),
      handlePaint,
    );
    if (resolvedHandleBorderColor != null && resolvedHandleBorderWidth > 0) {
      final handleBorderPaint = Paint()
        ..color = resolvedHandleBorderColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = resolvedHandleBorderWidth;
      if (handleBorderType == 'dashed' || handleBorderType == 'dotted') {
        _fortuneDrawRawChartDashedRect(
          canvas,
          handleRect.deflate(resolvedHandleBorderWidth / 2),
          handleBorderPaint,
          handleBorderType!,
        );
      } else {
        canvas.drawRRect(
          RRect.fromRectAndRadius(handleRect, const Radius.circular(1.5)),
          handleBorderPaint,
        );
      }
    }
  }
  if (showDetail != false) {
    _fortuneDrawRawChartDataZoomDetails(
      canvas,
      trackRect,
      fillRect,
      start,
      end,
      vertical: vertical,
    );
  }
}

void _fortuneDrawRawChartDataZoomDetails(
  Canvas canvas,
  Rect trackRect,
  Rect fillRect,
  double start,
  double end, {
  required bool vertical,
}) {
  void drawLabel(String label, Offset anchor, Alignment alignment) {
    final painter = TextPainter(
      text: TextSpan(
        text: label,
        style: const TextStyle(color: Color(0xff5f6368), fontSize: 8),
      ),
      textDirection: TextDirection.ltr,
    )..layout(maxWidth: 32);
    final dx = alignment.x < 0
        ? anchor.dx
        : alignment.x > 0
        ? anchor.dx - painter.width
        : anchor.dx - painter.width / 2;
    final dy = alignment.y < 0
        ? anchor.dy
        : alignment.y > 0
        ? anchor.dy - painter.height
        : anchor.dy - painter.height / 2;
    painter.paint(canvas, Offset(dx, dy));
  }

  final startLabel = '${start.round()}%';
  final endLabel = '${end.round()}%';
  if (vertical) {
    drawLabel(
      startLabel,
      Offset(trackRect.left - 3, fillRect.top),
      Alignment.centerRight,
    );
    drawLabel(
      endLabel,
      Offset(trackRect.left - 3, fillRect.bottom),
      Alignment.centerRight,
    );
  } else {
    drawLabel(
      startLabel,
      Offset(fillRect.left, trackRect.top - 2),
      Alignment.bottomCenter,
    );
    drawLabel(
      endLabel,
      Offset(fillRect.right, trackRect.top - 2),
      Alignment.bottomCenter,
    );
  }
}

void _fortuneDrawRawChartDataZoomShadow(
  Canvas canvas,
  Rect trackRect,
  List<FortuneRawChartSeries> chartSeries,
  Object? showDataShadow, {
  required bool vertical,
}) {
  if (!_fortuneRawChartDataZoomShadowVisible(showDataShadow)) {
    return;
  }
  final values = chartSeries
      .expand((series) => series.values)
      .where((value) => value.isFinite)
      .toList(growable: false);
  if (values.length < 2) {
    return;
  }
  final minValue = values.reduce(math.min);
  final maxValue = values.reduce(math.max);
  final span = maxValue - minValue;
  if (span <= 0 || !span.isFinite) {
    return;
  }
  final path = Path();
  if (vertical) {
    path.moveTo(trackRect.left, trackRect.top);
    for (var index = 0; index < values.length; index += 1) {
      final ratio = index / (values.length - 1);
      final valueRatio = (values[index] - minValue) / span;
      path.lineTo(
        trackRect.left + trackRect.width * valueRatio,
        trackRect.top + trackRect.height * ratio,
      );
    }
    path.lineTo(trackRect.left, trackRect.bottom);
  } else {
    path.moveTo(trackRect.left, trackRect.bottom);
    for (var index = 0; index < values.length; index += 1) {
      final ratio = index / (values.length - 1);
      final valueRatio = (values[index] - minValue) / span;
      path.lineTo(
        trackRect.left + trackRect.width * ratio,
        trackRect.bottom - trackRect.height * valueRatio,
      );
    }
    path.lineTo(trackRect.right, trackRect.bottom);
  }
  path.close();
  canvas.save();
  canvas.clipRRect(
    RRect.fromRectAndRadius(
      trackRect,
      Radius.circular(math.min(trackRect.width, trackRect.height) / 2),
    ),
  );
  canvas.drawPath(path, Paint()..color = const Color(0xff78909c));
  canvas.restore();
}

bool _fortuneRawChartDataZoomShadowVisible(Object? showDataShadow) {
  if (showDataShadow == null) {
    return false;
  }
  if (showDataShadow is String &&
      showDataShadow.trim().toLowerCase() == 'auto') {
    return true;
  }
  return _fortuneRawChartBool(showDataShadow) ?? false;
}

void _fortuneDrawRawChartVisualMap(
  Canvas canvas,
  Rect chartRect,
  List<Color> colors, {
  required bool vertical,
  required bool inverse,
  required bool calculable,
  String? minLabel,
  String? maxLabel,
  Color? textColor,
  Color? textBackgroundColor,
  Color? textBoxBorderColor,
  double? textBoxBorderWidth,
  String? textBoxBorderType,
  double? textBoxBorderRadius,
  Color? textBorderColor,
  double? textBorderWidth,
  EdgeInsets? textPadding,
  double? textWidth,
  double? textHeight,
  String? textOverflow,
  String? textEllipsis,
  String? textAlign,
  String? textVerticalAlign,
  Map<String, FortuneRawChartRichTextStyle> textRichStyles = const {},
  double? textFontSize,
  FontWeight? textFontWeight,
  FontStyle? textFontStyle,
  String? textFontFamily,
  double? textLineHeight,
  double? textOpacity,
  Color? textShadowColor,
  double? textShadowBlur,
  double? textShadowOffsetX,
  double? textShadowOffsetY,
  double? itemWidth,
  double? itemHeight,
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  EdgeInsets? padding,
  double? textGap,
  Color? shadowColor,
  double? shadowBlur,
  double? shadowOffsetX,
  double? shadowOffsetY,
  String? horizontalPosition,
  String? verticalPosition,
  double? leftOffset,
  double? topOffset,
  double? rightOffset,
  double? bottomOffset,
  double? leftPercent,
  double? topPercent,
  double? rightPercent,
  double? bottomPercent,
}) {
  final palette = colors.length < 2
      ? const [Color(0xff0188fb), Color(0xffea4335)]
      : colors;
  final shortSide = itemWidth ?? 8;
  final longSide =
      itemHeight ??
      (vertical
          ? math.max(20.0, chartRect.height * 0.42)
          : math.max(24.0, chartRect.width * 0.46));
  final defaultBarRect = vertical
      ? Rect.fromLTWH(
          chartRect.right - 19,
          chartRect.top + math.max(8.0, chartRect.height * 0.22),
          shortSide,
          longSide,
        )
      : Rect.fromLTWH(
          chartRect.left + math.max(8.0, chartRect.width * 0.2),
          chartRect.bottom - 22,
          longSide,
          shortSide,
        );
  final positioned =
      leftOffset != null ||
      topOffset != null ||
      rightOffset != null ||
      bottomOffset != null ||
      leftPercent != null ||
      topPercent != null ||
      rightPercent != null ||
      bottomPercent != null ||
      horizontalPosition != null ||
      verticalPosition != null;
  final barLeft = positioned
      ? _fortuneRawChartPositionedVisualMapLeft(
          chartRect,
          defaultBarRect.width,
          leftOffset,
          rightOffset,
          leftPercent,
          rightPercent,
          horizontalPosition,
        )
      : defaultBarRect.left;
  final barTop = positioned
      ? _fortuneRawChartPositionedVisualMapTop(
          chartRect,
          defaultBarRect.height,
          topOffset,
          bottomOffset,
          topPercent,
          bottomPercent,
          verticalPosition,
        )
      : defaultBarRect.top;
  final barRect = Rect.fromLTWH(
    barLeft,
    barTop,
    defaultBarRect.width,
    defaultBarRect.height,
  );
  if (barRect.width <= 0 || barRect.height <= 0) {
    return;
  }
  final resolvedPadding = padding ?? const EdgeInsets.all(3);
  final componentRect = Rect.fromLTRB(
    barRect.left - resolvedPadding.left,
    barRect.top - resolvedPadding.top,
    barRect.right + resolvedPadding.right,
    barRect.bottom + resolvedPadding.bottom,
  );
  if (shadowColor != null) {
    canvas.drawRect(
      componentRect.shift(Offset(shadowOffsetX ?? 0, shadowOffsetY ?? 0)),
      Paint()
        ..color = shadowColor
        ..maskFilter =
            (shadowBlur != null && shadowBlur.isFinite && shadowBlur > 0)
            ? MaskFilter.blur(BlurStyle.normal, shadowBlur)
            : null,
    );
  }
  if (backgroundColor != null) {
    canvas.drawRect(componentRect, Paint()..color = backgroundColor);
  }
  final resolvedBorderWidth = borderWidth ?? 0;
  if (borderColor != null && resolvedBorderWidth > 0) {
    final borderPaint = Paint()
      ..color = borderColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = resolvedBorderWidth;
    final borderRect = componentRect.deflate(resolvedBorderWidth / 2);
    if (borderType == 'dashed' || borderType == 'dotted') {
      _fortuneDrawRawChartDashedRect(
        canvas,
        borderRect,
        borderPaint,
        borderType!,
      );
    } else {
      canvas.drawRect(borderRect, borderPaint);
    }
  }
  final resolvedTextGap = textGap ?? 3;
  final segments = math.max(1, palette.length - 1) * 12;
  for (var index = 0; index < segments; index += 1) {
    final startRatio = index / segments;
    final endRatio = (index + 1) / segments;
    final color = _fortuneRawChartVisualMapColorAt(
      palette,
      inverse ? 1 - startRatio : startRatio,
    );
    final segmentRect = vertical
        ? Rect.fromLTRB(
            barRect.left,
            barRect.bottom - barRect.height * endRatio,
            barRect.right,
            barRect.bottom - barRect.height * startRatio,
          )
        : Rect.fromLTRB(
            barRect.left + barRect.width * startRatio,
            barRect.top,
            barRect.left + barRect.width * endRatio,
            barRect.bottom,
          );
    canvas.drawRect(segmentRect, Paint()..color = color);
  }
  canvas.drawRect(
    barRect.deflate(0.5),
    Paint()
      ..color = const Color(0xff5f6368)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1,
  );
  if (calculable) {
    if (vertical) {
      _fortuneDrawRawChartVisualMapHandle(
        canvas,
        Offset(barRect.center.dx, barRect.top),
      );
      _fortuneDrawRawChartVisualMapHandle(
        canvas,
        Offset(barRect.center.dx, barRect.bottom),
      );
    } else {
      _fortuneDrawRawChartVisualMapHandle(
        canvas,
        Offset(barRect.left, barRect.center.dy),
      );
      _fortuneDrawRawChartVisualMapHandle(
        canvas,
        Offset(barRect.right, barRect.center.dy),
      );
    }
  }
  if (vertical) {
    _fortuneDrawRawChartVisualMapLabel(
      canvas,
      inverse ? minLabel : maxLabel,
      Offset(barRect.right + resolvedTextGap, barRect.top - 1),
      color: textColor,
      backgroundColor: textBackgroundColor,
      boxBorderColor: textBoxBorderColor,
      boxBorderWidth: textBoxBorderWidth,
      boxBorderType: textBoxBorderType,
      boxBorderRadius: textBoxBorderRadius,
      textBorderColor: textBorderColor,
      textBorderWidth: textBorderWidth,
      padding: textPadding,
      width: textWidth,
      height: textHeight,
      overflow: textOverflow,
      ellipsis: textEllipsis,
      align: textAlign,
      verticalAlign: textVerticalAlign,
      richStyles: textRichStyles,
      fontSize: textFontSize,
      fontWeight: textFontWeight,
      fontStyle: textFontStyle,
      fontFamily: textFontFamily,
      lineHeight: textLineHeight,
      opacity: textOpacity,
      textShadowColor: textShadowColor,
      textShadowBlur: textShadowBlur,
      textShadowOffsetX: textShadowOffsetX,
      textShadowOffsetY: textShadowOffsetY,
    );
    _fortuneDrawRawChartVisualMapLabel(
      canvas,
      inverse ? maxLabel : minLabel,
      Offset(barRect.right + resolvedTextGap, barRect.bottom - 8),
      color: textColor,
      backgroundColor: textBackgroundColor,
      boxBorderColor: textBoxBorderColor,
      boxBorderWidth: textBoxBorderWidth,
      boxBorderType: textBoxBorderType,
      boxBorderRadius: textBoxBorderRadius,
      textBorderColor: textBorderColor,
      textBorderWidth: textBorderWidth,
      padding: textPadding,
      width: textWidth,
      height: textHeight,
      overflow: textOverflow,
      ellipsis: textEllipsis,
      align: textAlign,
      verticalAlign: textVerticalAlign,
      richStyles: textRichStyles,
      fontSize: textFontSize,
      fontWeight: textFontWeight,
      fontStyle: textFontStyle,
      fontFamily: textFontFamily,
      lineHeight: textLineHeight,
      opacity: textOpacity,
      textShadowColor: textShadowColor,
      textShadowBlur: textShadowBlur,
      textShadowOffsetX: textShadowOffsetX,
      textShadowOffsetY: textShadowOffsetY,
    );
  } else {
    _fortuneDrawRawChartVisualMapLabel(
      canvas,
      inverse ? maxLabel : minLabel,
      Offset(barRect.left, barRect.bottom + resolvedTextGap),
      color: textColor,
      backgroundColor: textBackgroundColor,
      boxBorderColor: textBoxBorderColor,
      boxBorderWidth: textBoxBorderWidth,
      boxBorderType: textBoxBorderType,
      boxBorderRadius: textBoxBorderRadius,
      textBorderColor: textBorderColor,
      textBorderWidth: textBorderWidth,
      padding: textPadding,
      width: textWidth,
      height: textHeight,
      overflow: textOverflow,
      ellipsis: textEllipsis,
      align: textAlign,
      verticalAlign: textVerticalAlign,
      richStyles: textRichStyles,
      fontSize: textFontSize,
      fontWeight: textFontWeight,
      fontStyle: textFontStyle,
      fontFamily: textFontFamily,
      lineHeight: textLineHeight,
      opacity: textOpacity,
      textShadowColor: textShadowColor,
      textShadowBlur: textShadowBlur,
      textShadowOffsetX: textShadowOffsetX,
      textShadowOffsetY: textShadowOffsetY,
    );
    _fortuneDrawRawChartVisualMapLabel(
      canvas,
      inverse ? minLabel : maxLabel,
      Offset(barRect.right - 10, barRect.bottom + resolvedTextGap),
      color: textColor,
      backgroundColor: textBackgroundColor,
      boxBorderColor: textBoxBorderColor,
      boxBorderWidth: textBoxBorderWidth,
      boxBorderType: textBoxBorderType,
      boxBorderRadius: textBoxBorderRadius,
      textBorderColor: textBorderColor,
      textBorderWidth: textBorderWidth,
      padding: textPadding,
      width: textWidth,
      height: textHeight,
      overflow: textOverflow,
      ellipsis: textEllipsis,
      align: textAlign,
      verticalAlign: textVerticalAlign,
      richStyles: textRichStyles,
      fontSize: textFontSize,
      fontWeight: textFontWeight,
      fontStyle: textFontStyle,
      fontFamily: textFontFamily,
      lineHeight: textLineHeight,
      opacity: textOpacity,
      textShadowColor: textShadowColor,
      textShadowBlur: textShadowBlur,
      textShadowOffsetX: textShadowOffsetX,
      textShadowOffsetY: textShadowOffsetY,
    );
  }
}

void _fortuneDrawRawChartVisualMapHandle(Canvas canvas, Offset center) {
  const halfSize = 5.5;
  final path = Path()
    ..moveTo(center.dx, center.dy - halfSize)
    ..lineTo(center.dx + halfSize, center.dy)
    ..lineTo(center.dx, center.dy + halfSize)
    ..lineTo(center.dx - halfSize, center.dy)
    ..close();
  canvas.drawPath(path, Paint()..color = const Color(0xffffffff));
  canvas.drawPath(
    path,
    Paint()
      ..color = const Color(0xff9aa0a6)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1,
  );
}

Color _fortuneRawChartVisualMapColorAt(List<Color> colors, double ratio) {
  if (colors.length == 1) {
    return colors.single;
  }
  final clamped = ratio.clamp(0.0, 1.0).toDouble();
  final scaled = clamped * (colors.length - 1);
  final start = scaled.floor().clamp(0, colors.length - 2);
  final localRatio = scaled - start;
  return Color.lerp(colors[start], colors[start + 1], localRatio) ??
      colors[start];
}

void _fortuneDrawRawChartVisualMapLabel(
  Canvas canvas,
  String? label,
  Offset offset, {
  Color? color,
  Color? backgroundColor,
  Color? boxBorderColor,
  double? boxBorderWidth,
  String? boxBorderType,
  double? boxBorderRadius,
  Color? textBorderColor,
  double? textBorderWidth,
  EdgeInsets? padding,
  double? width,
  double? height,
  String? overflow,
  String? ellipsis,
  String? align,
  String? verticalAlign,
  Map<String, FortuneRawChartRichTextStyle> richStyles = const {},
  double? fontSize,
  FontWeight? fontWeight,
  FontStyle? fontStyle,
  String? fontFamily,
  double? lineHeight,
  double? opacity,
  Color? textShadowColor,
  double? textShadowBlur,
  double? textShadowOffsetX,
  double? textShadowOffsetY,
}) {
  if (label == null) {
    return;
  }
  final effectiveFontSize = fontSize ?? 7;
  final effectiveColor =
      _fortuneRawChartColorWithOpacity(
        color ?? const Color(0xff5f6368),
        opacity,
      ) ??
      color ??
      const Color(0xff5f6368);
  final effectiveTextBorderColor = _fortuneRawChartColorWithOpacity(
    textBorderColor,
    opacity,
  );
  final effectiveBackgroundColor = _fortuneRawChartColorWithOpacity(
    backgroundColor,
    opacity,
  );
  final effectiveBoxBorderColor = _fortuneRawChartColorWithOpacity(
    boxBorderColor,
    opacity,
  );
  final effectiveTextShadowColor = _fortuneRawChartColorWithOpacity(
    textShadowColor,
    opacity,
  );
  final maxWidth = math.max(
    0.0,
    width ?? math.max(28.0, effectiveFontSize * 5),
  );
  final strokePainter = _fortuneRawChartLabelStrokePainter(
    text: label,
    fontSize: effectiveFontSize,
    fontWeight: fontWeight ?? FontWeight.w400,
    fontStyle: fontStyle ?? FontStyle.normal,
    fontFamily: fontFamily,
    lineHeight: lineHeight,
    textBorderColor: effectiveTextBorderColor,
    textBorderWidth: textBorderWidth,
    overflow: overflow,
    ellipsis: ellipsis,
    maxWidth: maxWidth,
  );
  final painter = TextPainter(
    text: _fortuneRawChartLabelTextSpan(
      label,
      TextStyle(
        color: effectiveColor,
        fontSize: effectiveFontSize,
        fontWeight: fontWeight,
        fontStyle: fontStyle,
        fontFamily: fontFamily,
        height: _fortuneRawChartLabelHeightRatio(effectiveFontSize, lineHeight),
        shadows: _fortuneRawChartLabelShadows(
          effectiveTextShadowColor,
          textShadowBlur,
          textShadowOffsetX,
          textShadowOffsetY,
        ),
      ),
      richStyles,
    ),
    maxLines: 1,
    ellipsis: overflow == 'truncate' ? ellipsis ?? '...' : null,
    textDirection: TextDirection.ltr,
  )..layout(maxWidth: maxWidth);
  _fortunePaintRawChartLabel(
    canvas,
    painter,
    strokePainter,
    offset,
    effectiveBackgroundColor,
    effectiveBoxBorderColor,
    boxBorderWidth,
    padding,
    boxBorderRadius,
    width,
    height,
    align,
    verticalAlign,
    0,
    boxBorderType,
  );
}

double _fortuneRawChartPositionedVisualMapLeft(
  Rect chartRect,
  double width,
  double? leftOffset,
  double? rightOffset,
  double? leftPercent,
  double? rightPercent,
  String? horizontalPosition,
) {
  final left = leftOffset != null
      ? chartRect.left + leftOffset
      : leftPercent != null
      ? chartRect.left + chartRect.width * leftPercent
      : rightOffset != null
      ? chartRect.right - rightOffset - width
      : rightPercent != null
      ? chartRect.right - chartRect.width * rightPercent - width
      : horizontalPosition == 'center'
      ? chartRect.left + (chartRect.width - width) / 2
      : horizontalPosition == 'right'
      ? chartRect.right - width
      : chartRect.left;
  final maxLeft = math.max(chartRect.left, chartRect.right - width);
  return left.clamp(chartRect.left, maxLeft).toDouble();
}

double _fortuneRawChartPositionedVisualMapTop(
  Rect chartRect,
  double height,
  double? topOffset,
  double? bottomOffset,
  double? topPercent,
  double? bottomPercent,
  String? verticalPosition,
) {
  final top = topOffset != null
      ? chartRect.top + topOffset
      : topPercent != null
      ? chartRect.top + chartRect.height * topPercent
      : bottomOffset != null
      ? chartRect.bottom - bottomOffset - height
      : bottomPercent != null
      ? chartRect.bottom - chartRect.height * bottomPercent - height
      : verticalPosition == 'middle'
      ? chartRect.top + (chartRect.height - height) / 2
      : verticalPosition == 'bottom'
      ? chartRect.bottom - height
      : chartRect.top;
  final maxTop = math.max(chartRect.top, chartRect.bottom - height);
  return top.clamp(chartRect.top, maxTop).toDouble();
}

void _fortuneDrawRawChartToolbox(
  Canvas canvas,
  Rect chartRect, {
  required int featureCount,
  bool vertical = false,
  Color? iconColor,
  double? iconBorderWidth,
  String? iconBorderType,
  double? iconOpacity,
  Color? iconShadowColor,
  double? iconShadowBlur,
  double? iconShadowOffsetX,
  double? iconShadowOffsetY,
  double? iconSize,
  double? itemGap,
  double? leftOffset,
  double? topOffset,
  double? rightOffset,
  double? bottomOffset,
  String? horizontalPosition,
  String? verticalPosition,
  double? leftPercent,
  double? topPercent,
  double? rightPercent,
  double? bottomPercent,
}) {
  if (featureCount <= 0) {
    return;
  }
  final count = math.min(featureCount, 6);
  final size = iconSize ?? 10;
  final gap = itemGap ?? 4;
  final totalWidth = vertical
      ? size
      : count * size + math.max(0, count - 1) * gap;
  final totalHeight = count * size + math.max(0, count - 1) * gap;
  final color =
      _fortuneRawChartColorWithOpacity(
        iconColor ?? const Color(0xff5f6368),
        iconOpacity,
      ) ??
      const Color(0xff5f6368);
  final strokeWidth = iconBorderWidth ?? 1.2;
  final top = _fortuneRawChartToolboxTop(
    chartRect,
    totalHeight,
    topOffset: topOffset,
    bottomOffset: bottomOffset,
    verticalPosition: verticalPosition,
    topPercent: topPercent,
    bottomPercent: bottomPercent,
  );
  final left = _fortuneRawChartToolboxLeft(
    chartRect,
    totalWidth,
    leftOffset: leftOffset,
    rightOffset: rightOffset,
    horizontalPosition: horizontalPosition,
    leftPercent: leftPercent,
    rightPercent: rightPercent,
  );
  var currentLeft = left;
  var currentTop = top;
  final paint = Paint()
    ..color = color
    ..style = PaintingStyle.stroke
    ..strokeWidth = strokeWidth;
  final shadowColor = _fortuneRawChartColorWithOpacity(
    iconShadowColor,
    iconOpacity,
  );
  final shadowPaint = shadowColor == null
      ? null
      : (Paint()
          ..color = shadowColor
          ..style = PaintingStyle.stroke
          ..strokeWidth = strokeWidth
          ..maskFilter =
              (iconShadowBlur != null &&
                  iconShadowBlur.isFinite &&
                  iconShadowBlur > 0)
              ? MaskFilter.blur(BlurStyle.normal, iconShadowBlur)
              : null);
  final shadowOffset = Offset(iconShadowOffsetX ?? 0, iconShadowOffsetY ?? 0);
  for (var index = 0; index < count; index += 1) {
    final rect = vertical
        ? Rect.fromLTWH(left, currentTop, size, size)
        : Rect.fromLTWH(currentLeft, top, size, size);
    final inset = math.max(2.0, size * 0.25);
    if (shadowPaint != null) {
      final shadowRect = rect.shift(shadowOffset);
      _fortuneDrawRawChartToolboxIconStroke(
        canvas,
        shadowRect,
        inset,
        shadowPaint,
        iconBorderType,
      );
    }
    _fortuneDrawRawChartToolboxIconStroke(
      canvas,
      rect,
      inset,
      paint,
      iconBorderType,
    );
    if (vertical) {
      currentTop += size + gap;
    } else {
      currentLeft += size + gap;
    }
  }
}

void _fortuneDrawRawChartToolboxIconStroke(
  Canvas canvas,
  Rect rect,
  double inset,
  Paint paint,
  String? type,
) {
  final topLeft = rect.topLeft;
  final topRight = rect.topRight;
  final bottomRight = rect.bottomRight;
  final bottomLeft = rect.bottomLeft;
  final diagonalStart = Offset(rect.left + inset, rect.bottom - inset);
  final diagonalEnd = Offset(rect.right - inset, rect.top + inset);
  if (type != 'dashed' && type != 'dotted') {
    canvas.drawRect(rect, paint);
    canvas.drawLine(diagonalStart, diagonalEnd, paint);
    return;
  }
  final segmentLength = type == 'dotted'
      ? math.max(1.5, paint.strokeWidth)
      : math.max(4.0, paint.strokeWidth * 3);
  final gapLength = type == 'dotted'
      ? segmentLength * 1.6
      : math.max(3.0, paint.strokeWidth * 2);
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    topLeft,
    topRight,
    paint,
    segmentLength,
    gapLength,
    0,
  );
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    topRight,
    bottomRight,
    paint,
    segmentLength,
    gapLength,
    0,
  );
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    bottomRight,
    bottomLeft,
    paint,
    segmentLength,
    gapLength,
    0,
  );
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    bottomLeft,
    topLeft,
    paint,
    segmentLength,
    gapLength,
    0,
  );
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    diagonalStart,
    diagonalEnd,
    paint,
    segmentLength,
    gapLength,
    0,
  );
}

double _fortuneRawChartToolboxLeft(
  Rect chartRect,
  double totalWidth, {
  double? leftOffset,
  double? rightOffset,
  String? horizontalPosition,
  double? leftPercent,
  double? rightPercent,
}) {
  if (leftOffset != null) {
    return chartRect.left + leftOffset;
  }
  if (rightOffset != null) {
    return chartRect.right - rightOffset - totalWidth;
  }
  if (leftPercent != null) {
    return chartRect.left + chartRect.width * leftPercent;
  }
  if (rightPercent != null) {
    return chartRect.right - chartRect.width * rightPercent - totalWidth;
  }
  switch (horizontalPosition) {
    case 'left':
      return chartRect.left + 7;
    case 'center':
      return chartRect.center.dx - totalWidth / 2;
    case 'right':
      return chartRect.right - 7 - totalWidth;
  }
  return chartRect.right - 7 - totalWidth;
}

double _fortuneRawChartToolboxTop(
  Rect chartRect,
  double totalHeight, {
  double? topOffset,
  double? bottomOffset,
  String? verticalPosition,
  double? topPercent,
  double? bottomPercent,
}) {
  if (topOffset != null) {
    return chartRect.top + topOffset;
  }
  if (bottomOffset != null) {
    return chartRect.bottom - bottomOffset - totalHeight;
  }
  if (topPercent != null) {
    return chartRect.top + chartRect.height * topPercent;
  }
  if (bottomPercent != null) {
    return chartRect.bottom - chartRect.height * bottomPercent - totalHeight;
  }
  switch (verticalPosition) {
    case 'top':
      return chartRect.top + 6;
    case 'middle':
      return chartRect.center.dy - totalHeight / 2;
    case 'bottom':
      return chartRect.bottom - 6 - totalHeight;
  }
  return chartRect.top + 6;
}

void _fortuneDrawRawChartAxisLines(
  Canvas canvas,
  Rect chartRect,
  double axisLeft,
  double axisBottom, {
  required double plotAxisLeft,
  required double plotAxisBottom,
  required bool xAxisLineVisible,
  required bool yAxisLineVisible,
  required Color xAxisLineColor,
  required Color yAxisLineColor,
  required double xAxisLineWidth,
  required double yAxisLineWidth,
  String? xAxisLineType,
  String? yAxisLineType,
  double? xAxisLineDashOffset,
  double? yAxisLineDashOffset,
  String? xAxisLineCap,
  String? yAxisLineCap,
  Color? xAxisLineShadowColor,
  Color? yAxisLineShadowColor,
  double? xAxisLineShadowBlur,
  double? yAxisLineShadowBlur,
  double? xAxisLineShadowOffsetX,
  double? yAxisLineShadowOffsetX,
  double? xAxisLineShadowOffsetY,
  double? yAxisLineShadowOffsetY,
  double? xAxisLineOpacity,
  double? yAxisLineOpacity,
  required bool xAxisLineSymbolStart,
  required bool xAxisLineSymbolEnd,
  required bool yAxisLineSymbolStart,
  required bool yAxisLineSymbolEnd,
  Size? xAxisLineSymbolSize,
  Size? yAxisLineSymbolSize,
  Offset? xAxisLineSymbolOffset,
  Offset? yAxisLineSymbolOffset,
  double? xAxisLineSymbolRotationDegrees,
  double? yAxisLineSymbolRotationDegrees,
}) {
  if (yAxisLineVisible) {
    _fortuneDrawRawChartShadowLine(
      canvas,
      start: Offset(axisLeft, chartRect.top),
      end: Offset(axisLeft, plotAxisBottom),
      color: yAxisLineShadowColor,
      width: yAxisLineWidth,
      type: yAxisLineType,
      cap: yAxisLineCap,
      blur: yAxisLineShadowBlur,
      offsetX: yAxisLineShadowOffsetX,
      offsetY: yAxisLineShadowOffsetY,
      dashOffset: yAxisLineDashOffset,
    );
    if (yAxisLineCap == null) {
      _fortuneDrawRawChartLineRect(
        canvas,
        Rect.fromLTRB(
          axisLeft - yAxisLineWidth / 2,
          chartRect.top,
          axisLeft + yAxisLineWidth / 2,
          plotAxisBottom,
        ),
        yAxisLineColor,
        yAxisLineType,
        horizontal: false,
        dashOffset: yAxisLineDashOffset,
      );
    } else {
      _fortuneDrawRawChartAxisStrokeLine(
        canvas,
        Offset(axisLeft, chartRect.top),
        Offset(axisLeft, plotAxisBottom),
        yAxisLineColor,
        yAxisLineWidth,
        yAxisLineType,
        yAxisLineCap,
        dashOffset: yAxisLineDashOffset,
      );
    }
    final symbolSize = yAxisLineSymbolSize ?? const Size(10, 10);
    final symbolOffset = yAxisLineSymbolOffset ?? Offset.zero;
    final symbolRotation = _fortuneDegreesToRadians(
      yAxisLineSymbolRotationDegrees,
    );
    if (yAxisLineSymbolStart) {
      _fortuneDrawRawChartAxisLineArrow(
        canvas,
        Offset(axisLeft, plotAxisBottom) + symbolOffset,
        symbolSize,
        yAxisLineColor,
        math.pi / 2 + symbolRotation,
      );
    }
    if (yAxisLineSymbolEnd) {
      _fortuneDrawRawChartAxisLineArrow(
        canvas,
        Offset(axisLeft, chartRect.top) + symbolOffset,
        symbolSize,
        yAxisLineColor,
        -math.pi / 2 + symbolRotation,
      );
    }
  }
  if (xAxisLineVisible) {
    _fortuneDrawRawChartShadowLine(
      canvas,
      start: Offset(plotAxisLeft, axisBottom),
      end: Offset(chartRect.right, axisBottom),
      color: xAxisLineShadowColor,
      width: xAxisLineWidth,
      type: xAxisLineType,
      cap: xAxisLineCap,
      blur: xAxisLineShadowBlur,
      offsetX: xAxisLineShadowOffsetX,
      offsetY: xAxisLineShadowOffsetY,
      dashOffset: xAxisLineDashOffset,
    );
    if (xAxisLineCap == null) {
      _fortuneDrawRawChartLineRect(
        canvas,
        Rect.fromLTRB(
          plotAxisLeft,
          axisBottom - xAxisLineWidth / 2,
          chartRect.right,
          axisBottom + xAxisLineWidth / 2,
        ),
        xAxisLineColor,
        xAxisLineType,
        horizontal: true,
        dashOffset: xAxisLineDashOffset,
      );
    } else {
      _fortuneDrawRawChartAxisStrokeLine(
        canvas,
        Offset(plotAxisLeft, axisBottom),
        Offset(chartRect.right, axisBottom),
        xAxisLineColor,
        xAxisLineWidth,
        xAxisLineType,
        xAxisLineCap,
        dashOffset: xAxisLineDashOffset,
      );
    }
    final symbolSize = xAxisLineSymbolSize ?? const Size(10, 10);
    final symbolOffset = xAxisLineSymbolOffset ?? Offset.zero;
    final symbolRotation = _fortuneDegreesToRadians(
      xAxisLineSymbolRotationDegrees,
    );
    if (xAxisLineSymbolStart) {
      _fortuneDrawRawChartAxisLineArrow(
        canvas,
        Offset(plotAxisLeft, axisBottom) + symbolOffset,
        symbolSize,
        xAxisLineColor,
        math.pi + symbolRotation,
      );
    }
    if (xAxisLineSymbolEnd) {
      _fortuneDrawRawChartAxisLineArrow(
        canvas,
        Offset(chartRect.right, axisBottom) + symbolOffset,
        symbolSize,
        xAxisLineColor,
        symbolRotation,
      );
    }
  }
}

void _fortuneDrawRawChartAxisPointers(
  Canvas canvas,
  Rect plotRect, {
