  double? xAxisPointerLabelShadowOffsetX,
  double? yAxisPointerLabelShadowOffsetX,
  double? xAxisPointerLabelShadowOffsetY,
  double? yAxisPointerLabelShadowOffsetY,
}) {
  final effectiveXAxisPointerVisible =
      xAxisPointerVisible && xAxisPointerStatus != 'hide';
  final effectiveYAxisPointerVisible =
      yAxisPointerVisible && yAxisPointerStatus != 'hide';
  if (!effectiveXAxisPointerVisible && !effectiveYAxisPointerVisible) {
    return;
  }
  final snappedHoverX = hoverPosition == null
      ? null
      : xAxisPointerSnap == true
      ? _fortuneRawChartNearestXAxisPosition(
              hoverPosition.dx,
              plotRect,
              xAxisLabels,
              chartSeries,
              xAxisInverse: xAxisInverse,
              xAxisBoundaryGap: xAxisBoundaryGap,
            ) ??
            hoverPosition.dx
      : hoverPosition.dx;
  final xPointerX = effectiveXAxisPointerVisible
      ? snappedHoverX ??
            _fortuneRawChartXAxisPointerPosition(
              xAxisPointerValue,
              plotRect,
              xAxisLabels,
              chartSeries,
              xAxisInverse: xAxisInverse,
              xAxisBoundaryGap: xAxisBoundaryGap,
            )
      : null;
  final snappedHoverY = hoverPosition == null
      ? null
      : yAxisPointerSnap == true
      ? _fortuneRawChartNearestYAxisPosition(
              hoverPosition.dy,
              plotRect,
              yAxisLabels,
              chartSeries,
              yAxisInverse: yAxisInverse,
            ) ??
            hoverPosition.dy
      : hoverPosition.dy;
  final yPointerY = effectiveYAxisPointerVisible
      ? snappedHoverY ??
            _fortuneRawChartYAxisPointerPosition(
              yAxisPointerValue,
              plotRect,
              yAxisLabels,
              chartSeries,
              yAxisInverse: yAxisInverse,
            )
      : null;
  canvas.save();
  canvas.clipRect(plotRect);
  if (effectiveXAxisPointerVisible && xPointerX != null) {
    final x = xPointerX;
    if (xAxisPointerAreaVisible) {
      _fortuneDrawRawChartAxisPointerArea(
        canvas,
        Rect.fromCenter(
          center: Offset(x, plotRect.center.dy),
          width: math.min(xAxisPointerAreaWidth ?? 20, plotRect.width),
          height: plotRect.height,
        ),
        xAxisPointerAreaColor,
        shadowColor: xAxisPointerAreaShadowColor,
        shadowBlur: xAxisPointerAreaShadowBlur,
        shadowOffsetX: xAxisPointerAreaShadowOffsetX,
        shadowOffsetY: xAxisPointerAreaShadowOffsetY,
      );
    } else {
      _fortuneDrawRawChartShadowLine(
        canvas,
        start: Offset(x, plotRect.top),
        end: Offset(x, plotRect.bottom),
        color: xAxisPointerShadowColor,
        width: xAxisPointerWidth,
        type: xAxisPointerType,
        cap: xAxisPointerCap,
        blur: xAxisPointerShadowBlur,
        offsetX: xAxisPointerShadowOffsetX,
        offsetY: xAxisPointerShadowOffsetY,
        dashOffset: xAxisPointerDashOffset,
      );
      _fortuneDrawRawChartTickLine(
        canvas,
        start: Offset(x, plotRect.top),
        end: Offset(x, plotRect.bottom),
        color: xAxisPointerColor,
        width: xAxisPointerWidth,
        type: xAxisPointerType,
        cap: xAxisPointerCap,
        dashOffset: xAxisPointerDashOffset,
      );
    }
  }
  if (effectiveYAxisPointerVisible && yPointerY != null) {
    final y = yPointerY;
    if (yAxisPointerAreaVisible) {
      _fortuneDrawRawChartAxisPointerArea(
        canvas,
        Rect.fromCenter(
          center: Offset(plotRect.center.dx, y),
          width: plotRect.width,
          height: math.min(yAxisPointerAreaHeight ?? 20, plotRect.height),
        ),
        yAxisPointerAreaColor,
        shadowColor: yAxisPointerAreaShadowColor,
        shadowBlur: yAxisPointerAreaShadowBlur,
        shadowOffsetX: yAxisPointerAreaShadowOffsetX,
        shadowOffsetY: yAxisPointerAreaShadowOffsetY,
      );
    } else {
      _fortuneDrawRawChartShadowLine(
        canvas,
        start: Offset(plotRect.left, y),
        end: Offset(plotRect.right, y),
        color: yAxisPointerShadowColor,
        width: yAxisPointerWidth,
        type: yAxisPointerType,
        cap: yAxisPointerCap,
        blur: yAxisPointerShadowBlur,
        offsetX: yAxisPointerShadowOffsetX,
        offsetY: yAxisPointerShadowOffsetY,
        dashOffset: yAxisPointerDashOffset,
      );
      _fortuneDrawRawChartTickLine(
        canvas,
        start: Offset(plotRect.left, y),
        end: Offset(plotRect.right, y),
        color: yAxisPointerColor,
        width: yAxisPointerWidth,
        type: yAxisPointerType,
        cap: yAxisPointerCap,
        dashOffset: yAxisPointerDashOffset,
      );
    }
  }
  canvas.restore();
  if (xPointerX != null) {
    _fortuneDrawRawChartAxisPointerLabel(
      canvas,
      anchor: Offset(xPointerX, plotRect.bottom),
      value: xAxisPointerValue,
      formatter: xAxisPointerLabelFormatter,
      precision: xAxisPointerLabelPrecision,
      color: xAxisPointerLabelColor,
      backgroundColor: xAxisPointerLabelBackgroundColor ?? xAxisPointerColor,
      fontSize: xAxisPointerLabelFontSize,
      fontWeight: xAxisPointerLabelFontWeight,
      fontStyle: xAxisPointerLabelFontStyle,
      fontFamily: xAxisPointerLabelFontFamily,
      lineHeight: xAxisPointerLabelLineHeight,
      boxWidth: xAxisPointerLabelWidth,
      boxHeight: xAxisPointerLabelHeight,
      align: xAxisPointerLabelAlign,
      verticalAlign: xAxisPointerLabelVerticalAlign,
      overflow: xAxisPointerLabelOverflow,
      ellipsis: xAxisPointerLabelEllipsis,
      borderColor: xAxisPointerLabelBorderColor,
      borderWidth: xAxisPointerLabelBorderWidth,
      borderType: xAxisPointerLabelBorderType,
      borderRadius: xAxisPointerLabelBorderRadius,
      padding: xAxisPointerLabelPadding,
      margin: xAxisPointerLabelMargin,
      shadowColor: xAxisPointerLabelShadowColor,
      shadowBlur: xAxisPointerLabelShadowBlur,
      shadowOffsetX: xAxisPointerLabelShadowOffsetX,
      shadowOffsetY: xAxisPointerLabelShadowOffsetY,
      visible: xAxisPointerLabelVisible,
      vertical: true,
    );
    _fortuneDrawRawChartAxisPointerHandle(
      canvas,
      Offset(xPointerX, plotRect.bottom + (xAxisPointerHandleMargin ?? 0)),
      xAxisPointerHandleSize,
      xAxisPointerHandleColor,
      icon: xAxisPointerHandleIcon,
      shadowColor: xAxisPointerHandleShadowColor,
      shadowBlur: xAxisPointerHandleShadowBlur,
      shadowOffsetX: xAxisPointerHandleShadowOffsetX,
      shadowOffsetY: xAxisPointerHandleShadowOffsetY,
      visible: xAxisPointerHandleVisible,
      vertical: true,
    );
  }
  if (yPointerY != null) {
    _fortuneDrawRawChartAxisPointerLabel(
      canvas,
      anchor: Offset(plotRect.left, yPointerY),
      value: yAxisPointerValue,
      formatter: yAxisPointerLabelFormatter,
      precision: yAxisPointerLabelPrecision,
      color: yAxisPointerLabelColor,
      backgroundColor: yAxisPointerLabelBackgroundColor ?? yAxisPointerColor,
      fontSize: yAxisPointerLabelFontSize,
      fontWeight: yAxisPointerLabelFontWeight,
      fontStyle: yAxisPointerLabelFontStyle,
      fontFamily: yAxisPointerLabelFontFamily,
      lineHeight: yAxisPointerLabelLineHeight,
      boxWidth: yAxisPointerLabelWidth,
      boxHeight: yAxisPointerLabelHeight,
      align: yAxisPointerLabelAlign,
      verticalAlign: yAxisPointerLabelVerticalAlign,
      overflow: yAxisPointerLabelOverflow,
      ellipsis: yAxisPointerLabelEllipsis,
      borderColor: yAxisPointerLabelBorderColor,
      borderWidth: yAxisPointerLabelBorderWidth,
      borderType: yAxisPointerLabelBorderType,
      borderRadius: yAxisPointerLabelBorderRadius,
      padding: yAxisPointerLabelPadding,
      margin: yAxisPointerLabelMargin,
      shadowColor: yAxisPointerLabelShadowColor,
      shadowBlur: yAxisPointerLabelShadowBlur,
      shadowOffsetX: yAxisPointerLabelShadowOffsetX,
      shadowOffsetY: yAxisPointerLabelShadowOffsetY,
      visible: yAxisPointerLabelVisible,
      vertical: false,
    );
    _fortuneDrawRawChartAxisPointerHandle(
      canvas,
      Offset(plotRect.left - (yAxisPointerHandleMargin ?? 0), yPointerY),
      yAxisPointerHandleSize,
      yAxisPointerHandleColor,
      icon: yAxisPointerHandleIcon,
      shadowColor: yAxisPointerHandleShadowColor,
      shadowBlur: yAxisPointerHandleShadowBlur,
      shadowOffsetX: yAxisPointerHandleShadowOffsetX,
      shadowOffsetY: yAxisPointerHandleShadowOffsetY,
      visible: yAxisPointerHandleVisible,
      vertical: false,
    );
  }
