void _fortuneDrawRawChartAxisPointerLabel(
  Canvas canvas, {
  required Offset anchor,
  required Object? value,
  required String? formatter,
  required int? precision,
  required Color? color,
  required Color? backgroundColor,
  required double? fontSize,
  required FontWeight? fontWeight,
  required FontStyle? fontStyle,
  required String? fontFamily,
  required double? lineHeight,
  required double? boxWidth,
  required double? boxHeight,
  required String? align,
  required String? verticalAlign,
  required String? overflow,
  required String? ellipsis,
  required Color? borderColor,
  required double? borderWidth,
  required String? borderType,
  required double? borderRadius,
  required EdgeInsets? padding,
  required double? margin,
  required Color? shadowColor,
  required double? shadowBlur,
  required double? shadowOffsetX,
  required double? shadowOffsetY,
  required bool? visible,
  required bool vertical,
}) {
  if (visible != true || value == null) {
    return;
  }
  final text = _fortuneRawChartAxisPointerLabelText(
    value,
    formatter,
    precision,
  );
  if (text.isEmpty) {
    return;
  }
  final effectiveFontSize = fontSize ?? 12;
  final painter = _fortuneRawChartLabelFillPainter(
    text: text,
    color: color ?? const Color(0xffffffff),
    fontSize: effectiveFontSize,
    fontWeight: fontWeight ?? FontWeight.w400,
    fontStyle: fontStyle ?? FontStyle.normal,
    fontFamily: fontFamily,
    backgroundColor: null,
    lineHeight: lineHeight,
    textShadowColor: null,
    textShadowBlur: null,
    textShadowOffsetX: null,
    textShadowOffsetY: null,
    overflow: overflow,
    ellipsis: ellipsis,
    richStyles: const {},
    maxWidth: _fortuneRawChartLabelMaxWidth(
      math.max(36, effectiveFontSize * 6),
      boxWidth,
      overflow,
    ),
  );
  final labelPadding =
      padding ?? const EdgeInsets.symmetric(horizontal: 5, vertical: 3);
  final labelWidth = math.max(painter.width, boxWidth ?? 0);
  final labelHeight = math.max(painter.height, boxHeight ?? 0);
  final labelSize = Size(
    labelWidth + labelPadding.horizontal,
    labelHeight + labelPadding.vertical,
  );
  final effectiveMargin = margin ?? 3;
  final topLeft = vertical
      ? Offset(anchor.dx - labelSize.width / 2, anchor.dy + effectiveMargin)
      : Offset(
          anchor.dx - labelSize.width - effectiveMargin,
          anchor.dy - labelSize.height / 2,
        );
  if (shadowColor != null) {
    final shadowPaint = Paint()..color = shadowColor;
    if (shadowBlur != null && shadowBlur > 0) {
      shadowPaint.maskFilter = ui.MaskFilter.blur(
        ui.BlurStyle.normal,
        shadowBlur,
      );
    }
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        Rect.fromLTWH(
          topLeft.dx + (shadowOffsetX ?? 0),
          topLeft.dy + (shadowOffsetY ?? 0),
          labelSize.width,
          labelSize.height,
        ),
        Radius.circular(borderRadius ?? 3),
      ),
      shadowPaint,
    );
  }
  _fortunePaintRawChartLabel(
    canvas,
    painter,
    null,
    topLeft + Offset(labelPadding.left, labelPadding.top),
    backgroundColor ?? const Color(0xff6b7280),
    borderColor,
    borderWidth,
    labelPadding,
    borderRadius ?? 3,
    boxWidth,
    boxHeight,
    align,
    verticalAlign,
    0,
    borderType,
  );
}

String _fortuneRawChartAxisPointerLabelText(
  Object value,
  String? formatter,
  int? precision,
) {
  final defaultValue = switch (value) {
    num number when precision != null => number.toStringAsFixed(precision),
    num number => number.toString(),
    _ => value.toString(),
  };
  final template = formatter?.trim();
  if (template == null || template.isEmpty) {
    return defaultValue;
  }
  return template.replaceAll('{value}', defaultValue);
}

void _fortuneDrawRawChartAxisPointerHandle(
  Canvas canvas,
  Offset anchor,
  Object? rawSize,
  Color? color, {
  required String? icon,
  Color? shadowColor,
  double? shadowBlur,
  double? shadowOffsetX,
  double? shadowOffsetY,
  required bool? visible,
  required bool vertical,
}) {
  if (visible != true) {
    return;
  }
  final size = _fortuneRawChartAxisPointerHandlePaintSize(rawSize);
  final paint = Paint()..color = color ?? const Color(0xff6b7280);
  final center = vertical
      ? anchor + Offset(0, size.height / 2)
      : anchor - Offset(size.width / 2, 0);
  final rect = Rect.fromCenter(
    center: center,
    width: size.width,
    height: size.height,
  );
  final shadowPaint = shadowColor == null
      ? null
      : (Paint()
          ..color = shadowColor
          ..maskFilter = shadowBlur != null && shadowBlur > 0
              ? ui.MaskFilter.blur(ui.BlurStyle.normal, shadowBlur)
              : null);
  if (shadowPaint != null) {
    final shadowRect = rect.shift(
      Offset(shadowOffsetX ?? 0, shadowOffsetY ?? 0),
    );
    if (!_fortuneDrawRawChartAxisPointerHandleIcon(
      canvas,
      shadowRect,
      icon,
      shadowPaint,
    )) {
      canvas.drawRRect(
        RRect.fromRectAndRadius(shadowRect, const Radius.circular(3)),
        shadowPaint,
      );
    }
  }
  if (_fortuneDrawRawChartAxisPointerHandleIcon(canvas, rect, icon, paint)) {
    return;
  }
  canvas.drawRRect(
    RRect.fromRectAndRadius(rect, const Radius.circular(3)),
    paint,
  );
}

bool _fortuneDrawRawChartAxisPointerHandleIcon(
  Canvas canvas,
  Rect rect,
  String? icon,
  Paint paint,
) {
  final normalizedIcon = icon?.trim();
  if (normalizedIcon == null || normalizedIcon.isEmpty) {
    return false;
  }
  final lowerIcon = normalizedIcon.toLowerCase();
  if (lowerIcon == 'none') {
    return true;
  }
  if (lowerIcon.startsWith('path://')) {
    final pathData = normalizedIcon.substring('path://'.length);
    final path = _fortuneRawChartGraphicSvgPath(pathData, Offset.zero);
    if (path == null) {
      return false;
    }
    final bounds = path.getBounds();
    if (bounds.width <= 0 || bounds.height <= 0) {
      return false;
    }
    final scale = math.min(
      rect.width / bounds.width,
      rect.height / bounds.height,
    );
    canvas.save();
    canvas.translate(
      rect.left + (rect.width - bounds.width * scale) / 2,
      rect.top + (rect.height - bounds.height * scale) / 2,
    );
    canvas.scale(scale, scale);
    canvas.translate(-bounds.left, -bounds.top);
    canvas.drawPath(path, paint);
    canvas.drawPath(
      path,
      Paint()
        ..color = paint.color
        ..style = PaintingStyle.stroke
        ..strokeCap = StrokeCap.round
        ..strokeJoin = StrokeJoin.round
        ..strokeWidth =
            math.max(1.5, math.min(rect.width, rect.height) / 6) / scale,
    );
    canvas.restore();
    return true;
  }
  switch (lowerIcon) {
    case 'circle':
    case 'emptycircle':
    case 'rect':
    case 'rectangle':
    case 'diamond':
    case 'triangle':
    case 'arrow':
      final iconPaint = lowerIcon == 'emptycircle'
          ? (Paint()
              ..color = paint.color
              ..style = PaintingStyle.stroke
              ..strokeWidth = math.max(2, math.min(rect.width, rect.height) / 8)
              ..strokeCap = StrokeCap.round
              ..strokeJoin = StrokeJoin.round)
          : paint;
      _fortuneDrawRawChartSeriesSymbol(
        canvas,
        rect.center,
        lowerIcon == 'arrow' ? 'triangle' : lowerIcon,
        math.min(rect.width, rect.height) / 2,
        iconPaint,
        lowerIcon == 'arrow' ? math.pi : 0,
        size: rect.size,
      );
      return true;
  }
  return false;
}

Size _fortuneRawChartAxisPointerHandlePaintSize(Object? rawSize) {
  if (rawSize is num && rawSize.isFinite) {
    final side = math.max(1.0, rawSize.toDouble());
    return Size(side, side);
  }
  if (rawSize is String) {
    final side = _fortuneRawShapeDouble(rawSize);
    if (side != null) {
      return Size.square(math.max(1.0, side));
    }
  }
  if (rawSize is List && rawSize.isNotEmpty) {
    final width = _fortuneRawShapeDouble(rawSize[0]);
    final height = rawSize.length > 1
        ? _fortuneRawShapeDouble(rawSize[1])
        : width;
    if (width != null && height != null) {
      return Size(math.max(1.0, width), math.max(1.0, height));
    }
  }
  return const Size(10, 18);
}

double _fortuneRawChartXAxisPointerPosition(
  Object? value,
  Rect plotRect,
  List<String> xAxisLabels,
  List<FortuneRawChartSeries> chartSeries, {
  required bool xAxisInverse,
  required bool xAxisBoundaryGap,
}) {
  var categoryCount = xAxisLabels.length;
  for (final series in chartSeries) {
    categoryCount = math.max(categoryCount, series.valueSlots.length);
    categoryCount = math.max(categoryCount, series.values.length);
  }
  double xForIndex(int index, int count) {
    final ratio = xAxisBoundaryGap
        ? (count <= 0 ? 0.0 : (index + 0.5) / count)
        : (count <= 1 ? 0.0 : index / (count - 1));
    return xAxisInverse
        ? plotRect.right - plotRect.width * ratio
        : plotRect.left + plotRect.width * ratio;
  }

  final index = _fortuneRawChartPointerCategoryIndex(value, xAxisLabels);
  if (index != null && categoryCount > 0) {
    return xForIndex(index.clamp(0, categoryCount - 1), categoryCount);
  }
  return plotRect.center.dx;
}

double _fortuneRawChartYAxisPointerPosition(
  Object? value,
  Rect plotRect,
  List<String> yAxisLabels,
  List<FortuneRawChartSeries> chartSeries, {
  required bool yAxisInverse,
}) {
  final numericValue = _fortuneRawChartPointerNumericValue(value);
  if (numericValue != null) {
    final values = _fortuneRawChartSeriesScaleValues(chartSeries);
    if (values.isNotEmpty) {
      final minimum = values.reduce(math.min);
      final maximum = values.reduce(math.max);
      if (minimum != maximum) {
        final ratio = ((numericValue - minimum) / (maximum - minimum)).clamp(
          0.0,
          1.0,
        );
        return yAxisInverse
            ? plotRect.top + ratio * plotRect.height
            : plotRect.bottom - ratio * plotRect.height;
      }
    }
  }

  final index = _fortuneRawChartPointerCategoryIndex(value, yAxisLabels);
  if (index != null && yAxisLabels.isNotEmpty) {
    final ratio = yAxisLabels.length <= 1
        ? 0.0
        : index.clamp(0, yAxisLabels.length - 1) / (yAxisLabels.length - 1);
    return yAxisInverse
        ? plotRect.top + plotRect.height * ratio
        : plotRect.bottom - plotRect.height * ratio;
  }
  return plotRect.center.dy;
}

int? _fortuneRawChartPointerCategoryIndex(Object? value, List<String> labels) {
  if (value == null) {
    return null;
  }
  if (value is num && value.isFinite) {
    return value.round();
  }
  if (value is String) {
    final trimmed = value.trim();
    if (trimmed.isEmpty) {
      return null;
    }
    final labelIndex = labels.indexWhere((label) => label == trimmed);
    if (labelIndex >= 0) {
      return labelIndex;
    }
    final parsed = double.tryParse(trimmed);
    if (parsed != null && parsed.isFinite) {
      return parsed.round();
    }
  }
  return null;
}

double? _fortuneRawChartPointerNumericValue(Object? value) {
  if (value is num && value.isFinite) {
    return value.toDouble();
  }
  if (value is String) {
    final parsed = double.tryParse(value.trim());
    if (parsed != null && parsed.isFinite) {
      return parsed;
    }
  }
  return null;
}

double _fortuneRawChartXAxisPointerAreaWidth(
  Rect plotRect,
  List<String> xAxisLabels,
  List<FortuneRawChartSeries> chartSeries,
) {
  var slotCount = xAxisLabels.length;
  for (final series in chartSeries) {
    slotCount = math.max(slotCount, series.valueSlots.length);
    slotCount = math.max(slotCount, series.values.length);
  }
  if (slotCount <= 0) {
    return math.min(20, plotRect.width);
  }
  return math.max(1.0, plotRect.width / slotCount);
}

double _fortuneRawChartYAxisPointerAreaHeight(
  Rect plotRect,
  List<String> yAxisLabels,
) {
  if (yAxisLabels.isEmpty) {
    return math.min(20, plotRect.height);
  }
  return math.max(1.0, plotRect.height / yAxisLabels.length);
}

void _fortuneDrawRawChartAxisPointerArea(
  Canvas canvas,
  Rect rect,
  Color? color, {
  Color? shadowColor,
  double? shadowBlur,
  double? shadowOffsetX,
  double? shadowOffsetY,
}) {
  if (shadowColor != null) {
    final shadowPaint = Paint()
      ..color = shadowColor
      ..style = PaintingStyle.fill
      ..maskFilter = shadowBlur != null && shadowBlur.isFinite && shadowBlur > 0
          ? MaskFilter.blur(BlurStyle.normal, shadowBlur)
          : null;
    canvas.drawRect(
      rect.shift(Offset(shadowOffsetX ?? 0, shadowOffsetY ?? 0)),
      shadowPaint,
    );
  }
  final paint = Paint()
    ..color = color ?? const Color(0x4d969696)
    ..style = PaintingStyle.fill;
  canvas.drawRect(rect, paint);
}

void _fortuneDrawRawChartAxisStrokeLine(
  Canvas canvas,
  Offset start,
  Offset end,
  Color color,
  double width,
  String? type,
  String? cap, {
  double? dashOffset,
}) {
  final paint = Paint()
    ..color = color
    ..strokeWidth = width
    ..style = PaintingStyle.stroke
    ..strokeCap = _fortuneRawChartStrokeCap(cap);
  final points = [start, end];
  final path = Path()
    ..moveTo(start.dx, start.dy)
    ..lineTo(end.dx, end.dy);
  _fortuneDrawRawChartSeriesLine(
    canvas,
    path,
    points,
    paint,
    type,
    dashOffset: dashOffset,
  );
}

double _fortuneDegreesToRadians(double? degrees) {
  if (degrees == null || !degrees.isFinite) {
    return 0;
  }
  return degrees * math.pi / 180;
}

void _fortuneDrawRawChartAxisLineArrow(
  Canvas canvas,
  Offset tip,
  Size size,
  Color color,
  double rotation,
) {
  final width = math.max(1.0, size.width);
  final height = math.max(1.0, size.height);
  final path = Path()
    ..moveTo(0, 0)
    ..lineTo(-width, -height / 2)
    ..lineTo(-width, height / 2)
    ..close();
  canvas.save();
  canvas.translate(tip.dx, tip.dy);
  canvas.rotate(rotation);
  canvas.drawPath(path, Paint()..color = color);
  canvas.restore();
}

void _fortuneDrawRawChartLineRect(
  Canvas canvas,
  Rect rect,
  Color color,
  String? type, {
  required bool horizontal,
  double? dashOffset,
}) {
  final paint = Paint()..color = color;
  if (type != 'dashed' && type != 'dotted') {
    canvas.drawRect(rect, paint);
    return;
  }
  final segmentLength = type == 'dotted'
      ? math.max(1.5, horizontal ? rect.height : rect.width)
      : 7.0;
  final gapLength = type == 'dotted' ? segmentLength * 1.6 : 4.0;
  final start = horizontal ? rect.left : rect.top;
  final end = horizontal ? rect.right : rect.bottom;
  final patternLength = segmentLength + gapLength;
  final normalizedOffset = patternLength <= 0
      ? 0.0
      : (((dashOffset ?? 0) % patternLength) + patternLength) % patternLength;
  var position = start - normalizedOffset;
  while (position < end) {
    final segmentStart = math.max(start, position);
    final segmentEnd = math.min(end, position + segmentLength);
    if (segmentEnd > segmentStart) {
      final segmentRect = horizontal
          ? Rect.fromLTRB(segmentStart, rect.top, segmentEnd, rect.bottom)
          : Rect.fromLTRB(rect.left, segmentStart, rect.right, segmentEnd);
      canvas.drawRect(segmentRect, paint);
    }
    position += patternLength;
  }
}

void _fortuneDrawRawChartTickLine(
  Canvas canvas, {
  required Offset start,
  required Offset end,
  required Color color,
  required double width,
  required String? type,
  required String? cap,
  double? dashOffset,
}) {
  if (cap == null) {
    final horizontal = (end.dy - start.dy).abs() < (end.dx - start.dx).abs();
    _fortuneDrawRawChartLineRect(
      canvas,
      horizontal
          ? Rect.fromLTRB(
              math.min(start.dx, end.dx),
              start.dy - width / 2,
              math.max(start.dx, end.dx),
              start.dy + width / 2,
            )
          : Rect.fromLTRB(
              start.dx - width / 2,
              math.min(start.dy, end.dy),
              start.dx + width / 2,
              math.max(start.dy, end.dy),
            ),
      color,
      type,
      horizontal: horizontal,
      dashOffset: dashOffset,
    );
    return;
  }
  _fortuneDrawRawChartAxisStrokeLine(
    canvas,
    start,
    end,
    color,
    width,
    type,
    cap,
    dashOffset: dashOffset,
  );
}

void _fortuneDrawRawChartShadowLine(
  Canvas canvas, {
  required Offset start,
  required Offset end,
  required Color? color,
  required double width,
  required String? type,
  required String? cap,
  double? blur,
  double? offsetX,
  double? offsetY,
  double? dashOffset,
}) {
  if (color == null) {
    return;
  }
  final effectiveBlur = blur ?? 0;
  final paint = Paint()
    ..color = color
    ..style = PaintingStyle.stroke
    ..strokeWidth = width
    ..strokeCap = _fortuneRawChartStrokeCap(cap);
  if (effectiveBlur.isFinite && effectiveBlur > 0) {
    paint.maskFilter = MaskFilter.blur(BlurStyle.normal, effectiveBlur);
  }
  final shadowStart = start.translate(offsetX ?? 0, offsetY ?? 0);
  final shadowEnd = end.translate(offsetX ?? 0, offsetY ?? 0);
  final points = [shadowStart, shadowEnd];
  final path = Path()
    ..moveTo(shadowStart.dx, shadowStart.dy)
    ..lineTo(shadowEnd.dx, shadowEnd.dy);
  _fortuneDrawRawChartSeriesLine(
    canvas,
    path,
    points,
    paint,
    type,
    dashOffset: dashOffset,
  );
}

void _fortuneDrawRawChartAxisTicks(
  Canvas canvas,
  Rect chartRect,
  double axisLeft,
  double axisBottom, {
  required double plotAxisLeft,
  required double plotAxisBottom,
  required bool xAxisTickVisible,
  required bool yAxisTickVisible,
  required Color xAxisTickColor,
  required Color yAxisTickColor,
  List<Color> xAxisTickColors = const [],
  List<Color> yAxisTickColors = const [],
  required double xAxisTickWidth,
  required double yAxisTickWidth,
  required double xAxisTickLength,
  required double yAxisTickLength,
  String? xAxisTickType,
  String? yAxisTickType,
  double? xAxisTickDashOffset,
  double? yAxisTickDashOffset,
  String? xAxisTickCap,
  String? yAxisTickCap,
  Color? xAxisTickShadowColor,
  Color? yAxisTickShadowColor,
  double? xAxisTickShadowBlur,
  double? yAxisTickShadowBlur,
  double? xAxisTickShadowOffsetX,
  double? yAxisTickShadowOffsetX,
  double? xAxisTickShadowOffsetY,
  double? yAxisTickShadowOffsetY,
  double? xAxisTickOpacity,
  double? yAxisTickOpacity,
  int? xAxisTickInterval,
  int? yAxisTickInterval,
  required bool xAxisTickAlignWithLabel,
  required bool yAxisTickAlignWithLabel,
  required bool xAxisTickInside,
  required bool yAxisTickInside,
  required bool xAxisMinorTickVisible,
  required bool yAxisMinorTickVisible,
  required Color xAxisMinorTickColor,
  required Color yAxisMinorTickColor,
  List<Color> xAxisMinorTickColors = const [],
  List<Color> yAxisMinorTickColors = const [],
  required double xAxisMinorTickWidth,
  required double yAxisMinorTickWidth,
  required double xAxisMinorTickLength,
  required double yAxisMinorTickLength,
  String? xAxisMinorTickType,
  String? yAxisMinorTickType,
  double? xAxisMinorTickDashOffset,
  double? yAxisMinorTickDashOffset,
  String? xAxisMinorTickCap,
  String? yAxisMinorTickCap,
  Color? xAxisMinorTickShadowColor,
  Color? yAxisMinorTickShadowColor,
  double? xAxisMinorTickShadowBlur,
  double? yAxisMinorTickShadowBlur,
  double? xAxisMinorTickShadowOffsetX,
  double? yAxisMinorTickShadowOffsetX,
  double? xAxisMinorTickShadowOffsetY,
  double? yAxisMinorTickShadowOffsetY,
  double? xAxisMinorTickOpacity,
  double? yAxisMinorTickOpacity,
  int? xAxisMinorTickSplitNumber,
  int? yAxisMinorTickSplitNumber,
}) {
  double xTickPosition(int index) {
    return xAxisTickAlignWithLabel
        ? plotAxisLeft + (chartRect.right - plotAxisLeft) * (index + 0.5) / 4
        : plotAxisLeft + (chartRect.right - plotAxisLeft) * index / 3;
  }

  double yTickPosition(int index) {
    return yAxisTickAlignWithLabel
        ? chartRect.top + (plotAxisBottom - chartRect.top) * (index + 0.5) / 4
        : chartRect.top + (plotAxisBottom - chartRect.top) * index / 3;
  }

  if (xAxisTickVisible) {
    final step = math.max(1, (xAxisTickInterval ?? 0) + 1);
    final colors = xAxisTickColors.isEmpty ? [xAxisTickColor] : xAxisTickColors;
    for (var index = 0; index < 4; index += 1) {
      if (index % step != 0) {
        continue;
      }
      final baseColor = colors[index % colors.length];
      final tickColor = xAxisTickColors.isEmpty
          ? baseColor
          : _fortuneRawChartColorWithOpacity(baseColor, xAxisTickOpacity) ??
                baseColor;
      final x = xTickPosition(index);
      final tickTop = xAxisTickInside
          ? axisBottom - xAxisTickLength
          : axisBottom;
      final tickBottom = xAxisTickInside
          ? axisBottom
          : axisBottom + xAxisTickLength;
      _fortuneDrawRawChartShadowLine(
        canvas,
        start: Offset(x, tickTop),
        end: Offset(x, tickBottom),
        color: xAxisTickShadowColor,
        width: xAxisTickWidth,
        type: xAxisTickType,
        cap: xAxisTickCap,
        blur: xAxisTickShadowBlur,
        offsetX: xAxisTickShadowOffsetX,
        offsetY: xAxisTickShadowOffsetY,
        dashOffset: xAxisTickDashOffset,
      );
      _fortuneDrawRawChartTickLine(
        canvas,
        start: Offset(x, tickTop),
        end: Offset(x, tickBottom),
        color: tickColor,
        width: xAxisTickWidth,
        type: xAxisTickType,
        cap: xAxisTickCap,
        dashOffset: xAxisTickDashOffset,
      );
    }
  }
  if (xAxisMinorTickVisible) {
    final splitNumber = math.max(2, xAxisMinorTickSplitNumber ?? 5);
    final intervalCount = xAxisTickAlignWithLabel ? 3 : 3;
    final colors = xAxisMinorTickColors.isEmpty
        ? [xAxisMinorTickColor]
        : xAxisMinorTickColors;
    for (var index = 0; index < intervalCount; index += 1) {
      final start = xTickPosition(index);
      final end = xTickPosition(index + 1);
      for (var splitIndex = 1; splitIndex < splitNumber; splitIndex += 1) {
        final lineIndex = index * (splitNumber - 1) + splitIndex - 1;
        final baseColor = colors[lineIndex % colors.length];
        final tickColor = xAxisMinorTickColors.isEmpty
            ? baseColor
            : _fortuneRawChartColorWithOpacity(
                    baseColor,
                    xAxisMinorTickOpacity,
                  ) ??
                  baseColor;
        final ratio = splitIndex / splitNumber;
        final x = start + (end - start) * ratio;
        final tickTop = xAxisTickInside
            ? axisBottom - xAxisMinorTickLength
            : axisBottom;
        final tickBottom = xAxisTickInside
            ? axisBottom
            : axisBottom + xAxisMinorTickLength;
        _fortuneDrawRawChartShadowLine(
          canvas,
          start: Offset(x, tickTop),
          end: Offset(x, tickBottom),
          color: xAxisMinorTickShadowColor,
          width: xAxisMinorTickWidth,
          type: xAxisMinorTickType,
          cap: xAxisMinorTickCap,
          blur: xAxisMinorTickShadowBlur,
          offsetX: xAxisMinorTickShadowOffsetX,
          offsetY: xAxisMinorTickShadowOffsetY,
          dashOffset: xAxisMinorTickDashOffset,
        );
        _fortuneDrawRawChartTickLine(
          canvas,
          start: Offset(x, tickTop),
          end: Offset(x, tickBottom),
          color: tickColor,
          width: xAxisMinorTickWidth,
          type: xAxisMinorTickType,
          cap: xAxisMinorTickCap,
          dashOffset: xAxisMinorTickDashOffset,
        );
      }
    }
  }
  if (yAxisTickVisible) {
    final step = math.max(1, (yAxisTickInterval ?? 0) + 1);
    final colors = yAxisTickColors.isEmpty ? [yAxisTickColor] : yAxisTickColors;
    for (var index = 0; index < 4; index += 1) {
      if (index % step != 0) {
        continue;
      }
      final baseColor = colors[index % colors.length];
      final tickColor = yAxisTickColors.isEmpty
          ? baseColor
          : _fortuneRawChartColorWithOpacity(baseColor, yAxisTickOpacity) ??
                baseColor;
      final y = yTickPosition(index);
      final tickLeft = yAxisTickInside ? axisLeft : axisLeft - yAxisTickLength;
      final tickRight = yAxisTickInside ? axisLeft + yAxisTickLength : axisLeft;
      _fortuneDrawRawChartShadowLine(
        canvas,
        start: Offset(tickLeft, y),
        end: Offset(tickRight, y),
        color: yAxisTickShadowColor,
        width: yAxisTickWidth,
        type: yAxisTickType,
        cap: yAxisTickCap,
        blur: yAxisTickShadowBlur,
        offsetX: yAxisTickShadowOffsetX,
        offsetY: yAxisTickShadowOffsetY,
        dashOffset: yAxisTickDashOffset,
      );
      _fortuneDrawRawChartTickLine(
        canvas,
        start: Offset(tickLeft, y),
        end: Offset(tickRight, y),
        color: tickColor,
        width: yAxisTickWidth,
        type: yAxisTickType,
        cap: yAxisTickCap,
        dashOffset: yAxisTickDashOffset,
      );
    }
  }
  if (yAxisMinorTickVisible) {
    final splitNumber = math.max(2, yAxisMinorTickSplitNumber ?? 5);
    final intervalCount = yAxisTickAlignWithLabel ? 3 : 3;
    final colors = yAxisMinorTickColors.isEmpty
        ? [yAxisMinorTickColor]
        : yAxisMinorTickColors;
    for (var index = 0; index < intervalCount; index += 1) {
      final start = yTickPosition(index);
      final end = yTickPosition(index + 1);
      for (var splitIndex = 1; splitIndex < splitNumber; splitIndex += 1) {
        final lineIndex = index * (splitNumber - 1) + splitIndex - 1;
        final baseColor = colors[lineIndex % colors.length];
        final tickColor = yAxisMinorTickColors.isEmpty
            ? baseColor
            : _fortuneRawChartColorWithOpacity(
                    baseColor,
                    yAxisMinorTickOpacity,
                  ) ??
                  baseColor;
        final ratio = splitIndex / splitNumber;
        final y = start + (end - start) * ratio;
        final tickLeft = yAxisTickInside
            ? axisLeft
            : axisLeft - yAxisMinorTickLength;
        final tickRight = yAxisTickInside
            ? axisLeft + yAxisMinorTickLength
            : axisLeft;
        _fortuneDrawRawChartShadowLine(
          canvas,
          start: Offset(tickLeft, y),
          end: Offset(tickRight, y),
          color: yAxisMinorTickShadowColor,
          width: yAxisMinorTickWidth,
          type: yAxisMinorTickType,
          cap: yAxisMinorTickCap,
          blur: yAxisMinorTickShadowBlur,
          offsetX: yAxisMinorTickShadowOffsetX,
          offsetY: yAxisMinorTickShadowOffsetY,
          dashOffset: yAxisMinorTickDashOffset,
        );
        _fortuneDrawRawChartTickLine(
          canvas,
          start: Offset(tickLeft, y),
          end: Offset(tickRight, y),
          color: tickColor,
          width: yAxisMinorTickWidth,
          type: yAxisMinorTickType,
          cap: yAxisMinorTickCap,
          dashOffset: yAxisMinorTickDashOffset,
        );
      }
    }
  }
}

void _fortuneDrawRawChartSeries(
  Canvas canvas,
  Rect chartRect,
  double axisLeft,
  double axisBottom,
  Rect plotRect,
  List<FortuneRawChartSeries> series, {
  required bool xAxisInverse,
  required bool yAxisInverse,
  required bool xAxisBoundaryGap,
  _FortuneRawChartDataZoomWindow? dataZoomWindow,
  Offset? hoverPosition,
}) {
  final allValues = _fortuneRawChartSeriesScaleValues(
    series,
    dataZoomWindow: dataZoomWindow,
  );
  if (allValues.isEmpty) {
    return;
  }
  var minimum = allValues.reduce(math.min);
  var maximum = allValues.reduce(math.max);
  if (minimum == maximum) {
    minimum -= 1;
    maximum += 1;
  }
  if (plotRect.width <= 0 || plotRect.height <= 0) {
    return;
  }
  double yFor(double value) {
    final ratio = (value - minimum) / (maximum - minimum);
    return yAxisInverse
        ? plotRect.top + ratio * plotRect.height
        : plotRect.bottom - ratio * plotRect.height;
  }

  double xForIndex(int index, int count) {
    final ratio = xAxisBoundaryGap
        ? (count <= 0 ? 0.0 : (index + 0.5) / count)
        : (count <= 1 ? 0.0 : index / (count - 1));
    return xAxisInverse
        ? plotRect.right - plotRect.width * ratio
        : plotRect.left + plotRect.width * ratio;
  }

  final scatterXValues = <double>[
    for (final item in series)
      if (_fortuneRawChartTypeIsScatter(item.type))
        for (final value in item.xValueSlots)
          if (value != null && value.isFinite) value,
  ];
  var scatterXMinimum = scatterXValues.isEmpty
      ? null
      : scatterXValues.reduce(math.min);
  var scatterXMaximum = scatterXValues.isEmpty
      ? null
      : scatterXValues.reduce(math.max);
  if (scatterXMinimum != null &&
      scatterXMaximum != null &&
      scatterXMinimum == scatterXMaximum) {
    scatterXMinimum -= 1;
    scatterXMaximum += 1;
  }

  double xForScatterValue(double value) {
    if (scatterXMinimum == null || scatterXMaximum == null) {
      return xForIndex(0, 1);
    }
    final ratio =
        (value - scatterXMinimum) / (scatterXMaximum - scatterXMinimum);
    return xAxisInverse
        ? plotRect.right - plotRect.width * ratio
        : plotRect.left + plotRect.width * ratio;
  }

  const colors = [
    Color(0xff0188fb),
    Color(0xffffb300),
    Color(0xff34a853),
    Color(0xffea4335),
  ];
  final barGroupKeys = _fortuneRawChartBarGroupKeys(series);
  final barSeriesCount = barGroupKeys.length;
  final groupedBarGap = series
      .where((item) => item.type == 'bar' || item.type == 'column')
      .where((item) => item.barGap != null)
      .firstOrNull;
  final stackPositiveOffsets = <String, List<double>>{};
  final stackNegativeOffsets = <String, List<double>>{};
  for (var seriesIndex = 0; seriesIndex < series.length; seriesIndex += 1) {
    final item = series[seriesIndex];
    final color = _fortuneRawChartSeriesPaintColor(item, seriesIndex, colors);
    final values = item.values;
    if (values.isEmpty) {
      continue;
    }
    if (_fortuneRawChartTypeIsPie(item.type)) {
      _fortuneDrawRawChartPie(canvas, plotRect, item);
      continue;
    }
    if (_fortuneRawChartTypeIsCandlestick(item.type)) {
      _fortuneDrawRawChartCandlestickSeries(
        canvas,
        item,
        color,
        plotRect,
        xForIndex,
        yFor,
        xAxisInverse: xAxisInverse,
      );
      _fortuneDrawRawChartSeriesMarkPoints(
        canvas,
        values,
        item,
        color,
        item.candlestickPoints.length,
        xForIndex,
        yFor,
      );
      _fortuneDrawRawChartSeriesMarkLines(
        canvas,
        values,
        item,
        color,
        plotRect,
        item.candlestickPoints.length,
        xForIndex,
        yFor,
      );
      continue;
    }
    if (_fortuneRawChartTypeIsHeatmap(item.type)) {
      _fortuneDrawRawChartHeatmapSeries(canvas, item, color, plotRect);
      continue;
    }
    if (_fortuneRawChartTypeIsFunnel(item.type)) {
      _fortuneDrawRawChartFunnelSeries(canvas, item, color, plotRect);
      continue;
    }
    if (_fortuneRawChartTypeIsGauge(item.type)) {
      _fortuneDrawRawChartGaugeSeries(canvas, item, color, plotRect);
      continue;
    }
    if (_fortuneRawChartTypeIsRadar(item.type)) {
      _fortuneDrawRawChartRadarSeries(canvas, item, color, plotRect);
      continue;
    }
    if (_fortuneRawChartTypeIsTreemap(item.type)) {
      _fortuneDrawRawChartTreemapSeries(canvas, item, color, plotRect);
      continue;
    }
    if (_fortuneRawChartTypeIsBoxplot(item.type)) {
      _fortuneDrawRawChartBoxplotSeries(
        canvas,
        item,
        color,
        plotRect,
        xForIndex,
        yFor,
      );
      continue;
    }
    if (_fortuneRawChartTypeIsPictorialBar(item.type)) {
      _fortuneDrawRawChartPictorialBarSeries(
        canvas,
        item,
        color,
        plotRect,
        xForIndex,
        yFor,
        yAxisInverse: yAxisInverse,
      );
      continue;
    }
    if (_fortuneRawChartTypeIsScatter(item.type)) {
      final valueSlots = item.valueSlots.isEmpty
          ? <double?>[for (final value in values) value]
          : item.valueSlots;
      final categoryCount = valueSlots.length;
      _fortuneDrawRawChartSeriesMarkAreas(
        canvas,
        values,
        item,
        plotRect,
        categoryCount,
        xForIndex,
        yFor,
        xForValue: xForScatterValue,
      );
      for (var index = 0; index < valueSlots.length; index += 1) {
        if (!_fortuneRawChartDataZoomContainsIndex(dataZoomWindow, index)) {
          continue;
        }
        final value = valueSlots[index];
        if (value == null) {
          continue;
        }
        if (!_fortuneRawChartDataZoomContainsValue(dataZoomWindow, value)) {
          continue;
        }
        final pointSymbol = index < item.pointSymbols.length
            ? item.pointSymbols[index]
            : null;
        final pointSymbolSize = index < item.pointSymbolSizes.length
            ? item.pointSymbolSizes[index]
            : null;
        final pointSymbolOffset = index < item.pointSymbolOffsets.length
            ? item.pointSymbolOffsets[index]
            : null;
        final pointSymbolRotationDegrees =
            index < item.pointSymbolRotationDegrees.length
            ? item.pointSymbolRotationDegrees[index]
            : null;
        final radius = (pointSymbolSize ?? item.symbolSize ?? 7.0) / 2;
        final xValue = index < item.xValueSlots.length
            ? item.xValueSlots[index]
            : null;
        final pointColor = index < item.pointColors.length
            ? item.pointColors[index]
            : null;
        final pointOpacity = index < item.pointOpacities.length
            ? item.pointOpacities[index]
            : null;
        final symbolColor = pointColor ?? item.itemColor ?? color;
        final emphasized = _fortuneRawChartPointIsHovered(
          hoverPosition,
          Offset(
                xValue == null || !xValue.isFinite
                    ? xForIndex(index, categoryCount)
                    : xForScatterValue(xValue),
                yFor(value),
              ) +
              (pointSymbolOffset ?? item.symbolOffset ?? Offset.zero),
          radius,
          item,
        );
        final effectiveSymbolColor = emphasized
            ? item.emphasisItemColor ?? symbolColor
            : symbolColor;
        final effectiveOpacity = emphasized
            ? item.emphasisItemOpacity ?? pointOpacity ?? item.itemOpacity
            : pointOpacity ?? item.itemOpacity;
        final paint = Paint()
          ..color =
              _fortuneRawChartColorWithOpacity(
                effectiveSymbolColor,
                effectiveOpacity,
              ) ??
              effectiveSymbolColor
          ..blendMode = _fortuneRawChartBlendMode(item.blendMode);
        final center =
            Offset(
              xValue == null || !xValue.isFinite
                  ? xForIndex(index, categoryCount)
                  : xForScatterValue(xValue),
              yFor(value),
            ) +
            (pointSymbolOffset ?? item.symbolOffset ?? Offset.zero);
        final symbol = pointSymbol ?? item.symbol;
        final rotationRadians = _fortuneDegreesToRadians(
          pointSymbolRotationDegrees ?? item.symbolRotationDegrees,
        );
        final shouldClipSymbol = item.clip == true;
        if (shouldClipSymbol) {
          canvas.save();
          canvas.clipRect(plotRect);
        }
        _fortuneDrawRawChartSeriesSymbolShadow(
          canvas,
          center,
          symbol,
          radius,
          rotationRadians,
          _fortuneRawChartResolvedPointShadowColor(item, index),
          _fortuneRawChartResolvedPointShadowBlur(item, index),
          _fortuneRawChartResolvedPointShadowOffset(item, index),
        );
        _fortuneDrawRawChartSeriesSymbol(
          canvas,
          center,
          symbol,
          radius,
          paint,
          rotationRadians,
        );
        _fortuneDrawRawChartSeriesSymbolBorder(
          canvas,
          center,
          symbol,
          radius,
          rotationRadians,
          _fortuneRawChartResolvedPointBorderColor(item, index),
          _fortuneRawChartResolvedPointBorderWidth(item, index),
          _fortuneRawChartResolvedPointBorderType(item, index),
        );
        if (emphasized) {
          _fortuneDrawRawChartSeriesSymbolBorder(
            canvas,
            center,
            symbol,
            radius,
            rotationRadians,
            item.emphasisItemBorderColor,
            item.emphasisItemBorderWidth,
            item.emphasisItemBorderType,
          );
        }
      }
      _fortuneDrawRawChartSeriesLineLabels(
        canvas,
        item,
        valueSlots,
        categoryCount,
        (index, count) {
          final xValue = index < item.xValueSlots.length
              ? item.xValueSlots[index]
              : null;
          return xValue == null || !xValue.isFinite
              ? xForIndex(index, count)
              : xForScatterValue(xValue);
        },
        yFor,
      );
      _fortuneDrawRawChartSeriesMarkPoints(
        canvas,
        values,
        item,
        color,
        categoryCount,
        xForIndex,
        yFor,
        xForMarkPoint: (markPoint, index, count) {
          final xValue = markPoint.xValue;
          return xValue == null || !xValue.isFinite
              ? xForIndex(index, count)
              : xForScatterValue(xValue);
        },
      );
      _fortuneDrawRawChartSeriesMarkLines(
        canvas,
        values,
        item,
        color,
        plotRect,
        categoryCount,
        xForIndex,
        yFor,
        xForValue: xForScatterValue,
      );
      continue;
    }
    if (item.type == 'bar' || item.type == 'column') {
      final barValueIndices = _fortuneRawChartDataZoomValueIndices(
        values,
        dataZoomWindow,
      );
      if (barValueIndices.isEmpty) {
        continue;
      }
      final barGroupKey = _fortuneRawChartBarGroupKey(item, seriesIndex);
      final currentBarSeriesPosition = barGroupKeys.indexOf(barGroupKey);
      final step = plotRect.width / barValueIndices.length;
      final grouped = barSeriesCount > 1 && groupedBarGap != null;
      final barWidth = grouped
          ? _fortuneRawChartGroupedBarWidth(
              item,
              step,
              barSeriesCount,
              groupedBarGap,
            )
          : _fortuneRawChartSingleBarWidth(item, step);
      final barGapWidth = grouped
          ? _fortuneRawChartBarGapWidth(groupedBarGap, barWidth)
          : 0.0;
      final groupWidth = grouped
          ? barWidth * barSeriesCount + barGapWidth * (barSeriesCount - 1)
          : barWidth;
      _fortuneDrawRawChartSeriesMarkAreas(
        canvas,
        values,
        item,
        plotRect,
        barValueIndices.length,
        xForIndex,
        yFor,
      );
      for (
        var slotIndex = 0;
        slotIndex < barValueIndices.length;
        slotIndex += 1
      ) {
        final index = barValueIndices[slotIndex];
        if (!_fortuneRawChartDataZoomContainsIndex(dataZoomWindow, index)) {
          continue;
        }
        final categoryCenterX = xAxisInverse
            ? plotRect.right - step * slotIndex - step / 2
            : plotRect.left + step * slotIndex + step / 2;
        final centerX = grouped
            ? categoryCenterX -
                  groupWidth / 2 +
                  currentBarSeriesPosition * (barWidth + barGapWidth) +
                  barWidth / 2
            : categoryCenterX;
        _fortuneDrawRawChartBarBackground(
          canvas,
          item,
          Rect.fromLTRB(
            centerX - barWidth / 2,
            plotRect.top,
            centerX + barWidth / 2,
            plotRect.bottom,
          ),
        );
        final value = values[index];
        if (!_fortuneRawChartDataZoomContainsValue(dataZoomWindow, value)) {
          continue;
        }
        final stacked = item.stack != null;
        final positiveOffsets = stackPositiveOffsets.putIfAbsent(
          barGroupKey,
          () => List<double>.filled(barValueIndices.length, 0),
        );
        final negativeOffsets = stackNegativeOffsets.putIfAbsent(
          barGroupKey,
          () => List<double>.filled(barValueIndices.length, 0),
        );
        final stackBase = stacked
            ? (value >= 0
                  ? positiveOffsets[slotIndex]
                  : negativeOffsets[slotIndex])
            : 0.0;
        final stackEnd = stackBase + value;
        final valueY = yFor(stackEnd);
        final baselineY = stacked
            ? yFor(stackBase)
            : (yAxisInverse ? plotRect.top : plotRect.bottom);
        var barTop = math.min(valueY, baselineY);
        var barBottom = math.max(valueY, baselineY);
        if (stacked) {
          if (value >= 0) {
            positiveOffsets[slotIndex] = stackEnd;
          } else {
            negativeOffsets[slotIndex] = stackEnd;
          }
        }
        final minHeight = item.barMinHeight;
        if (minHeight != null && barBottom - barTop < minHeight) {
          if (valueY <= baselineY) {
            barTop = math.max(plotRect.top, baselineY - minHeight);
            barBottom = baselineY;
          } else {
            barTop = baselineY;
            barBottom = math.min(plotRect.bottom, baselineY + minHeight);
          }
        }
        final barRect = Rect.fromLTRB(
          centerX - barWidth / 2,
          barTop,
          centerX + barWidth / 2,
          barBottom,
        );
        final pointBorderRadius = index < item.pointBorderRadii.length
            ? item.pointBorderRadii[index]
            : null;
        final itemBorderRadius = pointBorderRadius ?? item.itemBorderRadius;
        final pointShadowColor = index < item.pointShadowColors.length
            ? item.pointShadowColors[index]
            : null;
        final pointShadowBlur = index < item.pointShadowBlurs.length
            ? item.pointShadowBlurs[index]
            : null;
        final pointShadowOffsetX = index < item.pointShadowOffsetXs.length
            ? item.pointShadowOffsetXs[index]
            : null;
        final pointShadowOffsetY = index < item.pointShadowOffsetYs.length
            ? item.pointShadowOffsetYs[index]
            : null;
        final shadowColor = pointShadowColor ?? item.itemShadowColor;
        if (shadowColor != null) {
          final shadowRect = barRect.shift(
            Offset(
              pointShadowOffsetX ?? item.itemShadowOffsetX ?? 0,
              pointShadowOffsetY ?? item.itemShadowOffsetY ?? 0,
            ),
          );
          final shadowPaint = Paint()..color = shadowColor;
          final shadowBlur = pointShadowBlur ?? item.itemShadowBlur;
          if (shadowBlur != null && shadowBlur > 0) {
            shadowPaint.maskFilter = ui.MaskFilter.blur(
              ui.BlurStyle.normal,
              shadowBlur,
            );
          }
          if (itemBorderRadius != null) {
            canvas.drawRRect(
              RRect.fromRectAndRadius(
                shadowRect,
                Radius.circular(
                  math.min(
                    itemBorderRadius,
                    math.min(shadowRect.width, shadowRect.height) / 2,
                  ),
                ),
              ),
              shadowPaint,
            );
          } else {
            canvas.drawRect(shadowRect, shadowPaint);
          }
        }
        final barPaint = Paint()
          ..color =
              _fortuneRawChartColorWithOpacity(
                color,
                item.itemOpacity ?? 0.82,
              ) ??
              color.withValues(alpha: 0.82)
          ..blendMode = _fortuneRawChartBlendMode(item.blendMode);
        if (itemBorderRadius != null) {
          canvas.drawRRect(
            RRect.fromRectAndRadius(
              barRect,
              Radius.circular(
                math.min(
                  itemBorderRadius,
                  math.min(barRect.width, barRect.height) / 2,
                ),
              ),
            ),
            barPaint,
          );
        } else {
          canvas.drawRect(barRect, barPaint);
        }
        final pointBorderColor = index < item.pointBorderColors.length
            ? item.pointBorderColors[index]
            : null;
        final pointBorderWidth = index < item.pointBorderWidths.length
            ? item.pointBorderWidths[index]
            : null;
        final pointBorderType = index < item.pointBorderTypes.length
            ? item.pointBorderTypes[index]
            : null;
        final itemBorderColor = pointBorderColor ?? item.itemBorderColor;
        final itemBorderWidth = pointBorderWidth ?? item.itemBorderWidth;
        final itemBorderType = pointBorderType ?? item.itemBorderType;
        if (itemBorderColor != null && itemBorderWidth != null) {
          final borderPaint = Paint()
            ..color = itemBorderColor
            ..style = PaintingStyle.stroke
            ..strokeWidth = itemBorderWidth;
          if (itemBorderRadius != null) {
            canvas.drawRRect(
              RRect.fromRectAndRadius(
                barRect.deflate(itemBorderWidth / 2),
                Radius.circular(
                  math.min(
                    itemBorderRadius,
                    math.min(barRect.width, barRect.height) / 2,
                  ),
                ),
              ),
              borderPaint,
            );
          } else if (itemBorderType == 'dashed' || itemBorderType == 'dotted') {
            _fortuneDrawRawChartDashedRect(
              canvas,
              barRect.deflate(itemBorderWidth / 2),
              borderPaint,
              itemBorderType!,
            );
          } else {
            canvas.drawRect(barRect.deflate(itemBorderWidth / 2), borderPaint);
          }
        }
        _fortuneDrawRawChartSeriesDataLabel(
          canvas,
          item,
          values[index],
          index,
          item.type,
          Rect.fromLTRB(
            barRect.left,
            barRect.top,
            barRect.right,
            barRect.bottom,
          ),
          labelLayoutRect: plotRect,
        );
      }
      _fortuneDrawRawChartSeriesMarkPoints(
        canvas,
        values,
        item,
        color,
        values.length,
        xForIndex,
        yFor,
      );
      _fortuneDrawRawChartSeriesMarkLines(
        canvas,
        values,
        item,
        color,
        plotRect,
        values.length,
        xForIndex,
        yFor,
      );
      continue;
    }
    final valueSlots = item.valueSlots.isEmpty
        ? <double?>[for (final value in values) value]
        : item.valueSlots;
    final filteredValueSlots = _fortuneRawChartDataZoomValueSlots(
      valueSlots,
      dataZoomWindow,
    );
    final sampledValueSlots = _fortuneRawChartSeriesSampledValueSlots(
      filteredValueSlots,
      item.sampling,
      plotRect.width,
    );
    final nonNullValues = sampledValueSlots.whereType<double>().toList();
    if (nonNullValues.length < 2) {
      continue;
    }
    final categoryCount = sampledValueSlots.length;
    _fortuneDrawRawChartSeriesMarkAreas(
      canvas,
      values,
      item,
      plotRect,
      categoryCount,
      xForIndex,
      yFor,
    );
    final linePaint = Paint()
      ..color =
          _fortuneRawChartColorWithOpacity(color, item.lineOpacity) ?? color
      ..blendMode = _fortuneRawChartBlendMode(item.blendMode)
      ..strokeWidth = item.lineWidth ?? 1.8
      ..style = PaintingStyle.stroke
      ..strokeCap = _fortuneRawChartStrokeCap(item.lineCap)
      ..strokeJoin = _fortuneRawChartStrokeJoin(item.lineJoin);
    if (item.lineMiterLimit != null) {
      linePaint.strokeMiterLimit = item.lineMiterLimit!;
    }
    final lineRuns = _fortuneRawChartSeriesPointRuns(
      sampledValueSlots,
      categoryCount,
      xForIndex,
      yFor,
      connectNulls:
          item.connectNulls == true || sampledValueSlots != filteredValueSlots,
    );
    for (final points in lineRuns) {
      if (points.length < 2) {
        continue;
      }
      final shouldClipLinePath = item.clip == true;
      if (shouldClipLinePath) {
        canvas.save();
        canvas.clipRect(plotRect);
      }
      final linePoints = _fortuneRawChartSeriesLinePoints(points, item.step);
      final smooth = item.smooth == true && item.step == null;
      final path = smooth
          ? _fortuneRawChartSeriesSmoothLinePath(linePoints)
          : _fortuneRawChartSeriesLinePath(linePoints);
      final lineDashPoints = smooth
          ? _fortuneRawChartSeriesSmoothLineDashPoints(linePoints)
          : linePoints;
      if (_fortuneRawChartTypeIsArea(item.type)) {
        final baselineY = item.areaOrigin == 'end'
            ? (yAxisInverse ? plotRect.bottom : plotRect.top)
            : (yAxisInverse ? plotRect.top : plotRect.bottom);
        final areaColor = item.areaColor ?? color;
        final areaPath = Path.from(path)
          ..lineTo(points.last.dx, baselineY)
          ..lineTo(points.first.dx, baselineY)
          ..close();
        if (item.areaShadowColor != null) {
          final shadowPaint = Paint()..color = item.areaShadowColor!;
          if (item.areaShadowBlur != null && item.areaShadowBlur! > 0) {
            shadowPaint.maskFilter = ui.MaskFilter.blur(
              ui.BlurStyle.normal,
              item.areaShadowBlur!,
            );
          }
          canvas.drawPath(
            areaPath.shift(
              Offset(item.areaShadowOffsetX ?? 0, item.areaShadowOffsetY ?? 0),
            ),
            shadowPaint,
          );
        }
        canvas.drawPath(
          areaPath,
          Paint()
            ..color =
                _fortuneRawChartColorWithOpacity(
                  areaColor,
                  item.areaOpacity ?? (72 / 255),
                ) ??
                areaColor.withAlpha(72)
            ..blendMode = _fortuneRawChartBlendMode(item.blendMode),
        );
      }
      if (item.lineShadowColor != null) {
        final shadowOffset = Offset(
          item.lineShadowOffsetX ?? 0,
          item.lineShadowOffsetY ?? 0,
        );
        final shadowPaint = Paint()
          ..color = item.lineShadowColor!
          ..strokeWidth = linePaint.strokeWidth
          ..style = PaintingStyle.stroke
          ..strokeCap = linePaint.strokeCap
          ..strokeJoin = linePaint.strokeJoin
          ..strokeMiterLimit = linePaint.strokeMiterLimit;
        if (item.lineShadowBlur != null && item.lineShadowBlur! > 0) {
          shadowPaint.maskFilter = ui.MaskFilter.blur(
            ui.BlurStyle.normal,
            item.lineShadowBlur!,
          );
        }
        _fortuneDrawRawChartSeriesLine(
          canvas,
          path.shift(shadowOffset),
          [for (final point in lineDashPoints) point + shadowOffset],
          shadowPaint,
          item.lineType,
          dashPattern: item.lineDash,
          dashOffset: item.lineDashOffset,
        );
      }
      _fortuneDrawRawChartSeriesLine(
        canvas,
        path,
        lineDashPoints,
        linePaint,
        item.lineType,
        dashPattern: item.lineDash,
        dashOffset: item.lineDashOffset,
      );
      if (shouldClipLinePath) {
        canvas.restore();
      }
    }
    if (_fortuneRawChartSeriesShouldShowSymbol(item)) {
      for (var index = 0; index < sampledValueSlots.length; index += 1) {
        final value = sampledValueSlots[index];
        if (value == null) {
          continue;
        }
        if (!_fortuneRawChartSeriesShouldDrawSymbolAt(
          item,
          index,
          categoryCount,
          plotRect.width,
        )) {
          continue;
        }
        final pointSymbol = index < item.pointSymbols.length
            ? item.pointSymbols[index]
            : null;
        final pointSymbolSize = index < item.pointSymbolSizes.length
            ? item.pointSymbolSizes[index]
            : null;
        final pointSymbolOffset = index < item.pointSymbolOffsets.length
            ? item.pointSymbolOffsets[index]
            : null;
        final pointSymbolRotationDegrees =
            index < item.pointSymbolRotationDegrees.length
            ? item.pointSymbolRotationDegrees[index]
            : null;
        final radius = (pointSymbolSize ?? item.symbolSize ?? 6.0) / 2;
        final pointColor = index < item.pointColors.length
            ? item.pointColors[index]
            : null;
        final pointOpacity = index < item.pointOpacities.length
            ? item.pointOpacities[index]
            : null;
        final symbolColor = pointColor ?? item.itemColor ?? color;
        final center =
            Offset(xForIndex(index, categoryCount), yFor(value)) +
            (pointSymbolOffset ?? item.symbolOffset ?? Offset.zero);
        final emphasized = _fortuneRawChartPointIsHovered(
          hoverPosition,
          center,
          radius,
          item,
        );
        final effectiveSymbolColor = emphasized
            ? item.emphasisItemColor ?? symbolColor
            : symbolColor;
        final effectiveOpacity = emphasized
            ? item.emphasisItemOpacity ??
                  pointOpacity ??
                  item.itemOpacity ??
                  item.lineOpacity
            : pointOpacity ?? item.itemOpacity ?? item.lineOpacity;
        final paint = Paint()
          ..color =
              _fortuneRawChartColorWithOpacity(
                effectiveSymbolColor,
                effectiveOpacity,
              ) ??
              effectiveSymbolColor
          ..blendMode = _fortuneRawChartBlendMode(item.blendMode);
        final symbol = pointSymbol ?? item.symbol;
        final rotationRadians = _fortuneDegreesToRadians(
          pointSymbolRotationDegrees ?? item.symbolRotationDegrees,
        );
        final shouldClipSymbol = item.clip == true;
        if (shouldClipSymbol) {
          canvas.save();
          canvas.clipRect(plotRect);
        }
        _fortuneDrawRawChartSeriesSymbolShadow(
          canvas,
          center,
          symbol,
          radius,
          rotationRadians,
          _fortuneRawChartResolvedPointShadowColor(item, index),
          _fortuneRawChartResolvedPointShadowBlur(item, index),
          _fortuneRawChartResolvedPointShadowOffset(item, index),
        );
        _fortuneDrawRawChartSeriesSymbol(
          canvas,
          center,
          symbol,
          radius,
          paint,
          rotationRadians,
        );
        _fortuneDrawRawChartSeriesSymbolBorder(
          canvas,
          center,
          symbol,
          radius,
          rotationRadians,
          _fortuneRawChartResolvedPointBorderColor(item, index),
          _fortuneRawChartResolvedPointBorderWidth(item, index),
          _fortuneRawChartResolvedPointBorderType(item, index),
        );
        if (emphasized) {
          _fortuneDrawRawChartSeriesSymbolBorder(
            canvas,
            center,
            symbol,
            radius,
            rotationRadians,
            item.emphasisItemBorderColor,
            item.emphasisItemBorderWidth,
            item.emphasisItemBorderType,
          );
        }
        if (shouldClipSymbol) {
          canvas.restore();
        }
      }
    }
    _fortuneDrawRawChartSeriesLineLabels(
      canvas,
      item,
      sampledValueSlots,
      categoryCount,
      xForIndex,
      yFor,
      labelLayoutRect: plotRect,
    );
    _fortuneDrawRawChartSeriesEndLabel(
      canvas,
      item,
      sampledValueSlots,
      categoryCount,
      plotRect,
      xForIndex,
      yFor,
    );
    _fortuneDrawRawChartSeriesMarkPoints(
      canvas,
      values,
      item,
      color,
      categoryCount,
      xForIndex,
      yFor,
    );
    _fortuneDrawRawChartSeriesMarkLines(
      canvas,
      values,
      item,
      color,
      plotRect,
      categoryCount,
      xForIndex,
      yFor,
    );
  }
}

bool _fortuneRawChartPointIsHovered(
  Offset? hoverPosition,
  Offset center,
  double radius,
  FortuneRawChartSeries series,
) {
  if (hoverPosition == null || series.emphasisDisabled == true) {
    return false;
  }
  final hitRadius = math.max(10.0, radius + 6.0);
  return (hoverPosition - center).distance <= hitRadius;
}

void _fortuneDrawRawChartCandlestickSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor, {
  required bool xAxisInverse,
}) {
  final points = series.candlestickPoints;
  if (points.isEmpty) {
    return;
  }
  final categoryCount = points.length;
  final step = categoryCount <= 0
      ? plotRect.width
      : plotRect.width / categoryCount;
  final bodyWidth = _fortuneRawChartSingleBarWidth(
    series,
    step,
  ).clamp(2.0, math.max(2.0, step * 0.82));
  for (var index = 0; index < points.length; index += 1) {
    final point = points[index];
    final rising = point.close >= point.open;
    final pointColor = index < series.pointColors.length
        ? series.pointColors[index]
        : null;
    final fillColor =
        pointColor ??
        (rising
            ? series.candlestickColor ?? fallbackColor
            : series.candlestickColor0 ?? const Color(0xff34a853));
    final borderColor = rising
        ? series.candlestickBorderColor ?? series.itemBorderColor ?? fillColor
        : series.candlestickBorderColor0 ?? series.itemBorderColor ?? fillColor;
    final opacity = index < series.pointOpacities.length
        ? series.pointOpacities[index]
        : series.itemOpacity;
    final resolvedFill =
        _fortuneRawChartColorWithOpacity(fillColor, opacity) ?? fillColor;
    final centerX = xForIndex(index, categoryCount);
    final highY = yFor(point.high);
    final lowY = yFor(point.low);
    final openY = yFor(point.open);
    final closeY = yFor(point.close);
    final wickPaint = Paint()
      ..color = borderColor
      ..blendMode = _fortuneRawChartBlendMode(series.blendMode)
      ..strokeWidth = math.max(1.0, series.itemBorderWidth ?? 1.0)
      ..style = PaintingStyle.stroke;
    canvas.drawLine(Offset(centerX, highY), Offset(centerX, lowY), wickPaint);
    final bodyTop = math.min(openY, closeY);
    final bodyBottom = math.max(openY, closeY);
    final bodyRect = Rect.fromLTRB(
      centerX - bodyWidth / 2,
      bodyTop,
      centerX + bodyWidth / 2,
      math.max(bodyTop + 1.0, bodyBottom),
    );
    canvas.drawRect(
      bodyRect,
      Paint()
        ..color = resolvedFill
        ..blendMode = _fortuneRawChartBlendMode(series.blendMode),
    );
    canvas.drawRect(bodyRect, wickPaint);
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      point.close,
      index,
      series.type,
      bodyRect,
    );
  }
}

void _fortuneDrawRawChartHeatmapSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
) {
  final points = series.heatmapPoints;
  if (points.isEmpty) {
    return;
  }
  final xValues = points.map((point) => point.x).toSet().toList()..sort();
  final yValues = points.map((point) => point.y).toSet().toList()..sort();
  if (xValues.isEmpty || yValues.isEmpty) {
    return;
  }
  final minimum = points.map((point) => point.value).reduce(math.min);
  final maximum = points.map((point) => point.value).reduce(math.max);
  final cellWidth = plotRect.width / xValues.length;
  final cellHeight = plotRect.height / yValues.length;
  for (var index = 0; index < points.length; index += 1) {
    final point = points[index];
    final xIndex = xValues.indexOf(point.x);
    final yIndex = yValues.indexOf(point.y);
    if (xIndex < 0 || yIndex < 0) {
      continue;
    }
    final pointColor = index < series.pointColors.length
        ? series.pointColors[index]
        : null;
    final fillColor =
        pointColor ??
        _fortuneRawChartHeatmapValueColor(
          point.value,
          minimum,
          maximum,
          fallbackColor,
        );
    final opacity = index < series.pointOpacities.length
        ? series.pointOpacities[index]
        : series.itemOpacity;
    final rect = Rect.fromLTWH(
      plotRect.left + xIndex * cellWidth,
      plotRect.top + yIndex * cellHeight,
      cellWidth,
      cellHeight,
    ).deflate(0.5);
    canvas.drawRect(
      rect,
      Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(fillColor, opacity) ?? fillColor
        ..blendMode = _fortuneRawChartBlendMode(series.blendMode),
    );
    final borderColor = index < series.pointBorderColors.length
        ? series.pointBorderColors[index]
        : series.itemBorderColor;
    final borderWidth = index < series.pointBorderWidths.length
        ? series.pointBorderWidths[index]
        : series.itemBorderWidth;
    if (borderColor != null && borderWidth != null && borderWidth > 0) {
      canvas.drawRect(
        rect.deflate(borderWidth / 2),
        Paint()
          ..color = borderColor
          ..style = PaintingStyle.stroke
          ..strokeWidth = borderWidth,
      );
    }
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      point.value,
      index,
      series.type,
      rect,
    );
  }
}

Color _fortuneRawChartHeatmapValueColor(
  double value,
  double minimum,
  double maximum,
  Color fallbackColor,
) {
  if (minimum == maximum) {
    return fallbackColor;
  }
  final ratio = ((value - minimum) / (maximum - minimum))
      .clamp(0.0, 1.0)
      .toDouble();
  return Color.lerp(const Color(0xffd7ecff), fallbackColor, ratio) ??
      fallbackColor;
}

void _fortuneDrawRawChartFunnelSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
) {
  final values = series.values;
  if (values.isEmpty) {
    return;
  }
  final maximum = values.reduce(math.max);
  final minimum = values.reduce(math.min);
  final range = maximum == minimum ? 1.0 : maximum - minimum;
  final itemHeight = plotRect.height / values.length;
  double widthForValue(double value) {
    final ratio = ((value - minimum) / range).clamp(0.0, 1.0).toDouble();
    return plotRect.width * (0.28 + ratio * 0.72);
  }

  for (var index = 0; index < values.length; index += 1) {
    final value = values[index];
    final nextValue = index + 1 < values.length ? values[index + 1] : value;
    final topWidth = widthForValue(value);
    final bottomWidth = widthForValue(nextValue);
    final top = plotRect.top + index * itemHeight;
    final bottom = top + itemHeight;
    final centerX = plotRect.center.dx;
    final path = Path()
      ..moveTo(centerX - topWidth / 2, top)
      ..lineTo(centerX + topWidth / 2, top)
      ..lineTo(centerX + bottomWidth / 2, bottom)
      ..lineTo(centerX - bottomWidth / 2, bottom)
      ..close();
    final pointColor = index < series.pointColors.length
        ? series.pointColors[index]
        : null;
    final fillColor = pointColor ?? fallbackColor;
    final opacity = index < series.pointOpacities.length
        ? series.pointOpacities[index]
        : series.itemOpacity;
    canvas.drawPath(
      path,
      Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(fillColor, opacity) ?? fillColor
        ..blendMode = _fortuneRawChartBlendMode(series.blendMode),
    );
    final borderColor = index < series.pointBorderColors.length
        ? series.pointBorderColors[index]
        : series.itemBorderColor;
    final borderWidth = index < series.pointBorderWidths.length
        ? series.pointBorderWidths[index]
        : series.itemBorderWidth;
    if (borderColor != null && borderWidth != null && borderWidth > 0) {
      canvas.drawPath(
        path,
        Paint()
          ..color = borderColor
          ..style = PaintingStyle.stroke
          ..strokeWidth = borderWidth,
      );
    }
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      value,
      index,
      series.type,
      Rect.fromLTRB(
        centerX - math.max(topWidth, bottomWidth) / 2,
        top,
        centerX + math.max(topWidth, bottomWidth) / 2,
        bottom,
      ),
    );
  }
}

void _fortuneDrawRawChartGaugeSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
) {
  if (series.values.isEmpty || plotRect.isEmpty) {
    return;
  }
  final value = series.values.first;
  final ratio = (value / 100).clamp(0.0, 1.0).toDouble();
  final center = Offset(
    plotRect.center.dx,
    plotRect.bottom - plotRect.height * 0.18,
  );
  final radius = math.min(plotRect.width * 0.42, plotRect.height * 0.72);
  if (radius <= 0) {
    return;
  }
  final strokeWidth = math.max(4.0, radius * 0.13);
  final arcRect = Rect.fromCircle(center: center, radius: radius);
  const startAngle = math.pi * 1.15;
  const sweepAngle = math.pi * 1.7;
  final pointColor = series.pointColors.isNotEmpty
      ? series.pointColors.first
      : null;
  final progressColor = pointColor ?? series.color ?? fallbackColor;
  final progressPaint = Paint()
    ..color =
        _fortuneRawChartColorWithOpacity(
          progressColor,
          series.pointOpacities.isNotEmpty
              ? series.pointOpacities.first
              : series.itemOpacity,
        ) ??
        progressColor
    ..blendMode = _fortuneRawChartBlendMode(series.blendMode)
    ..style = PaintingStyle.stroke
    ..strokeWidth = strokeWidth
    ..strokeCap = StrokeCap.round;
  final backgroundPaint = Paint()
    ..color = const Color(0xffe6ebf2)
    ..style = PaintingStyle.stroke
    ..strokeWidth = strokeWidth
    ..strokeCap = StrokeCap.round;
  canvas.drawArc(arcRect, startAngle, sweepAngle, false, backgroundPaint);
  canvas.drawArc(arcRect, startAngle, sweepAngle * ratio, false, progressPaint);

  final pointerAngle = startAngle + sweepAngle * ratio;
  final pointerEnd = Offset(
    center.dx + math.cos(pointerAngle) * radius * 0.72,
    center.dy + math.sin(pointerAngle) * radius * 0.72,
  );
  final pointerPaint = Paint()
    ..color = series.itemBorderColor ?? const Color(0xff374151)
    ..strokeWidth = math.max(2.0, radius * 0.045)
    ..strokeCap = StrokeCap.round;
  canvas.drawLine(center, pointerEnd, pointerPaint);
  canvas.drawCircle(center, math.max(3.0, radius * 0.07), pointerPaint);

  _fortuneDrawRawChartSeriesDataLabel(
    canvas,
    series,
    value,
    0,
    series.type,
    Rect.fromCenter(
      center: Offset(center.dx, center.dy + strokeWidth * 1.4),
      width: radius,
      height: strokeWidth * 2,
    ),
  );
}

void _fortuneDrawRawChartRadarSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
) {
  final radarValues = series.radarValues;
  if (radarValues.isEmpty || plotRect.isEmpty) {
    return;
  }
  final dimensionCount = radarValues
      .map((item) => item.length)
      .reduce(math.max);
  if (dimensionCount < 3) {
    return;
  }
  final maximum = math.max(
    1.0,
    radarValues.expand((item) => item).reduce(math.max),
  );
  final center = plotRect.center;
  final radius = math.min(plotRect.width, plotRect.height) * 0.42;
  if (radius <= 0) {
    return;
  }
  final gridPaint = Paint()
    ..color = const Color(0xffd7dce5)
    ..style = PaintingStyle.stroke
    ..strokeWidth = 1;
  for (var ring = 1; ring <= 3; ring += 1) {
    final ringRadius = radius * ring / 3;
    final path = Path();
    for (var index = 0; index < dimensionCount; index += 1) {
      final angle = -math.pi / 2 + math.pi * 2 * index / dimensionCount;
      final point = Offset(
        center.dx + math.cos(angle) * ringRadius,
        center.dy + math.sin(angle) * ringRadius,
      );
      if (index == 0) {
        path.moveTo(point.dx, point.dy);
      } else {
        path.lineTo(point.dx, point.dy);
      }
    }
    path.close();
    canvas.drawPath(path, gridPaint);
  }
  for (var index = 0; index < dimensionCount; index += 1) {
    final angle = -math.pi / 2 + math.pi * 2 * index / dimensionCount;
    canvas.drawLine(
      center,
      Offset(
        center.dx + math.cos(angle) * radius,
        center.dy + math.sin(angle) * radius,
      ),
      gridPaint,
    );
  }
  for (var dataIndex = 0; dataIndex < radarValues.length; dataIndex += 1) {
    final values = radarValues[dataIndex];
    final pointColor = dataIndex < series.pointColors.length
        ? series.pointColors[dataIndex]
        : null;
    final color = pointColor ?? series.color ?? fallbackColor;
    final opacity = dataIndex < series.pointOpacities.length
        ? series.pointOpacities[dataIndex]
        : series.itemOpacity;
    final path = Path();
    for (var index = 0; index < dimensionCount; index += 1) {
      final value = index < values.length ? values[index] : 0.0;
      final ratio = (value / maximum).clamp(0.0, 1.0).toDouble();
      final angle = -math.pi / 2 + math.pi * 2 * index / dimensionCount;
      final point = Offset(
        center.dx + math.cos(angle) * radius * ratio,
        center.dy + math.sin(angle) * radius * ratio,
      );
      if (index == 0) {
        path.moveTo(point.dx, point.dy);
      } else {
        path.lineTo(point.dx, point.dy);
      }
    }
    path.close();
    canvas.drawPath(
      path,
      Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(color, opacity ?? 0.28) ??
            color.withValues(alpha: 0.28)
        ..blendMode = _fortuneRawChartBlendMode(series.blendMode),
    );
    canvas.drawPath(
      path,
      Paint()
        ..color = color
        ..blendMode = _fortuneRawChartBlendMode(series.blendMode)
        ..style = PaintingStyle.stroke
        ..strokeWidth = series.lineWidth ?? 2,
    );
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      values.isEmpty ? 0 : values.reduce(math.max),
      dataIndex,
      series.type,
      Rect.fromCenter(center: center, width: radius, height: radius),
    );
  }
}

void _fortuneDrawRawChartTreemapSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
) {
  final values = series.values
      .where((value) => value > 0)
      .toList(growable: false);
  if (values.isEmpty || plotRect.isEmpty) {
    return;
  }
  final total = values.reduce((sum, value) => sum + value);
  if (total <= 0) {
    return;
  }
  var cursor = plotRect.left;
  for (var index = 0; index < values.length; index += 1) {
    final value = values[index];
    final width = index == values.length - 1
        ? plotRect.right - cursor
        : plotRect.width * value / total;
    if (width <= 0) {
      continue;
    }
    final rect = Rect.fromLTWH(
      cursor,
      plotRect.top,
      width,
      plotRect.height,
    ).deflate(0.5);
    cursor += width;
    final pointColor = index < series.pointColors.length
        ? series.pointColors[index]
        : null;
    final fillColor = pointColor ?? fallbackColor;
    final opacity = index < series.pointOpacities.length
        ? series.pointOpacities[index]
        : series.itemOpacity;
    canvas.drawRect(
      rect,
      Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(fillColor, opacity) ?? fillColor
        ..blendMode = _fortuneRawChartBlendMode(series.blendMode),
    );
    final borderColor =
        (index < series.pointBorderColors.length
            ? series.pointBorderColors[index]
            : null) ??
        series.itemBorderColor ??
        const Color(0xffffffff);
    final borderWidth =
        (index < series.pointBorderWidths.length
            ? series.pointBorderWidths[index]
            : null) ??
        series.itemBorderWidth ??
        1.0;
    canvas.drawRect(
      rect.deflate(borderWidth / 2),
      Paint()
        ..color = borderColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = borderWidth,
    );
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      value,
      index,
      series.type,
      rect,
    );
  }
}

void _fortuneDrawRawChartBoxplotSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor,
) {
  final points = series.boxplotPoints;
  if (points.isEmpty || plotRect.isEmpty) {
    return;
  }
  final step = plotRect.width / points.length;
  final boxWidth = math.max(4.0, math.min(step * 0.58, 28.0));
  for (var index = 0; index < points.length; index += 1) {
    final point = points[index];
    final centerX = xForIndex(index, points.length);
    final color = index < series.pointColors.length
        ? series.pointColors[index] ?? fallbackColor
        : fallbackColor;
    final borderColor = index < series.pointBorderColors.length
        ? series.pointBorderColors[index] ?? series.itemBorderColor ?? color
        : series.itemBorderColor ?? color;
    final borderWidth = index < series.pointBorderWidths.length
        ? series.pointBorderWidths[index] ?? series.itemBorderWidth ?? 1.5
        : series.itemBorderWidth ?? 1.5;
    final q1Y = yFor(point.q1);
    final q3Y = yFor(point.q3);
    final medianY = yFor(point.median);
    final minY = yFor(point.minimum);
    final maxY = yFor(point.maximum);
    final boxRect = Rect.fromLTRB(
      centerX - boxWidth / 2,
      math.min(q1Y, q3Y),
      centerX + boxWidth / 2,
      math.max(q1Y, q3Y),
    );
    final paint = Paint()
      ..color = borderColor
      ..blendMode = _fortuneRawChartBlendMode(series.blendMode)
      ..style = PaintingStyle.stroke
      ..strokeWidth = borderWidth;
    canvas.drawLine(Offset(centerX, maxY), Offset(centerX, minY), paint);
    canvas.drawLine(
      Offset(centerX - boxWidth * 0.34, maxY),
      Offset(centerX + boxWidth * 0.34, maxY),
      paint,
    );
    canvas.drawLine(
      Offset(centerX - boxWidth * 0.34, minY),
      Offset(centerX + boxWidth * 0.34, minY),
      paint,
    );
    canvas.drawRect(
      boxRect,
      Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(
              color,
              series.itemOpacity ?? 0.18,
            ) ??
            color.withValues(alpha: 0.18)
        ..blendMode = _fortuneRawChartBlendMode(series.blendMode),
    );
    canvas.drawRect(boxRect, paint);
    canvas.drawLine(
      Offset(boxRect.left, medianY),
      Offset(boxRect.right, medianY),
      paint,
    );
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      point.median,
      index,
      series.type,
      boxRect,
    );
  }
}

void _fortuneDrawRawChartPictorialBarSeries(
  Canvas canvas,
  FortuneRawChartSeries series,
  Color fallbackColor,
  Rect plotRect,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor, {
  required bool yAxisInverse,
}) {
  final values = series.values;
  if (values.isEmpty || plotRect.isEmpty) {
    return;
  }
  final step = plotRect.width / values.length;
  final defaultSize = math.max(
    8.0,
    math.min(step * 0.52, plotRect.height * 0.28),
  );
  final symbolSize = series.symbolSize ?? defaultSize;
  for (var index = 0; index < values.length; index += 1) {
    final value = values[index];
    final centerX = xForIndex(index, values.length);
    final valueY = yFor(value);
    final baselineY = yAxisInverse ? plotRect.top : plotRect.bottom;
    final centerY = (valueY + baselineY) / 2;
    final pointColor = index < series.pointColors.length
        ? series.pointColors[index]
        : null;
    final color = pointColor ?? fallbackColor;
    final opacity = index < series.pointOpacities.length
        ? series.pointOpacities[index]
        : series.itemOpacity;
    final paint = Paint()
      ..color = _fortuneRawChartColorWithOpacity(color, opacity) ?? color
      ..blendMode = _fortuneRawChartBlendMode(series.blendMode);
    final symbolHeight = math.max(
      symbolSize,
      (baselineY - valueY).abs().clamp(symbolSize, plotRect.height).toDouble(),
    );
    _fortuneDrawRawChartSeriesSymbol(
      canvas,
      Offset(centerX, centerY) + (series.symbolOffset ?? Offset.zero),
      series.symbol ?? 'rect',
      math.min(symbolSize, symbolHeight) / 2,
      paint,
      _fortuneDegreesToRadians(series.symbolRotationDegrees),
      size: Size(symbolSize, symbolHeight),
    );
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      value,
      index,
      series.type,
      Rect.fromCenter(
        center: Offset(centerX, centerY),
        width: symbolSize,
        height: symbolHeight,
      ),
    );
  }
}

bool _fortuneRawChartSeriesShouldShowSymbol(FortuneRawChartSeries series) {
  final explicit = series.showSymbol;
  if (explicit != null) {
    return explicit;
  }
  return series.type == 'line' || _fortuneRawChartTypeIsArea(series.type);
}

bool _fortuneRawChartSeriesShouldDrawSymbolAt(
  FortuneRawChartSeries series,
  int index,
  int categoryCount,
  double plotWidth,
) {
  final showAllSymbol = series.showAllSymbol;
  if (_fortuneRawChartBool(showAllSymbol) == true) {
    return true;
  }
  if (_fortuneRawChartBool(showAllSymbol) == false) {
    return _fortuneRawChartSeriesShouldDrawSampledSymbolAt(
      index,
      categoryCount,
      plotWidth,
    );
  }
  final normalized = showAllSymbol is String
      ? showAllSymbol.trim().toLowerCase()
      : null;
  if (showAllSymbol == null || normalized != 'auto') {
    return true;
  }
  return _fortuneRawChartSeriesShouldDrawSampledSymbolAt(
    index,
    categoryCount,
    plotWidth,
  );
}

bool _fortuneRawChartSeriesShouldDrawSampledSymbolAt(
  int index,
  int categoryCount,
  double plotWidth,
) {
  if (categoryCount <= 2 || index == 0 || index == categoryCount - 1) {
    return true;
  }
  final maxSymbols = math.max(2, (plotWidth / 28).floor());
  if (categoryCount <= maxSymbols) {
    return true;
  }
  final step = ((categoryCount - 1) / (maxSymbols - 1)).ceil();
  return index % step == 0;
}

BlendMode _fortuneRawChartBlendMode(String? raw) {
  switch (raw?.trim().toLowerCase()) {
    case 'clear':
      return BlendMode.clear;
    case 'copy':
    case 'source':
      return BlendMode.src;
    case 'destination':
      return BlendMode.dst;
    case 'sourceover':
    case 'source-over':
    case 'normal':
      return BlendMode.srcOver;
    case 'destinationover':
    case 'destination-over':
      return BlendMode.dstOver;
    case 'sourcein':
    case 'source-in':
      return BlendMode.srcIn;
    case 'destinationin':
    case 'destination-in':
      return BlendMode.dstIn;
    case 'sourceout':
    case 'source-out':
      return BlendMode.srcOut;
    case 'destinationout':
    case 'destination-out':
      return BlendMode.dstOut;
    case 'sourceatop':
    case 'source-atop':
      return BlendMode.srcATop;
    case 'destinationatop':
    case 'destination-atop':
      return BlendMode.dstATop;
    case 'xor':
      return BlendMode.xor;
    case 'plus':
    case 'lighter':
      return BlendMode.plus;
    case 'multiply':
      return BlendMode.multiply;
    case 'screen':
      return BlendMode.screen;
    case 'overlay':
      return BlendMode.overlay;
    case 'darken':
      return BlendMode.darken;
    case 'lighten':
      return BlendMode.lighten;
    case 'colordodge':
    case 'color-dodge':
      return BlendMode.colorDodge;
    case 'colorburn':
    case 'color-burn':
      return BlendMode.colorBurn;
    case 'hardlight':
    case 'hard-light':
      return BlendMode.hardLight;
    case 'softlight':
    case 'soft-light':
      return BlendMode.softLight;
    case 'difference':
      return BlendMode.difference;
    case 'exclusion':
      return BlendMode.exclusion;
    case 'hue':
      return BlendMode.hue;
    case 'saturation':
      return BlendMode.saturation;
    case 'color':
      return BlendMode.color;
    case 'luminosity':
      return BlendMode.luminosity;
    default:
      return BlendMode.srcOver;
  }
}

bool _fortuneRawChartTypeIsScatter(String type) {
  return type == 'scatter' ||
      type == 'effectscatter' ||
      type == 'effectScatter';
}

bool _fortuneRawChartTypeIsCandlestick(String type) {
  return type == 'candlestick' || type == 'k';
}

bool _fortuneRawChartTypeIsHeatmap(String type) {
  return type == 'heatmap';
}

bool _fortuneRawChartTypeIsFunnel(String type) {
  return type == 'funnel';
}

bool _fortuneRawChartTypeIsGauge(String type) {
  return type == 'gauge';
}

bool _fortuneRawChartTypeIsRadar(String type) {
  return type == 'radar';
}

bool _fortuneRawChartTypeIsTreemap(String type) {
  return type == 'treemap';
}

bool _fortuneRawChartTypeIsBoxplot(String type) {
  return type == 'boxplot';
}

bool _fortuneRawChartTypeIsPictorialBar(String type) {
  return type == 'pictorialbar';
}

class _FortuneRawChartDataZoomWindow {
  const _FortuneRawChartDataZoomWindow(
    this.startIndex,
    this.endIndex, {
    required this.filterMode,
    this.valueMinimum,
    this.valueMaximum,
  });

  final int startIndex;
  final int endIndex;
  final String filterMode;
  final double? valueMinimum;
  final double? valueMaximum;

  bool contains(int index) => index >= startIndex && index <= endIndex;

  bool containsValue(double value) {
    final minimum = valueMinimum;
    final maximum = valueMaximum;
    if (minimum == null || maximum == null) {
      return true;
    }
    return value >= minimum && value <= maximum;
  }

  bool get keepsEmptySlots => filterMode == 'empty';
}

_FortuneRawChartDataZoomWindow? _fortuneRawChartDataZoomIndexWindow(
  List<FortuneRawChartSeries> series,
  double? startPercent,
  double? endPercent,
  String? filterMode, {
  required bool vertical,
}) {
  if (filterMode?.trim().toLowerCase() == 'none') {
    return null;
  }
  final mode = filterMode?.trim().toLowerCase() ?? 'filter';
  final start = (startPercent ?? 0).clamp(0, 100).toDouble();
  final end = (endPercent ?? 100).clamp(0, 100).toDouble();
  if (start <= 0 && end >= 100) {
    return null;
  }
  final categoryCount = series.fold<int>(
    0,
    (count, item) => math.max(count, item.values.length),
  );
  if (categoryCount <= 0) {
    return null;
  }
  final lowerPercent = math.min(start, end);
  final upperPercent = math.max(start, end);
  if (vertical) {
    final values = <double>[
      for (final item in series)
        for (final value in item.values)
          if (value.isFinite) value,
    ];
    if (values.isEmpty) {
      return null;
    }
    final minimum = values.reduce(math.min);
    final maximum = values.reduce(math.max);
    if (minimum == maximum) {
      return _FortuneRawChartDataZoomWindow(
        0,
        categoryCount - 1,
        filterMode: mode,
        valueMinimum: minimum,
        valueMaximum: maximum,
      );
    }
    final span = maximum - minimum;
    return _FortuneRawChartDataZoomWindow(
      0,
      categoryCount - 1,
      filterMode: mode,
      valueMinimum: minimum + span * lowerPercent / 100,
      valueMaximum: minimum + span * upperPercent / 100,
    );
  }
  final startIndex = (categoryCount * lowerPercent / 100).floor().clamp(
    0,
    categoryCount - 1,
  );
  final endIndex = ((categoryCount * upperPercent / 100).ceil() - 1).clamp(
    startIndex,
    categoryCount - 1,
  );
  return _FortuneRawChartDataZoomWindow(startIndex, endIndex, filterMode: mode);
}

bool _fortuneRawChartDataZoomContainsIndex(
  _FortuneRawChartDataZoomWindow? window,
  int index,
) {
  return window == null || window.contains(index);
}

bool _fortuneRawChartDataZoomContainsValue(
  _FortuneRawChartDataZoomWindow? window,
  double value,
) {
  return window == null || window.containsValue(value);
}

List<double?> _fortuneRawChartDataZoomValueSlots(
  List<double?> values,
  _FortuneRawChartDataZoomWindow? window,
) {
  if (window == null) {
    return values;
  }
  if (!window.keepsEmptySlots) {
    return [
      for (var index = 0; index < values.length; index += 1)
        if (window.contains(index) &&
            values[index] != null &&
            window.containsValue(values[index]!))
          values[index],
    ];
  }
  return [
    for (var index = 0; index < values.length; index += 1)
      window.contains(index) &&
              (values[index] == null || window.containsValue(values[index]!))
          ? values[index]
          : null,
  ];
}

List<double?> _fortuneRawChartSeriesSampledValueSlots(
  List<double?> values,
  String? sampling,
  double plotWidth,
) {
  final normalized = sampling?.trim().toLowerCase();
  if (normalized == null || normalized.isEmpty || normalized == 'none') {
    return values;
  }
  final numericIndices = [
    for (var index = 0; index < values.length; index += 1)
      if (values[index] != null) index,
  ];
  final maxSamples = math.max(3, (plotWidth / 12).floor());
  if (numericIndices.length <= maxSamples) {
    return values;
  }
  final selectedIndices = switch (normalized) {
    'average' || 'avg' => _fortuneRawChartSeriesBucketSampledIndices(
      values,
      numericIndices,
      maxSamples,
      _FortuneRawChartSamplingMode.average,
    ),
    'max' => _fortuneRawChartSeriesBucketSampledIndices(
      values,
      numericIndices,
      maxSamples,
      _FortuneRawChartSamplingMode.max,
    ),
    'min' => _fortuneRawChartSeriesBucketSampledIndices(
      values,
      numericIndices,
      maxSamples,
      _FortuneRawChartSamplingMode.min,
    ),
    'sum' => _fortuneRawChartSeriesBucketSampledIndices(
      values,
      numericIndices,
      maxSamples,
      _FortuneRawChartSamplingMode.sum,
    ),
    'lttb' => _fortuneRawChartSeriesLttbSampledIndices(
      values,
      numericIndices,
      maxSamples,
    ),
    _ => const <int>{},
  };
  if (selectedIndices.isEmpty) {
    return values;
  }
  return [
    for (var index = 0; index < values.length; index += 1)
      selectedIndices.contains(index) ? values[index] : null,
  ];
}

enum _FortuneRawChartSamplingMode { average, max, min, sum }

Set<int> _fortuneRawChartSeriesBucketSampledIndices(
  List<double?> values,
  List<int> numericIndices,
  int maxSamples,
  _FortuneRawChartSamplingMode mode,
) {
  final selected = <int>{numericIndices.first, numericIndices.last};
  final bucketCount = math.max(1, maxSamples - 2);
  for (var bucketIndex = 0; bucketIndex < bucketCount; bucketIndex += 1) {
    final start =
        1 + (bucketIndex * (numericIndices.length - 2) / bucketCount).floor();
    final end =
        1 +
        (((bucketIndex + 1) * (numericIndices.length - 2)) / bucketCount)
            .floor();
    if (start >= end) {
      continue;
    }
    final bucket = numericIndices.sublist(start, end);
    final selectedIndex = switch (mode) {
      _FortuneRawChartSamplingMode.average =>
        _fortuneRawChartSeriesNearestAverageIndex(values, bucket),
      _FortuneRawChartSamplingMode.max => bucket.reduce(
        (current, next) => values[next]! > values[current]! ? next : current,
      ),
      _FortuneRawChartSamplingMode.min => bucket.reduce(
        (current, next) => values[next]! < values[current]! ? next : current,
      ),
      _FortuneRawChartSamplingMode.sum => bucket[(bucket.length - 1) ~/ 2],
    };
    selected.add(selectedIndex);
  }
  return selected;
}

int _fortuneRawChartSeriesNearestAverageIndex(
  List<double?> values,
  List<int> bucket,
) {
  final average =
      bucket.fold<double>(0, (total, index) => total + values[index]!) /
      bucket.length;
  return bucket.reduce(
    (current, next) =>
        (values[next]! - average).abs() < (values[current]! - average).abs()
        ? next
        : current,
  );
}

Set<int> _fortuneRawChartSeriesLttbSampledIndices(
  List<double?> values,
  List<int> numericIndices,
  int maxSamples,
) {
  final selected = <int>{numericIndices.first, numericIndices.last};
  var anchorIndex = numericIndices.first;
  final bucketCount = math.max(1, maxSamples - 2);
  for (var bucketIndex = 0; bucketIndex < bucketCount; bucketIndex += 1) {
    final bucketStart =
        1 + (bucketIndex * (numericIndices.length - 2) / bucketCount).floor();
    final bucketEnd =
        1 +
        (((bucketIndex + 1) * (numericIndices.length - 2)) / bucketCount)
            .floor();
    if (bucketStart >= bucketEnd) {
      continue;
    }
    final nextBucketStart =
        1 +
        (((bucketIndex + 1) * (numericIndices.length - 2)) / bucketCount)
            .floor();
    final nextBucketEnd = bucketIndex == bucketCount - 1
        ? numericIndices.length - 1
        : 1 +
              (((bucketIndex + 2) * (numericIndices.length - 2)) / bucketCount)
                  .floor();
    final nextBucket = numericIndices.sublist(
      math.min(nextBucketStart, numericIndices.length - 1),
      math.max(
        math.min(nextBucketEnd, numericIndices.length),
        math.min(nextBucketStart, numericIndices.length - 1) + 1,
      ),
    );
    final averageIndex =
        nextBucket.fold<double>(0, (total, index) => total + index) /
        nextBucket.length;
    final averageValue =
        nextBucket.fold<double>(0, (total, index) => total + values[index]!) /
        nextBucket.length;
    var bestIndex = numericIndices[bucketStart];
    var bestArea = -1.0;
    for (
      var numericIndexOffset = bucketStart;
      numericIndexOffset < bucketEnd;
      numericIndexOffset += 1
    ) {
      final candidateIndex = numericIndices[numericIndexOffset];
      final area =
          ((anchorIndex - averageIndex) *
                      (values[candidateIndex]! - values[anchorIndex]!) -
                  (anchorIndex - candidateIndex) *
                      (averageValue - values[anchorIndex]!))
              .abs();
      if (area > bestArea) {
        bestArea = area;
        bestIndex = candidateIndex;
      }
    }
    selected.add(bestIndex);
    anchorIndex = bestIndex;
  }
  return selected;
}

List<int> _fortuneRawChartDataZoomValueIndices(
  List<double> values,
  _FortuneRawChartDataZoomWindow? window,
) {
  if (window == null || window.keepsEmptySlots) {
    return [for (var index = 0; index < values.length; index += 1) index];
  }
  return [
    for (var index = 0; index < values.length; index += 1)
      if (window.contains(index) && window.containsValue(values[index])) index,
  ];
}

List<double> _fortuneRawChartSeriesScaleValues(
  List<FortuneRawChartSeries> series, {
  _FortuneRawChartDataZoomWindow? dataZoomWindow,
}) {
  final values = <double>[];
  final stackPositiveTotals = <String, List<double>>{};
  final stackNegativeTotals = <String, List<double>>{};
  for (var seriesIndex = 0; seriesIndex < series.length; seriesIndex += 1) {
    final item = series[seriesIndex];
    if (_fortuneRawChartTypeIsCandlestick(item.type)) {
      for (final point in item.candlestickPoints) {
        values.addAll([point.open, point.close, point.low, point.high]);
      }
      continue;
    }
    if (_fortuneRawChartTypeIsHeatmap(item.type)) {
      values.addAll(item.heatmapPoints.map((point) => point.value));
      continue;
    }
    if (_fortuneRawChartTypeIsRadar(item.type)) {
      values.addAll(item.radarValues.expand((item) => item));
      continue;
    }
    if (_fortuneRawChartTypeIsBoxplot(item.type)) {
      for (final point in item.boxplotPoints) {
        values.addAll([
          point.minimum,
          point.q1,
          point.median,
          point.q3,
          point.maximum,
        ]);
      }
      continue;
    }
    if (item.type != 'bar' && item.type != 'column') {
      for (var index = 0; index < item.values.length; index += 1) {
        final value = item.values[index];
        if (_fortuneRawChartDataZoomContainsIndex(dataZoomWindow, index) &&
            _fortuneRawChartDataZoomContainsValue(dataZoomWindow, value)) {
          values.add(value);
        }
      }
      continue;
    }
    if (item.stack == null) {
      for (var index = 0; index < item.values.length; index += 1) {
        final value = item.values[index];
        if (_fortuneRawChartDataZoomContainsIndex(dataZoomWindow, index) &&
            _fortuneRawChartDataZoomContainsValue(dataZoomWindow, value)) {
          values.add(value);
        }
      }
      continue;
    }
    final key = _fortuneRawChartBarGroupKey(item, seriesIndex);
    final positiveTotals = stackPositiveTotals.putIfAbsent(
      key,
      () => List<double>.filled(item.values.length, 0),
    );
    final negativeTotals = stackNegativeTotals.putIfAbsent(
      key,
      () => List<double>.filled(item.values.length, 0),
    );
    for (var index = 0; index < item.values.length; index += 1) {
      if (!_fortuneRawChartDataZoomContainsIndex(dataZoomWindow, index)) {
        continue;
      }
      final value = item.values[index];
      if (!_fortuneRawChartDataZoomContainsValue(dataZoomWindow, value)) {
        continue;
      }
      if (value >= 0) {
        positiveTotals[index] += value;
      } else {
        negativeTotals[index] += value;
      }
    }
  }
  for (final totals in stackPositiveTotals.values) {
    values.addAll(totals);
  }
  for (final totals in stackNegativeTotals.values) {
    values.addAll(totals);
  }
  return values;
}

List<String> _fortuneRawChartBarGroupKeys(List<FortuneRawChartSeries> series) {
  final keys = <String>[];
  for (var index = 0; index < series.length; index += 1) {
    final item = series[index];
    if (item.type != 'bar' && item.type != 'column') {
      continue;
    }
    final key = _fortuneRawChartBarGroupKey(item, index);
    if (!keys.contains(key)) {
      keys.add(key);
    }
  }
  return keys;
}

String _fortuneRawChartBarGroupKey(FortuneRawChartSeries series, int index) {
  final stack = series.stack;
  if (stack != null) {
    return 'stack:$stack';
  }
  return 'series:$index';
}

void _fortuneDrawRawChartBarBackground(
  Canvas canvas,
  FortuneRawChartSeries series,
  Rect rect,
) {
  if (series.barBackgroundShow != true || rect.isEmpty) {
    return;
  }
  final fillColor =
      _fortuneRawChartColorWithOpacity(
        series.barBackgroundColor ?? const Color(0xffeeeeee),
        series.barBackgroundOpacity,
      ) ??
      (series.barBackgroundColor ?? const Color(0xffeeeeee));
  final radius = series.barBackgroundBorderRadius;
  final fillPaint = Paint()..color = fillColor;
  if (radius != null) {
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        rect,
        Radius.circular(
          math.min(radius, math.min(rect.width, rect.height) / 2),
        ),
      ),
      fillPaint,
    );
  } else {
    canvas.drawRect(rect, fillPaint);
  }
  final borderColor = series.barBackgroundBorderColor;
  final borderWidth = series.barBackgroundBorderWidth;
  final borderType = series.barBackgroundBorderType;
  if (borderColor == null || borderWidth == null) {
    return;
  }
  final borderPaint = Paint()
    ..color =
        _fortuneRawChartColorWithOpacity(
          borderColor,
          series.barBackgroundOpacity,
        ) ??
        borderColor
    ..style = PaintingStyle.stroke
    ..strokeWidth = borderWidth;
  if (radius != null) {
    final borderRRect = RRect.fromRectAndRadius(
      rect.deflate(borderWidth / 2),
      Radius.circular(math.min(radius, math.min(rect.width, rect.height) / 2)),
    );
    if (borderType == 'dashed' || borderType == 'dotted') {
      _fortuneDrawRawChartDashedRRect(
        canvas,
        borderRRect,
        borderPaint,
        borderType!,
      );
    } else {
      canvas.drawRRect(borderRRect, borderPaint);
    }
  } else if (borderType == 'dashed' || borderType == 'dotted') {
    _fortuneDrawRawChartDashedRect(
      canvas,
      rect.deflate(borderWidth / 2),
      borderPaint,
      borderType!,
    );
  } else {
    canvas.drawRect(rect.deflate(borderWidth / 2), borderPaint);
  }
}

void _fortuneDrawRawChartSeriesLineLabels(
  Canvas canvas,
  FortuneRawChartSeries series,
  List<double?> valueSlots,
  int categoryCount,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor, {
  Rect? labelLayoutRect,
}) {
  for (var index = 0; index < valueSlots.length; index += 1) {
    final value = valueSlots[index];
    if (value == null) {
      continue;
    }
    final center = Offset(xForIndex(index, categoryCount), yFor(value));
    _fortuneDrawRawChartSeriesDataLabel(
      canvas,
      series,
      value,
      index,
      series.type,
      Rect.fromCenter(center: center, width: 1, height: 1),
      labelLayoutRect: labelLayoutRect,
    );
  }
}

void _fortuneDrawRawChartSeriesEndLabel(
  Canvas canvas,
  FortuneRawChartSeries series,
  List<double?> valueSlots,
  int categoryCount,
  Rect plotRect,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor,
) {
  if (series.endLabelShow != true || valueSlots.isEmpty) {
    return;
  }
  var endIndex = -1;
  double? endValue;
  for (var index = valueSlots.length - 1; index >= 0; index -= 1) {
    final value = valueSlots[index];
    if (value != null) {
      endIndex = index;
      endValue = value;
      break;
    }
  }
  if (endIndex < 0 || endValue == null) {
    return;
  }
  final label = _fortuneRawChartSeriesEndLabelText(series, endValue, endIndex);
  if (label.isEmpty) {
    return;
  }
  final effectiveLabelColor = _fortuneRawChartColorWithOpacity(
    series.endLabelColor,
    series.endLabelOpacity,
  );
  final effectiveLabelBackgroundColor = _fortuneRawChartColorWithOpacity(
    series.endLabelBackgroundColor,
    series.endLabelOpacity,
  );
  final effectiveLabelBorderColor = _fortuneRawChartColorWithOpacity(
    series.endLabelBorderColor,
    series.endLabelOpacity,
  );
  final effectiveLabelShadowColor = _fortuneRawChartColorWithOpacity(
    series.endLabelShadowColor,
    series.endLabelOpacity,
  );
  final effectiveLabelTextBorderColor = _fortuneRawChartColorWithOpacity(
    series.endLabelTextBorderColor,
    series.endLabelOpacity,
  );
  final effectiveLabelTextShadowColor = _fortuneRawChartColorWithOpacity(
    series.endLabelTextShadowColor,
    series.endLabelOpacity,
  );
  final textPainter = _fortuneRawChartSeriesLabelTextPainter(
    label,
    effectiveLabelColor,
    series.endLabelFontSize,
    series.endLabelFontWeight,
    series.endLabelFontStyle,
    series.endLabelFontFamily,
    series.endLabelLineHeight,
    effectiveLabelTextShadowColor,
    series.endLabelTextShadowBlur,
    series.endLabelTextShadowOffsetX,
    series.endLabelTextShadowOffsetY,
    series.endLabelRichStyles,
    series.endLabelOpacity,
    series.endLabelWidth,
    series.endLabelOverflow,
    series.endLabelEllipsis,
  );
  final anchor = Offset(xForIndex(endIndex, categoryCount), yFor(endValue));
  final inside =
      series.endLabelPosition == 'inside' ||
      series.endLabelPosition == 'inner' ||
      series.endLabelPosition == 'center';
  final textOffset = inside
      ? anchor - Offset(textPainter.width / 2, textPainter.height / 2)
      : Offset(
          (anchor.dx + 8).clamp(
            plotRect.left + 2,
            math.max(plotRect.left + 2, plotRect.right - textPainter.width - 2),
          ),
          (anchor.dy - textPainter.height / 2).clamp(
            plotRect.top + 2,
            math.max(
              plotRect.top + 2,
              plotRect.bottom - textPainter.height - 2,
            ),
          ),
        );
  _fortunePaintRawChartSeriesLabelText(
    canvas,
    textOffset,
    textPainter,
    label,
    series.endLabelFontSize ?? 10,
    series.endLabelFontWeight,
    series.endLabelFontStyle,
    series.endLabelFontFamily,
    effectiveLabelBackgroundColor,
    effectiveLabelBorderColor,
    series.endLabelBorderWidth,
    series.endLabelBorderType,
    series.endLabelBorderRadius,
    series.endLabelPadding,
    effectiveLabelShadowColor,
    series.endLabelShadowBlur,
    series.endLabelShadowOffsetX,
    series.endLabelShadowOffsetY,
    effectiveLabelTextBorderColor,
    series.endLabelTextBorderWidth,
    series.endLabelRotationDegrees,
    series.endLabelWidth,
    series.endLabelHeight,
    series.endLabelAlign,
    series.endLabelVerticalAlign,
    series.endLabelOverflow,
    series.endLabelEllipsis,
  );
}

