      : series.labelOverflow;
  final labelEllipsis = dataIndex < series.pointLabelEllipses.length
      ? series.pointLabelEllipses[dataIndex] ?? series.labelEllipsis
      : series.labelEllipsis;
  final labelRichStyles =
