  final labelDistance = dataIndex < series.pointLabelDistances.length
      ? series.pointLabelDistances[dataIndex] ?? series.labelDistance
      : series.labelDistance;
  final effectiveLabelColor = _fortuneRawChartColorWithOpacity(
    labelColor,
