  );
  final inside =
      labelPosition == 'inside' ||
      labelPosition == 'inner' ||
      labelPosition == 'center';
  final effectiveDistance =
      labelDistance ??
      (seriesType == 'bar' || seriesType == 'column' ? 7.0 : 9.0);
  final anchor = seriesType == 'bar' || seriesType == 'column'
      ? inside
            ? itemRect.center
            : Offset(itemRect.center.dx, itemRect.top - effectiveDistance)
      : inside
      ? itemRect.center
      : Offset(itemRect.center.dx, itemRect.center.dy - effectiveDistance);
  final layoutAnchor = _fortuneRawChartSeriesLabelLayoutAdjustedCenter(
    anchor,
    labelLayoutRect ?? itemRect,
    series,
  );
  final textOffset =
      layoutAnchor - Offset(textPainter.width / 2, textPainter.height / 2);
  _fortunePaintRawChartSeriesLabelText(
    canvas,
    textOffset,
    textPainter,
    label,
    resolvedLabelFontSize ?? 10,
    labelFontWeight,
    labelFontStyle,
    labelFontFamily,
    effectiveLabelBackgroundColor,
    effectiveLabelBorderColor,
    labelBorderWidth,
    labelBorderType,
    labelBorderRadius,
    labelPadding,
    effectiveLabelShadowColor,
    labelShadowBlur,
    labelShadowOffsetX,
    labelShadowOffsetY,
    effectiveLabelTextBorderColor,
    labelTextBorderWidth,
    resolvedLabelRotationDegrees,
    resolvedLabelWidth,
    resolvedLabelHeight,
    resolvedLabelAlign,
    resolvedLabelVerticalAlign,
    labelOverflow,
    labelEllipsis,
  );
}

void _fortuneDrawRawChartSeriesMarkPoints(
  Canvas canvas,
  List<double> values,
  FortuneRawChartSeries series,
  Color seriesColor,
  int categoryCount,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor, {
  double Function(FortuneRawChartMarkPoint markPoint, int index, int count)?
  xForMarkPoint,
}) {
  if (series.markPoints.isEmpty || values.isEmpty) {
    return;
  }
  for (final markPoint in series.markPoints) {
    int? index = markPoint.xIndex;
    double? value = markPoint.yValue;
    if (markPoint.type == 'max') {
      value = values.reduce(math.max);
      index = values.indexOf(value);
    } else if (markPoint.type == 'min') {
      value = values.reduce(math.min);
      index = values.indexOf(value);
    } else if (markPoint.type == 'average') {
      value =
          values.fold<double>(0, (sum, value) => sum + value) / values.length;
      index = values.length ~/ 2;
    }
    if (index == null || value == null || index < 0) {
      continue;
    }
    if (index >= categoryCount && xForMarkPoint == null) {
      continue;
    }
    final center =
        Offset(
          xForMarkPoint?.call(markPoint, index, categoryCount) ??
              xForIndex(index, categoryCount),
          yFor(value),
        ) +
        (markPoint.symbolOffset ?? Offset.zero);
    final radius = (markPoint.symbolSize ?? 12) / 2;
    final fill = markPoint.color ?? seriesColor;
    final rotationRadians = _fortuneDegreesToRadians(
      markPoint.symbolRotationDegrees,
    );
    _fortuneDrawRawChartSeriesSymbolShadow(
      canvas,
      center,
      markPoint.symbol,
      radius,
      rotationRadians,
      markPoint.shadowColor,
      markPoint.shadowBlur,
      Offset(markPoint.shadowOffsetX ?? 0, markPoint.shadowOffsetY ?? 0),
    );
    _fortuneDrawRawChartSeriesSymbol(
      canvas,
      center,
      markPoint.symbol,
      radius,
      Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(fill, markPoint.opacity) ?? fill,
      rotationRadians,
    );
    final borderPaint = Paint()
      ..color =
          _fortuneRawChartColorWithOpacity(
            markPoint.borderColor ?? const Color(0xffffffff),
            markPoint.opacity,
          ) ??
          (markPoint.borderColor ?? const Color(0xffffffff))
      ..style = PaintingStyle.stroke
      ..strokeWidth = markPoint.borderWidth ?? math.max(1.0, radius / 4);
    final canDrawDashedCircle =
        markPoint.symbol == null ||
        markPoint.symbol == 'circle' ||
        markPoint.symbol == 'emptycircle';
    if (canDrawDashedCircle &&
        (markPoint.borderType == 'dashed' ||
            markPoint.borderType == 'dotted')) {
      _fortuneDrawRawChartDashedCircle(
        canvas,
        center,
        radius,
        borderPaint,
        markPoint.borderType!,
      );
    } else {
      _fortuneDrawRawChartSeriesSymbol(
        canvas,
        center,
        markPoint.symbol,
        radius,
        borderPaint,
        rotationRadians,
      );
    }
    if (markPoint.labelShow == true) {
      _fortuneDrawRawChartMarkerLabel(
        canvas,
        _fortuneRawChartMarkerLabelText(
          formatter: markPoint.labelFormatter,
          value: value,
          name: markPoint.name ?? markPoint.type,
          seriesName: series.name,
          precision: markPoint.precision,
        ),
        _fortuneRawChartMarkPointLabelAnchor(
          center,
          radius,
          markPoint.labelPosition,
          markPoint.labelDistance,
        ),
        markPoint.labelColor ?? const Color(0xff202124),
        markPoint.labelFontSize ?? 10,
        opacity: markPoint.labelOpacity,
        backgroundColor: markPoint.labelBackgroundColor,
        borderColor: markPoint.labelBorderColor,
        borderWidth: markPoint.labelBorderWidth,
        borderType: markPoint.labelBorderType,
        borderRadius: markPoint.labelBorderRadius,
        padding: markPoint.labelPadding,
        fontWeight: markPoint.labelFontWeight,
        fontStyle: markPoint.labelFontStyle,
        fontFamily: markPoint.labelFontFamily,
        rotationDegrees: markPoint.labelRotationDegrees,
        boxWidth: markPoint.labelWidth,
        boxHeight: markPoint.labelHeight,
        align: markPoint.labelAlign,
        verticalAlign: markPoint.labelVerticalAlign,
        lineHeight: markPoint.labelLineHeight,
        overflow: markPoint.labelOverflow,
        ellipsis: markPoint.labelEllipsis,
        richStyles: markPoint.labelRichStyles,
        textBorderColor: markPoint.labelTextBorderColor,
        textBorderWidth: markPoint.labelTextBorderWidth,
        textShadowColor: markPoint.labelTextShadowColor,
        textShadowBlur: markPoint.labelTextShadowBlur,
        textShadowOffsetX: markPoint.labelTextShadowOffsetX,
        textShadowOffsetY: markPoint.labelTextShadowOffsetY,
      );
    }
  }
}

Offset _fortuneRawChartMarkPointLabelAnchor(
  Offset center,
  double radius,
  String? position,
  double? distance,
) {
  final effectiveDistance = distance ?? 7;
  final insideOffset = math.max(0.0, radius - effectiveDistance);
  switch (position?.toLowerCase()) {
    case 'inside':
    case 'center':
      return center;
    case 'insidetop':
      return Offset(center.dx, center.dy - insideOffset);
    case 'insidebottom':
      return Offset(center.dx, center.dy + insideOffset);
    case 'insideleft':
      return Offset(center.dx - insideOffset, center.dy);
    case 'insideright':
      return Offset(center.dx + insideOffset, center.dy);
    case 'insidetopleft':
      return Offset(center.dx - insideOffset, center.dy - insideOffset);
    case 'insidetopright':
      return Offset(center.dx + insideOffset, center.dy - insideOffset);
    case 'insidebottomleft':
      return Offset(center.dx - insideOffset, center.dy + insideOffset);
    case 'insidebottomright':
      return Offset(center.dx + insideOffset, center.dy + insideOffset);
    case 'bottom':
      return Offset(center.dx, center.dy + radius + effectiveDistance);
    case 'bottomleft':
      return Offset(
        center.dx - radius - effectiveDistance,
        center.dy + radius + effectiveDistance,
      );
    case 'bottomright':
      return Offset(
        center.dx + radius + effectiveDistance,
        center.dy + radius + effectiveDistance,
      );
    case 'left':
      return Offset(center.dx - radius - effectiveDistance, center.dy);
    case 'right':
      return Offset(center.dx + radius + effectiveDistance, center.dy);
    case 'topleft':
      return Offset(
        center.dx - radius - effectiveDistance,
        center.dy - radius - effectiveDistance,
      );
    case 'topright':
      return Offset(
        center.dx + radius + effectiveDistance,
        center.dy - radius - effectiveDistance,
      );
    case 'top':
    default:
      return Offset(center.dx, center.dy - radius - effectiveDistance);
  }
}

void _fortuneDrawRawChartDashedCircle(
  Canvas canvas,
  Offset center,
  double radius,
  Paint paint,
  String type,
) {
  if (radius <= 0) {
    return;
  }
  final segmentLength = type == 'dotted'
      ? math.max(1.5, paint.strokeWidth)
      : math.max(4.0, paint.strokeWidth * 3);
  final gapLength = type == 'dotted'
      ? math.max(2.0, paint.strokeWidth * 1.6)
      : math.max(3.0, paint.strokeWidth * 1.6);
  final segmentAngle = segmentLength / radius;
  final gapAngle = gapLength / radius;
  final arcPaint = Paint()
    ..color = paint.color
    ..style = PaintingStyle.stroke
    ..strokeWidth = paint.strokeWidth
    ..strokeCap = type == 'dotted' ? StrokeCap.round : StrokeCap.butt;
  final rect = Rect.fromCircle(center: center, radius: radius);
  for (
    var angle = -math.pi / 2;
    angle < math.pi * 1.5;
    angle += segmentAngle + gapAngle
  ) {
    final remaining = math.pi * 1.5 - angle;
    if (remaining <= 0) {
      break;
    }
    canvas.drawArc(
      rect,
      angle,
      math.min(segmentAngle, remaining),
      false,
      arcPaint,
    );
  }
}

void _fortuneDrawRawChartSeriesMarkAreas(
  Canvas canvas,
  List<double> values,
  FortuneRawChartSeries series,
  Rect plotRect,
  int categoryCount,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor, {
  double Function(double value)? xForValue,
}) {
  if (series.markAreas.isEmpty || values.isEmpty) {
    return;
  }
  for (final markArea in series.markAreas) {
    double xForArea(int index, double? value) {
      if (value != null && value.isFinite && xForValue != null) {
        return xForValue(value).clamp(plotRect.left, plotRect.right).toDouble();
      }
      return xForIndex(
        index.clamp(0, categoryCount - 1).toInt(),
        categoryCount,
      ).clamp(plotRect.left, plotRect.right).toDouble();
    }

    final startX = markArea.startXIndex == null
        ? plotRect.left
        : xForArea(markArea.startXIndex!, markArea.startXValue);
    final endX = markArea.endXIndex == null
        ? plotRect.right
        : xForArea(markArea.endXIndex!, markArea.endXValue);
    final startY = markArea.startYValue == null
        ? plotRect.top
        : yFor(markArea.startYValue!).clamp(plotRect.top, plotRect.bottom);
    final endY = markArea.endYValue == null
        ? plotRect.bottom
        : yFor(markArea.endYValue!).clamp(plotRect.top, plotRect.bottom);
    final rect = Rect.fromLTRB(
      math.min(startX, endX),
      math.min(startY, endY).toDouble(),
      math.max(startX, endX),
      math.max(startY, endY).toDouble(),
    );
    if (rect.width <= 0 || rect.height <= 0) {
      continue;
    }
    final shadowColor = markArea.shadowColor;
    if (shadowColor != null) {
      final shadowPaint = Paint()..color = shadowColor;
      final shadowBlur = markArea.shadowBlur;
      if (shadowBlur != null && shadowBlur > 0) {
        shadowPaint.maskFilter = ui.MaskFilter.blur(
          ui.BlurStyle.normal,
          shadowBlur,
        );
      }
      canvas.drawRect(
        rect.shift(
          Offset(markArea.shadowOffsetX ?? 0, markArea.shadowOffsetY ?? 0),
        ),
        shadowPaint,
      );
    }
    final color = markArea.color ?? const Color(0x330188fb);
    canvas.drawRect(
      rect,
      Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(
              color,
              markArea.opacity ?? color.a,
            ) ??
            color.withAlpha(51),
    );
    final borderColor = markArea.borderColor;
    final borderWidth = markArea.borderWidth;
    if (borderColor != null && borderWidth != null && borderWidth > 0) {
      final borderPaint = Paint()
        ..color =
            _fortuneRawChartColorWithOpacity(borderColor, markArea.opacity) ??
            borderColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = borderWidth;
      if (markArea.borderType == 'dashed' || markArea.borderType == 'dotted') {
        _fortuneDrawRawChartDashedRect(
          canvas,
          rect,
          borderPaint,
          markArea.borderType!,
        );
      } else {
        canvas.drawRect(rect, borderPaint);
      }
    }
    if (markArea.labelShow == true) {
      _fortuneDrawRawChartMarkerLabel(
        canvas,
        _fortuneRawChartMarkerLabelText(
          formatter: markArea.labelFormatter,
          value: markArea.endYValue ?? markArea.startYValue,
          name: markArea.name,
          seriesName: series.name,
          precision: markArea.precision,
        ),
        _fortuneRawChartMarkAreaLabelAnchor(
          rect,
          markArea.labelPosition,
          markArea.labelDistance,
        ),
        markArea.labelColor ?? const Color(0xff202124),
        markArea.labelFontSize ?? 10,
        opacity: markArea.labelOpacity,
        backgroundColor: markArea.labelBackgroundColor,
        borderColor: markArea.labelBorderColor,
        borderWidth: markArea.labelBorderWidth,
        borderType: markArea.labelBorderType,
        borderRadius: markArea.labelBorderRadius,
        padding: markArea.labelPadding,
        fontWeight: markArea.labelFontWeight,
        fontStyle: markArea.labelFontStyle,
        fontFamily: markArea.labelFontFamily,
        rotationDegrees: markArea.labelRotationDegrees,
        boxWidth: markArea.labelWidth,
        boxHeight: markArea.labelHeight,
        align: markArea.labelAlign,
        verticalAlign: markArea.labelVerticalAlign,
        lineHeight: markArea.labelLineHeight,
        overflow: markArea.labelOverflow,
        ellipsis: markArea.labelEllipsis,
        richStyles: markArea.labelRichStyles,
        textBorderColor: markArea.labelTextBorderColor,
        textBorderWidth: markArea.labelTextBorderWidth,
        textShadowColor: markArea.labelTextShadowColor,
        textShadowBlur: markArea.labelTextShadowBlur,
        textShadowOffsetX: markArea.labelTextShadowOffsetX,
        textShadowOffsetY: markArea.labelTextShadowOffsetY,
      );
    }
  }
}

Offset _fortuneRawChartMarkAreaLabelAnchor(
  Rect rect,
  String? position,
  double? distance,
) {
  final effectiveDistance = distance ?? 8;
  switch (position?.toLowerCase()) {
    case 'top':
    case 'insidetop':
      return Offset(rect.center.dx, rect.top + effectiveDistance);
    case 'bottom':
    case 'insidebottom':
      return Offset(rect.center.dx, rect.bottom - effectiveDistance);
    case 'left':
    case 'insideleft':
      return Offset(rect.left + effectiveDistance, rect.center.dy);
    case 'right':
    case 'insideright':
      return Offset(rect.right - effectiveDistance, rect.center.dy);
    case 'insidetopleft':
      return rect.topLeft + Offset(effectiveDistance, effectiveDistance);
    case 'insidetopright':
      return rect.topRight + Offset(-effectiveDistance, effectiveDistance);
    case 'insidebottomleft':
      return rect.bottomLeft + Offset(effectiveDistance, -effectiveDistance);
    case 'insidebottomright':
      return rect.bottomRight + Offset(-effectiveDistance, -effectiveDistance);
    case 'inside':
    case 'center':
    default:
      return rect.center;
  }
}

void _fortuneDrawRawChartSeriesMarkLines(
  Canvas canvas,
  List<double> values,
  FortuneRawChartSeries series,
  Color seriesColor,
  Rect plotRect,
  int categoryCount,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor, {
  double Function(double value)? xForValue,
}) {
  if (series.markLines.isEmpty || values.isEmpty) {
    return;
  }
  for (final markLine in series.markLines) {
    int? xIndex = markLine.xIndex;
    double? yValue = markLine.yValue;
    if (markLine.type == 'max') {
      yValue = values.reduce(math.max);
    } else if (markLine.type == 'min') {
      yValue = values.reduce(math.min);
    } else if (markLine.type == 'average') {
      yValue =
          values.fold<double>(0, (sum, value) => sum + value) / values.length;
    }
    Offset? start;
    Offset? end;
    double xForMarker(int index, double? value) {
      if (value != null && value.isFinite && xForValue != null) {
        return xForValue(value).clamp(plotRect.left, plotRect.right).toDouble();
      }
      return xForIndex(
        index.clamp(0, categoryCount - 1).toInt(),
        categoryCount,
      ).clamp(plotRect.left, plotRect.right).toDouble();
    }

    if (markLine.startXIndex != null &&
        markLine.startYValue != null &&
        markLine.endXIndex != null &&
        markLine.endYValue != null) {
      start = Offset(
        xForMarker(markLine.startXIndex!, markLine.startXValue),
        yFor(
          markLine.startYValue!,
        ).clamp(plotRect.top, plotRect.bottom).toDouble(),
      );
      end = Offset(
        xForMarker(markLine.endXIndex!, markLine.endXValue),
        yFor(
          markLine.endYValue!,
        ).clamp(plotRect.top, plotRect.bottom).toDouble(),
      );
    } else if (yValue != null) {
      final y = yFor(yValue).clamp(plotRect.top, plotRect.bottom).toDouble();
      start = Offset(plotRect.left, y);
      end = Offset(plotRect.right, y);
    } else if (xIndex != null &&
        xIndex >= 0 &&
        (xIndex < categoryCount ||
            (markLine.xValue != null && xForValue != null))) {
      final x = xForMarker(xIndex, markLine.xValue);
      start = Offset(x, plotRect.top);
      end = Offset(x, plotRect.bottom);
    }
    if (start == null || end == null) {
      continue;
    }
    final lineColor = markLine.color ?? seriesColor;
    final curveness = markLine.curveness ?? 0;
    final curveControl = curveness == 0
        ? null
        : _fortuneRawChartMarkLineCurveControl(start, end, curveness);
    final path = Path()..moveTo(start.dx, start.dy);
    final points = curveControl == null
        ? [start, end]
        : _fortuneRawChartQuadraticPoints(start, curveControl, end);
    if (curveControl == null) {
      path.lineTo(end.dx, end.dy);
    } else {
      path.quadraticBezierTo(curveControl.dx, curveControl.dy, end.dx, end.dy);
    }
    if (markLine.shadowColor != null) {
      final shadowPaint = Paint()
        ..color = markLine.shadowColor!
        ..strokeWidth = markLine.width ?? 1.5
        ..style = PaintingStyle.stroke
        ..strokeCap = _fortuneRawChartStrokeCap(markLine.lineCap)
        ..strokeJoin = _fortuneRawChartStrokeJoin(markLine.lineJoin);
      if (markLine.lineMiterLimit != null) {
        shadowPaint.strokeMiterLimit = markLine.lineMiterLimit!;
      }
      final shadowBlur = markLine.shadowBlur;
      if (shadowBlur != null && shadowBlur > 0) {
        shadowPaint.maskFilter = ui.MaskFilter.blur(
          ui.BlurStyle.normal,
          shadowBlur,
        );
      }
      final shadowOffset = Offset(
        markLine.shadowOffsetX ?? 0,
        markLine.shadowOffsetY ?? 0,
      );
      _fortuneDrawRawChartSeriesLine(
        canvas,
        path.shift(shadowOffset),
        [for (final point in points) point + shadowOffset],
        shadowPaint,
        markLine.lineType,
        dashPattern: markLine.lineDash,
        dashOffset: markLine.lineDashOffset,
      );
    }
    final paint = Paint()
      ..color =
          _fortuneRawChartColorWithOpacity(lineColor, markLine.opacity) ??
          lineColor
      ..strokeWidth = markLine.width ?? 1.5
      ..style = PaintingStyle.stroke
      ..strokeCap = _fortuneRawChartStrokeCap(markLine.lineCap)
      ..strokeJoin = _fortuneRawChartStrokeJoin(markLine.lineJoin);
    if (markLine.lineMiterLimit != null) {
      paint.strokeMiterLimit = markLine.lineMiterLimit!;
    }
    _fortuneDrawRawChartSeriesLine(
      canvas,
      path,
      points,
      paint,
      markLine.lineType,
      dashPattern: markLine.lineDash,
      dashOffset: markLine.lineDashOffset,
    );
    _fortuneDrawRawChartMarkLineEndpointSymbol(
      canvas,
      start,
      curveControl ?? end,
      markLine.startSymbol,
      markLine.startSymbolSize,
      markLine.startSymbolOffset,
      markLine.startSymbolRotationDegrees,
      paint.color,
      isStart: true,
    );
    _fortuneDrawRawChartMarkLineEndpointSymbol(
      canvas,
      end,
      curveControl ?? start,
      markLine.endSymbol,
      markLine.endSymbolSize,
      markLine.endSymbolOffset,
      markLine.endSymbolRotationDegrees,
      paint.color,
      isStart: false,
    );
    if (markLine.labelShow == true) {
      _fortuneDrawRawChartMarkerLabel(
        canvas,
        _fortuneRawChartMarkerLabelText(
          formatter: markLine.labelFormatter,
          value: yValue ?? markLine.endYValue,
          name: markLine.name ?? markLine.type,
          seriesName: series.name,
          precision: markLine.precision,
        ),
        _fortuneRawChartMarkLineLabelAnchor(
          start,
          end,
          markLine.labelPosition,
          markLine.labelDistance,
        ),
        markLine.labelColor ?? markLine.color ?? seriesColor,
        markLine.labelFontSize ?? 10,
        opacity: markLine.labelOpacity,
        backgroundColor: markLine.labelBackgroundColor,
        borderColor: markLine.labelBorderColor,
        borderWidth: markLine.labelBorderWidth,
        borderType: markLine.labelBorderType,
        borderRadius: markLine.labelBorderRadius,
        padding: markLine.labelPadding,
        fontWeight: markLine.labelFontWeight,
        fontStyle: markLine.labelFontStyle,
        fontFamily: markLine.labelFontFamily,
        rotationDegrees: markLine.labelRotationDegrees,
        boxWidth: markLine.labelWidth,
        boxHeight: markLine.labelHeight,
        align: markLine.labelAlign,
        verticalAlign: markLine.labelVerticalAlign,
        lineHeight: markLine.labelLineHeight,
        overflow: markLine.labelOverflow,
        ellipsis: markLine.labelEllipsis,
        richStyles: markLine.labelRichStyles,
        textBorderColor: markLine.labelTextBorderColor,
        textBorderWidth: markLine.labelTextBorderWidth,
        textShadowColor: markLine.labelTextShadowColor,
        textShadowBlur: markLine.labelTextShadowBlur,
        textShadowOffsetX: markLine.labelTextShadowOffsetX,
        textShadowOffsetY: markLine.labelTextShadowOffsetY,
      );
    }
  }
}

Offset? _fortuneRawChartMarkLineCurveControl(
  Offset start,
  Offset end,
  double curveness,
) {
  if (curveness == 0 || !curveness.isFinite) {
    return null;
  }
  final delta = end - start;
  final length = delta.distance;
  if (length <= 0) {
    return null;
  }
  final normal = Offset(-delta.dy / length, delta.dx / length);
  return Offset((start.dx + end.dx) / 2, (start.dy + end.dy) / 2) +
      normal * length * curveness;
}

List<Offset> _fortuneRawChartQuadraticPoints(
  Offset start,
  Offset control,
  Offset end,
) {
  final points = <Offset>[start];
  for (var index = 1; index <= 24; index += 1) {
    final t = index / 24;
    final inverse = 1 - t;
    points.add(
      start * (inverse * inverse) + control * (2 * inverse * t) + end * (t * t),
    );
  }
  return points;
}

void _fortuneDrawRawChartMarkLineEndpointSymbol(
  Canvas canvas,
  Offset point,
  Offset opposite,
  String? symbol,
  double? symbolSize,
  Offset? symbolOffset,
  double? symbolRotationDegrees,
  Color color, {
  required bool isStart,
}) {
  if (symbol == null || symbol == 'none') {
    return;
  }
  final dx = point.dx - opposite.dx;
  final dy = point.dy - opposite.dy;
  final angle = math.atan2(dy, dx) + math.pi / 2;
  final normalizedSymbol = symbol == 'arrow' ? 'triangle' : symbol;
  final radius = (symbolSize ?? 8) / 2;
  final rotationRadians =
      (normalizedSymbol == 'triangle' ? angle : 0) +
      (symbolRotationDegrees ?? 0) * math.pi / 180;
  _fortuneDrawRawChartSeriesSymbol(
    canvas,
    point + (symbolOffset ?? Offset.zero),
    normalizedSymbol,
    radius,
    Paint()..color = color,
    rotationRadians,
  );
}

Offset _fortuneRawChartMarkLineLabelAnchor(
  Offset start,
  Offset end,
  String? position,
  double? distance,
) {
  final middle = Offset((start.dx + end.dx) / 2, (start.dy + end.dy) / 2);
  final effectiveDistance = distance ?? 7;
  final delta = end - start;
  final length = delta.distance;
  final normal = length <= 0
      ? const Offset(0, 1)
      : Offset(-delta.dy / length, delta.dx / length);
  final topOffset = -normal * effectiveDistance;
  final bottomOffset = normal * effectiveDistance;
  switch (position?.toLowerCase()) {
    case 'start':
      return Offset(start.dx, start.dy - effectiveDistance);
    case 'end':
      return Offset(end.dx, end.dy - effectiveDistance);
    case 'insidestart':
      return start;
    case 'insidestarttop':
      return start + topOffset;
    case 'insidestartbottom':
      return start + bottomOffset;
    case 'insidemiddle':
      return middle;
    case 'insidemiddletop':
      return middle + topOffset;
    case 'insidemiddlebottom':
      return middle + bottomOffset;
    case 'insideend':
      return end;
    case 'insideendtop':
      return end + topOffset;
    case 'insideendbottom':
      return end + bottomOffset;
    case 'inside':
    case 'center':
    case 'middle':
      return middle;
    case 'bottom':
      return middle + Offset(0, effectiveDistance);
    case 'top':
    default:
      return middle - Offset(0, effectiveDistance);
  }
}

void _fortuneDrawRawChartMarkerLabel(
  Canvas canvas,
  String label,
  Offset anchor,
  Color color,
  double fontSize, {
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  double? borderRadius,
  EdgeInsets? padding,
  double? opacity,
  FontWeight? fontWeight,
  FontStyle? fontStyle,
  String? fontFamily,
  double? rotationDegrees,
  double? boxWidth,
  double? boxHeight,
  String? align,
  String? verticalAlign,
  double? lineHeight,
  String? overflow,
  String? ellipsis,
  Map<String, FortuneRawChartRichTextStyle> richStyles = const {},
  Color? textBorderColor,
  double? textBorderWidth,
  Color? textShadowColor,
  double? textShadowBlur,
  double? textShadowOffsetX,
  double? textShadowOffsetY,
}) {
  if (label.isEmpty) {
    return;
  }
  final textColor = _fortuneRawChartColorWithOpacity(color, opacity) ?? color;
  final textPainter = _fortuneRawChartLabelFillPainter(
    text: label,
    color: textColor,
    fontSize: fontSize,
    fontWeight: fontWeight ?? FontWeight.normal,
    fontStyle: fontStyle ?? FontStyle.normal,
    fontFamily: fontFamily,
    backgroundColor: null,
    lineHeight: lineHeight,
    textShadowColor:
        _fortuneRawChartColorWithOpacity(textShadowColor, opacity) ??
        textShadowColor,
    textShadowBlur: textShadowBlur,
    textShadowOffsetX: textShadowOffsetX,
    textShadowOffsetY: textShadowOffsetY,
    overflow: overflow,
    ellipsis: ellipsis,
    richStyles: richStyles,
    maxWidth: overflow == 'truncate' && boxWidth != null
        ? boxWidth
        : double.infinity,
  );
  final strokePainter = _fortuneRawChartLabelStrokePainter(
    text: label,
    fontSize: fontSize,
    fontWeight: fontWeight ?? FontWeight.normal,
    fontStyle: fontStyle ?? FontStyle.normal,
    fontFamily: fontFamily,
    lineHeight: lineHeight,
    textBorderColor:
        _fortuneRawChartColorWithOpacity(textBorderColor, opacity) ??
        textBorderColor,
    textBorderWidth: textBorderWidth,
    overflow: overflow,
    ellipsis: ellipsis,
    maxWidth: overflow == 'truncate' && boxWidth != null
        ? boxWidth
        : double.infinity,
  );
  _fortunePaintRawChartLabel(
    canvas,
    textPainter,
    strokePainter,
    anchor - Offset(textPainter.width / 2, textPainter.height / 2),
    _fortuneRawChartColorWithOpacity(backgroundColor, opacity) ??
        backgroundColor,
    _fortuneRawChartColorWithOpacity(borderColor, opacity) ?? borderColor,
    borderWidth,
    padding ?? const EdgeInsets.symmetric(horizontal: 2, vertical: 1),
    borderRadius,
    boxWidth,
    boxHeight,
    align,
    verticalAlign,
    rotationDegrees ?? 0,
    borderType,
  );
}

void _fortuneDrawRawChartTooltip(
  Canvas canvas,
  Rect chartRect,
  Rect plotRect,
  List<FortuneRawChartSeries> series,
  List<String> xAxisLabels, {
  Offset? hoverPosition,
  required bool xAxisInverse,
  required bool yAxisInverse,
  required bool xAxisBoundaryGap,
  required String? trigger,
  required String? order,
  required String? formatter,
  required Object? position,
  required bool? confine,
  required Color? backgroundColor,
  required Color? borderColor,
  required double? borderWidth,
  required String? borderType,
  required double? borderRadius,
  required EdgeInsets? padding,
  required Color? shadowColor,
  required double? shadowBlur,
  required double? shadowOffsetX,
  required double? shadowOffsetY,
  required Color? textColor,
  required double? textFontSize,
  required FontWeight? textFontWeight,
  required FontStyle? textFontStyle,
  required String? textFontFamily,
  required double? textLineHeight,
  required double? textWidth,
  required double? textHeight,
  required String? textAlign,
  required String? textVerticalAlign,
  required String? textOverflow,
  required String? textEllipsis,
  required Color? textBorderColor,
  required double? textBorderWidth,
  required Color? textShadowColor,
  required double? textShadowBlur,
  required double? textShadowOffsetX,
  required double? textShadowOffsetY,
  required double? textOpacity,
}) {
  final sample = _fortuneRawChartTooltipSample(
    series,
    xAxisLabels,
    plotRect,
    hoverPosition: hoverPosition,
    triggerAxis: trigger == 'axis',
    order: order,
    formatter: formatter,
    xAxisInverse: xAxisInverse,
    yAxisInverse: yAxisInverse,
    xAxisBoundaryGap: xAxisBoundaryGap,
  );
  if (sample == null) {
    return;
  }
  final label =
      sample.text ??
      _fortuneRawChartTooltipText(
        formatter,
        sample.seriesName,
        sample.name,
        sample.value,
      );
  if (label.isEmpty) {
    return;
  }
  final fontSize = textFontSize ?? 12;
  final resolvedTextColor =
      _fortuneRawChartColorWithOpacity(
        textColor ?? const Color(0xff202124),
        textOpacity,
      ) ??
      textColor ??
      const Color(0xff202124);
  final resolvedTextBorderColor = _fortuneRawChartColorWithOpacity(
    textBorderColor,
    textOpacity,
  );
  final resolvedTextShadowColor = _fortuneRawChartColorWithOpacity(
    textShadowColor,
    textOpacity,
  );
  final maxWidth = textOverflow == 'truncate' && textWidth != null
      ? textWidth
      : chartRect.width;
  final tooltipMaxLines = label.contains('\n') && textOverflow != 'truncate'
      ? null
      : 1;
  final painter = _fortuneRawChartLabelFillPainter(
    text: label,
    color: resolvedTextColor,
    fontSize: fontSize,
    fontWeight: textFontWeight ?? FontWeight.normal,
    fontStyle: textFontStyle ?? FontStyle.normal,
    fontFamily: textFontFamily,
    backgroundColor: null,
    lineHeight: textLineHeight,
    textShadowColor: resolvedTextShadowColor,
    textShadowBlur: textShadowBlur,
    textShadowOffsetX: textShadowOffsetX,
    textShadowOffsetY: textShadowOffsetY,
    overflow: textOverflow,
    ellipsis: textEllipsis,
    richStyles: const {},
    maxWidth: maxWidth,
    maxLines: tooltipMaxLines,
  );
  final strokePainter = _fortuneRawChartLabelStrokePainter(
    text: label,
    fontSize: fontSize,
    fontWeight: textFontWeight ?? FontWeight.normal,
    fontStyle: textFontStyle ?? FontStyle.normal,
    fontFamily: textFontFamily,
    lineHeight: textLineHeight,
    textBorderColor: resolvedTextBorderColor,
    textBorderWidth: textBorderWidth,
    overflow: textOverflow,
    ellipsis: textEllipsis,
    maxWidth: maxWidth,
    maxLines: tooltipMaxLines,
  );
  final labelPadding =
      padding ?? const EdgeInsets.symmetric(horizontal: 8, vertical: 5);
  final labelWidth = math.max(painter.width, textWidth ?? 0);
  final labelHeight = math.max(painter.height, textHeight ?? 0);
  final labelRect = Rect.fromLTWH(
    0,
    0,
    labelWidth + labelPadding.left + labelPadding.right,
    labelHeight + labelPadding.top + labelPadding.bottom,
  );
  var topLeft = _fortuneRawChartTooltipPaintPosition(
    position,
    chartRect,
    plotRect,
    labelRect.size,
    sample.anchor,
  );
  if (confine != false) {
    topLeft = Offset(
      topLeft.dx
          .clamp(
            chartRect.left,
            math.max(chartRect.left, chartRect.right - labelRect.width),
          )
          .toDouble(),
      topLeft.dy
          .clamp(
            chartRect.top,
            math.max(chartRect.top, chartRect.bottom - labelRect.height),
          )
          .toDouble(),
    );
  }
  final paintRect = labelRect.shift(topLeft);
  final radius = Radius.circular(borderRadius ?? 4);
  if (shadowColor != null) {
    final shadowPaint = Paint()..color = shadowColor;
    if (shadowBlur != null && shadowBlur > 0) {
      shadowPaint.maskFilter = ui.MaskFilter.blur(
        ui.BlurStyle.normal,
        shadowBlur,
      );
    }
    final shadowRect = paintRect.shift(
      Offset(shadowOffsetX ?? 0, shadowOffsetY ?? 0),
    );
    if (borderRadius != null && borderRadius > 0) {
      canvas.drawRRect(
        RRect.fromRectAndRadius(shadowRect, radius),
        shadowPaint,
      );
    } else {
      canvas.drawRect(shadowRect, shadowPaint);
    }
  }
  _fortunePaintRawChartLabel(
    canvas,
    painter,
    strokePainter,
    topLeft + Offset(labelPadding.left, labelPadding.top),
    backgroundColor ?? const Color(0xeeffffff),
    borderColor,
    borderWidth,
    labelPadding,
    borderRadius,
    textWidth,
    textHeight,
    textAlign,
    textVerticalAlign,
    0,
    borderType,
  );
}

_FortuneRawChartTooltipSample? _fortuneRawChartTooltipSample(
  List<FortuneRawChartSeries> series,
  List<String> xAxisLabels,
  Rect plotRect, {
  Offset? hoverPosition,
  bool triggerAxis = false,
  String? order,
  String? formatter,
  required bool xAxisInverse,
  required bool yAxisInverse,
  required bool xAxisBoundaryGap,
}) {
  final allValues = _fortuneRawChartSeriesScaleValues(series);
  if (allValues.isEmpty || plotRect.width <= 0 || plotRect.height <= 0) {
    return null;
  }
  var minimum = allValues.reduce(math.min);
  var maximum = allValues.reduce(math.max);
  if (minimum == maximum) {
    minimum -= 1;
    maximum += 1;
  }
  double yFor(double value) {
    final ratio = (value - minimum) / (maximum - minimum);
    return yAxisInverse
        ? plotRect.top + ratio * plotRect.height
        : plotRect.bottom - ratio * plotRect.height;
  }

  double xForIndex(int index, int count) {
    final ratio = xAxisBoundaryGap
        ? (count <= 0 ? 0.0 : (index + 0.5) / count)
        : (count <= 1 ? 0.0 : index / (count - 1));
    return xAxisInverse
        ? plotRect.right - plotRect.width * ratio
        : plotRect.left + plotRect.width * ratio;
  }

  if (hoverPosition != null && plotRect.contains(hoverPosition)) {
    final interactiveSeries = [
      for (final item in series)
        if (item.silent != true) item,
    ];
    if (interactiveSeries.isEmpty) {
      return null;
    }
    if (triggerAxis) {
      final axisSample = _fortuneRawChartAxisTooltipSample(
        interactiveSeries,
        xAxisLabels,
        plotRect,
        hoverPosition,
        formatter,
        order,
        xAxisInverse: xAxisInverse,
        xAxisBoundaryGap: xAxisBoundaryGap,
      );
      if (axisSample != null) {
        return axisSample;
      }
    }
    _FortuneRawChartTooltipSample? nearestSample;
    var nearestDistance = double.infinity;
    for (final item in interactiveSeries) {
      final valueSlots = item.valueSlots.isEmpty
          ? <double?>[for (final value in item.values) value]
          : item.valueSlots;
      if (valueSlots.isEmpty) {
        continue;
      }
      for (var index = 0; index < valueSlots.length; index += 1) {
        final value = valueSlots[index];
        if (value == null) {
          continue;
        }
        final point = Offset(xForIndex(index, valueSlots.length), yFor(value));
        final distance = (point - hoverPosition).distanceSquared;
        if (distance >= nearestDistance) {
          continue;
        }
        final pointName = index < item.pointNames.length
            ? item.pointNames[index]
            : null;
        final name =
            pointName ??
            (index < xAxisLabels.length
                ? xAxisLabels[index]
                : index.toString());
        nearestDistance = distance;
        nearestSample = _FortuneRawChartTooltipSample(
          seriesName: item.name,
          name: name,
          value: value,
          anchor: hoverPosition,
        );
      }
    }
    if (nearestSample != null) {
      return nearestSample;
    }
    return null;
  }

  for (final item in series) {
    final valueSlots = item.valueSlots.isEmpty
        ? <double?>[for (final value in item.values) value]
        : item.valueSlots;
    if (valueSlots.isEmpty) {
      continue;
    }
    var index = -1;
    double? value;
    for (var offset = 0; offset < valueSlots.length; offset += 1) {
      final candidateIndex = valueSlots.length - 1 - offset;
      final candidateValue = valueSlots[candidateIndex];
      if (candidateValue != null) {
        index = candidateIndex;
        value = candidateValue;
        break;
      }
    }
    if (index < 0 || value == null) {
      continue;
    }
    final pointName = item.pointNames[index];
    final name =
        pointName ??
        (index < xAxisLabels.length ? xAxisLabels[index] : index.toString());
    return _FortuneRawChartTooltipSample(
      seriesName: item.name,
      name: name,
      value: value,
      anchor: Offset(xForIndex(index, valueSlots.length), yFor(value)),
    );
  }
  return null;
}

_FortuneRawChartTooltipSample? _fortuneRawChartAxisTooltipSample(
  List<FortuneRawChartSeries> series,
  List<String> xAxisLabels,
  Rect plotRect,
  Offset hoverPosition,
  String? formatter,
  String? order, {
  required bool xAxisInverse,
  required bool xAxisBoundaryGap,
}) {
  var categoryCount = xAxisLabels.length;
  for (final item in series) {
    categoryCount = math.max(categoryCount, item.valueSlots.length);
    categoryCount = math.max(categoryCount, item.values.length);
  }
  if (categoryCount <= 0) {
    return null;
  }
  var nearestIndex = 0;
  var nearestDistance = double.infinity;
  for (var index = 0; index < categoryCount; index += 1) {
    final distance =
        (_fortuneRawChartCategoryXForIndex(
                  index,
                  categoryCount,
                  plotRect,
                  xAxisInverse: xAxisInverse,
                  xAxisBoundaryGap: xAxisBoundaryGap,
                ) -
                hoverPosition.dx)
            .abs();
    if (distance < nearestDistance) {
      nearestDistance = distance;
      nearestIndex = index;
    }
  }
  final name = nearestIndex < xAxisLabels.length
      ? xAxisLabels[nearestIndex]
      : nearestIndex.toString();
  final rows = <_FortuneRawChartTooltipAxisRow>[];
  for (var seriesIndex = 0; seriesIndex < series.length; seriesIndex += 1) {
    final item = series[seriesIndex];
    final valueSlots = item.valueSlots.isEmpty
        ? <double?>[for (final value in item.values) value]
        : item.valueSlots;
    if (nearestIndex >= valueSlots.length) {
      continue;
    }
    final value = valueSlots[nearestIndex];
    if (value == null) {
      continue;
    }
    rows.add(
      _FortuneRawChartTooltipAxisRow(
        seriesIndex: seriesIndex,
        value: value,
        text: formatter == null
            ? _fortuneRawChartTooltipSeriesLine(item.name, value)
            : _fortuneRawChartTooltipText(formatter, item.name, name, value),
      ),
    );
  }
  if (rows.isEmpty) {
    return null;
  }
  _fortuneSortRawChartTooltipAxisRows(rows, order);
  final lines = [for (final row in rows) row.text];
  final text = formatter == null
      ? '$name\n${lines.join('\n')}'
      : lines.join('\n');
  return _FortuneRawChartTooltipSample(
    seriesName: series.isEmpty ? null : series.first.name,
    name: name,
    value: 0,
    anchor: hoverPosition,
    text: text,
  );
}

void _fortuneSortRawChartTooltipAxisRows(
  List<_FortuneRawChartTooltipAxisRow> rows,
  String? order,
) {
  switch (order?.trim()) {
    case 'seriesDesc':
      rows.sort((a, b) => b.seriesIndex.compareTo(a.seriesIndex));
    case 'valueAsc':
      rows.sort((a, b) {
        final byValue = a.value.compareTo(b.value);
        return byValue != 0 ? byValue : a.seriesIndex.compareTo(b.seriesIndex);
      });
    case 'valueDesc':
      rows.sort((a, b) {
        final byValue = b.value.compareTo(a.value);
        return byValue != 0 ? byValue : a.seriesIndex.compareTo(b.seriesIndex);
      });
  }
}

class _FortuneRawChartTooltipAxisRow {
  const _FortuneRawChartTooltipAxisRow({
    required this.seriesIndex,
    required this.value,
    required this.text,
  });

  final int seriesIndex;
  final double value;
  final String text;
}

double? _fortuneRawChartNearestXAxisPosition(
  double x,
  Rect plotRect,
  List<String> xAxisLabels,
  List<FortuneRawChartSeries> series, {
  required bool xAxisInverse,
  required bool xAxisBoundaryGap,
}) {
  var categoryCount = xAxisLabels.length;
  for (final item in series) {
    categoryCount = math.max(categoryCount, item.valueSlots.length);
    categoryCount = math.max(categoryCount, item.values.length);
  }
  if (categoryCount <= 0) {
    return null;
  }
  var nearestX = _fortuneRawChartCategoryXForIndex(
    0,
    categoryCount,
    plotRect,
    xAxisInverse: xAxisInverse,
    xAxisBoundaryGap: xAxisBoundaryGap,
  );
  var nearestDistance = (nearestX - x).abs();
  for (var index = 1; index < categoryCount; index += 1) {
    final candidateX = _fortuneRawChartCategoryXForIndex(
      index,
      categoryCount,
      plotRect,
      xAxisInverse: xAxisInverse,
      xAxisBoundaryGap: xAxisBoundaryGap,
    );
    final distance = (candidateX - x).abs();
    if (distance < nearestDistance) {
      nearestDistance = distance;
      nearestX = candidateX;
    }
  }
  return nearestX;
}

double? _fortuneRawChartNearestYAxisPosition(
  double y,
  Rect plotRect,
  List<String> yAxisLabels,
  List<FortuneRawChartSeries> series, {
  required bool yAxisInverse,
}) {
  final candidates = <double>[];
  if (yAxisLabels.isNotEmpty) {
    for (var index = 0; index < yAxisLabels.length; index += 1) {
      final ratio = yAxisLabels.length <= 1
          ? 0.0
          : index / (yAxisLabels.length - 1);
      candidates.add(
        yAxisInverse
            ? plotRect.top + plotRect.height * ratio
            : plotRect.bottom - plotRect.height * ratio,
      );
    }
  } else {
    final values = _fortuneRawChartSeriesScaleValues(series);
    if (values.isNotEmpty) {
      var minimum = values.reduce(math.min);
      var maximum = values.reduce(math.max);
      if (minimum == maximum) {
        minimum -= 1;
        maximum += 1;
      }
      for (final value in values.toSet()) {
        final ratio = (value - minimum) / (maximum - minimum);
        candidates.add(
          yAxisInverse
              ? plotRect.top + ratio * plotRect.height
              : plotRect.bottom - ratio * plotRect.height,
        );
      }
    }
  }
  if (candidates.isEmpty) {
    return null;
  }
  var nearestY = candidates.first;
  var nearestDistance = (nearestY - y).abs();
  for (final candidateY in candidates.skip(1)) {
    final distance = (candidateY - y).abs();
    if (distance < nearestDistance) {
      nearestDistance = distance;
      nearestY = candidateY;
    }
  }
  return nearestY;
}

double _fortuneRawChartCategoryXForIndex(
  int index,
  int categoryCount,
  Rect plotRect, {
  required bool xAxisInverse,
  required bool xAxisBoundaryGap,
}) {
  final ratio = xAxisBoundaryGap
      ? (index + 0.5) / categoryCount
      : (categoryCount <= 1 ? 0.0 : index / (categoryCount - 1));
  return xAxisInverse
      ? plotRect.right - plotRect.width * ratio
      : plotRect.left + plotRect.width * ratio;
}

String _fortuneRawChartTooltipSeriesLine(String? seriesName, double value) {
  final defaultValue = value == value.roundToDouble()
      ? value.round().toString()
      : value.toStringAsFixed(1);
  final name = seriesName?.trim();
  return name == null || name.isEmpty ? defaultValue : '$name: $defaultValue';
}

String _fortuneRawChartTooltipText(
  String? formatter,
  String? seriesName,
  String name,
  double value,
) {
  final defaultValue = value == value.roundToDouble()
      ? value.round().toString()
      : value.toStringAsFixed(1);
  if (formatter == null) {
    return name.isEmpty ? defaultValue : '$name: $defaultValue';
  }
  return formatter
      .replaceAll('{value}', defaultValue)
      .replaceAll('{c}', defaultValue)
      .replaceAll('{b}', name)
      .replaceAll('{name}', name)
      .replaceAll('{a}', seriesName ?? '');
}

Offset _fortuneRawChartTooltipPaintPosition(
  Object? position,
  Rect chartRect,
  Rect plotRect,
  Size tooltipSize,
  Offset anchor,
) {
  if (position is List && position.length >= 2) {
    return Offset(
      _fortuneRawChartTooltipAxisPosition(
        position[0],
        chartRect.left,
        chartRect.width,
      ),
      _fortuneRawChartTooltipAxisPosition(
        position[1],
        chartRect.top,
        chartRect.height,
      ),
    );
  }
  if (position is String) {
    switch (position.toLowerCase()) {
      case 'top':
        return Offset(
          chartRect.left + (chartRect.width - tooltipSize.width) / 2,
          chartRect.top + 8,
        );
      case 'bottom':
        return Offset(
          chartRect.left + (chartRect.width - tooltipSize.width) / 2,
          chartRect.bottom - tooltipSize.height - 8,
        );
      case 'left':
        return Offset(
          chartRect.left + 8,
          chartRect.center.dy - tooltipSize.height / 2,
        );
      case 'right':
        return Offset(
          chartRect.right - tooltipSize.width - 8,
          chartRect.center.dy - tooltipSize.height / 2,
        );
      case 'inside':
      case 'center':
        return Offset(
          chartRect.left + (chartRect.width - tooltipSize.width) / 2,
          chartRect.top + (chartRect.height - tooltipSize.height) / 2,
        );
    }
  }
  final fallbackAnchor = anchor == Offset.zero ? plotRect.topRight : anchor;
  return fallbackAnchor + const Offset(8, 8);
}

double _fortuneRawChartTooltipAxisPosition(
  Object? raw,
  double origin,
  double length,
) {
  if (raw is num) {
    return origin + raw.toDouble();
  }
  if (raw is String) {
    final trimmed = raw.trim();
    if (trimmed.endsWith('%')) {
      final percent = double.tryParse(trimmed.substring(0, trimmed.length - 1));
      if (percent != null && percent.isFinite) {
        return origin + length * percent / 100;
      }
    }
    final parsed = double.tryParse(trimmed);
    if (parsed != null && parsed.isFinite) {
      return origin + parsed;
    }
  }
  return origin;
}

class _FortuneRawChartTooltipSample {
  const _FortuneRawChartTooltipSample({
    required this.seriesName,
    required this.name,
    required this.value,
    required this.anchor,
    this.text,
  });

  final String? seriesName;
  final String name;
  final double value;
  final Offset anchor;
  final String? text;
}

String _fortuneRawChartMarkerLabelText({
  required String? formatter,
  required double? value,
  required String? name,
  required String? seriesName,
  int? precision,
}) {
  final defaultValue = value == null
      ? ''
      : precision != null
      ? value.toStringAsFixed(precision)
      : value == value.roundToDouble()
      ? value.round().toString()
      : value.toStringAsFixed(1);
  if (formatter == null) {
    return name ?? defaultValue;
  }
  return formatter
      .replaceAll('{value}', defaultValue)
      .replaceAll('{c}', defaultValue)
      .replaceAll('{b}', name ?? defaultValue)
      .replaceAll('{name}', name ?? defaultValue)
      .replaceAll('{a}', seriesName ?? '');
}

List<List<Offset>> _fortuneRawChartSeriesPointRuns(
  List<double?> valueSlots,
  int categoryCount,
  double Function(int index, int count) xForIndex,
  double Function(double value) yFor, {
  required bool connectNulls,
}) {
  final runs = <List<Offset>>[];
  var current = <Offset>[];
  for (var index = 0; index < valueSlots.length; index += 1) {
    final value = valueSlots[index];
    if (value == null) {
      if (!connectNulls && current.isNotEmpty) {
        runs.add(current);
        current = <Offset>[];
      }
      continue;
    }
    current.add(Offset(xForIndex(index, categoryCount), yFor(value)));
  }
  if (current.isNotEmpty) {
    runs.add(current);
  }
  return runs;
}

List<Offset> _fortuneRawChartSeriesLinePoints(
  List<Offset> points,
  String? step,
) {
  if (points.length < 2 || step == null) {
    return points;
  }
  final stepped = <Offset>[points.first];
  for (var index = 1; index < points.length; index += 1) {
    final previous = points[index - 1];
    final current = points[index];
    switch (step) {
      case 'start':
        stepped
          ..add(Offset(previous.dx, current.dy))
          ..add(current);
        break;
      case 'middle':
        final middleX = (previous.dx + current.dx) / 2;
        stepped
          ..add(Offset(middleX, previous.dy))
          ..add(Offset(middleX, current.dy))
          ..add(current);
        break;
      case 'end':
        stepped
          ..add(Offset(current.dx, previous.dy))
          ..add(current);
        break;
      default:
        stepped.add(current);
    }
  }
  return stepped;
}

Path _fortuneRawChartSeriesLinePath(List<Offset> points) {
  final path = Path()..moveTo(points.first.dx, points.first.dy);
  for (var index = 1; index < points.length; index += 1) {
    path.lineTo(points[index].dx, points[index].dy);
  }
  return path;
}

Path _fortuneRawChartSeriesSmoothLinePath(List<Offset> points) {
  final path = Path()..moveTo(points.first.dx, points.first.dy);
  if (points.length < 3) {
    for (var index = 1; index < points.length; index += 1) {
      path.lineTo(points[index].dx, points[index].dy);
    }
    return path;
  }
  for (var index = 0; index < points.length - 1; index += 1) {
    final previous = index == 0 ? points[index] : points[index - 1];
    final current = points[index];
    final next = points[index + 1];
    final afterNext = index + 2 < points.length ? points[index + 2] : next;
    final control1 = current + (next - previous) / 6;
    final control2 = next - (afterNext - current) / 6;
    path.cubicTo(
      control1.dx,
      control1.dy,
      control2.dx,
      control2.dy,
      next.dx,
      next.dy,
    );
  }
  return path;
}

List<Offset> _fortuneRawChartSeriesSmoothLineDashPoints(List<Offset> points) {
  if (points.length < 3) {
    return points;
  }
  final sampled = <Offset>[];
  for (var index = 0; index < points.length - 1; index += 1) {
    final previous = index == 0 ? points[index] : points[index - 1];
    final current = points[index];
    final next = points[index + 1];
    final afterNext = index + 2 < points.length ? points[index + 2] : next;
    final control1 = current + (next - previous) / 6;
    final control2 = next - (afterNext - current) / 6;
    final steps = math.max(4, ((next.dx - current.dx).abs() / 8).ceil());
    for (var step = 0; step <= steps; step += 1) {
      if (sampled.isNotEmpty && step == 0) {
        continue;
      }
      final t = step / steps;
      sampled.add(
        _fortuneRawChartCubicPoint(current, control1, control2, next, t),
      );
    }
  }
  return sampled;
}

Offset _fortuneRawChartCubicPoint(
  Offset start,
  Offset control1,
  Offset control2,
  Offset end,
  double t,
) {
  final inverse = 1 - t;
  return start * (inverse * inverse * inverse) +
      control1 * (3 * inverse * inverse * t) +
      control2 * (3 * inverse * t * t) +
      end * (t * t * t);
}

void _fortuneDrawRawChartSeriesLine(
  Canvas canvas,
  Path path,
  List<Offset> points,
  Paint paint,
  String? type, {
  List<double>? dashPattern,
  double? dashOffset,
}) {
  if ((dashPattern == null || dashPattern.isEmpty) &&
      type != 'dashed' &&
      type != 'dotted') {
    canvas.drawPath(path, paint);
    return;
  }
  final pattern = dashPattern == null || dashPattern.isEmpty
      ? [
          type == 'dotted'
              ? math.max(1.5, paint.strokeWidth)
              : math.max(4.0, paint.strokeWidth * 2.5),
          type == 'dotted'
              ? math.max(1.5, paint.strokeWidth) * 1.6
              : math.max(3.0, paint.strokeWidth * 1.4),
        ]
      : dashPattern;
  for (var index = 1; index < points.length; index += 1) {
    _fortuneDrawRawChartDashedPatternSegment(
      canvas,
      points[index - 1],
      points[index],
      paint,
      pattern,
      dashOffset ?? 0,
    );
  }
}

void _fortuneDrawRawChartLabelLineSegment(
  Canvas canvas,
  Offset start,
  Offset end,
  Paint paint,
  String? type,
) {
  if (type != 'dashed' && type != 'dotted') {
    canvas.drawLine(start, end, paint);
    return;
  }
  final segmentLength = type == 'dotted'
      ? math.max(1.5, paint.strokeWidth)
      : math.max(4.0, paint.strokeWidth * 2.5);
  final gapLength = type == 'dotted'
      ? segmentLength * 1.6
      : math.max(3.0, paint.strokeWidth * 1.4);
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    start,
    end,
    paint,
    segmentLength,
    gapLength,
    0,
  );
}

void _fortuneDrawRawChartLabelLinePath(
  Canvas canvas,
  List<Offset> points,
  Paint paint,
  String? type,
) {
  if (points.length < 2) {
    return;
  }
  if (type != 'dashed' && type != 'dotted') {
    final path = Path()..moveTo(points.first.dx, points.first.dy);
    for (var index = 1; index < points.length; index += 1) {
      path.lineTo(points[index].dx, points[index].dy);
    }
    canvas.drawPath(path, paint);
    return;
  }
  for (var index = 1; index < points.length; index += 1) {
    _fortuneDrawRawChartLabelLineSegment(
      canvas,
      points[index - 1],
      points[index],
      paint,
      type,
    );
  }
}

void _fortuneDrawRawChartSmoothLabelLine(
  Canvas canvas,
  Offset start,
  Offset control,
  Offset end,
  Paint paint,
  String? type,
) {
  final path = Path()
    ..moveTo(start.dx, start.dy)
    ..quadraticBezierTo(control.dx, control.dy, end.dx, end.dy);
  if (type != 'dashed' && type != 'dotted') {
    canvas.drawPath(path, paint);
    return;
  }
  final segmentLength = type == 'dotted'
      ? math.max(1.5, paint.strokeWidth)
      : math.max(4.0, paint.strokeWidth * 2.5);
  final gapLength = type == 'dotted'
      ? segmentLength * 1.6
      : math.max(3.0, paint.strokeWidth * 1.4);
  var previous = start;
  for (var index = 1; index <= 24; index += 1) {
    final t = index / 24;
    final inverse = 1 - t;
    final point =
        start * (inverse * inverse) +
        control * (2 * inverse * t) +
        end * (t * t);
    _fortuneDrawRawChartDashedSeriesSegment(
      canvas,
      previous,
      point,
      paint,
      segmentLength,
      gapLength,
      0,
    );
    previous = point;
  }
}

void _fortuneDrawRawChartDashedSeriesSegment(
  Canvas canvas,
  Offset start,
  Offset end,
  Paint paint,
  double segmentLength,
  double gapLength,
  double dashOffset,
) {
  final delta = end - start;
  final length = delta.distance;
  if (length <= 0) {
    return;
  }
  final direction = delta / length;
  final patternLength = segmentLength + gapLength;
  final normalizedOffset = patternLength <= 0
      ? 0.0
      : ((dashOffset % patternLength) + patternLength) % patternLength;
  var position = -normalizedOffset;
  while (position < length) {
    final segmentStart = math.max(0.0, position);
    final segmentEnd = math.min(length, position + segmentLength);
    if (segmentEnd > segmentStart) {
      canvas.drawLine(
        start + direction * segmentStart,
        start + direction * segmentEnd,
        paint,
      );
    }
    position += patternLength;
  }
}

void _fortuneDrawRawChartDashedPatternSegment(
  Canvas canvas,
  Offset start,
  Offset end,
  Paint paint,
  List<double> pattern,
  double dashOffset,
) {
  final delta = end - start;
  final length = delta.distance;
  if (length <= 0 || pattern.isEmpty) {
    return;
  }
  final direction = delta / length;
  final patternLength = pattern.fold<double>(0, (sum, value) => sum + value);
  if (patternLength <= 0) {
    return;
  }
  var offset = ((dashOffset % patternLength) + patternLength) % patternLength;
  var patternIndex = 0;
  var drawing = true;
  while (offset >= pattern[patternIndex]) {
    offset -= pattern[patternIndex];
    patternIndex = (patternIndex + 1) % pattern.length;
    drawing = !drawing;
  }
  var position = -offset;
  while (position < length) {
    final segmentLength = pattern[patternIndex];
    final segmentStart = math.max(0.0, position);
    final segmentEnd = math.min(length, position + segmentLength);
    if (drawing && segmentEnd > segmentStart) {
      canvas.drawLine(
        start + direction * segmentStart,
        start + direction * segmentEnd,
        paint,
      );
    }
    position += segmentLength;
    patternIndex = (patternIndex + 1) % pattern.length;
    drawing = !drawing;
  }
}

void _fortuneDrawRawChartSeriesSymbol(
  Canvas canvas,
  Offset center,
  String? symbol,
  double radius,
  Paint paint,
  double rotationRadians, {
  Size? size,
}) {
  final normalizedSymbol = symbol?.trim().toLowerCase();
  if (normalizedSymbol == 'none') {
    return;
  }
  if (normalizedSymbol == 'emptycircle' &&
      paint.style != PaintingStyle.stroke) {
    return;
  }
  if (rotationRadians != 0 && rotationRadians.isFinite) {
    canvas.save();
    canvas.translate(center.dx, center.dy);
    canvas.rotate(rotationRadians);
    canvas.translate(-center.dx, -center.dy);
  }
  try {
    switch (normalizedSymbol) {
      case 'rect':
      case 'rectangle':
        canvas.drawRect(
          size == null
              ? Rect.fromCircle(center: center, radius: radius)
              : Rect.fromCenter(
                  center: center,
                  width: size.width,
                  height: size.height,
                ),
          paint,
        );
        return;
      case 'diamond':
        final halfWidth = size?.width == null ? radius : size!.width / 2;
        final halfHeight = size?.height == null ? radius : size!.height / 2;
        canvas.drawPath(
          Path()
            ..moveTo(center.dx, center.dy - halfHeight)
            ..lineTo(center.dx + halfWidth, center.dy)
            ..lineTo(center.dx, center.dy + halfHeight)
            ..lineTo(center.dx - halfWidth, center.dy)
            ..close(),
          paint,
        );
        return;
      case 'triangle':
        final halfWidth = size?.width == null ? radius : size!.width / 2;
        final halfHeight = size?.height == null ? radius : size!.height / 2;
        canvas.drawPath(
          Path()
            ..moveTo(center.dx, center.dy - halfHeight)
            ..lineTo(center.dx + halfWidth, center.dy + halfHeight)
            ..lineTo(center.dx - halfWidth, center.dy + halfHeight)
            ..close(),
          paint,
        );
        return;
    }
    canvas.drawCircle(center, radius, paint);
  } finally {
    if (rotationRadians != 0 && rotationRadians.isFinite) {
      canvas.restore();
    }
  }
}

void _fortuneDrawRawChartSeriesSymbolBorder(
  Canvas canvas,
  Offset center,
  String? symbol,
  double radius,
  double rotationRadians,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
) {
  if (borderColor == null || borderWidth == null || borderWidth <= 0) {
    return;
  }
  final paint = Paint()
    ..color = borderColor
    ..style = PaintingStyle.stroke
    ..strokeWidth = borderWidth;
  final normalizedSymbol = symbol?.trim().toLowerCase();
  final isCircle =
      normalizedSymbol == null ||
      normalizedSymbol == 'circle' ||
      normalizedSymbol == 'emptycircle';
  if (isCircle && (borderType == 'dashed' || borderType == 'dotted')) {
    _fortuneDrawRawChartDashedCircle(
      canvas,
      center,
      radius,
      paint,
      borderType!,
    );
    return;
  }
  final isRect = normalizedSymbol == 'rect' || normalizedSymbol == 'rectangle';
  if (isRect && (borderType == 'dashed' || borderType == 'dotted')) {
    final hasRotation = rotationRadians != 0 && rotationRadians.isFinite;
    if (hasRotation) {
      canvas.save();
      canvas.translate(center.dx, center.dy);
      canvas.rotate(rotationRadians);
      canvas.translate(-center.dx, -center.dy);
    }
    try {
      _fortuneDrawRawChartDashedRect(
        canvas,
        Rect.fromCircle(center: center, radius: radius),
        paint,
        borderType!,
      );
    } finally {
      if (hasRotation) {
        canvas.restore();
      }
    }
    return;
  }
  final dashedPath = _fortuneRawChartSeriesSymbolPath(
    center,
    normalizedSymbol,
    radius,
  );
  if (dashedPath != null &&
      (borderType == 'dashed' || borderType == 'dotted')) {
    final hasRotation = rotationRadians != 0 && rotationRadians.isFinite;
    if (hasRotation) {
      canvas.save();
      canvas.translate(center.dx, center.dy);
      canvas.rotate(rotationRadians);
      canvas.translate(-center.dx, -center.dy);
    }
    try {
      _fortuneDrawRawChartDashedPath(canvas, dashedPath, paint, borderType!);
    } finally {
      if (hasRotation) {
        canvas.restore();
      }
    }
    return;
  }
  _fortuneDrawRawChartSeriesSymbol(
    canvas,
    center,
    symbol,
    radius,
    paint,
    rotationRadians,
  );
}

Path? _fortuneRawChartSeriesSymbolPath(
  Offset center,
  String? normalizedSymbol,
  double radius,
) {
  switch (normalizedSymbol) {
    case 'diamond':
      return Path()
        ..moveTo(center.dx, center.dy - radius)
        ..lineTo(center.dx + radius, center.dy)
        ..lineTo(center.dx, center.dy + radius)
        ..lineTo(center.dx - radius, center.dy)
        ..close();
    case 'triangle':
      return Path()
        ..moveTo(center.dx, center.dy - radius)
        ..lineTo(center.dx + radius, center.dy + radius)
        ..lineTo(center.dx - radius, center.dy + radius)
        ..close();
  }
  return null;
}

void _fortuneDrawRawChartSeriesSymbolShadow(
  Canvas canvas,
  Offset center,
  String? symbol,
  double radius,
  double rotationRadians,
  Color? shadowColor,
  double? shadowBlur,
  Offset shadowOffset,
) {
  if (shadowColor == null) {
    return;
  }
  final paint = Paint()..color = shadowColor;
  if (shadowBlur != null && shadowBlur > 0) {
    paint.maskFilter = ui.MaskFilter.blur(ui.BlurStyle.normal, shadowBlur);
  }
  _fortuneDrawRawChartSeriesSymbol(
    canvas,
    center + shadowOffset,
    symbol,
    radius,
    paint,
    rotationRadians,
  );
}

Color? _fortuneRawChartResolvedPointBorderColor(
  FortuneRawChartSeries series,
  int index,
) {
  final pointBorderColor = index < series.pointBorderColors.length
      ? series.pointBorderColors[index]
      : null;
  return pointBorderColor ?? series.itemBorderColor;
}

double? _fortuneRawChartResolvedPointBorderWidth(
  FortuneRawChartSeries series,
  int index,
) {
  final pointBorderWidth = index < series.pointBorderWidths.length
      ? series.pointBorderWidths[index]
      : null;
  return pointBorderWidth ?? series.itemBorderWidth;
}

String? _fortuneRawChartResolvedPointBorderType(
  FortuneRawChartSeries series,
  int index,
) {
  final pointBorderType = index < series.pointBorderTypes.length
      ? series.pointBorderTypes[index]
      : null;
  return pointBorderType ?? series.itemBorderType;
}

Color? _fortuneRawChartResolvedPointShadowColor(
  FortuneRawChartSeries series,
  int index,
) {
  final pointShadowColor = index < series.pointShadowColors.length
      ? series.pointShadowColors[index]
      : null;
  return pointShadowColor ?? series.itemShadowColor;
}

double? _fortuneRawChartResolvedPointShadowBlur(
  FortuneRawChartSeries series,
  int index,
) {
  final pointShadowBlur = index < series.pointShadowBlurs.length
      ? series.pointShadowBlurs[index]
