Offset _fortuneRawChartResolvedPointShadowOffset(
  FortuneRawChartSeries series,
  int index,
) {
  final pointShadowOffsetX = index < series.pointShadowOffsetXs.length
      ? series.pointShadowOffsetXs[index]
      : null;
  final pointShadowOffsetY = index < series.pointShadowOffsetYs.length
      ? series.pointShadowOffsetYs[index]
      : null;
  return Offset(
    pointShadowOffsetX ?? series.itemShadowOffsetX ?? 0,
    pointShadowOffsetY ?? series.itemShadowOffsetY ?? 0,
  );
}

double? _fortuneRawChartXAxisZeroY(
  Rect plotRect,
  List<FortuneRawChartSeries> series, {
  required bool yAxisInverse,
  required bool enabled,
}) {
  if (!enabled || plotRect.width <= 0 || plotRect.height <= 0) {
    return null;
  }
  final allValues = <double>[for (final item in series) ...item.values];
  if (allValues.isEmpty) {
    return null;
  }
  var minimum = allValues.reduce(math.min);
  var maximum = allValues.reduce(math.max);
  if (minimum == maximum) {
    minimum -= 1;
    maximum += 1;
  }
  if (minimum > 0 || maximum < 0) {
    return null;
  }
  final ratio = (0 - minimum) / (maximum - minimum);
  return yAxisInverse
      ? plotRect.top + ratio * plotRect.height
      : plotRect.bottom - ratio * plotRect.height;
}

double? _fortuneRawChartYAxisZeroX(
  Rect plotRect,
  List<FortuneRawChartSeries> series, {
  required bool xAxisInverse,
  required bool enabled,
}) {
  if (!enabled || plotRect.width <= 0 || plotRect.height <= 0) {
    return null;
  }
  final allValues = <double>[
    for (final item in series)
      for (final value in item.xValueSlots)
        if (value != null && value.isFinite) value,
  ];
  if (allValues.isEmpty) {
    return null;
  }
  var minimum = allValues.reduce(math.min);
  var maximum = allValues.reduce(math.max);
  if (minimum == maximum) {
    minimum -= 1;
    maximum += 1;
  }
  if (minimum > 0 || maximum < 0) {
    return null;
  }
  final ratio = (0 - minimum) / (maximum - minimum);
  return xAxisInverse
      ? plotRect.right - ratio * plotRect.width
      : plotRect.left + ratio * plotRect.width;
}

Rect _fortuneRawChartPlotRect(
  Rect chartRect,
  double axisLeft,
  double axisBottom,
) {
  return Rect.fromLTRB(
    axisLeft + 6,
    chartRect.top + 18,
    chartRect.right - 4,
    axisBottom - 3,
  );
}

void _fortuneDrawRawChartGridLines(
  Canvas canvas,
  Rect plotRect, {
  required bool horizontal,
  required bool vertical,
  required Color color,
  List<Color> horizontalColors = const [],
  List<Color> verticalColors = const [],
  required double horizontalWidth,
  required double verticalWidth,
  String? horizontalType,
  String? verticalType,
  double? horizontalDashOffset,
  double? verticalDashOffset,
  String? horizontalCap,
  String? verticalCap,
  Color? horizontalShadowColor,
  Color? verticalShadowColor,
  double? horizontalShadowBlur,
  double? verticalShadowBlur,
  double? horizontalShadowOffsetX,
  double? verticalShadowOffsetX,
  double? horizontalShadowOffsetY,
  double? verticalShadowOffsetY,
  double? horizontalOpacity,
  double? verticalOpacity,
  int? horizontalInterval,
  int? verticalInterval,
}) {
  if (plotRect.width <= 0 ||
      plotRect.height <= 0 ||
      (!horizontal && !vertical)) {
    return;
  }
  if (horizontal) {
    final step = math.max(1, (horizontalInterval ?? 0) + 1);
    for (var index = 1; index < 4; index += 1) {
      if ((index - 1) % step != 0) {
        continue;
      }
      final y = plotRect.top + plotRect.height * index / 4;
      final lineColor = horizontalColors.isEmpty
          ? color
          : horizontalColors[(index - 1) % horizontalColors.length];
      _fortuneDrawRawChartShadowLine(
        canvas,
        start: Offset(plotRect.left, y),
        end: Offset(plotRect.right, y),
        color: horizontalShadowColor,
        width: horizontalWidth,
        type: horizontalType,
        cap: horizontalCap,
        blur: horizontalShadowBlur,
        offsetX: horizontalShadowOffsetX,
        offsetY: horizontalShadowOffsetY,
        dashOffset: horizontalDashOffset,
      );
      _fortuneDrawRawChartTickLine(
        canvas,
        start: Offset(plotRect.left, y),
        end: Offset(plotRect.right, y),
        color:
            _fortuneRawChartColorWithOpacity(lineColor, horizontalOpacity) ??
            lineColor,
        width: horizontalWidth,
        type: horizontalType,
        cap: horizontalCap,
        dashOffset: horizontalDashOffset,
      );
    }
  }
  if (vertical) {
    final step = math.max(1, (verticalInterval ?? 0) + 1);
    for (var index = 1; index < 4; index += 1) {
      if ((index - 1) % step != 0) {
        continue;
      }
      final x = plotRect.left + plotRect.width * index / 4;
      final lineColor = verticalColors.isEmpty
          ? color
          : verticalColors[(index - 1) % verticalColors.length];
      _fortuneDrawRawChartShadowLine(
        canvas,
        start: Offset(x, plotRect.top),
        end: Offset(x, plotRect.bottom),
        color: verticalShadowColor,
        width: verticalWidth,
        type: verticalType,
        cap: verticalCap,
        blur: verticalShadowBlur,
        offsetX: verticalShadowOffsetX,
        offsetY: verticalShadowOffsetY,
        dashOffset: verticalDashOffset,
      );
      _fortuneDrawRawChartTickLine(
        canvas,
        start: Offset(x, plotRect.top),
        end: Offset(x, plotRect.bottom),
        color:
            _fortuneRawChartColorWithOpacity(lineColor, verticalOpacity) ??
            lineColor,
        width: verticalWidth,
        type: verticalType,
        cap: verticalCap,
        dashOffset: verticalDashOffset,
      );
    }
  }
}

void _fortuneDrawRawChartMinorGridLines(
  Canvas canvas,
  Rect plotRect, {
  required bool horizontal,
  required bool vertical,
  required Color horizontalColor,
  required Color verticalColor,
  List<Color> horizontalColors = const [],
  List<Color> verticalColors = const [],
  required double horizontalWidth,
  required double verticalWidth,
  String? horizontalType,
  String? verticalType,
  double? horizontalDashOffset,
  double? verticalDashOffset,
  String? horizontalCap,
  String? verticalCap,
  Color? horizontalShadowColor,
  Color? verticalShadowColor,
  double? horizontalShadowBlur,
  double? verticalShadowBlur,
  double? horizontalShadowOffsetX,
  double? verticalShadowOffsetX,
  double? horizontalShadowOffsetY,
  double? verticalShadowOffsetY,
  double? horizontalOpacity,
  double? verticalOpacity,
  int? horizontalSplitNumber,
  int? verticalSplitNumber,
}) {
  if (plotRect.width <= 0 ||
      plotRect.height <= 0 ||
      (!horizontal && !vertical)) {
    return;
  }
  if (horizontal) {
    final splitNumber = math.max(2, horizontalSplitNumber ?? 5);
    final colors = horizontalColors.isEmpty
        ? [horizontalColor]
        : horizontalColors;
    for (var bandIndex = 0; bandIndex < 4; bandIndex += 1) {
      final start = plotRect.top + plotRect.height * bandIndex / 4;
      final end = plotRect.top + plotRect.height * (bandIndex + 1) / 4;
      for (var splitIndex = 1; splitIndex < splitNumber; splitIndex += 1) {
        final lineIndex = bandIndex * (splitNumber - 1) + splitIndex - 1;
        final lineColor = colors[lineIndex % colors.length];
        final y = start + (end - start) * splitIndex / splitNumber;
        _fortuneDrawRawChartShadowLine(
          canvas,
          start: Offset(plotRect.left, y),
          end: Offset(plotRect.right, y),
          color: horizontalShadowColor,
          width: horizontalWidth,
          type: horizontalType,
          cap: horizontalCap,
          blur: horizontalShadowBlur,
          offsetX: horizontalShadowOffsetX,
          offsetY: horizontalShadowOffsetY,
          dashOffset: horizontalDashOffset,
        );
        _fortuneDrawRawChartTickLine(
          canvas,
          start: Offset(plotRect.left, y),
          end: Offset(plotRect.right, y),
          color:
              _fortuneRawChartColorWithOpacity(lineColor, horizontalOpacity) ??
              lineColor,
          width: horizontalWidth,
          type: horizontalType,
          cap: horizontalCap,
          dashOffset: horizontalDashOffset,
        );
      }
    }
  }
  if (vertical) {
    final splitNumber = math.max(2, verticalSplitNumber ?? 5);
    final colors = verticalColors.isEmpty ? [verticalColor] : verticalColors;
    for (var bandIndex = 0; bandIndex < 4; bandIndex += 1) {
      final start = plotRect.left + plotRect.width * bandIndex / 4;
      final end = plotRect.left + plotRect.width * (bandIndex + 1) / 4;
      for (var splitIndex = 1; splitIndex < splitNumber; splitIndex += 1) {
        final lineIndex = bandIndex * (splitNumber - 1) + splitIndex - 1;
        final lineColor = colors[lineIndex % colors.length];
        final x = start + (end - start) * splitIndex / splitNumber;
        _fortuneDrawRawChartShadowLine(
          canvas,
          start: Offset(x, plotRect.top),
          end: Offset(x, plotRect.bottom),
          color: verticalShadowColor,
          width: verticalWidth,
          type: verticalType,
          cap: verticalCap,
          blur: verticalShadowBlur,
          offsetX: verticalShadowOffsetX,
          offsetY: verticalShadowOffsetY,
          dashOffset: verticalDashOffset,
        );
        _fortuneDrawRawChartTickLine(
          canvas,
          start: Offset(x, plotRect.top),
          end: Offset(x, plotRect.bottom),
          color:
              _fortuneRawChartColorWithOpacity(lineColor, verticalOpacity) ??
              lineColor,
          width: verticalWidth,
          type: verticalType,
          cap: verticalCap,
          dashOffset: verticalDashOffset,
        );
      }
    }
  }
}

void _fortuneDrawRawChartSplitAreas(
  Canvas canvas,
  Rect plotRect, {
  required bool horizontal,
  required bool vertical,
  required List<Color> horizontalColors,
  required List<Color> verticalColors,
  double? horizontalOpacity,
  double? verticalOpacity,
  int? horizontalInterval,
  int? verticalInterval,
}) {
  if (plotRect.width <= 0 ||
      plotRect.height <= 0 ||
      (!horizontal && !vertical)) {
    return;
  }
  final fallbackColors = const [Color(0x00000000), Color(0x110188fb)];
  if (horizontal) {
    final colors = horizontalColors.isEmpty ? fallbackColors : horizontalColors;
    final step = math.max(1, (horizontalInterval ?? 0) + 1);
    for (var index = 0; index < 4; index += 1) {
      if (index % step != 0) {
        continue;
      }
      final color =
          _fortuneRawChartColorWithOpacity(
            colors[index % colors.length],
            horizontalOpacity,
          ) ??
          colors[index % colors.length];
      if (color.a == 0) {
        continue;
      }
      final top = plotRect.top + plotRect.height * index / 4;
      final bottom = plotRect.top + plotRect.height * (index + 1) / 4;
      canvas.drawRect(
        Rect.fromLTRB(plotRect.left, top, plotRect.right, bottom),
        Paint()..color = color,
      );
    }
  }
  if (vertical) {
    final colors = verticalColors.isEmpty ? fallbackColors : verticalColors;
    final step = math.max(1, (verticalInterval ?? 0) + 1);
    for (var index = 0; index < 4; index += 1) {
      if (index % step != 0) {
        continue;
      }
      final color =
          _fortuneRawChartColorWithOpacity(
            colors[index % colors.length],
            verticalOpacity,
          ) ??
          colors[index % colors.length];
      if (color.a == 0) {
        continue;
      }
      final left = plotRect.left + plotRect.width * index / 4;
      final right = plotRect.left + plotRect.width * (index + 1) / 4;
      canvas.drawRect(
        Rect.fromLTRB(left, plotRect.top, right, plotRect.bottom),
        Paint()..color = color,
      );
    }
  }
}

Color _fortuneRawChartSeriesPaintColor(
  FortuneRawChartSeries series,
  int index,
  List<Color> fallbackColors,
) {
  return series.color ?? fallbackColors[index % fallbackColors.length];
}

List<FortuneRawChartSeries> _fortuneRawChartVisibleSeries(
  List<FortuneRawChartSeries> series,
  Map<String, bool> selected,
) {
  if (selected.isEmpty) {
    return series;
  }
  return [
    for (final item in series)
      if (item.name == null || selected[item.name] != false) item,
  ];
}

void _fortuneDrawRawChartLegend(
  Canvas canvas,
  Rect chartRect,
  double axisBottom,
  List<FortuneRawChartSeries> series,
  List<String> legendLabels,
  Color textColor,
  double fontSize,
  FontWeight fontWeight,
  FontStyle fontStyle,
  String? fontFamily,
  double? lineHeight,
  double? opacity,
  Color? textBackgroundColor,
  Color? textBoxBorderColor,
  double? textBoxBorderWidth,
  String? textBoxBorderType,
  double? textBoxBorderRadius,
  Color? textBorderColor,
  double? textBorderWidth,
  EdgeInsets? textPadding,
  double? textWidth,
  double? textHeight,
  String? textOverflow,
  String? textEllipsis,
  String? textAlign,
  String? textVerticalAlign,
  Map<String, FortuneRawChartRichTextStyle> textRichStyles,
  Color? textShadowColor,
  double? textShadowBlur,
  double? textShadowOffsetX,
  double? textShadowOffsetY,
  String? formatter,
  double swatchWidth,
  double swatchHeight,
  double itemGap, {
  String? icon,
  Map<String, bool> selected = const {},
  Color? inactiveColor,
  Color? shadowColor,
  double? shadowBlur,
  double? shadowOffsetX,
  double? shadowOffsetY,
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  double? borderRadius,
  EdgeInsets padding = EdgeInsets.zero,
  bool vertical = false,
  String? horizontalPosition,
  String? verticalPosition,
  double? leftOffset,
  double? topOffset,
  double? rightOffset,
  double? bottomOffset,
  double? leftPercent,
  double? topPercent,
  double? rightPercent,
  double? bottomPercent,
}) {
  const fallbackColors = [
    Color(0xff0188fb),
    Color(0xffffb300),
    Color(0xff34a853),
    Color(0xffea4335),
  ];
  final count = math.max(series.length, legendLabels.length);
  final positioned =
      leftOffset != null ||
      topOffset != null ||
      rightOffset != null ||
      bottomOffset != null ||
      leftPercent != null ||
      topPercent != null ||
      rightPercent != null ||
      bottomPercent != null ||
      horizontalPosition != null ||
      verticalPosition != null;
  final legendHeight = vertical
      ? count * math.max(swatchHeight, lineHeight ?? fontSize) +
            math.max(0, count - 1) * itemGap
      : math.max(swatchHeight, lineHeight ?? fontSize);
  final contentWidth = _fortuneRawChartLegendContentWidth(
    series,
    legendLabels,
    textColor,
    fontSize,
    fontWeight,
    fontStyle,
    fontFamily,
    lineHeight,
    formatter,
    swatchWidth,
    itemGap,
    vertical,
  );
  final legendWidth = positioned
      ? math.min(
          math.max(0.0, chartRect.width),
          math.max(0.0, contentWidth + padding.horizontal + 6),
        )
      : math.max(0.0, chartRect.right - (chartRect.left + 8) - 5);
  final defaultStartLeft = chartRect.left + 8;
  final startLeft = positioned
      ? _fortuneRawChartPositionedLegendLeft(
          chartRect,
          legendWidth,
          leftOffset,
          rightOffset,
          leftPercent,
          rightPercent,
          horizontalPosition,
        )
      : defaultStartLeft;
  final startTop = positioned
      ? _fortuneRawChartPositionedLegendTop(
          chartRect,
          legendHeight + padding.vertical + 5,
          topOffset,
          bottomOffset,
          topPercent,
          bottomPercent,
          verticalPosition,
        )
      : axisBottom + 2;
  var left = startLeft + padding.left;
  var top = startTop + 2 + padding.top;
  final effectiveBorderWidth = borderWidth ?? 0;
  if ((shadowColor != null || backgroundColor != null || borderColor != null) &&
      count > 0) {
    final legendRect = Rect.fromLTWH(
      startLeft - 3,
      startTop,
      legendWidth,
      legendHeight + padding.vertical + 5,
    );
    final radius = Radius.circular(borderRadius ?? 0);
    final roundedLegendRect = RRect.fromRectAndRadius(legendRect, radius);
    if (shadowColor != null) {
      final shadowPaint = Paint()
        ..color = shadowColor
        ..maskFilter =
            (shadowBlur != null && shadowBlur.isFinite && shadowBlur > 0)
            ? MaskFilter.blur(BlurStyle.normal, shadowBlur)
            : null;
      final shadowOffset = Offset(shadowOffsetX ?? 0, shadowOffsetY ?? 0);
      if (borderRadius != null && borderRadius > 0) {
        canvas.drawRRect(roundedLegendRect.shift(shadowOffset), shadowPaint);
      } else {
        canvas.drawRect(legendRect.shift(shadowOffset), shadowPaint);
      }
    }
    if (backgroundColor != null) {
      if (borderRadius != null && borderRadius > 0) {
        canvas.drawRRect(roundedLegendRect, Paint()..color = backgroundColor);
      } else {
        canvas.drawRect(legendRect, Paint()..color = backgroundColor);
      }
    }
    if (borderColor != null && effectiveBorderWidth > 0) {
      final borderPaint = Paint()
        ..color = borderColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = effectiveBorderWidth;
      if (borderRadius != null && borderRadius > 0) {
        final strokeRRect = roundedLegendRect.deflate(effectiveBorderWidth / 2);
        if (borderType == 'dashed' || borderType == 'dotted') {
          _fortuneDrawRawChartDashedRRect(
            canvas,
            strokeRRect,
            borderPaint,
            borderType!,
          );
        } else {
          canvas.drawRRect(strokeRRect, borderPaint);
        }
      } else if (borderType == 'dashed' || borderType == 'dotted') {
        _fortuneDrawRawChartDashedRect(
          canvas,
          legendRect.deflate(effectiveBorderWidth / 2),
          borderPaint,
          borderType!,
        );
      } else {
        canvas.drawRect(
          legendRect.deflate(effectiveBorderWidth / 2),
          borderPaint,
        );
      }
    }
  }
  for (var index = 0; index < count; index += 1) {
    final name = index < series.length && series[index].name != null
        ? series[index].name
        : index < legendLabels.length
        ? legendLabels[index]
        : null;
    if (name == null) {
      continue;
    }
    final label = _fortuneRawChartLegendFormattedName(name, formatter);
    final active = selected[name] != false;
    final resolvedTextColor =
        _fortuneRawChartColorWithOpacity(
          active ? textColor : inactiveColor ?? const Color(0xffb0b0b0),
          opacity,
        ) ??
        (active ? textColor : inactiveColor ?? const Color(0xffb0b0b0));
    final resolvedTextShadowColor = _fortuneRawChartColorWithOpacity(
      textShadowColor,
      opacity,
    );
    final resolvedTextBackgroundColor = _fortuneRawChartColorWithOpacity(
      textBackgroundColor,
      opacity,
    );
    final resolvedTextBoxBorderColor = _fortuneRawChartColorWithOpacity(
      textBoxBorderColor,
      opacity,
    );
    final resolvedTextBorderColor = _fortuneRawChartColorWithOpacity(
      textBorderColor,
      opacity,
    );
    final color = index < series.length
        ? _fortuneRawChartSeriesPaintColor(series[index], index, fallbackColors)
        : fallbackColors[index % fallbackColors.length];
    _fortuneDrawRawChartLegendIcon(
      canvas,
      Rect.fromLTWH(left, top + 1, swatchWidth, swatchHeight),
      icon,
      active ? color : inactiveColor ?? const Color(0xffb0b0b0),
    );
    final maxTextWidth = math.max(
      0.0,
      textWidth ?? chartRect.right - left - swatchWidth - 4,
    );
    final strokePainter = _fortuneRawChartLabelStrokePainter(
      text: label,
      fontSize: fontSize,
      fontWeight: fontWeight,
      fontStyle: fontStyle,
      fontFamily: fontFamily,
      lineHeight: lineHeight,
      textBorderColor: resolvedTextBorderColor,
      textBorderWidth: textBorderWidth,
      overflow: textOverflow,
      ellipsis: textEllipsis,
      maxWidth: maxTextWidth,
    );
    final textPainter = TextPainter(
      text: _fortuneRawChartLabelTextSpan(
        label,
        TextStyle(
          color: resolvedTextColor,
          fontSize: fontSize,
          fontWeight: fontWeight,
          fontStyle: fontStyle,
          fontFamily: fontFamily,
          height: _fortuneRawChartLabelHeightRatio(fontSize, lineHeight),
          shadows: _fortuneRawChartLabelShadows(
            resolvedTextShadowColor,
            textShadowBlur,
            textShadowOffsetX,
            textShadowOffsetY,
          ),
        ),
        textRichStyles,
      ),
      maxLines: 1,
      ellipsis: textOverflow == 'truncate' ? textEllipsis ?? '...' : null,
      textDirection: TextDirection.ltr,
    )..layout(maxWidth: maxTextWidth);
    if (textPainter.width <= 0) {
      return;
    }
    final textOffset = Offset(left + swatchWidth + 3, top);
    _fortunePaintRawChartLabel(
      canvas,
      textPainter,
      strokePainter,
      textOffset,
      resolvedTextBackgroundColor,
      resolvedTextBoxBorderColor,
      textBoxBorderWidth,
      textPadding,
      textBoxBorderRadius,
      textWidth,
      textHeight,
      textAlign,
      textVerticalAlign,
      0,
      textBoxBorderType,
    );
    if (fontWeight.value >= FontWeight.w600.value) {
      textPainter.paint(canvas, textOffset + const Offset(0.45, 0));
    }
    if (vertical) {
      top += math.max(swatchHeight, textPainter.height) + itemGap;
      left = startLeft + padding.left;
    } else {
      left += swatchWidth + 3 + textPainter.width + itemGap;
      if (left >= chartRect.right - 14) {
        return;
      }
    }
  }
}

void _fortuneDrawRawChartDashedRect(
  Canvas canvas,
  Rect rect,
  Paint paint,
  String type,
) {
  final segmentLength = type == 'dotted'
      ? math.max(1.5, paint.strokeWidth)
      : math.max(4.0, paint.strokeWidth * 3);
  final gapLength = type == 'dotted'
      ? segmentLength * 1.6
      : math.max(3.0, paint.strokeWidth * 2);
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    rect.topLeft,
    rect.topRight,
    paint,
    segmentLength,
    gapLength,
    0,
  );
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    rect.topRight,
    rect.bottomRight,
    paint,
    segmentLength,
    gapLength,
    0,
  );
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    rect.bottomRight,
    rect.bottomLeft,
    paint,
    segmentLength,
    gapLength,
    0,
  );
  _fortuneDrawRawChartDashedSeriesSegment(
    canvas,
    rect.bottomLeft,
    rect.topLeft,
    paint,
    segmentLength,
    gapLength,
    0,
  );
}

void _fortuneDrawRawChartLegendIcon(
  Canvas canvas,
  Rect rect,
  String? icon,
  Color color,
) {
  if (icon == 'none') {
    return;
  }
  final paint = Paint()..color = color;
  switch (icon) {
    case 'circle':
      canvas.drawOval(rect, paint);
      return;
    case 'roundrect':
      canvas.drawRRect(
        RRect.fromRectAndRadius(rect, Radius.circular(rect.height / 2)),
        paint,
      );
      return;
    case 'diamond':
      final path = Path()
        ..moveTo(rect.center.dx, rect.top)
        ..lineTo(rect.right, rect.center.dy)
        ..lineTo(rect.center.dx, rect.bottom)
        ..lineTo(rect.left, rect.center.dy)
        ..close();
      canvas.drawPath(path, paint);
      return;
    case 'triangle':
      final path = Path()
        ..moveTo(rect.center.dx, rect.top)
        ..lineTo(rect.right, rect.bottom)
        ..lineTo(rect.left, rect.bottom)
        ..close();
      canvas.drawPath(path, paint);
      return;
  }
  canvas.drawRect(rect, paint);
}

double _fortuneRawChartLegendContentWidth(
  List<FortuneRawChartSeries> series,
  List<String> legendLabels,
  Color textColor,
  double fontSize,
  FontWeight fontWeight,
  FontStyle fontStyle,
  String? fontFamily,
  double? lineHeight,
  String? formatter,
  double swatchWidth,
  double itemGap,
  bool vertical,
) {
  final count = math.max(series.length, legendLabels.length);
  var width = 0.0;
  for (var index = 0; index < count; index += 1) {
    final name = index < series.length && series[index].name != null
        ? series[index].name
        : index < legendLabels.length
        ? legendLabels[index]
        : null;
    if (name == null) {
      continue;
    }
    final label = _fortuneRawChartLegendFormattedName(name, formatter);
    final textPainter = TextPainter(
      text: TextSpan(
        text: label,
        style: TextStyle(
          color: textColor,
          fontSize: fontSize,
          fontWeight: fontWeight,
          fontStyle: fontStyle,
          fontFamily: fontFamily,
          height: _fortuneRawChartLabelHeightRatio(fontSize, lineHeight),
        ),
      ),
      maxLines: 1,
      textDirection: TextDirection.ltr,
    )..layout();
    final itemWidth = swatchWidth + 3 + textPainter.width;
    width = vertical
        ? math.max(width, itemWidth)
        : width + itemWidth + (index == count - 1 ? 0 : itemGap);
  }
  return width;
}

String _fortuneRawChartLegendFormattedName(String name, String? formatter) {
  if (formatter == null) {
    return name;
  }
  if (formatter.contains('{name}')) {
    return formatter.replaceAll('{name}', name);
  }
  return formatter.replaceAll('{a}', name);
}

double _fortuneRawChartPositionedLegendLeft(
  Rect chartRect,
  double legendWidth,
  double? leftOffset,
  double? rightOffset,
  double? leftPercent,
  double? rightPercent,
  String? horizontalPosition,
) {
  final left = leftOffset != null
      ? chartRect.left + leftOffset
      : leftPercent != null
      ? chartRect.left + chartRect.width * leftPercent
      : rightOffset != null
      ? chartRect.right - rightOffset - legendWidth
      : rightPercent != null
      ? chartRect.right - chartRect.width * rightPercent - legendWidth
      : horizontalPosition == 'center'
      ? chartRect.left + (chartRect.width - legendWidth) / 2
      : horizontalPosition == 'right'
      ? chartRect.right - legendWidth
      : chartRect.left + 8;
  final maxLeft = math.max(chartRect.left, chartRect.right - legendWidth);
  return left.clamp(chartRect.left, maxLeft).toDouble();
}

double _fortuneRawChartPositionedLegendTop(
  Rect chartRect,
  double legendHeight,
  double? topOffset,
  double? bottomOffset,
  double? topPercent,
  double? bottomPercent,
  String? verticalPosition,
) {
  final top = topOffset != null
      ? chartRect.top + topOffset
      : topPercent != null
      ? chartRect.top + chartRect.height * topPercent
      : bottomOffset != null
      ? chartRect.bottom - bottomOffset - legendHeight
      : bottomPercent != null
      ? chartRect.bottom - chartRect.height * bottomPercent - legendHeight
      : verticalPosition == 'middle'
      ? chartRect.top + (chartRect.height - legendHeight) / 2
      : verticalPosition == 'top'
      ? chartRect.top
      : chartRect.bottom - legendHeight;
  final maxTop = math.max(chartRect.top, chartRect.bottom - legendHeight);
  return top.clamp(chartRect.top, maxTop).toDouble();
}

void _fortuneDrawRawChartXAxisLabels(
  Canvas canvas,
  Rect chartRect,
  double axisBottom,
  List<String> labels,
  Color color,
  double fontSize,
  FontWeight fontWeight,
  FontStyle fontStyle,
  String? fontFamily,
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  Color? textBorderColor,
  double? textBorderWidth,
  Color? textShadowColor,
  double? textShadowBlur,
  double? textShadowOffsetX,
  double? textShadowOffsetY,
  bool showMinLabel,
  bool showMaxLabel,
  int? interval,
  double? opacity,
  bool hideOverlap,
  String? overflow,
  String? ellipsis,
  Map<String, FortuneRawChartRichTextStyle> richStyles,
  EdgeInsets? padding,
  double? borderRadius,
  double? boxWidth,
  double? boxHeight,
  double? lineHeight,
  String? align,
  String? verticalAlign,
  double rotationDegrees,
  double margin,
  bool inside,
  bool inverse,
  bool boundaryGap,
) {
  if (labels.isEmpty) {
    return;
  }
  final labelColor = _fortuneRawChartColorWithOpacity(color, opacity) ?? color;
  final labelBackgroundColor = _fortuneRawChartColorWithOpacity(
    backgroundColor,
    opacity,
  );
  final labelBorderColor = _fortuneRawChartColorWithOpacity(
    borderColor,
    opacity,
  );
  final labelTextBorderColor = _fortuneRawChartColorWithOpacity(
    textBorderColor,
    opacity,
  );
  final labelTextShadowColor = _fortuneRawChartColorWithOpacity(
    textShadowColor,
    opacity,
  );
  if (interval != null) {
    final step = math.max(1, interval + 1);
    final paintedLabelRects = <Rect>[];
    for (var index = 0; index < labels.length; index += 1) {
      final isMin = index == 0;
      final isMax = index == labels.length - 1;
      if ((isMin && !showMinLabel) || (isMax && !showMaxLabel)) {
        continue;
      }
      if (!isMin && !isMax && index % step != 0) {
        continue;
      }
      final text = labels[index];
      final painter = _fortuneRawChartLabelFillPainter(
        text: text,
        color: labelColor,
        fontSize: fontSize,
        fontWeight: fontWeight,
        fontStyle: fontStyle,
        fontFamily: fontFamily,
        backgroundColor: labelBackgroundColor,
        lineHeight: lineHeight,
        textShadowColor: labelTextShadowColor,
        textShadowBlur: textShadowBlur,
        textShadowOffsetX: textShadowOffsetX,
        textShadowOffsetY: textShadowOffsetY,
        overflow: overflow,
        ellipsis: ellipsis,
        richStyles: richStyles,
        maxWidth: _fortuneRawChartLabelMaxWidth(
          math.max(0, chartRect.width / 2 - 4),
          boxWidth,
          overflow,
        ),
      );
      final strokePainter = _fortuneRawChartLabelStrokePainter(
        text: text,
        fontSize: fontSize,
        fontWeight: fontWeight,
        fontStyle: fontStyle,
        fontFamily: fontFamily,
        lineHeight: lineHeight,
        textBorderColor: labelTextBorderColor,
        textBorderWidth: textBorderWidth,
        overflow: overflow,
        ellipsis: ellipsis,
        maxWidth: _fortuneRawChartLabelMaxWidth(
          math.max(0, chartRect.width / 2 - 4),
          boxWidth,
          overflow,
        ),
      );
      final labelTop = inside
          ? axisBottom - margin - painter.height
          : axisBottom + margin;
      final rawRatio = boundaryGap
          ? (index + 0.5) / labels.length
          : (labels.length == 1 ? 0.0 : index / (labels.length - 1));
      final ratio = inverse ? 1.0 - rawRatio : rawRatio;
      final centerX = chartRect.left + 8 + (chartRect.width - 12) * ratio;
      final offset = boundaryGap
          ? Offset(centerX - painter.width / 2, labelTop)
          : isMin
          ? (inverse
                ? Offset(chartRect.right - 4 - painter.width, labelTop)
                : Offset(chartRect.left + 8, labelTop))
          : isMax
          ? (inverse
                ? Offset(chartRect.left + 8, labelTop)
                : Offset(chartRect.right - 4 - painter.width, labelTop))
          : Offset(centerX - painter.width / 2, labelTop);
      final labelRect = _fortuneRawChartLabelPaintRect(
        painter: painter,
        offset: offset,
        padding: padding,
        boxWidth: boxWidth,
        boxHeight: boxHeight,
        rotationDegrees: rotationDegrees,
      );
      if (hideOverlap &&
          paintedLabelRects.any((painted) => painted.overlaps(labelRect))) {
        continue;
      }
      _fortunePaintRawChartLabel(
        canvas,
        painter,
        strokePainter,
        offset,
        labelBackgroundColor,
        labelBorderColor,
        borderWidth,
        padding,
        borderRadius,
        boxWidth,
        boxHeight,
        align,
        verticalAlign,
        rotationDegrees,
        borderType,
      );
      paintedLabelRects.add(labelRect);
    }
    return;
  }
  final first = showMinLabel ? labels.first : null;
  final last = labels.length == 1 ? null : labels.last;
  if (first != null) {
    final firstPainter = _fortuneRawChartLabelFillPainter(
      text: first,
      color: labelColor,
      fontSize: fontSize,
      fontWeight: fontWeight,
      fontStyle: fontStyle,
      fontFamily: fontFamily,
      backgroundColor: labelBackgroundColor,
      lineHeight: lineHeight,
      textShadowColor: labelTextShadowColor,
      textShadowBlur: textShadowBlur,
      textShadowOffsetX: textShadowOffsetX,
      textShadowOffsetY: textShadowOffsetY,
      overflow: overflow,
      ellipsis: ellipsis,
      richStyles: richStyles,
      maxWidth: _fortuneRawChartLabelMaxWidth(
        math.max(0, chartRect.width / 2 - 4),
        boxWidth,
        overflow,
      ),
    );
    final firstStrokePainter = _fortuneRawChartLabelStrokePainter(
      text: first,
      fontSize: fontSize,
      fontWeight: fontWeight,
      fontStyle: fontStyle,
      fontFamily: fontFamily,
      lineHeight: lineHeight,
      textBorderColor: labelTextBorderColor,
      textBorderWidth: textBorderWidth,
      overflow: overflow,
      ellipsis: ellipsis,
      maxWidth: _fortuneRawChartLabelMaxWidth(
        math.max(0, chartRect.width / 2 - 4),
        boxWidth,
        overflow,
      ),
    );
    final labelTop = inside
        ? axisBottom - margin - firstPainter.height
        : axisBottom + margin;
    final firstCenterRatio = boundaryGap
        ? (inverse ? 1.0 - (0.5 / labels.length) : 0.5 / labels.length)
        : null;
    final firstOffset = firstCenterRatio != null
        ? Offset(
            chartRect.left +
                8 +
                (chartRect.width - 12) * firstCenterRatio -
                firstPainter.width / 2,
            labelTop,
          )
        : inverse
        ? Offset(chartRect.right - 4 - firstPainter.width, labelTop)
        : Offset(chartRect.left + 8, labelTop);
    _fortunePaintRawChartLabel(
      canvas,
      firstPainter,
      firstStrokePainter,
      firstOffset,
      labelBackgroundColor,
      labelBorderColor,
      borderWidth,
      padding,
      borderRadius,
      boxWidth,
      boxHeight,
      align,
      verticalAlign,
      rotationDegrees,
      borderType,
    );
  }
  if (last == null || !showMaxLabel) {
    return;
  }
  final lastPainter = _fortuneRawChartLabelFillPainter(
    text: last,
    color: labelColor,
    fontSize: fontSize,
    fontWeight: fontWeight,
    fontStyle: fontStyle,
    fontFamily: fontFamily,
    backgroundColor: labelBackgroundColor,
    lineHeight: lineHeight,
    textShadowColor: labelTextShadowColor,
    textShadowBlur: textShadowBlur,
    textShadowOffsetX: textShadowOffsetX,
    textShadowOffsetY: textShadowOffsetY,
    overflow: overflow,
    ellipsis: ellipsis,
    richStyles: richStyles,
    maxWidth: _fortuneRawChartLabelMaxWidth(
      math.max(0, chartRect.width / 2 - 4),
      boxWidth,
      overflow,
    ),
  );
  final lastStrokePainter = _fortuneRawChartLabelStrokePainter(
    text: last,
    fontSize: fontSize,
    fontWeight: fontWeight,
    fontStyle: fontStyle,
    fontFamily: fontFamily,
    lineHeight: lineHeight,
    textBorderColor: labelTextBorderColor,
    textBorderWidth: textBorderWidth,
    overflow: overflow,
    ellipsis: ellipsis,
    maxWidth: _fortuneRawChartLabelMaxWidth(
      math.max(0, chartRect.width / 2 - 4),
      boxWidth,
      overflow,
    ),
  );
  final lastLabelTop = inside
      ? axisBottom - margin - lastPainter.height
      : axisBottom + margin;
  final lastCenterRatio = boundaryGap
      ? (inverse
            ? 1.0 - ((labels.length - 0.5) / labels.length)
            : (labels.length - 0.5) / labels.length)
      : null;
  final lastOffset = lastCenterRatio != null
      ? Offset(
          chartRect.left +
              8 +
              (chartRect.width - 12) * lastCenterRatio -
              lastPainter.width / 2,
          lastLabelTop,
        )
      : inverse
      ? Offset(chartRect.left + 8, lastLabelTop)
      : Offset(chartRect.right - 4 - lastPainter.width, lastLabelTop);
  _fortunePaintRawChartLabel(
    canvas,
    lastPainter,
    lastStrokePainter,
    lastOffset,
    labelBackgroundColor,
    labelBorderColor,
    borderWidth,
    padding,
    borderRadius,
    boxWidth,
    boxHeight,
    align,
    verticalAlign,
    rotationDegrees,
    borderType,
  );
}

void _fortuneDrawRawChartYAxisLabels(
  Canvas canvas,
  Rect chartRect,
  double axisLeft,
  double axisBottom,
  List<String> labels,
  Color color,
  double fontSize,
  FontWeight fontWeight,
  FontStyle fontStyle,
  String? fontFamily,
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  Color? textBorderColor,
  double? textBorderWidth,
  Color? textShadowColor,
  double? textShadowBlur,
  double? textShadowOffsetX,
  double? textShadowOffsetY,
  bool showMinLabel,
  bool showMaxLabel,
  int? interval,
  double? opacity,
  bool hideOverlap,
  String? overflow,
  String? ellipsis,
  Map<String, FortuneRawChartRichTextStyle> richStyles,
  EdgeInsets? padding,
  double? borderRadius,
  double? boxWidth,
  double? boxHeight,
  double? lineHeight,
  String? align,
  String? verticalAlign,
  double rotationDegrees,
  double? margin,
  bool inside,
  bool inverse,
  bool boundaryGap,
) {
  if (labels.isEmpty) {
    return;
  }
  final labelColor = _fortuneRawChartColorWithOpacity(color, opacity) ?? color;
  final labelBackgroundColor = _fortuneRawChartColorWithOpacity(
    backgroundColor,
    opacity,
  );
  final labelBorderColor = _fortuneRawChartColorWithOpacity(
    borderColor,
    opacity,
  );
  final labelTextBorderColor = _fortuneRawChartColorWithOpacity(
    textBorderColor,
    opacity,
  );
  final labelTextShadowColor = _fortuneRawChartColorWithOpacity(
    textShadowColor,
    opacity,
  );
  if (interval != null) {
    final step = math.max(1, interval + 1);
    final effectiveMargin = margin ?? 3;
    final paintedLabelRects = <Rect>[];
    for (var index = 0; index < labels.length; index += 1) {
      final isMax = index == 0;
      final isMin = index == labels.length - 1;
      if ((isMin && !showMinLabel) || (isMax && !showMaxLabel)) {
        continue;
      }
      if (!isMin && !isMax && index % step != 0) {
        continue;
      }
      final text = labels[index];
      final painter = _fortuneRawChartLabelFillPainter(
        text: text,
        color: labelColor,
        fontSize: fontSize,
        fontWeight: fontWeight,
        fontStyle: fontStyle,
        fontFamily: fontFamily,
        backgroundColor: labelBackgroundColor,
        lineHeight: lineHeight,
        textShadowColor: labelTextShadowColor,
        textShadowBlur: textShadowBlur,
        textShadowOffsetX: textShadowOffsetX,
        textShadowOffsetY: textShadowOffsetY,
        overflow: overflow,
        ellipsis: ellipsis,
        richStyles: richStyles,
        maxWidth: _fortuneRawChartLabelMaxWidth(
          math.max(22, fontSize * 3),
          boxWidth,
          overflow,
        ),
      );
      final strokePainter = _fortuneRawChartLabelStrokePainter(
        text: text,
        fontSize: fontSize,
        fontWeight: fontWeight,
        fontStyle: fontStyle,
        fontFamily: fontFamily,
        lineHeight: lineHeight,
        textBorderColor: labelTextBorderColor,
        textBorderWidth: textBorderWidth,
        overflow: overflow,
        ellipsis: ellipsis,
        maxWidth: _fortuneRawChartLabelMaxWidth(
          math.max(22, fontSize * 3),
          boxWidth,
          overflow,
        ),
      );
      final rawRatio = boundaryGap
          ? (index + 0.5) / labels.length
          : (labels.length == 1 ? 0.0 : index / (labels.length - 1));
      final ratio = inverse ? 1.0 - rawRatio : rawRatio;
      final y = chartRect.top + 14 + (axisBottom - chartRect.top - 22) * ratio;
      final offset = inside
          ? Offset(axisLeft + effectiveMargin, y)
          : (margin == null
                ? Offset(chartRect.left + 1, y)
                : Offset(axisLeft - margin - painter.width, y));
      final labelRect = _fortuneRawChartLabelPaintRect(
        painter: painter,
        offset: offset,
        padding: padding,
        boxWidth: boxWidth,
        boxHeight: boxHeight,
        rotationDegrees: rotationDegrees,
      );
      if (hideOverlap &&
          paintedLabelRects.any((painted) => painted.overlaps(labelRect))) {
        continue;
      }
      _fortunePaintRawChartLabel(
        canvas,
        painter,
        strokePainter,
        offset,
        labelBackgroundColor,
        labelBorderColor,
        borderWidth,
        padding,
        borderRadius,
        boxWidth,
        boxHeight,
        align,
        verticalAlign,
        rotationDegrees,
        borderType,
      );
      paintedLabelRects.add(labelRect);
    }
    return;
  }
  final top = showMaxLabel ? labels.first : null;
  final bottom = labels.length == 1 ? null : labels.last;
  if (top != null) {
    final topPainter = _fortuneRawChartLabelFillPainter(
      text: top,
      color: labelColor,
      fontSize: fontSize,
      fontWeight: fontWeight,
      fontStyle: fontStyle,
      fontFamily: fontFamily,
      backgroundColor: labelBackgroundColor,
      lineHeight: lineHeight,
      textShadowColor: labelTextShadowColor,
      textShadowBlur: textShadowBlur,
      textShadowOffsetX: textShadowOffsetX,
      textShadowOffsetY: textShadowOffsetY,
      overflow: overflow,
      ellipsis: ellipsis,
      richStyles: richStyles,
      maxWidth: _fortuneRawChartLabelMaxWidth(
        math.max(22, fontSize * 3),
        boxWidth,
        overflow,
      ),
    );
    final topStrokePainter = _fortuneRawChartLabelStrokePainter(
      text: top,
      fontSize: fontSize,
      fontWeight: fontWeight,
      fontStyle: fontStyle,
      fontFamily: fontFamily,
      lineHeight: lineHeight,
      textBorderColor: labelTextBorderColor,
      textBorderWidth: textBorderWidth,
      overflow: overflow,
      ellipsis: ellipsis,
      maxWidth: _fortuneRawChartLabelMaxWidth(
        math.max(22, fontSize * 3),
        boxWidth,
        overflow,
      ),
    );
    final effectiveMargin = margin ?? 3;
    final firstCenterRatio = boundaryGap
        ? (inverse ? 1.0 - (0.5 / labels.length) : 0.5 / labels.length)
        : null;
    final y = firstCenterRatio == null
        ? (inverse ? axisBottom - 8 : chartRect.top + 14)
        : chartRect.top +
              14 +
              (axisBottom - chartRect.top - 22) * firstCenterRatio;
    final topOffset = inside
        ? Offset(axisLeft + effectiveMargin, y)
        : (margin == null
              ? Offset(chartRect.left + 1, y)
              : Offset(axisLeft - margin - topPainter.width, y));
    _fortunePaintRawChartLabel(
      canvas,
      topPainter,
      topStrokePainter,
      topOffset,
      labelBackgroundColor,
      labelBorderColor,
      borderWidth,
      padding,
      borderRadius,
      boxWidth,
      boxHeight,
      align,
      verticalAlign,
      rotationDegrees,
      borderType,
    );
  }
  if (bottom == null || !showMinLabel) {
    return;
  }
  final bottomPainter = _fortuneRawChartLabelFillPainter(
    text: bottom,
    color: labelColor,
    fontSize: fontSize,
    fontWeight: fontWeight,
    fontStyle: fontStyle,
    fontFamily: fontFamily,
    backgroundColor: labelBackgroundColor,
    lineHeight: lineHeight,
    textShadowColor: labelTextShadowColor,
    textShadowBlur: textShadowBlur,
    textShadowOffsetX: textShadowOffsetX,
    textShadowOffsetY: textShadowOffsetY,
    overflow: overflow,
    ellipsis: ellipsis,
    richStyles: richStyles,
    maxWidth: _fortuneRawChartLabelMaxWidth(
      math.max(22, fontSize * 3),
      boxWidth,
      overflow,
    ),
  );
  final bottomStrokePainter = _fortuneRawChartLabelStrokePainter(
    text: bottom,
    fontSize: fontSize,
    fontWeight: fontWeight,
    fontStyle: fontStyle,
    fontFamily: fontFamily,
    lineHeight: lineHeight,
    textBorderColor: labelTextBorderColor,
    textBorderWidth: textBorderWidth,
    overflow: overflow,
    ellipsis: ellipsis,
    maxWidth: _fortuneRawChartLabelMaxWidth(
      math.max(22, fontSize * 3),
      boxWidth,
      overflow,
    ),
  );
  final effectiveMargin = margin ?? 3;
  final lastCenterRatio = boundaryGap
      ? (inverse
            ? 1.0 - ((labels.length - 0.5) / labels.length)
            : (labels.length - 0.5) / labels.length)
      : null;
  final y = lastCenterRatio == null
      ? (inverse ? chartRect.top + 14 : axisBottom - 8)
      : chartRect.top +
            14 +
            (axisBottom - chartRect.top - 22) * lastCenterRatio;
  final bottomOffset = inside
      ? Offset(axisLeft + effectiveMargin, y)
      : (margin == null
            ? Offset(chartRect.left + 1, y)
            : Offset(axisLeft - margin - bottomPainter.width, y));
  _fortunePaintRawChartLabel(
    canvas,
    bottomPainter,
    bottomStrokePainter,
    bottomOffset,
    labelBackgroundColor,
    labelBorderColor,
    borderWidth,
    padding,
    borderRadius,
    boxWidth,
    boxHeight,
    align,
    verticalAlign,
    rotationDegrees,
    borderType,
  );
}

Color? _fortuneRawChartColorWithOpacity(Color? color, double? opacity) {
  if (color == null || opacity == null || !opacity.isFinite) {
    return color;
  }
  final alpha = math.max(0, math.min(255, (color.a * 255.0 * opacity).round()));
  return color.withAlpha(alpha);
}

double _fortuneRawChartLabelMaxWidth(
  double defaultMaxWidth,
  double? boxWidth,
  String? overflow,
) {
  if (overflow == 'truncate' && boxWidth != null && boxWidth.isFinite) {
    return math.max(0, boxWidth);
  }
  return defaultMaxWidth;
}

Rect _fortuneRawChartLabelPaintRect({
  required TextPainter painter,
  required Offset offset,
  required EdgeInsets? padding,
  required double? boxWidth,
  required double? boxHeight,
  required double rotationDegrees,
}) {
  final labelPadding = padding ?? EdgeInsets.zero;
  final labelWidth = math.max(painter.width, boxWidth ?? 0);
  final labelHeight = math.max(painter.height, boxHeight ?? 0);
  final rect = Rect.fromLTRB(
    -labelPadding.left,
    -labelPadding.top,
    labelWidth + labelPadding.right,
    labelHeight + labelPadding.bottom,
  );
  if (rotationDegrees == 0) {
    return rect.shift(offset);
  }
  final radians = rotationDegrees * math.pi / 180;
  final cosValue = math.cos(radians);
  final sinValue = math.sin(radians);
  Offset rotate(Offset point) {
    return Offset(
      offset.dx + point.dx * cosValue - point.dy * sinValue,
      offset.dy + point.dx * sinValue + point.dy * cosValue,
    );
  }

  final points = [
    rotate(rect.topLeft),
    rotate(rect.topRight),
    rotate(rect.bottomLeft),
    rotate(rect.bottomRight),
  ];
  final left = points.map((point) => point.dx).reduce(math.min);
  final top = points.map((point) => point.dy).reduce(math.min);
  final right = points.map((point) => point.dx).reduce(math.max);
  final bottom = points.map((point) => point.dy).reduce(math.max);
  return Rect.fromLTRB(left, top, right, bottom);
}

double _fortuneRawChartLabelHeightRatio(double fontSize, double? lineHeight) {
  if (lineHeight == null || !lineHeight.isFinite || lineHeight <= 0) {
    return 1;
  }
  return lineHeight / math.max(1, fontSize);
}

List<Shadow>? _fortuneRawChartLabelShadows(
  Color? color,
  double? blurRadius,
  double? offsetX,
  double? offsetY,
) {
  if (color == null) {
    return null;
  }
  final blur = blurRadius != null && blurRadius.isFinite
      ? math.max(0.0, blurRadius)
      : 0.0;
  final dx = offsetX != null && offsetX.isFinite ? offsetX : 0.0;
  final dy = offsetY != null && offsetY.isFinite ? offsetY : 0.0;
  return [Shadow(color: color, blurRadius: blur, offset: Offset(dx, dy))];
}

TextPainter _fortuneRawChartLabelFillPainter({
  required String text,
  required Color color,
  required double fontSize,
  required FontWeight fontWeight,
  required FontStyle fontStyle,
  required String? fontFamily,
  required Color? backgroundColor,
  required double? lineHeight,
  required Color? textShadowColor,
  required double? textShadowBlur,
  required double? textShadowOffsetX,
  required double? textShadowOffsetY,
  required String? overflow,
  required String? ellipsis,
  required Map<String, FortuneRawChartRichTextStyle> richStyles,
  required double maxWidth,
  int? maxLines = 1,
}) {
  final baseStyle = TextStyle(
    color: color,
    fontSize: fontSize,
    fontWeight: fontWeight,
    fontStyle: fontStyle,
    fontFamily: fontFamily,
    backgroundColor: backgroundColor,
    height: _fortuneRawChartLabelHeightRatio(fontSize, lineHeight),
    shadows: _fortuneRawChartLabelShadows(
      textShadowColor,
      textShadowBlur,
      textShadowOffsetX,
      textShadowOffsetY,
    ),
  );
  return TextPainter(
    text: _fortuneRawChartLabelTextSpan(text, baseStyle, richStyles),
    ellipsis: overflow == 'truncate' ? ellipsis ?? '...' : null,
    maxLines: maxLines,
    textDirection: TextDirection.ltr,
  )..layout(maxWidth: maxWidth);
}

TextSpan _fortuneRawChartLabelTextSpan(
  String text,
  TextStyle baseStyle,
  Map<String, FortuneRawChartRichTextStyle> richStyles, {
  double? opacity,
  bool breakAll = false,
}) {
  final tokenPattern = RegExp(r'\{([^{}|]+)\|([^{}]*)\}');
  final spans = <TextSpan>[];
  var cursor = 0;
  for (final match in tokenPattern.allMatches(text)) {
    if (match.start > cursor) {
      final plainText = text.substring(cursor, match.start);
      spans.add(
        TextSpan(
          text: breakAll ? _fortuneRawChartBreakAllText(plainText) : plainText,
        ),
      );
    }
    final styleName = match.group(1) ?? '';
    final content = match.group(2) ?? '';
    spans.add(
      TextSpan(
        text: breakAll ? _fortuneRawChartBreakAllText(content) : content,
        style: _fortuneRawChartRichTextStyle(
          baseStyle,
          richStyles[styleName],
          opacity: opacity,
        ),
      ),
    );
    cursor = match.end;
  }
  if (cursor == 0) {
    return TextSpan(
      text: breakAll ? _fortuneRawChartBreakAllText(text) : text,
      style: baseStyle,
    );
  }
  if (cursor < text.length) {
    final tailText = text.substring(cursor);
    spans.add(
      TextSpan(
        text: breakAll ? _fortuneRawChartBreakAllText(tailText) : tailText,
      ),
    );
  }
  return TextSpan(style: baseStyle, children: spans);
}

TextStyle _fortuneRawChartRichTextStyle(
  TextStyle baseStyle,
  FortuneRawChartRichTextStyle? richStyle, {
  double? opacity,
}) {
  if (richStyle == null) {
    return baseStyle;
  }
  return baseStyle.copyWith(
    color:
        _fortuneRawChartColorWithOpacity(richStyle.color, opacity) ??
        richStyle.color ??
        baseStyle.color,
    fontSize: richStyle.fontSize ?? baseStyle.fontSize,
    fontWeight: richStyle.fontWeight ?? baseStyle.fontWeight,
    fontStyle: richStyle.fontStyle ?? baseStyle.fontStyle,
    fontFamily: richStyle.fontFamily ?? baseStyle.fontFamily,
    backgroundColor:
        _fortuneRawChartColorWithOpacity(richStyle.backgroundColor, opacity) ??
        richStyle.backgroundColor ??
        baseStyle.backgroundColor,
  );
}

TextPainter? _fortuneRawChartLabelStrokePainter({
  required String text,
  required double fontSize,
  required FontWeight fontWeight,
  required FontStyle fontStyle,
  required String? fontFamily,
  required double? lineHeight,
  required Color? textBorderColor,
  required double? textBorderWidth,
  required String? overflow,
  required String? ellipsis,
  required double maxWidth,
  int? maxLines = 1,
}) {
  if (textBorderColor == null ||
      textBorderWidth == null ||
      textBorderWidth <= 0) {
    return null;
  }
  return TextPainter(
    text: TextSpan(
      text: text,
      style: TextStyle(
        fontSize: fontSize,
        fontWeight: fontWeight,
        fontStyle: fontStyle,
        fontFamily: fontFamily,
        height: _fortuneRawChartLabelHeightRatio(fontSize, lineHeight),
        foreground: Paint()
          ..color = textBorderColor
          ..style = PaintingStyle.stroke
          ..strokeWidth = textBorderWidth,
      ),
    ),
    ellipsis: overflow == 'truncate' ? ellipsis ?? '...' : null,
    maxLines: maxLines,
    textDirection: TextDirection.ltr,
  )..layout(maxWidth: maxWidth);
}

void _fortunePaintRawChartLabel(
  Canvas canvas,
  TextPainter painter,
  TextPainter? strokePainter,
  Offset offset,
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  EdgeInsets? padding,
  double? borderRadius,
  double? boxWidth,
  double? boxHeight,
  String? align,
  String? verticalAlign,
  double rotationDegrees, [
  String? borderType,
]) {
  final labelPadding = padding ?? EdgeInsets.zero;
  final radius = Radius.circular(borderRadius ?? 0);
  final labelWidth = math.max(painter.width, boxWidth ?? 0);
  final labelHeight = math.max(painter.height, boxHeight ?? 0);
  final textDx = switch (align) {
    'center' => math.max(0.0, (labelWidth - painter.width) / 2),
    'right' => math.max(0.0, labelWidth - painter.width),
    _ => 0.0,
  };
  final textDy = switch (verticalAlign) {
    'middle' => math.max(0.0, (labelHeight - painter.height) / 2),
    'bottom' => math.max(0.0, labelHeight - painter.height),
    _ => 0.0,
  };
  if (rotationDegrees == 0) {
    final labelRect = Rect.fromLTRB(
      offset.dx - labelPadding.left,
      offset.dy - labelPadding.top,
      offset.dx + labelWidth + labelPadding.right,
      offset.dy + labelHeight + labelPadding.bottom,
    );
    if (backgroundColor != null) {
      if (borderRadius != null && borderRadius > 0) {
        canvas.drawRRect(
          RRect.fromRectAndRadius(labelRect, radius),
          Paint()..color = backgroundColor,
        );
      } else {
        canvas.drawRect(labelRect, Paint()..color = backgroundColor);
      }
    }
    if (borderColor != null && borderWidth != null && borderWidth > 0) {
      final strokePaint = Paint()
        ..color = borderColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = borderWidth;
      final strokeRect = labelRect.deflate(borderWidth / 2);
      if (borderRadius != null && borderRadius > 0) {
        final strokeRRect = RRect.fromRectAndRadius(strokeRect, radius);
        if (borderType == 'dashed' || borderType == 'dotted') {
          _fortuneDrawRawChartDashedRRect(
            canvas,
            strokeRRect,
            strokePaint,
            borderType!,
          );
        } else {
          canvas.drawRRect(strokeRRect, strokePaint);
        }
      } else if (borderType == 'dashed' || borderType == 'dotted') {
        _fortuneDrawRawChartDashedRect(
          canvas,
          strokeRect,
          strokePaint,
          borderType!,
        );
      } else {
        canvas.drawRect(strokeRect, strokePaint);
      }
    }
    final textOffset = offset + Offset(textDx, textDy);
    strokePainter?.paint(canvas, textOffset);
    painter.paint(canvas, textOffset);
    return;
  }
  canvas.save();
  canvas.translate(offset.dx, offset.dy);
  canvas.rotate(rotationDegrees * math.pi / 180);
  final labelRect = Rect.fromLTRB(
    -labelPadding.left,
    -labelPadding.top,
    labelWidth + labelPadding.right,
    labelHeight + labelPadding.bottom,
  );
  if (backgroundColor != null) {
    if (borderRadius != null && borderRadius > 0) {
      canvas.drawRRect(
        RRect.fromRectAndRadius(labelRect, radius),
        Paint()..color = backgroundColor,
      );
    } else {
      canvas.drawRect(labelRect, Paint()..color = backgroundColor);
    }
  }
  if (borderColor != null && borderWidth != null && borderWidth > 0) {
    final strokePaint = Paint()
      ..color = borderColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = borderWidth;
    final strokeRect = labelRect.deflate(borderWidth / 2);
    if (borderRadius != null && borderRadius > 0) {
      final strokeRRect = RRect.fromRectAndRadius(strokeRect, radius);
      if (borderType == 'dashed' || borderType == 'dotted') {
        _fortuneDrawRawChartDashedRRect(
          canvas,
          strokeRRect,
          strokePaint,
          borderType!,
        );
      } else {
        canvas.drawRRect(strokeRRect, strokePaint);
      }
    } else if (borderType == 'dashed' || borderType == 'dotted') {
      _fortuneDrawRawChartDashedRect(
        canvas,
        strokeRect,
        strokePaint,
        borderType!,
      );
    } else {
      canvas.drawRect(strokeRect, strokePaint);
    }
  }
  final textOffset = Offset(textDx, textDy);
  strokePainter?.paint(canvas, textOffset);
  painter.paint(canvas, textOffset);
  canvas.restore();
}

bool _fortuneRawChartTypeIsArea(String type) {
  return type == 'area' || type == 'areaspline' || type == 'linearea';
}

double _fortuneRawChartSingleBarWidth(FortuneRawChartSeries item, double step) {
  final explicitBarWidth = item.barWidth;
  if (explicitBarWidth != null) {
    return _fortuneRawChartConstrainBarWidth(
      item,
      step,
      1.0,
      item.barWidthIsRatio ? step * explicitBarWidth : explicitBarWidth,
    );
  }
  final categoryGap = item.barCategoryGap;
  if (categoryGap == null) {
    return _fortuneRawChartConstrainBarWidth(item, step, 2.0, step * 0.58);
  }
  final gapWidth = item.barCategoryGapIsRatio
      ? step * categoryGap.clamp(0.0, 0.98)
      : math.min(step * 0.98, categoryGap);
  return _fortuneRawChartConstrainBarWidth(item, step, 1.0, step - gapWidth);
}

double _fortuneRawChartGroupedBarWidth(
  FortuneRawChartSeries item,
  double step,
  int barSeriesCount,
  FortuneRawChartSeries groupedBarGap,
) {
  final explicitBarWidth = item.barWidth;
  if (explicitBarWidth != null) {
    return _fortuneRawChartConstrainBarWidth(
      item,
      step,
      1.0,
      item.barWidthIsRatio ? step * explicitBarWidth : explicitBarWidth,
    );
  }
  final categoryWidth = _fortuneRawChartSingleBarWidth(item, step);
  final gap = groupedBarGap.barGap ?? 0.0;
  if (groupedBarGap.barGapIsRatio) {
    final ratio = math.max(-0.98, gap);
    final divisor = barSeriesCount + (barSeriesCount - 1) * ratio;
    return _fortuneRawChartConstrainBarWidth(
      item,
      step,
      1.0,
      categoryWidth / math.max(0.02, divisor),
    );
  }
  final availableWidth = categoryWidth - (barSeriesCount - 1) * gap;
  return _fortuneRawChartConstrainBarWidth(
    item,
    step,
    1.0,
    availableWidth / barSeriesCount,
  );
}

double _fortuneRawChartConstrainBarWidth(
  FortuneRawChartSeries item,
  double step,
  double fallbackMinimum,
  double width,
) {
  var constrainedWidth = math.max(fallbackMinimum, width);
  final minWidth = item.barMinWidth;
  if (minWidth != null) {
    constrainedWidth = math.max(
      constrainedWidth,
      item.barMinWidthIsRatio ? step * minWidth : minWidth,
    );
  }
  final maxWidth = item.barMaxWidth;
  if (maxWidth != null) {
    constrainedWidth = math.min(
      constrainedWidth,
      item.barMaxWidthIsRatio ? step * maxWidth : maxWidth,
    );
  }
  return math.max(1.0, constrainedWidth);
}

double _fortuneRawChartBarGapWidth(
  FortuneRawChartSeries groupedBarGap,
  double barWidth,
) {
  final gap = groupedBarGap.barGap ?? 0.0;
  if (groupedBarGap.barGapIsRatio) {
    return barWidth * math.max(-0.98, gap);
  }
  return gap;
}

bool _fortuneRawChartTypeIsPie(String type) {
  return type == 'pie' || type == 'doughnut' || type == 'donut';
}

void _fortuneDrawRawChartPie(
  Canvas canvas,
  Rect plotRect,
  FortuneRawChartSeries series,
) {
  var values = series.values;
  var positiveValues = values.where((value) => value > 0).toList();
  if (positiveValues.isEmpty) {
    if (series.pieStillShowZeroSum == false || values.isEmpty) {
      return;
    }
    values = List<double>.filled(values.length, 1.0);
    positiveValues = values;
  }
  final side = math.min(plotRect.width, plotRect.height);
  if (side <= 0) {
    return;
  }
  final defaultRadius = side / 2;
  final outerRadius = _fortuneRawChartPieRadius(
    series.pieOuterRadius,
    series.pieOuterRadiusIsRatio,
    defaultRadius,
  ).clamp(1.0, defaultRadius).toDouble();
  final innerRadius =
      (series.pieInnerRadius == null
              ? 0.0
              : _fortuneRawChartPieRadius(
                  series.pieInnerRadius,
                  series.pieInnerRadiusIsRatio,
                  defaultRadius,
                ))
          .clamp(0.0, outerRadius - 0.5)
          .toDouble();
  final center = Offset(
    _fortuneRawChartPieCenterCoordinate(
      plotRect.left,
      plotRect.width,
      series.pieCenterX,
      series.pieCenterXIsRatio,
    ),
    _fortuneRawChartPieCenterCoordinate(
      plotRect.top,
      plotRect.height,
      series.pieCenterY,
      series.pieCenterYIsRatio,
    ),
  );
  final pieRect = Rect.fromCircle(center: center, radius: outerRadius);
  const colors = [
    Color(0xff0188fb),
    Color(0xffffb300),
    Color(0xff34a853),
    Color(0xffea4335),
    Color(0xff7e57c2),
  ];
  final total = positiveValues.fold<double>(0, (sum, value) => sum + value);
  final maxValue = positiveValues.fold<double>(0, math.max);
  final roseType = series.pieRoseType;
  final sweepFractions = _fortuneRawChartPieSweepFractions(
    values,
    total,
    roseType,
    series.pieMinAngleDegrees,
  );
  var startAngle = -(series.pieStartAngleDegrees ?? 90) * math.pi / 180;
  final direction = series.pieClockwise == false ? -1.0 : 1.0;
  final padAngle = _fortuneRawChartPiePadAngleRadians(
    series.piePadAngleDegrees,
    positiveValues.length,
  );
  final paintedLabelRects = <Rect>[];
  var positiveIndex = 0;
  for (var index = 0; index < values.length; index += 1) {
    final value = values[index];
    if (value <= 0) {
      continue;
    }
    final sweepAngle = sweepFractions[index] * math.pi * 2 * direction;
    final visibleSweepAngle =
        math.max(0.0, sweepAngle.abs() - padAngle) * direction;
    final visibleStartAngle = startAngle + padAngle / 2 * direction;
    final midAngle = startAngle + sweepAngle / 2;
    final selected = index < series.pointSelecteds.length
        ? series.pointSelecteds[index] == true
        : false;
    final selectedOffset = selected ? series.pieSelectedOffset ?? 10.0 : 0.0;
    final sliceCenter = selectedOffset <= 0
        ? center
        : Offset(
            center.dx + math.cos(midAngle) * selectedOffset,
            center.dy + math.sin(midAngle) * selectedOffset,
          );
    final sliceOuterRadius = _fortuneRawChartPieRoseOuterRadius(
      value,
      maxValue,
      innerRadius,
      outerRadius,
      roseType,
    );
    final slicePieRect = Rect.fromCircle(
      center: sliceCenter,
      radius: sliceOuterRadius,
    );
    final sliceInnerRect = Rect.fromCircle(
      center: sliceCenter,
      radius: innerRadius,
    );
    final pointColor = index < series.pointColors.length
        ? series.pointColors[index]
        : null;
    final pointOpacity = index < series.pointOpacities.length
        ? series.pointOpacities[index]
        : null;
    final pointBorderColor = index < series.pointBorderColors.length
        ? series.pointBorderColors[index]
        : null;
    final pointBorderWidth = index < series.pointBorderWidths.length
        ? series.pointBorderWidths[index]
        : null;
    final pointBorderType = index < series.pointBorderTypes.length
        ? series.pointBorderTypes[index]
        : null;
    final pointShadowColor = index < series.pointShadowColors.length
        ? series.pointShadowColors[index]
        : null;
    final pointShadowBlur = index < series.pointShadowBlurs.length
        ? series.pointShadowBlurs[index]
        : null;
    final pointShadowOffsetX = index < series.pointShadowOffsetXs.length
        ? series.pointShadowOffsetXs[index]
        : null;
    final pointShadowOffsetY = index < series.pointShadowOffsetYs.length
        ? series.pointShadowOffsetYs[index]
        : null;
    final sliceColor =
        pointColor ?? series.color ?? colors[positiveIndex % colors.length];
    final paint = Paint()
      ..color =
          _fortuneRawChartColorWithOpacity(
            sliceColor,
            pointOpacity ?? series.itemOpacity,
          ) ??
          sliceColor;
    final slicePath = _fortuneRawChartPieSlicePath(
      sliceCenter,
      slicePieRect,
      sliceInnerRect,
      sliceOuterRadius,
      innerRadius,
      visibleStartAngle,
      visibleSweepAngle,
    );
    final shadowColor = pointShadowColor ?? series.itemShadowColor;
    if (shadowColor != null) {
      final shadowPaint = Paint()..color = shadowColor;
      final shadowBlur = pointShadowBlur ?? series.itemShadowBlur;
      if (shadowBlur != null && shadowBlur > 0) {
        shadowPaint.maskFilter = ui.MaskFilter.blur(
          ui.BlurStyle.normal,
          shadowBlur,
        );
      }
      canvas.drawPath(
        slicePath.shift(
          Offset(
            pointShadowOffsetX ?? series.itemShadowOffsetX ?? 0,
            pointShadowOffsetY ?? series.itemShadowOffsetY ?? 0,
          ),
        ),
        shadowPaint,
      );
    }
    canvas.drawPath(slicePath, paint);
    final borderColor = pointBorderColor ?? series.itemBorderColor;
    final borderWidth = pointBorderWidth ?? series.itemBorderWidth;
    final borderType = pointBorderType ?? series.itemBorderType;
    if (borderColor != null && borderWidth != null) {
      final borderPaint = Paint()
        ..color = borderColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = borderWidth;
      if (borderType == 'dashed' || borderType == 'dotted') {
        _fortuneDrawRawChartDashedPath(
          canvas,
          slicePath,
          borderPaint,
          borderType!,
        );
      } else {
        canvas.drawPath(slicePath, borderPaint);
      }
    }
    final labelShow = index < series.pointLabelShows.length
        ? series.pointLabelShows[index] ?? series.labelShow
        : series.labelShow;
    final minShowLabelAngle = series.pieMinShowLabelAngleDegrees;
    final labelAngleDegrees = visibleSweepAngle.abs() * 180 / math.pi;
    final labelAngleVisible =
        minShowLabelAngle == null || labelAngleDegrees >= minShowLabelAngle;
    if (labelShow == true && labelAngleVisible) {
      _fortuneDrawRawChartSeriesLabel(
        canvas,
        sliceCenter,
        value,
        total > 0 ? value / total * 100 : null,
        visibleStartAngle,
        visibleSweepAngle,
        innerRadius,
        sliceOuterRadius,
        plotRect,
        series,
        index,
        paintedLabelRects:
            series.avoidLabelOverlap == true ||
                series.labelLayoutHideOverlap == true ||
                series.labelLayoutMoveOverlap != null
            ? paintedLabelRects
            : null,
      );
    }
    startAngle += sweepAngle;
    positiveIndex += 1;
  }
  canvas.drawOval(
    pieRect,
    Paint()
      ..color = const Color(0xff5f6368)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1,
  );
}

void _fortuneDrawRawChartDashedPath(
  Canvas canvas,
  Path path,
  Paint paint,
  String type,
) {
  final segmentLength = type == 'dotted'
      ? math.max(1.5, paint.strokeWidth)
      : math.max(4.0, paint.strokeWidth * 3);
  final gapLength = type == 'dotted'
      ? segmentLength * 1.6
      : math.max(3.0, paint.strokeWidth * 2);
  final patternLength = segmentLength + gapLength;
  if (patternLength <= 0) {
    canvas.drawPath(path, paint);
    return;
  }
  for (final metric in path.computeMetrics()) {
    var distance = 0.0;
    while (distance < metric.length) {
      final end = math.min(metric.length, distance + segmentLength);
      if (end > distance) {
        canvas.drawPath(metric.extractPath(distance, end), paint);
      }
      distance += patternLength;
    }
  }
}

List<double> _fortuneRawChartPieSweepFractions(
  List<double> values,
  double total,
  String? roseType,
  double? minAngleDegrees,
) {
  final positiveCount = values.where((value) => value > 0).length;
  if (positiveCount == 0 || total <= 0) {
    return List<double>.filled(values.length, 0);
  }
  final rawFractions = [
    for (final value in values)
      value <= 0
          ? 0.0
          : roseType == 'area'
          ? 1 / positiveCount
          : value / total,
  ];
  final minFraction = minAngleDegrees == null
      ? 0.0
      : (minAngleDegrees / 360).clamp(0.0, 1.0).toDouble();
  if (minFraction <= 0) {
    return rawFractions;
  }
  if (minFraction * positiveCount >= 1) {
    return [for (final value in values) value > 0 ? 1 / positiveCount : 0.0];
  }

  final adjusted = [
    for (final fraction in rawFractions)
      fraction <= 0 ? 0.0 : math.max(fraction, minFraction),
  ];
  final adjustedTotal = adjusted.fold<double>(0, (sum, value) => sum + value);
  final excess = adjustedTotal - 1;
  if (excess <= 0) {
    return adjusted;
  }
  final reducible = adjusted.fold<double>(
    0,
    (sum, value) => value > minFraction ? sum + value - minFraction : sum,
  );
  if (reducible <= 0) {
    return [for (final value in values) value > 0 ? 1 / positiveCount : 0.0];
  }
  return [
    for (final value in adjusted)
      value > minFraction
          ? value - excess * ((value - minFraction) / reducible)
          : value,
  ];
}

void _fortuneDrawRawChartDashedRRect(
  Canvas canvas,
  RRect rrect,
  Paint paint,
  String type,
) {
  _fortuneDrawRawChartDashedPath(canvas, Path()..addRRect(rrect), paint, type);
}

double _fortuneRawChartPiePadAngleRadians(
  double? padAngleDegrees,
  int positiveCount,
) {
  if (padAngleDegrees == null || positiveCount <= 1) {
    return 0;
  }
  final maxPadAngle = 360 / positiveCount;
  final angle = padAngleDegrees.clamp(0.0, maxPadAngle).toDouble();
  return angle * math.pi / 180;
}

Path _fortuneRawChartPieSlicePath(
  Offset center,
  Rect pieRect,
  Rect innerRect,
  double outerRadius,
  double innerRadius,
  double startAngle,
  double sweepAngle,
) {
  if (sweepAngle.abs() >= math.pi * 2 - 0.0001) {
    final path = Path()..addOval(pieRect);
    if (innerRadius > 0) {
      path
        ..fillType = PathFillType.evenOdd
        ..addOval(innerRect);
    }
    return path;
  }
  if (innerRadius <= 0) {
    final path = Path()..moveTo(center.dx, center.dy);
    _fortuneRawChartPieAppendArcPoints(
      path,
      center,
      outerRadius,
      startAngle,
      sweepAngle,
      moveToFirst: false,
    );
    return path..close();
  }
  final path = Path();
  _fortuneRawChartPieAppendArcPoints(
    path,
    center,
    outerRadius,
    startAngle,
    sweepAngle,
    moveToFirst: true,
  );
  _fortuneRawChartPieAppendArcPoints(
    path,
    center,
    innerRadius,
    startAngle + sweepAngle,
    -sweepAngle,
    moveToFirst: false,
  );
  return path..close();
}

double _fortuneRawChartPieRoseOuterRadius(
  double value,
  double maxValue,
  double innerRadius,
  double outerRadius,
  String? roseType,
) {
  if (roseType == null || maxValue <= 0) {
    return outerRadius;
  }
  final ratio = (value / maxValue).clamp(0.0, 1.0).toDouble();
  final scaledRatio = roseType == 'area' ? math.sqrt(ratio) : ratio;
  final visibleRatio = 0.25 + scaledRatio * 0.75;
  return innerRadius + (outerRadius - innerRadius) * visibleRatio;
}

double _fortuneRawChartPieLabelEdgeDistance(
  Rect plotRect,
  double? distance,
  bool isRatio,
) {
  final value = distance ?? 0;
  if (isRatio) {
    return (plotRect.width * value).clamp(0.0, plotRect.width / 2).toDouble();
  }
  return value.clamp(0.0, plotRect.width / 2).toDouble();
}

Offset _fortuneRawChartPieLabelBleedAdjustedCenter(
  Offset center,
  Rect plotRect,
  double labelBoxWidth,
  double? bleedMargin,
  bool enabled,
) {
  if (!enabled || bleedMargin == null || !bleedMargin.isFinite) {
    return center;
  }
  final margin = bleedMargin.clamp(0.0, plotRect.width / 2).toDouble();
  final halfWidth = labelBoxWidth / 2;
  final minX = plotRect.left + margin + halfWidth;
  final maxX = plotRect.right - margin - halfWidth;
  if (minX > maxX) {
    return Offset(plotRect.center.dx, center.dy);
  }
  return Offset(center.dx.clamp(minX, maxX).toDouble(), center.dy);
}

Offset _fortuneRawChartPieLabelLayoutAdjustedCenter(
  Offset center,
  Rect plotRect,
  FortuneRawChartSeries series,
) {
  return _fortuneRawChartSeriesLabelLayoutAdjustedCenter(
    center,
    plotRect,
    series,
  );
}

Offset _fortuneRawChartSeriesLabelLayoutAdjustedCenter(
  Offset center,
  Rect plotRect,
  FortuneRawChartSeries series,
) {
  final x = series.labelLayoutX == null
      ? center.dx
      : series.labelLayoutXIsRatio
      ? plotRect.left + plotRect.width * series.labelLayoutX!
      : plotRect.left + series.labelLayoutX!;
  final y = series.labelLayoutY == null
      ? center.dy
      : series.labelLayoutYIsRatio
      ? plotRect.top + plotRect.height * series.labelLayoutY!
      : plotRect.top + series.labelLayoutY!;
  return Offset(
    x + (series.labelLayoutDx ?? 0),
    y + (series.labelLayoutDy ?? 0),
  );
}

