      : series.labelBorderType;
  final labelBorderRadius = dataIndex < series.pointLabelBorderRadii.length
      ? series.pointLabelBorderRadii[dataIndex] ?? series.labelBorderRadius
      : series.labelBorderRadius;
  final labelPadding = dataIndex < series.pointLabelPaddings.length
      ? series.pointLabelPaddings[dataIndex] ?? series.labelPadding
      : series.labelPadding;
  final labelShadowColor = dataIndex < series.pointLabelShadowColors.length
