  final labelFontStyle = dataIndex < series.pointLabelFontStyles.length
      ? series.pointLabelFontStyles[dataIndex] ?? series.labelFontStyle
      : series.labelFontStyle;
  final labelFontFamily = dataIndex < series.pointLabelFontFamilies.length
      ? series.pointLabelFontFamilies[dataIndex] ?? series.labelFontFamily
      : series.labelFontFamily;
  final labelRotationDegrees =
      dataIndex < series.pointLabelRotationDegrees.length
      ? series.pointLabelRotationDegrees[dataIndex] ??
            series.labelRotationDegrees
