  final labelLineShadowOffsetY =
      dataIndex < series.pointLabelLineShadowOffsetYs.length
      ? series.pointLabelLineShadowOffsetYs[dataIndex] ??
            series.labelLineShadowOffsetY
      : series.labelLineShadowOffsetY;
  final effectiveLabelColor = _fortuneRawChartColorWithOpacity(
    labelColor,
    labelOpacity,
  );
  final effectiveLabelBackgroundColor = _fortuneRawChartColorWithOpacity(
    labelBackgroundColor,
    labelOpacity,
  );
  final effectiveLabelBorderColor = _fortuneRawChartColorWithOpacity(
    labelBorderColor,
    labelOpacity,
  );
  final effectiveLabelShadowColor = _fortuneRawChartColorWithOpacity(
    labelShadowColor,
    labelOpacity,
  );
  final effectiveLabelTextBorderColor = _fortuneRawChartColorWithOpacity(
    labelTextBorderColor,
    labelOpacity,
  );
  final effectiveLabelTextShadowColor = _fortuneRawChartColorWithOpacity(
    labelTextShadowColor,
    labelOpacity,
  );
  final textPainter = _fortuneRawChartSeriesLabelTextPainter(
    label,
    effectiveLabelColor,
    resolvedLabelFontSize,
    labelFontWeight,
    labelFontStyle,
    labelFontFamily,
    labelLineHeight,
    effectiveLabelTextShadowColor,
    labelTextShadowBlur,
    labelTextShadowOffsetX,
    labelTextShadowOffsetY,
    labelRichStyles,
    labelOpacity,
    resolvedLabelWidth,
    labelOverflow,
    labelEllipsis,
  );
  final position = labelPosition;
  final midAngle = startAngle + sweepAngle / 2;
  final outsideLabel =
      position != 'inside' && position != 'inner' && position != 'center';
  final outsideLabelLine = labelLineShow == true && outsideLabel;
  final effectiveLabelLineLength = labelLineLength ?? 10;
  final effectiveLabelLineLength2 = labelLineLength2;
  final effectiveLabelDistanceToLabelLine = labelDistanceToLabelLine ?? 2;
  final labelBoxWidth = math.max(textPainter.width, resolvedLabelWidth ?? 0);
  final labelRadius = position == 'center'
      ? 0.0
      : (position == 'inside' || position == 'inner')
      ? innerRadius + (outerRadius - innerRadius) * 0.58
      : outerRadius +
            (outsideLabelLine && effectiveLabelLineLength2 == null
                ? effectiveLabelLineLength + effectiveLabelDistanceToLabelLine
                : 8);
  final labelDirection = math.cos(midAngle) >= 0 ? 1.0 : -1.0;
  final edgeAligned = outsideLabel && labelAlignTo == 'edge';
  final edgeDistance = _fortuneRawChartPieLabelEdgeDistance(
    plotRect,
    labelEdgeDistance,
    labelEdgeDistanceIsRatio,
  );
  final labelLineEnd = outsideLabelLine
      ? edgeAligned
            ? Offset(
                (labelDirection > 0
                        ? plotRect.right - edgeDistance - labelBoxWidth
                        : plotRect.left + edgeDistance + labelBoxWidth) -
                    labelDirection * effectiveLabelDistanceToLabelLine,
                center.dy +
                    math.sin(midAngle) *
                        (outerRadius + effectiveLabelLineLength),
              )
            : effectiveLabelLineLength2 != null
            ? Offset(
                center.dx +
                    math.cos(midAngle) *
                        (outerRadius + effectiveLabelLineLength) +
                    labelDirection * effectiveLabelLineLength2,
                center.dy +
                    math.sin(midAngle) *
                        (outerRadius + effectiveLabelLineLength),
              )
            : null
      : null;
  final rawLabelCenter = Offset(
    edgeAligned
        ? labelLineEnd!.dx +
              labelDirection *
                  (labelBoxWidth / 2 + effectiveLabelDistanceToLabelLine)
        : labelLineEnd == null
        ? center.dx + math.cos(midAngle) * labelRadius
        : labelLineEnd.dx +
              labelDirection *
                  (textPainter.width / 2 + effectiveLabelDistanceToLabelLine),
    labelLineEnd == null
        ? center.dy + math.sin(midAngle) * labelRadius
        : labelLineEnd.dy,
  );
  final labelCenter = _fortuneRawChartPieLabelLayoutAdjustedCenter(
    _fortuneRawChartPieLabelBleedAdjustedCenter(
      rawLabelCenter,
      plotRect,
      labelBoxWidth,
      labelBleedMargin,
      outsideLabel && !edgeAligned,
    ),
    plotRect,
    series,
  );
  final moveOverlap = series.labelLayoutMoveOverlap;
  var adjustedLabelCenter = labelCenter;
  var textOffset =
      adjustedLabelCenter -
      Offset(textPainter.width / 2, textPainter.height / 2);
  if (paintedLabelRects != null) {
    var labelRect = _fortuneRawChartSeriesLabelPaintRect(
      textOffset,
      textPainter,
      labelPadding,
      resolvedLabelWidth,
      resolvedLabelHeight,
      resolvedLabelRotationDegrees,
    );
    var overlaps = paintedLabelRects.any(
      (painted) => painted.overlaps(labelRect),
    );
    if (overlaps && (moveOverlap == 'shiftX' || moveOverlap == 'shiftY')) {
      final shiftYDirection = adjustedLabelCenter.dy >= plotRect.center.dy
          ? 1.0
          : -1.0;
      final shiftXDirection = labelDirection == 0 ? 1.0 : labelDirection;
      final step = moveOverlap == 'shiftY'
          ? Offset(0, math.max(2.0, labelRect.height + 2) * shiftYDirection)
          : Offset(math.max(2.0, labelRect.width + 2) * shiftXDirection, 0);
      for (var attempt = 0; attempt < 20 && overlaps; attempt += 1) {
        adjustedLabelCenter += step;
        textOffset =
            adjustedLabelCenter -
            Offset(textPainter.width / 2, textPainter.height / 2);
        labelRect = _fortuneRawChartSeriesLabelPaintRect(
          textOffset,
          textPainter,
          labelPadding,
          resolvedLabelWidth,
          resolvedLabelHeight,
          resolvedLabelRotationDegrees,
        );
        overlaps = paintedLabelRects.any(
          (painted) => painted.overlaps(labelRect),
        );
      }
    }
    if (overlaps) {
      return;
    }
    paintedLabelRects.add(labelRect);
  }
  if (outsideLabelLine) {
    final labelLayoutLinePoints = series.labelLayoutLinePoints;
    final shadowPaint = labelLineShadowColor == null
        ? null
        : (Paint()
            ..color = _fortuneRawChartColorWithOpacity(
              labelLineShadowColor,
              labelLineOpacity,
            )!
            ..strokeWidth = labelLineWidth ?? 1
            ..strokeCap = _fortuneRawChartStrokeCap(labelLineCap)
            ..strokeJoin = _fortuneRawChartStrokeJoin(labelLineJoin)
            ..style = PaintingStyle.stroke
            ..maskFilter =
                (labelLineShadowBlur != null &&
                    labelLineShadowBlur.isFinite &&
                    labelLineShadowBlur > 0)
                ? MaskFilter.blur(BlurStyle.normal, labelLineShadowBlur)
                : null);
    if (shadowPaint != null && labelLineMiterLimit != null) {
      shadowPaint.strokeMiterLimit = labelLineMiterLimit;
    }
    final shadowOffset = Offset(
      labelLineShadowOffsetX ?? 0,
      labelLineShadowOffsetY ?? 0,
    );
    if (labelLayoutLinePoints.length >= 2) {
      final paint = Paint()
        ..color = _fortuneRawChartColorWithOpacity(
          labelLineColor ?? labelColor ?? const Color(0xff5f6368),
          labelLineOpacity,
        )!
        ..strokeWidth = labelLineWidth ?? 1
        ..strokeCap = _fortuneRawChartStrokeCap(labelLineCap)
        ..strokeJoin = _fortuneRawChartStrokeJoin(labelLineJoin)
        ..style = PaintingStyle.stroke;
      if (labelLineMiterLimit != null) {
        paint.strokeMiterLimit = labelLineMiterLimit;
      }
      final points = [
        for (final point in labelLayoutLinePoints) plotRect.topLeft + point,
      ];
      if (shadowPaint != null) {
        _fortuneDrawRawChartLabelLinePath(
          canvas,
          [for (final point in points) point + shadowOffset],
          shadowPaint,
          labelLineType,
        );
      }
      _fortuneDrawRawChartLabelLinePath(canvas, points, paint, labelLineType);
    } else {
      final edge = Offset(
        center.dx + math.cos(midAngle) * outerRadius,
        center.dy + math.sin(midAngle) * outerRadius,
      );
      final elbow = Offset(
        center.dx +
            math.cos(midAngle) * (outerRadius + effectiveLabelLineLength),
        center.dy +
            math.sin(midAngle) * (outerRadius + effectiveLabelLineLength),
      );
      final paint = Paint()
        ..color = _fortuneRawChartColorWithOpacity(
          labelLineColor ?? labelColor ?? const Color(0xff5f6368),
          labelLineOpacity,
        )!
        ..strokeWidth = labelLineWidth ?? 1
        ..strokeCap = _fortuneRawChartStrokeCap(labelLineCap)
        ..strokeJoin = _fortuneRawChartStrokeJoin(labelLineJoin)
        ..style = PaintingStyle.stroke;
      if (labelLineMiterLimit != null) {
        paint.strokeMiterLimit = labelLineMiterLimit;
      }
      final end = labelLineEnd ?? adjustedLabelCenter;
      if (shadowPaint != null) {
        if (labelLineSmooth == true) {
          _fortuneDrawRawChartSmoothLabelLine(
            canvas,
            edge + shadowOffset,
            elbow + shadowOffset,
            end + shadowOffset,
            shadowPaint,
            labelLineType,
          );
        } else {
          _fortuneDrawRawChartLabelLinePath(
            canvas,
            [edge + shadowOffset, elbow + shadowOffset, end + shadowOffset],
            shadowPaint,
            labelLineType,
          );
        }
      }
      if (labelLineSmooth == true) {
        _fortuneDrawRawChartSmoothLabelLine(
          canvas,
          edge,
          elbow,
          end,
          paint,
          labelLineType,
        );
      } else {
        _fortuneDrawRawChartLabelLinePath(
          canvas,
          [edge, elbow, end],
          paint,
          labelLineType,
        );
      }
    }
  }
  _fortunePaintRawChartSeriesLabelText(
    canvas,
    textOffset,
    textPainter,
    label,
    resolvedLabelFontSize ?? 10,
    labelFontWeight,
    labelFontStyle,
    labelFontFamily,
    effectiveLabelBackgroundColor,
    effectiveLabelBorderColor,
    labelBorderWidth,
    labelBorderType,
    labelBorderRadius,
    labelPadding,
    effectiveLabelShadowColor,
    labelShadowBlur,
    labelShadowOffsetX,
    labelShadowOffsetY,
    effectiveLabelTextBorderColor,
    labelTextBorderWidth,
    resolvedLabelRotationDegrees,
    resolvedLabelWidth,
    resolvedLabelHeight,
    resolvedLabelAlign,
    resolvedLabelVerticalAlign,
    labelOverflow,
    labelEllipsis,
  );
}

void _fortunePaintRawChartSeriesLabelText(
  Canvas canvas,
  Offset textOffset,
  TextPainter textPainter,
  String label,
  double fontSize,
  FontWeight? fontWeight,
  FontStyle? fontStyle,
  String? fontFamily,
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  double? borderRadius,
  EdgeInsets? padding,
  Color? shadowColor,
  double? shadowBlur,
  double? shadowOffsetX,
  double? shadowOffsetY,
  Color? textBorderColor,
  double? textBorderWidth,
  double? rotationDegrees,
  double? boxWidth,
  double? boxHeight,
  String? align,
  String? verticalAlign,
  String? overflow,
  String? ellipsis,
) {
  final rotation = rotationDegrees ?? 0;
  final labelWidth = math.max(textPainter.width, boxWidth ?? 0);
  final labelHeight = math.max(textPainter.height, boxHeight ?? 0);
  final textDx = switch (align) {
    'center' => math.max(0.0, (labelWidth - textPainter.width) / 2),
    'right' => math.max(0.0, labelWidth - textPainter.width),
    _ => 0.0,
  };
  final textDy = switch (verticalAlign) {
    'middle' => math.max(0.0, (labelHeight - textPainter.height) / 2),
    'bottom' => math.max(0.0, labelHeight - textPainter.height),
    _ => 0.0,
  };
  final labelCenter =
      textOffset + Offset(textPainter.width / 2, textPainter.height / 2);
  final boxOffset = labelCenter - Offset(labelWidth / 2, labelHeight / 2);
  final alignedTextOffset = boxOffset + Offset(textDx, textDy);
  if (rotation == 0) {
    _fortuneDrawRawChartLabelBackground(
      canvas,
      boxOffset,
      textPainter,
      backgroundColor,
      borderColor,
      borderWidth,
      borderType,
      borderRadius,
      padding,
      shadowColor,
      shadowBlur,
      shadowOffsetX,
      shadowOffsetY,
      labelWidth,
      labelHeight,
    );
    _fortuneDrawRawChartLabelTextStroke(
      canvas,
      alignedTextOffset,
      label,
      fontSize,
      fontWeight,
      fontStyle,
      fontFamily,
      textBorderColor,
      textBorderWidth,
      textPainter.width,
      overflow,
      ellipsis,
    );
    textPainter.paint(canvas, alignedTextOffset);
    return;
  }
  final localBoxOffset = Offset(-labelWidth / 2, -labelHeight / 2);
  final localTextOffset = localBoxOffset + Offset(textDx, textDy);
  canvas.save();
  canvas.translate(labelCenter.dx, labelCenter.dy);
  canvas.rotate(rotation * math.pi / 180);
  _fortuneDrawRawChartLabelBackground(
    canvas,
    localBoxOffset,
    textPainter,
    backgroundColor,
    borderColor,
    borderWidth,
    borderType,
    borderRadius,
    padding,
    shadowColor,
    shadowBlur,
    shadowOffsetX,
    shadowOffsetY,
    labelWidth,
    labelHeight,
  );
  _fortuneDrawRawChartLabelTextStroke(
    canvas,
    localTextOffset,
    label,
    fontSize,
    fontWeight,
    fontStyle,
    fontFamily,
    textBorderColor,
    textBorderWidth,
    textPainter.width,
    overflow,
    ellipsis,
  );
  textPainter.paint(canvas, localTextOffset);
  canvas.restore();
}

double _fortuneRawChartSeriesLabelMaxWidth(double? boxWidth, String? overflow) {
  if ((overflow == 'truncate' ||
          overflow == 'break' ||
          overflow == 'breakAll') &&
      boxWidth != null &&
      boxWidth.isFinite) {
    return math.max(0, boxWidth);
  }
  return double.infinity;
}

int? _fortuneRawChartSeriesLabelMaxLines(double? boxWidth, String? overflow) {
  if ((overflow == 'break' || overflow == 'breakAll') &&
      boxWidth != null &&
      boxWidth.isFinite) {
    return null;
  }
  return 1;
}

TextPainter _fortuneRawChartSeriesLabelTextPainter(
  String label,
  Color? labelColor,
  double? labelFontSize,
  FontWeight? labelFontWeight,
  FontStyle? labelFontStyle,
  String? labelFontFamily,
  double? labelLineHeight,
  Color? labelTextShadowColor,
  double? labelTextShadowBlur,
  double? labelTextShadowOffsetX,
  double? labelTextShadowOffsetY,
  Map<String, FortuneRawChartRichTextStyle> labelRichStyles,
  double? labelOpacity,
  double? labelWidth,
  String? labelOverflow,
  String? labelEllipsis,
) {
  final fontSize = labelFontSize ?? 10;
  return TextPainter(
    text: _fortuneRawChartLabelTextSpan(
      label,
      TextStyle(
        color: labelColor ?? const Color(0xff202124),
        fontSize: fontSize,
        fontWeight: labelFontWeight,
        fontStyle: labelFontStyle,
        fontFamily: labelFontFamily,
        height: labelLineHeight == null ? 1 : labelLineHeight / fontSize,
        shadows: _fortuneRawChartLabelShadows(
          labelTextShadowColor,
          labelTextShadowBlur,
          labelTextShadowOffsetX,
          labelTextShadowOffsetY,
        ),
      ),
      labelRichStyles,
      opacity: labelOpacity,
      breakAll: labelOverflow == 'breakAll',
    ),
    maxLines: _fortuneRawChartSeriesLabelMaxLines(labelWidth, labelOverflow),
    ellipsis: labelOverflow == 'truncate' ? labelEllipsis ?? '...' : null,
    textDirection: TextDirection.ltr,
  )..layout(
    maxWidth: _fortuneRawChartSeriesLabelMaxWidth(labelWidth, labelOverflow),
  );
}

String _fortuneRawChartBreakAllText(String text) {
  if (text.length < 2) {
    return text;
  }
  return text.split('').join('\u200B');
}

Rect _fortuneRawChartSeriesLabelPaintRect(
  Offset textOffset,
  TextPainter textPainter,
  EdgeInsets? padding,
  double? boxWidth,
  double? boxHeight,
  double? rotationDegrees,
) {
  final labelWidth = math.max(textPainter.width, boxWidth ?? 0);
  final labelHeight = math.max(textPainter.height, boxHeight ?? 0);
  final labelCenter =
      textOffset + Offset(textPainter.width / 2, textPainter.height / 2);
  final boxOffset = labelCenter - Offset(labelWidth / 2, labelHeight / 2);
  final effectivePadding = padding ?? const EdgeInsets.fromLTRB(2, 1, 2, 1);
  final rect = Rect.fromLTWH(
    boxOffset.dx - effectivePadding.left,
    boxOffset.dy - effectivePadding.top,
    labelWidth + effectivePadding.left + effectivePadding.right,
    labelHeight + effectivePadding.top + effectivePadding.bottom,
  );
  final rotation = rotationDegrees ?? 0;
  if (rotation == 0) {
    return rect;
  }
  final radians = rotation * math.pi / 180;
  final cosValue = math.cos(radians);
  final sinValue = math.sin(radians);
  Offset rotate(Offset point) {
    final local = point - labelCenter;
    return Offset(
      labelCenter.dx + local.dx * cosValue - local.dy * sinValue,
      labelCenter.dy + local.dx * sinValue + local.dy * cosValue,
    );
  }

  final points = [
    rotate(rect.topLeft),
    rotate(rect.topRight),
    rotate(rect.bottomLeft),
    rotate(rect.bottomRight),
  ];
  final left = points.map((point) => point.dx).reduce(math.min);
  final top = points.map((point) => point.dy).reduce(math.min);
  final right = points.map((point) => point.dx).reduce(math.max);
  final bottom = points.map((point) => point.dy).reduce(math.max);
  return Rect.fromLTRB(left, top, right, bottom);
}

void _fortuneDrawRawChartLabelTextStroke(
  Canvas canvas,
  Offset textOffset,
  String label,
  double fontSize,
  FontWeight? fontWeight,
  FontStyle? fontStyle,
  String? fontFamily,
  Color? textBorderColor,
  double? textBorderWidth,
  double maxWidth,
  String? overflow,
  String? ellipsis,
) {
  if (textBorderColor == null ||
      textBorderWidth == null ||
      textBorderWidth <= 0) {
    return;
  }
  final strokePainter = TextPainter(
    text: TextSpan(
      text: overflow == 'breakAll'
          ? _fortuneRawChartBreakAllText(label)
          : label,
      style: TextStyle(
        fontSize: fontSize,
        fontWeight: fontWeight,
        fontStyle: fontStyle,
        fontFamily: fontFamily,
        height: 1,
        foreground: Paint()
          ..color = textBorderColor
          ..style = PaintingStyle.stroke
          ..strokeWidth = textBorderWidth,
      ),
    ),
    ellipsis: overflow == 'truncate' ? ellipsis ?? '...' : null,
    maxLines: _fortuneRawChartSeriesLabelMaxLines(maxWidth, overflow),
    textDirection: TextDirection.ltr,
  )..layout(maxWidth: maxWidth);
  strokePainter.paint(canvas, textOffset);
}

void _fortuneDrawRawChartLabelBackground(
  Canvas canvas,
  Offset textOffset,
  TextPainter textPainter,
  Color? backgroundColor,
  Color? borderColor,
  double? borderWidth,
  String? borderType,
  double? borderRadius,
  EdgeInsets? padding,
  Color? shadowColor,
  double? shadowBlur,
  double? shadowOffsetX,
  double? shadowOffsetY,
  double? boxWidth,
  double? boxHeight,
) {
  final effectiveBorderWidth = borderWidth ?? 0;
  if (backgroundColor == null || backgroundColor.a == 0) {
    if (borderColor == null || effectiveBorderWidth <= 0) {
      return;
    }
  }
  final effectivePadding = padding ?? const EdgeInsets.fromLTRB(2, 1, 2, 1);
  final rect = Rect.fromLTWH(
    textOffset.dx - effectivePadding.left,
    textOffset.dy - effectivePadding.top,
    math.max(textPainter.width, boxWidth ?? 0) +
        effectivePadding.left +
        effectivePadding.right,
    math.max(textPainter.height, boxHeight ?? 0) +
        effectivePadding.top +
        effectivePadding.bottom,
  );
  final radius = borderRadius == null
      ? null
      : Radius.circular(math.max(0, borderRadius));
  final rrect = radius == null ? null : RRect.fromRectAndRadius(rect, radius);
  final effectiveShadowBlur = math.max(0.0, shadowBlur ?? 0);
  final effectiveShadowOffset = Offset(shadowOffsetX ?? 0, shadowOffsetY ?? 0);
  if (shadowColor != null &&
      (effectiveShadowBlur > 0 || effectiveShadowOffset != Offset.zero)) {
    final shadowPaint = Paint()..color = shadowColor;
    if (effectiveShadowBlur > 0) {
      shadowPaint.maskFilter = MaskFilter.blur(
        BlurStyle.normal,
        effectiveShadowBlur,
      );
    }
    final shadowRect = rect.shift(effectiveShadowOffset);
    if (rrect == null) {
      canvas.drawRect(shadowRect, shadowPaint);
    } else {
      canvas.drawRRect(
        RRect.fromRectAndRadius(shadowRect, radius!),
        shadowPaint,
      );
    }
  }
  if (backgroundColor != null && backgroundColor.a > 0) {
    final paint = Paint()..color = backgroundColor;
    if (rrect == null) {
      canvas.drawRect(rect, paint);
    } else {
      canvas.drawRRect(rrect, paint);
    }
  }
  if (borderColor == null || effectiveBorderWidth <= 0) {
    return;
  }
  final paint = Paint()
    ..color = borderColor
    ..style = PaintingStyle.stroke
    ..strokeWidth = effectiveBorderWidth;
  if (rrect == null) {
    final strokeRect = rect.deflate(effectiveBorderWidth / 2);
    if (borderType == 'dashed' || borderType == 'dotted') {
      _fortuneDrawRawChartDashedRect(canvas, strokeRect, paint, borderType!);
    } else {
      canvas.drawRect(strokeRect, paint);
    }
  } else {
    final strokeRRect = rrect.deflate(effectiveBorderWidth / 2);
    if (borderType == 'dashed' || borderType == 'dotted') {
      _fortuneDrawRawChartDashedRRect(canvas, strokeRRect, paint, borderType!);
    } else {
      canvas.drawRRect(strokeRRect, paint);
    }
  }
}

String _fortuneRawChartSeriesLabelText(
  FortuneRawChartSeries series,
  double value,
  int dataIndex, {
  double? percentage,
}) {
  final defaultValue = value == value.roundToDouble()
      ? value.round().toString()
      : value.toStringAsFixed(1);
  final formatter = dataIndex < series.pointLabelFormatters.length
      ? series.pointLabelFormatters[dataIndex] ?? series.labelFormatter
      : series.labelFormatter;
  if (formatter == null) {
    return defaultValue;
  }
  final name = dataIndex < series.pointNames.length
      ? series.pointNames[dataIndex]
      : null;
  final percentText = percentage == null
      ? defaultValue
      : percentage.toStringAsFixed(series.percentPrecision ?? 2);
  return formatter
      .replaceAll('{value}', defaultValue)
      .replaceAll('{c}', defaultValue)
      .replaceAll('{d}', percentText)
      .replaceAll('{percent}', percentText)
      .replaceAll('{b}', name ?? defaultValue)
      .replaceAll('{name}', name ?? defaultValue)
      .replaceAll('{a}', series.name ?? '');
}

String _fortuneRawChartSeriesEndLabelText(
  FortuneRawChartSeries series,
  double value,
  int dataIndex,
) {
  final defaultValue = value == value.roundToDouble()
      ? value.round().toString()
      : value.toStringAsFixed(1);
  final formatter = series.endLabelFormatter;
  if (formatter == null) {
    return defaultValue;
  }
  final name = dataIndex < series.pointNames.length
      ? series.pointNames[dataIndex]
      : null;
  return formatter
      .replaceAll('{value}', defaultValue)
      .replaceAll('{c}', defaultValue)
      .replaceAll('{b}', name ?? defaultValue)
      .replaceAll('{name}', name ?? defaultValue)
      .replaceAll('{a}', series.name ?? '');
}

void _fortuneRawChartPieAppendArcPoints(
  Path path,
  Offset center,
  double radius,
  double startAngle,
  double sweepAngle, {
  required bool moveToFirst,
}) {
  final segments = math.max(6, (sweepAngle.abs() / (math.pi / 18)).ceil());
  for (var index = 0; index <= segments; index += 1) {
    final angle = startAngle + sweepAngle * index / segments;
    final point = Offset(
      center.dx + math.cos(angle) * radius,
      center.dy + math.sin(angle) * radius,
    );
    if (index == 0 && moveToFirst) {
      path.moveTo(point.dx, point.dy);
    } else {
      path.lineTo(point.dx, point.dy);
    }
  }
}

double _fortuneRawChartPieRadius(
  double? value,
  bool isRatio,
  double defaultRadius,
) {
  if (value == null) {
    return defaultRadius;
  }
  return isRatio ? defaultRadius * value : value;
}

double _fortuneRawChartPieCenterCoordinate(
  double origin,
  double extent,
  double? value,
  bool isRatio,
) {
  if (value == null) {
    return origin + extent / 2;
  }
  return origin + (isRatio ? extent * value : value);
}

double? _fortuneRawShapeDouble(Object? raw) {
  if (raw is num) {
    return raw.toDouble();
  }
  if (raw == null) {
    return null;
  }
  return double.tryParse('$raw'.replaceAll(',', '').trim());
}

Color? _fortuneRawShapeColor(Object? raw) {
  if (raw is Color) {
    return raw;
  }
  if (raw is Map) {
    return _fortuneRawShapeColor(
      raw['color'] ?? raw['value'] ?? raw['rgb'] ?? raw['hex'],
    );
  }
  if (raw == null) {
    return null;
  }
  return FortuneSheetCodec.parseColor('$raw');
}

Color fortuneSparklineColor(Object? raw) {
  if (raw is! Map) {
    return const Color(0xff0188fb);
  }
  final lineStyle = raw['lineStyle'] ?? raw['linestyle'];
  final itemStyle = raw['itemStyle'] ?? raw['itemstyle'];
  final style = raw['style'];
  return _fortuneRawShapeColor(
        raw['color'] ??
            raw['lineColor'] ??
            raw['linecolor'] ??
            raw['strokeColor'] ??
            raw['strokecolor'] ??
            (lineStyle is Map ? lineStyle['color'] : null) ??
            (itemStyle is Map ? itemStyle['color'] : null) ??
            (style is Map ? style['color'] : null),
      ) ??
      const Color(0xff0188fb);
}

