double? fortuneSparklineNormalRangeValue(Object? raw, List<double> values) {
  if (raw is! Map || values.isEmpty) {
    return null;
  }
  final rawRange = raw['normalRange'] ?? raw['normalrange'];
  if (rawRange == null) {
    return null;
  }
  final text = '$rawRange'.trim().toLowerCase();
  if (text.isEmpty || text == '0' || text == 'false') {
    return null;
  }
  return switch (text) {
    'min' => values.reduce(math.min),
    'max' => values.reduce(math.max),
    'avg' || 'average' =>
      values.fold<double>(0, (sum, value) => sum + value) / values.length,
    'median' => _fortuneSparklineMedian(values),
    _ => double.tryParse(text),
  };
}

double _fortuneSparklineMedian(List<double> values) {
  final sorted = [...values]..sort();
  final middle = sorted.length ~/ 2;
  if (sorted.length.isOdd) {
    return sorted[middle];
  }
  return (sorted[middle - 1] + sorted[middle]) / 2;
}

