List<List<double>> fortuneSparklineStackGroups(
  Object? raw,
  List<double> fallback,
) {
  if (raw is! Map) {
    return [fallback];
  }
  final rawGroups = raw['stackGroups'] ?? raw['stackgroups'] ?? raw['groups'];
  if (rawGroups is! Iterable) {
    return [fallback];
  }
  final groups = <List<double>>[];
  for (final rawGroup in rawGroups) {
    if (rawGroup is! Iterable) {
      continue;
    }
    final group = <double>[];
    for (final item in rawGroup) {
      final value = _fortuneRawShapeDouble(item);
      if (value != null && value.isFinite) {
        group.add(value);
      }
    }
    if (group.isNotEmpty) {
      groups.add(group);
    }
  }
  return groups.isEmpty ? [fallback] : groups;
}

Color fortuneSparklineMappedBarColor(
  List<Object?> colorMap,
  double value,
  int index,
  Color fallback,
) {
  for (final item in colorMap) {
    final mapped = _fortuneSparklineRangeColor(item, value);
    if (mapped != null) {
      return mapped;
    }
  }
  if (index >= 0 && index < colorMap.length) {
    return _fortuneRawShapeColor(colorMap[index]) ?? fallback;
  }
  return fallback;
}

Color? _fortuneSparklineRangeColor(Object? raw, double value) {
  if (raw is! String || !raw.contains(':')) {
    return null;
  }
  final parts = raw.split(':').map((part) => part.trim()).toList();
  if (parts.length < 2) {
    return null;
  }
  final color = _fortuneRawShapeColor(parts.last);
  if (color == null) {
    return null;
  }
  final first = double.tryParse(parts.first);
  if (first == null) {
    return null;
  }
  if (parts.length == 2) {
    return value == first ? color : null;
  }
  final second = double.tryParse(parts[1]);
  if (second == null) {
    return null;
  }
  final lower = math.min(first, second);
  final upper = math.max(first, second);
  return value >= lower && value <= upper ? color : null;
}

int fortuneFormatSearchFirstVisibleIndex(double scrollOffset, int optionCount) {
  final visibleRows = fortuneFormatSearchVisibleRowCount();
  final maxIndex = math.max(0, optionCount - visibleRows);
  return (scrollOffset / fortuneFormatSearchListRowHeight).floor().clamp(
    0,
    maxIndex,
  );
}

double fortuneFormatSearchMaxScrollOffset(int optionCount) {
  final visibleRows = fortuneFormatSearchVisibleRowCount();
  return math.max(0, optionCount - visibleRows) *
      fortuneFormatSearchListRowHeight;
}

const Color fortuneToolbarHoverBackgroundColor = Color(0x0f000000);
const Color fortuneToolbarActiveBackgroundColor = Color(0x1f000000);
const Set<String> fortuneToolbarTextComboItems = {
  fortuneToolbarFormatCommand,
  fortuneToolbarFontPopupKey,
  fortuneToolbarFontSizePopupKey,
};
const Map<String, String> fortuneToolbarDefaultComboLabels = {
  fortuneToolbarFormatCommand: 'Automatic',
  fortuneToolbarFontPopupKey: 'Times New Roman',
  fortuneToolbarFontSizePopupKey: '10',
};

bool fortuneToolbarUsesTextCombos(double width) {
  return width >= fortuneToolbarTextComboMinWidth;
}

bool fortuneToolbarItemUsesTextCombo(String item, double width) {
  return fortuneToolbarTextComboItems.contains(item);
}

double fortuneToolbarItemAdvance(
  String item, {
  double width = double.infinity,
}) {
  final compact = width.isFinite && !fortuneToolbarUsesTextCombos(width);
  if (compact) {
    if (item == '|') {
      return fortuneToolbarCompactDividerAdvance;
    }
    if (fortuneToolbarItemUsesTextCombo(item, width)) {
      return switch (item) {
        fortuneToolbarFormatCommand => fortuneToolbarFormatComboAdvance,
        fortuneToolbarFontPopupKey => fortuneToolbarFontComboAdvance,
        fortuneToolbarFontSizePopupKey => fortuneToolbarFontSizeComboAdvance,
        _ => fortuneToolbarCompactButtonAdvance,
      };
    }
    if (FortuneToolbarIconPainter.comboIconIds.contains(item)) {
      return fortuneToolbarCompactIconComboAdvance;
    }
    return fortuneToolbarCompactButtonAdvance;
  }
  if (!fortuneToolbarItemUsesTextCombo(item, width) &&
      fortuneToolbarTextComboItems.contains(item)) {
    return fortuneToolbarIconComboAdvance;
  }
  if (!fortuneToolbarItemUsesTextCombo(item, width) &&
      FortuneToolbarIconPainter.comboIconIds.contains(item)) {
    return fortuneToolbarIconComboAdvance;
  }
  return switch (item) {
    '|' => fortuneToolbarDividerAdvance,
    fortuneToolbarFormatCommand => fortuneToolbarFormatComboAdvance,
    fortuneToolbarFontPopupKey => fortuneToolbarFontComboAdvance,
    fortuneToolbarFontSizePopupKey => fortuneToolbarFontSizeComboAdvance,
    _ => fortuneToolbarButtonAdvance,
  };
}

Rect fortuneToolbarItemRectAt(
  double x,
  String item, {
  double width = double.infinity,
}) {
  return Rect.fromLTWH(
    x + fortuneToolbarButtonInset,
    fortuneToolbarButtonTop,
    fortuneToolbarItemAdvance(item, width: width) -
        fortuneToolbarButtonInset * 2,
    fortuneToolbarButtonHeight,
  );
}

bool fortuneToolbarItemUsesCombo(String item, double width) {
  return fortuneToolbarItemUsesTextCombo(item, width) ||
      FortuneToolbarIconPainter.comboIconIds.contains(item);
}

Rect fortuneToolbarComboArrowRect(Rect rect) {
  return Rect.fromLTWH(
    rect.right - fortuneToolbarComboArrowAreaWidth,
    rect.top,
    fortuneToolbarComboArrowAreaWidth,
    rect.height,
  );
}

const double fortuneColumnHeaderMenuArrowSize = 12.0;
const double fortuneColumnHeaderMenuArrowRightInset = 6.0;
const double fortuneColumnHeaderMenuButtonPadding = 2.0;
const double fortuneColumnHeaderMenuButtonSize =
    fortuneColumnHeaderMenuArrowSize + fortuneColumnHeaderMenuButtonPadding * 2;
const double fortuneColumnHeaderMenuMinWidth =
    fortuneColumnHeaderMenuArrowSize + fortuneColumnHeaderMenuArrowRightInset;
const double fortuneColumnHeaderMenuMinHeight = 14.0;

Rect fortuneColumnHeaderMenuButtonRect(Rect headerRect) {
  return Rect.fromLTWH(
    headerRect.right -
        fortuneColumnHeaderMenuArrowRightInset -
        fortuneColumnHeaderMenuArrowSize -
        fortuneColumnHeaderMenuButtonPadding,
    headerRect.top +
        math.max(
          0,
          (headerRect.height - fortuneColumnHeaderMenuButtonSize) / 2,
        ),
    fortuneColumnHeaderMenuButtonSize,
    fortuneColumnHeaderMenuButtonSize,
  );
}

List<String> fortuneToolbarItemsWithCustom(
  List<String> items,
  List<FortuneCustomToolbarItem> customItems,
) {
  if (customItems.isEmpty) {
    return items;
  }
  final placedKeys = items.toSet();
  final unplacedItems = [
    for (final item in customItems)
      if (!placedKeys.contains(item.key)) item.key,
  ];
  if (unplacedItems.isEmpty) {
    return items;
  }
  return <String>[...unplacedItems, '|', ...items];
}

List<MapEntry<String, Rect>> fortuneVisibleToolbarItemRects(
  double width, {
  List<String> items = fortuneToolbarItems,
}) {
  final entries = <MapEntry<String, Rect>>[];
  var x = fortuneToolbarLeftPadding;
  final lastVisibleIndex = fortuneToolbarLastVisibleItemIndex(
    width,
    items: items,
  );
  for (var i = 0; i <= lastVisibleIndex; i += 1) {
    final item = items[i];
    final advance = fortuneToolbarItemAdvance(item, width: width);
    if (item == '|') {
      x += advance;
      continue;
    }
    entries.add(
      MapEntry(item, fortuneToolbarItemRectAt(x, item, width: width)),
    );
    x += advance;
  }
  if (fortuneToolbarHasMoreItem(width, items: items)) {
    entries.add(
      MapEntry(
        fortuneToolbarMorePopupKey,
        fortuneToolbarItemRectAt(x, fortuneToolbarMorePopupKey, width: width),
      ),
    );
  }
  return entries;
}

bool fortuneToolbarHasMoreItem(
  double width, {
  List<String> items = fortuneToolbarItems,
}) {
  return fortuneToolbarLastVisibleItemIndex(width, items: items) <
      items.length - 1;
}

List<String> fortuneToolbarOverflowItems(
  double width, {
  List<String> items = fortuneToolbarItems,
}) {
  final lastVisibleIndex = fortuneToolbarLastVisibleItemIndex(
    width,
    items: items,
  );
  if (lastVisibleIndex >= items.length - 1) {
    return const <String>[];
  }
  return items
      .skip(lastVisibleIndex + 1)
      .where((item) => item != '|')
      .toList(growable: false);
}

int fortuneToolbarLastVisibleItemIndex(
  double width, {
  List<String> items = fortuneToolbarItems,
}) {
  if (items.isEmpty) {
    return -1;
  }
  if (!width.isFinite) {
    return items.length - 1;
  }
  var total = fortuneToolbarLeftPadding;
  for (final item in items) {
    total += fortuneToolbarItemAdvance(item, width: width);
  }
  if (total <= width) {
    return items.length - 1;
  }
  final reservedMoreAdvance = fortuneToolbarItemAdvance(
    fortuneToolbarMorePopupKey,
    width: width,
  );
  final limit = math.max(
    fortuneToolbarLeftPadding,
    width - reservedMoreAdvance,
  );
  var x = fortuneToolbarLeftPadding;
  var lastVisible = -1;
  for (var i = 0; i < items.length; i += 1) {
    final item = items[i];
    final nextX = x + fortuneToolbarItemAdvance(item, width: width);
    if (nextX > limit) {
      return lastVisible;
    }
    x = nextX;
    if (item != '|') {
      lastVisible = i;
    }
  }
  return items.length - 1;
}

