String? fortuneToolbarFontFamilyFromCommand(String command) {
  if (!command.startsWith(fortuneToolbarFontFamilyCommandPrefix)) {
    return null;
  }
  final encoded = command.substring(
    fortuneToolbarFontFamilyCommandPrefix.length,
  );
  try {
    return Uri.decodeComponent(encoded);
  } on FormatException {
    return encoded;
  }
}

