bool fortuneSheetTabContextMenuItemIsSupported(String item) {
  return switch (item) {
    fortuneSheetTabDeleteCommand ||
    fortuneSheetTabCopyCommand ||
    fortuneSheetTabRenameCommand ||
    fortuneSheetTabColorCommand ||
    fortuneSheetTabHideCommand ||
    fortuneSheetTabMoveCommand ||
    fortuneSheetTabMoveLeftCommand ||
    fortuneSheetTabMoveRightCommand ||
    fortuneSheetTabShowHiddenCommand ||
    fortuneSheetTabFocusCommand ||
    '|' => true,
    _ => false,
  };
}

List<String> fortuneSheetTabRenderableMenuItems(List<String> items) {
  List<String>? filtered;
  for (var index = 0; index < items.length; index += 1) {
    final item = items[index];
    if (fortuneSheetTabContextMenuItemIsSupported(item)) {
      filtered?.add(item);
    } else {
      filtered ??= items.take(index).toList();
    }
  }
  return filtered ?? items;
}

bool fortuneContextMenuItemIsRenderedByUpstream(String item) {
  return switch (item) {
    fortuneContextCopyCommand ||
    fortuneContextPasteCommand ||
    fortuneContextInsertRowCommand ||
    fortuneContextInsertRowBelowCommand ||
    fortuneContextInsertColumnCommand ||
    fortuneContextInsertColumnRightCommand ||
    fortuneContextSplitCellColumnCommand ||
    fortuneContextDeleteRowCommand ||
    fortuneContextDeleteColumnCommand ||
    fortuneContextHideRowCommand ||
    fortuneContextShowHiddenRowCommand ||
    fortuneContextHideColumnCommand ||
    fortuneContextShowHiddenColumnCommand ||
    fortuneContextSetRowHeightCommand ||
    fortuneContextSetColumnWidthCommand ||
    fortuneContextSetLabelWidthCommand ||
    fortuneContextSetLabelHeightCommand ||
    fortuneContextShowGridLinesCommand ||
    fortuneContextShowRulerCommand ||
    fortuneContextInsertAutoIngredientTableCommand ||
    fortuneContextLoadCommonLabelCommand ||
    fortuneContextImportLabelFileCommand ||
    fortuneContextExportLabelFileCommand ||
    fortuneContextClearCommand ||
    fortuneContextClearSheetCommand ||
    fortuneContextSortCommand ||
    fortuneContextOrderAzCommand ||
    fortuneContextOrderZaCommand ||
    fortuneEditorContextSuperscriptCommand ||
    fortuneEditorContextSubscriptCommand ||
    fortuneEditorContextClearScriptCommand ||
    fortuneEditorContextLetterSpacingCommand ||
    fortuneEditorContextFontScaleCommand ||
    fortuneEditorContextLineHeightCommand ||
    fortuneToolbarFilterCommand ||
    fortuneToolbarImageCommand ||
    fortuneToolbarBarcodeCommand ||
    fortuneToolbarLinkCommand ||
    '|' => true,
    _ => false,
  };
}

List<String> fortuneContextRenderableMenuItems(List<String> items) {
  final expanded = <String>[];
  var didExpand = false;
  for (final item in items) {
    if (item == fortuneContextInsertRowCommand) {
      expanded.add(fortuneContextInsertRowCommand);
      expanded.add(fortuneContextInsertRowBelowCommand);
      didExpand = true;
    } else if (item == fortuneContextInsertColumnCommand) {
      expanded.add(fortuneContextInsertColumnCommand);
      expanded.add(fortuneContextInsertColumnRightCommand);
      expanded.add(fortuneContextSplitCellColumnCommand);
      didExpand = true;
    } else if (item == fortuneContextHideRowCommand) {
      expanded.add(fortuneContextHideRowCommand);
      expanded.add(fortuneContextShowHiddenRowCommand);
      didExpand = true;
    } else if (item == fortuneContextHideColumnCommand) {
      expanded.add(fortuneContextHideColumnCommand);
      expanded.add(fortuneContextShowHiddenColumnCommand);
      didExpand = true;
    } else {
      expanded.add(item);
    }
  }
  final source = didExpand ? expanded : items;
  List<String>? filtered;
  for (var index = 0; index < source.length; index += 1) {
    final item = source[index];
    if (fortuneContextMenuItemIsRenderedByUpstream(item)) {
      filtered?.add(item);
    } else {
      filtered ??= source.take(index).toList();
    }
  }
  return _fortuneContextMenuItemsWithClearSheet(filtered ?? source);
}

List<String> _fortuneContextMenuItemsWithClearSheet(List<String> items) {
  final result = <String>[];
  for (final item in items) {
    if (item == fortuneContextClearSheetCommand) {
      continue;
    }
    result.add(item);
    if (item == fortuneContextClearCommand) {
      result.add(fortuneContextClearSheetCommand);
    }
  }
  return result;
}

