Rect? fortuneFormulaBarInputRect(Size size, FortuneSettings settings) {
  if (!settings.showFormulaBar) {
    return null;
  }
  const inputLeft =
      fortuneFormulaBarNameBoxWidth +
      fortuneFormulaBarFxBoxWidth +
      fortuneFormulaBarInputLeftPadding;
  return Rect.fromLTWH(
    inputLeft,
    settings.effectiveToolbarHeight,
    math.max(0, size.width - inputLeft),
    settings.effectiveFormulaBarHeight - 1,
  );
}

Rect? fortuneFormulaBarNameBoxRect(Size size, FortuneSettings settings) {
  if (!settings.showFormulaBar) {
    return null;
  }
  return Rect.fromLTWH(
    0,
    settings.effectiveToolbarHeight,
    math.min(fortuneFormulaBarNameBoxWidth, size.width),
    settings.effectiveFormulaBarHeight - 1,
  );
}

Rect fortuneZoomControlRect(Size size, FortuneSettings settings) {
  final statTop = size.height - settings.statisticBarHeight;
  final top =
      statTop +
      math.max(0, settings.statisticBarHeight - fortuneZoomControlHeight) / 2;
  return Rect.fromLTWH(
    math.max(
      0,
      size.width - fortuneZoomControlWidth - fortuneZoomControlRightPadding,
    ),
    top,
    fortuneZoomControlWidth,
    fortuneZoomControlHeight,
  );
}

Rect fortuneBottomAddRowsButtonRect(Size size, FortuneSettings settings) {
  final zoomRect = fortuneZoomControlRect(size, settings);
  final maxWidth = math.max(
    0.0,
    zoomRect.left -
        fortuneBottomAddRowsButtonLeftPadding -
        fortuneBottomAddRowsButtonRightGap,
  );
  final width = math.min(fortuneBottomAddRowsButtonWidth, maxWidth);
  final statTop = size.height - settings.statisticBarHeight;
  final top =
      statTop +
      math.max(
            0,
            settings.statisticBarHeight - fortuneBottomAddRowsButtonHeight,
          ) /
          2;
  return Rect.fromLTWH(
    fortuneBottomAddRowsButtonLeftPadding,
    top,
    width,
    fortuneBottomAddRowsButtonHeight,
  );
}

Rect fortuneBottomBackTopButtonRect(Size size, FortuneSettings settings) {
  final addRowsRect = fortuneBottomAddRowsButtonRect(size, settings);
  final zoomRect = fortuneZoomControlRect(size, settings);
  final left = addRowsRect.right + fortuneBottomAddRowsButtonRightGap;
  final maxWidth = math.max(
    0.0,
    zoomRect.left - left - fortuneBottomAddRowsButtonRightGap,
  );
  final width = math.min(fortuneBottomBackTopButtonWidth, maxWidth);
  return Rect.fromLTWH(
    left,
    addRowsRect.top,
    width,
    fortuneBottomAddRowsButtonHeight,
  );
}

Rect fortuneZoomOutButtonRect(Size size, FortuneSettings settings) {
  final rect = fortuneZoomControlRect(size, settings);
  return Rect.fromLTWH(
    rect.left,
    rect.top,
    fortuneZoomButtonWidth,
    rect.height,
  );
}

Rect fortuneZoomRatioButtonRect(Size size, FortuneSettings settings) {
  final rect = fortuneZoomControlRect(size, settings);
  return Rect.fromLTWH(
    rect.left + fortuneZoomButtonWidth,
    rect.top,
    fortuneZoomRatioWidth,
