  );
}

Rect fortuneZoomInButtonRect(Size size, FortuneSettings settings) {
  final rect = fortuneZoomControlRect(size, settings);
  return Rect.fromLTWH(
    rect.left + fortuneZoomButtonWidth + fortuneZoomRatioWidth,
    rect.top,
    fortuneZoomButtonWidth,
    rect.height,
