}

Rect fortuneZoomPresetMenuRect(Size size, FortuneSettings settings) {
  final ratio = fortuneZoomRatioButtonRect(size, settings);
  final height =
      fortuneZoomPresetValues.length * fortuneZoomPresetRowHeight +
      fortuneZoomPresetMenuVerticalPadding * 2;
  return Rect.fromLTWH(
