bool fortuneEditorContextMenuItemHasInlineInput(String item) {
  return item == fortuneEditorContextLetterSpacingCommand ||
      item == fortuneEditorContextFontScaleCommand ||
      item == fortuneEditorContextLineHeightCommand;
}

Rect fortuneInlineMenuInputRect(
  Rect row, {
  required double left,
  required double width,
  double height = fortuneInlineMenuInputHeight,
}) {
  return Rect.fromLTWH(
    row.left + left,
    row.top + (row.height - height) / 2,
    width,
    height,
  );
}

bool fortuneContextMenuItemHasInlineInput(String item) {
  return fortuneContextMenuInlineInputCommands.contains(item);
}

Rect? fortuneContextMenuItemRect(
  Offset menuAt,
  String command, [
  List<String> items = fortuneContextMenuItems,
]) {
  final rect = fortuneContextMenuRect(menuAt, items);
  var y = rect.top + fortuneContextMenuContentTopPadding;
  for (final item in items) {
    if (item == '|') {
      y += fortuneContextMenuDividerHeight;
      continue;
    }
    if (item == command) {
      return Rect.fromLTWH(
        rect.left,
        y,
        rect.width,
        fortuneContextMenuRowHeight,
      );
    }
    y += fortuneContextMenuRowHeight;
  }
  return null;
}

Rect? fortuneContextMenuInlineInputRect(
  Offset menuAt,
  String command, [
  List<String> items = fortuneContextMenuItems,
]) {
  final row = fortuneContextMenuItemRect(menuAt, command, items);
  if (row == null || !fortuneContextMenuItemHasInlineInput(command)) {
    return null;
  }
  if (command == fortuneContextSetRowHeightCommand) {
    return fortuneInlineMenuInputRect(
      row,
      left: fortuneContextMenuRowHeightInputLeft,
      width: fortuneContextMenuAxisInputWidth,
    );
  }
  if (command == fortuneContextSetColumnWidthCommand) {
    return fortuneInlineMenuInputRect(
      row,
      left: fortuneContextMenuColumnWidthInputLeft,
      width: fortuneContextMenuAxisInputWidth,
    );
  }
  if (command == fortuneContextSetLabelWidthCommand ||
      command == fortuneContextSetLabelHeightCommand) {
    return fortuneInlineMenuInputRect(
      row,
      left: fortuneContextMenuRowHeightInputLeft,
      width: fortuneContextMenuAxisInputWidth,
    );
  }
  if (fortuneEditorContextMenuItemHasInlineInput(command)) {
    return fortuneInlineMenuInputRect(
      row,
      left: fortuneContextMenuEditorInputLeft,
      width: fortuneContextMenuEditorInputWidth,
    );
  }
  return fortuneInlineMenuInputRect(
    row,
    left: fortuneContextMenuInsertInputLeft,
    width: fortuneContextMenuInsertInputWidth,
  );
}

double fortuneContextMenuHeight([
  List<String> items = fortuneContextMenuItems,
]) {
  var height = fortuneContextMenuVerticalPadding;
  for (final item in items) {
    height += item == '|'
        ? fortuneContextMenuDividerHeight
        : fortuneContextMenuRowHeight;
  }
  return height;
}

double fortuneContextMenuWidthForItems([
  List<String> items = fortuneContextMenuItems,
]) {
  return identical(items, fortuneEditorContextMenuItems) ||
          _listEquals(items, fortuneEditorContextMenuItems)
      ? fortuneEditorContextMenuWidth
      : fortuneContextMenuWidth;
}

bool _listEquals(List<String> left, List<String> right) {
  if (left.length != right.length) {
    return false;
  }
  for (var index = 0; index < left.length; index += 1) {
    if (left[index] != right[index]) {
      return false;
    }
  }
  return true;
}

Rect fortuneContextMenuRect(
  Offset at, [
  List<String> items = fortuneContextMenuItems,
]) {
  return Rect.fromLTWH(
    at.dx,
    at.dy,
    fortuneContextMenuWidthForItems(items),
    fortuneContextMenuHeight(items),
  );
}

Offset fortuneContextMenuItemCenter(
  Offset menuAt,
  String command, [
  List<String> items = fortuneContextMenuItems,
]) {
  var y = fortuneContextMenuContentTopPadding;
  for (final item in items) {
    if (item == '|') {
      y += fortuneContextMenuDividerHeight;
      continue;
    }
    if (item == command) {
      return menuAt +
          Offset(
            fortuneContextMenuTestTapX,
            y + fortuneContextMenuRowHeight / 2,
          );
    }
    y += fortuneContextMenuRowHeight;
  }
  throw ArgumentError.value(command, 'command');
}

