double fortuneToolbarPopupWidthFor(
  String key, {
  Iterable<String>? options,
  double? viewportWidth,
}) {
  var width = switch (key) {
    fortuneToolbarFormatCommand => fortuneToolbarFormatPopupWidth,
    fortuneToolbarFontColorPopupKey ||
    fortuneToolbarBackgroundPopupKey => fortuneToolbarFontColorPopupWidth,
    fortuneToolbarFontPopupKey => fortuneToolbarFontPopupWidth,
    fortuneToolbarFontSizePopupKey => fortuneToolbarFontSizePopupWidth,
    fortuneToolbarBorderPopupKey => fortuneToolbarBorderPopupWidth,
    fortuneToolbarMergePopupKey => fortuneToolbarMergePopupWidth,
    fortuneToolbarHorizontalAlignPopupKey =>
      fortuneToolbarHorizontalAlignPopupWidth,
    fortuneToolbarVerticalAlignPopupKey =>
      fortuneToolbarVerticalAlignPopupWidth,
    fortuneToolbarTextWrapPopupKey => fortuneToolbarTextWrapPopupWidth,
    fortuneToolbarTextRotationPopupKey => fortuneToolbarTextRotationPopupWidth,
    fortuneToolbarQuickFormulaPopupKey => fortuneToolbarFormulaPopupWidth,
    fortuneToolbarCommentCommand => fortuneToolbarCommentPopupWidth,
    fortuneToolbarFilterCommand => fortuneToolbarFilterPopupWidth,
    fortuneToolbarLocationConditionCommand => fortuneToolbarLocationPopupWidth,
    fortuneToolbarMorePopupKey => fortuneToolbarMorePopupWidth,
    fortuneToolbarFreezePopupKey => fortuneToolbarPopupFreezeWidth,
    _ => fortuneToolbarPopupDefaultWidth,
  };
  if (key == fortuneToolbarFontPopupKey && options != null) {
    width = math.max(width, fortuneToolbarFontPopupWidthForOptions(options));
  }
  if (viewportWidth != null) {
    width = math.min(
      width,
      math.max(
        fortuneToolbarPopupViewportMargin,
        viewportWidth - fortuneToolbarPopupViewportMargin * 2,
      ),
    );
  }
  return width;
}

double fortuneToolbarFontPopupWidthForOptions(Iterable<String> options) {
  return fortuneToolbarFontPopupWidthForLabels(
    options.map(fortuneToolbarFontFamilyFromCommand).nonNulls,
  );
}

double fortuneToolbarFontPopupWidthForLabels(Iterable<String> labels) {
  var maxLabelWidth = 0.0;
  for (final label in labels) {
    final painter = TextPainter(
      text: TextSpan(text: label, style: const TextStyle(fontSize: 12)),
      textDirection: TextDirection.ltr,
    )..layout();
    maxLabelWidth = math.max(maxLabelWidth, painter.width);
  }
  return math.max(
    fortuneToolbarFontPopupWidth,
    (maxLabelWidth + fortuneToolbarFontPopupTextWidthPadding).ceilToDouble(),
  );
}

double fortuneToolbarPopupHeightFor(String key, List<String> options) {
  if (key == fortuneToolbarFontColorPopupKey ||
      key == fortuneToolbarBackgroundPopupKey) {
    return fortuneToolbarFontColorPopupHeight;
  }
  if (key == fortuneToolbarFormatCommand) {
    return fortuneToolbarFormatPopupVerticalPadding +
        options.fold<double>(
          0,
          (height, option) =>
              height +
              (option == '|'
                  ? fortuneToolbarFormatPopupDividerHeight
                  : fortuneToolbarFormatPopupRowHeight),
        );
  }
  return fortuneToolbarPopupVerticalPaddingFor(key) +
      options.fold<double>(
        0,
        (height, option) =>
            height +
            (option == '|'
                ? fortuneToolbarMenuDividerHeight
                : fortuneToolbarPopupRowHeightFor(key)),
      );
}

double fortuneToolbarPopupVisibleHeightFor({
  required double viewportHeight,
  required double naturalHeight,
}) {
  final maxByBottom = math.max(
    0.0,
    viewportHeight - fortuneToolbarPopupTop - fortuneToolbarPopupViewportMargin,
  );
  final maxByRatio = math.max(
    0.0,
    viewportHeight * fortuneToolbarPopupMaxHeightRatio,
  );
  final cappedHeight = math.min(maxByBottom, maxByRatio);
  if (naturalHeight <= cappedHeight) {
    return naturalHeight;
  }
  return math.max(
    0.0,
    math.min(
      naturalHeight,
      cappedHeight - fortuneToolbarPopupScrollIndicatorReservedHeight,
    ),
  );
}

Rect fortuneToolbarPopupContentViewportRect(
  Rect rect,
  double scrollOffset,
  double maxScrollOffset,
) {
  final indicatorContentInset =
      fortuneToolbarPopupScrollIndicatorInset +
      fortuneToolbarPopupScrollIndicatorHeight +
      fortuneToolbarPopupScrollIndicatorContentGap;
  final topInset = scrollOffset > 0.5 ? indicatorContentInset : 0.0;
  final bottomInset = scrollOffset < maxScrollOffset - 0.5
      ? indicatorContentInset
      : 0.0;
  final top = math.min(rect.bottom, rect.top + topInset);
  final bottom = math.max(top, rect.bottom - bottomInset);
  return Rect.fromLTRB(rect.left, top, rect.right, bottom);
}

