double fortuneToolbarPopupLeftFor({
  required String key,
  required Rect? itemRect,
  required double viewportWidth,
  required double popupWidth,
}) {
  final rawLeft = fortuneToolbarUsesFontPopupMetrics(key)
      ? itemRect?.left ?? fortuneToolbarPopupFallbackLeft
      : (itemRect?.left ?? fortuneToolbarPopupFallbackLeft) -
            fortuneToolbarPopupViewportMargin;
  return math.min(
    math.max(fortuneToolbarPopupViewportMargin, rawLeft),
    math.max(
      fortuneToolbarPopupViewportMargin,
      viewportWidth - popupWidth - fortuneToolbarPopupViewportMargin,
    ),
  );
}

