const String fortuneBarcodeObjectIdExtraKey = 'barcodeObjectId';
const String fortuneBarcodeBodyTopExtraKey = 'barcodeBodyTop';
const String fortuneBarcodeBodyHeightExtraKey = 'barcodeBodyHeight';
const String fortuneBarcodeBodyRatioExtraKey = 'barcodeBodyRatio';
const String fortuneBarcodeIdLabelPrintExcludedExtraKey =
  'barcodeIdLabelPrintExcluded';
const double fortuneBarcodeObjectIdLabelScale = 1.5;

class FortuneBarcodeObjectIdLabelMetrics {
  const FortuneBarcodeObjectIdLabelMetrics({
    required this.bodyRect,
    required this.boxRect,
    required this.fontSize,
    required this.textMaxWidth,
    required this.strokeWidth,
  });

  final Rect bodyRect;
  final Rect boxRect;
  final double fontSize;
  final double textMaxWidth;
  final double strokeWidth;
}

FortuneBarcodeObjectIdLabelMetrics? fortuneBarcodeObjectIdLabelMetrics(
  Rect rect,
  FortuneImage image, {
  TextDirection textDirection = TextDirection.ltr,
}) {
  if (image.extraFields['fortuneBarcode'] != true) {
    return null;
  }
  final objectId = image.extraFields[fortuneBarcodeObjectIdExtraKey]
      ?.toString()
      .trim();
  if (objectId == null || objectId.isEmpty) {
    return null;
  }
  final bodyTopRatio = _fortuneBarcodeBodyTopRatioForLabel(image);
  final bodyRatio = _fortuneBarcodeBodyRatioForLabel(image);
  final bodyTop = rect.top + rect.height * bodyTopRatio;
  final bodyHeight = math.min(
    math.max(1.0, rect.height * bodyRatio),
    math.max(1.0, rect.bottom - bodyTop),
  );
  final bodyRect = Rect.fromLTWH(
    rect.left,
    bodyTop,
    rect.width,
    bodyHeight,
  );
  if (bodyRect.width < 12 || bodyRect.height < 10) {
    return null;
  }
  const labelScale = fortuneBarcodeObjectIdLabelScale;
  final fontSize = math.max(
    4.0 * labelScale,
    math.min(18.0 * labelScale, bodyRect.height * 0.18 * labelScale),
  );
  final textMaxWidth = math.min(
    bodyRect.width,
    math.max(8.0 * labelScale, bodyRect.width * 0.7 * labelScale),
  );
  final textPainter = TextPainter(
    text: TextSpan(
      text: objectId,
      style: TextStyle(
        color: const Color(0xff000000),
        fontSize: fontSize,
        height: 1,
        fontWeight: FontWeight.w600,
      ),
    ),
    maxLines: 1,
    ellipsis: '...',
    textDirection: textDirection,
  )..layout(maxWidth: textMaxWidth);
  final horizontalPadding = math.max(
    2.0 * labelScale,
    bodyRect.width * 0.04 * labelScale,
  );
  final verticalPadding = math.max(
    1.0 * labelScale,
    bodyRect.height * 0.04 * labelScale,
  );
  final minBoxWidth = math.min(
    bodyRect.width,
    math.max(8.0 * labelScale, bodyRect.width * 0.18 * labelScale),
  );
  final minBoxHeight = math.min(
    bodyRect.height,
    math.max(5.0 * labelScale, bodyRect.height * 0.12 * labelScale),
  );
  final boxWidth = math.max(
    math.min(
      bodyRect.width * 0.46 * labelScale,
      textPainter.width + horizontalPadding * 2,
    ),
    minBoxWidth,
  );
  final boxHeight = math.max(
    math.min(
      bodyRect.height * 0.28 * labelScale,
      textPainter.height + verticalPadding * 2,
    ),
    minBoxHeight,
  );
  final box = Rect.fromCenter(
    center: bodyRect.center,
    width: math.min(bodyRect.width, boxWidth),
    height: math.min(bodyRect.height, boxHeight),
  );
  return FortuneBarcodeObjectIdLabelMetrics(
    bodyRect: bodyRect,
    boxRect: box,
    fontSize: fontSize,
    textMaxWidth: textMaxWidth,
    strokeWidth: math.max(0.5, box.height * 0.06),
  );
}

double _fortuneBarcodeBodyTopRatioForLabel(FortuneImage image) {
  final raw = image.extraFields[fortuneBarcodeBodyTopExtraKey];
  final originalHeight = _fortuneBarcodeOriginalHeightForBodyRatio(image);
  if (originalHeight <= 0) {
    return 0.0;
  }
  if (raw is num) {
    return (raw.toDouble() / originalHeight).clamp(0.0, 1.0);
  }
  if (raw is String) {
    final parsed = double.tryParse(raw.trim());
    if (parsed != null) {
      return (parsed / originalHeight).clamp(0.0, 1.0);
    }
  }
  return 0.0;
}

double _fortuneBarcodeBodyRatioForLabel(FortuneImage image) {
  final rawRatio = image.extraFields[fortuneBarcodeBodyRatioExtraKey];
  if (rawRatio is num) {
    return rawRatio.toDouble().clamp(0.0, 1.0);
  }
  if (rawRatio is String) {
    final parsed = double.tryParse(rawRatio.trim());
    if (parsed != null) {
      return parsed.clamp(0.0, 1.0);
    }
  }
  final bodyHeight = _fortuneBarcodeBodyHeightForLabel(image);
  final originalHeight = _fortuneBarcodeOriginalHeightForBodyRatio(image);
  if (originalHeight <= 0) {
    return 1.0;
  }
  return (bodyHeight / originalHeight).clamp(0.0, 1.0);
}

double _fortuneBarcodeBodyHeightForLabel(FortuneImage image) {
  final raw = image.extraFields[fortuneBarcodeBodyHeightExtraKey];
  if (raw is num) {
    return math.max(1.0, raw.toDouble());
  }
  if (raw is String) {
    return math.max(1.0, double.tryParse(raw.trim()) ?? image.height);
  }
  return image.height;
}

double _fortuneBarcodeOriginalHeightForBodyRatio(FortuneImage image) {
  final rawHeightMm = image.extraFields['heightMm'];
  if (rawHeightMm is num && rawHeightMm > 0) {
    return fortuneMillimetersToLogicalPixels(rawHeightMm);
  }
  if (rawHeightMm is String) {
    final parsed = double.tryParse(rawHeightMm.trim());
    if (parsed != null && parsed > 0) {
      return fortuneMillimetersToLogicalPixels(parsed);
    }
  }
  final rawOriginHeight = image.extraFields['originHeight'];
  if (rawOriginHeight is num && rawOriginHeight > 0) {
    return rawOriginHeight.toDouble();
  }
  if (rawOriginHeight is String) {
    final parsed = double.tryParse(rawOriginHeight.trim());
    if (parsed != null && parsed > 0) {
      return parsed;
    }
  }
  return image.height;
}

