  final maxWidth = size.width * .9;
  return math.min(maxWidth, fortuneLocationMessageDialogMinWidth);
}

Rect fortuneLocationMessageDialogRect(Size size, {String? message}) {
  final dialogWidth = fortuneLocationMessageDialogWidthFor(message, size);
  final left = ((size.width - dialogWidth) / 2).clamp(
    0.0,
    math.max(0.0, size.width - dialogWidth),
  );
  final top = ((size.height - fortuneLocationMessageDialogHeight) / 2).clamp(
    0.0,
    math.max(0.0, size.height - fortuneLocationMessageDialogHeight),
  );
  return Rect.fromLTWH(
    left.toDouble(),
    top.toDouble(),
    dialogWidth,
    fortuneLocationMessageDialogHeight,
  );
}

