class FortuneSearchResultView {
  const FortuneSearchResultView({
    required this.sheetIndex,
    required this.sheetName,
    required this.row,
    required this.column,
    required this.value,
  });

  final int sheetIndex;
  final String sheetName;
  final int row;
  final int column;
  final String value;

  String get cellPosition => '${_columnNameForIndex(column)}${row + 1}';
}

String _columnNameForIndex(int index) {
  var value = index + 1;
  final chars = <String>[];
  while (value > 0) {
    value -= 1;
    chars.insert(0, String.fromCharCode(65 + value % 26));
    value ~/= 26;
  }
  return chars.join();
}

Rect fortuneSearchDialogRect(
  Size size, {
  required bool hasResults,
  Offset offset = Offset.zero,
}) {
  final height =
      fortuneSearchDialogBaseHeight +
      (hasResults ? fortuneSearchDialogResultsHeight + 10 : 0);
  final baseLeft = ((size.width - fortuneSearchDialogInitialPositionWidth) / 2)
      .clamp(0.0, math.max(0.0, size.width - fortuneSearchDialogWidth));
  final baseTop = ((size.height - fortuneSearchDialogInitialPositionHeight) / 3)
      .clamp(0.0, math.max(0.0, size.height - height));
  return Rect.fromLTWH(
    (baseLeft + offset.dx).clamp(
      0.0,
      math.max(0.0, size.width - fortuneSearchDialogWidth),
    ),
    (baseTop + offset.dy).clamp(0.0, math.max(0.0, size.height - height)),
    fortuneSearchDialogWidth,
    height,
  );
}

