Rect fortuneSearchButtonRect(
  Rect rect,
  String command, {
  required bool replace,
}) {
  final labels = replace
      ? const ['replaceAll', 'replace', 'findAll', 'findNext']
      : const ['findAll', 'findNext'];
  var left = rect.left + fortuneSearchDialogPaddingX + 10;
  for (final label in labels) {
    final width = switch (label) {
      'replaceAll' => 91.0,
      'replace' => 75.0,
      'findAll' => 70.0,
      _ => 83.0,
    };
    if (label == command) {
      return Rect.fromLTWH(
        left,
        rect.top + fortuneSearchButtonTop,
        width,
        fortuneSearchButtonHeight,
      );
    }
    left += width + fortuneSearchButtonGap;
  }
  return Rect.zero;
}

