Rect fortuneHyperlinkCardRect(
  Size size,
  Rect cellRect, {
  bool allowEdit = true,
  bool showCopy = true,
}) {
  final buttonCount = allowEdit ? (showCopy ? 3 : 2) : 0;
  final dividerCount = allowEdit ? (showCopy ? 2 : 1) : 0;
  final width =
      fortuneHyperlinkCardContentWidth +
      fortuneHyperlinkCardButtonWidth * buttonCount +
      fortuneHyperlinkCardDividerWidth * dividerCount;
  var left = cellRect.left + fortuneHyperlinkCardLeftOffset;
  left = left.clamp(0.0, math.max(0.0, size.width - width)).toDouble();
  var top = cellRect.bottom;
  top = top
      .clamp(0.0, math.max(0.0, size.height - fortuneHyperlinkCardHeight))
      .toDouble();
  return Rect.fromLTWH(left, top, width, fortuneHyperlinkCardHeight);
}

