class FortuneFormulaSearchCategory {
  const FortuneFormulaSearchCategory(this.type, this.label);

  final int type;
  final String label;
}

class FortuneFormulaSearchFunction {
  const FortuneFormulaSearchFunction({
    required this.name,
    required this.categoryType,
    required this.description,
    this.parameterHint = '',
    this.detail = '',
    this.parameters = const <FortuneFormulaSearchParameter>[],
  });

  final String name;
  final int categoryType;
  final String description;
  final String parameterHint;
  final String detail;
  final List<FortuneFormulaSearchParameter> parameters;

  bool get hasDetailedHelp => detail.isNotEmpty || parameters.isNotEmpty;

  String get exampleSignature {
    if (parameters.isEmpty ||
        parameters.any((parameter) => parameter.example.isEmpty)) {
      return '';
    }
    return '$name(${parameters.map((parameter) => parameter.example).join(', ')})';
  }
}

class FortuneFormulaSearchParameter {
  const FortuneFormulaSearchParameter({
    required this.name,
    this.detail = '',
    this.example = '',
    this.optional = false,
    this.repeat = false,
  });

  final String name;
  final String detail;
  final String example;
  final bool optional;
  final bool repeat;

  String get displayName {
    final repeatedName = repeat ? '$name, ...' : name;
    return optional ? '[$repeatedName]' : repeatedName;
  }
}

