List<FortuneFormulaSearchFunction> fortuneFormulaSearchFilteredFunctions(
  String searchText,
  int categoryType,
) {
  final trimmed = searchText.trim();
  if (trimmed.isEmpty) {
    return fortuneFormulaSearchFunctions
        .where((function) => function.categoryType == categoryType)
        .toList(growable: false);
  }
  final upper = trimmed.toUpperCase();
  final onlyLetters = RegExp(r'^[A-Z]+$').hasMatch(upper);
  return fortuneFormulaSearchFunctions
      .where((function) {
        if (onlyLetters) {
          return function.name.contains(upper);
        }
        return function.description.toUpperCase().contains(upper);
      })
      .toList(growable: false);
}

FortuneFormulaSearchFunction? fortuneFormulaSearchSelectedFunction(
  String searchText,
  int categoryType,
  int selectedIndex,
) {
  final functions = fortuneFormulaSearchFilteredFunctions(
    searchText,
    categoryType,
  );
  if (functions.isEmpty) {
    return null;
  }
  return functions[selectedIndex.clamp(0, functions.length - 1)];
}

String? fortuneFormulaSearchSelectedParameterHint(
  String searchText,
  int categoryType,
  int selectedIndex,
) {
  final hint = fortuneFormulaSearchSelectedFunction(
    searchText,
    categoryType,
    selectedIndex,
  )?.parameterHint;
  if (hint == null || hint.isEmpty) {
    return null;
  }
  return hint;
}

String? fortuneFormulaSearchSelectedExampleSignature(
  String searchText,
  int categoryType,
  int selectedIndex,
) {
  final exampleSignature = fortuneFormulaSearchSelectedFunction(
    searchText,
    categoryType,
    selectedIndex,
  )?.exampleSignature;
  if (exampleSignature == null || exampleSignature.isEmpty) {
    return null;
  }
  return exampleSignature;
}

String? fortuneFormulaSearchSelectedDetailedDescription(
  String searchText,
  int categoryType,
  int selectedIndex,
) {
  final detail = fortuneFormulaSearchSelectedFunction(
    searchText,
    categoryType,
    selectedIndex,
  )?.detail;
  if (detail == null || detail.isEmpty) {
    return null;
  }
  return detail;
}

String fortuneFormulaSearchCategoryLabel(int categoryType) {
  return fortuneFormulaSearchCategories
      .firstWhere(
        (category) => category.type == categoryType,
        orElse: () => fortuneFormulaSearchCategories.first,
      )
      .label;
}

