int fortuneFormulaSearchVisibleRowCount() {
  return (fortuneFormulaSearchListHeight / fortuneFormulaSearchListRowHeight)
      .floor();
}

int fortuneFormulaSearchFirstVisibleIndex(
  double scrollOffset,
  int functionCount,
) {
  final visibleRows = fortuneFormulaSearchVisibleRowCount();
  final maxIndex = math.max(0, functionCount - visibleRows);
  return (scrollOffset / fortuneFormulaSearchListRowHeight).floor().clamp(
    0,
    maxIndex,
  );
}

double fortuneFormulaSearchMaxScrollOffset(int functionCount) {
  final visibleRows = fortuneFormulaSearchVisibleRowCount();
  return math.max(0, functionCount - visibleRows) *
      fortuneFormulaSearchListRowHeight;
}

const double fortuneFormulaSearchHintWidth = 300.0;
const double fortuneFormulaSearchHintHeight = 84.0;
const double fortuneFormulaSearchHintGap = 8.0;

Rect fortuneFormulaSearchHintRect(Rect dialogRect, Size size) {
  final rightLeft = dialogRect.right + fortuneFormulaSearchHintGap;
  final left = rightLeft + fortuneFormulaSearchHintWidth <= size.width
      ? rightLeft
      : math.max(
          0.0,
          dialogRect.left -
              fortuneFormulaSearchHintGap -
              fortuneFormulaSearchHintWidth,
        );
  final top = (dialogRect.top + fortuneFormulaSearchListTop).clamp(
    0.0,
    math.max(0.0, size.height - fortuneFormulaSearchHintHeight),
  );
  return Rect.fromLTWH(
    left.toDouble(),
    top.toDouble(),
    fortuneFormulaSearchHintWidth,
    fortuneFormulaSearchHintHeight,
  );
}

Rect fortuneFormulaSearchDialogRect(Size size) {
  final width = math.min(
    fortuneFormulaSearchDialogWidth,
    math.max(0.0, size.width - fortuneFormulaSearchDialogHorizontalMargin),
  );
  return Rect.fromLTWH(
    (size.width - width) / 2,
    math.max(
      fortuneFormulaSearchDialogMinTop,
      (size.height - fortuneFormulaSearchDialogHeight) / 2,
    ),
    width,
    fortuneFormulaSearchDialogHeight,
  );
}

