Rect fortuneToolbarFormatMoreSubmenuRect(
  Rect popupRect, {
  required double viewportWidth,
}) {
  final height =
      fortuneToolbarFormatMoreSubmenuRowHeight *
      fortuneToolbarFormatMoreSubmenuCommands.length;
  final desiredLeft = popupRect.right;
  final left =
      desiredLeft + fortuneToolbarFormatMoreSubmenuWidth > viewportWidth
      ? math.max(
          fortuneToolbarPopupViewportMargin,
          popupRect.left - fortuneToolbarFormatMoreSubmenuWidth,
        )
      : desiredLeft;
  return Rect.fromLTWH(
    left,
    popupRect.bottom - height - fortuneToolbarFormatPopupContentTopPadding,
    fortuneToolbarFormatMoreSubmenuWidth,
    height,
  );
}

