Rect fortuneConditionRuleDialogRect(Size size, double height) {
  final width = math.min(
    fortuneConditionRuleDialogMaxWidth,
    math.max(
      fortuneConditionRuleDialogMinWidth,
      size.width - fortuneConditionRuleDialogHorizontalMargin,
    ),
  );
  return Rect.fromLTWH(
    (size.width - width) / 2,
    math.max(fortuneConditionRuleDialogMinTop, (size.height - height) / 2),
    width,
    height,
  );
}

Rect fortuneConditionRuleCancelButtonRect(Rect dialogRect) {
  return Rect.fromLTWH(
    dialogRect.right -
        fortuneConditionRuleButtonRightPadding -
        fortuneConditionRuleCancelButtonWidth,
    dialogRect.bottom - fortuneConditionRuleButtonBottomOffset,
    fortuneConditionRuleCancelButtonWidth,
    fortuneConditionRuleButtonHeight,
  );
}

Rect fortuneConditionRuleCloseButtonRect(Rect dialogRect) {
  return Rect.fromLTWH(
    dialogRect.right -
        fortuneConditionRuleCloseRight -
        fortuneConditionRuleCloseSize,
    dialogRect.top + fortuneConditionRuleCloseTop,
    fortuneConditionRuleCloseSize,
    fortuneConditionRuleCloseSize,
  );
}

Rect fortuneConditionRuleConfirmButtonRect(Rect dialogRect) {
  final cancelRect = fortuneConditionRuleCancelButtonRect(dialogRect);
  return Rect.fromLTWH(
    cancelRect.left -
        fortuneConditionRuleButtonMarginRight -
        fortuneConditionRuleConfirmButtonWidth,
    cancelRect.top,
    fortuneConditionRuleConfirmButtonWidth,
    fortuneConditionRuleButtonHeight,
  );
}

