  @override
  void paint(Canvas canvas, Size size) {
    final settings = workbook.settings;
    canvas.drawRect(
      Offset.zero & size,
      Paint()..color = const Color(0xffffffff),
    );
    _drawToolbar(canvas, size, settings);
    _drawFormulaBar(canvas, size, settings);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final footerHeight =
        settings.effectiveSheetBarHeight + settings.statisticBarHeight;
    final rawSheetHeight = math.max(0.0, size.height - sheetTop - footerHeight);
    final sheetSize = Size(
      math.min(size.width, gridSize?.width ?? size.width),
      math.min(rawSheetHeight, gridSize?.height ?? rawSheetHeight),
    );
    canvas.save();
    canvas.translate(0, sheetTop);
    _drawSheet(canvas, sheetSize);
    canvas.restore();
    _drawSheetTabs(canvas, size, settings);
    _drawZoomControl(canvas, size, settings);
    _drawToolbarTooltip(canvas, size, settings);
    _drawDataVerificationHint(canvas, size);
    _drawDataVerificationDropdown(canvas, size);
    _drawFilterDropdown(canvas, size);
    if (!deferToolbarPopup) {
      _drawToolbarPopup(canvas, size);
    }
    if (!deferContextMenu) {
      _drawContextMenu(canvas);
    }
    _drawSheetTabMenu(canvas);
    _drawSheetList(canvas, size);
    _drawHiddenSheetList(canvas);
    _drawCustomSortDialog(canvas, size);
    _drawAxisSizeDialog(canvas, size);
    _drawImageInsertDialog(canvas, size);
    _drawBarcodeDialog(canvas, size);
    _drawHyperlinkCard(canvas, size);
    _drawHyperlinkDialog(canvas, size);
    _drawDataVerificationDialog(canvas, size);
    _drawSplitTextDialog(canvas, size);
    _drawLocationDialog(canvas, size);
    _drawLocationMessageDialog(canvas, size);
    _drawScreenshotDialog(canvas, size);
    _drawSearchDialog(canvas, size);
    _drawConditionRuleDialog(canvas, size);
    _drawFormulaSearchDialog(canvas, size);
    _drawFormulaSearchHint(canvas, size);
    _drawFormatSearchDialog(canvas, size);
  }

  void _drawToolbar(Canvas canvas, Size size, FortuneSettings settings) {
    if (!settings.showToolbar) {
      return;
    }
    final bg = Paint()..color = const Color(0xfffafafc);
    canvas.drawRect(
      Rect.fromLTWH(0, 0, size.width, settings.effectiveToolbarHeight),
      bg,
    );
    _line(
      canvas,
      Offset(0, settings.effectiveToolbarHeight - 0.5),
      Offset(size.width, settings.effectiveToolbarHeight - 0.5),
      const Color(0xffd4d4d4),
    );

    var x = fortuneToolbarLeftPadding;
    final toolbarItems = fortuneToolbarItemsWithCustom(
      settings.toolbarItems,
      settings.customToolbarItems,
    );
    final customToolbarItems = {
      for (final item in settings.customToolbarItems) item.key: item,
    };
    final lastVisibleIndex = fortuneToolbarLastVisibleItemIndex(
      size.width,
      items: toolbarItems,
    );
    for (var i = 0; i <= lastVisibleIndex; i += 1) {
      final item = toolbarItems[i];
      final advance = fortuneToolbarItemAdvance(item, width: size.width);
      if (item == '|') {
        canvas.drawRect(
          Rect.fromLTWH(x + 6, 10, 1, 20),
          Paint()..color = const Color(0xffe0e0e0),
        );
        x += advance;
        continue;
      }
      final rect = fortuneToolbarItemRectAt(x, item, width: size.width);
      final hovered = toolbarHoveredKey == item;
      final arrowHovered = toolbarHoveredComboArrowKey == item;
      final active = toolbarPopupKey == item;
      final customToolbarItem = customToolbarItems[item];
      final disabled = customToolbarItem?.disabled == true;
      if (!disabled && (hovered || active)) {
        canvas.drawRRect(
          RRect.fromRectAndRadius(rect, const Radius.circular(4)),
          Paint()
            ..color = active
                ? fortuneToolbarActiveBackgroundColor
                : fortuneToolbarHoverBackgroundColor,
        );
      }
      if (customToolbarItem != null) {
        _drawCustomToolbarItem(canvas, customToolbarItem, rect);
        x += advance;
        continue;
      }
      final useTextCombo = fortuneToolbarItemUsesTextCombo(item, size.width);
      final useIconCombo =
          FortuneToolbarIconPainter.comboIconIds.contains(item) &&
          !useTextCombo;
      if (arrowHovered && (useTextCombo || useIconCombo)) {
        canvas.drawRRect(
          RRect.fromRectAndRadius(
            fortuneToolbarComboArrowRect(rect),
            const Radius.circular(2),
          ),
          Paint()..color = fortuneToolbarHoverBackgroundColor,
        );
      }
      if (useTextCombo) {
        _drawToolbarTextCombo(canvas, item, rect);
      } else if (useIconCombo) {
        FortuneToolbarIconPainter.draw(
          canvas,
          item,
          Rect.fromLTWH(rect.left + 2, rect.top + 2, 24, 24),
          currency: settings.currency,
          accentColor: switch (item) {
            fortuneToolbarFontColorPopupKey => toolbarFontColorIndicator,
            fortuneToolbarBackgroundPopupKey => toolbarBackgroundColorIndicator,
            _ => null,
          },
        );
        FortuneToolbarIconPainter.draw(
          canvas,
          'combo-arrow',
          Rect.fromLTWH(
            rect.right - 12,
            rect.top + 2,
            fortuneToolbarComboArrowIconWidth,
            fortuneToolbarComboArrowIconHeight,
          ),
        );
      } else {
        _drawToolbarGlyph(canvas, item, rect.center);
      }
      x += advance;
    }
    if (lastVisibleIndex < toolbarItems.length - 1) {
      final rect = fortuneToolbarItemRectAt(
        x,
        fortuneToolbarMorePopupKey,
        width: size.width,
      );
      if (toolbarHoveredKey == fortuneToolbarMorePopupKey) {
        canvas.drawRRect(
          RRect.fromRectAndRadius(rect, const Radius.circular(4)),
          Paint()..color = fortuneToolbarHoverBackgroundColor,
        );
      }
      _drawToolbarGlyph(canvas, fortuneToolbarMorePopupKey, rect.center);
    }
  }

  void _drawCustomToolbarItem(
    Canvas canvas,
    FortuneCustomToolbarItem item,
    Rect rect,
  ) {
    final opacity = item.disabled ? 0.38 : 1.0;
    if (item.disabled) {
      canvas.saveLayer(rect, Paint()..color = Color.fromRGBO(255, 255, 255, opacity));
    }
    final iconName = item.iconName;
    if (iconName != null && iconName.isNotEmpty) {
      FortuneToolbarIconPainter.draw(
        canvas,
        iconName,
        Rect.fromCenter(center: rect.center, width: 24, height: 24),
      );
      if (item.disabled) {
        canvas.restore();
      }
      return;
    }
    final label = (item.children ?? item.tooltip ?? item.key).toString();
    _drawText(
      canvas,
      label,
      rect.deflate(2),
      fontSize: label.length <= 2 ? 12 : 10,
      color: item.disabled ? const Color(0xff9aa0a6) : const Color(0xff202124),
      align: TextAlign.center,
    );
