  void _drawToolbarFormatPopup(Canvas canvas, Rect rect, List<String> options) {
    var top = rect.top + fortuneToolbarFormatPopupContentTopPadding;
    for (var i = 0; i < options.length; i += 1) {
      final option = options[i];
      if (option == '|') {
        _drawToolbarMenuDivider(
          canvas,
          Rect.fromLTWH(
            rect.left,
            top,
            rect.width,
            fortuneToolbarFormatPopupDividerHeight,
          ),
        );
        top += fortuneToolbarFormatPopupDividerHeight;
        continue;
      }
      final row = Rect.fromLTWH(
        rect.left,
        top,
        rect.width,
        fortuneToolbarFormatPopupRowHeight,
      );
      if (i == toolbarPopupHoveredIndex ||
          (toolbarPopupHoveredIndex == null &&
              i == toolbarPopupSelectedIndex)) {
        _drawToolbarPopupHoverFill(canvas, row);
      }
      final label = _toolbarPopupLabel(option);
      final example = fortuneToolbarFormatExamples[option] ?? '';
      _drawText(
        canvas,
        label,
        Rect.fromLTWH(
          row.left + fortuneToolbarSelectOptionHorizontalPadding,
          row.top,
          row.width -
              fortuneToolbarSelectOptionHorizontalPadding * 2 -
              fortuneToolbarFormatPopupExampleWidth,
          row.height,
        ),
        fontSize: 12,
      );
      if (example.isNotEmpty) {
        _drawText(
          canvas,
          example,
          Rect.fromLTWH(
            row.right -
                fortuneToolbarSelectOptionHorizontalPadding -
                fortuneToolbarFormatPopupExampleWidth,
            row.top,
            fortuneToolbarFormatPopupExampleWidth,
            row.height,
          ),
          fontSize: 12,
          color: const Color(0xff80868b),
          align: TextAlign.right,
        );
      }
      if (option == fortuneToolbarFormatMoreCommand) {
        final arrowPath = Path()
          ..moveTo(row.right - 18, row.center.dy - 5)
          ..lineTo(row.right - 10, row.center.dy)
          ..lineTo(row.right - 18, row.center.dy + 5)
          ..close();
        canvas.drawPath(arrowPath, Paint()..color = const Color(0xff525c6f));
      }
      top += fortuneToolbarFormatPopupRowHeight;
    }
  }

