  String _toolbarPopupLabel(String key) {
    final fontFamily = fortuneToolbarFontFamilyFromCommand(key);
    if (fontFamily != null) {
      return fontFamily;
    }
    return switch (key) {
      fortuneToolbarLocationCommand => locale.locationConstant,
      fortuneToolbarLocationFormulaCommand => locale.locationFormula,
      fortuneToolbarLocationDateCommand => locale.locationDate,
      fortuneToolbarLocationNumberCommand => locale.locationDigital,
      fortuneToolbarLocationStringCommand => locale.locationString,
      fortuneToolbarLocationBoolCommand => locale.locationBool,
      fortuneToolbarLocationErrorCommand => locale.locationError,
      fortuneToolbarLocationNullCommand => locale.locationNull,
      fortuneToolbarLocationRowSpanCommand => locale.locationRowSpan,
      fortuneToolbarLocationColumnSpanCommand => locale.locationColumnSpan,
      _ => locale.toolbarPopupLabels[key] ?? key,
    };
  }

  String? _toolbarTooltipLabel(String key) {
    for (final item in workbook.settings.customToolbarItems) {
      if (item.key == key) {
        return item.tooltip;
      }
    }
    return switch (key) {
      fortuneToolbarLocationConditionCommand => locale.location,
      _ => locale.toolbarTooltipLabels[key],
    };
  }

  void _drawToolbarTooltip(Canvas canvas, Size size, FortuneSettings settings) {
    if (!settings.showToolbar) {
      return;
    }
    final key = toolbarHoveredKey;
    if (key == null || toolbarPopupKey != null) {
      return;
    }
    final label = _toolbarTooltipLabel(key);
    if (label == null || label.isEmpty) {
      return;
    }
    final itemRect = _toolbarItemRectFor(key, size.width);
    if (itemRect == null) {
      return;
    }
    final textPainter = TextPainter(
      text: const TextSpan(
        style: TextStyle(fontSize: fortuneToolbarTooltipFontSize),
      ),
      textDirection: textDirection,
      maxLines: 1,
    );
    textPainter.text = TextSpan(
      text: label,
      style: const TextStyle(
        color: fortuneToolbarTooltipTextColor,
        fontSize: fortuneToolbarTooltipFontSize,
        fontFamily: 'Arial',
      ),
    );
    textPainter.layout(maxWidth: fortuneToolbarTooltipMaxWidth);
    final width = math.min(
      fortuneToolbarTooltipMaxWidth,
      textPainter.width + fortuneToolbarTooltipPaddingHorizontal * 2,
    );
    final height =
        textPainter.height + fortuneToolbarTooltipPaddingVertical * 2;
    final left = (itemRect.center.dx - width / 2).clamp(
      4.0,
      size.width - width - 4.0,
    );
    final top = math.min(fortuneToolbarTooltipTop, size.height - height - 4);
    final rect = Rect.fromLTWH(left, top, width, height);
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        rect,
        const Radius.circular(fortuneToolbarTooltipBorderRadius),
      ),
      Paint()..color = fortuneToolbarTooltipBackgroundColor,
    );
    _drawText(
      canvas,
      label,
      Rect.fromLTWH(
        rect.left + fortuneToolbarTooltipPaddingHorizontal,
        rect.top + fortuneToolbarTooltipPaddingVertical,
        rect.width - fortuneToolbarTooltipPaddingHorizontal * 2,
        rect.height - fortuneToolbarTooltipPaddingVertical * 2,
      ),
      fontSize: fortuneToolbarTooltipFontSize,
      color: fortuneToolbarTooltipTextColor,
      align: TextAlign.center,
    );
  }

  void _drawFormulaBar(Canvas canvas, Size size, FortuneSettings settings) {
    if (!settings.showFormulaBar) {
      return;
    }
    final top = settings.effectiveToolbarHeight;
    final height = settings.effectiveFormulaBarHeight - 1;
    canvas.drawRect(
      Rect.fromLTWH(0, top, size.width, height),
      Paint()..color = const Color(0xffffffff),
    );
    _line(
      canvas,
      Offset(0, top + height + 0.5),
      Offset(size.width, top + height + 0.5),
      const Color(0xffd4d4d4),
    );
    _line(
      canvas,
      Offset(fortuneFormulaBarNameBoxWidth, top),
      Offset(fortuneFormulaBarNameBoxWidth, top + height),
      const Color(0xffd4d4d4),
    );
    _line(
      canvas,
      Offset(fortuneFormulaBarNameBoxWidth + fortuneFormulaBarFxBoxWidth, top),
      Offset(
        fortuneFormulaBarNameBoxWidth + fortuneFormulaBarFxBoxWidth,
        top + height,
      ),
      const Color(0xffe5e5e5),
    );

    final sheet = workbook.activeSheet;
    final coord = FortuneCellCoord(selection.row, selection.column);
    final cell = sheet.cells[sheet.mergeAnchorFor(coord)];
    final formulaText = cell?.formula ?? cell?.renderedText ?? '';
    _drawText(
      canvas,
      formulaBarNameBoxText,
      Rect.fromLTWH(0, top, fortuneFormulaBarNameBoxWidth, height),
      fontSize: 14,
      align: TextAlign.center,
    );
    _drawText(
      canvas,
      'fx',
      Rect.fromLTWH(
        fortuneFormulaBarNameBoxWidth,
        top,
        fortuneFormulaBarFxBoxWidth,
        height,
      ),
      fontSize: 13,
      italic: true,
      align: TextAlign.center,
      color: const Color(0xff666666),
    );
    _drawText(
      canvas,
      formulaText,
      fortuneFormulaBarInputRect(size, settings) ?? Rect.zero,
      fontSize: 14,
    );
  }

  String get formulaBarNameBoxText {
    final sheet = workbook.activeSheet;
    final rawSelection = sheet.selectionSave;
    if (rawSelection is List && rawSelection.isNotEmpty) {
      final lastSelection = rawSelection.last;
      if (lastSelection is Map) {
        final rowFocus = _intValue(lastSelection['row_focus']);
        final columnFocus = _intValue(lastSelection['column_focus']);
        if (rowFocus != null && columnFocus != null) {
          final focus = FortuneCellCoord(rowFocus, columnFocus);
          final merge = sheet.cells[focus]?.merge;
          if (merge != null &&
              (merge.rowSpan > 1 || merge.columnSpan > 1) &&
              merge.row == rowFocus &&
              merge.column == columnFocus) {
            return getRangetxt(workbook, sheet.id, <String, Object?>{
              'row': [rowFocus, rowFocus],
              'column': [columnFocus, columnFocus],
            });
          }
        }
        final rangeText = getRangetxt(workbook, sheet.id, lastSelection);
        if (rangeText.isNotEmpty) {
          return rangeText;
        }
      }
    }
    return getRangetxt(
      workbook,
      sheet.id,
      FortuneRange(
        rowStart: selection.rowStart,
        rowEnd: selection.normalizedRowEnd,
        columnStart: selection.columnStart,
        columnEnd: selection.normalizedColumnEnd,
      ),
    );
  }

  void _drawSheet(Canvas canvas, Size size) {
    final settings = workbook.settings;
    final metrics = workbook.activeSheet.metrics(settings);
    final showCellSelection = activeImageId == null;
    _drawHeaders(canvas, size, settings, metrics);
    _drawFrozenHeaders(canvas, size, settings, metrics);
    if (showCellSelection) {
      _drawHeaderSelections(canvas, size, settings, metrics);
    }
    _drawSheetRulersAndGuides(canvas, size, settings, metrics);
    _drawFreezeHandles(canvas, size, settings, metrics);
    settings.beforeRenderCellArea?.call(
      getFlowdata(workbook) ?? const <List<FortuneCell?>>[],
      canvas,
    );
    _drawSheetPrintAreaBoundary(canvas, size, settings, metrics);
    _drawCells(canvas, size, settings, metrics);
    _drawFrozenCells(canvas, size, settings, metrics);
    _drawSheetScrollbars(canvas, size, settings, metrics);
    _drawImages(canvas, size, settings);
    _drawRawShapeOverlays(canvas, size, settings);
    _drawVisibleComments(canvas, size, settings, metrics);
    if (showCellSelection) {
      _drawSelection(canvas, size, settings, metrics);
    }
    _drawPresences(canvas, size, settings, metrics);
    _drawFrozenGuides(canvas, size, settings, metrics);
    _drawSheetRulerTooltip(canvas, size);
    _drawFreezeDragLine(canvas, size);
    _drawResizeDragLine(canvas, size);
  }

  Rect? _sheetRulerDataRect(
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    if (!sheetRulerVisible ||
        fortuneSheetGridClientPhysicalSize(workbook.activeSheet) == null) {
      return null;
    }
    final viewport = _sheetViewportGeometry(size, settings, metrics);
    final width = viewport.dataWidth;
    final height = viewport.dataHeight;
    if (width <= 0 || height <= 0) {
      return null;
    }
    return Rect.fromLTWH(
      _sheetDataLeft(settings),
      _sheetDataTop(settings),
      width,
      height,
    );
  }

  void _drawSheetRulersAndGuides(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final physicalSize = fortuneSheetGridClientPhysicalSize(
      workbook.activeSheet,
    );
    final dataRect = _sheetRulerDataRect(size, settings, metrics);
    if (physicalSize == null || dataRect == null) {
      return;
    }
    final borderPaint = Paint()
      ..color = fortuneSheetRulerBorderColor
      ..strokeWidth = 1;
    final topRuler = Rect.fromLTWH(
      dataRect.left,
      0,
      dataRect.width,
      _sheetRulerTopInset(settings),
    );
    final leftRuler = Rect.fromLTWH(
      0,
      dataRect.top,
      _sheetRulerLeftInset(settings),
      dataRect.height,
    );
    final corner = Rect.fromLTWH(
      0.0,
      0.0,
      _sheetDataLeft(settings),
      _sheetDataTop(settings),
    );
    canvas.drawLine(topRuler.bottomLeft, topRuler.bottomRight, borderPaint);
    canvas.drawLine(leftRuler.topRight, leftRuler.bottomRight, borderPaint);
    canvas.drawLine(corner.bottomLeft, corner.bottomRight, borderPaint);
    canvas.drawLine(corner.topRight, corner.bottomRight, borderPaint);
    _drawSheetRulerCornerSizeLabel(canvas, corner);
    _drawHorizontalSheetRuler(
      canvas,
      topRuler,
      _sheetRulerLogicalPixelsToMillimeters(metrics.columnTotalWidth),
      scrollOffset.dx,
    );
    _drawVerticalSheetRuler(
      canvas,
      leftRuler,
      _sheetRulerLogicalPixelsToMillimeters(metrics.rowTotalHeight),
      scrollOffset.dy,
    );
    _drawSheetGuides(canvas, dataRect, metrics);
  }

  String? get sheetRulerCornerSizeLabel {
    if (!sheetRulerVisible) {
      return null;
    }
    final physicalSize = fortuneSheetGridClientPhysicalSize(
      workbook.activeSheet,
    );
    if (physicalSize == null) {
      return null;
    }
    return '${_formatSheetRulerSizeValue(physicalSize.widthMm)} x '
        '${_formatSheetRulerSizeValue(physicalSize.heightMm)}';
  }

  String? get sheetRulerCornerSubtitleLabel {
    if (!sheetRulerVisible) {
      return null;
    }
    if (workbook.activeSheet.extraFields['labelRtfImportSource'] == true) {
      return '(RTF 변환 적용)';
    }
    return null;
  }

  void _drawSheetRulerCornerSizeLabel(Canvas canvas, Rect rect) {
    final label = sheetRulerCornerSizeLabel;
    if (label == null || rect.width <= 8 || rect.height <= 8) {
      return;
    }
    final contentRect = rect.deflate(4);
    final subtitle = sheetRulerCornerSubtitleLabel;
    const labelHeight = 12.0;
    if (subtitle != null && contentRect.height >= 24) {
      const subtitleHeight = 11.0;
      const lineGap = -2.0;
      final blockHeight = labelHeight + lineGap + subtitleHeight;
      final top = contentRect.top + (contentRect.height - blockHeight) / 2;
      final topRect = Rect.fromLTWH(
        contentRect.left,
        top,
        contentRect.width,
        labelHeight,
      );
      final bottomRect = Rect.fromLTWH(
        contentRect.left,
        topRect.bottom + lineGap,
        contentRect.width,
        subtitleHeight,
      );
      _drawText(
        canvas,
        label,
        topRect,
        fontSize: 10,
        color: fortuneSheetRulerTickColor,
        align: TextAlign.center,
      );
      _drawText(
        canvas,
        subtitle,
        bottomRect,
        fontSize: 9,
        color: fortuneSheetRulerTickColor,
        align: TextAlign.center,
      );
      return;
    }
    final labelRect = Rect.fromLTWH(
      contentRect.left,
      contentRect.top + (contentRect.height - labelHeight) / 2,
      contentRect.width,
      labelHeight,
    );
    _drawText(
      canvas,
      label,
      labelRect,
      fontSize: 10,
      color: fortuneSheetRulerTickColor,
      align: TextAlign.center,
    );
  }

  String _formatSheetRulerSizeValue(num value) {
    final doubleValue = value.toDouble();
    final rounded = doubleValue.roundToDouble();
    if ((doubleValue - rounded).abs() < 0.001) {
      return rounded.toInt().toString();
    }
    final fixed = doubleValue.toStringAsFixed(2);
    return fixed
        .replaceFirst(RegExp(r'0+$'), '')
        .replaceFirst(RegExp(r'\.$'), '');
  }

  void _drawHorizontalSheetRuler(
    Canvas canvas,
    Rect rect,
    double widthMm,
    double scrollX,
  ) {
    final tickPaint = Paint()
      ..color = fortuneSheetRulerTickColor
      ..strokeWidth = 1;
    final maxMm = math.max(0.0, widthMm);
    canvas.save();
    canvas.clipRect(rect, doAntiAlias: false);
    for (
      var mm = 0.0;
      mm <= maxMm + 0.001;
      mm += fortuneSheetRulerMinorTickMm
    ) {
      final x = rect.left + _sheetRulerMillimetersToLogicalPixels(mm) - scrollX;
      if (x < rect.left - 0.5) {
        continue;
      }
      if (x > rect.right + 0.5) {
        break;
      }
      final major = mm % fortuneSheetRulerMajorTickMm == 0;
      final tickHeight = major
          ? math.min(15.0, rect.height)
          : math.min(7.0, rect.height);
      canvas.drawLine(
        Offset(x, rect.bottom - tickHeight),
        Offset(x, rect.bottom),
        tickPaint,
      );
      if (major) {
        _drawText(
          canvas,
          mm.toInt().toString(),
          Rect.fromLTWH(x + 3, rect.top, 34, math.max(1, rect.height - 4)),
          fontSize: 10,
          color: fortuneSheetRulerTickColor,
        );
      }
    }
    canvas.restore();
  }

  void _drawVerticalSheetRuler(
    Canvas canvas,
    Rect rect,
    double heightMm,
    double scrollY,
  ) {
    final tickPaint = Paint()
      ..color = fortuneSheetRulerTickColor
      ..strokeWidth = 1;
    final maxMm = math.max(0.0, heightMm);
    canvas.save();
    canvas.clipRect(rect, doAntiAlias: false);
    for (
      var mm = 0.0;
      mm <= maxMm + 0.001;
      mm += fortuneSheetRulerMinorTickMm
    ) {
      final y = rect.top + _sheetRulerMillimetersToLogicalPixels(mm) - scrollY;
      if (y < rect.top - 0.5) {
        continue;
      }
      if (y > rect.bottom + 0.5) {
        break;
      }
      final major = mm % fortuneSheetRulerMajorTickMm == 0;
      final tickWidth = major
          ? math.min(16.0, rect.width)
          : math.min(8.0, rect.width);
      canvas.drawLine(
        Offset(rect.right - tickWidth, y),
        Offset(rect.right, y),
        tickPaint,
      );
      if (major) {
        _drawText(
          canvas,
          mm.toInt().toString(),
          Rect.fromLTWH(rect.left, y + 2, math.max(1, rect.width - 2), 14),
          fontSize: 10,
          color: fortuneSheetRulerTickColor,
          align: TextAlign.center,
        );
      }
    }
    canvas.restore();
  }

  void _drawSheetGuides(
    Canvas canvas,
    Rect dataRect,
    FortuneSheetMetrics metrics,
  ) {
    final guides = <FortuneSheetGuide>[];
    for (final guide in sheetRulerGuides) {
      if (sheetRulerDraggingGuide?.index == guide.index) {
        continue;
      }
      guides.add(guide);
    }
    final draggingGuide = sheetRulerDraggingGuide;
    if (draggingGuide != null) {
      guides.add(draggingGuide);
    }
    final linePaint = Paint()
      ..color = fortuneSheetGuideColor
      ..strokeWidth = 1.0;
    final selectedPaint = Paint()
      ..color = fortuneSheetGuideSelectionColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1;
    canvas.save();
    canvas.clipRect(dataRect, doAntiAlias: false);
    final maxWidthMm = _sheetRulerLogicalPixelsToMillimeters(
      metrics.columnTotalWidth,
    );
    final maxHeightMm = _sheetRulerLogicalPixelsToMillimeters(
      metrics.rowTotalHeight,
    );
    for (final guide in guides) {
      final selected =
          guide.index == sheetRulerSelectedGuideIndex && draggingGuide == null;
      final hovered = guide.index == sheetRulerHoveredGuideIndex;
      final paint = Paint()
        ..color = hovered || selected
            ? fortuneSheetGuideSelectionColor
            : fortuneSheetGuideColor
        ..strokeWidth = hovered || selected ? 1.5 : linePaint.strokeWidth;
      if (guide.axis == 'vertical') {
        final x =
            dataRect.left +
            _sheetRulerMillimetersToLogicalPixels(
              guide.positionMm.clamp(0.0, maxWidthMm),
            ) -
            scrollOffset.dx;
        canvas.drawLine(
          Offset(x, dataRect.top),
          Offset(x, dataRect.bottom),
          paint,
        );
        if (selected) {
          canvas.drawRect(
            Rect.fromLTRB(x - 3, dataRect.top, x + 3, dataRect.bottom),
            selectedPaint,
          );
        }
      } else if (guide.axis == 'horizontal') {
        final y =
            dataRect.top +
            _sheetRulerMillimetersToLogicalPixels(
              guide.positionMm.clamp(0.0, maxHeightMm),
            ) -
            scrollOffset.dy;
        canvas.drawLine(
          Offset(dataRect.left, y),
          Offset(dataRect.right, y),
          paint,
        );
        if (selected) {
          canvas.drawRect(
            Rect.fromLTRB(dataRect.left, y - 3, dataRect.right, y + 3),
            selectedPaint,
          );
        }
      }
    }
    canvas.restore();
  }

  void _drawSheetRulerTooltip(Canvas canvas, Size size) {
    final text = sheetRulerTooltipText;
    final position = sheetRulerTooltipPosition;
    if (!sheetRulerVisible || text == null || position == null) {
      return;
    }
    final textPainter = TextPainter(
      text: TextSpan(
        text: text,
        style: const TextStyle(
          color: Color(0xffffffff),
          fontSize: 11,
          fontFamily: 'Arial',
        ),
      ),
      textDirection: TextDirection.ltr,
    )..layout();
    final width = textPainter.width + 14;
    final height = textPainter.height + 8;
    final left = math.min(
      math.max(2.0, position.dx + fortuneSheetRulerTooltipOffset),
      math.max(2.0, size.width - width - 2),
    );
    final top = math.min(
      math.max(2.0, position.dy + fortuneSheetRulerTooltipOffset),
      math.max(2.0, size.height - height - 2),
    );
    final rect = RRect.fromRectAndRadius(
      Rect.fromLTWH(left, top, width, height),
      const Radius.circular(3),
    );
    canvas.drawRRect(rect, Paint()..color = const Color(0xcc202124));
    textPainter.paint(canvas, Offset(left + 7, top + 4));
  }

  ({double dataWidth, double dataHeight, bool vertical, bool horizontal})
  _sheetViewportGeometry(
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    var dataWidth = math.max(0.0, size.width - _sheetDataLeft(settings));
    var dataHeight = math.max(0.0, size.height - _sheetDataTop(settings));
    var vertical = metrics.rowTotalHeight > dataHeight;
    var horizontal = metrics.columnTotalWidth > dataWidth;
    if (vertical) {
      dataWidth = math.max(0.0, dataWidth - fortuneSheetScrollbarThickness);
    }
    if (horizontal) {
      dataHeight = math.max(0.0, dataHeight - fortuneSheetScrollbarThickness);
    }
    if (!vertical && metrics.rowTotalHeight > dataHeight) {
      vertical = true;
      dataWidth = math.max(0.0, dataWidth - fortuneSheetScrollbarThickness);
    }
    if (!horizontal && metrics.columnTotalWidth > dataWidth) {
      horizontal = true;
      dataHeight = math.max(0.0, dataHeight - fortuneSheetScrollbarThickness);
    }
    return (
      dataWidth: dataWidth,
      dataHeight: dataHeight,
      vertical: vertical,
      horizontal: horizontal,
    );
  }

  void _drawSheetPrintAreaBoundary(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final physicalSize = fortuneSheetGridClientPhysicalSize(
      workbook.activeSheet,
    );
    if (physicalSize == null) {
      return;
    }
    final viewport = _sheetViewportGeometry(size, settings, metrics);
    final dataRect = Rect.fromLTWH(
      _sheetDataLeft(settings),
      _sheetDataTop(settings),
      viewport.dataWidth,
      viewport.dataHeight,
    );
    if (dataRect.isEmpty) {
      return;
    }
    final paint = Paint()
      ..color = fortuneSheetPrintAreaBoundaryColor
      ..strokeWidth = 1.5;
    canvas.save();
    canvas.clipRect(dataRect, doAntiAlias: false);
    final x =
        dataRect.left +
        _sheetRulerMillimetersToLogicalPixels(physicalSize.widthMm) -
        scrollOffset.dx;
    final y =
        dataRect.top +
        _sheetRulerMillimetersToLogicalPixels(physicalSize.heightMm) -
        scrollOffset.dy;
    final endX = x.clamp(dataRect.left, dataRect.right).toDouble();
    final endY = y.clamp(dataRect.top, dataRect.bottom).toDouble();
    if (x >= dataRect.left - 0.5 && x <= dataRect.right + 0.5) {
      canvas.drawLine(Offset(x, dataRect.top), Offset(x, endY), paint);
    }
    if (y >= dataRect.top - 0.5 && y <= dataRect.bottom + 0.5) {
      canvas.drawLine(Offset(dataRect.left, y), Offset(endX, y), paint);
    }
    canvas.restore();
  }

  bool _sheetRulerInserted(FortuneSettings settings) {
    return sheetRulerVisible &&
        fortuneSheetGridClientPhysicalSize(workbook.activeSheet) != null;
  }

  double _sheetRulerMillimetersToLogicalPixels(num millimeters) {
    return fortuneMillimetersToLogicalPixels(
      millimeters,
    ) * workbook.activeSheet.zoomRatio;
  }

  double _sheetRulerLogicalPixelsToMillimeters(num logicalPixels) {
    return fortuneLogicalPixelsToMillimeters(
      logicalPixels / workbook.activeSheet.zoomRatio,
    );
  }

  double _sheetRulerTopInset(FortuneSettings settings) {
    return _sheetRulerInserted(settings) ? settings.columnHeaderHeight : 0.0;
  }

  double _sheetRulerLeftInset(FortuneSettings settings) {
    return _sheetRulerInserted(settings) ? settings.rowHeaderWidth : 0.0;
  }

  double _sheetHeaderTop(FortuneSettings settings) {
    return _sheetRulerTopInset(settings);
  }

  double _sheetHeaderLeft(FortuneSettings settings) {
    return _sheetRulerLeftInset(settings);
  }

  double _sheetDataTop(FortuneSettings settings) {
    return _sheetHeaderTop(settings) + settings.columnHeaderHeight;
  }

  double _sheetDataLeft(FortuneSettings settings) {
    return _sheetHeaderLeft(settings) + settings.rowHeaderWidth;
  }

  void _drawSheetScrollbars(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final viewport = _sheetViewportGeometry(size, settings, metrics);
    if (!viewport.vertical && !viewport.horizontal) {
      return;
    }
    final trackPaint = Paint()..color = fortuneSheetScrollbarTrackColor;
    final thumbPaint = Paint()..color = fortuneSheetScrollbarThumbColor;
    final maxScrollX = math.max(
      0.0,
      metrics.columnTotalWidth - viewport.dataWidth,
    );
    final maxScrollY = math.max(
      0.0,
      metrics.rowTotalHeight - viewport.dataHeight,
    );
    if (viewport.vertical && viewport.dataHeight > 0) {
      final track = Rect.fromLTWH(
        size.width - fortuneSheetScrollbarThickness,
        _sheetDataTop(settings),
        fortuneSheetScrollbarThickness,
        viewport.dataHeight,
      );
      canvas.drawRect(track, trackPaint);
      final thumbHeight = math.min(
        track.height,
        math.max(
          fortuneSheetScrollbarMinThumbLength,
          track.height * viewport.dataHeight / metrics.rowTotalHeight,
        ),
      );
      final travel = math.max(0.0, track.height - thumbHeight);
      final progress = maxScrollY <= 0
          ? 0.0
          : (scrollOffset.dy / maxScrollY).clamp(0.0, 1.0).toDouble();
      final thumb = Rect.fromLTWH(
        track.left + 1,
        track.top + travel * progress,
        track.width - 2,
        thumbHeight,
      );
      canvas.drawRRect(
        RRect.fromRectAndRadius(thumb, const Radius.circular(3)),
        thumbPaint,
      );
    }
    if (viewport.horizontal && viewport.dataWidth > 0) {
      final track = Rect.fromLTWH(
        _sheetDataLeft(settings),
        size.height - fortuneSheetScrollbarThickness,
        viewport.dataWidth,
        fortuneSheetScrollbarThickness,
      );
      canvas.drawRect(track, trackPaint);
      final thumbWidth = math.min(
        track.width,
        math.max(
          fortuneSheetScrollbarMinThumbLength,
          track.width * viewport.dataWidth / metrics.columnTotalWidth,
        ),
      );
      final travel = math.max(0.0, track.width - thumbWidth);
      final progress = maxScrollX <= 0
          ? 0.0
          : (scrollOffset.dx / maxScrollX).clamp(0.0, 1.0).toDouble();
      final thumb = Rect.fromLTWH(
        track.left + travel * progress,
        track.top + 1,
        thumbWidth,
        track.height - 2,
      );
      canvas.drawRRect(
        RRect.fromRectAndRadius(thumb, const Radius.circular(3)),
        thumbPaint,
      );
    }
    if (viewport.vertical && viewport.horizontal) {
      canvas.drawRect(
        Rect.fromLTWH(
          size.width - fortuneSheetScrollbarThickness,
          size.height - fortuneSheetScrollbarThickness,
          fortuneSheetScrollbarThickness,
          fortuneSheetScrollbarThickness,
        ),
        trackPaint,
      );
    }
  }

  _FrozenSheetView _frozenView(
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final frozen = workbook.activeSheet.frozen;
    final rowFocus = frozen?.rowFocusIndex(metrics.visibleDataRows.length);
    final columnFocus = frozen?.columnFocusIndex(
      metrics.visibleDataColumns.length,
    );
    return _FrozenSheetView(
      rowFocus: rowFocus,
      columnFocus: columnFocus,
      frozenHeight: rowFocus == null ? 0 : metrics.rowEnd(rowFocus),
      frozenWidth: columnFocus == null ? 0 : metrics.columnEnd(columnFocus),
    );
  }

  double _visualCellLeft(
    int column,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final view = _frozenView(settings, metrics);
    final start = metrics.columnStart(column);
    if (view.columnFocus != null && column <= view.columnFocus!) {
      return _sheetDataLeft(settings) + start;
    }
    return _sheetDataLeft(settings) + start - scrollOffset.dx;
  }

  double _visualCellTop(
    int row,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final view = _frozenView(settings, metrics);
    final start = metrics.rowStart(row);
    if (view.rowFocus != null && row <= view.rowFocus!) {
      return _sheetDataTop(settings) + start;
    }
    return _sheetDataTop(settings) + start - scrollOffset.dy;
  }

  void _drawHeaders(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final headerPaint = Paint()..color = fortuneSheetHeaderBackgroundColor;
    final filterColumns = _filterColumns(workbook.activeSheet);
    final activeFilterColumns = _activeFilterColumns(workbook.activeSheet);
    final headerLeft = _sheetHeaderLeft(settings);
    final headerTop = _sheetHeaderTop(settings);
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    canvas.drawRect(
      Rect.fromLTWH(
        headerLeft,
        headerTop,
        math.max(0.0, size.width - headerLeft),
        settings.columnHeaderHeight,
      ),
      headerPaint,
    );
    canvas.drawRect(
      Rect.fromLTWH(
        headerLeft,
        headerTop,
        settings.rowHeaderWidth,
        math.max(0.0, size.height - headerTop),
      ),
      headerPaint,
    );
    _line(
      canvas,
      Offset(dataLeft - 0.5, headerTop),
      Offset(dataLeft - 0.5, size.height),
      fortuneSheetGridLineColor,
    );
    _line(
      canvas,
      Offset(headerLeft, dataTop - 0.5),
      Offset(size.width, dataTop - 0.5),
      fortuneSheetGridLineColor,
    );

    final viewport = _sheetViewportGeometry(size, settings, metrics);
    final columnRange = metrics.visibleColumns(
      scrollOffset.dx,
      viewport.dataWidth,
    );
    final rowRange = metrics.visibleRows(scrollOffset.dy, viewport.dataHeight);

    for (var c = columnRange.start; c <= columnRange.end; c += 1) {
      final start = metrics.columnStart(c);
      final end = metrics.columnEnd(c);
      final w = end - start;
      if (w <= 0) {
        continue;
      }
      final x = _visualCellLeft(c, settings, metrics);
      final rect = Rect.fromLTWH(x, headerTop, w, settings.columnHeaderHeight);
      final visibleRect = rect.intersect(
        Rect.fromLTWH(
          dataLeft,
          headerTop,
          math.max(0.0, size.width - dataLeft),
          settings.columnHeaderHeight,
        ),
      );
      if (visibleRect.isEmpty) {
        continue;
      }
      final columnChar = _columnName(c);
      if (settings.beforeRenderColumnHeaderCell?.call(
            columnChar,
            c,
            x,
            w,
            settings.columnHeaderHeight - 1,
            canvas,
          ) ==
          false) {
        continue;
      }
      canvas.save();
      canvas.clipRect(visibleRect, doAntiAlias: false);
      if (hoveredColumnHeaderIndex == c) {
        canvas.drawRect(
          Rect.fromLTWH(
            x,
            headerTop,
            math.max(0, w - 1),
            settings.columnHeaderHeight,
          ),
          Paint()..color = fortuneSheetHeaderHoverFillColor,
        );
      }
      if (x + w <= size.width) {
        _line(
          canvas,
          Offset(x + w - 0.5, headerTop),
          Offset(x + w - 0.5, dataTop),
          fortuneSheetGridLineColor,
        );
      }
      _drawText(
        canvas,
        columnChar,
        rect,
        fontSize: 12,
        color: fortuneSheetHeaderTextColor,
        align: TextAlign.center,
      );
      if (filterColumns.contains(c)) {
        _drawFilterMarker(
          canvas,
          rect,
          active: activeFilterColumns.contains(c),
        );
      }
      if (hoveredColumnHeaderIndex == c && workbook.settings.allowEdit) {
        _drawColumnHeaderMenuButton(
          canvas,
          fortuneColumnHeaderMenuButtonRect(rect),
        );
      }
      canvas.restore();
      settings.afterRenderColumnHeaderCell?.call(
        columnChar,
        c,
        x,
        w,
        settings.columnHeaderHeight - 1,
        canvas,
      );
    }

    for (var r = rowRange.start; r <= rowRange.end; r += 1) {
      final start = metrics.rowStart(r);
      final end = metrics.rowEnd(r);
      final h = end - start;
      if (h <= 0) {
        continue;
      }
      final y = _visualCellTop(r, settings, metrics);
      final rect = Rect.fromLTWH(headerLeft, y, settings.rowHeaderWidth, h);
      final visibleRect = rect.intersect(
        Rect.fromLTWH(
          headerLeft,
          dataTop,
          settings.rowHeaderWidth,
          math.max(0.0, size.height - dataTop),
        ),
      );
      if (visibleRect.isEmpty) {
        continue;
      }
      final rowNumber = '${r + 1}';
      if (settings.beforeRenderRowHeaderCell?.call(
            rowNumber,
            r,
            y,
            settings.rowHeaderWidth - 1,
            h,
            canvas,
          ) ==
          false) {
        continue;
      }
      canvas.save();
      canvas.clipRect(visibleRect, doAntiAlias: false);
      if (hoveredRowHeaderIndex == r) {
        canvas.drawRect(
          Rect.fromLTWH(
            headerLeft,
            y,
            settings.rowHeaderWidth,
            math.max(0, h - 1),
          ),
          Paint()..color = fortuneSheetHeaderHoverFillColor,
        );
      }
      if (y + h <= size.height) {
        _line(
          canvas,
          Offset(headerLeft, y + h - 0.5),
          Offset(dataLeft, y + h - 0.5),
          fortuneSheetGridLineColor,
        );
      }
      _drawText(
        canvas,
        rowNumber,
        Rect.fromLTWH(headerLeft, y, settings.rowHeaderWidth - 2, h),
        fontSize: 12,
        color: fortuneSheetHeaderTextColor,
        align: TextAlign.center,
      );
      canvas.restore();
      settings.afterRenderRowHeaderCell?.call(
        rowNumber,
        r,
        y,
        settings.rowHeaderWidth - 1,
        h,
        canvas,
      );
    }
  }

  void _drawFrozenHeaders(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final view = _frozenView(settings, metrics);
    if (!view.hasFrozenPane) {
      return;
    }
    final filterColumns = _filterColumns(workbook.activeSheet);
    final activeFilterColumns = _activeFilterColumns(workbook.activeSheet);
    final headerPaint = Paint()..color = fortuneSheetHeaderBackgroundColor;
    final headerLeft = _sheetHeaderLeft(settings);
    final headerTop = _sheetHeaderTop(settings);
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    if (view.columnFocus != null) {
      canvas.save();
      canvas.clipRect(
        Rect.fromLTWH(
          dataLeft,
          headerTop,
          view.frozenWidth,
          settings.columnHeaderHeight,
        ),
      );
      canvas.drawRect(
        Rect.fromLTWH(
          dataLeft,
          headerTop,
          view.frozenWidth,
          settings.columnHeaderHeight,
        ),
        headerPaint,
      );
      for (var c = 0; c <= view.columnFocus!; c += 1) {
        final w = metrics.columnEnd(c) - metrics.columnStart(c);
        if (w <= 0) {
          continue;
        }
        final x = _visualCellLeft(c, settings, metrics);
        if (hoveredColumnHeaderIndex == c) {
          canvas.drawRect(
            Rect.fromLTWH(
              x,
              headerTop,
              math.max(0, w - 1),
              settings.columnHeaderHeight,
            ),
            Paint()..color = fortuneSheetHeaderHoverFillColor,
          );
        }
        _line(
          canvas,
          Offset(x + w - 0.5, headerTop),
          Offset(x + w - 0.5, dataTop),
          fortuneSheetGridLineColor,
        );
        _drawText(
          canvas,
          _columnName(c),
          Rect.fromLTWH(x, headerTop, w, settings.columnHeaderHeight),
          fontSize: 12,
          color: fortuneSheetHeaderTextColor,
          align: TextAlign.center,
        );
        if (filterColumns.contains(c)) {
          _drawFilterMarker(
            canvas,
            Rect.fromLTWH(x, headerTop, w, settings.columnHeaderHeight),
            active: activeFilterColumns.contains(c),
          );
        }
        if (hoveredColumnHeaderIndex == c && workbook.settings.allowEdit) {
          _drawColumnHeaderMenuButton(
            canvas,
            fortuneColumnHeaderMenuButtonRect(
              Rect.fromLTWH(x, headerTop, w, settings.columnHeaderHeight),
            ),
          );
        }
      }
      canvas.restore();
    }

    if (view.rowFocus != null) {
      canvas.save();
      canvas.clipRect(
        Rect.fromLTWH(
          headerLeft,
          dataTop,
          settings.rowHeaderWidth,
          view.frozenHeight,
        ),
      );
      canvas.drawRect(
        Rect.fromLTWH(
          headerLeft,
          dataTop,
          settings.rowHeaderWidth,
          view.frozenHeight,
        ),
        headerPaint,
      );
      for (var r = 0; r <= view.rowFocus!; r += 1) {
        final h = metrics.rowEnd(r) - metrics.rowStart(r);
        if (h <= 0) {
          continue;
        }
        final y = _visualCellTop(r, settings, metrics);
        if (hoveredRowHeaderIndex == r) {
          canvas.drawRect(
            Rect.fromLTWH(
              headerLeft,
              y,
              settings.rowHeaderWidth,
              math.max(0, h - 1),
            ),
            Paint()..color = fortuneSheetHeaderHoverFillColor,
          );
        }
        _line(
          canvas,
          Offset(headerLeft, y + h - 0.5),
          Offset(dataLeft, y + h - 0.5),
          fortuneSheetGridLineColor,
        );
        _drawText(
          canvas,
          '${r + 1}',
          Rect.fromLTWH(headerLeft, y, settings.rowHeaderWidth - 2, h),
          fontSize: 12,
          color: fortuneSheetHeaderTextColor,
          align: TextAlign.center,
        );
      }
      canvas.restore();
    }
  }

  void _drawHeaderSelections(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final fillPaint = Paint()..color = fortuneSheetHeaderSelectionFillColor;
    final headerLeft = _sheetHeaderLeft(settings);
    final headerTop = _sheetHeaderTop(settings);
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    for (final range in _selectedHeaderRanges(metrics)) {
      for (final piece in _rangePieces(range, size, settings, metrics)) {
        final rowClip = Rect.fromLTRB(
          headerLeft,
          math.max(dataTop, piece.clip.top),
          dataLeft,
          math.min(size.height, piece.clip.bottom),
        );
        final rowRect = Rect.fromLTWH(
          headerLeft,
          piece.rect.top,
          settings.rowHeaderWidth,
          math.max(0, piece.rect.height - 1),
        );
        if (!rowClip.isEmpty && rowRect.overlaps(rowClip)) {
          canvas.save();
          canvas.clipRect(rowClip);
          canvas.drawRect(rowRect, fillPaint);
          _line(
            canvas,
            Offset(dataLeft - 0.5, rowRect.top),
            Offset(dataLeft - 0.5, rowRect.bottom),
            fortuneSheetSelectionColor,
          );
          canvas.restore();
        }

        final columnClip = Rect.fromLTRB(
          math.max(dataLeft, piece.clip.left),
          headerTop,
          math.min(size.width, piece.clip.right),
          dataTop,
        );
        final columnRect = Rect.fromLTWH(
          piece.rect.left,
          headerTop,
          math.max(0, piece.rect.width - 1),
          settings.columnHeaderHeight,
        );
        if (!columnClip.isEmpty && columnRect.overlaps(columnClip)) {
          canvas.save();
          canvas.clipRect(columnClip);
          canvas.drawRect(columnRect, fillPaint);
          _line(
            canvas,
            Offset(columnRect.left, dataTop - 0.5),
            Offset(columnRect.right, dataTop - 0.5),
            fortuneSheetSelectionColor,
          );
          canvas.restore();
        }
      }
    }
  }

  Set<int> _filterColumns(FortuneSheet sheet) {
    final columns = <int>{};
    final filterSelectRange = _filterSelectRange(sheet);
    if (filterSelectRange != null) {
      for (
        var column = filterSelectRange.columnStart;
        column <= filterSelectRange.columnEnd;
        column += 1
      ) {
        columns.add(column);
      }
    }
    for (final entry in sheet.filter.entries) {
      final value = entry.value;
      if (entry.key.startsWith('column_')) {
        final parsed = int.tryParse(entry.key.substring('column_'.length));
        if (parsed != null) {
          columns.add(parsed);
        }
      }
      if (value is Map) {
        final focus = value['column_focus'];
        if (focus is int) {
          columns.add(focus);
        }
        final column = value['column'];
        if (column is List && column.isNotEmpty) {
          final first = column.first;
          if (first is int) {
            columns.add(first);
          }
        } else if (column is int) {
          columns.add(column);
        }
      }
    }
    return columns;
  }

  Set<int> _activeFilterColumns(FortuneSheet sheet) {
    final columns = <int>{};
    for (final entry in sheet.filter.entries) {
      final value = entry.value;
      if (value is! Map) {
        continue;
      }
      final rowhidden = value['rowhidden'];
      final hasRowHidden = rowhidden is Map && rowhidden.isNotEmpty;
      final hasColorFilter =
          _filterColorFilterFromCaljs(value['caljs']) != null;
      if (value['filterValue'] == null && !hasRowHidden && !hasColorFilter) {
        continue;
      }
      final column = _filterColumnFromConfig(entry.key, value);
      if (column != null) {
        columns.add(column);
      }
    }
    return columns;
  }

  FortuneRange? _filterSelectRange(FortuneSheet sheet) {
    final raw = sheet.filterSelect;
    if (raw is! Map) {
      return null;
    }
    final row = raw['row'];
    final column = raw['column'];
    if (row is! List ||
        row.length < 2 ||
        column is! List ||
        column.length < 2) {
      return null;
    }
    final rowStart = _intValue(row[0]);
    final rowEnd = _intValue(row[1]);
    final columnStart = _intValue(column[0]);
    final columnEnd = _intValue(column[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null) {
      return null;
    }
    return FortuneRange(
      rowStart: math.min(rowStart, rowEnd),
      rowEnd: math.max(rowStart, rowEnd),
      columnStart: math.min(columnStart, columnEnd),
      columnEnd: math.max(columnStart, columnEnd),
    );
  }

  void _drawFilterMarker(
    Canvas canvas,
    Rect headerRect, {
    required bool active,
  }) {
    if (headerRect.width <
            fortuneFilterMarkerSize + fortuneFilterMarkerRightInset ||
        headerRect.height < fortuneFilterMarkerSize - 1) {
      return;
    }
    final markerRect = Rect.fromLTWH(
      headerRect.right -
          fortuneFilterMarkerSize -
          fortuneFilterMarkerRightInset,
      headerRect.top + fortuneFilterMarkerTopInset,
      fortuneFilterMarkerSize,
      fortuneFilterMarkerSize,
    );
    final radius = BorderRadius.circular(
      fortuneFilterMarkerBorderRadius,
    ).toRRect(markerRect);
    final borderPaint = Paint()
      ..color = fortuneFilterMarkerColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1;
    if (active) {
      canvas.drawRRect(
        radius,
        Paint()
          ..color = fortuneFilterMarkerColor
          ..style = PaintingStyle.fill,
      );
    } else {
      canvas.drawRRect(radius, Paint()..color = const Color(0xffffffff));
    }
    canvas.drawRRect(radius, borderPaint);
    if (!active) {
      final centerX = markerRect.center.dx;
      final top = markerRect.top + fortuneFilterMarkerCaretTopInset;
      final caret = Path()
        ..moveTo(centerX - fortuneFilterMarkerCaretHalfWidth, top)
        ..lineTo(centerX + fortuneFilterMarkerCaretHalfWidth, top)
        ..lineTo(centerX, top + fortuneFilterMarkerCaretHeight)
        ..close();
      canvas.drawPath(caret, Paint()..color = fortuneFilterMarkerColor);
      return;
    }
    final right = markerRect.right - 3;
    final top = markerRect.top + 3;
    final path = Path()
      ..moveTo(right - 9, top)
      ..lineTo(right, top)
      ..lineTo(right - 5, top + 6)
      ..lineTo(right - 5, top + 10)
      ..lineTo(right - 7, top + 10)
      ..lineTo(right - 7, top + 6)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xffffffff));
  }

  void _drawColumnHeaderMenuButton(Canvas canvas, Rect rect) {
    if (rect.isEmpty ||
        rect.width < fortuneColumnHeaderMenuArrowSize ||
        rect.height < fortuneColumnHeaderMenuArrowSize) {
      return;
    }
    final buttonRect = rect.deflate(1);
    canvas.drawRRect(
      BorderRadius.circular(2).toRRect(buttonRect),
      Paint()..color = const Color(0xffffffff),
    );
    canvas.drawRRect(
      BorderRadius.circular(2).toRRect(buttonRect),
      Paint()
        ..color = const Color(0xffd0d4dc)
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1,
    );
    FortuneToolbarIconPainter.draw(
      canvas,
      'combo-arrow',
      Rect.fromCenter(
        center: buttonRect.center,
        width: fortuneColumnHeaderMenuArrowSize,
        height: fortuneColumnHeaderMenuArrowSize,
      ),
    );
  }

  void _drawCells(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheet = workbook.activeSheet;
    final borderCompute = FortuneBorderCompute.compute(sheet);
    final mergeLookup = _buildMergeLookup(sheet, settings);
    final conditionStyles = _conditionFormatStyles(sheet);
    final alternateBackgrounds = _alternateFormatBackgrounds(sheet);
    final alternateForegrounds = _alternateFormatForegrounds(sheet);
    final showGridLines = sheet.showGridLines;
    final viewport = _sheetViewportGeometry(size, settings, metrics);
    final rowRange = metrics.visibleRows(scrollOffset.dy, viewport.dataHeight);
    final columnRange = metrics.visibleColumns(
      scrollOffset.dx,
      viewport.dataWidth,
    );
    final cellClip = Rect.fromLTWH(
      _sheetDataLeft(settings),
      _sheetDataTop(settings),
      viewport.dataWidth,
      viewport.dataHeight,
    );
    if (cellClip.isEmpty) {
      return;
    }
    canvas.save();
    canvas.clipRect(cellClip, doAntiAlias: false);

    // First pass: backgrounds and grid lines. Text is rendered in a second pass
    // so overflow text can draw over adjacent empty cells like FortuneSheet.
    final drawnMergedBackgrounds = <FortuneCellCoord>{};
    final renderedCellRects = <FortuneCellCoord, Rect>{};
    final skippedRenderCells = <FortuneCellCoord>{};
    for (var r = rowRange.start; r <= rowRange.end; r += 1) {
      final rowStart = metrics.rowStart(r);
      final rowEnd = metrics.rowEnd(r);
      final h = rowEnd - rowStart;
      if (h <= 0) {
        continue;
      }
      final y = _visualCellTop(r, settings, metrics);
      for (var c = columnRange.start; c <= columnRange.end; c += 1) {
        final columnStart = metrics.columnStart(c);
        final columnEnd = metrics.columnEnd(c);
        final w = columnEnd - columnStart;
        if (w <= 0) {
          continue;
        }
        final coord = FortuneCellCoord(r, c);
        final mergeAnchor = mergeLookup[coord];
        final drawCoord = mergeAnchor ?? coord;
        final isMerged = mergeAnchor != null;
        if (isMerged && !drawnMergedBackgrounds.add(drawCoord)) {
          continue;
        }
        final x = _visualCellLeft(c, settings, metrics);
        final singleRect = Rect.fromLTWH(x, y, w, h);
        final cell = sheet.cells[drawCoord];
        final rect = isMerged
            ? _mergedCellRect(
                settings: settings,
                metrics: metrics,
                anchor: drawCoord,
                merge: cell?.merge,
              )
            : singleRect;
        if (rect == null) {
          continue;
        }
        if (!_beforeRenderCell(settings, canvas, cell, drawCoord, rect)) {
          skippedRenderCells.add(drawCoord);
          continue;
        }
        renderedCellRects[drawCoord] = rect;
        final conditionStyle = conditionStyles[drawCoord];
        final background =
            conditionStyle?.cellColor ??
            cell?.background ??
            alternateBackgrounds[drawCoord];
        if (background != null) {
          canvas.drawRect(rect.deflate(0.5), Paint()..color = background);
        }
        if (conditionStyle?.dataBar case final dataBar?) {
          _drawConditionDataBar(canvas, rect, dataBar);
        }
        if (cell?.sparkline != null) {
          _drawCellSparkline(canvas, rect, cell!);
        }
        final dataVerification = _dataVerificationForCoord(sheet, drawCoord);
        if (_dataVerificationFails(sheet, drawCoord, cell, dataVerification)) {
          _drawDataVerificationFailureIndicator(canvas, rect);
        }
        if (cell?.comment != null) {
          _drawCommentIndicator(canvas, rect);
        }
        if (_showsQuotePrefixIndicator(cell)) {
          _drawQuotePrefixIndicator(canvas, rect);
        }
        if (dataVerification != null &&
            dataVerification['type'] != 'checkbox') {
          _drawDataVerificationMarker(canvas, rect);
        }
        if (showGridLines) {
          _line(
            canvas,
            Offset(rect.right - 0.5, rect.top),
            Offset(rect.right - 0.5, rect.bottom),
            fortuneSheetGridLineColor,
          );
          _line(
            canvas,
            Offset(rect.left, rect.bottom - 0.5),
            Offset(rect.right, rect.bottom - 0.5),
            fortuneSheetGridLineColor,
          );
        }
      }
    }
    if (showGridLines) {
      _drawSheetViewportGridLines(
        canvas,
        sheet,
        cellClip,
        settings,
        metrics,
        rowRange: rowRange,
        columnRange: columnRange,
      );
    }

    final drawnMergedTexts = <FortuneCellCoord>{};
    for (var r = rowRange.start; r <= rowRange.end; r += 1) {
      final rowStart = metrics.rowStart(r);
      final rowEnd = metrics.rowEnd(r);
      final h = rowEnd - rowStart;
      if (h <= 0) {
        continue;
      }
      final y = _visualCellTop(r, settings, metrics);
      for (var c = columnRange.start; c <= columnRange.end; c += 1) {
        final columnStart = metrics.columnStart(c);
        final columnEnd = metrics.columnEnd(c);
        final w = columnEnd - columnStart;
        if (w <= 0) {
          continue;
        }
        final coord = FortuneCellCoord(r, c);
        final mergeAnchor = mergeLookup[coord];
        final drawCoord = mergeAnchor ?? coord;
        if (mergeAnchor != null && !drawnMergedTexts.add(drawCoord)) {
          continue;
        }
        final x = _visualCellLeft(c, settings, metrics);
        final singleRect = Rect.fromLTWH(x, y, w, h);
        final cell = sheet.cells[drawCoord];
        final cellRect = mergeAnchor == null
            ? singleRect
            : _mergedCellRect(
                settings: settings,
                metrics: metrics,
                anchor: drawCoord,
                merge: cell?.merge,
              );
        if (cellRect == null) {
          continue;
        }
        final renderedRect = renderedCellRects[drawCoord];
        if (renderedRect == null || skippedRenderCells.contains(drawCoord)) {
          continue;
        }
        final dataVerification = _dataVerificationForCoord(sheet, drawCoord);
        if (dataVerification != null &&
            dataVerification['type'] == 'checkbox') {
          _drawDataVerificationCheckbox(
            canvas,
            cellRect,
            cell,
            dataVerification,
          );
          _afterRenderCell(settings, canvas, cell, drawCoord, renderedRect);
          continue;
        }
        final renderCell = _dynamicArrayRenderCell(sheet, drawCoord, cell);
        if (renderCell != null && renderCell.renderedText.isNotEmpty) {
          final conditionStyle = conditionStyles[drawCoord];
          if (conditionStyle?.icon case final icon?) {
            _drawConditionIcon(canvas, cellRect, icon);
          }
          final baseTextRect = _cellTextRect(
            sheet: sheet,
            metrics: metrics,
            settings: settings,
            row: drawCoord.row,
            column: drawCoord.column,
            cell: renderCell,
            cellRect: cellRect,
          );
          final textRect = conditionStyle?.icon == null
              ? baseTextRect
              : Rect.fromLTRB(
                  math.min(baseTextRect.left + 14, baseTextRect.right),
                  baseTextRect.top,
                  baseTextRect.right,
                  baseTextRect.bottom,
                );
          _drawCellText(
            canvas,
            textRect.deflate(2),
            renderCell,
            fontSize:
                (renderCell.fontSize ?? settings.defaultFontSize) *
                sheet.zoomRatio,
            textScale: sheet.zoomRatio,
            textColor:
                conditionStyle?.textColor ??
                (_cellHasExplicitForeground(renderCell)
                    ? null
                    : alternateForegrounds[drawCoord]),
          );
        }
        _afterRenderCell(settings, canvas, cell, drawCoord, renderedRect);
      }
    }
    canvas.restore();

    canvas.save();
    canvas.clipRect(_borderClip(cellClip), doAntiAlias: false);
    _drawRenderedCellBorders(
      canvas,
      sheet,
      metrics,
      rowStart: rowRange.start,
      rowEnd: rowRange.end,
      columnStart: columnRange.start,
      columnEnd: columnRange.end,
      borderCompute: borderCompute,
      mergeLookup: mergeLookup,
      renderedCellRects: renderedCellRects,
      skippedRenderCells: skippedRenderCells,
      clipBounds: cellClip,
    );
    canvas.restore();
  }

  void _drawSheetViewportGridLines(
    Canvas canvas,
    FortuneSheet sheet,
    Rect clip,
    FortuneSettings settings,
    FortuneSheetMetrics metrics, {
    required FortuneAxisRange rowRange,
    required FortuneAxisRange columnRange,
  }) {
    for (var c = columnRange.start; c <= columnRange.end; c += 1) {
      final x = _visualCellLeft(c, settings, metrics);
      final right = x + metrics.columnEnd(c) - metrics.columnStart(c);
      if (right < clip.left - 0.5 || right > clip.right + 0.5) {
        continue;
      }
      _drawGridLineExcludingSpans(
        canvas,
        start: Offset(right - 0.5, clip.top),
        end: Offset(right - 0.5, clip.bottom),
        vertical: true,
        excludedSpans: _mergedGridLineExcludedSpans(
          sheet,
          settings,
          metrics,
          clip,
          index: c,
          vertical: true,
        ),
        color: fortuneSheetGridLineColor,
      );
    }
    for (var r = rowRange.start; r <= rowRange.end; r += 1) {
      final y = _visualCellTop(r, settings, metrics);
      final bottom = y + metrics.rowEnd(r) - metrics.rowStart(r);
      if (bottom < clip.top - 0.5 || bottom > clip.bottom + 0.5) {
        continue;
      }
      _drawGridLineExcludingSpans(
        canvas,
        start: Offset(clip.left, bottom - 0.5),
        end: Offset(clip.right, bottom - 0.5),
        vertical: false,
        excludedSpans: _mergedGridLineExcludedSpans(
          sheet,
          settings,
          metrics,
          clip,
          index: r,
          vertical: false,
        ),
        color: fortuneSheetGridLineColor,
      );
    }
  }

  List<(double, double)> _mergedGridLineExcludedSpans(
    FortuneSheet sheet,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
    Rect clip, {
    required int index,
    required bool vertical,
  }) {
    final spans = <(double, double)>[];
    for (final entry in sheet.cells.entries) {
      final merge = entry.value.merge;
      if (merge == null ||
          entry.key.row != merge.row ||
          entry.key.column != merge.column ||
          (merge.rowSpan <= 1 && merge.columnSpan <= 1)) {
        continue;
      }
      if (vertical) {
        final insideColumn = index >= merge.column &&
            index < merge.column + merge.columnSpan - 1;
        if (!insideColumn) {
          continue;
        }
        final top = _visualCellTop(merge.row, settings, metrics);
        final bottom = _visualCellTop(merge.row + merge.rowSpan - 1, settings, metrics) +
            metrics.rowEnd(merge.row + merge.rowSpan - 1) -
            metrics.rowStart(merge.row + merge.rowSpan - 1);
        spans.add((math.max(top, clip.top), math.min(bottom, clip.bottom)));
      } else {
        final insideRow = index >= merge.row && index < merge.row + merge.rowSpan - 1;
        if (!insideRow) {
          continue;
        }
        final left = _visualCellLeft(merge.column, settings, metrics);
        final right = _visualCellLeft(merge.column + merge.columnSpan - 1, settings, metrics) +
            metrics.columnEnd(merge.column + merge.columnSpan - 1) -
            metrics.columnStart(merge.column + merge.columnSpan - 1);
        spans.add((math.max(left, clip.left), math.min(right, clip.right)));
      }
    }
    spans.removeWhere((span) => span.$2 <= span.$1);
    spans.sort((a, b) => a.$1.compareTo(b.$1));
    return spans;
  }

  void _drawGridLineExcludingSpans(
    Canvas canvas, {
    required Offset start,
    required Offset end,
    required bool vertical,
    required List<(double, double)> excludedSpans,
    required Color color,
  }) {
    var cursor = vertical ? start.dy : start.dx;
    final limit = vertical ? end.dy : end.dx;
    for (final span in excludedSpans) {
      final spanStart = span.$1.clamp(cursor, limit).toDouble();
      final spanEnd = span.$2.clamp(cursor, limit).toDouble();
      if (spanStart > cursor) {
        _line(
          canvas,
          vertical ? Offset(start.dx, cursor) : Offset(cursor, start.dy),
          vertical ? Offset(start.dx, spanStart) : Offset(spanStart, start.dy),
          color,
        );
      }
      cursor = math.max(cursor, spanEnd);
    }
    if (cursor < limit) {
      _line(
        canvas,
        vertical ? Offset(start.dx, cursor) : Offset(cursor, start.dy),
        vertical ? Offset(start.dx, limit) : Offset(limit, start.dy),
        color,
      );
    }
  }

  FortuneRenderCellHookInfo _renderCellHookInfo(
    FortuneCellCoord coord,
    Rect rect,
  ) => {
    'row': coord.row,
    'column': coord.column,
    'startX': rect.left,
    'startY': rect.top,
    'endX': rect.right,
    'endY': rect.bottom,
  };

  bool _beforeRenderCell(
    FortuneSettings settings,
    Canvas canvas,
    FortuneCell? cell,
    FortuneCellCoord coord,
    Rect rect,
  ) =>
      settings.beforeRenderCell?.call(
        cell,
        _renderCellHookInfo(coord, rect),
        canvas,
      ) !=
      false;

  void _afterRenderCell(
    FortuneSettings settings,
    Canvas canvas,
    FortuneCell? cell,
    FortuneCellCoord coord,
    Rect rect,
  ) {
    settings.afterRenderCell?.call(
      cell,
      _renderCellHookInfo(coord, rect),
      canvas,
    );
  }

  void _drawFrozenCells(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final view = _frozenView(settings, metrics);
    if (!view.hasFrozenPane) {
      return;
    }
    final sheet = workbook.activeSheet;
    final borderCompute = FortuneBorderCompute.compute(sheet);
    final mergeLookup = _buildMergeLookup(sheet, settings);
    final viewport = _sheetViewportGeometry(size, settings, metrics);
    final rowViewport = viewport.dataHeight;
    final columnViewport = viewport.dataWidth;
    final rowRange = metrics.visibleRows(scrollOffset.dy, rowViewport);
    final columnRange = metrics.visibleColumns(scrollOffset.dx, columnViewport);
    final frozenRowEnd = view.rowFocus;
    final frozenColumnEnd = view.columnFocus;

    if (frozenRowEnd != null) {
      _drawCellRange(
        canvas,
        settings,
        metrics,
        rowStart: 0,
        rowEnd: frozenRowEnd,
        columnStart: columnRange.start,
        columnEnd: columnRange.end,
        borderCompute: borderCompute,
        mergeLookup: mergeLookup,
        clip: Rect.fromLTWH(
          _sheetDataLeft(settings),
          _sheetDataTop(settings),
          columnViewport,
          view.frozenHeight,
        ),
      );
    }

    if (frozenColumnEnd != null) {
      _drawCellRange(
        canvas,
        settings,
        metrics,
        rowStart: rowRange.start,
        rowEnd: rowRange.end,
        columnStart: 0,
        columnEnd: frozenColumnEnd,
        borderCompute: borderCompute,
        mergeLookup: mergeLookup,
        clip: Rect.fromLTWH(
          _sheetDataLeft(settings),
          _sheetDataTop(settings),
          view.frozenWidth,
          rowViewport,
        ),
      );
    }

    if (frozenRowEnd != null && frozenColumnEnd != null) {
      _drawCellRange(
        canvas,
        settings,
        metrics,
        rowStart: 0,
        rowEnd: frozenRowEnd,
        columnStart: 0,
        columnEnd: frozenColumnEnd,
        borderCompute: borderCompute,
        mergeLookup: mergeLookup,
        clip: Rect.fromLTWH(
          _sheetDataLeft(settings),
          _sheetDataTop(settings),
          view.frozenWidth,
          view.frozenHeight,
        ),
      );
    }
  }

  void _drawCellRange(
    Canvas canvas,
    FortuneSettings settings,
    FortuneSheetMetrics metrics, {
    required int rowStart,
    required int rowEnd,
    required int columnStart,
    required int columnEnd,
    required Map<FortuneCellCoord, FortuneCellBorders> borderCompute,
    required Map<FortuneCellCoord, FortuneCellCoord> mergeLookup,
    required Rect clip,
  }) {
    if (rowEnd < rowStart || columnEnd < columnStart || clip.isEmpty) {
      return;
    }
    final sheet = workbook.activeSheet;
    final showGridLines = sheet.showGridLines;
    final conditionStyles = _conditionFormatStyles(sheet);
    final alternateBackgrounds = _alternateFormatBackgrounds(sheet);
    final alternateForegrounds = _alternateFormatForegrounds(sheet);
    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    final drawnBackgrounds = <FortuneCellCoord>{};
    final renderedCellRects = <FortuneCellCoord, Rect>{};
    final skippedRenderCells = <FortuneCellCoord>{};
    for (var r = rowStart; r <= rowEnd; r += 1) {
      final h = metrics.rowEnd(r) - metrics.rowStart(r);
      if (h <= 0) {
        continue;
      }
      final y = _visualCellTop(r, settings, metrics);
      for (var c = columnStart; c <= columnEnd; c += 1) {
        final w = metrics.columnEnd(c) - metrics.columnStart(c);
        if (w <= 0) {
          continue;
        }
        final coord = FortuneCellCoord(r, c);
        final mergeAnchor = mergeLookup[coord];
        final drawCoord = mergeAnchor ?? coord;
        if (mergeAnchor != null && !drawnBackgrounds.add(drawCoord)) {
          continue;
        }
        final cell = sheet.cells[drawCoord];
        final rect = mergeAnchor == null
            ? Rect.fromLTWH(_visualCellLeft(c, settings, metrics), y, w, h)
            : _mergedCellRect(
                settings: settings,
                metrics: metrics,
                anchor: drawCoord,
                merge: cell?.merge,
              );
        if (rect == null) {
          continue;
        }
        if (!_beforeRenderCell(settings, canvas, cell, drawCoord, rect)) {
          skippedRenderCells.add(drawCoord);
          continue;
        }
        renderedCellRects[drawCoord] = rect;
        canvas.drawRect(
          rect.deflate(0.5),
          Paint()..color = const Color(0xffffffff),
        );
        final conditionStyle = conditionStyles[drawCoord];
        final background =
            conditionStyle?.cellColor ??
            cell?.background ??
            alternateBackgrounds[drawCoord];
        if (background != null) {
          canvas.drawRect(rect.deflate(0.5), Paint()..color = background);
        }
        if (conditionStyle?.dataBar case final dataBar?) {
          _drawConditionDataBar(canvas, rect, dataBar);
        }
        if (cell?.sparkline != null) {
          _drawCellSparkline(canvas, rect, cell!);
        }
        final dataVerification = _dataVerificationForCoord(sheet, drawCoord);
        if (_dataVerificationFails(sheet, drawCoord, cell, dataVerification)) {
          _drawDataVerificationFailureIndicator(canvas, rect);
        }
        if (cell?.comment != null) {
          _drawCommentIndicator(canvas, rect);
        }
        if (_showsQuotePrefixIndicator(cell)) {
          _drawQuotePrefixIndicator(canvas, rect);
        }
        if (dataVerification != null &&
            dataVerification['type'] != 'checkbox') {
          _drawDataVerificationMarker(canvas, rect);
        }
        if (showGridLines) {
          _line(
            canvas,
            Offset(rect.right - 0.5, rect.top),
            Offset(rect.right - 0.5, rect.bottom),
            fortuneSheetGridLineColor,
          );
          _line(
            canvas,
            Offset(rect.left, rect.bottom - 0.5),
            Offset(rect.right, rect.bottom - 0.5),
            fortuneSheetGridLineColor,
          );
        }
      }
    }

    final drawnTexts = <FortuneCellCoord>{};
    for (var r = rowStart; r <= rowEnd; r += 1) {
      final h = metrics.rowEnd(r) - metrics.rowStart(r);
      if (h <= 0) {
        continue;
      }
      final y = _visualCellTop(r, settings, metrics);
      for (var c = columnStart; c <= columnEnd; c += 1) {
        final w = metrics.columnEnd(c) - metrics.columnStart(c);
        if (w <= 0) {
          continue;
        }
        final coord = FortuneCellCoord(r, c);
        final mergeAnchor = mergeLookup[coord];
        final drawCoord = mergeAnchor ?? coord;
        if (mergeAnchor != null && !drawnTexts.add(drawCoord)) {
          continue;
        }
        final cell = sheet.cells[drawCoord];
        final cellRect = mergeAnchor == null
            ? Rect.fromLTWH(_visualCellLeft(c, settings, metrics), y, w, h)
            : _mergedCellRect(
                settings: settings,
                metrics: metrics,
                anchor: drawCoord,
                merge: cell?.merge,
              );
        if (cellRect == null) {
          continue;
        }
        final renderedRect = renderedCellRects[drawCoord];
        if (renderedRect == null || skippedRenderCells.contains(drawCoord)) {
          continue;
        }
        final dataVerification = _dataVerificationForCoord(sheet, drawCoord);
        if (dataVerification != null &&
            dataVerification['type'] == 'checkbox') {
          _drawDataVerificationCheckbox(
            canvas,
            cellRect,
            cell,
            dataVerification,
          );
          _afterRenderCell(settings, canvas, cell, drawCoord, renderedRect);
          continue;
        }
        final renderCell = _dynamicArrayRenderCell(sheet, drawCoord, cell);
        if (renderCell != null && renderCell.renderedText.isNotEmpty) {
          final conditionStyle = conditionStyles[drawCoord];
          if (conditionStyle?.icon case final icon?) {
            _drawConditionIcon(canvas, cellRect, icon);
          }
          final baseTextRect = _cellTextRect(
            sheet: sheet,
            metrics: metrics,
            settings: settings,
            row: drawCoord.row,
            column: drawCoord.column,
            cell: renderCell,
            cellRect: cellRect,
          );
          final textRect = conditionStyle?.icon == null
              ? baseTextRect
              : Rect.fromLTRB(
                  math.min(baseTextRect.left + 14, baseTextRect.right),
                  baseTextRect.top,
                  baseTextRect.right,
                  baseTextRect.bottom,
                );
          _drawCellText(
            canvas,
            textRect.deflate(2),
            renderCell,
            fontSize:
                (renderCell.fontSize ?? settings.defaultFontSize) *
                sheet.zoomRatio,
            textScale: sheet.zoomRatio,
            textColor:
                conditionStyle?.textColor ??
                (_cellHasExplicitForeground(renderCell)
                    ? null
                    : alternateForegrounds[drawCoord]),
          );
        }
        _afterRenderCell(settings, canvas, cell, drawCoord, renderedRect);
      }
    }
    canvas.restore();

    canvas.save();
    canvas.clipRect(_borderClip(clip), doAntiAlias: false);
    _drawRenderedCellBorders(
      canvas,
      sheet,
      metrics,
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
      borderCompute: borderCompute,
      mergeLookup: mergeLookup,
      renderedCellRects: renderedCellRects,
      skippedRenderCells: skippedRenderCells,
      clipBounds: clip,
    );
    canvas.restore();
  }

  void _drawRenderedCellBorders(
    Canvas canvas,
    FortuneSheet sheet,
    FortuneSheetMetrics metrics, {
    required int rowStart,
    required int rowEnd,
    required int columnStart,
    required int columnEnd,
    required Map<FortuneCellCoord, FortuneCellBorders> borderCompute,
    required Map<FortuneCellCoord, FortuneCellCoord> mergeLookup,
    required Map<FortuneCellCoord, Rect> renderedCellRects,
    required Set<FortuneCellCoord> skippedRenderCells,
    required Rect clipBounds,
  }) {
    final drawnMergedBorders = <FortuneCellCoord>{};
    final segments = <_BorderLineSegment>[];
    final slashSegments = <_BorderLineSegment>[];
    for (var r = rowStart; r <= rowEnd; r += 1) {
      final h = metrics.rowEnd(r) - metrics.rowStart(r);
      if (h <= 0) {
        continue;
      }
      for (var c = columnStart; c <= columnEnd; c += 1) {
        final w = metrics.columnEnd(c) - metrics.columnStart(c);
        if (w <= 0) {
          continue;
        }
        final coord = FortuneCellCoord(r, c);
        final mergeAnchor = mergeLookup[coord];
        final drawCoord = mergeAnchor ?? coord;
        if (mergeAnchor != null && !drawnMergedBorders.add(drawCoord)) {
          continue;
        }
        if (skippedRenderCells.contains(drawCoord)) {
          continue;
        }
        final rect = renderedCellRects[drawCoord];
        if (rect == null) {
          continue;
        }
        final cell = sheet.cells[drawCoord];
        final borders = _renderedCellBorders(
          sheet: sheet,
          coord: drawCoord,
          merge: cell?.merge,
          borderCompute: borderCompute,
        );
        if (borders != null) {
          _addCellBorderSegments(segments, slashSegments, rect, borders);
        }
      }
    }
    final mergedSegments = _mergeBorderSegments(segments);
    for (final segment in mergedSegments.where(
      (segment) => segment.horizontal,
    )) {
      _drawBorderLine(
        canvas,
        segment.side,
        segment.start,
        segment.end,
        horizontal: true,
        clipBounds: clipBounds,
      );
    }
    for (final segment in mergedSegments.where(
      (segment) => !segment.horizontal,
    )) {
      _drawBorderLine(
        canvas,
        segment.side,
        segment.start,
        segment.end,
        horizontal: false,
        clipBounds: clipBounds,
      );
    }
    _drawSolidBorderJoins(canvas, mergedSegments, clipBounds: clipBounds);
    for (final segment in slashSegments) {
      _drawBorderLine(
        canvas,
        segment.side,
        segment.start,
        segment.end,
        horizontal: false,
        clipBounds: clipBounds,
      );
    }
  }

  void _drawSolidBorderJoins(
    Canvas canvas,
    List<_BorderLineSegment> segments, {
    required Rect clipBounds,
  }) {
    final horizontalSegments = segments.where((segment) => segment.horizontal);
    final verticalSegments = segments.where((segment) => !segment.horizontal);
    for (final horizontal in horizontalSegments) {
      if (_borderDash(horizontal.side.style) != null) {
        continue;
      }
      for (final vertical in verticalSegments) {
        if (_borderDash(vertical.side.style) != null ||
            horizontal.side.color != vertical.side.color ||
            horizontal.side.style != vertical.side.style ||
            _borderWidthForSide(horizontal.side) !=
                _borderWidthForSide(vertical.side)) {
          continue;
        }
        final x = vertical.crossAxis;
        final y = horizontal.crossAxis;
        if (x < horizontal.mainStart - 0.001 ||
            x > horizontal.mainEnd + 0.001 ||
            y < vertical.mainStart - 0.001 ||
            y > vertical.mainEnd + 0.001) {
          continue;
        }
        _drawSolidBorderJoinSquare(
          canvas,
          horizontal.side,
          Offset(x, y),
          clipBounds: clipBounds,
        );
      }
    }
  }

  void _drawSolidBorderJoinSquare(
    Canvas canvas,
    FortuneBorderSide side,
    Offset point, {
    Rect? clipBounds,
  }) {
    final strokeWidth = _borderWidthForSide(side);
    if (clipBounds != null) {
      canvas.save();
      canvas.clipRect(
        _borderSegmentClip(clipBounds, strokeWidth, point, point),
        doAntiAlias: false,
      );
    }
    canvas.drawRect(
      Rect.fromCenter(
        center: Offset(point.dx - 0.5, point.dy - 0.5),
        width: strokeWidth,
        height: strokeWidth,
      ),
      Paint()
        ..color = side.color
        ..style = PaintingStyle.fill
        ..isAntiAlias = false,
    );
    if (clipBounds != null) {
      canvas.restore();
    }
  }

  void _addCellBorderSegments(
    List<_BorderLineSegment> segments,
    List<_BorderLineSegment> slashSegments,
    Rect rect,
    FortuneCellBorders borders,
  ) {
    if (borders.top case final side?) {
      segments.add(
        _BorderLineSegment(
          side: side,
          start: rect.topLeft,
          end: rect.topRight,
          horizontal: true,
        ),
      );
    }
    if (borders.right case final side?) {
      segments.add(
        _BorderLineSegment(
          side: side,
          start: rect.topRight,
          end: rect.bottomRight,
          horizontal: false,
        ),
      );
    }
    if (borders.bottom case final side?) {
      segments.add(
        _BorderLineSegment(
          side: side,
          start: rect.bottomLeft,
          end: rect.bottomRight,
          horizontal: true,
        ),
      );
    }
    if (borders.left case final side?) {
      segments.add(
        _BorderLineSegment(
          side: side,
          start: rect.topLeft,
          end: rect.bottomLeft,
          horizontal: false,
        ),
      );
    }
    if (borders.slash case final side?) {
      slashSegments.add(
        _BorderLineSegment(
          side: side,
          start: rect.bottomLeft,
          end: rect.topRight,
          horizontal: false,
        ),
      );
    }
  }

  List<_BorderLineSegment> _mergeBorderSegments(
    List<_BorderLineSegment> segments,
  ) {
    if (segments.length < 2) {
      return segments;
    }
    final sorted = [...segments]
      ..sort((a, b) {
        final keyCompare = _borderSegmentKey(a).compareTo(_borderSegmentKey(b));
        if (keyCompare != 0) {
          return keyCompare;
        }
        return a.mainStart.compareTo(b.mainStart);
      });
    final merged = <_BorderLineSegment>[];
    for (final segment in sorted) {
      if (merged.isEmpty) {
        merged.add(segment);
        continue;
      }
      final previous = merged.last;
      if (_borderSegmentKey(previous) != _borderSegmentKey(segment) ||
          segment.mainStart > previous.mainEnd + 0.001) {
        merged.add(segment);
        continue;
      }
      if (segment.mainEnd > previous.mainEnd) {
        merged[merged.length - 1] = previous.copyWithMainEnd(segment.mainEnd);
      }
    }
    return merged;
  }

  String _borderSegmentKey(_BorderLineSegment segment) {
    return '${segment.horizontal ? 'h' : 'v'}:'
        '${(segment.crossAxis * 1000).round()}:'
        '${segment.side.color.toARGB32()}:'
        '${segment.side.style}:'
        '${(_borderWidthForSide(segment.side) * 1000).round()}';
  }

  Rect _borderClip(Rect clip) {
    final strokeWidth = fortuneToolbarBorderStyleValues.fold<double>(
      4,
      (current, style) => math.max(current, _borderWidth(style)),
    );
    return clip.inflate(strokeWidth);
  }

  Rect _borderSegmentClip(
    Rect clip,
    double strokeWidth,
    Offset start,
    Offset end,
  ) {
    final minX = math.min(start.dx, end.dx);
    final maxX = math.max(start.dx, end.dx);
    final minY = math.min(start.dy, end.dy);
    final maxY = math.max(start.dy, end.dy);
    final leftOut = math.max(0, clip.left - minX);
    final rightOut = math.max(0, maxX - clip.right);
    final topOut = math.max(0, clip.top - minY);
    final bottomOut = math.max(0, maxY - clip.bottom);
    return Rect.fromLTRB(
      clip.left - math.max(0, strokeWidth - leftOut),
      clip.top - math.max(0, strokeWidth - topOut),
      clip.right + math.max(0, strokeWidth - rightOut),
      clip.bottom + math.max(0, strokeWidth - bottomOut),
    );
  }

  FortuneCell? _dynamicArrayRenderCell(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell? cell,
  ) {
    final text = _dynamicArrayComputeText(sheet.dynamicArrayCompute, coord);
    if (text == null) {
      return cell;
    }
    final source = cell ?? const FortuneCell();
    return source.copyWith(
      value: text,
      displayValue: text,
      rawDisplayValue: text,
      hasRawDisplayValue: true,
      inlineRuns: null,
    );
  }

  String? _dynamicArrayComputeText(Object? raw, FortuneCellCoord coord) {
    Object? entry;
    if (raw is Map) {
      entry = raw['${coord.row}_${coord.column}'];
    } else if (raw is List) {
      for (final item in raw) {
        if (item is Map &&
            _intValue(item['r']) == coord.row &&
            _intValue(item['c']) == coord.column) {
          entry = item;
          break;
        }
      }
    }
    if (entry is Map && entry.containsKey('v')) {
      final value = entry['v'];
      return value == null ? '' : '$value';
    }
    return null;
  }

  void _drawFrozenGuides(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final view = _frozenView(settings, metrics);
    final paint = Paint()
      ..color = const Color(0xffb7b7b7)
      ..strokeWidth = 1;
    if (view.rowFocus != null) {
      final y = _sheetDataTop(settings) + view.frozenHeight - 0.5;
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
    if (view.columnFocus != null) {
      final x = _sheetDataLeft(settings) + view.frozenWidth - 0.5;
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
    }
  }

  void _drawFreezeHandles(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final view = _frozenView(settings, metrics);
    final paint = Paint()..color = const Color(0xffdddddd);
    final headerTop = _sheetHeaderTop(settings);
    final dataTop = _sheetDataTop(settings);
    final headerLeft = _sheetHeaderLeft(settings);
    final dataLeft = _sheetDataLeft(settings);
    final columnHandleX = dataLeft + view.frozenWidth - 1.5;
    canvas.drawRect(
      Rect.fromLTWH(columnHandleX, headerTop, 3, settings.columnHeaderHeight),
      paint,
    );
    final rowHandleY = dataTop + view.frozenHeight - 1.5;
    canvas.drawRect(
      Rect.fromLTWH(headerLeft, rowHandleY, settings.rowHeaderWidth, 3),
      paint,
    );
  }

  void _drawFreezeDragLine(Canvas canvas, Size size) {
    final x = freezeDragLineX;
    final y = freezeDragLineY;
    final paint = Paint()
      ..color = const Color(0xffcccccc)
      ..strokeWidth = 3;
    if (x != null) {
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
    }
    if (y != null) {
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }

  void _drawResizeDragLine(Canvas canvas, Size size) {
    final x = resizeDragLineX;
    final y = resizeDragLineY;
    final paint = Paint()
      ..color = const Color(0xff0188fb)
      ..strokeWidth = 1;
    if (x != null) {
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
    }
    if (y != null) {
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }

  void _drawSelection(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    if (selection.row >= metrics.visibleDataRows.length ||
        selection.column >= metrics.visibleDataColumns.length) {
      return;
    }
    final sheet = workbook.activeSheet;
    final mergeLookup = _buildMergeLookup(sheet, settings);
    final selected = FortuneCellCoord(selection.row, selection.column);
    final anchor = mergeLookup[selected] ?? selected;
    final cell = sheet.cells[anchor];
    final rect = _mergedCellRect(
      settings: settings,
      metrics: metrics,
      anchor: anchor,
      merge: cell?.merge,
    );
    if (rect == null || rect.width <= 0 || rect.height <= 0) {
      return;
    }
    final activeRange = _expandRangeForMergedCells(
      FortuneRange(
        rowStart: selection.rowStart,
        rowEnd: selection.normalizedRowEnd,
        columnStart: selection.columnStart,
        columnEnd: selection.normalizedColumnEnd,
      ),
      sheet,
    );
    for (final range in _selectionSaveRanges()) {
      if (_sameRange(range, activeRange)) {
        continue;
      }
      for (final piece in _rangePieces(range, size, settings, metrics)) {
        _drawSelectionRangePiece(canvas, piece);
      }
    }
    final rangePieces = _selectionRangePieces(size, settings, metrics);
    for (final piece in rangePieces) {
      _drawSelectionFocusPiece(canvas, piece, rect);
    }
    for (final piece in rangePieces) {
      _drawSelectionRangePiece(canvas, piece);
    }
    final handleRect = rangePieces.isNotEmpty ? rangePieces.last.rect : rect;
    _drawSelectionFillHandle(canvas, handleRect);
    _drawCopiedRange(canvas, size, settings, metrics, sheet);
  }

  void _drawCopiedRange(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
    FortuneSheet sheet,
  ) {
    final range = copiedCellRange;
    if (range == null) {
      return;
    }
    final expandedRange = _expandRangeForMergedCells(range, sheet);
    for (final piece in _rangePieces(expandedRange, size, settings, metrics)) {
      final visible = piece.rect.intersect(piece.clip);
      if (visible.isEmpty) {
        continue;
      }
      canvas.save();
      canvas.clipRect(piece.clip);
      _drawDashedSelectionOutline(
        canvas,
        piece.rect,
        copiedCellsAreCut
            ? fortuneSheetCutSelectionColor
            : fortuneSheetSelectionColor,
      );
      canvas.restore();
    }
  }

  List<_SelectionRangePiece> _selectionRangePieces(
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    return _rangePieces(
      _expandRangeForMergedCells(
        FortuneRange(
          rowStart: selection.rowStart,
          rowEnd: selection.normalizedRowEnd,
          columnStart: selection.columnStart,
          columnEnd: selection.normalizedColumnEnd,
        ),
        workbook.activeSheet,
      ),
      size,
      settings,
      metrics,
    );
  }

  List<_SelectionRangePiece> _rangePieces(
    FortuneRange range,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final view = _frozenView(settings, metrics);
    final rowRanges = _splitRangeAxis(
      range.rowStart,
      range.rowEnd,
      view.rowFocus,
    );
    final columnRanges = _splitRangeAxis(
      range.columnStart,
      range.columnEnd,
      view.columnFocus,
    );
    final pieces = <_SelectionRangePiece>[];
    for (final rowRange in rowRanges) {
      for (final columnRange in columnRanges) {
        final pieceRange = FortuneRange(
          rowStart: rowRange.start,
          rowEnd: rowRange.end,
          columnStart: columnRange.start,
          columnEnd: columnRange.end,
        );
        final rect = _rangeRect(pieceRange, settings, metrics);
        if (rect == null) {
          continue;
        }
        pieces.add(
          _SelectionRangePiece(
            rect: rect,
            clip: _rangePieceClip(
              rowRange.isFrozen,
              columnRange.isFrozen,
              size,
              settings,
              view,
            ),
          ),
        );
      }
    }
    return pieces;
  }

  List<_SplitAxisRange> _splitRangeAxis(int start, int end, int? focus) {
    if (focus == null) {
      return [_SplitAxisRange(start: start, end: end, isFrozen: false)];
    }
    if (end <= focus) {
      return [_SplitAxisRange(start: start, end: end, isFrozen: true)];
    }
    if (start > focus) {
      return [_SplitAxisRange(start: start, end: end, isFrozen: false)];
    }
    return [
      _SplitAxisRange(start: start, end: focus, isFrozen: true),
      _SplitAxisRange(start: focus + 1, end: end, isFrozen: false),
    ];
  }

  Rect _rangePieceClip(
    bool frozenRows,
    bool frozenColumns,
    Size size,
    FortuneSettings settings,
    _FrozenSheetView view,
  ) {
    final left =
        _sheetDataLeft(settings) + (frozenColumns ? 0 : view.frozenWidth);
    final top = _sheetDataTop(settings) + (frozenRows ? 0 : view.frozenHeight);
    final right = frozenColumns
        ? _sheetDataLeft(settings) + view.frozenWidth
        : size.width;
    final bottom = frozenRows
        ? _sheetDataTop(settings) + view.frozenHeight
        : size.height;
    return Rect.fromLTRB(left, top, right, bottom);
  }

  void _drawSelectionRangePiece(Canvas canvas, _SelectionRangePiece piece) {
    final visible = piece.rect.intersect(piece.clip);
    if (visible.isEmpty) {
      return;
    }
    canvas.save();
    canvas.clipRect(piece.clip);
    _drawSelectionBox(canvas, piece.rect);
    canvas.restore();
  }

  void _drawSelectionFocusPiece(
    Canvas canvas,
    _SelectionRangePiece piece,
    Rect focusRect,
  ) {
    final visible = focusRect.intersect(piece.clip);
    if (visible.isEmpty) {
      return;
    }
    canvas.save();
    canvas.clipRect(piece.clip);
    final focusFillRect = _selectionContentRect(focusRect);
    if (focusFillRect.width > 0 && focusFillRect.height > 0) {
      canvas.drawRect(
        focusFillRect,
        Paint()..color = fortuneSheetSelectionFocusFillColor,
      );
    }
    canvas.restore();
  }

  void _drawSelectionBox(Canvas canvas, Rect rect) {
    final contentRect = _selectionContentRect(rect);
    if (contentRect.width <= 0 || contentRect.height <= 0) {
      return;
    }
    final selectionRect = Rect.fromLTRB(
      contentRect.left,
      contentRect.top,
      contentRect.right,
      contentRect.bottom,
    );
    canvas.drawRect(
      selectionRect,
      Paint()..color = fortuneSheetSelectionFillColor,
    );
    _drawOnePixelRectOutline(canvas, selectionRect, fortuneSheetSelectionColor);
    final innerRect = selectionRect.deflate(1);
    _drawOnePixelRectOutline(
      canvas,
      innerRect,
      fortuneSheetSelectionInnerBorderColor,
    );
  }

  void _drawSelectionFillHandle(Canvas canvas, Rect rect) {
    final contentRect = _selectionContentRect(rect);
    if (contentRect.width <= 0 || contentRect.height <= 0) {
      return;
    }
    final handleRect = Rect.fromLTWH(
      contentRect.right - 3,
      contentRect.bottom - 3,
      6,
      6,
    );
    final handleBorderRect = handleRect.inflate(1);
    canvas.drawRect(
      handleBorderRect,
      Paint()..color = fortuneSheetSelectionInnerBorderColor,
    );
    canvas.drawRect(handleRect, Paint()..color = fortuneSheetSelectionColor);
  }

  void _drawPresences(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final presences = _visiblePresenceRanges(size, settings, metrics);
    if (presences.isEmpty) {
      return;
    }
    for (final presence in presences) {
      for (final piece in presence.pieces) {
        final visible = piece.rect.intersect(piece.clip);
        if (visible.isEmpty) {
          continue;
        }
        canvas.save();
        canvas.clipRect(piece.clip);
        _drawOnePixelRectOutline(
          canvas,
          _selectionContentRect(piece.rect),
          presence.color,
        );
        canvas.restore();
      }
      if (presence.label.isEmpty || presence.pieces.isEmpty) {
        continue;
      }
      final labelRect = _presenceLabelRect(
        presence.pieces.last.rect,
        presence.row,
        size,
      );
      if (labelRect.width <= 0 || labelRect.height <= 0) {
        continue;
      }
      canvas.drawRect(labelRect, Paint()..color = presence.color);
      _drawText(
        canvas,
        presence.label,
        labelRect.deflate(3),
        fontSize: 11,
        color: const Color(0xffffffff),
      );
    }
  }

  Rect _presenceLabelRect(Rect cellRect, int row, Size size) {
    final width = math.min(
      math.max(24.0, cellRect.width + 1),
      math.max(0.0, size.width - cellRect.left),
    );
    final top = row == 0
        ? cellRect.bottom
        : math.max(0.0, cellRect.top - _fortunePresenceLabelHeight);
    return Rect.fromLTWH(
      cellRect.left,
      top,
      width,
      _fortunePresenceLabelHeight,
    );
  }

  List<_PresenceRange> _visiblePresenceRanges(
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheet = workbook.activeSheet;
    final raw = workbook.extraFields['presences'];
    if (raw is! Iterable) {
      return const <_PresenceRange>[];
    }
    final visible = <_PresenceRange>[];
    for (final item in raw) {
      if (item is! Map) {
        continue;
      }
      if ('${item['sheetId'] ?? ''}' != sheet.id) {
        continue;
      }
      final selection = item['selection'];
      if (selection is! Map) {
        continue;
      }
      final row = _intValue(selection['r']);
      final column = _intValue(selection['c']);
      if (row == null || column == null) {
        continue;
      }
      final range = _expandRangeForMergedCells(
        FortuneRange(
          rowStart: row,
          rowEnd: row,
          columnStart: column,
          columnEnd: column,
        ),
        sheet,
      );
      final pieces = _rangePieces(range, size, settings, metrics);
      if (pieces.isEmpty) {
        continue;
      }
      final color =
          FortuneSheetCodec.parseColor('${item['color'] ?? ''}') ??
          _fortunePresenceDefaultColor;
      visible.add(
        _PresenceRange(
          row: row,
          column: column,
          label: '${item['username'] ?? ''}',
          color: color,
          pieces: pieces,
        ),
      );
    }
    return visible;
  }

  void _drawOnePixelRectOutline(Canvas canvas, Rect rect, Color color) {
    if (rect.width <= 0 || rect.height <= 0) {
      return;
    }
    final paint = Paint()..color = color;
    canvas.drawRect(Rect.fromLTWH(rect.left, rect.top, rect.width, 1), paint);
    canvas.drawRect(
      Rect.fromLTWH(rect.left, rect.bottom - 1, rect.width, 1),
      paint,
    );
    canvas.drawRect(Rect.fromLTWH(rect.left, rect.top, 1, rect.height), paint);
    canvas.drawRect(
      Rect.fromLTWH(rect.right - 1, rect.top, 1, rect.height),
      paint,
    );
  }

  void _drawDashedSelectionOutline(Canvas canvas, Rect rect, Color color) {
    final contentRect = _selectionContentRect(rect);
    if (contentRect.width <= 0 || contentRect.height <= 0) {
      return;
    }
    final selectionRect = Rect.fromLTRB(
      rect.left - 1,
      rect.top - 1,
      contentRect.right + 1,
      contentRect.bottom + 1,
    );
    final paint = Paint()..color = color;
    _drawDashedHorizontalLine(
      canvas,
      selectionRect.left,
      selectionRect.right,
      selectionRect.top,
      paint,
    );
    _drawDashedHorizontalLine(
      canvas,
      selectionRect.left,
      selectionRect.right,
      selectionRect.bottom - 1,
      paint,
    );
    _drawDashedVerticalLine(
      canvas,
      selectionRect.left,
      selectionRect.top,
      selectionRect.bottom,
      paint,
    );
    _drawDashedVerticalLine(
      canvas,
      selectionRect.right - 1,
      selectionRect.top,
      selectionRect.bottom,
      paint,
    );
  }

  void _drawDashedHorizontalLine(
    Canvas canvas,
    double left,
    double right,
    double y,
    Paint paint,
  ) {
    const dash = 4.0;
    const gap = 3.0;
    for (var x = left; x < right; x += dash + gap) {
      final width = math.min(dash, right - x);
      canvas.drawRect(Rect.fromLTWH(x, y, width, 2), paint);
    }
  }

  void _drawDashedVerticalLine(
    Canvas canvas,
    double x,
    double top,
    double bottom,
    Paint paint,
  ) {
    const dash = 4.0;
    const gap = 3.0;
    for (var y = top; y < bottom; y += dash + gap) {
      final height = math.min(dash, bottom - y);
      canvas.drawRect(Rect.fromLTWH(x, y, 2, height), paint);
    }
  }

  Rect _selectionContentRect(Rect rect) {
    return Rect.fromLTWH(
      rect.left,
      rect.top,
      math.max(0, rect.width - 1),
      math.max(0, rect.height - 1),
    );
  }

  Rect? _rangeRect(
    FortuneRange range,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final rowStart = range.rowStart;
    final rowEnd = range.rowEnd;
    final columnStart = range.columnStart;
    final columnEnd = range.columnEnd;
    if (rowStart < 0 ||
        columnStart < 0 ||
        rowStart >= metrics.visibleDataRows.length ||
        columnStart >= metrics.visibleDataColumns.length) {
      return null;
    }
    final clampedRowEnd = math.min(rowEnd, metrics.visibleDataRows.length - 1);
    final clampedColumnEnd = math.min(
      columnEnd,
      metrics.visibleDataColumns.length - 1,
    );
    final startX = metrics.columnStart(columnStart);
    final endX = metrics.columnEnd(clampedColumnEnd);
    final startY = metrics.rowStart(rowStart);
    final endY = metrics.rowEnd(clampedRowEnd);
    if (endX <= startX || endY <= startY) {
      return null;
    }
    return Rect.fromLTWH(
      _visualCellLeft(columnStart, settings, metrics),
      _visualCellTop(rowStart, settings, metrics),
      endX - startX,
      endY - startY,
    );
  }

  List<FortuneRange> _selectionSaveRanges() {
    final raw = workbook.activeSheet.selectionSave;
    if (raw is! List) {
      return <FortuneRange>[];
    }
    final ranges = <FortuneRange>[];
    for (final item in raw) {
      if (item is! Map) {
        continue;
      }
      final row = item['row'];
      final column = item['column'];
      if (row is! List ||
          row.length < 2 ||
          column is! List ||
          column.length < 2) {
        continue;
      }
      final rowStart = _intValue(row[0]);
      final rowEnd = _intValue(row[1]);
      final columnStart = _intValue(column[0]);
      final columnEnd = _intValue(column[1]);
      if (rowStart == null ||
          rowEnd == null ||
          columnStart == null ||
          columnEnd == null) {
        continue;
      }
      ranges.add(
        _expandRangeForMergedCells(
          FortuneRange(
            rowStart: math.min(rowStart, rowEnd),
            rowEnd: math.max(rowStart, rowEnd),
            columnStart: math.min(columnStart, columnEnd),
            columnEnd: math.max(columnStart, columnEnd),
          ),
          workbook.activeSheet,
        ),
      );
    }
    return ranges;
  }

  List<FortuneRange> _selectedHeaderRanges(FortuneSheetMetrics metrics) {
    final ranges = <FortuneRange>[];
    for (final range in _selectionSaveRanges()) {
      ranges.add(range);
    }
    if (selection.row < metrics.visibleDataRows.length &&
        selection.column < metrics.visibleDataColumns.length) {
      final activeRange = FortuneRange(
        rowStart: selection.rowStart,
        rowEnd: selection.normalizedRowEnd,
        columnStart: selection.columnStart,
        columnEnd: selection.normalizedColumnEnd,
      );
      if (!ranges.any((range) => _sameRange(range, activeRange))) {
        ranges.add(activeRange);
      }
    }
    return ranges;
  }

  FortuneRange _expandRangeForMergedCells(
    FortuneRange range,
    FortuneSheet sheet,
  ) {
    var expanded = FortuneRange(
      rowStart: math.min(range.rowStart, range.rowEnd),
      rowEnd: math.max(range.rowStart, range.rowEnd),
      columnStart: math.min(range.columnStart, range.columnEnd),
      columnEnd: math.max(range.columnStart, range.columnEnd),
    );
    var changed = true;
    while (changed) {
      changed = false;
      for (final cell in sheet.cells.values) {
        final merge = cell.merge;
        if (merge == null || (merge.rowSpan <= 1 && merge.columnSpan <= 1)) {
          continue;
        }
        final mergeRange = FortuneRange(
          rowStart: merge.row,
          rowEnd: merge.row + (merge.rowSpan < 1 ? 1 : merge.rowSpan) - 1,
          columnStart: merge.column,
          columnEnd:
              merge.column + (merge.columnSpan < 1 ? 1 : merge.columnSpan) - 1,
        );
        if (!_rangesIntersect(expanded, mergeRange)) {
          continue;
        }
        final next = FortuneRange(
          rowStart: math.min(expanded.rowStart, mergeRange.rowStart),
          rowEnd: math.max(expanded.rowEnd, mergeRange.rowEnd),
          columnStart: math.min(expanded.columnStart, mergeRange.columnStart),
          columnEnd: math.max(expanded.columnEnd, mergeRange.columnEnd),
        );
        if (!_sameRange(expanded, next)) {
          expanded = next;
          changed = true;
        }
      }
    }
    return expanded;
  }

  bool _rangesIntersect(FortuneRange a, FortuneRange b) {
    return a.rowStart <= b.rowEnd &&
        a.rowEnd >= b.rowStart &&
        a.columnStart <= b.columnEnd &&
        a.columnEnd >= b.columnStart;
  }

  bool _sameRange(FortuneRange a, FortuneRange b) {
    return a.rowStart == b.rowStart &&
        a.rowEnd == b.rowEnd &&
        a.columnStart == b.columnStart &&
        a.columnEnd == b.columnEnd;
  }

  Map<FortuneCellCoord, FortuneCellCoord> _buildMergeLookup(
    FortuneSheet sheet,
    FortuneSettings settings,
  ) {
    final lookup = <FortuneCellCoord, FortuneCellCoord>{};
    for (final entry in sheet.cells.entries) {
      final merge = entry.value.merge;
      if (merge == null || (merge.rowSpan <= 1 && merge.columnSpan <= 1)) {
        continue;
      }
      final anchor = FortuneCellCoord(merge.row, merge.column);
      final rowEnd = math.min(settings.row, merge.row + merge.rowSpan);
      final columnEnd = math.min(
        settings.column,
        merge.column + merge.columnSpan,
      );
      for (var r = math.max(0, merge.row); r < rowEnd; r += 1) {
        for (var c = math.max(0, merge.column); c < columnEnd; c += 1) {
          lookup[FortuneCellCoord(r, c)] = anchor;
        }
      }
    }
    return lookup;
  }

  Rect? _mergedCellRect({
    required FortuneSettings settings,
    required FortuneSheetMetrics metrics,
    required FortuneCellCoord anchor,
    required FortuneCellMerge? merge,
  }) {
    if (anchor.row < 0 ||
        anchor.column < 0 ||
        anchor.row >= metrics.visibleDataRows.length ||
        anchor.column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final rowSpan = math.max(1, merge?.rowSpan ?? 1);
    final columnSpan = math.max(1, merge?.columnSpan ?? 1);
    final rowEndIndex = math.min(
      metrics.visibleDataRows.length - 1,
      anchor.row + rowSpan - 1,
    );
    final columnEndIndex = math.min(
      metrics.visibleDataColumns.length - 1,
      anchor.column + columnSpan - 1,
    );
    final startX = metrics.columnStart(anchor.column);
    final endX = metrics.columnEnd(columnEndIndex);
    final startY = metrics.rowStart(anchor.row);
    final endY = metrics.rowEnd(rowEndIndex);
    if (endX <= startX || endY <= startY) {
      return null;
    }
    return Rect.fromLTWH(
      _visualCellLeft(anchor.column, settings, metrics),
      _visualCellTop(anchor.row, settings, metrics),
      endX - startX,
      endY - startY,
    );
  }

  FortuneCellBorders? _renderedCellBorders({
    required FortuneSheet sheet,
    required FortuneCellCoord coord,
    required FortuneCellMerge? merge,
    required Map<FortuneCellCoord, FortuneCellBorders> borderCompute,
  }) {
    if (merge == null || (merge.rowSpan <= 1 && merge.columnSpan <= 1)) {
      return borderCompute[coord];
    }
    final rowStart = merge.row;
    final columnStart = merge.column;
    final rowSpan = merge.rowSpan < 1 ? 1 : merge.rowSpan;
    final columnSpan = merge.columnSpan < 1 ? 1 : merge.columnSpan;
    final mergeRowEnd = merge.row + rowSpan - 1;
    final mergeColumnEnd = merge.column + columnSpan - 1;
    final rowEnd = mergeRowEnd < workbook.settings.row
        ? mergeRowEnd
        : workbook.settings.row - 1;
    final columnEnd = mergeColumnEnd < workbook.settings.column
        ? mergeColumnEnd
        : workbook.settings.column - 1;
    FortuneBorderSide? top;
    FortuneBorderSide? right;
    FortuneBorderSide? bottom;
    FortuneBorderSide? left;
    for (var column = columnStart; column <= columnEnd; column += 1) {
      top ??= borderCompute[FortuneCellCoord(rowStart, column)]?.top;
      bottom ??= borderCompute[FortuneCellCoord(rowEnd, column)]?.bottom;
    }
    for (var row = rowStart; row <= rowEnd; row += 1) {
      left ??= borderCompute[FortuneCellCoord(row, columnStart)]?.left;
      right ??= borderCompute[FortuneCellCoord(row, columnEnd)]?.right;
    }
    final slash = borderCompute[coord]?.slash;
    final borders = FortuneCellBorders(
      top: top,
      right: right,
      bottom: bottom,
      left: left,
      slash: slash,
    );
    return borders.isEmpty ? null : borders;
  }

  void _drawSheetTabs(Canvas canvas, Size size, FortuneSettings settings) {
    if (!settings.showSheetTabs) {
      return;
    }
    final statTop = size.height - settings.statisticBarHeight;
    final tabTop = statTop - settings.effectiveSheetBarHeight;
    if (tabTop < settings.effectiveToolbarHeight) {
      return;
    }
    canvas.drawRect(
      Rect.fromLTWH(0, tabTop, size.width, settings.effectiveSheetBarHeight),
      Paint()..color = const Color(0xfffafafc),
    );
    _line(
      canvas,
      Offset(0, tabTop),
      Offset(size.width, tabTop),
      const Color(0xffd4d4d4),
    );

    if (settings.allowEdit) {
      _drawText(
        canvas,
        '+',
        Rect.fromLTWH(0, tabTop + 1, 29, 29),
        fontSize: 18,
        align: TextAlign.center,
        color: const Color(0xff444444),
      );
    }
    _drawSheetTabScrollButton(
      canvas,
      Rect.fromLTWH(30, tabTop + 1, 14, 29),
      '<',
    );
    _drawSheetTabScrollButton(
      canvas,
      Rect.fromLTWH(44, tabTop + 1, 14, 29),
      '>',
    );

    final viewport = Rect.fromLTWH(
      58,
      tabTop + 1,
      math.max(0, size.width - 58),
      29,
    );
    if (settings.allowEdit && _sheetTabsTotalWidth() <= viewport.width) {
      _drawSheetTabScrollButton(
        canvas,
        Rect.fromLTWH(30, tabTop + 1, 28, 29),
        'S',
      );
    }
    canvas.save();
    canvas.clipRect(viewport);
    var x = viewport.left - sheetTabScrollOffset;
    for (var i = 0; i < workbook.sheets.length; i += 1) {
      final sheet = workbook.sheets[i];
      if (sheet.hide == 1) {
        continue;
      }
      final active = i == workbook.activeSheetIndex;
      final width = math.max(72.0, (sheet.name.length * 8 + 32).toDouble());
      final rect = Rect.fromLTWH(x, tabTop + 1, width, 29);
      if (rect.right < viewport.left) {
        x += width - 1;
        continue;
      }
      if (rect.left > viewport.right) {
        break;
      }
      canvas.drawRect(
        rect,
        Paint()
          ..color = active ? const Color(0xffefefef) : const Color(0xfffafafc),
      );
      _line(canvas, rect.topLeft, rect.bottomLeft, const Color(0xffe0e0e0));
      _line(canvas, rect.topRight, rect.bottomRight, const Color(0xffe0e0e0));
      _drawText(
        canvas,
        sheet.name,
        rect.deflate(6),
        fontSize: 13,
        color: active ? const Color(0xff222222) : const Color(0xff676464),
      );
      _drawText(
        canvas,
        'v',
        Rect.fromLTWH(rect.right - 18, rect.top, 15, rect.height),
        fontSize: 10,
        align: TextAlign.center,
        color: hoveredSheetTabOptionsIndex == i
            ? fortuneSheetTabOptionsHoverColor
            : fortuneSheetTabOptionsColor,
      );
      if (sheet.color != null) {
        canvas.drawRect(
          Rect.fromLTWH(rect.left, rect.bottom - 3, rect.width, 2),
          Paint()
            ..color =
                FortuneSheetCodec.parseColor(sheet.color) ??
                const Color(0xff0188fb),
        );
      }
      x += width - 1;
    }
    canvas.restore();
    _drawSheetTabScrollBoundaries(canvas, viewport);
    _drawSheetTabDragInsert(canvas, tabTop, settings);

    canvas.drawRect(
      Rect.fromLTWH(0, statTop, size.width, settings.statisticBarHeight),
      Paint()..color = const Color(0xffffffff),
    );
    _line(
      canvas,
      Offset(0, statTop),
      Offset(size.width, statTop),
      const Color(0xffd4d4d4),
    );
    _drawSelectionInfo(canvas, size, settings, statTop);
    _drawBottomAddRowsButton(canvas, size, settings);
  }

  void _drawSelectionInfo(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    double statTop,
  ) {
    final items = _selectionInfoItems();
    if (items.isEmpty) {
      return;
    }
    var right = size.width - fortuneSelectionInfoRightPadding;
    for (final item in items.reversed) {
      final width = _selectionInfoItemWidth(item);
      final rect = Rect.fromLTWH(
        right - width,
        statTop,
        width,
        settings.statisticBarHeight,
      );
      if (rect.right <= 0) {
        break;
      }
      _drawText(
        canvas,
        item,
        rect,
        fontSize: 12,
        color: const Color(0xff666666),
        align: TextAlign.left,
      );
      right = rect.left - fortuneSelectionInfoItemGap;
    }
  }

  List<String> _selectionInfoItems() {
    final info = calcSelectionInfo(workbook.activeSheet);
    final numberC = info['numberC'];
    final count = info['count'];
    final items = <String>[];
    if (count is num && count != 0) {
      items.add('${locale.selectionCount}: $count');
    }
    if (numberC is! num || numberC == 0) {
      return items;
    }
    void addTruthy(String key, String label) {
      final value = info[key];
      if (_selectionInfoTruthy(value)) {
        items.add('$label: $value');
      }
    }

    addTruthy('sum', locale.selectionSum);
    addTruthy('average', locale.selectionAverage);
    addTruthy('max', locale.selectionMax);
    addTruthy('min', locale.selectionMin);
    return items;
  }

  bool _selectionInfoTruthy(Object? value) {
    if (value == null) {
      return false;
    }
    if (value is num) {
      return value != 0;
    }
    final text = value.toString();
    return text.isNotEmpty;
  }

  double _selectionInfoItemWidth(String item) {
    return math.max(42.0, item.length * fortuneSelectionInfoEstimatedCharWidth);
  }

  void _drawSheetTabScrollBoundaries(Canvas canvas, Rect viewport) {
    if (_sheetTabsTotalWidth() <= viewport.width) {
      return;
    }
    final leftRect = Rect.fromLTWH(
      viewport.left,
      viewport.top,
      fortuneSheetTabBoundaryWidth,
      viewport.height,
    );
    final rightRect = Rect.fromLTWH(
      viewport.right - fortuneSheetTabBoundaryWidth,
      viewport.top,
      fortuneSheetTabBoundaryWidth,
      viewport.height,
    );
    if (sheetTabScrollOffset > 0) {
      canvas.drawRect(
        leftRect,
        Paint()
          ..shader = ui.Gradient.linear(
            leftRect.centerLeft,
            leftRect.centerRight,
            const [
              fortuneSheetTabBoundaryStartColor,
              fortuneSheetTabBoundaryEndColor,
            ],
          ),
      );
      return;
    }
    canvas.drawRect(
      rightRect,
      Paint()
        ..shader = ui.Gradient.linear(
          rightRect.centerRight,
          rightRect.centerLeft,
          const [
            fortuneSheetTabBoundaryStartColor,
            fortuneSheetTabBoundaryEndColor,
          ],
        ),
    );
  }

  void _drawBottomAddRowsButton(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
  ) {
    if (!settings.allowEdit) {
      return;
    }
    final backTopRect = fortuneBottomBackTopButtonRect(size, settings);
    if (backTopRect.width >= 48) {
      final rrect = RRect.fromRectAndRadius(
        backTopRect,
        const Radius.circular(3),
      );
      canvas.drawRRect(rrect, Paint()..color = const Color(0xffffffff));
      canvas.drawRRect(
        rrect,
        Paint()
          ..color = const Color(0xffd0d0d0)
          ..style = PaintingStyle.stroke,
      );
      _drawText(
        canvas,
        locale.backToTop,
        backTopRect.deflate(2),
        fontSize: 12,
        align: TextAlign.center,
        color: const Color(0xff444444),
      );
    }
    final count = workbook.activeSheet.addRows ?? settings.addRows;
    if (count <= 0) {
      return;
    }
    final rect = fortuneBottomAddRowsButtonRect(size, settings);
    if (rect.width < 48) {
      return;
    }
    final rrect = RRect.fromRectAndRadius(rect, const Radius.circular(3));
    canvas.drawRRect(rrect, Paint()..color = const Color(0xffffffff));
    canvas.drawRRect(
      rrect,
      Paint()
        ..color = const Color(0xffd0d0d0)
        ..style = PaintingStyle.stroke,
    );
    _drawText(
      canvas,
      'Add $count rows',
      rect.deflate(2),
      fontSize: 12,
      align: TextAlign.center,
      color: const Color(0xff444444),
    );
  }

  void _drawZoomControl(Canvas canvas, Size size, FortuneSettings settings) {
    if (!settings.showSheetTabs) {
      return;
    }
    final statTop = size.height - settings.statisticBarHeight;
    if (statTop < settings.effectiveToolbarHeight) {
      return;
    }
    final controlRect = fortuneZoomControlRect(size, settings);
    final outRect = fortuneZoomOutButtonRect(size, settings);
    final ratioRect = fortuneZoomRatioButtonRect(size, settings);
    final inRect = fortuneZoomInButtonRect(size, settings);
    final activeZoom = workbook.activeSheet.zoomRatio <= 0
        ? 1.0
        : workbook.activeSheet.zoomRatio;

    if (zoomMenuOpen) {
      final menuRect = fortuneZoomPresetMenuRect(size, settings);
      _drawShadowBox(
        canvas,
        menuRect,
        radius: 4,
        border: const Color(0xffdadce0),
      );
      for (var index = 0; index < fortuneZoomPresetValues.length; index += 1) {
        final value = fortuneZoomPresetValues[index];
        final itemRect = fortuneZoomPresetItemRect(size, settings, index);
        if ((value * 10).round() == (activeZoom * 10).round()) {
          canvas.drawRect(
            itemRect.deflate(1),
            Paint()..color = const Color(0xffe8f0fe),
          );
        }
        _drawText(
          canvas,
          '${(value * 100).round()}%',
          _menuLabelRect(itemRect, 8),
          fontSize: 12,
          align: TextAlign.center,
          color: const Color(0xff333333),
        );
      }
    }

    canvas.drawRRect(
      RRect.fromRectAndRadius(controlRect, const Radius.circular(4)),
      Paint()..color = const Color(0xffffffff),
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(controlRect, const Radius.circular(4)),
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0xffdadce0),
    );
    _line(
      canvas,
      Offset(ratioRect.left, ratioRect.top + 4),
      Offset(ratioRect.left, ratioRect.bottom - 4),
      const Color(0xffe0e0e0),
    );
    _line(
      canvas,
      Offset(inRect.left, inRect.top + 4),
      Offset(inRect.left, inRect.bottom - 4),
      const Color(0xffe0e0e0),
    );
    _drawText(
      canvas,
      '-',
      outRect,
      fontSize: 18,
      align: TextAlign.center,
      color: const Color(0xff444444),
    );
    _drawText(
      canvas,
      '${(activeZoom * 100).round()}%',
      ratioRect,
      fontSize: 12,
      align: TextAlign.center,
      color: const Color(0xff333333),
    );
    _drawText(
      canvas,
      '+',
      inRect,
      fontSize: 18,
      align: TextAlign.center,
      color: const Color(0xff444444),
    );
  }

  void _drawSheetTabDragInsert(
    Canvas canvas,
    double tabTop,
    FortuneSettings settings,
  ) {
    final x = sheetTabDragInsertX;
    if (x == null) {
      return;
    }
    final paint = Paint()
      ..color = const Color(0xff0188fb)
      ..strokeWidth = 2;
    canvas.drawLine(
      Offset(x, tabTop + 3),
      Offset(x, tabTop + settings.effectiveSheetBarHeight - 3),
      paint,
    );
  }

  void _drawSheetTabScrollButton(Canvas canvas, Rect rect, String label) {
    _drawText(
      canvas,
      label,
      rect,
      fontSize: 13,
      align: TextAlign.center,
      color: const Color(0xff444444),
    );
  }

  double _sheetTabsTotalWidth() {
    var total = 0.0;
    for (final sheet in workbook.sheets) {
      if (sheet.hide == 1) {
        continue;
      }
      total += math.max(72.0, (sheet.name.length * 8 + 32).toDouble()) - 1;
    }
    return math.max(0, total);
  }

  Rect? _toolbarItemRectFor(String itemKey, double width) {
    final settings = workbook.settings;
    final items = fortuneToolbarItemsWithCustom(
      settings.toolbarItems,
      settings.customToolbarItems,
    );
    for (final entry in fortuneVisibleToolbarItemRects(width, items: items)) {
      if (entry.key == itemKey) return entry.value;
    }
    return null;
  }

  List<String> _toolbarPopupOptionsFor(String key, double width) {
    if (key == fortuneToolbarFontPopupKey) {
      return [
        for (final family in workbook.settings.fontFamilies)
          fortuneToolbarFontFamilyCommand(family),
      ];
    }
    if (key == fortuneToolbarMorePopupKey) {
      final settings = workbook.settings;
      return fortuneToolbarOverflowItems(
        width,
        items: fortuneToolbarItemsWithCustom(
          settings.toolbarItems,
          settings.customToolbarItems,
        ),
      );
    }
    if (key == fortuneToolbarFreezePopupKey) {
      return fortuneFreezeMenuItems;
    }
    if (key == fortuneToolbarCommentCommand) {
      final sheet = workbook.activeSheet;
      final coord = sheet.mergeAnchorFor(
        FortuneCellCoord(selection.row, selection.column),
      );
      return sheet.cells[coord]?.comment == null
          ? fortuneToolbarCommentEmptyPopupCommands
          : fortuneToolbarCommentExistingPopupCommands;
    }
    return fortuneToolbarPopupItems[key] ??
        const ['Default', 'Arial', '10', '12', '14', '18'];
  }

  void _drawToolbarPopup(Canvas canvas, Size size) {
    _toolbarPopupHoverViewportRect = null;
    if (toolbarPopupKey == null) {
      return;
    }
    final itemRect = _toolbarItemRectFor(toolbarPopupKey!, size.width);
    final options = _toolbarPopupOptionsFor(toolbarPopupKey!, size.width);
    final popupWidth = fortuneToolbarPopupWidthFor(
      toolbarPopupKey!,
      options: options,
      viewportWidth: size.width,
    );
    final left = fortuneToolbarPopupLeftFor(
      key: toolbarPopupKey!,
      itemRect: itemRect,
      viewportWidth: size.width,
      popupWidth: popupWidth,
    );
    final popupContentTopPadding = fortuneToolbarPopupContentTopPaddingFor(
      toolbarPopupKey!,
    );
    final popupRowHeight = fortuneToolbarPopupRowHeightFor(toolbarPopupKey!);
    final naturalHeight = fortuneToolbarPopupHeightFor(
      toolbarPopupKey!,
      options,
    );
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final maxScrollOffset = math.max(0.0, naturalHeight - visibleHeight);
    final scrollOffset = toolbarPopupScrollOffset.clamp(0.0, maxScrollOffset);
    final rect = Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop,
      popupWidth,
      visibleHeight,
    );
    final contentRect = Rect.fromLTWH(
      rect.left,
      rect.top - scrollOffset,
      rect.width,
      naturalHeight,
    );
    final contentViewportRect = fortuneToolbarPopupContentViewportRect(
      rect,
      scrollOffset,
      maxScrollOffset,
    );
    _toolbarPopupHoverViewportRect = contentViewportRect;
    if (toolbarPopupKey == fortuneToolbarFontColorPopupKey ||
        toolbarPopupKey == fortuneToolbarBackgroundPopupKey) {
      canvas.save();
      canvas.clipRect(contentViewportRect);
      _drawToolbarFontColorPopup(canvas, contentRect);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    _drawShadowBox(canvas, rect, radius: 6);
    canvas.save();
    canvas.clipRect(contentViewportRect);
    if (toolbarPopupKey == fortuneToolbarFormatCommand) {
      _drawToolbarFormatPopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      if (formatMoreSubmenuOpen) {
        _drawToolbarFormatMoreSubmenu(canvas, rect, size.width);
      }
      return;
    }
    if (toolbarPopupKey == fortuneToolbarQuickFormulaPopupKey) {
      _drawToolbarFormulaPopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    if (toolbarPopupKey == fortuneToolbarMergePopupKey) {
      _drawToolbarMergePopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    if (toolbarPopupKey == fortuneToolbarHorizontalAlignPopupKey) {
      _drawToolbarHorizontalAlignPopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    if (toolbarPopupKey == fortuneToolbarVerticalAlignPopupKey) {
      _drawToolbarVerticalAlignPopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    if (toolbarPopupKey == fortuneToolbarTextWrapPopupKey) {
      _drawToolbarTextWrapPopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    if (toolbarPopupKey == fortuneToolbarTextRotationPopupKey) {
      _drawToolbarTextRotationPopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    if (toolbarPopupKey == fortuneToolbarFilterCommand) {
      _drawToolbarFilterPopup(canvas, contentRect, options);
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      return;
    }
    var top = contentRect.top + popupContentTopPadding;
    for (var i = 0; i < options.length; i += 1) {
      if (options[i] == '|') {
        _drawToolbarMenuDivider(
          canvas,
          Rect.fromLTWH(
            rect.left,
            top,
            rect.width,
            fortuneToolbarMenuDividerHeight,
          ),
        );
        top += fortuneToolbarMenuDividerHeight;
        continue;
      }
      final row = Rect.fromLTWH(rect.left, top, rect.width, popupRowHeight);
      if (i == toolbarPopupHoveredIndex ||
          (toolbarPopupHoveredIndex == null &&
              i == toolbarPopupSelectedIndex)) {
        _drawToolbarPopupHoverFill(canvas, row);
      }
      if (toolbarPopupKey == fortuneToolbarConditionFormatPopupKey &&
          i == conditionFormatHoveredTopLevelIndex) {
        _drawToolbarPopupHoverFill(canvas, row);
      }
      if (toolbarPopupKey == fortuneToolbarBorderPopupKey &&
          i == toolbarBorderHoveredTopLevelIndex) {
        _drawToolbarPopupHoverFill(canvas, row);
      }
      final label =
          locale.freezeMenuLabels[options[i]] ??
          _toolbarTooltipLabel(options[i]) ??
          _toolbarPopupLabel(options[i]);
      final hasConditionFormatArrow =
          toolbarPopupKey == fortuneToolbarConditionFormatPopupKey &&
          (options[i] == fortuneConditionFormatHighlightRulesCommand ||
              options[i] == fortuneConditionFormatItemSelectionRulesCommand ||
              options[i] == fortuneConditionFormatDeleteRuleCommand);
      final hasBorderSubmenuArrow =
          toolbarPopupKey == fortuneToolbarBorderPopupKey &&
          (options[i] == fortuneToolbarBorderColorSubmenuKey ||
              options[i] == fortuneToolbarBorderStyleSubmenuKey);
      final swatch = fortuneToolbarColorCommands[options[i]];
      if (swatch != null) {
        canvas.drawRect(
          Rect.fromLTWH(row.left + 12, row.top + 6, 14, 14),
          Paint()..color = swatch,
        );
        canvas.drawRect(
          Rect.fromLTWH(row.left + 12, row.top + 6, 14, 14),
          Paint()
            ..style = PaintingStyle.stroke
            ..color = const Color(0xff888888),
        );
        _drawText(
          canvas,
          label,
          Rect.fromLTWH(row.left + 34, row.top, row.width - 40, row.height),
          fontSize: 12,
        );
      } else {
        _drawText(
          canvas,
          label,
          Rect.fromLTWH(
            row.left + fortuneToolbarSelectOptionHorizontalPadding,
            row.top,
            row.width -
                fortuneToolbarSelectOptionHorizontalPadding * 2 -
                (hasConditionFormatArrow
                    ? fortuneConditionFormatTopLevelArrowReservedWidth
                    : hasBorderSubmenuArrow
                    ? fortuneConditionFormatTopLevelArrowReservedWidth
                    : 0),
            row.height,
          ),
          fontSize: 12,
        );
      }
      if (hasConditionFormatArrow) {
        _drawConditionFormatRightArrow(canvas, row);
      }
      if (hasBorderSubmenuArrow) {
        _drawText(
          canvas,
          '›',
          Rect.fromLTWH(
            row.right -
                fortuneConditionFormatTopLevelArrowRightPadding -
                fortuneConditionFormatTopLevelArrowWidth,
            row.top,
            fortuneConditionFormatTopLevelArrowWidth,
            row.height,
          ),
          fontSize: fortuneConditionFormatTopLevelArrowFontSize,
          color: const Color(0xffa0a0a0),
          align: TextAlign.center,
        );
        _drawToolbarBorderPopupPreview(canvas, row, options[i]);
      } else if (toolbarPopupKey == fortuneToolbarBorderPopupKey) {
        _drawToolbarBorderPopupIcon(canvas, row, options[i]);
      }
      if (toolbarPopupKey == fortuneToolbarFreezePopupKey) {
        FortuneToolbarIconPainter.draw(
          canvas,
          options[i],
          Rect.fromLTWH(row.right - 30, row.top + 8, 24, 24),
        );
      }
      top += popupRowHeight;
    }
    if (toolbarPopupKey == fortuneToolbarConditionFormatPopupKey) {
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      _drawConditionFormatSubmenu(canvas, size, rect);
    } else if (toolbarPopupKey == fortuneToolbarBorderPopupKey) {
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
      _drawToolbarBorderSubmenu(canvas, size, rect);
    } else {
      canvas.restore();
      _drawToolbarPopupScrollIndicators(
        canvas,
        rect,
        scrollOffset,
        maxScrollOffset,
      );
    }
  }

  void _drawToolbarPopupScrollIndicators(
    Canvas canvas,
    Rect rect,
    double scrollOffset,
    double maxScrollOffset,
  ) {
    if (maxScrollOffset <= 0) {
      return;
    }
    final paint = Paint()..color = fortuneToolbarPopupScrollIndicatorColor;
    if (scrollOffset > 0.5) {
      _drawToolbarPopupScrollButton(
        canvas,
        rect,
        fortuneToolbarPopupScrollButtonUp,
      );
      final button = fortuneToolbarPopupScrollButtonRect(
        rect,
        fortuneToolbarPopupScrollButtonUp,
      );
      final top = button.top + fortuneToolbarPopupScrollIndicatorInset;
      final centerX = button.center.dx;
      final path = Path()
        ..moveTo(centerX, top)
        ..lineTo(
          centerX - fortuneToolbarPopupScrollIndicatorWidth / 2,
          top + fortuneToolbarPopupScrollIndicatorHeight,
        )
        ..lineTo(
          centerX + fortuneToolbarPopupScrollIndicatorWidth / 2,
          top + fortuneToolbarPopupScrollIndicatorHeight,
        )
        ..close();
      canvas.drawPath(path, paint);
    }
    if (scrollOffset < maxScrollOffset - 0.5) {
      _drawToolbarPopupScrollButton(
        canvas,
        rect,
        fortuneToolbarPopupScrollButtonDown,
      );
      final button = fortuneToolbarPopupScrollButtonRect(
        rect,
        fortuneToolbarPopupScrollButtonDown,
      );
      final bottom = button.bottom - fortuneToolbarPopupScrollIndicatorInset;
      final centerX = button.center.dx;
      final path = Path()
        ..moveTo(centerX, bottom)
        ..lineTo(
          centerX - fortuneToolbarPopupScrollIndicatorWidth / 2,
          bottom - fortuneToolbarPopupScrollIndicatorHeight,
        )
        ..lineTo(
          centerX + fortuneToolbarPopupScrollIndicatorWidth / 2,
          bottom - fortuneToolbarPopupScrollIndicatorHeight,
        )
        ..close();
      canvas.drawPath(path, paint);
    }
  }

  void _drawToolbarPopupScrollButton(
    Canvas canvas,
    Rect rect,
    String direction,
  ) {
    final isPressed = toolbarPopupPressedScrollButtonDirection == direction;
    final isHovered = toolbarPopupHoveredScrollButtonDirection == direction;
    if (!isPressed && !isHovered) {
      return;
    }
    final button = fortuneToolbarPopupScrollButtonRect(rect, direction);
    canvas.drawRRect(
      RRect.fromRectAndRadius(button, const Radius.circular(3)),
      Paint()
        ..color = isPressed
            ? fortuneToolbarPopupScrollButtonPressedColor
            : fortuneToolbarPopupScrollButtonHoverColor,
    );
  }

  void _drawToolbarBorderPopupPreview(Canvas canvas, Rect row, String option) {
    final y = row.bottom - 5;
    final left = row.left + fortuneToolbarBorderPreviewInset;
    if (option == fortuneToolbarBorderColorSubmenuKey) {
      canvas.drawRect(
        Rect.fromLTRB(left, y - 2, row.right - 12, y + 1),
        Paint()..color = toolbarBorderColor,
      );
      return;
    }
    _drawToolbarBorderStyleLine(
      canvas,
      Offset(left, y),
      Offset(row.right - 12, y),
      toolbarBorderStyle,
      color: const Color(0xff777777),
    );
  }

  void _drawToolbarBorderPopupIcon(Canvas canvas, Rect row, String command) {
    if (!fortuneToolbarBorderCommands.contains(command)) {
      return;
    }
    final rect = Rect.fromLTWH(row.right - 31, row.center.dy - 7, 14, 14);
    final paint = Paint()
      ..color = const Color(0xff5d6677)
      ..strokeWidth = 1
      ..style = PaintingStyle.stroke;
    final muted = Paint()
      ..color = const Color(0xffc4cad3)
      ..strokeWidth = 1
      ..style = PaintingStyle.stroke;
    canvas.drawRect(rect, muted);
    final midX = rect.left + rect.width / 2;
    final midY = rect.top + rect.height / 2;
    canvas.drawLine(Offset(rect.left, midY), Offset(rect.right, midY), muted);
    canvas.drawLine(Offset(midX, rect.top), Offset(midX, rect.bottom), muted);
    switch (command) {
      case fortuneToolbarBorderTopCommand:
        canvas.drawLine(rect.topLeft, rect.topRight, paint);
        break;
      case fortuneToolbarBorderBottomCommand:
        canvas.drawLine(rect.bottomLeft, rect.bottomRight, paint);
        break;
      case fortuneToolbarBorderLeftCommand:
        canvas.drawLine(rect.topLeft, rect.bottomLeft, paint);
        break;
      case fortuneToolbarBorderRightCommand:
        canvas.drawLine(rect.topRight, rect.bottomRight, paint);
        break;
      case fortuneToolbarBorderNoneCommand:
        canvas.drawLine(rect.topLeft, rect.bottomRight, paint);
        break;
      case fortuneToolbarBorderAllCommand:
        canvas.drawRect(rect, paint);
        canvas.drawLine(
          Offset(rect.left, midY),
          Offset(rect.right, midY),
          paint,
        );
        canvas.drawLine(
          Offset(midX, rect.top),
          Offset(midX, rect.bottom),
          paint,
        );
        break;
      case fortuneToolbarBorderOutsideCommand:
        canvas.drawRect(rect, paint);
        break;
      case fortuneToolbarBorderInsideCommand:
        canvas.drawLine(
          Offset(rect.left, midY),
          Offset(rect.right, midY),
          paint,
        );
        canvas.drawLine(
          Offset(midX, rect.top),
          Offset(midX, rect.bottom),
          paint,
        );
        break;
      case fortuneToolbarBorderHorizontalCommand:
        canvas.drawLine(
          Offset(rect.left, midY),
          Offset(rect.right, midY),
          paint,
        );
        break;
      case fortuneToolbarBorderVerticalCommand:
        canvas.drawLine(
          Offset(midX, rect.top),
          Offset(midX, rect.bottom),
          paint,
        );
        break;
      case fortuneToolbarBorderSlashCommand:
        canvas.drawLine(rect.topLeft, rect.bottomRight, paint);
        break;
    }
  }

  void _drawToolbarBorderSubmenu(Canvas canvas, Size size, Rect topLevelRect) {
    final submenuKey = toolbarBorderSubmenuKey;
    if (submenuKey == null) {
      return;
    }
    final rect = _toolbarBorderSubmenuRect(size, topLevelRect, submenuKey);
    if (submenuKey == fortuneToolbarBorderColorSubmenuKey) {
      _drawToolbarFontColorPopup(canvas, rect);
      return;
    }
    _drawShadowBox(canvas, rect, radius: 6);
    final resetRect = Rect.fromLTWH(
      rect.left,
      rect.top + fortuneToolbarPopupContentTopPadding,
      rect.width,
      fortuneToolbarBorderStyleSubmenuResetHeight,
    );
    if (toolbarBorderHoveredSubmenuIndex == 0) {
      canvas.drawRect(
        resetRect,
        Paint()..color = fortuneConditionFormatSubmenuHoverColor,
      );
    }
    _drawText(
      canvas,
      _toolbarPopupLabel(fortuneToolbarBorderStyleDefaultCommand),
      Rect.fromLTWH(
        resetRect.left + 10,
        resetRect.top,
        resetRect.width - 20,
        resetRect.height,
      ),
      fontSize: 12,
      color: const Color(0xff333333),
    );
    var top = resetRect.bottom;
    for (var i = 0; i < fortuneToolbarBorderStyleValues.length; i += 1) {
      final row = Rect.fromLTWH(
        rect.left,
        top,
        rect.width,
        fortuneToolbarBorderStyleSubmenuRowHeight,
      );
      if (toolbarBorderHoveredSubmenuIndex == i + 1) {
        canvas.drawRect(
          row,
          Paint()..color = fortuneConditionFormatSubmenuHoverColor,
        );
      }
      final y = row.center.dy;
      final style = fortuneToolbarBorderStyleValues[i];
      final inputRect = fortuneToolbarBorderWidthEditableStyles.contains(style)
          ? fortuneToolbarBorderStyleWidthInputRect(row)
          : null;
      if (inputRect != null) {
        canvas.drawRect(inputRect, Paint()..color = const Color(0xffffffff));
        canvas.drawRect(
          inputRect,
          Paint()
            ..style = PaintingStyle.stroke
            ..color = const Color(0xffc8c8c8),
        );
      }
      _drawToolbarBorderStyleLine(
        canvas,
        Offset(row.left + 10, y),
        Offset(
          inputRect == null
              ? row.right - 15
              : inputRect.left - fortuneToolbarBorderStyleWidthInputLineGap,
          y,
        ),
        style,
      );
      top += fortuneToolbarBorderStyleSubmenuRowHeight;
    }
  }

  Rect _toolbarBorderSubmenuRect(
    Size size,
    Rect topLevelRect,
    String submenuKey,
  ) {
    final width = submenuKey == fortuneToolbarBorderColorSubmenuKey
        ? fortuneToolbarFontColorPopupWidth
        : fortuneToolbarBorderStyleSubmenuWidth;
    final height = submenuKey == fortuneToolbarBorderColorSubmenuKey
        ? fortuneToolbarFontColorPopupHeight
        : fortuneToolbarPopupVerticalPadding +
              fortuneToolbarBorderStyleSubmenuResetHeight +
              fortuneToolbarBorderStyleSubmenuRowHeight *
                  fortuneToolbarBorderStyleValues.length;
    final desiredLeft = topLevelRect.right;
    final left = desiredLeft + width > size.width
        ? math.max(fortuneToolbarPopupViewportMargin, topLevelRect.left - width)
        : desiredLeft;
    return Rect.fromLTWH(left, topLevelRect.bottom - height, width, height);
  }

  void _drawToolbarBorderStyleLine(
    Canvas canvas,
    Offset start,
    Offset end,
    int style, {
    Color color = const Color(0xff000000),
  }) {
    final paint = Paint()
      ..color = color
      ..strokeWidth = fortuneToolbarBorderStrokeWidth(
        style,
        toolbarBorderStyleStrokeWidths,
      )
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.square;
    final pattern =
        fortuneToolbarBorderStyleDashPatterns[style] ?? const [1, 0];
    if (pattern.length < 2 || pattern[1] == 0) {
      canvas.drawLine(start, end, paint);
      return;
    }
    var x = start.dx;
    var patternIndex = 0;
    var draw = true;
    while (x < end.dx) {
      final length = pattern[patternIndex % pattern.length];
      final nextX = math.min(end.dx, x + length);
      if (draw) {
        canvas.drawLine(Offset(x, start.dy), Offset(nextX, end.dy), paint);
      }
      x = nextX;
      patternIndex += 1;
      draw = !draw;
    }
  }

  void _drawToolbarFontColorPopup(
    Canvas canvas,
    Rect rect, {
    String? resetLabel,
    String? confirmLabel,
  }) {
    final rrect = RRect.fromRectAndRadius(
      rect,
      const Radius.circular(fortuneToolbarColorPopupBorderRadius),
    );
    canvas.drawRRect(
      rrect.shift(const Offset(0, 2)),
      Paint()
        ..color = const Color(0x33000000)
        ..maskFilter = const ui.MaskFilter.blur(ui.BlurStyle.normal, 2),
    );
    canvas.drawRRect(rrect, Paint()..color = const Color(0xfff0f0f0));
    canvas.drawRRect(
      rrect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0x33000000),
    );

    final resetRect = Rect.fromLTWH(
      rect.left,
      rect.top,
      rect.width,
      fortuneToolbarFontColorResetHeight,
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        resetRect,
        const Radius.circular(fortuneToolbarColorPopupBorderRadius),
      ),
      Paint()..color = const Color(0xffffffff),
    );
    if (toolbarPopupHoveredIndex == 0) {
      _drawToolbarPopupHoverFill(canvas, resetRect);
    }
    _drawText(
      canvas,
      resetLabel ?? locale.customColorReset,
      Rect.fromLTWH(
        resetRect.left + 8,
        resetRect.top,
        resetRect.width - 32,
        resetRect.height,
      ),
      fontSize: 12,
      color: const Color(0xff333333),
    );

    final customRect = Rect.fromLTWH(
      rect.left,
      rect.top + fortuneToolbarFontColorCustomTop,
      rect.width,
      fortuneToolbarFontColorCustomHeight,
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        customRect,
        const Radius.circular(fortuneToolbarColorPopupBorderRadius),
      ),
      Paint()..color = const Color(0xffffffff),
    );
    if (toolbarPopupHoveredIndex == 1) {
      _drawToolbarPopupHoverFill(canvas, customRect);
    }
    _drawText(
      canvas,
      _toolbarPopupLabel('custom-color-label'),
      Rect.fromLTWH(
        customRect.left + fortuneToolbarFontColorCustomLabelLeft,
        customRect.top,
        fortuneToolbarFontColorCustomLabelWidth,
        customRect.height,
      ),
      fontSize: 12,
      color: const Color(0xff000000),
    );
    final inputRect = Rect.fromLTWH(
      customRect.left + fortuneToolbarFontColorCustomInputLeft,
      customRect.top + fortuneToolbarFontColorCustomInputTop,
      fortuneToolbarFontColorCustomInputWidth,
      fortuneToolbarFontColorCustomInputHeight,
    );
    canvas.drawRect(inputRect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      inputRect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0xff888888),
    );
    canvas.drawRect(
      Rect.fromLTRB(
        inputRect.left + fortuneToolbarFontColorCustomSwatchHorizontalInset,
        inputRect.top + fortuneToolbarFontColorCustomSwatchVerticalInset,
        inputRect.right - fortuneToolbarFontColorCustomSwatchHorizontalInset,
        inputRect.bottom - fortuneToolbarFontColorCustomSwatchVerticalInset,
      ),
      Paint()..color = const Color(0xff000000),
    );
    final okRect = Rect.fromLTWH(
      customRect.right -
          fortuneToolbarFontColorCustomOkRightInset -
          fortuneToolbarFontColorCustomOkWidth,
      customRect.top + fortuneToolbarFontColorCustomOkTop,
      fortuneToolbarFontColorCustomOkWidth,
      fortuneToolbarFontColorCustomOkHeight,
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(okRect, const Radius.circular(2)),
      Paint()..color = const Color(0xff0188fb),
    );
    _drawText(
      canvas,
      confirmLabel ?? locale.customColorConfirm,
      okRect,
      fontSize: 12,
      color: const Color(0xffffffff),
      align: TextAlign.center,
    );

    final pickerRect = Rect.fromLTWH(
      rect.left,
      rect.top + fortuneToolbarFontColorPickerTop,
      rect.width,
      rect.height - fortuneToolbarFontColorPickerTop,
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        pickerRect,
        const Radius.circular(fortuneToolbarColorPopupBorderRadius),
      ),
      Paint()..color = const Color(0xffffffff),
    );
    final step =
        fortuneToolbarColorPickerItemSize +
        fortuneToolbarColorPickerItemMargin * 2;
    for (var row = 0; row < fortuneToolbarColorPickerPalette.length; row += 1) {
      final colors = fortuneToolbarColorPickerPalette[row];
      for (var column = 0; column < colors.length; column += 1) {
        final itemRect = Rect.fromLTWH(
          pickerRect.left +
              fortuneToolbarColorPickerPadding +
              column * step +
              fortuneToolbarColorPickerItemMargin,
          pickerRect.top +
              fortuneToolbarColorPickerPadding +
              row * step +
              fortuneToolbarColorPickerItemMargin,
          fortuneToolbarColorPickerItemSize,
          fortuneToolbarColorPickerItemSize,
        );
        canvas.drawRect(
          itemRect,
          Paint()..color = fortuneToolbarHexColor(colors[column]),
        );
      }
    }
  }

  void _drawConditionFormatSubmenu(
    Canvas canvas,
    Size size,
    Rect topLevelRect,
  ) {
    final submenuKey = conditionFormatSubmenuKey;
    if (submenuKey == null) {
      return;
    }
    final items = switch (submenuKey) {
      fortuneConditionFormatHighlightSubmenuKey =>
        fortuneConditionFormatHighlightItems,
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionItems,
      fortuneConditionFormatDeleteSubmenuKey =>
        fortuneConditionFormatDeleteItems,
      _ => const <String>[],
    };
    if (items.isEmpty) {
      return;
    }
    final width = switch (submenuKey) {
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionSubmenuWidth,
      _ => fortuneConditionFormatSubmenuWidth,
    };
    final topLevelIndex = switch (submenuKey) {
      fortuneConditionFormatHighlightSubmenuKey =>
        fortuneConditionFormatHighlightTopLevelIndex,
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionTopLevelIndex,
      fortuneConditionFormatDeleteSubmenuKey =>
        fortuneConditionFormatDeleteTopLevelIndex,
      _ => 0,
    };
    final desiredLeft = topLevelRect.right;
    final left = desiredLeft + width > size.width
        ? math.max(
            fortuneToolbarPopupViewportMargin,
            topLevelRect.left +
                fortuneConditionFormatSubmenuOverflowLeftInset -
                width,
          )
        : desiredLeft;
    final rect = Rect.fromLTWH(
      left,
      _toolbarPopupOptionTop(
            topLevelRect,
            fortuneToolbarConditionFormatPopupKey,
            fortuneConditionFormatTopLevelItems,
            topLevelIndex,
          ) -
          toolbarPopupScrollOffset +
          fortuneConditionFormatSubmenuTopOffset,
      width,
      items.length * fortuneConditionFormatSubmenuRowHeight,
    );
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneConditionFormatSubmenuBorderRadius,
      border: fortuneConditionFormatSubmenuBorderColor,
    );
    for (var i = 0; i < items.length; i += 1) {
      final row = Rect.fromLTWH(
        rect.left,
        rect.top + i * fortuneConditionFormatSubmenuRowHeight,
        rect.width,
        fortuneConditionFormatSubmenuRowHeight,
      );
      if (i == conditionFormatHoveredSubmenuIndex) {
        canvas.drawRect(
          row,
          Paint()..color = fortuneConditionFormatSubmenuHoverColor,
        );
      }
      final label = _toolbarPopupLabel(items[i]);
      final valueLabel = _conditionFormatSubmenuValueLabel(items[i]);
      if (valueLabel == null) {
        _drawText(
          canvas,
          label,
          Rect.fromLTWH(
            row.left + fortuneConditionFormatDeleteSubmenuHorizontalPadding,
            row.top,
            row.width -
                fortuneConditionFormatDeleteSubmenuHorizontalPadding * 2,
            row.height,
          ),
          fontSize: 12,
        );
      } else {
        _drawText(
          canvas,
          label,
          Rect.fromLTWH(
            row.left + fortuneConditionFormatSubmenuHorizontalPadding,
            row.top,
            row.width - 80,
            row.height,
          ),
          fontSize: 12,
        );
        _drawText(
          canvas,
          valueLabel,
          Rect.fromLTWH(
            row.right - fortuneConditionFormatSubmenuHorizontalPadding - 44,
            row.top,
            44,
            row.height,
          ),
          fontSize: fortuneConditionFormatSubmenuValueFontSize,
          color: fortuneConditionFormatSubmenuValueColor,
          align: TextAlign.right,
        );
      }
    }
  }

  String? _conditionFormatSubmenuValueLabel(String key) {
    return locale.toolbarPopupLabels['condition-submenu-value-$key'] ??
        fortuneConditionFormatSubmenuValueLabels[key];
  }

  void _drawConditionFormatRightArrow(Canvas canvas, Rect row) {
    final iconRect = Rect.fromLTWH(
      row.right -
          fortuneConditionFormatTopLevelArrowRightPadding -
          fortuneConditionFormatTopLevelArrowWidth,
      row.center.dy - fortuneConditionFormatTopLevelArrowWidth / 2,
      fortuneConditionFormatTopLevelArrowWidth,
      fortuneConditionFormatTopLevelArrowWidth,
    );
    final path = Path()
      ..moveTo(781.963636, 495.709091)
      ..lineTo(363.054545, 172.218182)
      ..cubicTo(
        342.10909,
        155.927273,
        325.818182,
        162.909091,
        325.818182,
        188.509091,
      )
      ..lineTo(325.818182, 835.490909)
      ..cubicTo(
        325.818182,
        861.090909,
        342.10909,
        868.072727,
        363.054545,
        851.781818,
      )
      ..lineTo(781.963636, 528.290909)
      ..cubicTo(793.6, 518.981818, 793.6, 505.018182, 781.963636, 495.709091)
      ..close();
    canvas.save();
    canvas.translate(iconRect.left, iconRect.top);
    canvas.scale(iconRect.width / 1024, iconRect.height / 1024);
    canvas.drawPath(path, Paint()..color = const Color(0xffa8abb0));
    canvas.restore();
  }

  double _toolbarPopupOptionTop(
    Rect rect,
    String key,
    List<String> options,
    int optionIndex,
  ) {
    var top = rect.top + fortuneToolbarPopupContentTopPaddingFor(key);
    for (
      var index = 0;
      index < optionIndex && index < options.length;
      index += 1
    ) {
      top += options[index] == '|'
          ? fortuneToolbarMenuDividerHeight
          : fortuneToolbarPopupRowHeightFor(key);
    }
    return top;
  }

  void _drawContextMenu(Canvas canvas) {
    final at = contextMenuAt;
    if (at == null) {
      return;
    }
    final rect = fortuneContextMenuRect(at, contextMenuItems);
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneContextMenuBorderRadius,
      border: const Color(0x33000000),
    );
    var y = rect.top + fortuneContextMenuContentTopPadding;
    for (var index = 0; index < contextMenuItems.length; index += 1) {
      final item = contextMenuItems[index];
      if (item == '|') {
        canvas.drawRect(
          Rect.fromLTWH(
            rect.left,
            y + fortuneContextMenuDividerTopInset,
            rect.width,
            fortuneContextMenuDividerStrokeHeight,
          ),
          Paint()..color = const Color(0xffe0e0e0),
        );
        y += fortuneContextMenuDividerHeight;
      } else {
        final enabled = !contextMenuDisabledItems.contains(item);
        if (enabled && index == contextMenuHoveredIndex) {
          canvas.drawRect(
            Rect.fromLTWH(
              rect.left,
              y,
              rect.width,
              fortuneContextMenuRowHeight,
            ),
            Paint()..color = fortuneToolbarHoverBackgroundColor,
          );
        }
        final row = Rect.fromLTWH(
          rect.left,
          y,
          rect.width,
          fortuneContextMenuRowHeight,
        );
        if (fortuneContextMenuItemHasInlineInput(item)) {
          _drawContextMenuInlineInputRow(canvas, row, item);
        } else {
          if (item == fortuneContextShowGridLinesCommand ||
              item == fortuneContextShowRulerCommand) {
            _drawContextMenuCheckMark(
              canvas,
              row,
              checked: contextMenuCheckedItems.contains(item),
              enabled: enabled,
            );
          }
          _drawText(
            canvas,
            _contextMenuLabel(item),
            Rect.fromLTWH(
              rect.left + fortuneContextMenuTextLeft,
              y,
              fortuneContextMenuTextWidth,
              fortuneContextMenuRowHeight,
            ),
            fontSize: 13,
            color: enabled ? const Color(0xff202124) : const Color(0xff9aa0a6),
          );
        }
        y += fortuneContextMenuRowHeight;
      }
    }
  }

  void _drawContextMenuCheckMark(
    Canvas canvas,
    Rect row, {
    required bool checked,
    required bool enabled,
  }) {
    if (!checked) {
      return;
    }
    final rect = Rect.fromLTWH(row.left + 12, row.top + 7, 14, 14);
    final checkPaint = Paint()
      ..color = enabled ? const Color(0xff0188fb) : const Color(0xff9aa0a6)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2
      ..strokeCap = StrokeCap.round
      ..strokeJoin = StrokeJoin.round;
    final path = Path()
      ..moveTo(rect.left + 3, rect.center.dy)
      ..lineTo(rect.left + 6, rect.bottom - 4)
      ..lineTo(rect.right - 3, rect.top + 4);
    canvas.drawPath(path, checkPaint);
  }

  void _drawContextMenuInlineInputRow(Canvas canvas, Rect row, String item) {
    final inputRect = _contextMenuInlineInputRectForRow(row, item);
    if (fortuneEditorContextMenuItemHasInlineInput(item)) {
      _drawText(
        canvas,
        _contextMenuLabel(item),
        Rect.fromLTWH(
          row.left + fortuneContextMenuPrimaryTextLeft,
          row.top,
          inputRect.left - row.left - fortuneContextMenuPrimaryTextLeft - 4,
          row.height,
        ),
        fontSize: 13,
      );
      _drawInlineMenuInputBox(canvas, inputRect);
      _drawText(
        canvas,
        _contextMenuInlineLabel('$item-unit'),
        Rect.fromLTWH(
          inputRect.right + fortuneContextMenuInlineInputGap,
          row.top,
          row.right - inputRect.right - fortuneContextMenuInlineInputGap,
          row.height,
        ),
        fontSize: 13,
      );
      return;
    }
    if (item == fortuneContextSetRowHeightCommand ||
        item == fortuneContextSetColumnWidthCommand ||
        item == fortuneContextSetLabelWidthCommand ||
        item == fortuneContextSetLabelHeightCommand) {
      final label = switch (item) {
        fortuneContextSetRowHeightCommand => _contextMenuInlineLabel(
          'row-height-inline-label',
        ),
        fortuneContextSetColumnWidthCommand => _contextMenuInlineLabel(
          'column-width-inline-label',
        ),
        fortuneContextSetLabelWidthCommand => _contextMenuInlineLabel(
          'label-width-inline-label',
        ),
        fortuneContextSetLabelHeightCommand => _contextMenuInlineLabel(
          'label-height-inline-label',
        ),
        _ => _contextMenuLabel(item),
      };
      _drawText(
        canvas,
        label,
        Rect.fromLTWH(
          row.left + fortuneContextMenuPrimaryTextLeft,
          row.top,
          inputRect.left - row.left - fortuneContextMenuPrimaryTextLeft - 4,
          row.height,
        ),
        fontSize: 13,
      );
      _drawInlineMenuInputBox(canvas, inputRect);
      _drawText(
        canvas,
        fortuneContextMenuAxisSizeUnitLabel(workbook.activeSheet, locale),
        Rect.fromLTWH(
          inputRect.right + fortuneContextMenuInlineInputGap,
          row.top,
          row.right - inputRect.right - fortuneContextMenuInlineInputGap,
          row.height,
        ),
        fontSize: 13,
      );
      return;
    }
    _drawText(
      canvas,
      _contextMenuInlineLabel('insert-inline-prefix'),
      Rect.fromLTWH(
        row.left + fortuneContextMenuPrimaryTextLeft,
        row.top,
        inputRect.left - row.left - fortuneContextMenuPrimaryTextLeft - 4,
        row.height,
      ),
      fontSize: 13,
    );
    _drawInlineMenuInputBox(canvas, inputRect);
    final suffix = switch (item) {
      fortuneContextInsertRowCommand => _contextMenuInlineLabel(
        'insert-row-inline-suffix',
      ),
      fortuneContextInsertRowBelowCommand => _contextMenuInlineLabel(
        'insert-row-below-inline-suffix',
      ),
      fortuneContextInsertColumnCommand => _contextMenuInlineLabel(
        'insert-column-inline-suffix',
      ),
      fortuneContextInsertColumnRightCommand => _contextMenuInlineLabel(
        'insert-column-right-inline-suffix',
      ),
      _ => _contextMenuLabel(item),
    };
    _drawText(
      canvas,
      suffix,
      Rect.fromLTWH(
        inputRect.right + fortuneContextMenuInlineInputGap,
        row.top,
        row.right - inputRect.right - fortuneContextMenuInlineInputGap,
        row.height,
      ),
      fontSize: 13,
    );
  }

  void _drawInlineMenuInputBox(Canvas canvas, Rect rect) {
    canvas.drawRect(
      rect,
      Paint()..color = fortuneInlineMenuInputBackgroundColor,
    );
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = fortuneInlineMenuInputBorderWidth
        ..color = fortuneInlineMenuInputBorderColor,
    );
  }

  Rect _contextMenuInlineInputRectForRow(Rect row, String item) {
    if (item == fortuneContextSetRowHeightCommand) {
      return fortuneInlineMenuInputRect(
        row,
        left: fortuneContextMenuRowHeightInputLeft,
        width: fortuneContextMenuAxisInputWidth,
      );
    }
    if (item == fortuneContextSetColumnWidthCommand) {
      return fortuneInlineMenuInputRect(
        row,
        left: fortuneContextMenuColumnWidthInputLeft,
        width: fortuneContextMenuAxisInputWidth,
      );
    }
    if (item == fortuneContextSetLabelWidthCommand ||
        item == fortuneContextSetLabelHeightCommand) {
      return fortuneInlineMenuInputRect(
        row,
        left: fortuneContextMenuRowHeightInputLeft,
        width: fortuneContextMenuAxisInputWidth,
      );
    }
    if (fortuneEditorContextMenuItemHasInlineInput(item)) {
      return fortuneInlineMenuInputRect(
        row,
        left: fortuneContextMenuEditorInputLeft,
        width: fortuneContextMenuEditorInputWidth,
      );
    }
    return fortuneInlineMenuInputRect(
      row,
      left: fortuneContextMenuInsertInputLeft,
      width: fortuneContextMenuInsertInputWidth,
    );
  }

  String _contextMenuLabel(String item) {
    return locale.contextMenuLabels[item] ?? item;
  }

  String _contextMenuInlineLabel(String item) {
    return locale.contextMenuLabels[item] ?? item;
  }

  void _drawCustomSortDialog(Canvas canvas, Size size) {
    if (!customSortDialogOpen) {
      return;
    }
    final labels = _customSortColumnLabels();
    final visibleCount = labels.length
        .clamp(1, fortuneCustomSortDialogMaxVisibleColumns)
        .toInt();
    final rect = fortuneCustomSortDialogRect(size, visibleCount);
    canvas.drawRect(
      Offset.zero & size,
      Paint()..color = const Color(0x1a000000),
    );
    _drawShadowBox(canvas, rect, radius: 4, border: const Color(0x33000000));
    _drawDialogCloseButton(
      canvas,
      fortuneCustomSortCloseButtonRect(rect),
      'custom-sort',
    );
    _drawText(
      canvas,
      _customSortRangeTitle(),
      Rect.fromLTWH(rect.left + 18, rect.top + 14, rect.width - 36, 24),
      fontSize: 13,
      bold: true,
    );
    _drawCheckbox(
      canvas,
      Rect.fromLTWH(rect.left + 18, rect.top + 55, 14, 14),
      customSortHasHeader,
    );
    _drawText(
      canvas,
      locale.hasTitle,
      Rect.fromLTWH(rect.left + 40, rect.top + 50, 140, 24),
      fontSize: 12,
    );
    _drawText(
      canvas,
      locale.sortBy,
      Rect.fromLTWH(rect.left + 18, rect.top + 76, 120, 18),
      fontSize: 11,
      color: const Color(0xff666666),
    );
    for (var index = 0; index < visibleCount; index += 1) {
      final row = fortuneCustomSortColumnRowRect(rect, index);
      if (index == customSortColumnOffset) {
        canvas.drawRect(
          row.deflate(1),
          Paint()..color = const Color(0xffe8f0fe),
        );
      }
      canvas.drawRect(
        row.deflate(1),
        Paint()
          ..style = PaintingStyle.stroke
          ..color = const Color(0xffdadce0),
      );
      _drawText(canvas, labels[index], _menuLabelRect(row, 8), fontSize: 12);
    }
    _drawRadio(
      canvas,
      Rect.fromLTWH(rect.right - 118, rect.top + 92, 14, 14),
      customSortAscending,
    );
    _drawText(
      canvas,
      locale.ascending,
      Rect.fromLTWH(rect.right - 96, rect.top + 87, 78, 24),
      fontSize: 12,
    );
    _drawRadio(
      canvas,
      Rect.fromLTWH(rect.right - 118, rect.top + 120, 14, 14),
      !customSortAscending,
    );
    _drawText(
      canvas,
      locale.descending,
      Rect.fromLTWH(rect.right - 96, rect.top + 115, 78, 24),
      fontSize: 12,
    );
    _drawDialogButton(
      canvas,
      fortuneCustomSortConfirmButtonRect(rect),
      locale.sortConfirm,
      primary: true,
    );
  }

  void _drawFormatSearchDialog(Canvas canvas, Size size) {
    if (!formatSearchDialogOpen) {
      return;
    }
    final rect = fortuneFormatSearchDialogRect(size);
    final options = fortuneFormatSearchOptionsFor(formatSearchType);
    final isDateTime =
        formatSearchType == fortuneToolbarFormatMoreDateTimeCommand;
    final titleDateTime =
        locale.formatLabels['titleDateTime'] ?? 'Date and time formats';
    final title = switch (formatSearchType) {
      fortuneToolbarFormatMoreNumberCommand => locale.titleNumber,
      fortuneToolbarFormatMoreDateTimeCommand => titleDateTime,
      _ => locale.titleCurrency,
    };
    final tip = switch (formatSearchType) {
      fortuneToolbarFormatMoreNumberCommand =>
        '${locale.titleNumber.split(' ').first} ${locale.format}:',
      fortuneToolbarFormatMoreDateTimeCommand =>
        '${titleDateTime.split(' ').first} ${locale.format}:',
      _ =>
        '${locale.currency.substring(0, 1).toUpperCase()}${locale.currency.substring(1)} ${locale.format}:',
    };
    canvas.drawRect(
      Offset.zero & size,
      Paint()..color = const Color(0x1a000000),
    );
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneFormatSearchDialogBorderRadius,
      border: const Color(0x11000000),
    );
    _drawDialogCloseButton(
      canvas,
      fortuneFormatSearchCloseButtonRect(rect),
      'format-search',
    );
    _drawText(
      canvas,
      title,
      Rect.fromLTWH(
        rect.left + fortuneFormatSearchContentLeft,
        rect.top + 12,
        rect.width - fortuneFormatSearchContentLeft * 2,
        22,
      ),
      fontSize: 14,
      color: const Color(0xff222222),
    );
    _drawText(
      canvas,
      tip,
      Rect.fromLTWH(
        rect.left + fortuneFormatSearchContentLeft,
        rect.top + fortuneFormatSearchContentTop,
        240,
        18,
      ),
      fontSize: 12,
      color: const Color(0xff222222),
    );
    if (!isDateTime) {
      _drawText(
        canvas,
        '${locale.decimalPlaces}:',
        Rect.fromLTWH(
          rect.left + fortuneFormatSearchContentLeft,
          rect.top + fortuneFormatSearchDecimalTop,
          110,
          fortuneFormatSearchInputHeight,
        ),
        fontSize: 12,
        color: const Color(0xff222222),
      );
      final inputRect = fortuneFormatSearchDecimalInputRect(rect);
      canvas.drawRect(inputRect, Paint()..color = const Color(0xffffffff));
      canvas.drawRect(
        inputRect,
        Paint()
          ..style = PaintingStyle.stroke
          ..color = const Color(0xffd4d4d4),
      );
      _drawText(
        canvas,
        formatSearchDecimalPlacesText,
        Rect.fromLTWH(
          inputRect.left + 6,
          inputRect.top,
          inputRect.width - 12,
          inputRect.height,
        ),
        fontSize: 12,
        color: const Color(0xff222222),
      );
    }
    final listRect = fortuneFormatSearchListRect(rect);
    canvas.drawRect(listRect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      listRect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = const Color(0xffd4d4d4),
    );
    canvas.save();
    canvas.clipRect(listRect);
    final firstVisibleIndex = fortuneFormatSearchFirstVisibleIndex(
      formatSearchScrollOffset,
      options.length,
    );
    final visibleRows = math.min(
      options.length - firstVisibleIndex,
      fortuneFormatSearchVisibleRowCount(),
    );
    for (var visibleIndex = 0; visibleIndex < visibleRows; visibleIndex += 1) {
      final optionIndex = firstVisibleIndex + visibleIndex;
      final row = fortuneFormatSearchListRowRect(rect, visibleIndex);
      final selected = optionIndex == formatSearchSelectedIndex;
      if (selected) {
        canvas.drawRect(
          row,
          Paint()..color = fortuneFormulaSearchSelectedColor,
        );
      }
      canvas.drawRect(
        Rect.fromLTWH(row.left, row.bottom - 1, row.width, 1),
        Paint()..color = const Color(0xffd4d4d4),
      );
      final textColor = selected
          ? const Color(0xffffffff)
          : const Color(0xff222222);
      final option = options[optionIndex];
      _drawText(
        canvas,
        option.name,
        Rect.fromLTWH(row.left + 8, row.top, row.width * 0.58, row.height),
        fontSize: 12,
        color: textColor,
      );
      _drawText(
        canvas,
        option.value,
        Rect.fromLTWH(
          row.left + row.width * 0.62,
          row.top,
          row.width * 0.32,
          row.height,
        ),
        fontSize: 12,
        color: textColor,
        align: TextAlign.right,
      );
    }
    if (options.length > visibleRows) {
      _drawScrollbar(
        canvas,
        listRect,
        visibleRows,
        options.length,
        firstVisibleRow: firstVisibleIndex,
      );
    }
    canvas.restore();
    _drawDialogButton(
      canvas,
      fortuneFormatSearchConfirmButtonRect(rect),
      locale.ok,
      primary: true,
    );
    _drawDialogButton(
      canvas,
      fortuneFormatSearchCancelButtonRect(rect),
      locale.cancel,
    );
  }

  FortuneFormulaSearchFunction? get formulaSearchSelectedFunction {
    if (!formulaSearchDialogOpen) {
      return null;
    }
    return fortuneFormulaSearchSelectedFunction(
      formulaSearchText,
      formulaSearchCategoryType,
      formulaSearchSelectedIndex,
    );
  }

  String? get formulaSearchSelectedParameterHint {
    final hint = formulaSearchSelectedFunction?.parameterHint;
    if (hint == null || hint.isEmpty) {
      return null;
    }
    return hint;
  }

  String? get formulaSearchSelectedExampleSignature {
    final exampleSignature = formulaSearchSelectedFunction?.exampleSignature;
    if (exampleSignature == null || exampleSignature.isEmpty) {
      return null;
    }
    return exampleSignature;
  }

  String? get formulaSearchSelectedDetailedDescription {
    final detail = formulaSearchSelectedFunction?.detail;
    if (detail == null || detail.isEmpty) {
      return null;
    }
    return detail;
  }

  void _drawFormulaSearchHint(Canvas canvas, Size size) {
    final function = formulaSearchSelectedFunction;
    final hint = function?.parameterHint;
    if (function == null || hint == null || hint.isEmpty) {
      return;
    }
    final dialogRect = fortuneFormulaSearchDialogRect(size);
    final rect = fortuneFormulaSearchHintRect(dialogRect, size);
    canvas.drawRect(
      rect.shift(const Offset(0, 1)),
      Paint()
        ..color = const Color(0x22000000)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 4),
    );
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = const Color(0xffc7c7c7),
    );
    _drawText(
      canvas,
      function.name,
      Rect.fromLTWH(rect.left + 10, rect.top + 8, rect.width - 20, 18),
      fontSize: 13,
      color: const Color(0xff222222),
      bold: true,
    );
    _drawText(
      canvas,
      'Parameters:',
      Rect.fromLTWH(rect.left + 10, rect.top + 32, 86, 18),
      fontSize: 12,
      color: const Color(0xff666666),
    );
    _drawText(
      canvas,
      hint,
      Rect.fromLTWH(rect.left + 94, rect.top + 32, rect.width - 104, 18),
      fontSize: 12,
      color: const Color(0xff222222),
    );
    _drawText(
      canvas,
      function.description,
      Rect.fromLTWH(rect.left + 10, rect.top + 56, rect.width - 20, 18),
      fontSize: 12,
      color: const Color(0xff555555),
