  void _drawFormulaSearchDialog(Canvas canvas, Size size) {
    if (!formulaSearchDialogOpen) {
      return;
    }
    final rect = fortuneFormulaSearchDialogRect(size);
    final filteredFunctions = fortuneFormulaSearchFilteredFunctions(
      formulaSearchText,
      formulaSearchCategoryType,
    );
    final firstVisibleIndex = fortuneFormulaSearchFirstVisibleIndex(
      formulaSearchScrollOffset,
      filteredFunctions.length,
    );
    final visibleRows = math.min(
      filteredFunctions.length - firstVisibleIndex,
      fortuneFormulaSearchVisibleRowCount(),
    );
    canvas.drawRect(
      Offset.zero & size,
      Paint()..color = fortuneFormulaSearchOverlayColor,
    );
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneFormulaSearchDialogBorderRadius,
      border: fortuneFormulaSearchDialogBorderColor,
    );
    _drawDialogCloseButton(
      canvas,
      fortuneFormulaSearchCloseButtonRect(rect),
      'formula-search',
    );

    _drawText(
      canvas,
      '${locale.findFunctionTitle} :',
      Rect.fromLTWH(
        rect.left + fortuneFormulaSearchContentLeft,
        rect.top + fortuneFormulaSearchSearchLabelTop,
        fortuneFormulaSearchContentWidth,
        18,
      ),
      fontSize: 12,
      color: fortuneFormulaSearchTextColor,
    );
    final inputRect = fortuneFormulaSearchInputRect(rect);
    canvas.drawRect(
      inputRect,
      Paint()..color = fortuneFormulaSearchBackgroundColor,
    );
    canvas.drawRect(
      inputRect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = fortuneFormulaSearchFieldBorderColor,
    );
    if (formulaSearchText.isEmpty) {
      _drawText(
        canvas,
        locale.functionSearchPlaceholder,
        Rect.fromLTWH(
          inputRect.left + fortuneFormulaSearchInputHorizontalPadding,
          inputRect.top,
          math.max(
            0,
            inputRect.width - fortuneFormulaSearchInputHorizontalPadding * 2,
          ),
          inputRect.height,
        ),
        fontSize: 12,
        color: fortuneFormulaSearchPlaceholderColor,
      );
    }

    _drawText(
      canvas,
      '${locale.functionCategoryLabel} :',
      Rect.fromLTWH(
        rect.left + fortuneFormulaSearchContentLeft,
        rect.top + fortuneFormulaSearchCategoryTop,
        fortuneFormulaSearchCategoryLabelWidth,
        fortuneFormulaSearchInputHeight,
      ),
      fontSize: 12,
      color: fortuneFormulaSearchTextColor,
    );
    final selectRect = fortuneFormulaSearchCategorySelectRect(rect);
    canvas.drawRect(
      selectRect,
      Paint()..color = fortuneFormulaSearchBackgroundColor,
    );
    canvas.drawRect(
      selectRect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = fortuneFormulaSearchFieldBorderColor,
    );
    _drawText(
      canvas,
      fortuneFormulaSearchCategoryLabel(formulaSearchCategoryType),
      Rect.fromLTWH(
        selectRect.left + fortuneFormulaSearchFieldHorizontalPadding,
        selectRect.top,
        selectRect.width - fortuneFormulaSearchCategoryArrowReserve,
        selectRect.height,
      ),
      fontSize: 12,
      color: fortuneFormulaSearchTextColor,
    );
    final arrowPath = Path()
      ..moveTo(
        selectRect.right - fortuneFormulaSearchCategoryArrowLeftInset,
        selectRect.top + fortuneFormulaSearchCategoryArrowTopInset,
      )
      ..lineTo(
        selectRect.right - fortuneFormulaSearchCategoryArrowRightInset,
        selectRect.top + fortuneFormulaSearchCategoryArrowTopInset,
      )
      ..lineTo(
        selectRect.right - fortuneFormulaSearchCategoryArrowCenterInset,
        selectRect.top + fortuneFormulaSearchCategoryArrowBottomInset,
      )
      ..close();
    canvas.drawPath(arrowPath, Paint()..color = fortuneFormulaSearchArrowColor);

    _drawText(
      canvas,
      '${locale.selectFunctionLabel} :',
      Rect.fromLTWH(
        rect.left + fortuneFormulaSearchContentLeft,
        rect.top + fortuneFormulaSearchListTitleTop,
        fortuneFormulaSearchContentWidth,
        18,
      ),
      fontSize: 12,
      color: fortuneFormulaSearchTextColor,
    );
    final listRect = fortuneFormulaSearchListRect(rect);
    canvas.drawRect(
      listRect,
      Paint()..color = fortuneFormulaSearchBackgroundColor,
    );
    canvas.drawRect(
      listRect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = fortuneFormulaSearchFieldBorderColor,
    );
    canvas.save();
    canvas.clipRect(listRect);
    for (var visibleIndex = 0; visibleIndex < visibleRows; visibleIndex += 1) {
      final functionIndex = firstVisibleIndex + visibleIndex;
      final row = fortuneFormulaSearchListRowRect(rect, visibleIndex);
      final function = filteredFunctions[functionIndex];
      final selected = functionIndex == formulaSearchSelectedIndex;
      if (selected) {
        canvas.drawRect(
          row,
          Paint()..color = fortuneFormulaSearchSelectedColor,
        );
      }
      canvas.drawRect(
        Rect.fromLTWH(row.left, row.bottom - 1, row.width, 1),
        Paint()..color = const Color(0xffd4d4d4),
      );
      final textColor = selected
          ? fortuneFormulaSearchSelectedTextColor
          : fortuneFormulaSearchTextColor;
      _drawText(
        canvas,
        function.name,
        Rect.fromLTWH(
          row.left + fortuneFormulaSearchListCellPadding,
          row.top,
          fortuneFormulaSearchFunctionNameWidth,
          row.height,
        ),
        fontSize: 12,
        color: textColor,
      );
      _drawText(
        canvas,
        function.description,
        Rect.fromLTWH(
          row.left +
              fortuneFormulaSearchFunctionNameWidth +
              fortuneFormulaSearchListCellPadding * 2,
          row.top,
          row.width -
              fortuneFormulaSearchFunctionNameWidth -
              fortuneFormulaSearchListCellPadding * 3,
          row.height,
        ),
        fontSize: 12,
        color: textColor,
      );
    }
    if (filteredFunctions.length > visibleRows) {
      _drawScrollbar(
        canvas,
        listRect,
        visibleRows,
        filteredFunctions.length,
        firstVisibleRow: firstVisibleIndex,
      );
    }
    canvas.restore();

    _drawDialogButton(
      canvas,
      fortuneFormulaSearchOkButtonRect(rect),
      locale.ok,
      primary: true,
    );
    _drawDialogButton(
      canvas,
      fortuneFormulaSearchCancelButtonRect(rect),
      locale.cancel,
    );

    if (formulaSearchCategoryMenuOpen) {
      final menuRect = fortuneFormulaSearchCategoryMenuRect(rect);
      _drawShadowBox(
        canvas,
        menuRect,
        radius: 0,
        border: const Color(0xffd4d4d4),
      );
      for (
        var index = 0;
        index < fortuneFormulaSearchCategories.length;
        index += 1
      ) {
        final option = Rect.fromLTWH(
          menuRect.left,
          menuRect.top + index * fortuneFormulaSearchCategoryOptionHeight,
          menuRect.width,
          fortuneFormulaSearchCategoryOptionHeight,
        );
        final category = fortuneFormulaSearchCategories[index];
        if (category.type == formulaSearchCategoryType) {
          canvas.drawRect(option, Paint()..color = const Color(0xffe8f0fe));
        }
        _drawText(
          canvas,
          category.label,
          _menuLabelRect(option, 8),
          fontSize: 12,
        );
      }
    }
  }

  void _drawScrollbar(
    Canvas canvas,
    Rect rect,
    int visibleRows,
    int totalRows, {
    int firstVisibleRow = 0,
  }) {
    if (totalRows <= visibleRows || visibleRows <= 0) {
      return;
    }
    final track = Rect.fromLTWH(rect.right - 12, rect.top, 12, rect.height);
    final thumbHeight = math.max(20.0, rect.height * visibleRows / totalRows);
    final maxFirstRow = math.max(1, totalRows - visibleRows);
    final availableThumbTravel = math.max(0.0, rect.height - thumbHeight);
    final thumbTop =
        track.top +
        availableThumbTravel *
            (firstVisibleRow.clamp(0, maxFirstRow) / maxFirstRow);
    final thumb = Rect.fromLTWH(
      track.left + 3,
      thumbTop + 4,
      7,
      thumbHeight - 8,
    );
    final upPath = Path()
      ..moveTo(track.center.dx, track.top + 4)
      ..lineTo(track.left + 3, track.top + 10)
      ..lineTo(track.right - 3, track.top + 10)
      ..close();
    final downPath = Path()
      ..moveTo(track.center.dx, track.bottom - 4)
      ..lineTo(track.left + 3, track.bottom - 10)
      ..lineTo(track.right - 3, track.bottom - 10)
      ..close();
    canvas.drawPath(upPath, Paint()..color = const Color(0xff9a9a9a));
    canvas.drawPath(downPath, Paint()..color = const Color(0xff9a9a9a));
    canvas.drawRRect(
      RRect.fromRectAndRadius(thumb, const Radius.circular(4)),
      Paint()..color = const Color(0xff8a8a8a),
    );
  }

