  void _drawBarcodeTextMenu(
    Canvas canvas,
    Rect menu,
    List<String> options,
    int? hoveredIndex,
    int? selectedIndex,
    double scrollOffset,
  ) {
    if (options.isEmpty) {
      return;
    }
    _drawShadowBox(canvas, menu, radius: 4);
    canvas.save();
    canvas.clipRect(menu);
    for (var i = 0; i < options.length; i += 1) {
      final row = Rect.fromLTWH(
        menu.left,
        menu.top + i * fortuneContextMenuRowHeight - scrollOffset,
        menu.width,
        fortuneContextMenuRowHeight,
      );
      if (!row.overlaps(menu)) {
        continue;
      }
      if (i == hoveredIndex || (hoveredIndex == null && i == selectedIndex)) {
        canvas.drawRect(row, Paint()..color = const Color(0xffe8f2ff));
      }
      _drawText(
        canvas,
        options[i],
        _menuLabelRect(row, 8),
        fontSize: 12,
        color: const Color(0xff222222),
      );
    }
    canvas.restore();
  }

  void _drawBarcodeButton(
    Canvas canvas,
    Rect rect,
    String label,
    String control, {
    bool primary = false,
    bool enabled = true,
  }) {
    final hovered = barcodeHoveredControl == control && enabled;
    final pressed = barcodePressedControl == control && enabled;
    Color? background;
    Color? border;
    Color? text;
    if (!enabled) {
      background = const Color(0xfff3f3f3);
      border = const Color(0xffd8d8d8);
      text = const Color(0xffa0a0a0);
    } else if (pressed) {
      background = primary ? const Color(0xff1c6fc4) : const Color(0xffe3e3e3);
      border = primary ? const Color(0xff1c6fc4) : const Color(0xffb9b9b9);
    } else if (hovered) {
      background = primary ? const Color(0xff2f8fed) : const Color(0xfff5f5f5);
      border = primary ? const Color(0xff2f8fed) : const Color(0xffb9b9b9);
    }
    _drawDialogButton(
      canvas,
      rect,
      label,
      primary: primary,
      backgroundColor: background,
      borderColor: border,
      textColor: text,
    );
  }

  void _drawBarcodeFormatMenu(Canvas canvas, Rect dialogRect) {
    final menu = fortuneBarcodeFormatMenuRect(
      dialogRect,
      barcodeFormatOptions.length,
    );
    if (menu.isEmpty) {
      return;
    }
    final maxScrollOffset = fortuneBarcodeFormatMenuMaxScrollOffset(
      barcodeFormatOptions.length,
    );
    final scrollOffset = barcodeFormatMenuScrollOffset
        .clamp(0.0, maxScrollOffset)
        .toDouble();
    _drawShadowBox(canvas, menu, radius: 3, border: const Color(0xffc8c8c8));
    canvas.save();
    canvas.clipRect(menu.deflate(1));
    for (var index = 0; index < barcodeFormatOptions.length; index += 1) {
      final itemRect = fortuneBarcodeFormatMenuItemRectAtScroll(
        dialogRect,
        barcodeFormatOptions.length,
        index,
        scrollOffset,
      );
      if (!itemRect.overlaps(menu)) {
        continue;
      }
      if (barcodeFormatMenuHoveredIndex == index ||
          (barcodeFormatMenuHoveredIndex == null &&
              barcodeFormatMenuSelectedIndex == index)) {
        canvas.drawRect(itemRect, Paint()..color = const Color(0xffe8f0fe));
      }
      _drawText(
        canvas,
        barcodeFormatOptions[index],
        itemRect.deflate(8),
        fontSize: 12,
        color: const Color(0xff222222),
      );
    }
    canvas.restore();
  }

  void _drawComboArrow(Canvas canvas, double centerX, double centerY) {
    final path = Path()
      ..moveTo(centerX - 4, centerY - 2)
      ..lineTo(centerX + 4, centerY - 2)
      ..lineTo(centerX, centerY + 3)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xff555555));
  }

  void _drawBarcodeLink(
    Canvas canvas,
    Rect dialogRect,
    Rect widthInput,
    Rect heightInput,
  ) {
    final button = fortuneBarcodeLinkButtonRect(dialogRect);
    final linePaint = Paint()
      ..color = const Color(0xff9b9b9b)
      ..strokeWidth = 1.2
      ..style = PaintingStyle.stroke;
    final x = button.center.dx;
    canvas.drawLine(
      Offset(x, widthInput.center.dy),
      Offset(x, button.top),
      linePaint,
    );
    canvas.drawLine(
      Offset(x, button.bottom),
      Offset(x, heightInput.center.dy),
      linePaint,
    );
    canvas.drawLine(
      Offset(
        fortuneBarcodeWidthUnitRect(dialogRect).right,
        widthInput.center.dy,
      ),
      Offset(x, widthInput.center.dy),
      linePaint,
    );
    canvas.drawLine(
      Offset(
        fortuneBarcodeHeightUnitRect(dialogRect).right,
        heightInput.center.dy,
      ),
      Offset(x, heightInput.center.dy),
      linePaint,
    );
    _drawBarcodeIconButton(
      canvas,
      button,
      'link',
      selected: barcodeAspectLocked,
      drawIcon: _drawImageInsertLinkIcon,
    );
  }

  void _drawBarcodeIconButton(
    Canvas canvas,
    Rect rect,
    String control, {
    bool selected = false,
    required void Function(Canvas, Rect, Color) drawIcon,
  }) {
    final hovered = barcodeHoveredControl == control;
    final pressed = barcodePressedControl == control;
    final fill = pressed || selected
        ? const Color(0xffdbeafe)
        : hovered
        ? const Color(0xfff0f7ff)
        : const Color(0xffffffff);
    final border = pressed || selected
        ? const Color(0xff4d90fe)
        : hovered
        ? const Color(0xff8ab4f8)
        : const Color(0xffc8c8c8);
    final rrect = RRect.fromRectAndRadius(rect, const Radius.circular(4));
    canvas.drawRRect(rrect, Paint()..color = fill);
    canvas.drawRRect(
      rrect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = border,
    );
    drawIcon(
      canvas,
      control == 'rotate' ? rect.deflate(4) : rect.deflate(5),
      const Color(0xff333333),
    );
  }

  void _drawImageInsertButton(
    Canvas canvas,
    Rect rect,
    String label,
    String control, {
    bool primary = false,
    bool enabled = true,
  }) {
    final hovered = imageInsertHoveredControl == control && enabled;
    final pressed = imageInsertPressedControl == control && enabled;
    Color? background;
    Color? border;
    Color? text;
    if (!enabled) {
      background = const Color(0xfff3f3f3);
      border = const Color(0xffd8d8d8);
      text = const Color(0xffa0a0a0);
    } else if (pressed) {
      background = primary ? const Color(0xff1c6fc4) : const Color(0xffe3e3e3);
      border = primary ? const Color(0xff1c6fc4) : const Color(0xffb9b9b9);
    } else if (hovered) {
      background = primary ? const Color(0xff2f8fed) : const Color(0xfff5f5f5);
      border = primary ? const Color(0xff2f8fed) : const Color(0xffb9b9b9);
    }
    _drawDialogButton(
      canvas,
      rect,
      label,
      primary: primary,
      backgroundColor: background,
      borderColor: border,
      textColor: text,
    );
  }

