  void _drawImageInsertLinkIcon(Canvas canvas, Rect rect, Color color) {
    final paint = Paint()
      ..color = color
      ..strokeWidth = 1.6
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.round;
    final left = Rect.fromLTWH(
      rect.left,
      rect.top + rect.height * 0.18,
      rect.width * 0.55,
      rect.height * 0.42,
    );
    final right = Rect.fromLTWH(
      rect.right - rect.width * 0.55,
      rect.bottom - rect.height * 0.60,
      rect.width * 0.55,
      rect.height * 0.42,
    );
    canvas.drawArc(left, math.pi * 0.75, math.pi * 1.35, false, paint);
    canvas.drawArc(right, -math.pi * 0.25, math.pi * 1.35, false, paint);
    canvas.drawLine(
      Offset(rect.left + rect.width * 0.38, rect.center.dy),
      Offset(rect.right - rect.width * 0.38, rect.center.dy),
      paint,
    );
  }

  void _drawImageInsertRotateIcon(Canvas canvas, Rect rect, Color color) {
    final iconSize = math.min(rect.width, rect.height);
    final icon = Icons.refresh_rounded;
    final painter = TextPainter(
      text: TextSpan(
        text: String.fromCharCode(icon.codePoint),
        style: TextStyle(
          color: color,
          fontFamily: icon.fontFamily,
          package: icon.fontPackage,
          fontSize: iconSize * 1.18,
          height: 1,
        ),
      ),
      textDirection: TextDirection.ltr,
    );
    painter.layout();
    painter.paint(canvas, rect.center - painter.size.center(Offset.zero));
  }

  void _drawHyperlinkDialog(Canvas canvas, Size size) {
    if (!hyperlinkDialogOpen) {
      return;
    }
    final settings = workbook.settings;
    final sheet = workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    final cellRect = _cellRectForCoord(
      FortuneCellCoord(selection.row, selection.column),
      settings,
      metrics,
    );
    if (cellRect == null) {
      return;
    }
    if (hyperlinkDialogSelectingCellRange) {
      _drawHyperlinkRangeSelectionDialog(canvas, size, cellRect);
      return;
    }
    final rect = fortuneHyperlinkDialogRect(size, cellRect);
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneHyperlinkDialogBorderRadius,
      border: fortuneHyperlinkDialogBorderColor,
    );
    _drawHyperlinkDialogRow(
      canvas,
      rect,
      0,
      locale.linkText,
      fortuneHyperlinkDialogDisplayInputRect(rect),
      hyperlinkDialogDisplayText,
      focused: true,
    );
    final select = fortuneHyperlinkDialogTypeSelectRect(rect);
    _drawHyperlinkDialogRow(
      canvas,
      rect,
      1,
      locale.linkType,
      select,
      _hyperlinkDialogTypeLabel(hyperlinkDialogLinkType),
    );
    final arrowPaint = Paint()
      ..color = const Color(0xff111111)
      ..style = PaintingStyle.fill;
    final arrow = Path()
      ..moveTo(select.right - 15, select.top + 10)
      ..lineTo(select.right - 7, select.top + 10)
      ..lineTo(select.right - 11, select.top + 15)
      ..close();
    canvas.drawPath(arrow, arrowPaint);
    _drawHyperlinkDialogRow(
      canvas,
      rect,
      2,
      _hyperlinkDialogAddressLabel(hyperlinkDialogLinkType),
      fortuneHyperlinkDialogAddressInputRect(rect),
      hyperlinkDialogAddressText,
      textRect: hyperlinkDialogLinkType == 'cellrange'
          ? fortuneHyperlinkDialogCellRangeInputTextRect(rect)
          : null,
    );
    if (hyperlinkDialogLinkType == 'cellrange') {
      final selector = fortuneHyperlinkDialogCellSelectorRect(rect);
      canvas.drawRRect(
        RRect.fromRectAndRadius(
          selector,
          const Radius.circular(fortuneHyperlinkDialogCellSelectorBorderRadius),
        ),
        Paint()..color = fortuneHyperlinkDialogCellSelectorBackgroundColor,
      );
      canvas.drawRRect(
        RRect.fromRectAndRadius(
          selector,
          const Radius.circular(fortuneHyperlinkDialogCellSelectorBorderRadius),
        ),
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 1
          ..color = fortuneHyperlinkDialogCellSelectorBorderColor,
      );
      final iconPaint = Paint()
        ..color = fortuneHyperlinkDialogCellSelectorIconColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = fortuneHyperlinkDialogCellSelectorIconStrokeWidth;
      final icon = selector.deflate(7);
      canvas.drawRect(icon, iconPaint);
      canvas.drawLine(
        Offset(icon.left, icon.top + icon.height / 2),
        Offset(icon.right, icon.top + icon.height / 2),
        iconPaint,
      );
      canvas.drawLine(
        Offset(icon.left + icon.width / 2, icon.top),
        Offset(icon.left + icon.width / 2, icon.bottom),
        iconPaint,
      );
    }
    _drawDialogButton(
      canvas,
      fortuneHyperlinkDialogCancelButtonRect(rect),
      locale.cancel,
    );
    _drawDialogButton(
      canvas,
      fortuneHyperlinkDialogOkButtonRect(rect),
      locale.ok,
      primary: true,
    );
  }

  void _drawHyperlinkRangeSelectionDialog(
    Canvas canvas,
    Size size,
    Rect cellRect,
  ) {
    final rect = fortuneHyperlinkRangeSelectionDialogRect(size, cellRect);
    _drawShadowBox(
