    _drawText(
      canvas,
      locale.selectCellRange,
      Rect.fromLTWH(
        rect.left + fortuneHyperlinkRangeSelectionPadding,
        rect.top + fortuneHyperlinkRangeSelectionPadding - 2,
        rect.width - fortuneHyperlinkRangeSelectionPadding * 2 - 36,
        fortuneHyperlinkRangeSelectionTitleHeight,
      ),
      fontSize: fortuneHyperlinkRangeSelectionTitleFontSize,
      color: fortuneHyperlinkRangeSelectionTitleColor,
      fontWeight: fortuneHyperlinkRangeSelectionTitleFontWeight,
    );
    final input = fortuneHyperlinkRangeSelectionInputRect(rect);
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        input,
        const Radius.circular(fortuneHyperlinkRangeSelectionInputBorderRadius),
      ),
      Paint()..color = const Color(0xffffffff),
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        input,
        const Radius.circular(fortuneHyperlinkRangeSelectionInputBorderRadius),
      ),
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = fortuneHyperlinkRangeSelectionInputFocusBorderColor,
    );
    final inputText = hyperlinkDialogAddressText.isEmpty
        ? locale.cellRangePlaceholder
        : hyperlinkDialogAddressText;
    _drawText(
      canvas,
      inputText,
      Rect.fromLTWH(
        input.left + fortuneHyperlinkRangeSelectionInputHorizontalPadding,
        input.top,
        input.width - fortuneHyperlinkRangeSelectionInputHorizontalPadding * 2,
        input.height,
      ),
      fontSize: 14,
      color: hyperlinkDialogAddressText.isEmpty
          ? const Color(0xff9b9b9b)
          : const Color(0xff111111),
    );
    _drawDialogButton(
      canvas,
      fortuneHyperlinkRangeSelectionCancelButtonRect(rect),
      locale.cancel,
    );
    _drawDialogButton(
      canvas,
      fortuneHyperlinkRangeSelectionOkButtonRect(rect),
      locale.ok,
      primary: true,
    );
  }

  void _drawHyperlinkCard(Canvas canvas, Size size) {
    if (hyperlinkDialogOpen) {
      return;
    }
    final hyperlink = _selectedHyperlinkFields();
    if (hyperlink == null) {
      return;
    }
    final settings = workbook.settings;
    final sheet = workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final cellRect = _cellRectForCoord(coord, settings, metrics);
    if (cellRect == null) {
      return;
    }
    final allowEdit = settings.allowEdit;
    final showCopy = hyperlink.type == 'webpage';
    final rect = fortuneHyperlinkCardRect(
      size,
      cellRect,
      allowEdit: allowEdit,
      showCopy: showCopy,
    );
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneHyperlinkCardBorderRadius,
      border: fortuneHyperlinkCardBorderColor,
    );
    final contentRect = fortuneHyperlinkCardContentRect(rect);
    final contentLabel = hyperlink.type == 'webpage'
        ? locale.openLink
        : locale.goToLink
              .replaceAll(r'${linkAddress}', hyperlink.address)
              .replaceAll('{linkAddress}', hyperlink.address);
    _drawText(
      canvas,
      contentLabel,
      contentRect.deflate(fortuneHyperlinkCardContentTextInset),
      fontSize: 12,
      color: fortuneHyperlinkCardContentTextColor,
    );
    if (!allowEdit) {
      return;
    }
    final dividerPaint = Paint()..color = fortuneHyperlinkCardDividerColor;
    void drawDivider(double left) {
      canvas.drawRect(
        Rect.fromLTWH(
          left,
          rect.top + (rect.height - fortuneHyperlinkCardDividerHeight) / 2,
          fortuneHyperlinkCardDividerWidth,
          fortuneHyperlinkCardDividerHeight,
        ),
        dividerPaint,
      );
    }

    void drawButton(Rect buttonRect, String label) {
      _drawText(
        canvas,
        label,
        buttonRect,
        fontSize: 12,
        color: fortuneHyperlinkCardButtonTextColor,
        align: TextAlign.center,
      );
    }

    drawDivider(contentRect.right);
    if (showCopy) {
      final copyRect = fortuneHyperlinkCardCopyButtonRect(rect);
      drawButton(copyRect, 'C');
      drawDivider(copyRect.right);
    }
    final editRect = fortuneHyperlinkCardEditButtonRect(
      rect,
      showCopy: showCopy,
    );
    drawButton(editRect, 'E');
    final unlinkRect = fortuneHyperlinkCardUnlinkButtonRect(
      rect,
      showCopy: showCopy,
    );
    drawButton(unlinkRect, 'U');
  }

  ({String type, String address})? _selectedHyperlinkFields() {
    final sheet = workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final cellLink = sheet.cells[coord]?.hyperlink;
    if (cellLink != null) {
      return (
        type: cellLink.linkType ?? 'webpage',
        address: cellLink.linkAddress ?? '',
      );
    }
    final rawLink = sheet.hyperlinks['${coord.row}_${coord.column}'];
    if (rawLink is Map) {
      return (
        type: '${rawLink['linkType'] ?? 'webpage'}',
        address: '${rawLink['linkAddress'] ?? ''}',
      );
    }
    return null;
  }

  String _hyperlinkDialogTypeLabel(String type) {
    return switch (type) {
      'cellrange' => locale.cellRange,
      'sheet' => locale.linkSheetOption,
      _ => locale.linkWebpages,
    };
  }

  String _hyperlinkDialogAddressLabel(String type) {
    return switch (type) {
      'cellrange' => locale.linkCell,
      'sheet' => locale.linkSheet,
      _ => locale.linkAddress,
    };
  }

  void _drawHyperlinkDialogRow(
    Canvas canvas,
    Rect dialogRect,
    int index,
    String label,
    Rect inputRect,
    String value, {
    bool focused = false,
    Rect? textRect,
  }) {
    final top =
        dialogRect.top +
        fortuneHyperlinkDialogPaddingTop +
        index *
            (fortuneHyperlinkDialogInputHeight + fortuneHyperlinkDialogLineGap);
    _drawText(
      canvas,
      label,
      Rect.fromLTWH(
        dialogRect.left + fortuneHyperlinkDialogPaddingLeft,
        top - 2,
        fortuneHyperlinkDialogLabelWidth,
        fortuneHyperlinkDialogLabelBoxHeight,
      ),
      fontSize: 12,
      color: fortuneHyperlinkDialogLabelColor,
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        inputRect,
        const Radius.circular(fortuneHyperlinkDialogInputBorderRadius),
      ),
      Paint()..color = const Color(0xffffffff),
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        inputRect,
        const Radius.circular(fortuneHyperlinkDialogInputBorderRadius),
      ),
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = focused
            ? fortuneHyperlinkDialogInputFocusBorderColor
            : fortuneHyperlinkDialogInputBorderColor,
    );
    if (value.isNotEmpty) {
      final valueRect = textRect ?? inputRect;
      _drawText(
        canvas,
        value,
        Rect.fromLTWH(
          valueRect.left + fortuneHyperlinkDialogInputHorizontalPadding,
          valueRect.top,
          valueRect.width - fortuneHyperlinkDialogInputHorizontalPadding * 2,
          valueRect.height,
        ),
        fontSize: 12,
        color: const Color(0xff111111),
      );
    }
  }

