  bool _dataVerificationDialogUsesType2Selector(String type) {
    return (_dataVerificationDialogType2Options[type] ?? const <String>[])
        .isNotEmpty;
  }

  String _dataVerificationDialogType2Label(String type2) {
    return locale.dataVerificationRuleLabels[type2] ?? type2;
  }

  bool _dataVerificationDialogUsesSecondValueInput(String type) {
    if (type == 'number' ||
        type == 'number_integer' ||
        type == 'number_decimal' ||
        type == 'text_length' ||
        type == 'date') {
      return dataVerificationDialogType2 == 'between' ||
          dataVerificationDialogType2 == 'notBetween';
    }
    return type == 'checkbox';
  }

  Rect _dataVerificationValueInputRect(Rect dialogRect) {
    final input = fortuneDataVerificationInputRect(dialogRect);
    if (!_dataVerificationDialogUsesType2Selector(dataVerificationDialogType)) {
      return input;
    }
    return Rect.fromLTWH(
      input.left +
          fortuneDataVerificationRuleSelectWidth +
          fortuneDataVerificationRuleSelectGap,
      input.top,
      math.max(
        24.0,
        input.width -
            fortuneDataVerificationRuleSelectWidth -
            fortuneDataVerificationRuleSelectGap,
      ),
      input.height,
    );
  }

  String _dataVerificationSecondValueSemanticsLabel(String type) {
    return switch (type) {
      'checkbox' =>
        locale.dataVerificationRuleLabels['notSelected'] ?? 'Not selected',
      'number' ||
      'number_integer' ||
      'number_decimal' ||
      'text_length' ||
      'date' => locale.dataVerificationRuleLabels['between'] ?? 'Between',
      _ => locale.dropdown,
    };
  }

