  void _drawDataVerificationDialog(Canvas canvas, Size size) {
    if (!dataVerificationDialogOpen) {
      return;
    }
    final rect = fortuneDataVerificationDialogRect(size);
    canvas.drawRect(
      Offset.zero & size,
      Paint()..color = const Color(0x1a000000),
    );
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneDataVerificationDialogBorderRadius,
      border: const Color(0x11000000),
    );
    _drawDialogCloseButton(
      canvas,
      fortuneDataVerificationCloseButtonRect(rect),
      'data-verification',
    );

    _drawText(
      canvas,
      locale.dataVerification,
      Rect.fromLTWH(
        rect.left + fortuneDataVerificationContentLeft,
        rect.top + fortuneDataVerificationTitleTop,
        fortuneDataVerificationContentWidth,
        24,
      ),
      fontSize: 16,
