  void _drawSplitTextPreviewTable(Canvas canvas, Rect rect) {
    canvas.save();
    canvas.clipRect(rect.deflate(1));
    final scrollBar = Rect.fromLTWH(
      rect.right - 15,
      rect.top + 1,
      14,
      rect.height - 2,
    );
    canvas.drawRect(scrollBar, Paint()..color = const Color(0xffffffff));
    final arrowPaint = Paint()..color = const Color(0xff888888);
    final topArrow = Path()
      ..moveTo(scrollBar.center.dx, scrollBar.top + 6)
      ..lineTo(scrollBar.left + 4, scrollBar.top + 12)
      ..lineTo(scrollBar.right - 4, scrollBar.top + 12)
      ..close();
    final bottomArrow = Path()
      ..moveTo(scrollBar.center.dx, scrollBar.bottom - 6)
      ..lineTo(scrollBar.left + 4, scrollBar.bottom - 12)
      ..lineTo(scrollBar.right - 4, scrollBar.bottom - 12)
      ..close();
    canvas.drawPath(topArrow, arrowPaint);
    canvas.drawPath(bottomArrow, arrowPaint);

    final tableClip = Rect.fromLTRB(
      rect.left + 5,
      rect.top + 5,
      scrollBar.left - 3,
      rect.bottom - 5,
    );
    canvas.clipRect(tableClip);
    const rowHeight = 17.0;
    var y = rect.top + 5;
    final rows = splitTextPreview.isEmpty
        ? const <List<String>>[[]]
        : splitTextPreview;
    for (final row in rows.take(6)) {
      var x = rect.left + 5;
      final columns = row.isEmpty ? const [''] : row;
      for (final value in columns.take(12)) {
        final empty = value.isEmpty;
        final columnWidth = empty ? 5.0 : math.max(9.0, value.length * 7.0 + 4);
        final cellHeight = empty ? 5.0 : rowHeight;
        final cell = Rect.fromLTWH(x, y, columnWidth, cellHeight);
        canvas.drawRect(
          cell,
          Paint()
            ..style = PaintingStyle.stroke
            ..strokeWidth = 1
            ..color = const Color(0xff333333),
        );
        if (!empty) {
          _drawText(canvas, value, cell.deflate(2), fontSize: 14);
        }
        x += columnWidth - 1;
      }
      y += rowHeight - 1;
    }
    canvas.restore();
  }

