  void _drawScreenshotPreview(Canvas canvas, Rect rect) {
    final range = screenshotRange;
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = const Color(0xffd4d4d4),
    );
    final image = screenshotImage;
    if (image != null) {
      final imageRect = _containRect(
        Size(image.width.toDouble(), image.height.toDouble()),
        rect.deflate(6),
      );
      canvas.drawImageRect(
        image,
        Rect.fromLTWH(0, 0, image.width.toDouble(), image.height.toDouble()),
        imageRect,
        Paint()..filterQuality = FilterQuality.none,
      );
      return;
    }
    if (range == null) {
      return;
    }
    final rowCount = range.rowEnd - range.rowStart + 1;
    final columnCount = range.columnEnd - range.columnStart + 1;
    final visibleRows = math.min(rowCount, 8);
    final visibleColumns = math.min(columnCount, 6);
    final cellWidth = rect.width / visibleColumns;
    final cellHeight = rect.height / visibleRows;
    final sheet = workbook.activeSheet;
    for (var row = 0; row < visibleRows; row += 1) {
      for (var column = 0; column < visibleColumns; column += 1) {
        final cellRect = Rect.fromLTWH(
          rect.left + column * cellWidth,
          rect.top + row * cellHeight,
          cellWidth,
          cellHeight,
        );
        final coord = FortuneCellCoord(
          range.rowStart + row,
          range.columnStart + column,
        );
        final anchor = sheet.mergeAnchorFor(coord);
        final cell = sheet.cells[anchor];
        if (cell?.background != null) {
          canvas.drawRect(cellRect, Paint()..color = cell!.background!);
        }
        canvas.drawRect(
          cellRect,
          Paint()
            ..style = PaintingStyle.stroke
            ..color = const Color(0xffdfdfdf),
        );
        final value = cell?.renderedText ?? '';
        if (value.isNotEmpty) {
          _drawText(
            canvas,
            value,
            cellRect.deflate(4),
            fontSize: 10,
            color: cell?.foreground ?? const Color(0xff000000),
          );
        }
      }
    }
  }

  Rect _containRect(Size source, Rect target) {
    if (source.width <= 0 || source.height <= 0) {
      return target;
    }
    final scale = math.min(
      target.width / source.width,
      target.height / source.height,
    );
    final width = source.width * scale;
    final height = source.height * scale;
    return Rect.fromLTWH(
      target.left + (target.width - width) / 2,
      target.top + (target.height - height) / 2,
      width,
      height,
    );
  }

