      _drawText(
        canvas,
        '${locale.replaceTextbox}:',
        Rect.fromLTWH(content.left + 10, content.top + 38, 118, 30),
        fontSize: 14,
        color: const Color(0xff111111),
      );
      _drawInputShell(canvas, fortuneSearchReplaceInputRect(rect));
    }
    _drawSearchCheckbox(canvas, rect, 0, searchRegex, locale.regexTextbox);
    _drawSearchCheckbox(canvas, rect, 1, searchWholeWord, locale.wholeTextbox);
    _drawSearchCheckbox(
      canvas,
      rect,
      2,
      searchCaseSensitive,
      locale.distinguishTextbox,
    );
    if (searchReplaceMode) {
      _drawDialogButton(
        canvas,
        fortuneSearchButtonRect(rect, 'replaceAll', replace: true),
        locale.allReplaceBtn,
        radius: 4,
        fontSize: 14,
        backgroundColor: const Color(0xffffffff),
        borderColor: fortuneSearchDialogBorderColor,
        textColor: const Color(0xff262a33),
      );
      _drawDialogButton(
        canvas,
        fortuneSearchButtonRect(rect, 'replace', replace: true),
        locale.replaceBtn,
        radius: 4,
        fontSize: 14,
        backgroundColor: const Color(0xffffffff),
        borderColor: fortuneSearchDialogBorderColor,
        textColor: const Color(0xff262a33),
      );
    }
    _drawDialogButton(
      canvas,
      fortuneSearchButtonRect(rect, 'findAll', replace: searchReplaceMode),
      locale.allFindBtn,
      radius: 4,
      fontSize: 14,
      backgroundColor: const Color(0xffffffff),
      borderColor: fortuneSearchDialogBorderColor,
      textColor: const Color(0xff262a33),
    );
    _drawDialogButton(
      canvas,
      fortuneSearchButtonRect(rect, 'findNext', replace: searchReplaceMode),
      locale.findBtn,
      radius: 4,
      fontSize: 14,
      backgroundColor: const Color(0xffffffff),
      borderColor: fortuneSearchDialogBorderColor,
      textColor: const Color(0xff262a33),
    );
    _drawDialogButton(
      canvas,
      fortuneSearchBottomCloseButtonRect(rect),
      locale.close,
      radius: 4,
      fontSize: 14,
      backgroundColor: const Color(0xffffffff),
      borderColor: fortuneSearchDialogBorderColor,
      textColor: const Color(0xff262a33),
    );
    if (searchResults.isNotEmpty) {
      _drawSearchResults(canvas, fortuneSearchResultsRect(rect));
    }
  }

  void _drawFloatingDialogSurface(Canvas canvas, Rect rect, double radius) {
    final rrect = RRect.fromRectAndRadius(rect, Radius.circular(radius));
    canvas.drawShadow(
      Path()..addRRect(rrect),
      const Color(0x22000000),
      18,
      true,
    );
    canvas.drawRRect(rrect, Paint()..color = const Color(0xffffffff));
  }

  void _drawDialogCloseButton(
    Canvas canvas,
    Rect rect,
    String key, {
    Rect? glyphRect,
  }) {
    final pressed = dialogClosePressedKey == key;
    final hovered = pressed || dialogCloseHoveredKey == key;
    if (hovered) {
      canvas.drawRRect(
        RRect.fromRectAndRadius(rect, const Radius.circular(4)),
        Paint()..color = pressed ? const Color(0xffdadce0) : const Color(0xfff1f3f4),
      );
    }
    _drawCloseGlyph(
      canvas,
      glyphRect ?? rect,
      color: hovered ? const Color(0xff3c4043) : const Color(0xff9a9a9a),
    );
  }

  void _drawCloseGlyph(Canvas canvas, Rect rect, {Color color = const Color(0xff9a9a9a)}) {
    final glyphRect = Rect.fromCenter(
      center: rect.center,
      width: fortuneSheetDialogCloseGlyphSize,
      height: fortuneSheetDialogCloseGlyphSize,
    );
    final paint = Paint()
      ..color = color
      ..strokeWidth = 1.4
      ..strokeCap = StrokeCap.round;
    canvas.drawLine(glyphRect.topLeft, glyphRect.bottomRight, paint);
    canvas.drawLine(glyphRect.topRight, glyphRect.bottomLeft, paint);
  }

  void _drawBarcodeCloseGlyph(Canvas canvas, Rect rect) {
    _drawDialogCloseButton(canvas, rect, 'barcode');
  }

  void _drawSearchTab(Canvas canvas, Rect rect, String label, bool selected) {
    canvas.drawRect(
      rect,
      Paint()
        ..color = selected
            ? fortuneSearchSelectedColor
            : const Color(0xffffffff),
    );
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = selected
            ? fortuneSearchSelectedBorderColor
            : fortuneSearchDialogBorderColor,
    );
    _drawText(
      canvas,
      label,
      rect,
      fontSize: 14,
      color: selected ? const Color(0xffffffff) : const Color(0xff111111),
      align: TextAlign.center,
    );
  }

  void _drawInputShell(Canvas canvas, Rect rect) {
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = const Color(0xff111111),
    );
  }

  void _drawSearchCheckbox(
    Canvas canvas,
    Rect rect,
    int index,
    bool checked,
    String label,
  ) {
    final box = fortuneSearchCheckboxRect(rect, index);
    _drawCheckbox(canvas, box, checked);
    _drawText(
      canvas,
      label,
      Rect.fromLTWH(box.right + 6, box.top - 8, 140, 30),
      fontSize: 14,
      color: const Color(0xff111111),
    );
  }

  void _drawSearchResults(Canvas canvas, Rect rect) {
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = fortuneSearchResultsBorderColor,
    );
    final header = Rect.fromLTWH(
      rect.left,
      rect.top,
      rect.width,
      fortuneSearchResultRowHeight,
    );
    canvas.drawLine(
      header.bottomLeft,
      header.bottomRight,
      Paint()..color = fortuneSearchResultsBorderColor,
    );
    _drawSearchResultColumns(
      canvas,
      header,
      locale.searchTargetSheet,
      locale.searchTargetCell,
      locale.searchTargetValue,
      selected: false,
    );
    final visible = math.min(searchResults.length, 6);
    for (var i = 0; i < visible; i += 1) {
      final row = Rect.fromLTWH(
        rect.left,
        rect.top +
            fortuneSearchResultRowHeight +
            i * fortuneSearchResultRowHeight,
        rect.width,
        fortuneSearchResultRowHeight,
      );
      final selected = i == searchSelectedResultIndex;
      if (selected) {
        canvas.drawRect(row, Paint()..color = fortuneSearchSelectedColor);
      }
      canvas.drawLine(
        row.bottomLeft,
        row.bottomRight,
        Paint()..color = fortuneSearchResultsBorderColor,
      );
      final result = searchResults[i];
      _drawSearchResultColumns(
        canvas,
        row,
        result.sheetName,
        result.cellPosition,
        result.value,
        selected: selected,
      );
    }
  }

  void _drawSearchResultColumns(
    Canvas canvas,
    Rect rect,
    String sheet,
    String cell,
    String value, {
    required bool selected,
  }) {
    final color = selected ? const Color(0xffffffff) : const Color(0xff111111);
    _drawText(
      canvas,
      sheet,
      Rect.fromLTWH(
        rect.left + fortuneSearchResultColumnPadding,
        rect.top,
        rect.width * fortuneSearchResultSheetColumnRatio -
            fortuneSearchResultColumnPadding * 2,
        rect.height,
      ),
      fontSize: 12,
      color: color,
      align: TextAlign.center,
    );
    _drawText(
      canvas,
      cell,
      Rect.fromLTWH(
        rect.left +
            rect.width * fortuneSearchResultSheetColumnRatio +
            fortuneSearchResultColumnPadding,
        rect.top,
        rect.width * fortuneSearchResultCellColumnRatio -
            fortuneSearchResultColumnPadding * 2,
        rect.height,
      ),
      fontSize: 12,
      color: color,
      align: TextAlign.center,
    );
    _drawText(
      canvas,
      value,
      Rect.fromLTWH(
        rect.left +
            rect.width *
                (fortuneSearchResultSheetColumnRatio +
                    fortuneSearchResultCellColumnRatio) +
            fortuneSearchResultColumnPadding,
        rect.top,
        rect.width * fortuneSearchResultValueColumnRatio -
            fortuneSearchResultColumnPadding * 2,
        rect.height,
      ),
      fontSize: 12,
      color: color,
      align: TextAlign.center,
    );
  }

  void _drawDataVerificationInputBox(Canvas canvas, Rect rect) {
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0xffd4d4d4),
    );
  }

  void _drawDataVerificationRangeIcon(Canvas canvas, Rect inputRect) {
    final icon = Rect.fromLTWH(inputRect.right - 22, inputRect.top + 8, 14, 14);
    final paint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1
      ..color = const Color(0xff222222);
    canvas.drawRect(icon, paint);
    canvas.drawLine(
      Offset(icon.left, icon.top + icon.height / 3),
      Offset(icon.right, icon.top + icon.height / 3),
      paint,
    );
    canvas.drawLine(
      Offset(icon.left, icon.top + icon.height * 2 / 3),
      Offset(icon.right, icon.top + icon.height * 2 / 3),
      paint,
    );
    canvas.drawLine(
      Offset(icon.left + icon.width / 3, icon.top),
      Offset(icon.left + icon.width / 3, icon.bottom),
      paint,
    );
    canvas.drawLine(
      Offset(icon.left + icon.width * 2 / 3, icon.top),
      Offset(icon.left + icon.width * 2 / 3, icon.bottom),
      paint,
    );
  }

  void _drawConditionRuleDialog(Canvas canvas, Size size) {
    if (!conditionRuleDialogOpen) {
      return;
    }
    final height = _conditionRuleDialogHeight();
    final rect = fortuneConditionRuleDialogRect(size, height);
    final contentLeft =
        rect.left + fortuneConditionRuleContentPaddingHorizontal;
    final contentWidth =
        rect.width - fortuneConditionRuleContentPaddingHorizontal * 2;
    canvas.drawRect(
      Offset.zero & size,
      Paint()..color = fortuneConditionRuleOverlayColor,
    );
    _drawShadowBox(
      canvas,
      rect,
      radius: fortuneConditionRuleDialogBorderRadius,
      border: fortuneConditionRuleDialogBorderColor,
    );
    _drawDialogCloseButton(
      canvas,
      fortuneConditionRuleCloseButtonRect(rect),
      'condition-rule',
    );
    _drawText(
      canvas,
      _conditionRuleTitle(),
      Rect.fromLTWH(
        contentLeft,
        rect.top + fortuneConditionRuleTitleTop,
        contentWidth,
        fortuneConditionRuleTitleHeight,
      ),
      fontSize: fortuneConditionRuleTitleFontSize,
    );
    _drawText(
      canvas,
      _conditionRuleDescription(),
      Rect.fromLTWH(
        contentLeft,
        rect.top + fortuneConditionRuleValueTop,
        contentWidth,
        fortuneConditionRuleValueHeight,
      ),
      fontSize: fortuneConditionRuleFontSize,
      fontWeight: fortuneConditionRuleValueFontWeight,
    );
    if (conditionRuleType == fortuneConditionRuleDuplicateType) {
      _drawConditionRuleSelect(canvas, rect);
    } else if (_conditionRuleIsProjectType()) {
      final prefixWidth = _conditionRuleProjectPrefixWidth();
      final input = Rect.fromLTWH(
        contentLeft + prefixWidth + fortuneConditionRuleProjectInputMargin,
        rect.top + fortuneConditionRuleControlTop,
        fortuneConditionRuleInputBoxWidth,
        fortuneConditionRuleInputBoxHeight,
      );
      _drawText(
        canvas,
        _conditionRuleProjectPrefix(),
        Rect.fromLTWH(contentLeft, input.top, prefixWidth, input.height),
        fontSize: fortuneConditionRuleFontSize,
      );
      canvas.drawRect(
        input,
        Paint()..color = fortuneConditionRuleInputBackgroundColor,
      );
      canvas.drawRect(
        input,
        Paint()
          ..style = PaintingStyle.stroke
          ..color = fortuneConditionRuleInputBorderColor,
      );
      _drawText(
        canvas,
        _conditionRuleProjectSuffix(),
        Rect.fromLTWH(
          input.right + fortuneConditionRuleProjectInputMargin,
          input.top,
          _conditionRuleProjectSuffixWidth(),
          input.height,
        ),
        fontSize: fortuneConditionRuleFontSize,
      );
    } else if (!_conditionRuleIsAverageType()) {
      final inputWidth = conditionRuleType == fortuneConditionRuleBetweenType
          ? fortuneConditionRuleBetweenInputBoxWidth
          : fortuneConditionRuleInputBoxWidth;
      final input = Rect.fromLTWH(
        contentLeft,
        rect.top + fortuneConditionRuleControlTop,
        inputWidth,
        fortuneConditionRuleInputBoxHeight,
      );
      canvas.drawRect(
        input,
        Paint()..color = fortuneConditionRuleInputBackgroundColor,
      );
      canvas.drawRect(
        input,
        Paint()
          ..style = PaintingStyle.stroke
          ..color = fortuneConditionRuleInputBorderColor,
      );
    }
    if (conditionRuleType == fortuneConditionRuleBetweenType) {
      final firstInput = Rect.fromLTWH(
        contentLeft,
        rect.top + fortuneConditionRuleControlTop,
        fortuneConditionRuleBetweenInputBoxWidth,
        fortuneConditionRuleInputBoxHeight,
      );
      _drawText(
        canvas,
        locale.betweenSeparator,
        Rect.fromLTWH(
          firstInput.right + fortuneConditionRuleBetweenSeparatorMargin,
          firstInput.top,
          fortuneConditionRuleBetweenSeparatorWidth,
          firstInput.height,
        ),
        fontSize: fortuneConditionRuleFontSize,
      );
      final secondInput = Rect.fromLTWH(
        firstInput.right +
            fortuneConditionRuleBetweenSeparatorMargin * 2 +
            fortuneConditionRuleBetweenSeparatorWidth,
        firstInput.top,
        fortuneConditionRuleBetweenInputBoxWidth,
        fortuneConditionRuleInputBoxHeight,
      );
      canvas.drawRect(
        secondInput,
        Paint()..color = fortuneConditionRuleInputBackgroundColor,
      );
      canvas.drawRect(
        secondInput,
        Paint()
          ..style = PaintingStyle.stroke
          ..color = fortuneConditionRuleInputBorderColor,
      );
    }
    final setTop = _conditionRuleSetAsTop(rect);
    _drawText(
      canvas,
      '${locale.setAs}:',
      Rect.fromLTWH(
        contentLeft,
        setTop,
        contentWidth,
        fortuneConditionRuleSetTitleHeight,
      ),
      fontSize: fortuneConditionRuleSetTitleFontSize,
    );
    final setBox = Rect.fromLTWH(
      contentLeft,
      setTop + fortuneConditionRuleSetBoxTopOffset,
      contentWidth,
      fortuneConditionRuleSetBoxHeight,
    );
    canvas.drawRect(
      setBox,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = fortuneConditionRuleSetBoxBorderColor,
    );
    _drawConditionRuleFormatOption(
      canvas,
      Rect.fromLTWH(
        contentLeft,
        setTop + fortuneConditionRuleSetBoxTopOffset,
        contentWidth,
        fortuneConditionRuleSetRowHeight,
      ),
      locale.textColor,
      fortuneConditionRuleTextColorChoices,
      conditionRuleTextColor,
      conditionRuleTextColorEnabled,
    );
    _drawConditionRuleFormatOption(
      canvas,
      Rect.fromLTWH(
        contentLeft,
        setTop +
            fortuneConditionRuleSetBoxTopOffset +
            fortuneConditionRuleSetRowHeight,
        contentWidth,
        fortuneConditionRuleSetRowHeight,
      ),
      locale.cellColor,
      fortuneConditionRuleCellColorChoices,
      conditionRuleCellColor,
      conditionRuleCellColorEnabled,
    );
    _drawDialogButton(
      canvas,
      fortuneConditionRuleConfirmButtonRect(rect),
      locale.ok,
      primary: true,
      fontSize: fortuneConditionRuleButtonFontSize,
      radius: fortuneConditionRuleButtonBorderRadius,
      backgroundColor: fortuneConditionRulePrimaryButtonColor,
      borderColor: fortuneConditionRulePrimaryButtonColor,
      textColor: fortuneConditionRulePrimaryButtonTextColor,
    );
    _drawDialogButton(
      canvas,
      fortuneConditionRuleCancelButtonRect(rect),
      locale.cancel,
      fontSize: fortuneConditionRuleButtonFontSize,
      radius: fortuneConditionRuleButtonBorderRadius,
      backgroundColor: fortuneConditionRuleCloseButtonBackgroundColor,
      borderColor: fortuneConditionRuleCloseButtonBorderColor,
      textColor: fortuneConditionRuleCloseButtonTextColor,
    );
    if (conditionRuleType == fortuneConditionRuleDuplicateType &&
        conditionRuleDuplicateMenuOpen) {
      _drawConditionRuleSelectOptions(canvas, rect);
    }
  }

  double _conditionRuleDialogHeight() {
    if (conditionRuleType == fortuneConditionRuleBetweenType) {
      return fortuneConditionRuleExpandedDialogHeight;
    }
    if (_conditionRuleIsAverageType()) {
      return fortuneConditionRuleAverageDialogHeight;
    }
    return fortuneConditionRuleDefaultDialogHeight;
  }

  double _conditionRuleSetAsTop(Rect rect) {
    if (conditionRuleType == fortuneConditionRuleBetweenType) {
      return rect.top + fortuneConditionRuleDefaultSetTop;
    }
    if (_conditionRuleIsAverageType()) {
      return rect.top + fortuneConditionRuleAverageSetTop;
    }
    return rect.top + fortuneConditionRuleDefaultSetTop;
  }

  void _drawConditionRuleFormatOption(
    Canvas canvas,
    Rect rect,
    String label,
    List<String> choices,
    String value,
    bool selected,
  ) {
    final contentLeft = rect.left + fortuneConditionRuleSetRowPaddingHorizontal;
    final colorLineTop = rect.top + fortuneConditionRuleSetRowPaddingVertical;
    final checkbox = Rect.fromLTWH(
      contentLeft,
      colorLineTop + fortuneConditionRuleSetCheckboxMarginTop,
      fortuneConditionRuleSetCheckboxSize,
      fortuneConditionRuleSetCheckboxSize,
    );
    canvas.drawRect(
      checkbox,
      Paint()..color = fortuneConditionRuleSetCheckboxBackgroundColor,
    );
    canvas.drawRect(
      checkbox,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = fortuneConditionRuleSetCheckboxBorderWidth
        ..color = fortuneConditionRuleSetCheckboxBorderColor,
    );
    if (selected) {
      final path = Path()
        ..moveTo(
          checkbox.left + fortuneConditionRuleSetCheckboxCheckStartInset,
          checkbox.center.dy,
        )
        ..lineTo(
          checkbox.left + fortuneConditionRuleSetCheckboxCheckMiddleInset,
          checkbox.bottom - fortuneConditionRuleSetCheckboxCheckEndInset,
        )
        ..lineTo(
          checkbox.right - fortuneConditionRuleSetCheckboxCheckEndInset,
          checkbox.top + fortuneConditionRuleSetCheckboxCheckStartInset,
        );
      canvas.drawPath(
        path,
        Paint()
          ..color = fortuneConditionRuleSetCheckboxCheckColor
          ..style = PaintingStyle.stroke
          ..strokeWidth = fortuneConditionRuleSetCheckboxCheckStrokeWidth,
      );
    }
    _drawText(
      canvas,
      label,
      Rect.fromLTWH(
        contentLeft +
            fortuneConditionRuleSetCheckboxSize +
            fortuneConditionRuleSetCheckboxLabelGap,
        colorLineTop,
        fortuneConditionRuleSetLabelWidth,
        fortuneConditionRuleSetColorLineHeight,
      ),
      fontSize: fortuneConditionRuleFontSize,
      color: fortuneConditionRuleSetLabelColor,
    );
    for (var index = 0; index < choices.length; index += 1) {
      final colorText = choices[index];
      final swatch = _conditionRulePaletteRect(rect, index, choices.length);
      final swatchBox = swatch.inflate(fortuneConditionRuleColorInputPadding);
      canvas.drawRect(
        swatchBox,
        Paint()..color = fortuneConditionRuleColorInputBackgroundColor,
      );
      canvas.drawRect(
        swatchBox,
        Paint()
          ..style = PaintingStyle.stroke
          ..color = fortuneConditionRuleColorInputBorderColor,
      );
      canvas.drawRect(
        swatch,
        Paint()
          ..color =
              FortuneSheetCodec.parseColor(colorText) ??
              fortuneConditionRuleColorSwatchFallbackColor,
      );
      canvas.drawRect(
        swatch,
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = colorText == value
              ? fortuneConditionRuleColorSwatchSelectedStrokeWidth
              : fortuneConditionRuleColorSwatchStrokeWidth
          ..color = colorText == value
              ? fortuneConditionRuleColorSwatchSelectedBorderColor
              : fortuneConditionRuleColorSwatchBorderColor,
      );
    }
  }

  Rect _conditionRulePaletteRect(Rect row, int index, int count) {
    final paletteWidth =
        count * fortuneConditionRuleColorSwatchSize +
        (count - 1) * fortuneConditionRuleColorSwatchGap;
    final left =
        row.right -
        fortuneConditionRuleSetRowPaddingHorizontal -
        paletteWidth +
        index *
            (fortuneConditionRuleColorSwatchSize +
                fortuneConditionRuleColorSwatchGap);
    final top =
        row.top +
        fortuneConditionRuleSetRowPaddingVertical +
        (fortuneConditionRuleSetColorLineHeight -
                fortuneConditionRuleColorSwatchSize) /
            2;
    return Rect.fromLTWH(
      left,
      top,
      fortuneConditionRuleColorSwatchSize,
      fortuneConditionRuleColorSwatchSize,
    );
  }

  void _drawConditionRuleSelect(Canvas canvas, Rect dialogRect) {
    final select = _conditionRuleSelectRect(dialogRect);
    canvas.drawRect(
      select,
      Paint()..color = fortuneConditionRuleSelectBackgroundColor,
    );
    canvas.drawRect(
      select,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = fortuneConditionRuleInputBorderColor,
    );
    _drawText(
      canvas,
      _conditionRuleDuplicateLabel(conditionRuleDuplicateValue),
      Rect.fromLTWH(
        select.left + fortuneConditionRuleSelectLabelLeftPadding,
        select.top,
        select.width -
            fortuneConditionRuleSelectArrowWidth -
            fortuneConditionRuleSelectLabelRightPadding,
        select.height,
      ),
      fontSize: fortuneConditionRuleFontSize,
    );
    final arrowCenter = Offset(
      select.right - fortuneConditionRuleSelectArrowWidth / 2,
      select.center.dy + fortuneConditionRuleSelectArrowCenterYOffset,
    );
    final arrow = Path()
      ..moveTo(
        arrowCenter.dx - fortuneConditionRuleSelectArrowHalfWidth,
        arrowCenter.dy - fortuneConditionRuleSelectArrowVerticalOffset,
      )
      ..lineTo(
        arrowCenter.dx,
        arrowCenter.dy + fortuneConditionRuleSelectArrowVerticalOffset,
      )
      ..lineTo(
        arrowCenter.dx + fortuneConditionRuleSelectArrowHalfWidth,
        arrowCenter.dy - fortuneConditionRuleSelectArrowVerticalOffset,
      );
    canvas.drawPath(
      arrow,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = fortuneConditionRuleSelectArrowStrokeWidth
        ..color = fortuneConditionRuleSelectArrowColor,
    );
  }

  void _drawConditionRuleSelectOptions(Canvas canvas, Rect dialogRect) {
    final select = _conditionRuleSelectRect(dialogRect);
    final options = Rect.fromLTWH(
      select.left,
      select.bottom,
      select.width,
      fortuneConditionRuleSelectOptionHeight *
          fortuneConditionRuleDuplicateValues.length,
    );
    canvas.drawRect(
      options,
      Paint()..color = fortuneConditionRuleSelectBackgroundColor,
    );
    canvas.drawRect(
      options,
      Paint()
        ..style = PaintingStyle.stroke
        ..color = fortuneConditionRuleInputBorderColor,
    );
    for (
      var index = 0;
      index < fortuneConditionRuleDuplicateValues.length;
      index += 1
    ) {
      final value = fortuneConditionRuleDuplicateValues[index];
      final row = Rect.fromLTWH(
        options.left,
        options.top + index * fortuneConditionRuleSelectOptionHeight,
        options.width,
        fortuneConditionRuleSelectOptionHeight,
      );
      if (conditionRuleDuplicateValue == value) {
        canvas.drawRect(
          row,
          Paint()..color = fortuneConditionRuleSelectOptionSelectedColor,
        );
      }
      _drawText(
        canvas,
        _conditionRuleDuplicateLabel(value),
        Rect.fromLTWH(
          row.left + fortuneConditionRuleSelectLabelLeftPadding,
          row.top,
          row.width - fortuneConditionRuleSelectLabelLeftPadding * 2,
          row.height,
        ),
        fontSize: fortuneConditionRuleFontSize,
      );
    }
  }

  Rect _conditionRuleSelectRect(Rect dialogRect) {
    return Rect.fromLTWH(
      dialogRect.left + fortuneConditionRuleContentPaddingHorizontal,
      dialogRect.top + fortuneConditionRuleControlTop,
      fortuneConditionRuleSelectBoxWidth,
      fortuneConditionRuleSelectBoxHeight,
    );
  }

  String _conditionRuleDuplicateLabel(String value) {
    if (value == fortuneConditionRuleUniqueValue) {
      return locale.uniqueValue;
    }
    return locale.duplicateValue;
  }

  String _conditionRuleTitle() {
    return locale.conditionRuleTitles[conditionRuleType] ?? conditionRuleType;
  }

  String _conditionRuleDescription() {
    return locale.conditionRuleDescriptions[conditionRuleType] ??
        locale.conditionRuleFallbackDescription;
  }

  bool _conditionRuleIsAverageType() {
    return fortuneConditionRuleAverageTypes.contains(conditionRuleType);
  }

  bool _conditionRuleIsProjectType() {
    return fortuneConditionRuleProjectTypes.contains(conditionRuleType);
  }

  String _conditionRuleProjectPrefix() {
    if (fortuneConditionRuleProjectTopTypes.contains(conditionRuleType)) {
      return locale.top;
    }
    if (fortuneConditionRuleProjectBottomTypes.contains(conditionRuleType)) {
      return locale.bottom;
    }
    return '';
  }

  String _conditionRuleProjectSuffix() {
    if (fortuneConditionRuleProjectItemTypes.contains(conditionRuleType)) {
      return locale.item;
    }
    if (fortuneConditionRuleProjectPercentTypes.contains(conditionRuleType)) {
      return locale.percent;
    }
    return '';
  }

  double _conditionRuleProjectPrefixWidth() {
    if (fortuneConditionRuleProjectTopTypes.contains(conditionRuleType)) {
      return fortuneConditionRuleProjectTopLabelWidth;
    }
    if (fortuneConditionRuleProjectBottomTypes.contains(conditionRuleType)) {
      return fortuneConditionRuleProjectBottomLabelWidth;
    }
    return 0;
  }

  double _conditionRuleProjectSuffixWidth() {
    if (fortuneConditionRuleProjectItemTypes.contains(conditionRuleType)) {
      return fortuneConditionRuleProjectItemLabelWidth;
    }
    if (fortuneConditionRuleProjectPercentTypes.contains(conditionRuleType)) {
      return fortuneConditionRuleProjectPercentLabelWidth;
    }
    return 0;
  }

  void _drawCheckbox(Canvas canvas, Rect rect, bool checked) {
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0xff5f6368),
    );
    if (checked) {
      final path = Path()
        ..moveTo(rect.left + 3, rect.center.dy)
        ..lineTo(rect.left + 6, rect.bottom - 3)
        ..lineTo(rect.right - 3, rect.top + 3);
      canvas.drawPath(
        path,
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 2
          ..strokeCap = StrokeCap.round
          ..strokeJoin = StrokeJoin.round
          ..color = const Color(0xff0188fb),
      );
    }
  }

  void _drawRadio(Canvas canvas, Rect rect, bool selected) {
    canvas.drawOval(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0xff5f6368),
    );
    if (selected) {
      canvas.drawOval(
        rect.deflate(4),
        Paint()..color = const Color(0xff0188fb),
      );
    }
  }

  void _drawDialogButton(
    Canvas canvas,
    Rect rect,
    String label, {
    bool primary = false,
    double fontSize = 12,
    double radius = 3,
    Color? backgroundColor,
    Color? borderColor,
    Color? textColor,
  }) {
    final rrect = RRect.fromRectAndRadius(rect, Radius.circular(radius));
    canvas.drawRRect(
      rrect,
      Paint()
        ..color =
            backgroundColor ??
            (primary
                ? fortuneDialogPrimaryButtonBackgroundColor
                : fortuneDialogDefaultButtonBackgroundColor),
    );
    canvas.drawRRect(
      rrect,
      Paint()
        ..style = PaintingStyle.stroke
        ..color =
            borderColor ??
            (primary
                ? fortuneDialogPrimaryButtonBackgroundColor
                : fortuneDialogDefaultButtonBorderColor),
    );
    _drawText(
      canvas,
      label,
      rect,
      fontSize: fontSize,
      color:
          textColor ??
          (primary
              ? fortuneDialogPrimaryButtonTextColor
              : fortuneDialogDefaultButtonTextColor),
      align: TextAlign.center,
    );
  }

  void _drawSheetTabMenu(Canvas canvas) {
    final at = sheetTabMenuAt;
    if (at == null) {
      return;
    }
    final rect = fortuneSheetTabMenuRect(at, sheetTabMenuItems);
    _drawShadowBox(canvas, rect, radius: 4, border: const Color(0x33000000));
    var y = rect.top + fortuneSheetTabMenuContentTopPadding;
    for (var index = 0; index < sheetTabMenuItems.length; index += 1) {
      final item = sheetTabMenuItems[index];
      if (item == '|') {
        canvas.drawRect(
          Rect.fromLTWH(
            rect.left,
            y + fortuneSheetTabMenuDividerTopInset,
            rect.width,
            fortuneSheetTabMenuDividerStrokeHeight,
          ),
          Paint()..color = const Color(0xffe0e0e0),
        );
        y += fortuneSheetTabMenuDividerHeight;
        continue;
      }
      _drawText(
        canvas,
        _sheetTabMenuLabel(item),
        fortuneSheetTabMenuItemTextRect(at, index, sheetTabMenuItems),
        fontSize: fortuneSheetTabMenuFontSize,
      );
      y += fortuneSheetTabMenuRowHeight;
    }
    if (sheetTabColorMenuOpen) {
      final colorRect = fortuneSheetTabColorMenuRect(at, sheetTabMenuItems);
      if (!colorRect.isEmpty) {
        _drawToolbarFontColorPopup(
          canvas,
          colorRect,
          resetLabel: locale.customColorReset,
          confirmLabel: locale.customColorConfirm,
        );
      }
    }
  }

  String _sheetTabMenuLabel(String item) {
    return locale.sheetTabMenuLabels[item] ?? item;
  }

  void _drawHiddenSheetList(Canvas canvas) {
    final at = hiddenSheetListAt;
    if (at == null) {
      return;
    }
    final hidden = <FortuneSheet>[];
    for (final sheet in workbook.sheets) {
      if (sheet.hide == 1) {
        hidden.add(sheet);
      }
    }
    if (hidden.isEmpty) {
      return;
    }
    final rect = fortuneHiddenSheetListRect(at, hidden.length);
    _drawShadowBox(canvas, rect, radius: 4, border: const Color(0x33000000));
    for (var index = 0; index < hidden.length; index += 1) {
      final sheet = hidden[index];
      if (sheet.color != null) {
        canvas.drawRect(
          fortuneHiddenSheetColorRect(at, index, hidden.length),
          Paint()
            ..color =
                FortuneSheetCodec.parseColor(sheet.color) ??
                const Color(0xff0188fb),
        );
      }
      _drawText(
        canvas,
        sheet.name,
        fortuneHiddenSheetTextRect(at, index, hidden.length),
        fontSize: fortuneSheetTabMenuFontSize,
      );
    }
  }

  void _drawSheetList(Canvas canvas, Size size) {
    final at = sheetListAt;
    if (at == null || workbook.sheets.isEmpty) {
      return;
    }
    final sheetCount = workbook.sheets.length;
    final rect = fortuneSheetListRect(
      at,
      sheetCount,
      viewportHeight: size.height,
    );
    final scrolledAt = at.translate(0, -sheetListScrollOffset);
    _drawShadowBox(canvas, rect, radius: 4, border: const Color(0x33000000));
    canvas.save();
    canvas.clipRect(rect);
    for (var index = 0; index < sheetCount; index += 1) {
      final sheet = workbook.sheets[index];
      final rowTop =
          scrolledAt.dy +
          fortuneSheetTabMenuContentTopPadding +
          index * fortuneSheetListRowHeight;
      if (rowTop >= rect.bottom ||
          rowTop + fortuneSheetListRowHeight <= rect.top) {
        continue;
      }
      if (index == hoveredSheetListIndex) {
        canvas.drawRect(
          Rect.fromLTWH(
            rect.left,
            rowTop,
            rect.width,
            fortuneSheetListRowHeight,
          ),
          Paint()..color = fortuneSheetListHoverColor,
        );
      }
      if (index == workbook.activeSheetIndex) {
        _drawText(
          canvas,
          '*',
          fortuneSheetListCheckRect(scrolledAt, index, sheetCount),
          fontSize: fortuneSheetTabMenuFontSize,
          align: TextAlign.center,
        );
      }
      if (sheet.color != null) {
        canvas.drawRect(
          fortuneHiddenSheetColorRect(scrolledAt, index, sheetCount),
          Paint()
            ..color =
                FortuneSheetCodec.parseColor(sheet.color) ??
                const Color(0xff0188fb),
        );
      }
      _drawText(
        canvas,
        sheet.name,
        fortuneSheetListTextRect(scrolledAt, index, sheetCount),
        fontSize: fortuneSheetTabMenuFontSize,
      );
      if (sheet.hide == 1) {
        final hiddenButtonRect = fortuneSheetListHiddenButtonRect(
          scrolledAt,
          index,
          sheetCount,
        );
        if (index == hoveredSheetListHiddenButtonIndex) {
          canvas.drawRect(
            hiddenButtonRect,
            Paint()..color = fortuneSheetListHiddenButtonHoverColor,
          );
        }
        FortuneToolbarIconPainter.draw(canvas, 'hidden', hiddenButtonRect);
      }
    }
    canvas.restore();
  }

  void _drawShadowBox(
    Canvas canvas,
    Rect rect, {
    double radius = 4,
    Color? border,
  }) {
    final rrect = RRect.fromRectAndRadius(rect, Radius.circular(radius));
    canvas.drawRRect(
      rrect.shift(fortuneToolbarPopupShadowOffset),
      Paint()
        ..color = fortuneToolbarPopupShadowColor
        ..maskFilter = const ui.MaskFilter.blur(
          ui.BlurStyle.normal,
          fortuneToolbarPopupShadowBlur,
        ),
    );
    canvas.drawRRect(rrect, Paint()..color = const Color(0xffffffff));
    if (border != null) {
      canvas.drawRRect(
        rrect,
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 1
          ..color = border,
      );
    }
  }

  void _drawToolbarGlyph(Canvas canvas, String item, Offset center) {
    FortuneToolbarIconPainter.draw(
      canvas,
      item,
      Rect.fromCenter(center: center, width: 24, height: 24),
      currency: workbook.settings.currency,
    );
  }

  void _drawText(
    Canvas canvas,
    String value,
    Rect rect, {
    double fontSize = 12,
    Color color = const Color(0xff333333),
    bool bold = false,
    bool italic = false,
    FontWeight? fontWeight,
    TextAlign align = TextAlign.left,
  }) {
    final paragraphStyle = ui.ParagraphStyle(
      textDirection: textDirection,
      textAlign: align,
      fontSize: fontSize,
      maxLines: 1,
      ellipsis: '',
    );
    final builder = ui.ParagraphBuilder(paragraphStyle)
      ..pushStyle(
        ui.TextStyle(
          color: color,
          fontSize: fontSize,
          fontFamily: 'Arial',
          fontWeight: fontWeight ?? (bold ? FontWeight.w700 : FontWeight.w400),
          fontStyle: italic ? FontStyle.italic : FontStyle.normal,
        ),
      )
      ..addText(value);
    final paragraph = builder.build()
      ..layout(ui.ParagraphConstraints(width: rect.width));
    final dy = rect.top + math.max(0, (rect.height - paragraph.height) / 2);
    canvas.save();
    canvas.clipRect(rect);
    canvas.drawParagraph(paragraph, Offset(rect.left, dy));
    canvas.restore();
  }

  Rect _menuLabelRect(
    Rect row,
    double horizontalInset, {
    double leftOffset = 0,
  }) {
    return Rect.fromLTRB(
      row.left + horizontalInset + leftOffset,
      row.top,
      row.right - horizontalInset,
      row.bottom,
    );
  }

  void _drawCellText(
    Canvas canvas,
    Rect rect,
    FortuneCell cell, {
    required double fontSize,
    double textScale = 1,
    Color? textColor,
  }) {
    if (cell.isVerticalText) {
      _drawVerticalCellText(
        canvas,
        rect,
        cell,
        fontSize: fontSize,
        textScale: textScale,
        textColor: textColor,
      );
      return;
    }
    final rotation = cell.normalizedTextRotation;
    final align = cell.normalizedTextWrap == '2' && rotation > 0
        ? TextAlign.right
        : switch (cell.normalizedHorizontalAlign) {
            '0' => TextAlign.center,
            '2' => TextAlign.right,
            '3' => TextAlign.justify,
            _ => TextAlign.left,
          };
    final maxLines = cell.normalizedTextWrap == '2' ? null : 1;
    if (_cellNeedsInlineRunPainters(cell)) {
      if (maxLines == 1) {
        _drawSingleLineInlineScriptCellText(
          canvas,
          rect,
          cell,
          fontSize: fontSize,
          textScale: textScale,
          textColor: textColor,
          textAlign: align,
          rotation: rotation,
        );
      } else {
        _drawMultilineInlineScriptCellText(
          canvas,
          rect,
          cell,
          fontSize: fontSize,
          textScale: textScale,
          textColor: textColor,
          textAlign: align,
          rotation: rotation,
        );
      }
      return;
    }
    final painter =
        TextPainter(
          text: _cellTextSpan(
            cell,
            fontSize: fontSize,
            textScale: textScale,
            textColor: textColor,
          ),
          textDirection: textDirection,
          textAlign: align,
          maxLines: maxLines,
          ellipsis: cell.normalizedTextWrap == '2' ? null : '',
        )..layout(
          minWidth: align == TextAlign.left ? 0 : rect.width,
          maxWidth: rect.width,
        );

    final dy = switch (cell.normalizedVerticalAlign) {
      '1' => rect.top,
      '2' => rect.bottom - painter.height,
      _ => rect.top + math.max(0, (rect.height - painter.height) / 2),
    };

    canvas.save();
    canvas.clipRect(rect);
    if (rotation != 0) {
      final pivot = rect.center;
      canvas.translate(pivot.dx, pivot.dy);
      canvas.rotate(-rotation * math.pi / 180);
      canvas.translate(-pivot.dx, -pivot.dy);
    }
    final textOrigin = Offset(rect.left, dy);
    painter.paint(canvas, textOrigin);
    _drawCellCustomUnderlines(
      canvas,
      cell,
      painter,
      textOrigin,
      color: _cellTextColor(cell, textColor: textColor),
      fontSize: fontSize,
    );
    canvas.restore();
  }

  void _drawCellSparkline(Canvas canvas, Rect rect, FortuneCell cell) {
    final type = fortuneSparklineType(cell.sparkline);
    if (type == 'compose' ||
        type == 'composespline' ||
        type == 'composesplines') {
      for (final child in fortuneSparklineChildren(cell.sparkline)) {
        _drawCellSparkline(canvas, rect, FortuneCell(sparkline: child));
      }
      return;
    }
    final values = fortuneSparklineValues(cell.sparkline);
    if (values.isEmpty) {
      return;
    }
    final sparklineColor = fortuneSparklineColor(cell.sparkline);
    final negativeColor = fortuneSparklineNegativeColor(cell.sparkline);
    final zeroColor = fortuneSparklineZeroColor(cell.sparkline);
    final sparklineLineWidth = fortuneSparklineLineWidth(cell.sparkline);
    final normalRangeValue = fortuneSparklineNormalRangeValue(
      cell.sparkline,
      values,
    );
    final normalRangeColor = fortuneSparklineNormalRangeColor(cell.sparkline);
    final maxSpotColor = fortuneSparklineMaxSpotColor(cell.sparkline);
    final minSpotColor = fortuneSparklineMinSpotColor(cell.sparkline);
    final thresholdValue = fortuneSparklineThresholdValue(cell.sparkline);
    final pieOffset = fortuneSparklinePieOffset(cell.sparkline);
    final pieBorderWidth = fortuneSparklinePieBorderWidth(cell.sparkline);
    final pieBorderColor = fortuneSparklinePieBorderColor(cell.sparkline);
    final sliceColors = fortuneSparklineSliceColors(cell.sparkline);
    final targetValue = fortuneSparklineTargetValue(cell.sparkline);
    final outlierIqr = fortuneSparklineOutlierIqr(cell.sparkline);
    final spotRadius = fortuneSparklineSpotRadius(cell.sparkline);
    final barSpacing = fortuneSparklineBarSpacing(cell.sparkline);
    final chartRangeMax = fortuneSparklineChartRangeMax(cell.sparkline);
    final colorMap = fortuneSparklineColorMap(cell.sparkline);
    final stackedBarColors = fortuneSparklineStackedBarColors(cell.sparkline);
    final stackGroups = fortuneSparklineStackGroups(cell.sparkline, values);
    final chartRect = rect.deflate(4);
    if (chartRect.width <= 0 || chartRect.height <= 0) {
      return;
    }
    if (type == 'pie' || type == 'piespline' || type == 'piesplines') {
      _drawSparklinePie(
        canvas,
        rect,
        chartRect,
        values,
        offsetDegrees: pieOffset,
        borderWidth: pieBorderWidth,
        borderColor: pieBorderColor,
        sliceColors: sliceColors,
      );
      return;
    }
    if (type == 'box' ||
        type == 'boxspline' ||
        type == 'boxsplines' ||
        type == 'boxplot') {
      _drawSparklineBox(
        canvas,
        rect,
        chartRect,
        values,
        sparklineColor,
        targetValue: targetValue,
        outlierIqr: outlierIqr,
        spotRadius: spotRadius,
      );
      return;
    }
    if (type == 'bullet' || type == 'bulletspline' || type == 'bulletsplines') {
      _drawSparklineBullet(canvas, rect, chartRect, values, sparklineColor);
      return;
    }
    if (type == 'discrete' ||
        type == 'discretespline' ||
        type == 'discretesplines' ||
        type == 'tristate' ||
        type == 'tristatespline' ||
        type == 'tristatesplines') {
      final useThreshold =
          type == 'discrete' ||
          type == 'discretespline' ||
          type == 'discretesplines';
      _drawSparklineDiscrete(
        canvas,
        rect,
        chartRect,
        values,
        sparklineColor,
        negativeColor,
        zeroColor: zeroColor,
        thresholdValue: useThreshold ? thresholdValue : 0,
        useThreshold: useThreshold,
      );
      return;
    }
    canvas.save();
    canvas.clipRect(rect, doAntiAlias: false);
    if (type == 'stackcolumn' ||
        type == 'stackcolumnspline' ||
        type == 'stackcolumnsplines') {
      _drawSparklineStackColumns(
        canvas,
        chartRect,
        values,
        sparklineColor,
        stackGroups: stackGroups,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        stackedBarColors: stackedBarColors,
      );
      canvas.restore();
      return;
    }
    if (type == 'stackbar' ||
        type == 'stackbarspline' ||
        type == 'stackbarsplines') {
      _drawSparklineStackBars(
        canvas,
        chartRect,
        values,
        sparklineColor,
        stackGroups: stackGroups,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        stackedBarColors: stackedBarColors,
      );
      canvas.restore();
      return;
    }
    if (type == 'column' || type == 'columnspline' || type == 'columnsplines') {
      _drawSparklineColumns(
        canvas,
        chartRect,
        values,
        sparklineColor,
        negativeColor,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        colorMap: colorMap,
      );
      canvas.restore();
      return;
    }
    if (type == 'bar' || type == 'barspline' || type == 'barsplines') {
      _drawSparklineBars(
        canvas,
        chartRect,
        values,
        sparklineColor,
        negativeColor,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        colorMap: colorMap,
      );
      canvas.restore();
      return;
    }
    if (values.length < 2) {
      canvas.restore();
      return;
    }
    final points = fortuneSparklinePoints(values, chartRect);
    if (points.isEmpty) {
      canvas.restore();
      return;
    }
    final path = Path();
    for (var index = 0; index < points.length; index += 1) {
      final point = points[index];
      if (index == 0) {
        path.moveTo(point.dx, point.dy);
      } else {
        path.lineTo(point.dx, point.dy);
      }
    }
    if (type == 'area' || type == 'areaspline' || type == 'areasplines') {
      final areaOpacity = fortuneSparklineAreaOpacity(cell.sparkline);
      final areaColor = fortuneSparklineAreaColor(
        cell.sparkline,
        sparklineColor,
      );
      final areaPath = Path.from(path)
        ..lineTo(points.last.dx, chartRect.bottom)
        ..lineTo(points.first.dx, chartRect.bottom)
        ..close();
      canvas.drawPath(
        areaPath,
        Paint()..color = areaColor.withValues(alpha: areaColor.a * areaOpacity),
      );
    } else if (type != 'line' &&
        type != 'linespline' &&
        type != 'linesplines') {
      canvas.restore();
      return;
    }
    canvas.drawPath(
      path,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = sparklineLineWidth
        ..strokeCap = StrokeCap.round
        ..strokeJoin = StrokeJoin.round
        ..color = sparklineColor,
    );
    if (normalRangeValue != null) {
      _drawSparklineNormalRange(
        canvas,
        chartRect,
        values,
        normalRangeValue,
        normalRangeColor,
      );
    }
    if (maxSpotColor != null || minSpotColor != null) {
      _drawSparklineValueSpots(
        canvas,
        values,
        points,
        maxSpotColor: maxSpotColor,
        minSpotColor: minSpotColor,
        spotRadius: spotRadius,
      );
    }
    canvas.restore();
  }

  void _drawSparklineColumns(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color color,
    Color negativeColor, {
    double? barSpacing,
    double? chartRangeMax,
    List<Object?> colorMap = const [],
  }) {
    final maximum =
        chartRangeMax ?? values.map((value) => value.abs()).reduce(math.max);
    if (maximum == 0) {
      return;
    }
    final baseline = rect.center.dy;
    final slotWidth = rect.width / values.length;
    final gap = math.min(
      barSpacing ?? math.min(2.0, rect.width / (values.length * 4)),
      math.max(0.0, slotWidth - 1),
    );
    final barWidth = math.max(1.0, slotWidth - gap);
    for (var index = 0; index < values.length; index += 1) {
      final value = values[index];
      final ratio = (value.abs() / maximum).clamp(0.0, 1.0).toDouble();
      final height = ratio * rect.height / 2;
      final left = rect.left + index * slotWidth + gap / 2;
      final top = value >= 0 ? baseline - height : baseline;
      final barColor = fortuneSparklineMappedBarColor(
        colorMap,
        value,
        index,
        value >= 0 ? color : negativeColor,
      );
      canvas.drawRect(
        Rect.fromLTWH(left, top, barWidth, math.max(1.0, height)),
        Paint()..color = barColor,
      );
    }
  }

  void _drawSparklineBars(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color color,
    Color negativeColor, {
    double? barSpacing,
    double? chartRangeMax,
    List<Object?> colorMap = const [],
  }) {
    final maximum =
        chartRangeMax ?? values.map((value) => value.abs()).reduce(math.max);
    if (maximum == 0) {
      return;
    }
    final baseline = rect.center.dx;
    final slotHeight = rect.height / values.length;
    final gap = math.min(
      barSpacing ?? math.min(2.0, rect.height / (values.length * 4)),
      math.max(0.0, slotHeight - 1),
    );
    final barHeight = math.max(1.0, slotHeight - gap);
    for (var index = 0; index < values.length; index += 1) {
      final value = values[index];
      final ratio = (value.abs() / maximum).clamp(0.0, 1.0).toDouble();
      final width = ratio * rect.width / 2;
      final top = rect.top + index * slotHeight + gap / 2;
      final left = value >= 0 ? baseline : baseline - width;
      final barColor = fortuneSparklineMappedBarColor(
        colorMap,
        value,
        index,
        value >= 0 ? color : negativeColor,
      );
      canvas.drawRect(
        Rect.fromLTWH(left, top, math.max(1.0, width), barHeight),
        Paint()..color = barColor,
      );
    }
  }

  void _drawSparklineNormalRange(
    Canvas canvas,
    Rect rect,
    List<double> values,
    double value,
    Color color,
  ) {
    final minimum = values.reduce(math.min);
    final maximum = values.reduce(math.max);
    if (maximum == minimum || value < minimum || value > maximum) {
      return;
    }
    final y =
        rect.bottom - ((value - minimum) / (maximum - minimum)) * rect.height;
    canvas.drawLine(
      Offset(rect.left, y),
      Offset(rect.right, y),
      Paint()
        ..strokeWidth = 1
        ..color = color,
    );
  }

  void _drawSparklineValueSpots(
    Canvas canvas,
    List<double> values,
    List<Offset> points, {
    Color? maxSpotColor,
    Color? minSpotColor,
    double spotRadius = 1.5,
  }) {
    if (values.isEmpty || values.length != points.length) {
      return;
    }
    final maximum = values.reduce(math.max);
    final minimum = values.reduce(math.min);
    if (maxSpotColor != null) {
      final paint = Paint()..color = maxSpotColor;
      for (var index = 0; index < values.length; index += 1) {
        if (values[index] == maximum) {
          canvas.drawCircle(points[index], spotRadius, paint);
        }
      }
    }
    if (minSpotColor != null && minimum != maximum) {
      final paint = Paint()..color = minSpotColor;
      for (var index = 0; index < values.length; index += 1) {
        if (values[index] == minimum) {
          canvas.drawCircle(points[index], spotRadius, paint);
        }
      }
    }
  }

  void _drawSparklineStackColumns(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color firstColor, {
    List<List<double>>? stackGroups,
    double? barSpacing,
    double? chartRangeMax,
    List<Color> stackedBarColors = const [],
  }) {
    final groups = (stackGroups ?? [values])
        .map(
          (group) => [
            for (final value in group)
              if (value != 0) value.abs(),
          ],
        )
        .where((group) => group.isNotEmpty)
        .toList();
    if (groups.isEmpty) {
      return;
    }
    final totals = [
      for (final group in groups)
        group.fold<double>(0, (sum, value) => sum + value),
    ];
    final maximum = chartRangeMax ?? totals.reduce(math.max);
    if (maximum <= 0) {
      return;
    }
    final gap = groups.length <= 1
        ? 0.0
        : math.min(
            barSpacing ?? math.min(2.0, rect.width / (groups.length * 4)),
            math.max(0.0, rect.width / groups.length - 1),
          );
    final stackWidth = groups.length <= 1
        ? rect.width
        : math.max(
            1.0,
            (rect.width - gap * (groups.length - 1)) / groups.length,
          );
    const colors = [
      Color(0xffffb300),
      Color(0xff34a853),
      Color(0xffea4335),
      Color(0xff7e57c2),
    ];
    for (var groupIndex = 0; groupIndex < groups.length; groupIndex += 1) {
      final group = groups[groupIndex];
      final left = rect.left + groupIndex * (stackWidth + gap);
      final right = math.min(rect.right, left + stackWidth);
      var bottom = rect.bottom;
      var remainingHeight = rect.height;
      for (var index = 0; index < group.length; index += 1) {
        final height = math.min(
          group[index] / maximum * rect.height,
          remainingHeight,
        );
        final segmentColor = index < stackedBarColors.length
            ? stackedBarColors[index]
            : index == 0
            ? firstColor
            : colors[(index - 1) % colors.length];
        canvas.drawRect(
          Rect.fromLTRB(left, bottom - height, right, bottom),
          Paint()..color = segmentColor,
        );
        bottom -= height;
        remainingHeight -= height;
        if (remainingHeight <= 0) {
          break;
        }
      }
    }
  }

  void _drawSparklineStackBars(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color firstColor, {
    List<List<double>>? stackGroups,
    double? barSpacing,
    double? chartRangeMax,
    List<Color> stackedBarColors = const [],
  }) {
    final groups = (stackGroups ?? [values])
        .map(
          (group) => [
            for (final value in group)
              if (value != 0) value.abs(),
          ],
        )
        .where((group) => group.isNotEmpty)
        .toList();
    if (groups.isEmpty) {
      return;
    }
    final totals = [
      for (final group in groups)
        group.fold<double>(0, (sum, value) => sum + value),
    ];
    final maximum = chartRangeMax ?? totals.reduce(math.max);
    if (maximum <= 0) {
      return;
    }
    final gap = groups.length <= 1
        ? 0.0
        : math.min(
            barSpacing ?? math.min(2.0, rect.height / (groups.length * 4)),
            math.max(0.0, rect.height / groups.length - 1),
          );
    final stackHeight = groups.length <= 1
        ? rect.height
        : math.max(
            1.0,
            (rect.height - gap * (groups.length - 1)) / groups.length,
          );
    const colors = [
      Color(0xffffb300),
      Color(0xff34a853),
      Color(0xffea4335),
      Color(0xff7e57c2),
    ];
    for (var groupIndex = 0; groupIndex < groups.length; groupIndex += 1) {
      final group = groups[groupIndex];
      final top = rect.top + groupIndex * (stackHeight + gap);
      final bottom = math.min(rect.bottom, top + stackHeight);
      var left = rect.left;
      var remainingWidth = rect.width;
      for (var index = 0; index < group.length; index += 1) {
        final width = math.min(
          group[index] / maximum * rect.width,
          remainingWidth,
        );
        final segmentColor = index < stackedBarColors.length
            ? stackedBarColors[index]
            : index == 0
            ? firstColor
            : colors[(index - 1) % colors.length];
        canvas.drawRect(
          Rect.fromLTRB(left, top, left + width, bottom),
          Paint()..color = segmentColor,
        );
        left += width;
        remainingWidth -= width;
        if (remainingWidth <= 0) {
          break;
        }
      }
    }
  }

  void _drawSparklinePie(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values, {
    double offsetDegrees = 0,
    double borderWidth = 1,
    Color borderColor = const Color(0xff5f6368),
    List<Color> sliceColors = const [],
  }) {
    final positiveValues = [
      for (final value in values)
        if (value > 0) value,
    ];
    if (positiveValues.isEmpty) {
      return;
    }
    final total = positiveValues.fold<double>(0, (sum, value) => sum + value);
    if (total <= 0) {
      return;
    }
    final side = math.min(rect.width, rect.height);
    final pieRect = Rect.fromCenter(
      center: rect.center,
      width: side,
      height: side,
    );
    const colors = [
      Color(0xff0188fb),
      Color(0xffffb300),
      Color(0xff34a853),
      Color(0xffea4335),
      Color(0xff7e57c2),
    ];
    final palette = sliceColors.isEmpty ? colors : sliceColors;
    var start = -math.pi / 2 + offsetDegrees * math.pi / 180;
    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    for (var index = 0; index < positiveValues.length; index += 1) {
      final sweep = positiveValues[index] / total * math.pi * 2;
      canvas.drawArc(
        pieRect,
        start,
        sweep,
        true,
        Paint()..color = palette[index % palette.length],
      );
      start += sweep;
    }
    if (borderWidth > 0) {
      canvas.drawOval(
        pieRect,
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = borderWidth
          ..color = borderColor,
      );
    }
    canvas.restore();
  }

  void _drawSparklineBox(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values,
    Color color, {
    double? targetValue,
    double? outlierIqr,
    double spotRadius = 1.5,
  }) {
    if (values.length < 2) {
      return;
    }
    final sorted = [...values]..sort();
    final minimum = sorted.first;
    final maximum = sorted.last;
    if (minimum == maximum) {
      return;
    }
    double percentile(double position) {
      final lower = position.floor();
      final upper = position.ceil();
      if (lower == upper) {
        return sorted[lower];
      }
      final weight = position - lower;
      return sorted[lower] + (sorted[upper] - sorted[lower]) * weight;
    }

    final q1 = percentile((sorted.length - 1) * 0.25);
    final median = percentile((sorted.length - 1) * 0.5);
    final q3 = percentile((sorted.length - 1) * 0.75);
    final iqr = q3 - q1;
    final lowerFence = outlierIqr == null ? null : q1 - iqr * outlierIqr;
    final upperFence = outlierIqr == null ? null : q3 + iqr * outlierIqr;
    final inlierValues = lowerFence == null || upperFence == null
        ? sorted
        : sorted
              .where((value) => value >= lowerFence && value <= upperFence)
              .toList();
    final whiskerMinimum = inlierValues.isEmpty ? minimum : inlierValues.first;
    final whiskerMaximum = inlierValues.isEmpty ? maximum : inlierValues.last;
    double xFor(double value) {
      return rect.left + (value - minimum) / (maximum - minimum) * rect.width;
    }

    final centerY = rect.center.dy;
    final boxTop = rect.top + rect.height * 0.22;
    final boxBottom = rect.bottom - rect.height * 0.22;
    final whiskerTop = rect.top + rect.height * 0.32;
    final whiskerBottom = rect.bottom - rect.height * 0.32;
    final outline = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.2
      ..color = const Color(0xff5f6368);
    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    canvas.drawLine(
      Offset(xFor(whiskerMinimum), centerY),
      Offset(xFor(q1), centerY),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(q3), centerY),
      Offset(xFor(whiskerMaximum), centerY),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(whiskerMinimum), whiskerTop),
      Offset(xFor(whiskerMinimum), whiskerBottom),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(whiskerMaximum), whiskerTop),
      Offset(xFor(whiskerMaximum), whiskerBottom),
      outline,
    );
    canvas.drawRect(
      Rect.fromLTRB(xFor(q1), boxTop, xFor(q3), boxBottom),
      Paint()..color = color.withValues(alpha: color.a * 0.13),
    );
    canvas.drawRect(
      Rect.fromLTRB(xFor(q1), boxTop, xFor(q3), boxBottom),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(median), boxTop),
      Offset(xFor(median), boxBottom),
      Paint()
        ..strokeWidth = 1.5
        ..color = color,
    );
    if (targetValue != null &&
        targetValue >= minimum &&
        targetValue <= maximum) {
      canvas.drawCircle(
        Offset(xFor(targetValue), centerY),
        spotRadius,
        Paint()..color = color,
      );
    }
    if (lowerFence != null && upperFence != null) {
      final outlierPaint = Paint()..color = color;
      for (final value in sorted) {
        if (value < lowerFence || value > upperFence) {
          canvas.drawCircle(
            Offset(xFor(value), centerY),
            spotRadius,
            outlierPaint,
          );
        }
      }
    }
    canvas.restore();
  }

  void _drawSparklineBullet(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values,
    Color color,
  ) {
    if (values.length < 2) {
      return;
    }
    final target = values[0].abs();
    final achieved = values[1].abs();
    final comparisons = [
      for (var index = 2; index < values.length; index += 1)
        values[index].abs(),
    ]..sort();
    final maximum = [
      ...comparisons,
      target,
      achieved,
    ].fold<double>(0, math.max);
    if (maximum <= 0) {
      return;
    }
    final track = Rect.fromLTWH(
      rect.left,
      rect.top + rect.height * 0.25,
      rect.width,
      rect.height * 0.5,
    );
    double widthFor(double value) =>
        (value / maximum).clamp(0.0, 1.0) * track.width;

    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    canvas.drawRect(track, Paint()..color = const Color(0xffe8eaed));
    const comparisonColors = [
      Color(0xffdadce0),
      Color(0xffcfd4da),
      Color(0xffbdc1c6),
    ];
    for (var index = comparisons.length - 1; index >= 0; index -= 1) {
      canvas.drawRect(
        Rect.fromLTWH(
          track.left,
          track.top,
          widthFor(comparisons[index]),
          track.height,
        ),
        Paint()..color = comparisonColors[index % comparisonColors.length],
      );
    }
    canvas.drawRect(
      Rect.fromLTWH(
        track.left,
        track.top + track.height * 0.32,
        widthFor(achieved),
        track.height * 0.36,
      ),
      Paint()..color = color,
    );
    final targetX = track.left + widthFor(target);
    canvas.drawLine(
      Offset(targetX, track.top - 2),
      Offset(targetX, track.bottom + 2),
      Paint()
        ..strokeWidth = 1.5
        ..color = const Color(0xffea4335),
    );
    canvas.restore();
  }

  void _drawSparklineDiscrete(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values,
    Color positiveColor,
    Color negativeColor, {
    Color zeroColor = const Color(0xff9aa0a6),
    double thresholdValue = 0,
    bool useThreshold = false,
  }) {
    if (values.isEmpty) {
      return;
    }
    final baseline = rect.center.dy;
    final gap = math.min(2.0, rect.width / (values.length * 4));
    final barWidth = math.max(1.0, rect.width / values.length - gap);
    final positiveHeight = math.max(1.0, baseline - rect.top);
    final negativeHeight = math.max(1.0, rect.bottom - baseline);
    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    for (var index = 0; index < values.length; index += 1) {
      final value = values[index];
      final state = useThreshold
          ? value.compareTo(thresholdValue)
          : value.compareTo(0);
      final left = rect.left + index * rect.width / values.length + gap / 2;
      final top = state > 0
          ? baseline - positiveHeight
          : state < 0
          ? baseline
          : baseline - 0.75;
      final height = state == 0
          ? 1.5
          : state > 0
          ? positiveHeight
          : negativeHeight;
      final color = state > 0
          ? positiveColor
          : state < 0
          ? negativeColor
          : zeroColor;
      canvas.drawRect(
        Rect.fromLTWH(left, top, barWidth, height),
        Paint()..color = color,
      );
    }
    canvas.restore();
  }

  Rect _cellTextRect({
    required FortuneSheet sheet,
    required FortuneSheetMetrics metrics,
    required FortuneSettings settings,
    required int row,
    required int column,
    required FortuneCell cell,
    required Rect cellRect,
  }) {
    if (cell.normalizedTextWrap != '1' ||
        cell.normalizedTextRotation != 0 ||
        cell.isVerticalText) {
      return cellRect;
    }
    final textWidth = _measureCellTextWidth(
      cell,
      fontSize: cell.fontSize ?? settings.defaultFontSize,
    );
    if (textWidth <= cellRect.width - 4) {
      return cellRect;
    }

    final align = cell.normalizedHorizontalAlign;
    var startColumn = column;
    var endColumn = column;
    var startX = metrics.columnStart(column);
    var endX = metrics.columnEnd(column);
    final columnCount = sheet.columnCount ?? settings.column;

    bool canUseColumn(int c) {
      if (c < 0 || c >= columnCount || sheet.hiddenColumns.contains(c)) {
        return false;
      }
      final other = sheet.cells[FortuneCellCoord(row, c)];
      return other == null || other.isVisuallyEmpty;
    }

    double width() => endX - startX;

    if (align == '2') {
      while (width() < textWidth + 4 && canUseColumn(startColumn - 1)) {
        startColumn -= 1;
        startX = metrics.columnStart(startColumn);
      }
    } else if (align == '0') {
      var growLeft = true;
      while (width() < textWidth + 4) {
        if (growLeft && canUseColumn(startColumn - 1)) {
          startColumn -= 1;
          startX = metrics.columnStart(startColumn);
        } else if (canUseColumn(endColumn + 1)) {
          endColumn += 1;
          endX = metrics.columnEnd(endColumn);
        } else if (!growLeft && canUseColumn(startColumn - 1)) {
          startColumn -= 1;
          startX = metrics.columnStart(startColumn);
        } else {
          break;
        }
        growLeft = !growLeft;
      }
    } else {
      while (width() < textWidth + 4 && canUseColumn(endColumn + 1)) {
        endColumn += 1;
        endX = metrics.columnEnd(endColumn);
      }
    }

    return Rect.fromLTWH(
      _visualCellLeft(startColumn, settings, metrics),
      cellRect.top,
      endX - startX,
      cellRect.height,
    );
  }

  double _measureCellTextWidth(FortuneCell cell, {required double fontSize}) {
    if (!cell.isVerticalText &&
        cell.normalizedTextWrap != '2' &&
        _cellNeedsInlineRunPainters(cell)) {
      return _inlineScriptTextSize(
        cell,
        fontSize: fontSize,
        textColor: null,
      ).width;
    }
    final painter = TextPainter(
      text: _cellTextSpan(cell, fontSize: fontSize),
      textDirection: textDirection,
      maxLines: 1,
    )..layout();
    return painter.width;
  }

  void _drawSingleLineInlineScriptCellText(
    Canvas canvas,
    Rect rect,
    FortuneCell cell, {
    required double fontSize,
    required double textScale,
    Color? textColor,
    required TextAlign textAlign,
    required double rotation,
  }) {
    final runPainters = _inlineScriptRunPainters(
      cell,
      fontSize: fontSize,
      textScale: textScale,
      textColor: textColor,
    );
    if (runPainters.isEmpty) {
      return;
    }
    final metrics = runPainters.map((runPainter) {
      final lineMetrics = runPainter.painter.computeLineMetrics();
      return lineMetrics.isEmpty ? null : lineMetrics.first;
    }).toList();
    var width = 0.0;
    var ascent = 0.0;
    var descent = 0.0;
    for (var index = 0; index < runPainters.length; index += 1) {
      final runPainter = runPainters[index];
      final metric = metrics[index];
      if (metric == null) {
        continue;
      }
      width += runPainter.width;
      ascent = math.max(ascent, metric.baseline - runPainter.baselineShift);
      descent = math.max(
        descent,
        runPainter.painter.height - metric.baseline + runPainter.baselineShift,
      );
    }
    final height = ascent + descent;
    final dx = switch (textAlign) {
      TextAlign.center => rect.left + math.max(0, (rect.width - width) / 2),
      TextAlign.right || TextAlign.end => rect.right - width,
      _ => rect.left,
    };
    final dy = switch (cell.normalizedVerticalAlign) {
      '1' => rect.top,
      '2' => rect.bottom - height,
      _ => rect.top + math.max(0, (rect.height - height) / 2),
    };
    final baselineY = dy + ascent;
    canvas.save();
    canvas.clipRect(rect);
    if (rotation != 0) {
      final pivot = rect.center;
      canvas.translate(pivot.dx, pivot.dy);
      canvas.rotate(-rotation * math.pi / 180);
      canvas.translate(-pivot.dx, -pivot.dy);
    }
    var x = dx;
    for (var index = 0; index < runPainters.length; index += 1) {
      final runPainter = runPainters[index];
      final metric = metrics[index];
      if (metric == null) {
        continue;
      }
      final y = baselineY + runPainter.baselineShift - metric.baseline;
      _paintInlineRunPainter(canvas, runPainter, Offset(x, y));
      x += runPainter.width;
    }
    canvas.restore();
  }

  void _drawMultilineInlineScriptCellText(
    Canvas canvas,
    Rect rect,
    FortuneCell cell, {
    required double fontSize,
    required double textScale,
    Color? textColor,
    required TextAlign textAlign,
    required double rotation,
  }) {
    final lineRuns = _splitInlineRunsByLine(
      cell.inlineRuns ?? const <FortuneInlineTextRun>[],
    );
    if (lineRuns.isEmpty) {
      return;
    }
    final lineLayouts = lineRuns
        .map(
          (runs) => _inlineScriptLineLayout(
            cell,
            runs,
            fontSize: fontSize,
            textScale: textScale,
            textColor: textColor,
          ),
        )
        .toList();
    final totalHeight = lineLayouts.fold<double>(
      0,
      (sum, layout) => sum + layout.height,
    );
    var lineY = switch (cell.normalizedVerticalAlign) {
      '1' => rect.top,
      '2' => rect.bottom - totalHeight,
      _ => rect.top + math.max(0, (rect.height - totalHeight) / 2),
    };

    canvas.save();
    canvas.clipRect(rect);
    if (rotation != 0) {
      final pivot = rect.center;
      canvas.translate(pivot.dx, pivot.dy);
      canvas.rotate(-rotation * math.pi / 180);
      canvas.translate(-pivot.dx, -pivot.dy);
    }
    for (final layout in lineLayouts) {
      final lineX = switch (textAlign) {
        TextAlign.center =>
          rect.left + math.max(0, (rect.width - layout.width) / 2),
        TextAlign.right || TextAlign.end => rect.right - layout.width,
        _ => rect.left,
      };
      final baselineY = lineY + layout.ascent;
      var runX = lineX;
      for (var index = 0; index < layout.runPainters.length; index += 1) {
        final runPainter = layout.runPainters[index];
        final metric = layout.metrics[index];
        if (metric == null) {
          continue;
        }
        final runY = baselineY + runPainter.baselineShift - metric.baseline;
        _paintInlineRunPainter(canvas, runPainter, Offset(runX, runY));
        runX += runPainter.width;
      }
      lineY += layout.height;
    }
    canvas.restore();
  }

  Size _inlineScriptTextSize(
    FortuneCell cell, {
    required double fontSize,
    double textScale = 1,
    Color? textColor,
  }) {
    final runPainters = _inlineScriptRunPainters(
      cell,
      fontSize: fontSize,
      textScale: textScale,
      textColor: textColor,
    );
    var width = 0.0;
    var ascent = 0.0;
    var descent = 0.0;
    for (final runPainter in runPainters) {
      final metrics = runPainter.painter.computeLineMetrics();
      if (metrics.isEmpty) {
        continue;
      }
      final metric = metrics.first;
      width += runPainter.width;
      ascent = math.max(ascent, metric.baseline - runPainter.baselineShift);
      descent = math.max(
        descent,
        runPainter.painter.height - metric.baseline + runPainter.baselineShift,
      );
    }
    return Size(width, ascent + descent);
  }

  List<_FortuneInlineRunPainter> _inlineScriptRunPainters(
    FortuneCell cell, {
    required double fontSize,
    required double textScale,
    Color? textColor,
  }) {
    return _inlineScriptRunPaintersForRuns(
      cell,
      cell.inlineRuns ?? const <FortuneInlineTextRun>[],
      fontSize: fontSize,
      textScale: textScale,
      textColor: textColor,
    );
  }

  List<_FortuneInlineRunPainter> _inlineScriptRunPaintersForRuns(
    FortuneCell cell,
    Iterable<FortuneInlineTextRun> runs, {
    required double fontSize,
    required double textScale,
    Color? textColor,
  }) {
    final baseStyle = _cellTextStyle(
      cell,
      fontSize: fontSize,
      textColor: textColor,
    );
    final forceBaseColor =
        textColor != null || _isRedNegativeNumberFormat(cell);
    return [
      for (final run in runs)
        _FortuneInlineRunPainter(
          painter: TextPainter(
            text: TextSpan(
              text: run.text,
              style: _inlineRunTextStyle(
                cell,
                run,
                baseStyle,
                textScale: textScale,
                forceBaseColor: forceBaseColor,
              ),
            ),
            textDirection: textDirection,
            maxLines: 1,
            ellipsis: '',
          )..layout(),
          baselineShift: _inlineRunBaselineShift(run, fontSize, textScale),
          fontScale: _inlineRunFontScale(run),
        ),
    ];
  }

  ({
    List<_FortuneInlineRunPainter> runPainters,
    List<ui.LineMetrics?> metrics,
    double width,
    double ascent,
    double height,
  })
  _inlineScriptLineLayout(
    FortuneCell cell,
    List<FortuneInlineTextRun> runs, {
    required double fontSize,
    required double textScale,
    Color? textColor,
  }) {
    final runPainters = _inlineScriptRunPaintersForRuns(
      cell,
      runs,
      fontSize: fontSize,
      textScale: textScale,
      textColor: textColor,
    );
    if (runPainters.isEmpty) {
      final painter = TextPainter(
        text: TextSpan(
          text: ' ',
          style: _cellTextStyle(cell, fontSize: fontSize, textColor: textColor),
        ),
        textDirection: textDirection,
        maxLines: 1,
      )..layout();
      final metric = painter.computeLineMetrics().firstOrNull;
      final height = metric == null ? painter.height : metric.height;
      return (
        runPainters: const <_FortuneInlineRunPainter>[],
        metrics: const <ui.LineMetrics?>[],
        width: 0,
        ascent: metric?.baseline ?? height,
        height: height,
      );
    }
    final metrics = runPainters.map((runPainter) {
      final lineMetrics = runPainter.painter.computeLineMetrics();
      return lineMetrics.isEmpty ? null : lineMetrics.first;
    }).toList();
    var width = 0.0;
    var ascent = 0.0;
    var descent = 0.0;
    for (var index = 0; index < runPainters.length; index += 1) {
      final runPainter = runPainters[index];
      final metric = metrics[index];
      if (metric == null) {
        continue;
      }
      width += runPainter.width;
      ascent = math.max(ascent, metric.baseline - runPainter.baselineShift);
      descent = math.max(
        descent,
        runPainter.painter.height - metric.baseline + runPainter.baselineShift,
      );
    }
    return (
      runPainters: runPainters,
      metrics: metrics,
      width: width,
      ascent: ascent,
      height: ascent + descent,
    );
  }

  List<List<FortuneInlineTextRun>> _splitInlineRunsByLine(
    List<FortuneInlineTextRun> runs,
  ) {
    final lines = <List<FortuneInlineTextRun>>[<FortuneInlineTextRun>[]];
    for (final run in runs) {
      final parts = run.text.split('\n');
      for (var index = 0; index < parts.length; index += 1) {
        if (index > 0) {
          lines.add(<FortuneInlineTextRun>[]);
        }
        final text = parts[index];
        if (text.isNotEmpty) {
          lines.last.add(run.copyWith(text: text));
        }
      }
    }
    return lines;
  }

  void _paintInlineRunPainter(
    Canvas canvas,
    _FortuneInlineRunPainter runPainter,
    Offset offset,
  ) {
    if (runPainter.fontScale == 1) {
      runPainter.painter.paint(canvas, offset);
      return;
    }
    canvas.save();
    canvas.translate(offset.dx, offset.dy);
    canvas.scale(runPainter.fontScale, 1);
    runPainter.painter.paint(canvas, Offset.zero);
    canvas.restore();
  }

  void _drawVerticalCellText(
    Canvas canvas,
    Rect rect,
    FortuneCell cell, {
    required double fontSize,
    required double textScale,
    Color? textColor,
  }) {
    final color = _cellTextColor(cell, textColor: textColor);
    final style = TextStyle(
      color: color,
      fontSize: fontSize,
      fontFamily: _resolvedCellFontFamily(cell),
      fontWeight: cell.bold ? FontWeight.w700 : FontWeight.w400,
      fontStyle: cell.italic ? FontStyle.italic : FontStyle.normal,
      decoration: _cellTextDecoration(cell),
      decorationColor: color,
    );
    final spans = _verticalTextSpans(
      cell,
      fallbackStyle: style,
      textScale: textScale,
      forceBaseColor: textColor != null || _isRedNegativeNumberFormat(cell),
    );
    final painters = spans.map((span) {
      return TextPainter(
        text: span,
        textDirection: textDirection,
        textAlign: TextAlign.center,
        maxLines: 1,
      )..layout(maxWidth: rect.width);
    }).toList();
    if (painters.isEmpty) {
      return;
    }

    final totalHeight = painters.fold<double>(
      0,
      (sum, painter) => sum + painter.height,
    );
    var y = switch (cell.normalizedVerticalAlign) {
      '1' => rect.top,
      '2' => rect.bottom - totalHeight,
      _ => rect.top + math.max(0, (rect.height - totalHeight) / 2),
    };
    canvas.save();
    canvas.clipRect(rect);
    for (final painter in painters) {
      final x = switch (cell.normalizedHorizontalAlign) {
        '0' => rect.left + (rect.width - painter.width) / 2,
        '2' => rect.right - painter.width,
        _ => rect.left,
      };
      painter.paint(canvas, Offset(x, y));
      y += painter.height;
    }
    canvas.restore();
  }

  TextDecoration _cellTextDecoration(FortuneCell cell) {
    if (_skipsTextLineDecoration(cell)) {
      return TextDecoration.none;
    }
    final decorations = [
      if (_cellUnderlineType(cell) == 1) TextDecoration.underline,
      if (cell.strikeThrough) TextDecoration.lineThrough,
    ];
    return decorations.isEmpty
        ? TextDecoration.none
        : TextDecoration.combine(decorations);
  }

  int _cellUnderlineType(FortuneCell cell) {
    if (cell.hasRawUnderline) {
      final raw = cell.rawUnderline;
      final value = switch (raw) {
        bool() => raw ? 1 : 0,
        num() => raw.toInt(),
        _ => num.tryParse('$raw')?.toInt(),
      };
      return value == null ? 0 : value.clamp(0, 4);
    }
    if (cell.underline || cell.hyperlink != null) {
      return 1;
    }
    return 0;
  }

  void _drawCellCustomUnderlines(
    Canvas canvas,
    FortuneCell cell,
    TextPainter painter,
    Offset origin, {
    required Color color,
    required double fontSize,
  }) {
    if (_skipsTextLineDecoration(cell)) {
      return;
    }
    final underlineType = _cellUnderlineType(cell);
    if (underlineType <= 1) {
      return;
    }
    final lineMetrics = painter.computeLineMetrics();
    if (lineMetrics.isEmpty) {
      return;
    }
    final strokeWidth = (fontSize / 9).floorToDouble();
    final paint = Paint()
      ..color = color
      ..strokeWidth = strokeWidth;
    for (final metric in lineMetrics) {
      final startX = origin.dx + metric.left;
      final endX = startX + metric.width;
      final baselineY = origin.dy + metric.baseline;
      final firstY = underlineType == 2
          ? baselineY + 3
          : baselineY + metric.descent - strokeWidth / 2;
      canvas.drawLine(Offset(startX, firstY), Offset(endX, firstY), paint);
      if (underlineType == 2 || underlineType == 4) {
        final secondY = underlineType == 2
            ? baselineY + metric.descent - strokeWidth / 2
            : firstY + 2;
        canvas.drawLine(Offset(startX, secondY), Offset(endX, secondY), paint);
      }
    }
  }

  TextSpan _cellTextSpan(
    FortuneCell cell, {
    required double fontSize,
    double textScale = 1,
    Color? textColor,
  }) {
    final baseStyle = _cellTextStyle(
      cell,
      fontSize: fontSize,
      textColor: textColor,
    );
    final runs = cell.inlineRuns;
    if (runs == null || runs.isEmpty) {
      return TextSpan(text: cell.renderedText, style: baseStyle);
    }
    final forceBaseColor =
        textColor != null || _isRedNegativeNumberFormat(cell);
    return TextSpan(
      style: baseStyle,
      children: runs.map((run) {
        return TextSpan(
          text: run.text,
          style: _inlineRunTextStyle(
            cell,
            run,
            baseStyle,
            textScale: textScale,
            forceBaseColor: forceBaseColor,
          ),
        );
      }).toList(),
    );
  }

  bool _cellNeedsInlineRunPainters(FortuneCell cell) {
    final runs = cell.inlineRuns;
    if (runs == null || runs.isEmpty) {
      return false;
    }
    return runs.any(
      (run) =>
          run.extraFields['script'] != null || _inlineRunFontScale(run) != 1,
    );
  }

  TextStyle _inlineRunTextStyle(
    FortuneCell cell,
    FortuneInlineTextRun run,
    TextStyle baseStyle, {
    required double textScale,
    required bool forceBaseColor,
  }) {
    final color = forceBaseColor
        ? baseStyle.color ?? cell.foreground
        : run.foreground ?? cell.foreground;
    return baseStyle.copyWith(
      color: color,
      backgroundColor: _inlineRunBackgroundColor(run),
      fontSize: run.fontSize == null
          ? baseStyle.fontSize
          : run.fontSize! * textScale,
      height: _inlineRunLineHeight(run) ?? baseStyle.height,
      letterSpacing: _inlineRunLetterSpacing(run, textScale),
      fontFamily: _resolvedRunFontFamily(run.fontFamily, cell),
      fontWeight: (run.bold ?? cell.bold) ? FontWeight.w700 : FontWeight.w400,
      fontStyle: (run.italic ?? cell.italic)
          ? FontStyle.italic
          : FontStyle.normal,
      decoration: _inlineTextDecoration(run, cell),
      decorationColor: color,
    );
  }

  Color? _inlineRunBackgroundColor(FortuneInlineTextRun run) {
    final raw = run.extraFields['bg'];
    if (raw == null) {
      return null;
    }
    if (raw is Color) {
      return raw;
    }
    return FortuneSheetCodec.parseColor('$raw');
  }

  double? _inlineRunLetterSpacing(FortuneInlineTextRun run, double textScale) {
    final value = _inlineRunDoubleExtra(run, 'letterSpacing');
    return value == null || !value.isFinite ? null : value * textScale;
  }

  double? _inlineRunLineHeight(FortuneInlineTextRun run) {
    final value = _inlineRunDoubleExtra(run, 'lineHeight');
    return value == null || !value.isFinite || value <= 0 ? null : value;
  }

  double _inlineRunFontScale(FortuneInlineTextRun run) {
    final value = _inlineRunDoubleExtra(run, 'fontScale');
    if (value == null || !value.isFinite || value <= 0) {
      return 1;
    }
    return value / 100;
  }

  double? _inlineRunDoubleExtra(FortuneInlineTextRun run, String key) {
    final value = run.extraFields[key];
    if (value is num) {
      return value.toDouble();
    }
    return double.tryParse('$value');
  }

  double _inlineRunBaselineShift(
    FortuneInlineTextRun run,
    double baseFontSize,
    double textScale,
  ) {
    final effectiveBaseFontSize = run.fontSize == null
        ? baseFontSize
        : run.fontSize! * textScale / fortuneInlineScriptFontSizeScale;
    return switch (run.extraFields['script']) {
      'superscript' =>
        effectiveBaseFontSize * fortuneInlineSuperscriptBaselineShiftScale,
      'subscript' =>
        effectiveBaseFontSize * fortuneInlineSubscriptBaselineShiftScale,
      _ => 0,
    };
  }

  TextStyle _cellTextStyle(
    FortuneCell cell, {
    required double fontSize,
    Color? textColor,
  }) {
    final color = _cellTextColor(cell, textColor: textColor);
    return TextStyle(
      color: color,
      fontSize: fontSize,
      fontFamily: _resolvedCellFontFamily(cell),
      fontWeight: cell.bold ? FontWeight.w700 : FontWeight.w400,
      fontStyle: cell.italic ? FontStyle.italic : FontStyle.normal,
      decoration: _cellTextDecoration(cell),
      decorationColor: color,
    );
  }

  Color _cellTextColor(FortuneCell cell, {Color? textColor}) {
    if (_isRedNegativeNumberFormat(cell)) {
      return const Color(0xffff0000);
    }
    if (textColor != null) {
      return textColor;
    }
    if (cell.hyperlink != null) {
      return const Color(0xff1155cc);
    }
    return cell.foreground;
  }

  bool _isRedNegativeNumberFormat(FortuneCell cell) {
    final cellType = cell.cellType;
    if (cellType?.type != 'n' || !(cellType?.format ?? '').contains('[Red]')) {
      return false;
    }
    final numberValue =
        _numberValue(cell.value) ?? _numberValue(cell.renderedText);
    return numberValue != null && numberValue < 0;
  }

  TextDecoration _inlineTextDecoration(
    FortuneInlineTextRun run,
    FortuneCell cell,
  ) {
    if (run.wrap == true) {
      return TextDecoration.none;
    }
    final decorations = [
      if (run.underline ?? cell.underline) TextDecoration.underline,
      if (run.strikeThrough ?? cell.strikeThrough) TextDecoration.lineThrough,
    ];
    return decorations.isEmpty
        ? TextDecoration.none
        : TextDecoration.combine(decorations);
  }

  bool _skipsTextLineDecoration(FortuneCell cell) =>
      cell.normalizedTextWrap == '2';

  List<TextSpan> _verticalTextSpans(
    FortuneCell cell, {
    required TextStyle fallbackStyle,
    required double textScale,
    bool forceBaseColor = false,
  }) {
    final runs = cell.inlineRuns;
    if (runs == null || runs.isEmpty) {
      return cell.renderedText.runes
          .map(
            (rune) =>
                TextSpan(text: String.fromCharCode(rune), style: fallbackStyle),
          )
          .toList();
    }
    final spans = <TextSpan>[];
    for (final run in runs) {
      final color = forceBaseColor
          ? fallbackStyle.color ?? cell.foreground
          : run.foreground ?? cell.foreground;
      final style = fallbackStyle.copyWith(
        color: color,
        backgroundColor: _inlineRunBackgroundColor(run),
        fontSize: run.fontSize == null
            ? fallbackStyle.fontSize
            : run.fontSize! * textScale,
        fontFamily: _resolvedRunFontFamily(run.fontFamily, cell),
        fontWeight: (run.bold ?? cell.bold) ? FontWeight.w700 : FontWeight.w400,
        fontStyle: (run.italic ?? cell.italic)
            ? FontStyle.italic
            : FontStyle.normal,
        decoration: _inlineTextDecoration(run, cell),
        decorationColor: color,
      );
      spans.addAll(
        run.text.runes.map(
          (rune) => TextSpan(text: String.fromCharCode(rune), style: style),
        ),
      );
    }
    return spans;
  }

  String _resolvedCellFontFamily(FortuneCell cell) {
    return fortuneResolveFontFamily(
      cell.fontFamily,
      workbook.settings.fontFamilies,
    );
  }

  String _resolvedRunFontFamily(String? raw, FortuneCell fallback) {
    return fortuneResolveFontFamily(
      raw,
      workbook.settings.fontFamilies,
      fallback: _resolvedCellFontFamily(fallback),
    );
  }

  void _drawCommentIndicator(Canvas canvas, Rect rect) {
    final path = Path()
      ..moveTo(rect.right - 7, rect.top + 1)
      ..lineTo(rect.right - 1, rect.top + 1)
      ..lineTo(rect.right - 1, rect.top + 7)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xffd93025));
  }

  Map? _dataVerificationForCoord(FortuneSheet sheet, FortuneCellCoord coord) {
    final raw = sheet.dataVerification[_cellKey(coord)];
    return raw is Map ? raw : null;
  }

  bool _dataVerificationFails(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell? cell,
    Map? dataVerification,
  ) {
    if (dataVerification == null) {
      return false;
    }
    final item = Map<String, Object?>.from(dataVerification);
    final value =
        _dynamicArrayComputeText(sheet.dynamicArrayCompute, coord) ??
        cell?.renderedText;
    return !validateCellData(item, value, sheet: sheet);
  }

  void _drawDataVerificationFailureIndicator(Canvas canvas, Rect rect) {
    final path = Path()
      ..moveTo(rect.left, rect.top)
      ..lineTo(rect.left + 5, rect.top)
      ..lineTo(rect.left, rect.top + 5)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xfffc6666));
  }

  bool _showsQuotePrefixIndicator(FortuneCell? cell) {
    if (cell == null || !cell.quotePrefix) {
      return false;
    }
    final value = cell.hasRawValue ? cell.rawValue : cell.value;
    return _numberValue(value) != null;
  }

  void _drawQuotePrefixIndicator(Canvas canvas, Rect rect) {
    final path = Path()
      ..moveTo(rect.left + 5, rect.top)
      ..lineTo(rect.left - 1, rect.top)
      ..lineTo(rect.left - 1, rect.top + 6)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xff487f1e));
  }

  void _drawDataVerificationCheckbox(
    Canvas canvas,
    Rect rect,
    FortuneCell? cell,
    Map dataVerification,
  ) {
    if (rect.width < 14 || rect.height < 12) {
      return;
    }
    final text = cell?.renderedText ?? '';
    final foreground = cell?.foreground ?? const Color(0xff000000);
    final fontSize = cell?.fontSize ?? workbook.settings.defaultFontSize;
    final checkboxTop = rect.center.dy - 5;
    final checkboxLeft = switch (cell?.normalizedHorizontalAlign) {
      '0' => rect.center.dx - (text.isEmpty ? 5 : 28),
      '2' => rect.right - 14 - (text.isEmpty ? 0 : 42),
      _ => rect.left + 2,
    };
    final box = Rect.fromLTWH(
      checkboxLeft.clamp(rect.left + 1, rect.right - 11).toDouble(),
      checkboxTop.clamp(rect.top + 1, rect.bottom - 11).toDouble(),
      10,
      10,
    );
    final paint = Paint()
      ..color = const Color(0xff000000)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1;
    canvas.drawRect(box, paint);
    if (fortuneRawBool(dataVerification['checked']) == true) {
      final check = Path()
        ..moveTo(box.left + 1, box.top + 6)
        ..lineTo(box.left + 4, box.top + 9)
        ..lineTo(box.left + 9, box.top + 2);
      canvas.drawPath(check, paint);
    }
    if (text.isEmpty) {
      return;
    }
    _drawText(
      canvas,
      text,
      Rect.fromLTRB(box.right + 4, rect.top, rect.right - 2, rect.bottom),
      fontSize: fontSize,
      color: foreground,
      align: TextAlign.left,
    );
  }

  Map<FortuneCellCoord, _ConditionFormatStyle> _conditionFormatStyles(
    FortuneSheet sheet,
  ) {
    final rawRules = sheet.conditionFormats;
    if (rawRules is! List || rawRules.isEmpty) {
      return const {};
    }
    final styles = <FortuneCellCoord, _ConditionFormatStyle>{};
    for (final rawRule in rawRules) {
      if (rawRule is! Map) {
        continue;
      }
      final conditionName = '${rawRule['conditionName'] ?? rawRule['type']}';
      if (conditionName == 'dataBar') {
        _applyDataBarCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == 'colorGradation') {
        _applyColorGradationCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == 'icons') {
        _applyIconCondition(sheet, rawRule, styles);
        continue;
      }
      if (_isAggregateCondition(conditionName)) {
        _applyAggregateCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == 'formula') {
        _applyFormulaCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == fortuneConditionRuleOccurrenceDateType) {
        _applyOccurrenceDateCondition(sheet, rawRule, styles);
        continue;
      }
      final ranges = _conditionRanges(rawRule['cellrange']);
      if (ranges.isEmpty) {
        continue;
      }
      final format = rawRule['format'];
      final textColor = format is Map
          ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
          : null;
      final cellColor = format is Map
          ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
          : null;
      if (textColor == null && cellColor == null) {
        continue;
      }
      final values = rawRule['conditionValue'] is List
          ? rawRule['conditionValue'] as List
          : const [];
      for (final range in ranges) {
        for (var r = range.rowStart; r <= range.rowEnd; r += 1) {
          for (var c = range.columnStart; c <= range.columnEnd; c += 1) {
            final coord = FortuneCellCoord(r, c);
            final cell = sheet.cells[coord];
            if (cell == null || _conditionCellText(cell).isEmpty) {
              continue;
            }
            if (_matchesConditionFormat(cell, conditionName, values)) {
              _applyConditionFormatStyle(
                styles,
                coord,
                textColor: textColor,
                cellColor: cellColor,
              );
            }
          }
        }
      }
    }
    return styles;
  }

  Map<FortuneCellCoord, Color> _alternateFormatBackgrounds(FortuneSheet sheet) {
    return _alternateFormatColors(sheet, 'bc');
  }

  Map<FortuneCellCoord, Color> _alternateFormatForegrounds(FortuneSheet sheet) {
    return _alternateFormatColors(sheet, 'fc');
  }

  Map<FortuneCellCoord, Color> _alternateFormatColors(
    FortuneSheet sheet,
    String colorKey,
  ) {
    final rawFormats = sheet.alternateFormats;
    if (rawFormats is! List || rawFormats.isEmpty) {
      return const {};
    }
    final colors = <FortuneCellCoord, Color>{};
    for (final rawFormat in rawFormats) {
      if (rawFormat is! Map) {
        continue;
      }
      final ranges = _alternateFormatRanges(rawFormat['cellrange']);
      if (ranges.isEmpty) {
        continue;
      }
      final format = rawFormat['format'];
      if (format is! Map) {
        continue;
      }
      final headColor = _alternateFormatColor(format['head'], colorKey);
      final oneColor = _alternateFormatColor(format['one'], colorKey);
      final twoColor = _alternateFormatColor(format['two'], colorKey);
      final footColor = _alternateFormatColor(format['foot'], colorKey);
      if (headColor == null &&
          oneColor == null &&
          twoColor == null &&
          footColor == null) {
        continue;
      }
      final hasRowHeader =
          _fortuneRawChartBool(
            rawFormat['hasRowHeader'] ?? rawFormat['hasrowheader'],
          ) ==
          true;
      final hasRowFooter =
          _fortuneRawChartBool(
            rawFormat['hasRowFooter'] ?? rawFormat['hasrowfooter'],
          ) ==
          true;
      for (final range in ranges) {
        final bodyStart = range.rowStart + (hasRowHeader ? 1 : 0);
        for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
          final color = row == range.rowStart && hasRowHeader
              ? headColor ?? oneColor ?? twoColor
              : row == range.rowEnd && hasRowFooter
              ? footColor ?? twoColor ?? oneColor
              : ((row - bodyStart).isEven
                    ? oneColor ?? twoColor
                    : twoColor ?? oneColor);
          if (color == null) {
            continue;
          }
          for (
            var column = range.columnStart;
            column <= range.columnEnd;
            column += 1
          ) {
            colors[FortuneCellCoord(row, column)] = color;
          }
        }
      }
    }
    return colors;
  }

  List<FortuneRange> _alternateFormatRanges(Object? raw) {
    if (raw is Map) {
      final range = _rangeFromRowColumnMap(raw);
      return range == null ? const [] : [range];
    }
    return _conditionRanges(raw);
  }

  Color? _alternateFormatColor(Object? rawStyle, String colorKey) {
    if (rawStyle is Map) {
      if (colorKey == 'fc') {
        return _fortuneRawShapeColor(
          rawStyle['fc'] ??
              rawStyle['textColor'] ??
              rawStyle['foreground'] ??
              rawStyle['fontColor'] ??
              rawStyle['color'],
        );
      }
      return _fortuneRawShapeColor(
        rawStyle[colorKey] ??
            rawStyle['backgroundColor'] ??
            rawStyle['background'] ??
            rawStyle['cellColor'] ??
            rawStyle['color'],
      );
    }
    return _fortuneRawShapeColor(rawStyle);
  }

  bool _cellHasExplicitForeground(FortuneCell cell) {
    return cell.hasRawForeground || cell.foreground != const Color(0xff000000);
  }

  FortuneRange? _rangeFromRowColumnMap(Map raw) {
    final row = raw['row'];
    final column = raw['column'];
    if (row is! List ||
        row.length < 2 ||
        column is! List ||
        column.length < 2) {
      return null;
    }
    final rowStart = _intValue(row[0]);
    final rowEnd = _intValue(row[1]);
    final columnStart = _intValue(column[0]);
    final columnEnd = _intValue(column[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null) {
      return null;
    }
    return FortuneRange(
      rowStart: math.min(rowStart, rowEnd),
      rowEnd: math.max(rowStart, rowEnd),
      columnStart: math.min(columnStart, columnEnd),
      columnEnd: math.max(columnStart, columnEnd),
    );
  }

  bool _isAggregateCondition(String conditionName) {
    return conditionName == fortuneConditionRuleDuplicateType ||
        fortuneConditionRuleProjectTypes.contains(conditionName) ||
        fortuneConditionRuleAverageTypes.contains(conditionName);
  }

  void _applyAggregateCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
  ) {
    final conditionName = '${rawRule['conditionName'] ?? rawRule['type']}';
    final ranges = _conditionRanges(rawRule['cellrange']);
    if (ranges.isEmpty) {
      return;
    }
    final format = rawRule['format'];
    final textColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
        : null;
    final cellColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
        : null;
    if (textColor == null && cellColor == null) {
      return;
    }
    final values = rawRule['conditionValue'] is List
        ? rawRule['conditionValue'] as List
        : const [];
    if (conditionName == fortuneConditionRuleDuplicateType) {
      _applyDuplicateCondition(
        sheet,
        ranges,
        styles,
        unique: values.isNotEmpty && '${values[0]}' == '1',
        textColor: textColor,
        cellColor: cellColor,
      );
      return;
    }
    _applyNumericAggregateCondition(
      sheet,
      ranges,
      styles,
      conditionName,
      values,
      textColor: textColor,
      cellColor: cellColor,
    );
  }

  void _applyFormulaCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
  ) {
    final ranges = _conditionRanges(rawRule['cellrange']);
    if (ranges.isEmpty) {
      return;
    }
    final values = rawRule['conditionValue'] is List
        ? rawRule['conditionValue'] as List
        : const [];
    if (values.isEmpty || '${values[0]}'.trim().isEmpty) {
      return;
    }
    final format = rawRule['format'];
    final textColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
        : null;
    final cellColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
        : null;
    if (textColor == null && cellColor == null) {
      return;
    }
    final baseFormula = '${values[0]}'.startsWith('=')
        ? '${values[0]}'
        : '=${values[0]}';
    for (final range in ranges) {
      for (var r = range.rowStart; r <= range.rowEnd; r += 1) {
        for (var c = range.columnStart; c <= range.columnEnd; c += 1) {
          final formula = FortuneFormulaEngine.translateReferences(
            baseFormula,
            rowDelta: r - range.rowStart,
            columnDelta: c - range.columnStart,
          );
          final value = FortuneFormulaEngine.evaluateFormula(sheet, formula);
          if (!_conditionFormulaTruthy(value)) {
            continue;
          }
          _applyConditionFormatStyle(
            styles,
            FortuneCellCoord(r, c),
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  void _applyOccurrenceDateCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
  ) {
    final ranges = _conditionRanges(rawRule['cellrange']);
    if (ranges.isEmpty) {
      return;
    }
    final values = rawRule['conditionValue'] is List
        ? rawRule['conditionValue'] as List
        : const [];
    if (values.isEmpty || '${values[0]}'.trim().isEmpty) {
      return;
    }
    final dateRange = _conditionDateRange(values[0]);
    if (dateRange == null) {
      return;
    }
    final format = rawRule['format'];
    final textColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
        : null;
    final cellColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
        : null;
    if (textColor == null && cellColor == null) {
      return;
    }
    for (final range in ranges) {
      for (var r = range.rowStart; r <= range.rowEnd; r += 1) {
        for (var c = range.columnStart; c <= range.columnEnd; c += 1) {
          final coord = FortuneCellCoord(r, c);
          final cell = sheet.cells[coord];
          if (cell?.cellType?.type != 'd') {
            continue;
          }
          final serial =
              (cell == null
                  ? null
                  : _conditionDateSerial(_conditionCellValue(cell))) ??
              _conditionDateSerial(cell?.value) ??
              _conditionDateSerial(cell?.displayValue);
          if (serial == null ||
              serial < dateRange.start ||
              serial > dateRange.end) {
            continue;
          }
          _applyConditionFormatStyle(
            styles,
            coord,
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  _ConditionDateRange? _conditionDateRange(Object raw) {
    final text = '$raw'.trim();
    final parts = text.split(RegExp(r'\s+-\s+'));
    if (parts.length == 2) {
      final start = _conditionDateSerial(parts[0]);
      final end = _conditionDateSerial(parts[1]);
      if (start == null || end == null) {
        return null;
      }
      return _ConditionDateRange(math.min(start, end), math.max(start, end));
    }
    final exact = _conditionDateSerial(text);
    if (exact == null) {
      return null;
    }
    return _ConditionDateRange(exact, exact);
  }

  int? _conditionDateSerial(Object? raw) {
    if (raw == null) {
      return null;
    }
    if (raw is num) {
      return raw.floor();
    }
    final text = '$raw'.trim();
    if (text.isEmpty) {
      return null;
    }
    final number = double.tryParse(text);
    if (number != null) {
      return number.floor();
    }
    final match = RegExp(
      r'^(\d{4})[-/.](\d{1,2})[-/.](\d{1,2})',
    ).firstMatch(text);
    if (match == null) {
      return null;
    }
    final year = int.parse(match.group(1)!);
    final month = int.parse(match.group(2)!);
    final day = int.parse(match.group(3)!);
    final date = DateTime.utc(year, month, day);
    if (date.year != year || date.month != month || date.day != day) {
      return null;
    }
    return date.difference(DateTime.utc(1899, 12, 30)).inDays;
  }

  bool _conditionFormulaTruthy(Object? value) {
    if (value == null) {
      return false;
    }
    if (value is bool) {
      return value;
    }
    if (value is num) {
      return value != 0 && value.isFinite;
    }
    final text = '$value'.trim();
    if (text.isEmpty) {
      return false;
    }
    if (text.toUpperCase() == 'FALSE') {
      return false;
    }
    final number = _numberValue(text);
    return number == null ? true : number != 0 && number.isFinite;
  }

  void _applyDuplicateCondition(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles, {
    required bool unique,
    required Color? textColor,
    required Color? cellColor,
  }) {
    for (final range in ranges) {
      final groups = <String, List<FortuneCellCoord>>{};
      for (var r = range.rowStart; r <= range.rowEnd; r += 1) {
        for (var c = range.columnStart; c <= range.columnEnd; c += 1) {
          final coord = FortuneCellCoord(r, c);
          final cell = sheet.cells[coord];
          if (cell == null || _conditionCellText(cell).isEmpty) {
            continue;
          }
          groups.putIfAbsent(_conditionCellText(cell), () => []).add(coord);
        }
      }
      for (final coords in groups.values) {
        final matches = unique ? coords.length == 1 : coords.length > 1;
        if (!matches) {
          continue;
        }
        for (final coord in coords) {
          _applyConditionFormatStyle(
            styles,
            coord,
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  void _applyNumericAggregateCondition(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
    String conditionName,
    List conditionValues, {
    required Color? textColor,
    required Color? cellColor,
  }) {
    for (final range in ranges) {
      final numbers = _conditionNumericValues(sheet, [range]);
      if (numbers.isEmpty) {
        continue;
      }
      final selectedValues = <double>{};
      if (fortuneConditionRuleAverageTypes.contains(conditionName)) {
        final average =
            numbers.values.reduce((sum, value) => sum + value) / numbers.length;
        for (final entry in numbers.entries) {
          final matches = conditionName == fortuneConditionRuleAboveAverageType
              ? entry.value > average
              : entry.value < average;
          if (matches) {
            _applyConditionFormatStyle(
              styles,
              entry.key,
              textColor: textColor,
              cellColor: cellColor,
            );
          }
        }
        continue;
      }

      final sorted = numbers.values.toList()..sort((a, b) => b.compareTo(a));
      final rawCount = _intValue(
        conditionValues.isEmpty ? 10 : conditionValues[0],
      );
      final count = rawCount == null ? 10 : math.max(0, rawCount);
      final takeCount =
          fortuneConditionRuleProjectPercentTypes.contains(conditionName)
          ? ((count * sorted.length) / 100).floor()
          : count;
      if (takeCount <= 0) {
        continue;
      }
      final clampedTake = math.min(takeCount, sorted.length);
      if (fortuneConditionRuleProjectTopTypes.contains(conditionName)) {
        selectedValues.addAll(sorted.take(clampedTake));
      } else if (fortuneConditionRuleProjectBottomTypes.contains(
        conditionName,
      )) {
        selectedValues.addAll(sorted.skip(sorted.length - clampedTake));
      }
      if (selectedValues.isEmpty) {
        continue;
      }
      for (final entry in numbers.entries) {
        if (selectedValues.contains(entry.value)) {
          _applyConditionFormatStyle(
            styles,
            entry.key,
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  void _applyConditionFormatStyle(
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
    FortuneCellCoord coord, {
    required Color? textColor,
    required Color? cellColor,
  }) {
    final current = styles[coord];
    styles[coord] = _ConditionFormatStyle(
      textColor: textColor,
      cellColor: cellColor,
      dataBar: current?.dataBar,
      icon: current?.icon,
    );
  }

  void _applyDataBarCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
  ) {
    final ranges = _conditionRanges(rawRule['cellrange']);
    final values = _conditionNumericValues(
      sheet,
      ranges,
    ).map((coord, value) => MapEntry(coord, value.truncateToDouble()));
    if (values.isEmpty) {
      return;
    }
    final maxValue = values.values.reduce(math.max);
    final minValue = values.values.reduce(math.min);
    final colors = _conditionFormatColors(rawRule['format']);
    final plusLen = minValue < 0 && maxValue > 0
        ? (((maxValue / (maxValue - minValue)) * 10).round() / 10).clamp(
            0.0,
            1.0,
          )
        : 1.0;
    final minusLen = minValue < 0 && maxValue > 0
        ? (((minValue.abs() / (maxValue - minValue)) * 10).round() / 10).clamp(
            0.0,
            1.0,
          )
        : 0.0;

    for (final entry in values.entries) {
      final value = entry.value;
      if (value == 0 && minValue < 0 && maxValue > 0) {
        continue;
      }
      final valueLen = value < 0
          ? (minValue == 0
                ? 0.0
                : ((value.abs() / minValue.abs()) * 100).round() / 100)
          : (maxValue == 0 ? 1.0 : ((value / maxValue) * 100).round() / 100);
      final current = styles[entry.key];
      styles[entry.key] = _ConditionFormatStyle(
        textColor: current?.textColor,
        cellColor: current?.cellColor,
        icon: current?.icon,
        dataBar: _ConditionDataBar(
          valueType: value < 0
              ? _ConditionDataBarType.minus
              : _ConditionDataBarType.plus,
          valueLen: valueLen.clamp(0.0, 1.0),
          plusLen: plusLen,
          minusLen: minusLen,
          colors: colors.isEmpty ? const [Color(0xff638ec6)] : colors,
        ),
      );
    }
  }

  void _applyColorGradationCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
  ) {
    final ranges = _conditionRanges(rawRule['cellrange']);
    final values = _conditionNumericValues(
      sheet,
      ranges,
    ).map((coord, value) => MapEntry(coord, value.truncateToDouble()));
    final colors = _conditionFormatColors(rawRule['format']);
    if (values.isEmpty || colors.length < 2) {
      return;
    }
    final maxValue = values.values.reduce(math.max);
    final minValue = values.values.reduce(math.min);
    final middleValue =
        (values.values.reduce((sum, value) => sum + value) / values.length)
            .floorToDouble();
    for (final entry in values.entries) {
      final color = colors.length >= 3
          ? _threeColorScale(
              entry.value,
              minValue,
              middleValue,
              maxValue,
              low: colors[2],
              middle: colors[1],
              high: colors[0],
            )
          : _twoColorScale(
              entry.value,
              minValue,
              maxValue,
              low: colors[1],
              high: colors[0],
            );
      final current = styles[entry.key];
      styles[entry.key] = _ConditionFormatStyle(
        textColor: current?.textColor,
        cellColor: color,
        dataBar: current?.dataBar,
        icon: current?.icon,
      );
    }
  }

  void _applyIconCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _ConditionFormatStyle> styles,
  ) {
    final ranges = _conditionRanges(rawRule['cellrange']);
    final values = _conditionNumericValues(sheet, ranges);
    if (values.isEmpty) {
      return;
    }
    final maxValue = values.values.reduce(math.max);
    final minValue = values.values.reduce(math.min);
    final span = maxValue - minValue;
    for (final entry in values.entries) {
      final normalized = span == 0 ? 1.0 : (entry.value - minValue) / span;
      final kind = normalized >= 2 / 3
          ? _ConditionIconKind.up
          : normalized >= 1 / 3
          ? _ConditionIconKind.side
          : _ConditionIconKind.down;
      final current = styles[entry.key];
      styles[entry.key] = _ConditionFormatStyle(
        textColor: current?.textColor,
        cellColor: current?.cellColor,
        dataBar: current?.dataBar,
        icon: _ConditionIcon(kind),
      );
    }
  }

  Map<FortuneCellCoord, double> _conditionNumericValues(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
  ) {
    final values = <FortuneCellCoord, double>{};
    for (final range in ranges) {
      for (var r = range.rowStart; r <= range.rowEnd; r += 1) {
        for (var c = range.columnStart; c <= range.columnEnd; c += 1) {
          final coord = FortuneCellCoord(r, c);
          final cell = sheet.cells[coord];
          final value = cell == null
              ? null
              : _numberValue(_conditionCellValue(cell));
          if (value != null) {
            values[coord] = value;
          }
        }
      }
    }
    return values;
  }

  List<Color> _conditionFormatColors(Object? raw) {
    if (raw is List) {
      return [for (final item in raw) ?FortuneSheetCodec.parseColor('$item')];
    }
    if (raw is Map) {
      return [
        ?FortuneSheetCodec.parseColor('${raw['cellColor'] ?? ''}'),
        ?FortuneSheetCodec.parseColor('${raw['textColor'] ?? ''}'),
      ];
    }
    return const [];
  }

  Color _twoColorScale(
    double value,
    double minValue,
    double maxValue, {
    required Color low,
    required Color high,
  }) {
    if (maxValue == minValue) {
      return high;
    }
    final t = ((value - minValue) / (maxValue - minValue)).clamp(0.0, 1.0);
    return Color.lerp(low, high, t)!;
  }

  Color _threeColorScale(
    double value,
    double minValue,
    double middleValue,
    double maxValue, {
    required Color low,
    required Color middle,
    required Color high,
  }) {
    if (value <= middleValue) {
      return _twoColorScale(
        value,
        minValue,
        middleValue,
        low: low,
        high: middle,
      );
    }
    return _twoColorScale(
      value,
      middleValue,
      maxValue,
      low: middle,
      high: high,
    );
  }

  void _drawConditionDataBar(
    Canvas canvas,
    Rect rect,
    _ConditionDataBar dataBar,
  ) {
    if (rect.width <= 4 || rect.height <= 4 || dataBar.valueLen <= 0) {
      return;
    }
    final content = rect.deflate(2);
    final width = content.width;
    final paint = Paint();
    final color = dataBar.colors.first;
    late Rect barRect;
    if (dataBar.valueType == _ConditionDataBarType.minus) {
      final axis = content.left + width * dataBar.minusLen;
      final barWidth = width * dataBar.minusLen * dataBar.valueLen;
      barRect = Rect.fromLTWH(
        axis - barWidth,
        content.top,
        barWidth,
        content.height,
      );
      paint.color = const Color(0xffff0000);
    } else if (dataBar.minusLen > 0 && dataBar.plusLen < 1) {
      final axis = content.left + width * dataBar.minusLen;
      barRect = Rect.fromLTWH(
        axis,
        content.top,
        width * dataBar.plusLen * dataBar.valueLen,
        content.height,
      );
      paint.color = color;
    } else {
      barRect = Rect.fromLTWH(
        content.left,
        content.top,
        width * dataBar.valueLen,
        content.height,
      );
      paint.color = color;
    }
    if (barRect.width <= 0) {
      return;
    }
    if (dataBar.colors.length > 1 &&
        dataBar.valueType == _ConditionDataBarType.plus) {
      paint.shader = ui.Gradient.linear(
        barRect.topLeft,
        barRect.topRight,
        dataBar.colors.take(2).toList(),
      );
    }
    if (dataBar.valueType == _ConditionDataBarType.minus &&
        dataBar.colors.length > 1) {
      final columns = math.max(1, barRect.width.ceil());
      for (var i = 0; i < columns; i += 1) {
        final t = columns <= 1 ? 1.0 : i / (columns - 1);
        final stripLeft = barRect.left + i;
        final stripRight = math.min(stripLeft + 1, barRect.right);
        canvas.drawRect(
          Rect.fromLTRB(stripLeft, barRect.top, stripRight, barRect.bottom),
          Paint()
            ..color = Color.lerp(
              const Color(0xffffffff),
              const Color(0xffff0000),
              t,
            )!,
        );
      }
    } else {
      canvas.drawRect(barRect, paint);
    }
    canvas.drawRect(
      barRect,
      Paint()
        ..color = dataBar.valueType == _ConditionDataBarType.minus
            ? const Color(0xffff0000)
            : color
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1,
    );
  }

  void _drawConditionIcon(Canvas canvas, Rect rect, _ConditionIcon icon) {
    if (rect.width < 16 || rect.height < 12) {
      return;
    }
    final size = math.min(11.0, rect.height - 6);
    final center = Offset(rect.left + 8, rect.center.dy);
    final paint = Paint()..style = PaintingStyle.fill;
    final path = Path();
    switch (icon.kind) {
      case _ConditionIconKind.up:
        paint.color = const Color(0xff188038);
        path
          ..moveTo(center.dx, center.dy - size / 2)
          ..lineTo(center.dx + size / 2, center.dy + size / 2)
          ..lineTo(center.dx - size / 2, center.dy + size / 2)
          ..close();
      case _ConditionIconKind.side:
        paint.color = const Color(0xfffbbc04);
        path
          ..moveTo(center.dx + size / 2, center.dy)
          ..lineTo(center.dx - size / 2, center.dy - size / 2)
          ..lineTo(center.dx - size / 2, center.dy + size / 2)
          ..close();
      case _ConditionIconKind.down:
        paint.color = const Color(0xffd93025);
        path
          ..moveTo(center.dx, center.dy + size / 2)
          ..lineTo(center.dx + size / 2, center.dy - size / 2)
          ..lineTo(center.dx - size / 2, center.dy - size / 2)
          ..close();
    }
    canvas.drawPath(path, paint);
  }

  List<FortuneRange> _conditionRanges(Object? raw) {
    if (raw is! List) {
      return const [];
    }
    final ranges = <FortuneRange>[];
    for (final item in raw) {
      if (item is! Map) {
        continue;
      }
      final row = item['row'];
      final column = item['column'];
      if (row is! List ||
          row.length < 2 ||
          column is! List ||
          column.length < 2) {
        continue;
      }
      final rowStart = _intValue(row[0]);
      final rowEnd = _intValue(row[1]);
      final columnStart = _intValue(column[0]);
      final columnEnd = _intValue(column[1]);
      if (rowStart == null ||
          rowEnd == null ||
          columnStart == null ||
          columnEnd == null) {
        continue;
      }
      ranges.add(
        FortuneRange(
          rowStart: math.min(rowStart, rowEnd),
          rowEnd: math.max(rowStart, rowEnd),
          columnStart: math.min(columnStart, columnEnd),
          columnEnd: math.max(columnStart, columnEnd),
        ),
      );
    }
    return ranges;
  }

  bool _matchesConditionFormat(
    FortuneCell cell,
    String conditionName,
    List values,
  ) {
    final text = _conditionCellText(cell);
    final number = _numberValue(_conditionCellValue(cell));
    final first = values.isEmpty ? null : values[0];
    final second = values.length < 2 ? null : values[1];
    final firstNumber = _numberValue(first);
    final secondNumber = _numberValue(second);
    return switch (conditionName) {
      'greaterThan' =>
        number != null && firstNumber != null && number > firstNumber,
      'lessThan' =>
        number != null && firstNumber != null && number < firstNumber,
      'equal' => text == '$first',
      'textContains' => first != null && text.contains('$first'),
      'between' =>
        number != null &&
            firstNumber != null &&
            secondNumber != null &&
            number >= math.min(firstNumber, secondNumber) &&
            number <= math.max(firstNumber, secondNumber),
      _ => false,
    };
  }

  Object? _conditionCellValue(FortuneCell cell) {
    return cell.hasRawValue ? cell.rawValue : cell.value;
  }

  String _conditionCellText(FortuneCell cell) {
    final raw = _conditionCellValue(cell);
    return raw == null ? '' : '$raw';
  }

  int? _intValue(Object? raw) {
    if (raw is int) {
      return raw;
    }
    if (raw is num) {
      return raw.toInt();
    }
    return int.tryParse('$raw');
  }

  double? _numberValue(Object? raw) {
    if (raw is num) {
      return raw.toDouble();
    }
    return double.tryParse('$raw'.replaceAll(',', '').trim());
  }

  void _drawDataVerificationMarker(Canvas canvas, Rect rect) {
    if (rect.width < 14 || rect.height < 12) {
      return;
    }
    final center = Offset(rect.right - 8, rect.center.dy + 1);
    final path = Path()
      ..moveTo(center.dx - 4, center.dy - 2)
      ..lineTo(center.dx + 4, center.dy - 2)
      ..lineTo(center.dx, center.dy + 3)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xff5f6368));
  }

  void _drawDataVerificationDropdown(Canvas canvas, Size size) {
    final coord = dataVerificationDropdownCoord;
    if (coord == null) {
      return;
    }
    final sheet = workbook.activeSheet;
    final options = _dataVerificationOptions(
      sheet.dataVerification[_cellKey(coord)],
      sheet: sheet,
    );
    if (options.isEmpty) {
      return;
    }
    final settings = workbook.settings;
    final metrics = sheet.metrics(settings);
    final cellRect = _cellRectForCoord(coord, settings, metrics);
    if (cellRect == null) {
      return;
    }
    final raw = sheet.dataVerification[_cellKey(coord)];
    final isMultiSelect = raw is Map && fortuneRawBool(raw['type2']) == true;
    final selectedOptions = isMultiSelect
        ? _dataVerificationOptions({
            'value1': sheet.cells[coord]?.value,
          }, resolveReferences: false).toSet()
        : const <String>{};
    final width = math.max(
      120.0,
      math.max(cellRect.width, _longestOptionWidth(options)),
    );
    final height = math.min(8, options.length) * 24.0;
    var left = cellRect.left;
    var top = cellRect.bottom + 1;
    left = left.clamp(0.0, math.max(0.0, size.width - width)).toDouble();
    if (top + height > size.height) {
      top = math.max(0.0, cellRect.top - height - 1);
    }
    final rect = Rect.fromLTWH(left, top, width, height);
    canvas.drawRect(
      rect,
      Paint()
        ..color = const Color(0x22000000)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 4),
    );
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..color = const Color(0xffc7c7c7)
        ..style = PaintingStyle.stroke,
    );
    for (var i = 0; i < options.length && i < 8; i += 1) {
      final rowRect = Rect.fromLTWH(
        rect.left,
        rect.top + i * 24,
        rect.width,
        24,
      );
      if (i > 0) {
        _line(
          canvas,
          Offset(rowRect.left, rowRect.top),
          Offset(rowRect.right, rowRect.top),
          const Color(0xffeeeeee),
        );
      }
      final checked = selectedOptions.contains(options[i]);
      if (checked) {
        final checkPath = Path()
          ..moveTo(rowRect.left + 6, rowRect.center.dy)
          ..lineTo(rowRect.left + 10, rowRect.center.dy + 4)
          ..lineTo(rowRect.left + 18, rowRect.center.dy - 5);
        canvas.drawPath(
          checkPath,
          Paint()
            ..color = fortuneConditionRuleSetCheckboxCheckColor
            ..style = PaintingStyle.stroke
            ..strokeWidth = 2
            ..strokeCap = StrokeCap.round
            ..strokeJoin = StrokeJoin.round,
        );
      }
      _drawText(
        canvas,
        options[i],
        _menuLabelRect(rowRect, 6, leftOffset: checked ? 16 : 0),
        fontSize: 12,
        align: TextAlign.left,
        color: const Color(0xff222222),
      );
    }
  }

  String? get dataVerificationHintText {
    final body = _selectedDataVerificationHintBody();
    if (body == null) {
      return null;
    }
    final prefix = _dataVerificationHintPrefix();
    return body.isEmpty ? prefix : '$prefix $body';
  }

  void _drawDataVerificationHint(Canvas canvas, Size size) {
    final text = dataVerificationHintText;
    if (text == null) {
      return;
    }
    final coord = FortuneCellCoord(selection.row, selection.column);
    final settings = workbook.settings;
    final metrics = workbook.activeSheet.metrics(settings);
    final cellRect = _cellRectForCoord(coord, settings, metrics);
    if (cellRect == null) {
      return;
    }
    final width = math.min(
      math.max(160.0, text.length * 7.0 + 24.0),
      math.max(0.0, size.width),
    );
    const height = 30.0;
    var left = cellRect.left;
    var top = cellRect.bottom + 1;
    left = left.clamp(0.0, math.max(0.0, size.width - width)).toDouble();
    if (top + height > size.height) {
      top = math.max(0.0, cellRect.top - height - 1);
    }
    final rect = Rect.fromLTWH(left, top, width, height);
    canvas.drawRect(
      rect,
      Paint()
        ..color = const Color(0x22000000)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 4),
    );
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..color = const Color(0xffc7c7c7)
        ..style = PaintingStyle.stroke,
    );
    final body = text.startsWith('Hint: ') ? text.substring(6) : '';
    final paragraphStyle = ui.ParagraphStyle(
      textDirection: textDirection,
      fontSize: 12,
      maxLines: 1,
      ellipsis: '',
    );
    final builder = ui.ParagraphBuilder(paragraphStyle)
      ..pushStyle(
        ui.TextStyle(
          color: const Color(0xfff5a623),
          fontSize: 12,
          fontFamily: 'Arial',
          fontWeight: FontWeight.w700,
        ),
      )
      ..addText(_dataVerificationHintPrefix());
    if (body.isNotEmpty) {
      builder
        ..addText(' ')
        ..pushStyle(
          ui.TextStyle(
            color: const Color(0xff222222),
            fontSize: 12,
            fontFamily: 'Arial',
            fontWeight: FontWeight.w400,
          ),
        )
        ..addText(body);
    }
    final paragraph = builder.build()
      ..layout(ui.ParagraphConstraints(width: rect.width - 16));
    canvas.save();
    canvas.clipRect(rect.deflate(1));
    canvas.drawParagraph(
      paragraph,
      Offset(
        rect.left + 8,
        rect.top + math.max(0, (height - paragraph.height) / 2),
      ),
    );
    canvas.restore();
  }

  String? _selectedDataVerificationHintBody() {
    final coord = FortuneCellCoord(selection.row, selection.column);
    final raw = workbook.activeSheet.dataVerification[_cellKey(coord)];
    if (raw is! Map || fortuneRawBool(raw['hintShow']) != true) {
      return null;
    }
    return getHintText(Map<String, Object?>.from(raw), lang: _workbookLang);
  }

  String get _workbookLang => workbook.settings.lang ?? 'en';

  String _dataVerificationHintPrefix() {
    return switch (_workbookLang) {
      'ru' => 'Подсказка:',
      'zh' || 'zh-CN' || 'zh-TW' => '提示：',
      'es' => 'Consejos：',
      'hi' => 'संकेत:',
      _ => 'Hint:',
    };
  }

  void _drawFilterDropdown(Canvas canvas, Size size) {
    final column = filterDropdownColumn;
    if (column == null) {
      return;
    }
    final rect = _filterDropdownRect(size, column);
    if (rect == null) {
      return;
    }
    final options = _filterDropdownLabels(column);
    if (options.isEmpty) {
      return;
    }
    final checkedLabels = _filterDropdownCheckedLabels(column);
    final valueCounts = _filterDropdownValueCounts(column);
    canvas.drawRect(
      rect,
      Paint()
        ..color = const Color(0x22000000)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 4),
    );
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      rect,
      Paint()
        ..color = const Color(0xffc7c7c7)
        ..style = PaintingStyle.stroke,
    );
    _drawFilterDropdownSearch(canvas, rect);
    final fixedRows = _filterDropdownFixedRowCount();
    final firstVisibleChoiceIndex =
        (filterDropdownScrollOffset / fortuneFilterDropdownRowHeight).floor();
    for (var visibleIndex = 0; visibleIndex < 8; visibleIndex += 1) {
      final index = visibleIndex < fixedRows
          ? visibleIndex
          : fixedRows + firstVisibleChoiceIndex + visibleIndex - fixedRows;
      if (index >= options.length) {
        break;
      }
      final rowRect = Rect.fromLTWH(
        rect.left,
        rect.top + visibleIndex * fortuneFilterDropdownRowHeight,
        rect.width,
        fortuneFilterDropdownRowHeight,
      );
      if (index > 0) {
        _line(
          canvas,
          Offset(rowRect.left, rowRect.top),
          Offset(rowRect.right, rowRect.top),
          const Color(0xffeeeeee),
        );
      }
      final isClearRow = options[index] == locale.filterClear;
      final colorHex = _filterDropdownColorHex(options[index]);
      final isChoiceRow = index >= fixedRows;
      final isCheckedRow = checkedLabels.contains(options[index]);
      final valueCount = colorHex == null ? valueCounts[options[index]] : null;
      var textRect = _menuLabelRect(rowRect, 6);
      if (isClearRow) {
        final controlsRect = Rect.fromLTRB(
          rowRect.right - fortuneFilterDropdownBulkControlsWidth - 6,
          rowRect.top,
          rowRect.right - 6,
          rowRect.bottom,
        );
        textRect = Rect.fromLTRB(
          textRect.left,
          textRect.top,
          controlsRect.left - 4,
          textRect.bottom,
        );
        _drawFilterDropdownBulkControls(canvas, controlsRect);
      }
      if (isChoiceRow) {
        final checkboxRect = Rect.fromLTWH(
          rowRect.left + 7,
          rowRect.top + (fortuneFilterDropdownRowHeight - 12) / 2,
          12,
          12,
        );
        _drawCheckbox(canvas, checkboxRect, isCheckedRow);
        textRect = Rect.fromLTRB(
          rowRect.left + 25,
          textRect.top,
          textRect.right,
          textRect.bottom,
        );
      }
      if (colorHex != null) {
        final swatchColor = FortuneSheetCodec.parseColor(colorHex);
        final swatchLeft = rowRect.left + (isChoiceRow ? 25 : 7);
        final swatchRect = Rect.fromLTWH(
          swatchLeft,
          rowRect.top + (fortuneFilterDropdownRowHeight - 12) / 2,
          12,
          12,
        );
        canvas.drawRect(
          swatchRect,
          Paint()..color = swatchColor ?? const Color(0xffffffff),
        );
        canvas.drawRect(
          swatchRect,
          Paint()
            ..color = const Color(0xff888888)
            ..style = PaintingStyle.stroke,
        );
        textRect = Rect.fromLTRB(
          rowRect.left + (isChoiceRow ? 43 : 25),
          textRect.top,
          textRect.right,
          textRect.bottom,
        );
      }
      if (valueCount != null) {
        final countRect = Rect.fromLTRB(
          rowRect.right - fortuneFilterDropdownCountWidth - 6,
          textRect.top,
          rowRect.right - 6,
          textRect.bottom,
        );
        textRect = Rect.fromLTRB(
          textRect.left,
          textRect.top,
          countRect.left - 4,
          textRect.bottom,
        );
        _drawText(
          canvas,
          '( $valueCount )',
          countRect,
          fontSize: 12,
          color: const Color(0xff777777),
          align: TextAlign.right,
        );
      }
      _drawText(
        canvas,
        options[index],
        textRect,
        fontSize: 12,
        color: isClearRow ? const Color(0xff666666) : const Color(0xff222222),
        bold: isClearRow,
      );
    }
    final noMatchVisibleIndex = _filterDropdownNoMatchVisibleIndex(
      options,
      firstVisibleChoiceIndex,
    );
    if (noMatchVisibleIndex != null) {
      final rowRect = Rect.fromLTWH(
        rect.left,
        rect.top + noMatchVisibleIndex * fortuneFilterDropdownRowHeight,
        rect.width,
        fortuneFilterDropdownRowHeight,
      );
      _line(
        canvas,
        Offset(rowRect.left, rowRect.top),
        Offset(rowRect.right, rowRect.top),
        const Color(0xffeeeeee),
      );
      _drawText(
        canvas,
        locale.filterNoMatches,
        _menuLabelRect(rowRect, 6),
        fontSize: 12,
        color: const Color(0xff999999),
        align: TextAlign.left,
      );
    }
    _drawFilterDropdownScrollbar(canvas, rect, options.length);
  }

  int? _filterDropdownNoMatchVisibleIndex(
    List<String> options,
    int firstVisibleChoiceIndex,
  ) {
    if (filterDropdownSearchText.trim().isEmpty) {
      return null;
    }
    final fixedRows = _filterDropdownFixedRowCount();
    final colorChoiceCount = options.skip(fixedRows).where((option) {
      return _filterDropdownColorHex(option) != null;
    }).length;
    final hasValueMatch = options.skip(fixedRows + colorChoiceCount).any((
      option,
    ) {
      return _filterDropdownColorHex(option) == null;
    });
    if (hasValueMatch) {
      return null;
    }
    final noMatchIndex = fixedRows + colorChoiceCount;
    final visibleIndex = noMatchIndex - firstVisibleChoiceIndex;
    if (visibleIndex < fixedRows ||
        visibleIndex >= fortuneFilterDropdownMaxVisibleRows) {
      return null;
    }
    return visibleIndex;
  }

  void _drawFilterDropdownSearch(Canvas canvas, Rect rect) {
    final searchRect = fortuneFilterDropdownSearchRect(rect);
    canvas.drawRect(
      searchRect,
      Paint()
        ..color = const Color(0x22000000)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 3),
    );
    canvas.drawRect(searchRect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      searchRect,
      Paint()
        ..color = const Color(0xffc7c7c7)
        ..style = PaintingStyle.stroke,
    );
    final text = filterDropdownSearchText.trim().isEmpty
        ? locale.filterValueSearchPlaceholder
        : filterDropdownSearchText;
    _drawText(
      canvas,
      text,
      searchRect.deflate(7),
      fontSize: 12,
      color: filterDropdownSearchText.trim().isEmpty
          ? const Color(0xff999999)
          : const Color(0xff222222),
      align: TextAlign.left,
    );
  }

  void _drawFilterDropdownScrollbar(Canvas canvas, Rect rect, int optionCount) {
    final fixedRows = _filterDropdownFixedRowCount();
    final choiceCount = math.max(0, optionCount - fixedRows);
    final visibleChoiceRows = math.max(
      0.0,
      fortuneFilterDropdownMaxVisibleRows - fixedRows,
    );
    if (choiceCount <= visibleChoiceRows) {
      return;
    }
    final trackTop = rect.top + fixedRows * fortuneFilterDropdownRowHeight + 3;
    final trackHeight =
        (visibleChoiceRows * fortuneFilterDropdownRowHeight) - 6;
    final trackRect = Rect.fromLTWH(rect.right - 5, trackTop, 3, trackHeight);
    canvas.drawRRect(
      RRect.fromRectAndRadius(trackRect, const Radius.circular(1.5)),
      Paint()..color = const Color(0xffe0e0e0),
    );
    final maxScrollOffset =
        (choiceCount - visibleChoiceRows) * fortuneFilterDropdownRowHeight;
    final thumbHeight = math.max(
      16.0,
      trackHeight * visibleChoiceRows / choiceCount,
    );
    final thumbTop =
        trackTop +
        (trackHeight - thumbHeight) *
            (filterDropdownScrollOffset / maxScrollOffset).clamp(0.0, 1.0);
    final thumbRect = Rect.fromLTWH(
      trackRect.left,
      thumbTop,
      trackRect.width,
      thumbHeight,
    );
    canvas.drawRRect(
      RRect.fromRectAndRadius(thumbRect, const Radius.circular(1.5)),
      Paint()..color = const Color(0xff9a9a9a),
    );
  }

  void _drawFilterDropdownBulkControls(Canvas canvas, Rect rect) {
    final labels = [
      locale.filterCheckAll,
      locale.filterClearSelection,
      locale.filterInverseSelection,
    ];
    final widths = [
      fortuneFilterDropdownBulkCheckAllWidth,
      fortuneFilterDropdownBulkClearWidth,
      fortuneFilterDropdownBulkInverseWidth,
    ];
    var left = rect.left;
    for (var index = 0; index < labels.length; index += 1) {
      final width = widths[index];
      final itemRect = Rect.fromLTWH(left, rect.top, width, rect.height);
      _drawText(
        canvas,
        labels[index],
        itemRect,
        fontSize: 11,
        color: const Color(0xff0188fb),
        align: TextAlign.center,
      );
      left += width;
      if (index < labels.length - 1) {
        _drawText(
          canvas,
          '-',
          Rect.fromLTWH(
            left,
            rect.top,
            fortuneFilterDropdownBulkSeparatorWidth,
            rect.height,
          ),
          fontSize: 9,
          color: const Color(0xff999999),
          align: TextAlign.center,
        );
        left += fortuneFilterDropdownBulkSeparatorWidth;
      }
    }
  }

  Set<String> _filterDropdownCheckedLabels(int column) {
    final sheet = workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final raw = sheet.filter[key];
    if (raw is! Map) {
      return _filterDropdownChoiceLabels(column).toSet();
    }
    final colorLabel = _filterDropdownColorLabelFromCaljs(raw['caljs']);
    if (colorLabel != null) {
      return {colorLabel};
    }
    final value = raw['filterValue'];
    if (value != null) {
      return {'$value'};
    }
    final hiddenRows = _filterHiddenRowsForEntry(sheet, key, raw);
    if (hiddenRows.isEmpty) {
      return _filterDropdownChoiceLabels(column).toSet();
    }
    final checkedByLabel = <String, bool>{};
    final rowRange = _filterRowRangeFromConfig(sheet, raw);
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final isHidden = hiddenRows.contains(row);
      void markLabel(String label) {
        checkedByLabel[label] = (checkedByLabel[label] ?? true) && !isHidden;
      }

      final text = _filterCellOptionText(
        sheet.cells[FortuneCellCoord(row, column)],
      );
      final trimmed = text?.trim();
      markLabel(
        trimmed == null || trimmed.isEmpty ? fortuneFilterBlankLabel : trimmed,
      );
      final cell = sheet.cells[FortuneCellCoord(row, column)];
      markLabel(
        '${locale.filterCellColor} ${_filterCellColorHex(cell, 'cell')}',
      );
      final foreground = _filterCellForegroundHex(cell);
      if (foreground != null) {
        markLabel('${locale.filterTextColor} $foreground');
      }
    }
    final choiceLabels = _filterDropdownChoiceLabels(column).toSet();
    return checkedByLabel.entries
        .where((entry) => entry.value && choiceLabels.contains(entry.key))
        .map((entry) => entry.key)
        .toSet();
  }

  Iterable<String> _filterDropdownChoiceLabels(int column) sync* {
    for (final label in _filterDropdownLabels(
      column,
    ).skip(_filterDropdownFixedRowCount())) {
      yield label;
    }
  }

  Map<String, int> _filterDropdownValueCounts(int column) {
    final sheet = workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final raw = sheet.filter[key];
    final rowRange = raw is Map
        ? _filterRowRangeFromConfig(sheet, raw)
        : _filterDataRowRangeFromSelect(sheet);
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    final counts = <String, int>{};
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final text = _filterCellOptionText(
        sheet.cells[FortuneCellCoord(row, column)],
      );
      final trimmed = text?.trim();
      final label = trimmed == null || trimmed.isEmpty
          ? fortuneFilterBlankLabel
          : trimmed;
      counts[label] = (counts[label] ?? 0) + 1;
    }
    return counts;
  }

  String? _filterDropdownColorLabelFromCaljs(Object? raw) {
    final colorFilter = _filterColorFilterFromCaljs(raw);
    if (colorFilter == null) {
      return null;
    }
    final label = colorFilter.$1 == 'cell'
        ? locale.filterCellColor
        : locale.filterTextColor;
    return '$label ${colorFilter.$2}';
  }

  String? _filterDropdownColorHex(String label) {
    final cellPrefix = '${locale.filterCellColor} ';
    if (label.startsWith(cellPrefix)) {
      return label.substring(cellPrefix.length).trim();
    }
    final textPrefix = '${locale.filterTextColor} ';
    if (label.startsWith(textPrefix)) {
      return label.substring(textPrefix.length).trim();
    }
    return null;
  }

  Rect? _cellRectForCoord(
    FortuneCellCoord coord,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheet = workbook.activeSheet;
    if (coord.row < 0 ||
        coord.column < 0 ||
        coord.row >= metrics.visibleDataRows.length ||
        coord.column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final cell = sheet.cells[coord];
    final rowSpan = math.max(1, cell?.merge?.rowSpan ?? 1);
    final columnSpan = math.max(1, cell?.merge?.columnSpan ?? 1);
    final rowEnd = math.min(
      metrics.visibleDataRows.length - 1,
      coord.row + rowSpan - 1,
    );
    final columnEnd = math.min(
      metrics.visibleDataColumns.length - 1,
      coord.column + columnSpan - 1,
    );
    final startX = metrics.columnStart(coord.column);
    final endX = metrics.columnEnd(columnEnd);
    final startY = metrics.rowStart(coord.row);
    final endY = metrics.rowEnd(rowEnd);
    if (endX <= startX || endY <= startY) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    return Rect.fromLTWH(
      _visualCellLeft(coord.column, settings, metrics),
      sheetTop + _visualCellTop(coord.row, settings, metrics),
      endX - startX,
      endY - startY,
    );
  }

  String _cellKey(FortuneCellCoord coord) => '${coord.row}_${coord.column}';

  double _longestOptionWidth(List<String> options) {
    var longest = 0;
    for (final option in options) {
      longest = math.max(longest, option.length);
    }
    return longest * 7.0 + 26;
  }

  List<String> _dataVerificationOptions(
    Object? raw, {
    FortuneSheet? sheet,
    bool resolveReferences = true,
  }) {
    if (raw is! Map) {
      return const [];
    }
    final value = raw['value1'] ?? raw['value'] ?? raw['values'];
    if (value is Iterable) {
      return _dedupeDataVerificationOptions(
        value.map((item) => '$item'.trim()),
      );
    }
    final text = '$value';
    if (resolveReferences) {
      final referenceOptions = _dataVerificationReferenceOptions(
        text,
        sheet ?? workbook.activeSheet,
      );
      if (referenceOptions != null) {
        return referenceOptions;
      }
    }
    return _dedupeDataVerificationOptions(
      text.split(RegExp(r'[\n,]')).map((item) => item.trim()),
    );
  }

  List<String> _dedupeDataVerificationOptions(Iterable<String> values) {
    final options = <String>[];
    for (final value in values) {
      if (value.isEmpty || options.contains(value)) {
        continue;
      }
      options.add(value);
    }
    return options;
  }

  List<String>? _dataVerificationReferenceOptions(
    String text,
    FortuneSheet defaultSheet,
  ) {
    final reference = text.trim();
    final match = RegExp(
      r"^(?:(?:'([^']+)'|([^'!]+))!)?\$?([A-Za-z]+)\$?(\d+)(?::\$?([A-Za-z]+)\$?(\d+))?$",
    ).firstMatch(reference);
    if (match == null) {
      return null;
    }
    final sheetName = match.group(1) ?? match.group(2);
    var sourceSheet = defaultSheet;
    if (sheetName != null) {
      final matchingSheets = workbook.sheets.where(
        (candidate) => candidate.name == sheetName || candidate.id == sheetName,
      );
      if (matchingSheets.isEmpty) {
        return const [];
      }
      sourceSheet = matchingSheets.first;
    }
    final startColumn = _columnIndex(match.group(3)!);
    final startRow = int.tryParse(match.group(4)!) == null
        ? null
        : int.parse(match.group(4)!) - 1;
    final endColumn = _columnIndex(match.group(5) ?? match.group(3)!);
    final endRow = int.tryParse(match.group(6) ?? match.group(4)!) == null
        ? null
        : int.parse(match.group(6) ?? match.group(4)!) - 1;
    if (startColumn == null ||
        startRow == null ||
        endColumn == null ||
        endRow == null) {
      return const [];
    }
    final rowStart = math.min(startRow, endRow);
    final rowEnd = math.max(startRow, endRow);
    final columnStart = math.min(startColumn, endColumn);
    final columnEnd = math.max(startColumn, endColumn);
    final options = <String>[];
    for (var rowIndex = rowStart; rowIndex <= rowEnd; rowIndex += 1) {
      for (
        var columnIndex = columnStart;
        columnIndex <= columnEnd;
        columnIndex += 1
      ) {
        final option = sourceSheet
            .cells[FortuneCellCoord(rowIndex, columnIndex)]
            ?.renderedText
            .trim();
        if (option == null || option.isEmpty || options.contains(option)) {
          continue;
        }
        options.add(option);
      }
    }
    return options;
  }

  int? _columnIndex(String name) {
    var value = 0;
    for (final codeUnit in name.toUpperCase().codeUnits) {
      if (codeUnit < 65 || codeUnit > 90) {
        return null;
      }
      value = value * 26 + codeUnit - 64;
    }
    return value - 1;
  }

  Rect? _filterHeaderRect(int column) {
    return _columnHeaderRect(column);
  }

  Rect? _columnHeaderRect(int column) {
    final settings = workbook.settings;
    final sheet = workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    if (column < 0 || column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final width = metrics.columnEnd(column) - metrics.columnStart(column);
    if (width <= 0) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    return Rect.fromLTWH(
      _visualCellLeft(column, settings, metrics),
      sheetTop,
      width,
      settings.columnHeaderHeight,
    );
  }

  Rect? _filterDropdownRect(Size size, int column) {
    final headerRect = _filterHeaderRect(column);
    if (headerRect == null) {
      return null;
    }
    final options = _filterDropdownUnfilteredLabels(column);
    if (options.isEmpty) {
      return null;
    }
    final width = math.max(
      fortuneFilterDropdownMinWidth,
      _longestOptionWidth(options),
    );
    final height =
        math.min(
          fortuneFilterDropdownMaxVisibleRows,
          options.length.toDouble(),
        ) *
        fortuneFilterDropdownRowHeight;
    var left = headerRect.right - width;
    var top = headerRect.bottom + 1;
    left = left.clamp(0.0, math.max(0.0, size.width - width)).toDouble();
    if (top + height > size.height) {
      top = math.max(0.0, headerRect.top - height - 1);
    }
    return Rect.fromLTWH(left, top, width, height);
  }

  List<String> _filterDropdownLabels(int column, {bool applySearch = true}) {
    final values = <String>{};
    var hasBlank = false;
    final sheet = workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final raw = sheet.filter[key];
    final rowRange = raw is Map
        ? _filterRowRangeFromConfig(sheet, raw)
        : _filterDataRowRangeFromSelect(sheet);
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final text = _filterCellOptionText(
        sheet.cells[FortuneCellCoord(row, column)],
      );
      final trimmed = text?.trim();
      if (trimmed == null || trimmed.isEmpty) {
        hasBlank = true;
      } else {
        values.add(trimmed);
      }
    }
    final valueLabels = values.toList();
    if (hasBlank) {
      valueLabels.add(fortuneFilterBlankLabel);
    }
    final searchText = applySearch
        ? filterDropdownSearchText.trim().toLowerCase()
        : '';
    final filteredValues = searchText.isEmpty
        ? valueLabels
        : valueLabels
              .where((value) => value.toLowerCase().contains(searchText))
              .toList(growable: false);
    final colorLabels = _filterDropdownColorLabels(column, rowRange, key);
    return _filterDropdownLabelsForSettings(
      colorLabels: colorLabels,
      valueLabels: filteredValues,
    );
  }

  List<String> _filterDropdownUnfilteredLabels(int column) {
    return _filterDropdownLabels(column, applySearch: false);
  }

  List<String> _filterDropdownLabelsForSettings({
    required List<String> colorLabels,
    required List<String> valueLabels,
  }) {
    final items = workbook.settings.filterContextMenu;
    final labels = <String>[];
    if (items.contains(fortuneFilterSortAscCommand)) {
      labels.add(locale.filterSortByAsc);
    }
    if (items.contains(fortuneFilterSortDescCommand)) {
      labels.add(locale.filterSortByDesc);
    }
    if (items.contains(fortuneFilterByValueCommand)) {
      labels.add(locale.filterClear);
    }
    if (items.contains(fortuneFilterByConditionCommand)) {
      labels.add(locale.filterByCondition);
    }
    if (items.contains(fortuneFilterByColorCommand)) {
      labels.addAll(colorLabels);
    }
    if (items.contains(fortuneFilterByValueCommand)) {
      labels.addAll(valueLabels);
    }
    return labels;
  }

  int _filterDropdownFixedRowCount() {
    final items = workbook.settings.filterContextMenu;
    var count = 0;
    if (items.contains(fortuneFilterSortAscCommand)) {
      count += 1;
    }
    if (items.contains(fortuneFilterSortDescCommand)) {
      count += 1;
    }
    if (items.contains(fortuneFilterByValueCommand)) {
      count += 1;
    }
    if (items.contains(fortuneFilterByConditionCommand)) {
      count += 1;
    }
    return count;
  }

  List<String> _filterDropdownColorLabels(
    int column,
    (int, int) rowRange,
    String key,
  ) {
    final sheet = workbook.activeSheet;
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    final backgroundColors = <String>{};
    final foregroundColors = <String>{};
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final cell = sheet.cells[FortuneCellCoord(row, column)];
      backgroundColors.add(_filterCellColorHex(cell, 'cell'));
      final foreground = _filterCellForegroundHex(cell);
      if (foreground != null) {
        foregroundColors.add(foreground);
      }
    }
    final labels = <String>[];
    if (backgroundColors.length > 1) {
      labels.addAll(
        (backgroundColors.toList()..sort()).map(
          (color) => '${locale.filterCellColor} $color',
        ),
      );
    }
    if (foregroundColors.length > 1) {
      labels.addAll(
        (foregroundColors.toList()..sort()).map(
          (color) => '${locale.filterTextColor} $color',
        ),
      );
    }
    return labels;
  }

  String _filterKeyForColumn(FortuneSheet sheet, int column) {
    for (final entry in sheet.filter.entries) {
      final value = entry.value;
      if (entry.key == 'column_$column') {
        return entry.key;
      }
      if (value is Map) {
        final focus = value['column_focus'];
        if (focus is int && focus == column) {
          return entry.key;
        }
        final cindex = value['cindex'];
        if (cindex is int && cindex == column) {
          return entry.key;
        }
        final rawColumn = value['column'];
        if (rawColumn is List &&
            rawColumn.isNotEmpty &&
            rawColumn.first == column) {
          return entry.key;
        }
        if (rawColumn is int && rawColumn == column) {
          return entry.key;
        }
      }
    }
    final filterSelectRange = _filterSelectRange(sheet);
    if (filterSelectRange != null &&
        column >= filterSelectRange.columnStart &&
        column <= filterSelectRange.columnEnd) {
      return '${column - filterSelectRange.columnStart}';
    }
    return 'column_$column';
  }

  Set<int> _filterHiddenRows(FortuneSheet sheet, {String? exceptKey}) {
    final rows = <int>{};
    for (final entry in sheet.filter.entries) {
      if (entry.key == exceptKey) {
        continue;
      }
      rows.addAll(_filterHiddenRowsForEntry(sheet, entry.key, entry.value));
    }
    return rows;
  }

  Set<int> _filterHiddenRowsForEntry(
    FortuneSheet sheet,
    String key,
    Object? raw,
  ) {
    if (raw is! Map) {
      return const {};
    }
    final rowhidden = raw['rowhidden'];
    final parsed = <int>{};
    if (rowhidden is Map) {
      for (final entry in rowhidden.entries) {
        final row = entry.key is int
            ? entry.key as int
            : int.tryParse('${entry.key}');
        if (row != null) {
          parsed.add(row);
        }
      }
    }
    if (parsed.isNotEmpty) {
      return parsed;
    }
    final column = _filterColumnFromConfig(key, raw);
    if (column == null) {
      return const {};
    }
    final colorFilter = _filterColorFilterFromCaljs(raw['caljs']);
    if (colorFilter != null) {
      final rows = <int>{};
      final rowRange = _filterRowRangeFromConfig(sheet, raw);
      for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
        final cell = sheet.cells[FortuneCellCoord(row, column)];
        final cellColor = colorFilter.$1 == 'cell'
            ? _filterCellColorHex(cell, colorFilter.$1)
            : _filterCellForegroundHex(cell);
        if (cellColor != colorFilter.$2) {
          rows.add(row);
        }
      }
      return rows;
    }
    final filterValue = raw['filterValue'];
    if (filterValue == null) {
      return const {};
    }
    final value = '$filterValue';
    final rows = <int>{};
    final rowRange = _filterRowRangeFromConfig(sheet, raw);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      final text =
          _filterCellOptionText(
            sheet.cells[FortuneCellCoord(row, column)],
          )?.trim() ??
          '';
      final matches = value == fortuneFilterBlankLabel
          ? text.isEmpty
          : text == value;
      if (!matches) {
        rows.add(row);
      }
    }
    return rows;
  }

  int? _filterColumnFromConfig(String key, Map raw) {
    if (key.startsWith('column_')) {
      final parsed = int.tryParse(key.substring('column_'.length));
      if (parsed != null) {
        return parsed;
      }
    }
    final focus = raw['column_focus'];
    if (focus is int) {
      return focus;
    }
    final cindex = raw['cindex'];
    if (cindex is int) {
      return cindex;
    }
    final column = raw['column'];
    if (column is int) {
      return column;
    }
    if (column is List && column.isNotEmpty) {
      final first = column.first;
      if (first is int) {
        return first;
      }
      return int.tryParse('$first');
    }
    return null;
  }

  String? _filterCellOptionText(FortuneCell? cell) {
    if (cell == null) {
      return null;
    }
    if (cell.cellType?.type == 'd') {
      final value = cell.hasRawValue ? cell.rawValue : cell.value;
      if (value != null && !isRealNull(value)) {
        return update('YYYY-MM-DD', value);
      }
    }
    return cell.renderedText;
  }

  String _filterCellColorHex(FortuneCell? cell, String type) {
    if (type == 'cell') {
      return _filterColorHex(cell?.background ?? const Color(0xffffffff));
    }
    return _filterColorHex(cell?.foreground ?? const Color(0xff000000));
  }

  String? _filterCellForegroundHex(FortuneCell? cell) {
    if (cell == null) {
      return null;
    }
    if (!cell.hasRawForeground && cell.foreground == const Color(0xff000000)) {
      return null;
    }
    return _filterColorHex(cell.foreground);
  }

  String _filterColorHex(Color color) {
    final rgb = color.toARGB32() & 0x00ffffff;
    return '#${rgb.toRadixString(16).padLeft(6, '0')}';
  }

  (String, String)? _filterColorFilterFromCaljs(Object? raw) {
    if (raw is! Map) {
      return null;
    }
    final type = '${raw['type'] ?? ''}'.trim();
    if (type != 'cell' && type != 'text') {
      return null;
    }
    final color = '${raw['color'] ?? ''}'.trim().toLowerCase();
    if (!color.startsWith('#')) {
      return null;
    }
    return (type, color);
  }

  (int, int) _filterRowRangeFromConfig(FortuneSheet sheet, Map raw) {
    final rowCount = math.max(1, sheet.rowCount ?? workbook.settings.row);
    final row = raw['row'];
    if (row is List && row.length >= 2) {
      final start = _intValue(row[0]);
      final end = _intValue(row[1]);
      if (start != null && end != null) {
        return (
          math.min(start, end).clamp(0, rowCount - 1).toInt() + 1,
          math.max(start, end).clamp(0, rowCount - 1).toInt(),
        );
      }
    }
    final str = _intValue(raw['str']);
    final edr = _intValue(raw['edr']);
    if (str != null && edr != null) {
      return (
        math.min(str, edr).clamp(0, rowCount - 1).toInt() + 1,
        math.max(str, edr).clamp(0, rowCount - 1).toInt(),
      );
    }
    return (1, math.max(0, rowCount - 1));
  }

  (int, int) _filterDataRowRangeFromSelect(FortuneSheet sheet) {
    final range = _filterSelectRange(sheet);
    if (range == null) {
      final rowCount = math.max(1, sheet.rowCount ?? workbook.settings.row);
      return (1, math.max(0, rowCount - 1));
    }
    return (range.rowStart + 1, range.rowEnd);
  }

  void _drawImages(Canvas canvas, Size size, FortuneSettings settings) {
    final sheet = workbook.activeSheet;
    if (sheet.images.isEmpty) {
      return;
    }
    final clip = Rect.fromLTWH(
      _sheetDataLeft(settings),
      _sheetDataTop(settings),
      math.max(0, size.width - _sheetDataLeft(settings)),
      math.max(0, size.height - _sheetDataTop(settings)),
    );
    canvas.save();
    canvas.clipRect(clip);
    final zoomRatio = sheet.zoomRatio <= 0 ? 1.0 : sheet.zoomRatio;
    for (final image in sheet.images) {
      final rect = Rect.fromLTWH(
        _sheetDataLeft(settings) + image.left * zoomRatio - scrollOffset.dx,
        _sheetDataTop(settings) + image.top * zoomRatio - scrollOffset.dy,
        image.width * zoomRatio,
        image.height * zoomRatio,
      );
      if (!rect.overlaps(clip)) {
        continue;
      }
      final decoded = decodedImages[image.src];
      if (decoded == null) {
        _drawImagePlaceholder(canvas, rect, image);
      } else {
        _drawImageBitmap(
          canvas,
          rect,
          decoded,
          rotationDegrees: _imageRotationDegrees(image.extraFields['rotation']),
        );
      }
      _drawBarcodeObjectIdLabel(canvas, rect, image);
      if (image.id == activeImageId) {
        _drawActiveImageSelection(canvas, rect, clip);
      }
    }
    canvas.restore();
  }

  void _drawRawShapeOverlays(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
  ) {
    final overlays = fortuneRawShapeOverlays(workbook.activeSheet);
    if (overlays.isEmpty) {
      return;
    }
    final clip = Rect.fromLTWH(
      _sheetDataLeft(settings),
      _sheetDataTop(settings),
      math.max(0, size.width - _sheetDataLeft(settings)),
      math.max(0, size.height - _sheetDataTop(settings)),
    );
    canvas.save();
    canvas.clipRect(clip);
    final sheet = workbook.activeSheet;
    for (final overlay in overlays) {
      final rect = fortuneRawShapeOverlayScreenRect(
        overlay,
        settings,
        scrollOffset,
        sheet.zoomRatio,
      );
      _drawRawShapeOverlay(canvas, rect, overlay, clip);
    }
    canvas.restore();
  }

  void _drawRawShapeOverlay(
    Canvas canvas,
    Rect rect,
    FortuneRawShapeOverlay overlay,
    Rect clip,
  ) {
    fortuneDrawRawShapeOverlay(
      canvas,
      rect,
      overlay,
      clip,
      decodedImages: decodedImages,
      hoverPosition: rawChartHoverPosition,
      clickPosition: rawChartClickPosition,
      hoverOverlayKey: rawChartHoverOverlayKey,
      clickOverlayKey: rawChartClickOverlayKey,
    );
  }

  void _drawActiveImageSelection(Canvas canvas, Rect rect, Rect clip) {
    if (!rect.overlaps(clip)) {
      return;
    }
    const activeBlue = Color(0xff0188fb);
    const borderWidth = 2.0;
    const handleOuterSize = 10.0;
    const handleRadius = handleOuterSize / 2;
    const handleCenterOutset = borderWidth / 2;

    final borderPaint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = borderWidth
      ..color = activeBlue;
    canvas.drawRect(rect.inflate(borderWidth / 2), borderPaint);

    final handlePaint = Paint()..color = const Color(0xffffffff);
    final handleBorder = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = borderWidth
      ..color = activeBlue;

    final outsideLeft = rect.left - handleCenterOutset;
    final outsideTop = rect.top - handleCenterOutset;
    final outsideRight = rect.right + handleCenterOutset;
    final outsideBottom = rect.bottom + handleCenterOutset;
    final middleX = rect.center.dx;
    final middleY = rect.center.dy;
    final topMiddle = Offset(middleX, outsideTop);
    final rotateCenter = Offset(middleX, rect.top - 32.0);

    canvas.drawLine(topMiddle, rotateCenter, borderPaint);

    final centers = <Offset>[
      Offset(outsideLeft, outsideTop),
      topMiddle,
      Offset(outsideRight, outsideTop),
      Offset(outsideLeft, middleY),
      Offset(outsideRight, middleY),
      Offset(outsideLeft, outsideBottom),
      Offset(middleX, outsideBottom),
      Offset(outsideRight, outsideBottom),
      rotateCenter,
    ];
    for (final center in centers) {
      canvas.drawCircle(center, handleRadius, handlePaint);
      canvas.drawCircle(center, handleRadius - borderWidth / 2, handleBorder);
    }
  }

  void _drawImageBitmap(
    Canvas canvas,
    Rect rect,
    ui.Image image, {
    double rotationDegrees = 0,
  }) {
    final normalizedRotation = rotationDegrees % 360;
    if (normalizedRotation != 0) {
      canvas.save();
      canvas.translate(rect.center.dx, rect.center.dy);
      canvas.rotate(normalizedRotation * math.pi / 180);
      canvas.translate(-rect.center.dx, -rect.center.dy);
    }
    canvas.drawImageRect(
      image,
      Rect.fromLTWH(0, 0, image.width.toDouble(), image.height.toDouble()),
      rect,
      Paint()..filterQuality = FilterQuality.medium,
    );
    if (normalizedRotation != 0) {
      canvas.restore();
    }
  }

  void _drawBarcodeObjectIdLabel(Canvas canvas, Rect rect, FortuneImage image) {
    final metrics = fortuneBarcodeObjectIdLabelMetrics(
      rect,
      image,
      textDirection: textDirection,
    );
    if (metrics == null) {
      return;
    }
    final objectId = image.extraFields[fortuneBarcodeObjectIdExtraKey]
        .toString()
        .trim();
    final textPainter = TextPainter(
      text: TextSpan(
        text: objectId,
        style: TextStyle(
          color: const Color(0xff000000),
          fontSize: metrics.fontSize,
          height: 1,
          fontWeight: FontWeight.w600,
        ),
      ),
      maxLines: 1,
      ellipsis: '...',
      textDirection: textDirection,
    )..layout(maxWidth: metrics.textMaxWidth);
    final box = metrics.boxRect;
    final rotation = _imageRotationDegrees(image.extraFields['rotation']) % 360;
    if (rotation != 0) {
      canvas.save();
      canvas.translate(rect.center.dx, rect.center.dy);
      canvas.rotate(rotation * math.pi / 180);
      canvas.translate(-rect.center.dx, -rect.center.dy);
    }
    canvas.drawRect(box, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(
      box,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = metrics.strokeWidth
        ..color = const Color(0xff000000),
    );
    textPainter.paint(
      canvas,
      Offset(
        box.left + (box.width - textPainter.width) / 2,
        box.top + (box.height - textPainter.height) / 2,
      ),
    );
    if (rotation != 0) {
      canvas.restore();
    }
  }

  double _imageRotationDegrees(Object? value) {
    if (value is num) {
      return value.toDouble();
    }
    if (value is String) {
      return double.tryParse(value.trim()) ?? 0;
    }
    return 0;
  }

  void _drawImagePlaceholder(Canvas canvas, Rect rect, FortuneImage image) {
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(rect, Paint()..color = const Color(0xffe8f0fe));
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0xff0188fb),
    );
    final iconRect = Rect.fromCenter(
      center: rect.center,
      width: math.max(0, math.min(32, rect.width - 8)),
      height: math.max(0, math.min(24, rect.height - 8)),
    );
    if (iconRect.width > 8 && iconRect.height > 8) {
      final paint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1.4
        ..color = const Color(0xff5f6368);
      canvas.drawRect(iconRect, paint);
      final mountain = Path()
        ..moveTo(iconRect.left + 4, iconRect.bottom - 4)
        ..lineTo(iconRect.left + iconRect.width * 0.42, iconRect.center.dy)
        ..lineTo(iconRect.left + iconRect.width * 0.58, iconRect.bottom - 7)
        ..lineTo(iconRect.right - 4, iconRect.bottom - 4);
      canvas.drawPath(mountain, paint);
      canvas.drawCircle(
        Offset(iconRect.right - 7, iconRect.top + 6),
        2,
        Paint()..color = const Color(0xff5f6368),
      );
    }
    if (image.src.isNotEmpty && rect.width > 42 && rect.height > 28) {
      _drawText(
        canvas,
        'image',
        Rect.fromLTWH(rect.left + 4, rect.bottom - 20, rect.width - 8, 16),
        fontSize: 10,
        color: const Color(0xff5f6368),
        align: TextAlign.center,
      );
    }
  }

  void _drawVisibleComments(
    Canvas canvas,
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final comments = _visibleCommentBoxes(size, settings, metrics);
    if (comments.isEmpty) {
      return;
    }
    final clip = Rect.fromLTWH(
      _sheetDataLeft(settings),
      _sheetDataTop(settings),
      math.max(0, size.width - _sheetDataLeft(settings)),
      math.max(0, size.height - _sheetDataTop(settings)),
    );
    canvas.save();
    canvas.clipRect(clip);
    for (final comment in comments) {
      _drawCommentBox(canvas, comment.rect, comment.target, comment.value);
    }
    canvas.restore();
  }

  List<({Rect rect, Offset target, String value})> _visibleCommentBoxes(
    Size size,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheet = workbook.activeSheet;
    final comments = sheet.cells.entries.where((entry) {
      if (entry.key == editingCommentCoord) {
        return false;
      }
      final comment = entry.value.comment;
      return (comment?.isShow ?? false) || entry.key == hoveredCommentCoord;
    }).toList();
    if (comments.isEmpty) {
      return const <({Rect rect, Offset target, String value})>[];
    }
    final mergeLookup = _buildMergeLookup(sheet, settings);
    final clip = Rect.fromLTWH(
      settings.rowHeaderWidth,
      settings.columnHeaderHeight,
      math.max(0, size.width - settings.rowHeaderWidth),
      math.max(0, size.height - settings.columnHeaderHeight),
    );
    final boxes = <({Rect rect, Offset target, String value})>[];
    for (final entry in comments) {
      final coord = entry.key;
      if (mergeLookup[coord] != null) {
        continue;
      }
      final cell = entry.value;
      final comment = cell.comment;
      if (comment == null) {
        continue;
      }
      final cellRect = _mergedCellRect(
        settings: settings,
        metrics: metrics,
        anchor: coord,
        merge: cell.merge,
      );
      if (cellRect == null) {
        continue;
      }
      final target = Offset(cellRect.right, cellRect.top);
      final boxLeft = comment.left == null
          ? target.dx + 18 * sheet.zoomRatio
          : _sheetDataLeft(settings) +
                comment.left! * sheet.zoomRatio -
                scrollOffset.dx;
      final boxTop = comment.top == null
          ? math.max(2.0, target.dy - 18 * sheet.zoomRatio)
          : _sheetDataTop(settings) +
                comment.top! * sheet.zoomRatio -
                scrollOffset.dy;
      final boxRect = Rect.fromLTWH(
        boxLeft,
        boxTop,
        (comment.width ?? 144) * sheet.zoomRatio,
        (comment.height ?? 84) * sheet.zoomRatio,
      );
      if (!boxRect.overlaps(clip) &&
          !Rect.fromPoints(target, boxRect.topLeft).overlaps(clip)) {
        continue;
      }
      boxes.add((rect: boxRect, target: target, value: comment.value));
    }
    return boxes;
  }

  void _drawCommentBox(Canvas canvas, Rect rect, Offset target, String value) {
    final paint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1
      ..color = const Color(0xff000000);
    final anchor = Offset(rect.left, rect.top + 12);
    canvas.drawLine(anchor, target, paint);
    final angle = math.atan2(anchor.dy - target.dy, anchor.dx - target.dx);
    const headLength = 6.0;
    const theta = math.pi / 6;
    final headA = Offset(
      target.dx + headLength * math.cos(angle + theta),
      target.dy + headLength * math.sin(angle + theta),
    );
    final headB = Offset(
      target.dx + headLength * math.cos(angle - theta),
      target.dy + headLength * math.sin(angle - theta),
    );
    final arrow = Path()
      ..moveTo(target.dx, target.dy)
      ..lineTo(headA.dx, headA.dy)
      ..lineTo(headB.dx, headB.dy)
      ..close();
    canvas.drawPath(arrow, Paint()..color = const Color(0xff000000));
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffd9));
    canvas.drawRect(rect, paint);
    _drawText(
      canvas,
      value,
      rect.deflate(6),
      fontSize: 12,
      color: const Color(0xff000000),
    );
  }

  void _drawBorderLine(
    Canvas canvas,
    FortuneBorderSide side,
    Offset start,
    Offset end, {
    required bool horizontal,
    Rect? clipBounds,
  }) {
    final strokeWidth = _borderWidthForSide(side);
    final paint = Paint()
      ..color = side.color
      ..strokeWidth = strokeWidth
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.butt
      ..isAntiAlias = false;
    final dash = _borderDash(side.style);
    var adjustedStart = horizontal
        ? Offset(start.dx, start.dy - 0.5)
        : Offset(start.dx - 0.5, start.dy);
    var adjustedEnd = horizontal
        ? Offset(end.dx - 0.5, end.dy - 0.5)
        : Offset(end.dx - 0.5, end.dy);
    if (clipBounds != null) {
      canvas.save();
      canvas.clipRect(
        _borderSegmentClip(clipBounds, strokeWidth, start, end),
        doAntiAlias: false,
      );
    }
    if (dash == null) {
      canvas.drawLine(adjustedStart, adjustedEnd, paint);
      if (clipBounds != null) {
        canvas.restore();
      }
      return;
    }
    _drawDashedLine(canvas, adjustedStart, adjustedEnd, paint, dash);
    if (clipBounds != null) {
      canvas.restore();
    }
  }

  double _borderWidth(int style) {
    return fortuneToolbarBorderStrokeWidth(
      style,
      toolbarBorderStyleStrokeWidths,
    );
  }

  double _borderWidthForSide(FortuneBorderSide side) {
    return side.strokeWidth ?? _borderWidth(side.style);
  }

  List<double>? _borderDash(int style) {
    final pattern = fortuneToolbarBorderStyleDashPatterns[style];
    if (pattern == null || pattern.length < 2 || pattern[1] == 0) {
      return null;
    }
    return pattern;
  }

  void _drawDashedLine(
    Canvas canvas,
    Offset start,
    Offset end,
    Paint paint,
    List<double> dash,
  ) {
    final delta = end - start;
    final distance = delta.distance;
    if (distance == 0) {
      return;
    }
    final direction = delta / distance;
    var drawn = 0.0;
    var dashIndex = 0;
    while (drawn < distance) {
      final length = dash[dashIndex % dash.length];
      final next = math.min(distance, drawn + length);
      if (dashIndex.isEven) {
        canvas.drawLine(
          start + direction * drawn,
          start + direction * next,
          paint,
        );
      }
      drawn = next;
      dashIndex += 1;
    }
  }

  void _line(Canvas canvas, Offset a, Offset b, Color color) {
    canvas.drawLine(
      a,
      b,
      Paint()
        ..color = color
        ..strokeWidth = 1,
    );
  }

  String _columnName(int index) {
    var n = index + 1;
    final chars = <String>[];
    while (n > 0) {
      final rem = (n - 1) % 26;
      chars.add(String.fromCharCode(65 + rem));
      n = (n - rem - 1) ~/ 26;
    }
    return chars.reversed.join();
  }

  FortuneRange? _customSortRange() {
    final raw = workbook.activeSheet.selectionSave;
    if (raw is! List || raw.isEmpty) {
      return null;
    }
    final first = raw.first;
    if (first is! Map) {
      return null;
    }
    final row = first['row'];
    final column = first['column'];
    if (row is! List ||
        row.length < 2 ||
        column is! List ||
        column.length < 2) {
      return null;
    }
    final rowStart = _intValue(row[0]);
    final rowEnd = _intValue(row[1]);
    final columnStart = _intValue(column[0]);
    final columnEnd = _intValue(column[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null) {
      return null;
    }
    return FortuneRange(
      rowStart: math.min(rowStart, rowEnd),
      rowEnd: math.max(rowStart, rowEnd),
      columnStart: math.min(columnStart, columnEnd),
      columnEnd: math.max(columnStart, columnEnd),
    );
  }

  String _customSortRangeTitle() {
    final range = _customSortRange();
    if (range == null) {
      return locale.sortRangeTitle;
    }
    return '${locale.sortRangeTitle} '
        '${_columnName(range.columnStart)}${range.rowStart + 1}'
        ' ${locale.sortRangeTitleTo} '
        '${_columnName(range.columnEnd)}${range.rowEnd + 1}';
  }

  List<String> _customSortColumnLabels() {
    final range = _customSortRange();
    if (range == null) {
      return const ['A'];
    }
    final labels = <String>[];
    final sheet = workbook.activeSheet;
    for (
      var column = range.columnStart;
      column <= range.columnEnd;
      column += 1
    ) {
      if (customSortHasHeader) {
        final cell = sheet.cells[FortuneCellCoord(range.rowStart, column)];
        final label = (cell?.displayValue ?? cell?.value ?? '').trim();
        labels.add(
          label.isEmpty
              ? '${locale.sortColumnOperation} ${_columnName(column)}'
              : label,
        );
      } else {
        labels.add(_columnName(column));
      }
    }
    return labels;
  }

  @override
  bool shouldRepaint(covariant FortuneSheetPainter oldDelegate) {
    return oldDelegate.workbook != workbook ||
