  @override
  SemanticsBuilderCallback get semanticsBuilder {
    return (Size size) => <CustomPainterSemantics>[
      ..._keyboardShortcutSemantics(size),
      ..._sheetOverlayAlertSemantics(size),
      ..._okDialogSemantics(size),
      ..._dialogActionButtonSemantics(size),
      ..._toolbarSemantics(size),
      ..._toolbarMorePopupSemantics(size),
      ..._toolbarPopupRowSemantics(size),
      ..._toolbarColorPopupSemantics(size),
      ..._toolbarConditionFormatPopupSemantics(size),
      ..._toolbarBorderPopupSemantics(size),
      ..._contextMenuSemantics(),
      ..._sheetTabMenuSemantics(),
      ..._sheetTabColorMenuSemantics(),
      ..._sheetCornerSemantics(size),
      ..._filterDropdownSemantics(size),
      ..._columnHeaderMenuButtonSemantics(),
      ..._filterMarkerSemantics(),
      ..._dataVerificationMarkerSemantics(size),
      ..._dataVerificationDropdownSemantics(size),
      ..._commentBoxSemantics(size),
      ..._formulaBarSemantics(size),
      ..._hyperlinkCardSemantics(size),
      ..._imageSemantics(size),
      ..._presenceSemantics(size),
      ..._selectionInfoSemantics(size),
      ..._sheetTabSemantics(size),
      ..._sheetListSemantics(size),
      ..._bottomAddRowsSemantics(size),
      ..._zoomControlSemantics(size),
    ];
  }

  List<CustomPainterSemantics> _sheetOverlayAlertSemantics(Size size) {
    if (size.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final selectionText = _screenReaderSelectionText();
    final cellValue = _focusedCellRenderedText();
    final selectionAnnouncement = selectionText.isEmpty
        ? 'A1. ${locale.sheetSrIntro}'
        : [selectionText, cellValue].where((text) => text.isNotEmpty).join(' ');
    final focusAnnouncement = sheetFocused
        ? [
            selectionText,
            if (cellValue.isNotEmpty) '$cellValue.',
            locale.sheetIsFocused,
          ].where((text) => text.isNotEmpty).join(' ')
        : '${locale.toolbar}. ${locale.sheetNotFocused}';
    return <CustomPainterSemantics>[
      CustomPainterSemantics(
        rect: const Rect.fromLTWH(1, 0, 1, 1),
        properties: SemanticsProperties(
          label: selectionAnnouncement,
          liveRegion: true,
          textDirection: textDirection,
        ),
      ),
      CustomPainterSemantics(
        rect: const Rect.fromLTWH(2, 0, 1, 1),
        properties: SemanticsProperties(
          label: focusAnnouncement,
          liveRegion: true,
          textDirection: textDirection,
        ),
      ),
    ];
  }

  String _screenReaderSelectionText() {
    return formulaBarNameBoxText.replaceAllMapped(
      RegExp(r'([A-Z]+)(\d+)'),
      (match) => '${match.group(1)}. ${match.group(2)}',
    );
  }

  String _focusedCellRenderedText() {
    final sheet = workbook.activeSheet;
    final coord = FortuneCellCoord(selection.row, selection.column);
    return sheet.cells[sheet.mergeAnchorFor(coord)]?.renderedText ?? '';
  }

  List<CustomPainterSemantics> _presenceSemantics(Size size) {
    if (size.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final settings = workbook.settings;
    final metrics = workbook.activeSheet.metrics(settings);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    return [
      for (final presence in _visiblePresenceRanges(size, settings, metrics))
        CustomPainterSemantics(
          rect: presence.pieces.first.rect.translate(0, sheetTop),
          properties: SemanticsProperties(
            label:
                'Presence ${presence.label} ${_columnName(presence.column)}${presence.row + 1}',
            textDirection: textDirection,
          ),
        ),
    ];
  }

  List<CustomPainterSemantics> _hyperlinkCardSemantics(Size size) {
    if (size.isEmpty || hyperlinkDialogOpen) {
      return const <CustomPainterSemantics>[];
    }
    final hyperlink = _selectedHyperlinkFields();
    if (hyperlink == null) {
      return const <CustomPainterSemantics>[];
    }
    final settings = workbook.settings;
    final sheet = workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final cellRect = _cellRectForCoord(coord, settings, metrics);
    if (cellRect == null) {
      return const <CustomPainterSemantics>[];
    }
    final allowEdit = settings.allowEdit;
    final showCopy = hyperlink.type == 'webpage';
    final rect = fortuneHyperlinkCardRect(
      size,
      cellRect,
      allowEdit: allowEdit,
      showCopy: showCopy,
    );
    CustomPainterSemantics button(Rect rect, String label) {
      return CustomPainterSemantics(
        rect: rect,
        properties: SemanticsProperties(
          label: label,
          button: true,
          textDirection: textDirection,
        ),
      );
    }

    final contentLabel = hyperlink.type == 'webpage'
        ? locale.openLink
        : locale.goToLink
              .replaceAll(r'${linkAddress}', hyperlink.address)
              .replaceAll('{linkAddress}', hyperlink.address);
    final semantics = <CustomPainterSemantics>[
      button(fortuneHyperlinkCardContentRect(rect), contentLabel),
    ];
    if (allowEdit) {
      if (showCopy) {
        semantics.add(
          button(fortuneHyperlinkCardCopyButtonRect(rect), locale.copyLink),
        );
      }
      semantics.add(
        button(
          fortuneHyperlinkCardEditButtonRect(rect, showCopy: showCopy),
          locale.editLink,
        ),
      );
      semantics.add(
        button(
          fortuneHyperlinkCardUnlinkButtonRect(rect, showCopy: showCopy),
          locale.unlink,
        ),
      );
    }
    return semantics;
  }

  List<CustomPainterSemantics> _keyboardShortcutSemantics(Size size) {
    if (size.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final shortcutLabels = <String>[
      locale.toggleSheetFocusShortcut,
      locale.selectRangeShortcut,
      locale.autoFillDownShortcut,
      locale.autoFillRightShortcut,
      locale.boldTextShortcut,
      locale.copyShortcut,
      locale.pasteShortcut,
      locale.undoShortcut,
      locale.redoShortcut,
      locale.deleteCellContentShortcut,
      locale.confirmCellEditShortcut,
      locale.moveRightShortcut,
      locale.moveLeftShortcut,
    ];
    return <CustomPainterSemantics>[
      CustomPainterSemantics(
        rect: const Rect.fromLTWH(0, 0, 1, 1),
        properties: SemanticsProperties(
          label: locale.shortcuts,
          value: shortcutLabels.join('\n'),
          textDirection: textDirection,
        ),
      ),
    ];
  }

  List<CustomPainterSemantics> _okDialogSemantics(Size size) {
    if (size.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final semantics = <CustomPainterSemantics>[];
    final locationMessage = locationMessageDialogText;
    if (locationMessage != null) {
      final rect = fortuneLocationMessageDialogRect(
        size,
        message: locationMessage,
      );
      semantics.addAll([
        CustomPainterSemantics(
          rect: fortuneLocationMessageCloseButtonRect(rect),
          properties: SemanticsProperties(
            label: locale.close,
            button: true,
            textDirection: textDirection,
          ),
        ),
        CustomPainterSemantics(
          rect: Rect.fromLTWH(
            rect.left + fortuneLocationMessageHorizontalPadding,
            rect.top + 52,
            rect.width - fortuneLocationMessageHorizontalPadding * 2,
            24,
          ),
          properties: SemanticsProperties(
            label: locationMessage,
            textDirection: textDirection,
          ),
        ),
        CustomPainterSemantics(
          rect: locationMessageDialogConfirm
              ? fortuneLocationMessageConfirmOkButtonRect(rect)
              : fortuneLocationMessageOkButtonRect(rect),
          properties: SemanticsProperties(
            label: locale.ok,
            button: true,
            textDirection: textDirection,
          ),
        ),
      ]);
      if (locationMessageDialogConfirm) {
        semantics.add(
          CustomPainterSemantics(
            rect: fortuneLocationMessageConfirmCancelButtonRect(rect),
            properties: SemanticsProperties(
              label: locale.cancel,
              button: true,
              textDirection: textDirection,
            ),
          ),
        );
      }
    }
    if (screenshotDialogOpen) {
      final rect = fortuneScreenshotDialogRect(size);
      semantics.addAll([
        CustomPainterSemantics(
          rect: fortuneScreenshotCloseButtonRect(rect),
          properties: SemanticsProperties(
            label: locale.close,
            button: true,
            textDirection: textDirection,
          ),
        ),
        CustomPainterSemantics(
          rect: Rect.fromLTWH(
            rect.left + 25,
            rect.top + 38,
            rect.width - 50,
            24,
          ),
          properties: SemanticsProperties(
            label: locale.screenshotTipSuccess,
            textDirection: textDirection,
          ),
        ),
        CustomPainterSemantics(
          rect: fortuneScreenshotOkButtonRect(rect),
          properties: SemanticsProperties(
            label: locale.ok,
            button: true,
            textDirection: textDirection,
          ),
        ),
      ]);
    }
    return semantics;
  }

  List<CustomPainterSemantics> _dialogActionButtonSemantics(Size size) {
    if (size.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final semantics = <CustomPainterSemantics>[];

    void addButton(Rect rect, String label, {bool? selected}) {
      if (rect.isEmpty) {
        return;
      }
      semantics.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            button: true,
            selected: selected,
            textDirection: textDirection,
          ),
        ),
      );
    }

    void addCheckbox(Rect rect, String label, bool checked) {
      if (rect.isEmpty) {
        return;
      }
      semantics.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            checked: checked,
            textDirection: textDirection,
          ),
        ),
      );
    }

    void addTextField(Rect rect, String label, String value) {
      if (rect.isEmpty) {
        return;
      }
      semantics.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            value: value,
            textField: true,
            textDirection: textDirection,
          ),
        ),
      );
    }

    void addListOption(
      Rect rect,
      String label, {
      String? value,
      bool selected = false,
    }) {
      if (rect.isEmpty) {
        return;
      }
      semantics.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            value: value,
            button: true,
            selected: selected,
            textDirection: textDirection,
          ),
        ),
      );
    }

    if (formatSearchDialogOpen) {
      final rect = fortuneFormatSearchDialogRect(size);
      addButton(fortuneFormatSearchCloseButtonRect(rect), locale.close);
      addButton(fortuneFormatSearchConfirmButtonRect(rect), locale.ok);
      addButton(fortuneFormatSearchCancelButtonRect(rect), locale.cancel);
      if (formatSearchType != fortuneToolbarFormatMoreDateTimeCommand) {
        addTextField(
          fortuneFormatSearchDecimalInputRect(rect),
          locale.decimalPlaces,
          formatSearchDecimalPlacesText,
        );
      }
      final options = fortuneFormatSearchOptionsFor(formatSearchType);
      final firstVisibleIndex = fortuneFormatSearchFirstVisibleIndex(
        formatSearchScrollOffset,
        options.length,
      );
      final visibleRows = math.min(
        options.length - firstVisibleIndex,
        fortuneFormatSearchVisibleRowCount(),
      );
      for (
        var visibleIndex = 0;
        visibleIndex < visibleRows;
        visibleIndex += 1
      ) {
        final optionIndex = firstVisibleIndex + visibleIndex;
        final option = options[optionIndex];
        addListOption(
          fortuneFormatSearchListRowRect(rect, visibleIndex),
          option.name,
          value: option.value,
          selected: optionIndex == formatSearchSelectedIndex,
        );
      }
    }

    if (formulaSearchDialogOpen) {
      final rect = fortuneFormulaSearchDialogRect(size);
      addButton(fortuneFormulaSearchCloseButtonRect(rect), locale.close);
      addButton(fortuneFormulaSearchOkButtonRect(rect), locale.ok);
      addButton(fortuneFormulaSearchCancelButtonRect(rect), locale.cancel);
      addTextField(
        fortuneFormulaSearchInputRect(rect),
        locale.findFunctionTitle,
        formulaSearchText,
      );
      addListOption(
        fortuneFormulaSearchCategorySelectRect(rect),
        locale.functionCategoryLabel,
        value: fortuneFormulaSearchCategoryLabel(formulaSearchCategoryType),
      );
      if (formulaSearchCategoryMenuOpen) {
        final menuRect = fortuneFormulaSearchCategoryMenuRect(rect);
        for (
          var index = 0;
          index < fortuneFormulaSearchCategories.length;
          index += 1
        ) {
          final category = fortuneFormulaSearchCategories[index];
          addListOption(
            Rect.fromLTWH(
              menuRect.left,
              menuRect.top + index * fortuneFormulaSearchCategoryOptionHeight,
              menuRect.width,
              fortuneFormulaSearchCategoryOptionHeight,
            ),
            category.label,
            selected: category.type == formulaSearchCategoryType,
          );
        }
      }
      final filteredFunctions = fortuneFormulaSearchFilteredFunctions(
        formulaSearchText,
        formulaSearchCategoryType,
      );
      final firstVisibleIndex = fortuneFormulaSearchFirstVisibleIndex(
        formulaSearchScrollOffset,
        filteredFunctions.length,
      );
      final visibleRows = math.min(
        filteredFunctions.length - firstVisibleIndex,
        fortuneFormulaSearchVisibleRowCount(),
      );
      for (
        var visibleIndex = 0;
        visibleIndex < visibleRows;
        visibleIndex += 1
      ) {
        final functionIndex = firstVisibleIndex + visibleIndex;
        final function = filteredFunctions[functionIndex];
        addListOption(
          fortuneFormulaSearchListRowRect(rect, visibleIndex),
          function.name,
          value: function.description,
          selected: functionIndex == formulaSearchSelectedIndex,
        );
      }
    }

    if (customSortDialogOpen) {
      final labels = _customSortColumnLabels();
      final visibleCount = labels.length
          .clamp(1, fortuneCustomSortDialogMaxVisibleColumns)
          .toInt();
      final rect = fortuneCustomSortDialogRect(size, visibleCount);
      addButton(fortuneCustomSortCloseButtonRect(rect), locale.close);
      addButton(fortuneCustomSortConfirmButtonRect(rect), locale.sortConfirm);
      addCheckbox(
        Rect.fromLTWH(rect.left + 18, rect.top + 50, 180, 24),
        locale.hasTitle,
        customSortHasHeader,
      );
      for (var index = 0; index < visibleCount; index += 1) {
        addListOption(
          fortuneCustomSortColumnRowRect(rect, index),
          labels[index],
          selected: index == customSortColumnOffset,
        );
      }
      addCheckbox(
        Rect.fromLTWH(
          rect.right - fortuneCustomSortRadioLeftInset,
          rect.top + fortuneCustomSortDescendingHitTop - 28,
