      addLocationValues(fortuneToolbarLocationFormulaCommand, {
        fortuneToolbarLocationDateCommand: locationFormulaDate,
        fortuneToolbarLocationNumberCommand: locationFormulaNumber,
        fortuneToolbarLocationStringCommand: locationFormulaString,
        fortuneToolbarLocationBoolCommand: locationFormulaLogical,
