        );
        addListOption(
          fortuneHyperlinkDialogTypeSelectRect(rect),
          locale.linkType,
          value: _hyperlinkDialogTypeLabel(hyperlinkDialogLinkType),
        );
        if (hyperlinkDialogLinkType == 'sheet') {
          addListOption(
            fortuneHyperlinkDialogAddressInputRect(rect),
            _hyperlinkDialogAddressLabel(hyperlinkDialogLinkType),
            value: hyperlinkDialogAddressText,
          );
        } else {
          addTextField(
            fortuneHyperlinkDialogAddressInputRect(rect),
            _hyperlinkDialogAddressLabel(hyperlinkDialogLinkType),
