      addButton(fortuneConditionRuleConfirmButtonRect(rect), locale.ok);
      addButton(fortuneConditionRuleCancelButtonRect(rect), locale.cancel);
      if (conditionRuleType == fortuneConditionRuleDuplicateType) {
        addListOption(
          _conditionRuleSelectRect(rect),
          _conditionRuleDescription(),
          value: _conditionRuleDuplicateLabel(conditionRuleDuplicateValue),
        );
        if (conditionRuleDuplicateMenuOpen) {
          final select = _conditionRuleSelectRect(rect);
          for (
            var index = 0;
            index < fortuneConditionRuleDuplicateValues.length;
            index += 1
          ) {
            final value = fortuneConditionRuleDuplicateValues[index];
            addListOption(
              Rect.fromLTWH(
                select.left,
                select.bottom + index * fortuneConditionRuleSelectOptionHeight,
                select.width,
                fortuneConditionRuleSelectOptionHeight,
              ),
              _conditionRuleDuplicateLabel(value),
              selected: conditionRuleDuplicateValue == value,
            );
          }
        }
      }
      final setTop = _conditionRuleSetAsTop(rect);
      final setBoxTop = setTop + fortuneConditionRuleSetBoxTopOffset;
      void addFormatOptionSemantics(
        int rowIndex,
        String label,
        List<String> choices,
        String value,
        bool checked,
      ) {
        final row = Rect.fromLTWH(
          rect.left + fortuneConditionRuleContentPaddingHorizontal,
          setBoxTop + rowIndex * fortuneConditionRuleSetRowHeight,
          rect.width - fortuneConditionRuleContentPaddingHorizontal * 2,
          fortuneConditionRuleSetRowHeight,
        );
