      );
      addButton(fortuneSearchBottomCloseButtonRect(rect), locale.close);
      if (searchResults.isNotEmpty) {
        final resultsRect = fortuneSearchResultsRect(rect);
        final visible = math.min(searchResults.length, 6);
        for (var index = 0; index < visible; index += 1) {
          final result = searchResults[index];
          addListOption(
            Rect.fromLTWH(
              resultsRect.left,
              resultsRect.top +
                  fortuneSearchResultRowHeight +
                  index * fortuneSearchResultRowHeight,
              resultsRect.width,
              fortuneSearchResultRowHeight,
            ),
            '${result.sheetName} ${result.cellPosition}',
            value: result.value,
            selected: index == searchSelectedResultIndex,
          );
        }
      }
      addCheckbox(
        fortuneSearchCheckboxRect(rect, 0),
        locale.regexTextbox,
        searchRegex,
      );
      addCheckbox(
        fortuneSearchCheckboxRect(rect, 1),
        locale.wholeTextbox,
        searchWholeWord,
      );
      addCheckbox(
        fortuneSearchCheckboxRect(rect, 2),
        locale.distinguishTextbox,
        searchCaseSensitive,
      );
      addTextField(
        fortuneSearchInputRect(rect),
        locale.findTextbox,
        searchText,
      );
      if (searchReplaceMode) {
        addTextField(
          fortuneSearchReplaceInputRect(rect),
          locale.replaceTextbox,
          replaceText,
        );
      }
    }

    return semantics;
  }

  List<CustomPainterSemantics> _toolbarSemantics(Size size) {
    final settings = workbook.settings;
    if (!settings.showToolbar) {
      return const <CustomPainterSemantics>[];
    }
    final entries = fortuneVisibleToolbarItemRects(
      size.width,
      items: fortuneToolbarItemsWithCustom(
        settings.toolbarItems,
        settings.customToolbarItems,
      ),
    );
    final semantics = <CustomPainterSemantics>[];
    semantics.add(
      CustomPainterSemantics(
        rect: Rect.fromLTWH(0, 0, size.width, settings.effectiveToolbarHeight),
        properties: SemanticsProperties(
          label: locale.toolbar,
          textDirection: textDirection,
        ),
      ),
    );
    for (final entry in entries) {
      final tooltip = _toolbarTooltipLabel(entry.key);
      if (tooltip == null || tooltip.isEmpty) {
        continue;
      }
      final rect = entry.value;
      if (fortuneToolbarItemUsesCombo(entry.key, size.width)) {
        final arrowRect = fortuneToolbarComboArrowRect(rect);
        semantics.add(
          CustomPainterSemantics(
            rect: Rect.fromLTRB(
              rect.left,
              rect.top,
              arrowRect.left,
              rect.bottom,
            ),
            properties: SemanticsProperties(
              label: '$tooltip: ${_toolbarComboLabel(entry.key)}',
              button: true,
              textDirection: textDirection,
            ),
          ),
        );
        semantics.add(
          CustomPainterSemantics(
            rect: arrowRect,
            properties: SemanticsProperties(
              label: '$tooltip: ${locale.dropdownShortcutLabel}',
              button: true,
              textDirection: textDirection,
            ),
          ),
        );
      } else {
        semantics.add(
          CustomPainterSemantics(
            rect: rect,
            properties: SemanticsProperties(
              label: tooltip,
              button: true,
              textDirection: textDirection,
            ),
          ),
        );
      }
    }
    return semantics;
  }

  List<CustomPainterSemantics> _toolbarMorePopupSemantics(Size size) {
    if (toolbarPopupKey != fortuneToolbarMorePopupKey) {
      return const <CustomPainterSemantics>[];
    }
    final itemRect = _toolbarItemRectFor(
      fortuneToolbarMorePopupKey,
      size.width,
    );
    final popupWidth = fortuneToolbarPopupWidthFor(fortuneToolbarMorePopupKey);
    final left = fortuneToolbarPopupLeftFor(
      key: fortuneToolbarMorePopupKey,
      itemRect: itemRect,
      viewportWidth: size.width,
      popupWidth: popupWidth,
    );
    final options = _toolbarPopupOptionsFor(
      fortuneToolbarMorePopupKey,
      size.width,
    );
    if (options.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final naturalHeight = fortuneToolbarPopupHeightFor(
      fortuneToolbarMorePopupKey,
      options,
    );
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final scrollOffset = toolbarPopupScrollOffset
        .clamp(0.0, math.max(0.0, naturalHeight - visibleHeight))
        .toDouble();
    final viewportRect = Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop,
      popupWidth,
      visibleHeight,
    );
    final contentViewportRect = fortuneToolbarPopupContentViewportRect(
      viewportRect,
      scrollOffset,
      math.max(0.0, naturalHeight - visibleHeight),
    );
    final nodes = <CustomPainterSemantics>[];
    var top =
        fortuneToolbarPopupTop +
        fortuneToolbarPopupContentTopPaddingFor(fortuneToolbarMorePopupKey) -
        scrollOffset;
    final rowHeight = fortuneToolbarPopupRowHeightFor(
      fortuneToolbarMorePopupKey,
    );
    for (final option in options) {
      final rowRect = Rect.fromLTWH(left, top, popupWidth, rowHeight);
      top += rowHeight;
      if (!rowRect.overlaps(contentViewportRect)) {
        continue;
      }
      final clippedRect = rowRect.intersect(contentViewportRect);
      final label = _toolbarTooltipLabel(option) ?? _toolbarPopupLabel(option);
      nodes.add(
        CustomPainterSemantics(
          rect: clippedRect,
          properties: SemanticsProperties(
            label: label,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }
    return nodes;
  }

  List<CustomPainterSemantics> _toolbarPopupRowSemantics(Size size) {
    final key = toolbarPopupKey;
    if (key == null ||
        key == fortuneToolbarMorePopupKey ||
        key == fortuneToolbarFontColorPopupKey ||
        key == fortuneToolbarBackgroundPopupKey ||
        key == fortuneToolbarConditionFormatPopupKey ||
        key == fortuneToolbarBorderPopupKey) {
      return const <CustomPainterSemantics>[];
    }
    final options = _toolbarPopupOptionsFor(key, size.width);
    if (options.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final itemRect = _toolbarItemRectFor(key, size.width);
    final popupWidth = fortuneToolbarPopupWidthFor(key);
    final left = fortuneToolbarPopupLeftFor(
      key: key,
      itemRect: itemRect,
      viewportWidth: size.width,
      popupWidth: popupWidth,
    );
    final naturalHeight = fortuneToolbarPopupHeightFor(key, options);
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final scrollOffset = toolbarPopupScrollOffset
        .clamp(0.0, math.max(0.0, naturalHeight - visibleHeight))
        .toDouble();
    final viewportRect = Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop,
      popupWidth,
      visibleHeight,
    );
    final contentViewportRect = fortuneToolbarPopupContentViewportRect(
      viewportRect,
      scrollOffset,
      math.max(0.0, naturalHeight - visibleHeight),
    );
    final nodes = <CustomPainterSemantics>[];

    void addButton(Rect rect, String label) {
      nodes.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }

    void addVisibleButton(Rect rect, String label) {
      if (!rect.overlaps(contentViewportRect)) {
        return;
      }
      addButton(rect.intersect(contentViewportRect), label);
    }

    var top =
        fortuneToolbarPopupTop +
        fortuneToolbarPopupContentTopPaddingFor(key) -
        scrollOffset;
    final rowHeight = fortuneToolbarPopupRowHeightFor(key);
    for (final option in options) {
      if (option == '|') {
        top += fortuneToolbarMenuDividerHeight;
        continue;
      }
      final label =
          locale.freezeMenuLabels[option] ??
          _toolbarTooltipLabel(option) ??
          _toolbarPopupLabel(option);
      addVisibleButton(Rect.fromLTWH(left, top, popupWidth, rowHeight), label);
      top += rowHeight;
    }

    if (key == fortuneToolbarFormatCommand && formatMoreSubmenuOpen) {
      final submenuRect = fortuneToolbarFormatMoreSubmenuRect(
        viewportRect,
        viewportWidth: size.width,
      );
      const submenuOptions = fortuneToolbarFormatMoreSubmenuCommands;
      for (var index = 0; index < submenuOptions.length; index += 1) {
        final option = submenuOptions[index];
        addButton(
          Rect.fromLTWH(
            submenuRect.left,
            submenuRect.top + index * fortuneToolbarFormatMoreSubmenuRowHeight,
            submenuRect.width,
            fortuneToolbarFormatMoreSubmenuRowHeight,
          ),
          _toolbarPopupLabel(option),
        );
      }
    }
    return nodes;
  }

  List<CustomPainterSemantics> _toolbarColorPopupSemantics(Size size) {
    final key = toolbarPopupKey;
    if (key != fortuneToolbarFontColorPopupKey &&
        key != fortuneToolbarBackgroundPopupKey) {
      return const <CustomPainterSemantics>[];
    }
    final itemRect = _toolbarItemRectFor(key!, size.width);
    final popupWidth = fortuneToolbarPopupWidthFor(key);
    final left = fortuneToolbarPopupLeftFor(
      key: key,
      itemRect: itemRect,
      viewportWidth: size.width,
      popupWidth: popupWidth,
    );
    final naturalHeight = fortuneToolbarPopupHeightFor(key, const <String>[]);
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final scrollOffset = toolbarPopupScrollOffset
        .clamp(0.0, math.max(0.0, naturalHeight - visibleHeight))
        .toDouble();
    final viewportRect = Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop,
      popupWidth,
      visibleHeight,
    );
    final contentViewportRect = fortuneToolbarPopupContentViewportRect(
      viewportRect,
      scrollOffset,
      math.max(0.0, naturalHeight - visibleHeight),
    );
    final contentRect = Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop - scrollOffset,
      popupWidth,
      naturalHeight,
    );
    final nodes = <CustomPainterSemantics>[];

    void addVisibleButton(Rect rect, String label) {
      if (!rect.overlaps(contentViewportRect)) {
        return;
      }
      nodes.add(
        CustomPainterSemantics(
          rect: rect.intersect(contentViewportRect),
          properties: SemanticsProperties(
            label: label,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }

    addVisibleButton(
      Rect.fromLTWH(
        contentRect.left,
        contentRect.top,
        contentRect.width,
        fortuneToolbarFontColorResetHeight,
      ),
      locale.customColorReset,
    );

    final customRect = Rect.fromLTWH(
      contentRect.left,
      contentRect.top + fortuneToolbarFontColorCustomTop,
      contentRect.width,
      fortuneToolbarFontColorCustomHeight,
    );
    addVisibleButton(
      Rect.fromLTWH(
        customRect.right -
            fortuneToolbarFontColorCustomOkRightInset -
            fortuneToolbarFontColorCustomOkWidth,
        customRect.top + fortuneToolbarFontColorCustomOkTop,
        fortuneToolbarFontColorCustomOkWidth,
        fortuneToolbarFontColorCustomOkHeight,
      ),
      locale.customColorConfirm,
    );

    final pickerRect = Rect.fromLTWH(
      contentRect.left,
      contentRect.top + fortuneToolbarFontColorPickerTop,
      contentRect.width,
      contentRect.height - fortuneToolbarFontColorPickerTop,
    );
    final step =
        fortuneToolbarColorPickerItemSize +
        fortuneToolbarColorPickerItemMargin * 2;
    for (var row = 0; row < fortuneToolbarColorPickerPalette.length; row += 1) {
      final colors = fortuneToolbarColorPickerPalette[row];
      for (var column = 0; column < colors.length; column += 1) {
        final color = colors[column];
        addVisibleButton(
          Rect.fromLTWH(
            pickerRect.left +
                fortuneToolbarColorPickerPadding +
                column * step +
                fortuneToolbarColorPickerItemMargin,
            pickerRect.top +
                fortuneToolbarColorPickerPadding +
                row * step +
                fortuneToolbarColorPickerItemMargin,
            fortuneToolbarColorPickerItemSize,
            fortuneToolbarColorPickerItemSize,
          ),
          color,
        );
      }
    }
    return nodes;
  }

  List<CustomPainterSemantics> _toolbarConditionFormatPopupSemantics(
    Size size,
  ) {
    if (toolbarPopupKey != fortuneToolbarConditionFormatPopupKey) {
      return const <CustomPainterSemantics>[];
    }
    final key = toolbarPopupKey!;
    final itemRect = _toolbarItemRectFor(key, size.width);
    final popupWidth = fortuneToolbarPopupWidthFor(key);
    final left = fortuneToolbarPopupLeftFor(
      key: key,
      itemRect: itemRect,
      viewportWidth: size.width,
      popupWidth: popupWidth,
    );
    final options = _toolbarPopupOptionsFor(key, size.width);
    if (options.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final naturalHeight = fortuneToolbarPopupHeightFor(key, options);
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final scrollOffset = toolbarPopupScrollOffset
        .clamp(0.0, math.max(0.0, naturalHeight - visibleHeight))
        .toDouble();
    final viewportRect = Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop,
      popupWidth,
      visibleHeight,
    );
    final contentViewportRect = fortuneToolbarPopupContentViewportRect(
      viewportRect,
      scrollOffset,
      math.max(0.0, naturalHeight - visibleHeight),
    );
    final nodes = <CustomPainterSemantics>[];

    void addButton(Rect rect, String label) {
      nodes.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }

    var top =
        fortuneToolbarPopupTop +
        fortuneToolbarPopupContentTopPaddingFor(key) -
        scrollOffset;
    final rowHeight = fortuneToolbarPopupRowHeightFor(key);
    for (final option in options) {
      if (option == '|') {
        top += fortuneToolbarMenuDividerHeight;
        continue;
      }
      final rowRect = Rect.fromLTWH(left, top, popupWidth, rowHeight);
      top += rowHeight;
      if (!rowRect.overlaps(contentViewportRect)) {
        continue;
      }
      addButton(
        rowRect.intersect(contentViewportRect),
        _toolbarPopupLabel(option),
      );
    }

    final submenuKey = conditionFormatSubmenuKey;
    if (submenuKey == null) {
      return nodes;
    }
    final items = switch (submenuKey) {
      fortuneConditionFormatHighlightSubmenuKey =>
        fortuneConditionFormatHighlightItems,
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionItems,
      fortuneConditionFormatDeleteSubmenuKey =>
        fortuneConditionFormatDeleteItems,
      _ => const <String>[],
    };
    if (items.isEmpty) {
      return nodes;
    }
    final submenuWidth = switch (submenuKey) {
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionSubmenuWidth,
      _ => fortuneConditionFormatSubmenuWidth,
    };
    final topLevelIndex = switch (submenuKey) {
      fortuneConditionFormatHighlightSubmenuKey =>
        fortuneConditionFormatHighlightTopLevelIndex,
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionTopLevelIndex,
      fortuneConditionFormatDeleteSubmenuKey =>
        fortuneConditionFormatDeleteTopLevelIndex,
      _ => 0,
    };
    final topLevelRect = viewportRect;
    final desiredLeft = topLevelRect.right;
    final submenuLeft = desiredLeft + submenuWidth > size.width
        ? math.max(
            fortuneToolbarPopupViewportMargin,
            topLevelRect.left +
                fortuneConditionFormatSubmenuOverflowLeftInset -
                submenuWidth,
          )
        : desiredLeft;
    final submenuTop =
        _toolbarPopupOptionTop(
          topLevelRect,
          key,
          fortuneConditionFormatTopLevelItems,
          topLevelIndex,
        ) -
        scrollOffset +
        fortuneConditionFormatSubmenuTopOffset;
    for (var index = 0; index < items.length; index += 1) {
      addButton(
        Rect.fromLTWH(
          submenuLeft,
          submenuTop + index * fortuneConditionFormatSubmenuRowHeight,
          submenuWidth,
          fortuneConditionFormatSubmenuRowHeight,
        ),
        _toolbarPopupLabel(items[index]),
      );
    }
    return nodes;
  }

  List<CustomPainterSemantics> _toolbarBorderPopupSemantics(Size size) {
    if (toolbarPopupKey != fortuneToolbarBorderPopupKey) {
      return const <CustomPainterSemantics>[];
    }
    final key = toolbarPopupKey!;
    final itemRect = _toolbarItemRectFor(key, size.width);
    final popupWidth = fortuneToolbarPopupWidthFor(key);
    final left = fortuneToolbarPopupLeftFor(
      key: key,
      itemRect: itemRect,
      viewportWidth: size.width,
      popupWidth: popupWidth,
    );
    final options = _toolbarPopupOptionsFor(key, size.width);
    if (options.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final naturalHeight = fortuneToolbarPopupHeightFor(key, options);
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final scrollOffset = toolbarPopupScrollOffset
        .clamp(0.0, math.max(0.0, naturalHeight - visibleHeight))
        .toDouble();
    final viewportRect = Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop,
      popupWidth,
      visibleHeight,
    );
    final contentViewportRect = fortuneToolbarPopupContentViewportRect(
      viewportRect,
      scrollOffset,
      math.max(0.0, naturalHeight - visibleHeight),
    );
    final nodes = <CustomPainterSemantics>[];

    void addButton(Rect rect, String label, {bool selected = false}) {
      nodes.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            button: true,
            selected: selected,
            textDirection: textDirection,
          ),
        ),
      );
    }

    void addVisibleButton(Rect rect, String label, {bool selected = false}) {
      if (!rect.overlaps(contentViewportRect)) {
        return;
      }
      addButton(rect.intersect(contentViewportRect), label, selected: selected);
    }

    var top =
        fortuneToolbarPopupTop +
        fortuneToolbarPopupContentTopPaddingFor(key) -
        scrollOffset;
    final rowHeight = fortuneToolbarPopupRowHeightFor(key);
    for (final option in options) {
      if (option == '|') {
        top += fortuneToolbarMenuDividerHeight;
        continue;
      }
      addVisibleButton(
        Rect.fromLTWH(left, top, popupWidth, rowHeight),
        _toolbarPopupLabel(option),
      );
      top += rowHeight;
    }

    final submenuKey = toolbarBorderSubmenuKey;
    if (submenuKey == null) {
      return nodes;
    }
    final submenuRect = _toolbarBorderSubmenuRect(
      size,
      viewportRect,
      submenuKey,
    );
    if (submenuKey == fortuneToolbarBorderColorSubmenuKey) {
      addButton(
        Rect.fromLTWH(
          submenuRect.left,
          submenuRect.top,
          submenuRect.width,
          fortuneToolbarFontColorResetHeight,
        ),
        locale.customColorReset,
      );
      final customRect = Rect.fromLTWH(
        submenuRect.left,
        submenuRect.top + fortuneToolbarFontColorCustomTop,
        submenuRect.width,
        fortuneToolbarFontColorCustomHeight,
      );
      addButton(
        Rect.fromLTWH(
          customRect.right -
              fortuneToolbarFontColorCustomOkRightInset -
              fortuneToolbarFontColorCustomOkWidth,
          customRect.top + fortuneToolbarFontColorCustomOkTop,
          fortuneToolbarFontColorCustomOkWidth,
          fortuneToolbarFontColorCustomOkHeight,
        ),
        locale.customColorConfirm,
      );
      final pickerRect = Rect.fromLTWH(
        submenuRect.left,
        submenuRect.top + fortuneToolbarFontColorPickerTop,
        submenuRect.width,
        submenuRect.height - fortuneToolbarFontColorPickerTop,
      );
      final step =
          fortuneToolbarColorPickerItemSize +
          fortuneToolbarColorPickerItemMargin * 2;
      for (
        var row = 0;
        row < fortuneToolbarColorPickerPalette.length;
        row += 1
      ) {
        final colors = fortuneToolbarColorPickerPalette[row];
        for (var column = 0; column < colors.length; column += 1) {
          final color = colors[column];
          addButton(
            Rect.fromLTWH(
              pickerRect.left +
                  fortuneToolbarColorPickerPadding +
                  column * step +
                  fortuneToolbarColorPickerItemMargin,
              pickerRect.top +
                  fortuneToolbarColorPickerPadding +
                  row * step +
                  fortuneToolbarColorPickerItemMargin,
              fortuneToolbarColorPickerItemSize,
              fortuneToolbarColorPickerItemSize,
            ),
            color,
            selected: color == _filterColorHex(toolbarBorderColor),
          );
        }
      }
      return nodes;
    }
    if (submenuKey == fortuneToolbarBorderStyleSubmenuKey) {
      addButton(
        Rect.fromLTWH(
          submenuRect.left,
          submenuRect.top + fortuneToolbarPopupContentTopPadding,
          submenuRect.width,
          fortuneToolbarBorderStyleSubmenuResetHeight,
        ),
        _toolbarPopupLabel(fortuneToolbarBorderStyleDefaultCommand),
        selected: toolbarBorderStyle == 1,
      );
      var styleTop =
          submenuRect.top +
          fortuneToolbarPopupContentTopPadding +
          fortuneToolbarBorderStyleSubmenuResetHeight;
      for (final style in fortuneToolbarBorderStyleValues) {
        addButton(
          Rect.fromLTWH(
            submenuRect.left,
            styleTop,
            submenuRect.width,
            fortuneToolbarBorderStyleSubmenuRowHeight,
          ),
          _toolbarPopupLabel('border-style-label-$style'),
          selected: toolbarBorderStyle == style,
        );
        styleTop += fortuneToolbarBorderStyleSubmenuRowHeight;
      }
    }
    return nodes;
  }

  List<CustomPainterSemantics> _contextMenuSemantics() {
    final at = contextMenuAt;
    if (at == null) {
      return const <CustomPainterSemantics>[];
    }
    final rect = fortuneContextMenuRect(at, contextMenuItems);
    final nodes = <CustomPainterSemantics>[];
    var y = rect.top + fortuneContextMenuContentTopPadding;
    for (final item in contextMenuItems) {
      if (item == '|') {
        y += fortuneContextMenuDividerHeight;
        continue;
      }
      final enabled = !contextMenuDisabledItems.contains(item);
      nodes.add(
        CustomPainterSemantics(
          rect: Rect.fromLTWH(
            rect.left,
            y,
            rect.width,
            fortuneContextMenuRowHeight,
          ),
          properties: SemanticsProperties(
            label: _contextMenuLabel(item),
            button: true,
            enabled: enabled,
            textDirection: textDirection,
          ),
        ),
      );
      y += fortuneContextMenuRowHeight;
    }
    return nodes;
  }

  List<CustomPainterSemantics> _sheetTabMenuSemantics() {
    final at = sheetTabMenuAt;
    if (at == null) {
      return const <CustomPainterSemantics>[];
    }
    final rect = fortuneSheetTabMenuRect(at, sheetTabMenuItems);
    final nodes = <CustomPainterSemantics>[];
    var y = rect.top + fortuneSheetTabMenuContentTopPadding;
    for (final item in sheetTabMenuItems) {
      if (item == '|') {
        y += fortuneSheetTabMenuDividerHeight;
        continue;
      }
      nodes.add(
        CustomPainterSemantics(
          rect: Rect.fromLTWH(
            rect.left,
            y,
            rect.width,
            fortuneSheetTabMenuRowHeight,
          ),
          properties: SemanticsProperties(
            label: _sheetTabMenuLabel(item),
            button: true,
            textDirection: textDirection,
          ),
