      );
      y += fortuneSheetTabMenuRowHeight;
    }
    return nodes;
  }

  List<CustomPainterSemantics> _sheetTabColorMenuSemantics() {
    final at = sheetTabMenuAt;
    if (!sheetTabColorMenuOpen || at == null) {
      return const <CustomPainterSemantics>[];
    }
    final rect = fortuneSheetTabColorMenuRect(at, sheetTabMenuItems);
    if (rect.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final nodes = <CustomPainterSemantics>[];

    void addButton(Rect buttonRect, String label) {
      nodes.add(
        CustomPainterSemantics(
          rect: buttonRect,
          properties: SemanticsProperties(
            label: label,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }

    addButton(
      Rect.fromLTWH(
        rect.left,
        rect.top,
        rect.width,
        fortuneToolbarFontColorResetHeight,
      ),
      locale.customColorReset,
    );
    final customRect = Rect.fromLTWH(
      rect.left,
      rect.top + fortuneToolbarFontColorCustomTop,
      rect.width,
      fortuneToolbarFontColorCustomHeight,
    );
    addButton(
      Rect.fromLTWH(
        customRect.right -
            fortuneToolbarFontColorCustomOkRightInset -
            fortuneToolbarFontColorCustomOkWidth,
        customRect.top + fortuneToolbarFontColorCustomOkTop,
        fortuneToolbarFontColorCustomOkWidth,
        fortuneToolbarFontColorCustomOkHeight,
      ),
      locale.customColorConfirm,
    );
    final pickerRect = Rect.fromLTWH(
      rect.left,
      rect.top + fortuneToolbarFontColorPickerTop,
      rect.width,
      rect.height - fortuneToolbarFontColorPickerTop,
    );
    final step =
        fortuneToolbarColorPickerItemSize +
        fortuneToolbarColorPickerItemMargin * 2;
    for (var row = 0; row < fortuneToolbarColorPickerPalette.length; row += 1) {
      final colors = fortuneToolbarColorPickerPalette[row];
      for (var column = 0; column < colors.length; column += 1) {
        addButton(
          Rect.fromLTWH(
            pickerRect.left +
                fortuneToolbarColorPickerPadding +
                column * step +
                fortuneToolbarColorPickerItemMargin,
            pickerRect.top +
                fortuneToolbarColorPickerPadding +
                row * step +
                fortuneToolbarColorPickerItemMargin,
            fortuneToolbarColorPickerItemSize,
            fortuneToolbarColorPickerItemSize,
          ),
          colors[column],
        );
      }
    }
    return nodes;
  }

  List<CustomPainterSemantics> _filterDropdownSemantics(Size size) {
    final column = filterDropdownColumn;
    if (column == null || size.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final rect = _filterDropdownRect(size, column);
    if (rect == null) {
      return const <CustomPainterSemantics>[];
    }
    final options = _filterDropdownLabels(column);
    if (options.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final checkedLabels = _filterDropdownCheckedLabels(column);
    final valueCounts = _filterDropdownValueCounts(column);
    final fixedRows = _filterDropdownFixedRowCount();
    final firstVisibleChoiceIndex =
        (filterDropdownScrollOffset / fortuneFilterDropdownRowHeight).floor();
    final nodes = <CustomPainterSemantics>[];

    void addButton(Rect rect, String label) {
      nodes.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }

    void addCheckbox(Rect rect, String label, bool checked, {String? value}) {
      nodes.add(
        CustomPainterSemantics(
          rect: rect,
          properties: SemanticsProperties(
            label: label,
            value: value,
            checked: checked,
            textDirection: textDirection,
          ),
        ),
      );
    }

    for (
      var visibleIndex = 0;
      visibleIndex < fortuneFilterDropdownMaxVisibleRows;
      visibleIndex += 1
    ) {
      final index = visibleIndex < fixedRows
          ? visibleIndex
          : fixedRows + firstVisibleChoiceIndex + visibleIndex - fixedRows;
      if (index >= options.length) {
        break;
      }
      final rowRect = Rect.fromLTWH(
        rect.left,
        rect.top + visibleIndex * fortuneFilterDropdownRowHeight,
        rect.width,
        fortuneFilterDropdownRowHeight,
      );
      final label = options[index];
      if (index < fixedRows) {
        addButton(rowRect, label);
        if (label == locale.filterClear) {
          final controlsRect = Rect.fromLTRB(
            rowRect.right - fortuneFilterDropdownBulkControlsWidth - 6,
            rowRect.top,
            rowRect.right - 6,
            rowRect.bottom,
          );
          var left = controlsRect.left;
          addButton(
            Rect.fromLTWH(
              left,
              controlsRect.top,
              fortuneFilterDropdownBulkCheckAllWidth,
              controlsRect.height,
            ),
            locale.filterCheckAll,
          );
          left +=
              fortuneFilterDropdownBulkCheckAllWidth +
              fortuneFilterDropdownBulkSeparatorWidth;
          addButton(
            Rect.fromLTWH(
              left,
              controlsRect.top,
              fortuneFilterDropdownBulkClearWidth,
              controlsRect.height,
            ),
            locale.filterClearSelection,
          );
          left +=
              fortuneFilterDropdownBulkClearWidth +
              fortuneFilterDropdownBulkSeparatorWidth;
          addButton(
            Rect.fromLTWH(
              left,
              controlsRect.top,
              fortuneFilterDropdownBulkInverseWidth,
              controlsRect.height,
            ),
            locale.filterInverseSelection,
          );
        }
      } else {
        final count = valueCounts[label];
        addCheckbox(
          rowRect,
          label,
          checkedLabels.contains(label),
          value: count == null ? null : '( $count )',
        );
      }
    }
    final noMatchVisibleIndex = _filterDropdownNoMatchVisibleIndex(
      options,
      firstVisibleChoiceIndex,
    );
    if (noMatchVisibleIndex != null) {
      nodes.add(
        CustomPainterSemantics(
          rect: Rect.fromLTWH(
            rect.left,
            rect.top + noMatchVisibleIndex * fortuneFilterDropdownRowHeight,
            rect.width,
            fortuneFilterDropdownRowHeight,
          ),
          properties: SemanticsProperties(
            label: locale.filterNoMatches,
            textDirection: textDirection,
          ),
        ),
      );
    }
    return nodes;
  }

  List<CustomPainterSemantics> _filterMarkerSemantics() {
    final sheet = workbook.activeSheet;
    final columns = _filterColumns(sheet);
    if (columns.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final activeColumns = _activeFilterColumns(sheet);
    final nodes = <CustomPainterSemantics>[];
    for (final column in columns) {
      final headerRect = _filterHeaderRect(column);
      if (headerRect == null ||
          headerRect.width < 18 ||
          headerRect.height < 14) {
        continue;
      }
      nodes.add(
        CustomPainterSemantics(
          rect: Rect.fromLTWH(
            headerRect.right - 18,
            headerRect.top,
            18,
            headerRect.height,
          ),
          properties: SemanticsProperties(
            label: 'Filter ${_columnName(column)}',
            button: true,
            selected: activeColumns.contains(column),
            textDirection: textDirection,
          ),
        ),
      );
    }
    return nodes;
  }

  List<CustomPainterSemantics> _columnHeaderMenuButtonSemantics() {
    final column = hoveredColumnHeaderIndex;
    if (column == null || !workbook.settings.allowEdit) {
      return const <CustomPainterSemantics>[];
    }
    final headerRect = _columnHeaderRect(column);
    if (headerRect == null || headerRect.width < 18 || headerRect.height < 14) {
      return const <CustomPainterSemantics>[];
    }
    return <CustomPainterSemantics>[
      CustomPainterSemantics(
        rect: fortuneColumnHeaderMenuButtonRect(headerRect),
        properties: SemanticsProperties(
          label: '${locale.sheetOptions} ${_columnName(column)}',
          button: true,
          textDirection: textDirection,
        ),
      ),
    ];
  }

  List<CustomPainterSemantics> _sheetCornerSemantics(Size size) {
    final settings = workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetHeight = math.max(
      0.0,
      size.height -
          sheetTop -
          settings.effectiveSheetBarHeight -
          settings.statisticBarHeight,
    );
    if (sheetHeight <= 0 ||
        settings.rowHeaderWidth <= 0 ||
        settings.columnHeaderHeight <= 0) {
      return const <CustomPainterSemantics>[];
    }
    return <CustomPainterSemantics>[
      CustomPainterSemantics(
        rect: Rect.fromLTWH(
          0,
          sheetTop,
          settings.rowHeaderWidth,
          settings.columnHeaderHeight,
        ),
        properties: SemanticsProperties(
          label: locale.selectAll,
          button: true,
          textDirection: textDirection,
        ),
      ),
    ];
  }

  List<CustomPainterSemantics> _dataVerificationMarkerSemantics(Size size) {
    final sheet = workbook.activeSheet;
    if (sheet.dataVerification.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final settings = workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetHeight = math.max(
      0.0,
      size.height -
          sheetTop -
          settings.effectiveSheetBarHeight -
          settings.statisticBarHeight,
    );
    if (sheetHeight <= settings.columnHeaderHeight) {
      return const <CustomPainterSemantics>[];
    }
    final metrics = sheet.metrics(settings);
    final rowRange = metrics.visibleRows(
      scrollOffset.dy,
      sheetHeight - settings.columnHeaderHeight,
    );
    final columnRange = metrics.visibleColumns(
      scrollOffset.dx,
      size.width - settings.rowHeaderWidth,
    );
    final nodes = <CustomPainterSemantics>[];
    for (var row = rowRange.start; row <= rowRange.end; row += 1) {
      for (
        var column = columnRange.start;
        column <= columnRange.end;
        column += 1
      ) {
        final coord = FortuneCellCoord(row, column);
        final dataVerification = _dataVerificationForCoord(sheet, coord);
        if (dataVerification == null ||
            dataVerification['type'] == 'checkbox') {
          continue;
        }
        final cellRect = _cellRectForCoord(coord, settings, metrics);
        if (cellRect == null || cellRect.width < 14 || cellRect.height < 12) {
          continue;
        }
        nodes.add(
          CustomPainterSemantics(
            rect: Rect.fromLTWH(
              cellRect.right - 18,
              cellRect.top,
              18,
              cellRect.height,
            ),
            properties: SemanticsProperties(
              label: locale.dropdownShortcutLabel,
              button: true,
              textDirection: textDirection,
            ),
          ),
        );
      }
    }
    return nodes;
  }

  List<CustomPainterSemantics> _dataVerificationDropdownSemantics(Size size) {
    final coord = dataVerificationDropdownCoord;
    if (coord == null) {
      return const <CustomPainterSemantics>[];
    }
    final sheet = workbook.activeSheet;
    final options = _dataVerificationOptions(
      sheet.dataVerification[_cellKey(coord)],
      sheet: sheet,
    );
    if (options.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final settings = workbook.settings;
    final metrics = sheet.metrics(settings);
    final cellRect = _cellRectForCoord(coord, settings, metrics);
    if (cellRect == null) {
      return const <CustomPainterSemantics>[];
    }
    final raw = sheet.dataVerification[_cellKey(coord)];
    final isMultiSelect = raw is Map && fortuneRawBool(raw['type2']) == true;
    final selectedOptions = isMultiSelect
        ? _dataVerificationOptions({
            'value1': sheet.cells[coord]?.value,
          }, resolveReferences: false).toSet()
        : const <String>{};
    final width = math.max(
      120.0,
      math.max(cellRect.width, _longestOptionWidth(options)),
    );
    final height = math.min(8, options.length) * 24.0;
    var left = cellRect.left;
    var top = cellRect.bottom + 1;
    left = left.clamp(0.0, math.max(0.0, size.width - width)).toDouble();
    if (top + height > size.height) {
      top = math.max(0.0, cellRect.top - height - 1);
    }
    final rect = Rect.fromLTWH(left, top, width, height);
    return <CustomPainterSemantics>[
      for (var i = 0; i < options.length && i < 8; i += 1)
        CustomPainterSemantics(
          rect: Rect.fromLTWH(rect.left, rect.top + i * 24, rect.width, 24),
          properties: SemanticsProperties(
            label: options[i],
            button: true,
            checked: isMultiSelect
                ? selectedOptions.contains(options[i])
                : null,
            textDirection: textDirection,
          ),
        ),
    ];
  }

  List<CustomPainterSemantics> _commentBoxSemantics(Size size) {
    final settings = workbook.settings;
    final metrics = workbook.activeSheet.metrics(settings);
    return _visibleCommentBoxes(size, settings, metrics)
        .map(
          (comment) => CustomPainterSemantics(
            rect: comment.rect,
            properties: SemanticsProperties(
              label: comment.value,
              textField: true,
              textDirection: textDirection,
            ),
          ),
        )
        .toList(growable: false);
  }

  List<CustomPainterSemantics> _formulaBarSemantics(Size size) {
    final inputRect = fortuneFormulaBarInputRect(size, workbook.settings);
    final nameBoxRect = fortuneFormulaBarNameBoxRect(size, workbook.settings);
    if ((inputRect == null || inputRect.isEmpty) &&
        (nameBoxRect == null || nameBoxRect.isEmpty)) {
      return const <CustomPainterSemantics>[];
    }
    return <CustomPainterSemantics>[
      if (nameBoxRect != null && !nameBoxRect.isEmpty)
        CustomPainterSemantics(
          rect: nameBoxRect,
          properties: SemanticsProperties(
            label: formulaBarNameBoxText,
            textDirection: textDirection,
          ),
        ),
      if (inputRect != null && !inputRect.isEmpty)
        CustomPainterSemantics(
          rect: inputRect,
          properties: SemanticsProperties(
            label: locale.currentCellInput,
            textField: true,
            textDirection: textDirection,
          ),
        ),
    ];
  }

  List<CustomPainterSemantics> _sheetTabSemantics(Size size) {
    final settings = workbook.settings;
    if (!settings.showSheetTabs || !settings.allowEdit) {
      return const <CustomPainterSemantics>[];
    }
    final statTop = size.height - settings.statisticBarHeight;
    final tabTop = statTop - settings.effectiveSheetBarHeight;
    if (tabTop < settings.effectiveToolbarHeight) {
      return const <CustomPainterSemantics>[];
    }
    return <CustomPainterSemantics>[
      CustomPainterSemantics(
        rect: Rect.fromLTWH(0, tabTop + 1, 29, 29),
        properties: SemanticsProperties(
          label: locale.newSheet,
          button: true,
          textDirection: textDirection,
        ),
      ),
      if (_sheetTabsTotalWidth() > math.max(0, size.width - 58)) ...[
        CustomPainterSemantics(
          rect: Rect.fromLTWH(30, tabTop + 1, 14, 29),
          properties: SemanticsProperties(
            label: locale.scrollSheetsLeft,
            button: true,
            textDirection: textDirection,
          ),
        ),
        CustomPainterSemantics(
          rect: Rect.fromLTWH(44, tabTop + 1, 14, 29),
          properties: SemanticsProperties(
            label: locale.scrollSheetsRight,
            button: true,
            textDirection: textDirection,
          ),
        ),
      ] else
        CustomPainterSemantics(
          rect: Rect.fromLTWH(30, tabTop + 1, 28, 29),
          properties: SemanticsProperties(
            label: locale.sheetList,
            button: true,
            textDirection: textDirection,
          ),
        ),
      ..._sheetTabOptionSemantics(size, tabTop),
    ];
  }

  List<CustomPainterSemantics> _selectionInfoSemantics(Size size) {
    final settings = workbook.settings;
    if (!settings.showSheetTabs) {
      return const <CustomPainterSemantics>[];
    }
    final statTop = size.height - settings.statisticBarHeight;
    final tabTop = statTop - settings.effectiveSheetBarHeight;
    if (tabTop < settings.effectiveToolbarHeight) {
      return const <CustomPainterSemantics>[];
    }
    final items = _selectionInfoItems();
    if (items.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final nodes = <CustomPainterSemantics>[];
    var right = size.width - fortuneSelectionInfoRightPadding;
    for (final item in items.reversed) {
      final width = _selectionInfoItemWidth(item);
      final rect = Rect.fromLTWH(
        right - width,
        statTop,
        width,
        settings.statisticBarHeight,
      );
      if (rect.right <= 0) {
        break;
      }
      if (rect.left < size.width) {
        nodes.add(
          CustomPainterSemantics(
            rect: rect.intersect(Offset.zero & size),
            properties: SemanticsProperties(
              label: item,
              textDirection: textDirection,
            ),
          ),
        );
      }
      right = rect.left - fortuneSelectionInfoItemGap;
    }
    return nodes;
  }

  List<CustomPainterSemantics> _sheetListSemantics(Size size) {
    final nodes = <CustomPainterSemantics>[];
    final openSheetListAt = sheetListAt;
    if (openSheetListAt != null && workbook.sheets.isNotEmpty) {
      final sheetCount = workbook.sheets.length;
      final rect = fortuneSheetListRect(
        openSheetListAt,
        sheetCount,
        viewportHeight: size.height,
      );
      final scrolledAt = openSheetListAt.translate(0, -sheetListScrollOffset);
      for (var index = 0; index < sheetCount; index += 1) {
        final sheet = workbook.sheets[index];
        final textRect = fortuneSheetListTextRect(
          scrolledAt,
          index,
          sheetCount,
        );
        if (!rect.overlaps(textRect)) {
          continue;
        }
        nodes.add(
          CustomPainterSemantics(
            rect: textRect.intersect(rect),
            properties: SemanticsProperties(
              label: sheet.name,
              button: true,
              selected: index == workbook.activeSheetIndex,
              textDirection: textDirection,
            ),
          ),
        );
        if (sheet.hide == 1) {
          final hiddenButtonRect = fortuneSheetListHiddenButtonRect(
            scrolledAt,
            index,
            sheetCount,
          );
          nodes.add(
            CustomPainterSemantics(
              rect: hiddenButtonRect.intersect(rect),
              properties: SemanticsProperties(
                button: true,
                textDirection: textDirection,
              ),
            ),
          );
        }
      }
    }

    final openHiddenSheetListAt = hiddenSheetListAt;
    if (openHiddenSheetListAt != null) {
      final hidden = [
        for (final sheet in workbook.sheets)
          if (sheet.hide == 1) sheet,
      ];
      for (var index = 0; index < hidden.length; index += 1) {
        nodes.add(
          CustomPainterSemantics(
            rect: fortuneHiddenSheetTextRect(
              openHiddenSheetListAt,
              index,
              hidden.length,
            ),
            properties: SemanticsProperties(
              label: hidden[index].name,
              button: true,
              textDirection: textDirection,
            ),
          ),
        );
      }
    }
    return nodes;
  }

  List<CustomPainterSemantics> _sheetTabOptionSemantics(
    Size size,
    double tabTop,
  ) {
    final viewport = Rect.fromLTWH(
      58,
      tabTop + 1,
      math.max(0, size.width - 58),
      29,
    );
    final nodes = <CustomPainterSemantics>[];
    var x = viewport.left - sheetTabScrollOffset;
    for (final sheet in workbook.sheets) {
      if (sheet.hide == 1) {
        continue;
      }
      final width = math.max(72.0, (sheet.name.length * 8 + 32).toDouble());
      final rect = Rect.fromLTWH(x, tabTop + 1, width, 29);
      if (rect.right < viewport.left) {
        x += width - 1;
        continue;
      }
      if (rect.left > viewport.right) {
        break;
      }
      final optionRect = Rect.fromLTWH(
        rect.right - 22,
        rect.top,
        22,
        rect.height,
      ).intersect(viewport);
      if (!optionRect.isEmpty) {
        nodes.add(
          CustomPainterSemantics(
            rect: optionRect,
            properties: SemanticsProperties(
              label: locale.sheetOptions,
              button: true,
              textDirection: textDirection,
            ),
          ),
        );
      }
      x += width - 1;
    }
    return nodes;
  }

  List<CustomPainterSemantics> _bottomAddRowsSemantics(Size size) {
    final settings = workbook.settings;
    if (!settings.showSheetTabs || !settings.allowEdit) {
      return const <CustomPainterSemantics>[];
    }
    final nodes = <CustomPainterSemantics>[];
    final backTopRect = fortuneBottomBackTopButtonRect(size, settings);
    if (backTopRect.width >= 48) {
      nodes.add(
        CustomPainterSemantics(
          rect: backTopRect,
          properties: SemanticsProperties(
            label: locale.backToTop,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }
    final count = workbook.activeSheet.addRows ?? settings.addRows;
    if (count <= 0) {
      return nodes;
    }
    final rect = fortuneBottomAddRowsButtonRect(size, settings);
    if (rect.width < 48) {
      return nodes;
    }
    nodes.add(
      CustomPainterSemantics(
        rect: rect,
        properties: SemanticsProperties(
          label: 'Add $count rows',
          button: true,
          textDirection: textDirection,
        ),
      ),
    );
    return nodes;
  }

  List<CustomPainterSemantics> _zoomControlSemantics(Size size) {
    final settings = workbook.settings;
    if (!settings.showSheetTabs) {
      return const <CustomPainterSemantics>[];
    }
    final statTop = size.height - settings.statisticBarHeight;
    if (statTop < settings.effectiveToolbarHeight) {
      return const <CustomPainterSemantics>[];
    }
    final activeZoom = workbook.activeSheet.zoomRatio <= 0
        ? 1.0
        : workbook.activeSheet.zoomRatio;
    return <CustomPainterSemantics>[
      CustomPainterSemantics(
        rect: fortuneZoomOutButtonRect(size, settings),
        properties: SemanticsProperties(
          label: locale.zoomOut,
          button: true,
          textDirection: textDirection,
        ),
      ),
      CustomPainterSemantics(
        rect: fortuneZoomRatioButtonRect(size, settings),
        properties: SemanticsProperties(
          label: '${(activeZoom * 100).round()}%',
          button: true,
          textDirection: textDirection,
        ),
      ),
      CustomPainterSemantics(
        rect: fortuneZoomInButtonRect(size, settings),
        properties: SemanticsProperties(
          label: locale.zoomIn,
          button: true,
          textDirection: textDirection,
        ),
      ),
      if (zoomMenuOpen)
        for (var index = 0; index < fortuneZoomPresetValues.length; index += 1)
          CustomPainterSemantics(
            rect: fortuneZoomPresetItemRect(size, settings, index),
            properties: SemanticsProperties(
              label: '${(fortuneZoomPresetValues[index] * 100).round()}%',
              button: true,
              selected:
                  (fortuneZoomPresetValues[index] * 10).round() ==
                  (activeZoom * 10).round(),
              textDirection: textDirection,
            ),
          ),
    ];
  }

  List<CustomPainterSemantics> _imageSemantics(Size size) {
    final sheet = workbook.activeSheet;
    if (sheet.images.isEmpty) {
      return const <CustomPainterSemantics>[];
    }
    final settings = workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetHeight = math.max(
      0.0,
      size.height -
          sheetTop -
          settings.effectiveSheetBarHeight -
          settings.statisticBarHeight,
    );
    final clip = Rect.fromLTWH(
      settings.rowHeaderWidth,
      settings.columnHeaderHeight,
      math.max(0, size.width - settings.rowHeaderWidth),
      math.max(0, sheetHeight - settings.columnHeaderHeight),
    );
    final zoomRatio = sheet.zoomRatio <= 0 ? 1.0 : sheet.zoomRatio;
    final semantics = <CustomPainterSemantics>[];
    for (final image in sheet.images) {
      if (image.id == activeImageId) {
        continue;
      }
      final rect = Rect.fromLTWH(
        settings.rowHeaderWidth + image.left * zoomRatio - scrollOffset.dx,
        settings.columnHeaderHeight + image.top * zoomRatio - scrollOffset.dy,
        image.width * zoomRatio,
        image.height * zoomRatio,
      );
      if (!rect.overlaps(clip)) {
        continue;
      }
      semantics.add(
        CustomPainterSemantics(
          rect: rect.intersect(clip).shift(Offset(0, sheetTop)),
          properties: SemanticsProperties(
            label: image.id,
            button: true,
            textDirection: textDirection,
          ),
        ),
      );
    }
    return semantics;
  }

  @override
  bool shouldRebuildSemantics(covariant FortuneSheetPainter oldDelegate) {
    return shouldRepaint(oldDelegate);
  }
}

class _FortuneToolbarPopupForegroundPainter extends CustomPainter {
  const _FortuneToolbarPopupForegroundPainter(this.delegate);

  final FortuneSheetPainter delegate;

  @override
  void paint(Canvas canvas, Size size) {
    delegate._drawToolbarPopup(canvas, size);
  }

  @override
  bool shouldRepaint(
    covariant _FortuneToolbarPopupForegroundPainter oldDelegate,
  ) {
    return delegate.shouldRepaint(oldDelegate.delegate);
  }
}

class _FortuneContextMenuForegroundPainter extends CustomPainter {
  const _FortuneContextMenuForegroundPainter(this.delegate);

  final FortuneSheetPainter delegate;

  @override
  void paint(Canvas canvas, Size size) {
    delegate._drawContextMenu(canvas);
  }

  @override
  bool shouldRepaint(
    covariant _FortuneContextMenuForegroundPainter oldDelegate,
  ) {
    return delegate.shouldRepaint(oldDelegate.delegate);
  }
}

class _ConditionFormatStyle {
  const _ConditionFormatStyle({
    this.textColor,
    this.cellColor,
    this.dataBar,
    this.icon,
  });

  final Color? textColor;
  final Color? cellColor;
  final _ConditionDataBar? dataBar;
  final _ConditionIcon? icon;
}

enum _ConditionDataBarType { plus, minus }

class _ConditionDataBar {
  const _ConditionDataBar({
    required this.valueType,
    required this.valueLen,
    required this.plusLen,
    required this.minusLen,
    required this.colors,
  });

  final _ConditionDataBarType valueType;
  final double valueLen;
  final double plusLen;
  final double minusLen;
  final List<Color> colors;
}

enum _ConditionIconKind { up, side, down }

class _ConditionIcon {
  const _ConditionIcon(this.kind);

  final _ConditionIconKind kind;
}

class _ConditionDateRange {
  const _ConditionDateRange(this.start, this.end);

  final int start;
  final int end;
}

class _BorderLineSegment {
  const _BorderLineSegment({
    required this.side,
    required this.start,
    required this.end,
    required this.horizontal,
  });

  final FortuneBorderSide side;
  final Offset start;
  final Offset end;
  final bool horizontal;

  double get crossAxis => horizontal ? start.dy : start.dx;
  double get mainStart =>
      horizontal ? math.min(start.dx, end.dx) : math.min(start.dy, end.dy);
  double get mainEnd =>
      horizontal ? math.max(start.dx, end.dx) : math.max(start.dy, end.dy);

  _BorderLineSegment copyWithMainEnd(double value) {
    return _BorderLineSegment(
      side: side,
      start: start,
      end: horizontal ? Offset(value, end.dy) : Offset(end.dx, value),
      horizontal: horizontal,
    );
  }
}

class _SelectionRangePiece {
  const _SelectionRangePiece({required this.rect, required this.clip});

  final Rect rect;
  final Rect clip;
}

class _PresenceRange {
  const _PresenceRange({
    required this.row,
    required this.column,
    required this.label,
    required this.color,
    required this.pieces,
  });

  final int row;
  final int column;
  final String label;
  final Color color;
  final List<_SelectionRangePiece> pieces;
}

class _SplitAxisRange {
  const _SplitAxisRange({
    required this.start,
    required this.end,
    required this.isFrozen,
  });

  final int start;
  final int end;
  final bool isFrozen;
}

class _FrozenSheetView {
  const _FrozenSheetView({
    required this.rowFocus,
    required this.columnFocus,
    required this.frozenHeight,
    required this.frozenWidth,
  });

  final int? rowFocus;
  final int? columnFocus;
  final double frozenHeight;
  final double frozenWidth;

  bool get hasFrozenPane => rowFocus != null || columnFocus != null;
}
